// physicsImportant.js
// Class 11 Physics - Important Questions (700 across 14 chapters).
// Default-exports a { chapterName: cardsHtml } map. Wire it into
// importantQuestions.js:  Physics: PHYSICS_IMPORTANT  (import default).
// Same pastel template as the PYQ files; math is {tex}...{/tex} (MathJax);
// images come straight from the source (rendered by the WebView).

const PQ_PASTEL_HEAD = `
<style>
  .pq-wrap{ font-family:-apple-system,Roboto,"Segoe UI",sans-serif; }
  .pq-card{ background:#ffffff; border:1px solid #ECEEF3; border-radius:18px;
            padding:20px; margin-bottom:16px; box-shadow:0 6px 20px rgba(17,24,39,0.06); }
  .pq-top{ display:flex; justify-content:space-between; align-items:center; margin-bottom:14px; }
  .pq-q{ font-size:13px; font-weight:800; color:#0F172A; letter-spacing:0.3px; }
  .pq-tag{ font-size:11px; font-weight:700; color:#7C6F9B; background:#F1EEFA; padding:4px 10px; border-radius:999px; }
  .pq-opt-text{ flex:1; }
  .pq-year{ font-size:12px; font-weight:700; color:#14B8A6; background:#ECFDFA;
            padding:4px 12px; border-radius:999px; }
  .pq-question{ font-size:16px; line-height:1.65; color:#1E293B; margin:0 0 16px; }

  /* MCQ options */
  .pq-opt{ display:flex; gap:12px; align-items:flex-start; background:#F5F6FA;
           border:1px solid #EEF0F5; border-radius:12px; padding:13px 16px;
           margin-bottom:10px; font-size:15px; color:#334155; }
  .pq-letter{ font-weight:800; color:#475569; min-width:16px; }
  .pq-opt-correct{ background:#ECFBF2; border:1px solid #BBF7D0;
                   border-left:4px solid #34D399; flex-direction:column; align-items:stretch; }
  .pq-correct-row{ display:flex; gap:12px; }
  .pq-correct-letter{ color:#059669; }
  .pq-expl-label{ color:#059669; font-weight:700; font-size:13px; margin:10px 0 6px; }
  .pq-expl{ border-left:3px solid #A7F3D0; padding-left:12px; color:#475569;
            font-size:14px; line-height:1.6; }
  .pq-expl p{ margin:3px 0; }

  /* Subjective solution box (cream) */
  .pq-solution{ background:#FBF6EC; border:1px solid #F2E7D2; border-radius:14px;
                padding:16px 18px; margin-top:4px; }
  .pq-solution-title{ font-size:14px; font-weight:800; color:#1C1C1E; margin-bottom:10px; }
  .pq-solution-body{ color:#6B7280; font-size:15px; line-height:1.75; }
  .pq-solution-body p{ margin:4px 0; }

  .pq-foot{ display:flex; justify-content:flex-end; margin-top:12px; }
  .pq-report{ font-family:inherit; font-size:13px; font-weight:600; color:#64748B;
              background:#ffffff; border:1px solid #E2E8F0; border-radius:10px;
              padding:9px 16px; cursor:pointer; }
  .pq-report:active{ background:#F8FAFC; }
</style>
<script>
  function pqReport(btn){
    btn.innerText='\\u2713 Reported';
    btn.style.color='#047857';
    btn.style.borderColor='#6EE7B7';
    btn.style.background='#ECFDF5';
    btn.disabled=true;
    try{
      if(window.ReactNativeWebView){
        window.ReactNativeWebView.postMessage(
          JSON.stringify({ type:'report_error', id: btn.getAttribute('data-qid') })
        );
      }
    }catch(e){}
  }
</script>
`;


const PHYIMP_UNITS_AND_MEASUREMENTS = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Force F is given by F = at + bt<sup>2</sup>,&nbsp;where t is time. What are the dimensions of a and b?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">[MLT<sup>-3</sup>] and [MLT<sup>-4</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>[a] =&nbsp;<span class="math-tex">{tex}\\frac{[F]}{[t]}=\\frac{\\left[\\mathrm{MLT}^{-2}\\right]}{[\\mathrm{T}]}{/tex}</span>&nbsp;=&nbsp;[MLT<sup>-3</sup>]<br />
[b] =&nbsp;<span class="math-tex">{tex}\\frac{[F]}{[t]^{2}}=\\frac{\\left[\\mathrm{MLT}^{-2}\\right]}{[\\mathrm{T}]^{2}}{/tex}</span>&nbsp;=&nbsp;[MLT<sup>-4</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">[MLT<sup>-1</sup>] and [MLT<sup>0</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[MLT<sup>-3</sup>] and [MLT<sup>4</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[MLT<sup>-4</sup>] and [MLT<sup>1</sup>]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The equation of state of the gas is expressed as&nbsp;<span class="math-tex">{tex}\\left(P+\\frac{a}{V^{2}}\\right)(V-b){/tex}</span>&nbsp;= nRT,&nbsp;where P = pressure, V = volume, T = temperature and n, a, b, R are constants. The dimensions of a will be:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">[MLT<sup>-1</sup>]</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>5</sup>T<sup>-2</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>[a]&nbsp;= [P][V<sup>2</sup>] =[ML<sup>-1</sup>T<sup>-2</sup>][L<sup>3</sup>]<sup>2</sup> = [ML<sup>5</sup>T<sup>-2</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[L<sup>-3</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[L<sup>6</sup>]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which of the following has the dimensions of pressure?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">[MLT<sup>-2</sup>]</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>-1</sup>T<sup>-2</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>ML<sup>-2</sup>T<sup>-2</sup> is dimensions of pressure.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>-2</sup>T<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[M<sup>-1</sup>L<sup>-1</sup>]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>What is the dimensional formula of gravitational constant G?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">[M<sup>-1</sup>L<sup>3</sup>T<sup>-2</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}[G]=\\frac{F r^{2}}{m_{1} m_{2}}=\\frac{\\left[\\mathrm{MLT}^{-2}\\right]\\left[\\mathrm{L}^{2}\\right]}{[\\mathrm{M}][\\mathrm{M}]}{/tex}</span><br />
= [M<sup>-1</sup>L<sup>3</sup>T<sup>-2</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">[M<sup>-2</sup>L<sup>3</sup>T<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[M<sup>-1</sup>L<sup>2</sup>T<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[M<sup>-1</sup>L<sup>3</sup>T<sup>-1</sup>]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>What are the dimensions of <span class="math-tex">{tex}\\frac{A}{B}{/tex}</span> in the relation <span class="math-tex">{tex}F=A \\sqrt{x}+B t^{2}{/tex}</span>, where F is the force, x is distance and t is time?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>2</sup>T<sup>-2</sup>]</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">[<span class="math-tex">{tex}L^{-\\frac{1}{2}}{/tex}</span>T<sup>2</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}L^{-\\frac{1}{2}}{/tex}</span>T<sup>2</sup></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[<span class="math-tex">{tex}L^{-\\frac{1}{2}}{/tex}</span>T<sup>-1</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[LT<sup>-2</sup>]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the dimensions of a physical quantity are given by M<sup>a</sup>L<sup>b</sup>T<sup>c</sup>, then the physical quantity will be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Velocity if a = 1, b = 0, c = -1</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Acceleration if a = 1, b = 1, c = -2</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Force if a = 0, b = -1, c = -2</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">Pressure if a = 1, b = -1, c = -2</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Pressure, <span class="math-tex">{tex}[P]=\\frac{[F]}{[A]}=\\frac{M L T^{-2}}{L^{2}}{/tex}</span><br />
= [M<sup>1</sup>L<sup>-1</sup>T<sup>-2</sup>]<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> a = 1, b = -1, c = -2</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>[ML<sup>2</sup>T<sup>-2</sup>] are dimensions of:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">force</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">moment of force</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>[Moment of force] = [Torque] = [ML<sup>2</sup>T<sup>-2</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">momentum</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">power</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If force (F), length (L) and time (T) be considered fundamental units, then units of mass will be:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">[FLT<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">[FL<sup>-2</sup>T<sup>-1</sup>]</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">[FL<sup>-1</sup>T<sup>2</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>[F] = [MLT<sup>-2</sup>]<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;[M] = [FL<sup>-1</sup>T<sup>2</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[F<sup>2</sup>LT<sup>-2</sup>]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The equation&nbsp;<span class="math-tex">{tex}\\left(P+\\frac{a}{V^{2}}\\right)(V-b){/tex}</span>&nbsp;=&nbsp;Constant. The units of a are</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">dyne <span class="math-tex">{tex}\\times{/tex}</span> cm<sup>5</sup></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">dyne <span class="math-tex">{tex}\\times{/tex}</span> cm<sup>4</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Unit of a = Unit of P <span class="math-tex">{tex}\\times{/tex}</span> Unit of V<sup>2</sup><br />
=&nbsp;dyne cm<sup>-2</sup> <span class="math-tex">{tex}\\times{/tex}</span> (cm<sup>3</sup>)<sup>2</sup><br />
= dyne cm<sup>4</sup></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">dyne cm<sup>-3</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">dyne cm<sup>-2</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The dimensions of universal gravitational constant are</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">[M<sup>-1</sup>L<sup><span style="font-size:10.5px">3</span></sup>T<sup>-2</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>M<sup>-1</sup>L<sup>3</sup>T<sup>-2</sup> is dimensional formula of universal gravitational constant .</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>2</sup>T<sup>-1</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>-1</sup>T<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>-2</sup>T<sup>-2</sup>]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which of the following physical quantity has the dimension of [ML<sup>2</sup>T<sup>-3</sup>]?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Work</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">Power</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>[Power] <span class="math-tex">{tex}=\\frac{\\text { work }}{\\text { time }}{/tex}</span> <span class="math-tex">{tex}=\\frac{\\left[\\mathrm{ML}^{2} \\mathrm{~T}^{-2}\\right]}{[\\mathrm{T}]}{/tex}</span> = [ML<sup>2</sup>T<sup>-3</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Pressure</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Impulse</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The force F is given in terms of time t&nbsp;and displacement x by the equation F = A cos Bx + C sin Dt. The dimensional formula of <span class="math-tex">{tex}\\frac DB{/tex}</span>&nbsp;is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">[M<sup>0</sup>L<sup>0</sup>T<sup>0</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">[M<sup>0</sup>L<sup>0</sup>T<sup>-1</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[M<sup>0</sup>L<sup>-1</sup>T<sup>0</sup>]</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">[M<sup>0</sup>LT<sup>-1</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>[D/B] =&nbsp;<span class="math-tex">{tex}\\frac{\\left[t^{-1}\\right]}{\\left[x^{-1}\\right]}=\\frac{T^{-1}}{L^{-1}}{/tex}</span>&nbsp;=&nbsp;[M<sup>0</sup>LT<sup>-1</sup>]</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the energy (E), velocity (v) and force (F) be taken as fundamental quantity, then the dimensions of mass will be:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Fv<sup>-2</sup></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Fv<sup>-1</sup></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">Ev<sup>-2</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>E = mc<sup>2</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;[m] =&nbsp;<span class="math-tex">{tex}\\frac{[E]}{\\left[c^{2}\\right]}=\\frac{[E]}{\\left[v^{2}\\right]}{/tex}</span>&nbsp;= [Ev<sup>-2</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Ev<sup>2</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If force (F), velocity (V) and time (T) are taken as fundamental units, then the dimensions of mass are</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">[FVT<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">[FV<sup>-1</sup>T<sup>-1</sup>]</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">[FV<sup>-1</sup>T]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>F = ma <span class="math-tex">{tex}=m \\frac{v}{t} {/tex}</span> or <span class="math-tex">{tex}m=\\frac{F t}{v}{/tex}</span><br />
[Mass] = [FTV<sup>-1</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[FVT<sup>-1</sup>]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If momentum (P), area (A) and time (T) are taken to be fundamental quantities, then energy has the dimensional formula.</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">(P<sup>1</sup> A<sup>-1</sup> T<sup>1</sup>)</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">(P<sup>2</sup> A<sup>1</sup> T<sup>1</sup>)</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">(P<sup>1</sup> A<sup>-1/2</sup> T<sup>1</sup>)</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">(P<sup>1</sup> A<sup>1/2</sup> T<sup>-1</sup>)</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>According to the problem, fundamental quantities are momentum (p), area (A) and time (T) and we have to express energy in these fundamental quantities.<br />
Let energy E,<br />
<span class="math-tex">{tex}E \\propto p^{a} A^{A} T^{c}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}E=k p^{a} A^{A} T^{c}{/tex}</span>&nbsp;<br />
where, k is dimensionless constant of proportionality.<br />
Dimensional formula of energy, [E] = [ML<sup>2</sup>T<sup>-2</sup>] and [p] = [MLT<sup>-1</sup>]<br />
[A] = [L<sup>2</sup>], [T] = [T] and [E] = [K][p]<sup>a</sup>[A]<sup>b</sup>[T]<sup>c&nbsp;</sup><br />
Putting all the dimensions, we get<br />
ML<sup>2</sup>T<sup>-2</sup> = [MLT<sup>-1</sup>]<sup>a</sup>[L<sup>2</sup>]<sup>b</sup>[T]<sup>c</sup><br />
= M<sup>a</sup>L<sup>a+2b</sup>T<sup>a+c</sup>&nbsp;&nbsp;<br />
According to the principle of homogeneity of dimensions, we get<br />
a = 1 ......(i)<br />
a + 2b = 2 .....(ii)<br />
-a + c = -2 .....(iii)<br />
By solving these equations (i), (ii) and (iii), we get<br />
a = 1, b =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>, c = -1<br />
Dimesnional formula for E is&nbsp;<span class="math-tex">{tex}\\left[p^{1} A^{1 / 2} t^{-1}\\right]{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>What are the dimensional formulae of the following:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>pressure</li>
	<li>power</li>
	<li>density</li>
	<li>angle?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>[ML<sup>-1</sup>T<sup>-2</sup>]</li>
	<li>[ML<sup>2</sup>T<sup>-3</sup>]</li>
	<li>[ML<sup>-3</sup>T<sup>0</sup>]</li>
	<li>dimensionless</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>State the number of significant figures in the following :</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>0.007 m<sup>2</sup></li>
	<li>2.64 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>24</sup>&nbsp;kg</li>
	<li>0.2370 g cm<sup>-3</sup></li>
	<li>6.320 J</li>
	<li>6.032 N m<sup>-2</sup></li>
	<li>0.0006032 m<sup>2</sup></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>1. If the number is less than one, then all zeros on the right of the decimal point are insignificant. This means that here, two zeros after the decimal are not significant. Hence, only 7 is a significant figure in this quantity.</li>
	<li>3. For the determination of significant values, we do not consider the power of 10 (Number is not less than 1).&nbsp;The digits 2, 6, and 4&nbsp;are significant figures. Hence, It has 3 significant digits.</li>
	<li>4. Explanation: Significant figure- 2, 3, 7, 0. Trailing 0&rsquo;s is significant. These 0&rsquo;s increase the accuracy of the answer.</li>
	<li>4. From the condition of a significant figure, the zero after the decimal point comes after a non-zero number so it significant figure. The number of significant figures is 4.</li>
	<li>4. Explanation: Significant figure- 6, 0, 3, 2. 0&rsquo;s between 2 non-zero digits are significant.</li>
	<li>4. Explanation: Significant figure- 6, 0, 3, 2.&nbsp;Since&nbsp;<strong>the number is less than 1.</strong></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Each side of a cube is measured to be 7.203 m. What are the&nbsp;total surface area and the volume of the cube to appropriate significant figures?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here it is given that, Side of the cube = 7.203 m<br />
Therefore, Total Surface area =&nbsp;<span class="math-tex">{tex}6 \\times ( \\text { side } ) ^ { 2 } = 6 \\times ( 7.203 ) ^ { 2 }{/tex}</span><br />
= 311.299254 m<sup>2</sup><br />
&nbsp;= 311.3 m<sup>2&nbsp; &nbsp; &nbsp; &nbsp;</sup>[where the value has been rounded off to 4 significant figures]<br />
Now, Volume of the cube = (side)<sup>3</sup>&nbsp;=&nbsp;&nbsp;(7.203)<sup>3</sup><br />
&nbsp;= 373.714754 m<sup>3</sup><br />
= 373.7 m<sup>3 </sup>[Rounded off to 4 significant figures]</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Find the dimensions of <span class="math-tex">{tex}\\frac ab{/tex}</span>&nbsp;in the equation: F = <span class="math-tex">{tex}a \\sqrt{x}{/tex}</span>&nbsp;+ bt<sup>2</sup>, where F is force, x is distance and t is time.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><span class="math-tex">{tex}[a \\sqrt{x}]{/tex}</span>&nbsp;= [F]<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;[a] =&nbsp;<span class="math-tex">{tex}\\frac{[F]}{[\\sqrt{x}]}=\\frac{\\mathrm{MLT}^{-2}}{\\mathrm{~L}^{1 / 2}}{/tex}</span>&nbsp;=&nbsp;ML<sup>1/2</sup>&nbsp;T<sup>-2</sup><br />
[bt<sup>2</sup>] = [F]<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;[b] =&nbsp;<span class="math-tex">{tex}\\frac{[F]}{\\left[t^{2}\\right]}=\\frac{\\mathrm{MLT}^{-2}}{\\mathrm{~T}^{2}}{/tex}</span>&nbsp;=&nbsp;MLT<sup>-4</sup><br />
[<span class="math-tex">{tex}\\frac ab{/tex}</span>] =&nbsp;<span class="math-tex">{tex}\\frac{M L^{1 / 2} T^{-2}}{M L T^{-4}}{/tex}</span>&nbsp;=&nbsp;L<sup>-1/2</sup>T<sup>2</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>If x = 2at - 5bt<sup>2</sup>, where x is in metres and t in seconds, find the dimensions of a and b.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If x = 2at - 5bt<sup>2</sup><br />
Where x is in metres<br />
i.e., x has dimensions of length<br />
[x] = 2a[T]<br />
[L] = 2a[T]<br />
a = <span class="math-tex">{tex}\\frac{[L]}{[T]}{/tex}</span><br />
a = [LT<sup>-1</sup>]<br />
[x] = 5b[T<sup>2</sup>]<br />
[L] = 5b[T<sup>2</sup>]<br />
b = <span class="math-tex">{tex}\\frac{[L]}{[T^2]}{/tex}</span><br />
b = [LT<sup>-2</sup>]</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Let us consider an equation&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>mv<sup>2</sup>&nbsp;= mgh&nbsp;where m is the mass of the body, v its velocity, g is the acceleration due to gravity, and h is the height. Check whether this equation is dimensionally correct.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The dimensions of LHS are<br />
[M] [L T<sup>&ndash;1</sup>]<sup>2</sup> = [M] [L<sup>2</sup> T<sup>&ndash;2</sup>]<br />
= [M L<sup>2</sup> T<sup>&ndash;2</sup>]<br />
The dimensions of RHS are [M][L T<sup>&ndash;2</sup>] [L] = [M][L<sup>2</sup> T<sup>&ndash;2</sup>]<br />
= [M L<sup>2</sup> T<sup>&ndash;2</sup>]<br />
The dimensions of LHS and RHS are the same and hence the equation is dimensionally correct.<br />
&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>If the value of universal gravitational constant in SI is 6.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-11</sup> Nm<sup>2</sup>kg<sup>-2</sup>, then find its value in CGS system.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>G = 6.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-11</sup> Nm<sup>2</sup> kg<sup>-2</sup><br />
= 6.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-11</sup> Ng<sup>-1 </sup>m<sup>3</sup> kg<sup>-2</sup><br />
since,<br />
1 kg = 10<sup>3</sup> g<br />
1 m = 10<sup>2</sup> cm<br />
Hence<br />
= 6.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-11</sup> (10<sup>3</sup> g) (10<sup>2</sup> cm)3 s<sup>-2</sup><br />
= 6.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-11-3+3</sup> g<sup>-1</sup> cm<sup>3</sup> s<sup>-2</sup><br />
= 6.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-8</sup> g<sup>-1</sup> cm<sup>3</sup> s<sup>-2</sup><br />
&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>The Vander Wall&#39;s equation for a gas is&nbsp;<span class="math-tex">{tex}\\left(P+\\frac{a}{V^{2}}\\right){/tex}</span>(V - b) = RT<br />
Determine the dimensions of a and b. Hence write the SI units of a and b.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Since dimensionally similar quantities can be added or subtracted, therefore,<br />
[P] =&nbsp;<span class="math-tex">{tex}\\left[\\frac{a}{V^{2}}\\right]{/tex}</span><br />
or [a] =&nbsp;[PV<sup>2</sup>] = [ML<sup>-1</sup>&nbsp;T<sup>-2</sup>] [L<sup>3</sup>]<sup>2</sup> = ML<sup>5</sup>T<sup>-2</sup><br />
Also,&nbsp;[b] = [V] = L<sup>3</sup><br />
The SI unit of a is kg m<sup>5</sup>s<sup>-2</sup> and that of b is m<sup>3</sup>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>The mass of a box measured by a grocer&#39;s balance is 2.300 kg. Two gold pieces of masses 20.15 g and 20.17 g are added to the box. What is (a) the total mass of the box, (b) the difference in the masses of the pieces to correct significant figures?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Mass of grocer&#39;s box = 2.300 kg<br />
Mass of gold piece I = 20.15g = 0.02015 kg<br />
Mass of gold piece II = 20.17 g = 0.02017 kg</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Total mass of the box = 2.3 + 0.02015 + 0.02017 = 2.34032 kg<br />
	In addition, the final result should retain as many decimal places as there are in the number with the least decimal places. Hence, the total mass of the box is 2.3 kg.</li>
	<li>Difference in masses = 20.17 - 20.15 = 0.02 g<br />
	In subtraction, the final result should retain as many decimal places as there are in the number with the least decimal places.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Convert:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>3.0m/s<sup>2</sup> = .............. km/hr<sup>2</sup></li>
	<li>6.67 10<sup>-11</sup>Nm<sup>2</sup>/kg<sup>2</sup> = .............. g<sup>-1</sup>cm<sup>3</sup>s<sup>-2</sup></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>
	<div class="MsoNoSpacing" style="text-align:left; -webkit-text-stroke-width:0px">1 hour = 3600 sec&nbsp; &nbsp;so that 1 sec = 1/3600 hour&nbsp;<br />
	1 km = 1000 m&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;so that 1 m&nbsp;&nbsp;= 1/1000 km<br />
	3.0&nbsp;m s<sup>&ndash;2</sup>&nbsp;&nbsp;= 3.0 (1/1000 km)(&nbsp;1/3600 hour&nbsp;)<sup>-2</sup></div>
	&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;= 3.9 <span class="math-tex">{tex}\\times{/tex}</span>10<sup>4</sup> km/hr<sup>2</sup></li>
	<li>6.67 10<sup>-11</sup>Nm<sup>2</sup>/kg<sup>2</sup> = g<sup>-1</sup>cm<sup>3</sup>s<sup>-2</sup><br />
	<span class="math-tex">{tex}= 6.67 \\times 10 ^ { - 11 } k g ^ { - 1 } m ^ {3 } s ^ { - 2 }{/tex}</span><br />
	<span class="math-tex">{tex}= 6.67 \\times 10 ^ { - 11 } \\times 10 ^ { 3 } \\times \\left( 10 ^ { 2 } \\right) ^ { 3 }{/tex}</span><br />
	<span class="math-tex">{tex}= 6.67 \\times 10 ^ { - 8 } g ^ { - 1 } c m ^ { 3 } s ^ { - 2 }{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>The value G in CGS system is 6.67 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-8</sup> dyne cm<sup>2</sup> g<sup>-2</sup>.&nbsp;Calculate the value in SI units.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>As F =&nbsp;<span class="math-tex">{tex}G \\frac{m_{1} m_{2}}{r^{2}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;G =&nbsp;<span class="math-tex">{tex}\\frac{F r^{2}}{m_{1} m_{2}}{/tex}</span><br />
[G] =&nbsp;<span class="math-tex">{tex}\\frac{{MLT}^{-2} \\cdot {L}^{2}}{{MM}}{/tex}</span>&nbsp;=&nbsp;M<sup>-1</sup>L<sup>3</sup>T<sup>-2</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;a = -1, b = 3, c = -2<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;n<sub>2</sub> =&nbsp;<span class="math-tex">{tex}n_{1}\\left[\\frac{{M}_{1}}{{M}_{2}}\\right]^{a}\\left[\\frac{{L}_{1}}{{L}_{2}}\\right]^{b}\\left[\\frac{{T}_{1}}{{~T}_{2}}\\right]^{c}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}6.67 \\times 10^{-8}\\left[\\frac{1}{1000}\\right]^{-1}\\left[\\frac{1}{100}\\right]^{3}\\left[\\frac{1}{1}\\right]^{-2}{/tex}</span><br />
Hence in SI units,<br />
G = 6.67 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-11</sup> Nm<sup>2</sup> kg<sup>-2</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A gas bubble, from an explosion underwater, oscillates with a period T proportional to p<sup>a</sup> d<sup>b</sup> E<sup>c</sup>, where p is the static pressure, d is the density of water and E is the total energy of the explosion. Find the values of a, b and c.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let T = K p<sup>a</sup> d<sup>b</sup> E<sup>c</sup>,<br />
where K = a dimensionless constant.<br />
Putting the dimensions of various quantities,<br />
T = [ML<sup>-1</sup> T<sup>-2</sup>]<sup>a</sup> [ML<sup>-3</sup>]<sup>b</sup> [ML<sup>2</sup> T<sup>-2</sup>]<sup>c</sup><br />
or M<sup>0</sup>L<sup>0</sup>T = M<sup>a +b + c</sup> L<sup>~a ~3b + 2c</sup> T<sup>-2a - 2c</sup><br />
Equating the powers of M, L and T on both sides, we get<br />
a + b + c = 0, - a - 3b + 2c = 0, - 2a - 2c = 1<br />
On solving,<br />
a =&nbsp;<span class="math-tex">{tex}-\\frac{5}{6}{/tex}</span>, b =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>, c =&nbsp;<span class="math-tex">{tex}\\frac{1}{3}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>The density of mercury is 13.6 g cm<sup>-3</sup> in CGS system. Find its value in SI units.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>[Density] = M<sup>1</sup> L<sup>-3</sup><br />
n<sub>2</sub> = n<sub>1</sub><span class="math-tex">{tex}\\left[\\frac{{M}_{1}}{{M}_{2}}\\right]^{1}\\left[\\frac{{L}_{1}}{{L}_{2}}\\right]^{-3}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\text { 13.6 }\\left[\\frac{1 \\mathrm{~g}}{1 \\mathrm{~kg}}\\right]^{1}\\left[\\frac{1 \\mathrm{~cm}}{1 \\mathrm{~m}}\\right]^{-3}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\text { 13.6 }\\left[\\frac{1 \\mathrm{~g}}{1000 \\mathrm{~g}}\\right]\\left[\\frac{1 \\mathrm{~cm}}{100 \\mathrm{~cm}}\\right]^{-3}{/tex}</span>&nbsp;=&nbsp;13.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>3</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;13.6g cm<sup>-3</sup> = 13.6&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup> kgm<sup>-3</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The frequency &#39;<span class="math-tex">{tex}\\nu{/tex}</span>&#39;&nbsp;of vibration of stretched string depends&nbsp;upon</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>its length l,</li>
	<li>its&nbsp;mass per unit length &#39;m&#39; and</li>
	<li>the tension T in the string</li>
</ol>

<p>Obtain dimensionally an expression for frequency <span class="math-tex">{tex}\\nu{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let the frequency of vibration of the string be given by<br />
<span class="math-tex">{tex}\\nu{/tex}</span>&nbsp;=&nbsp;Kl<sup>a</sup>m<sup>b</sup>T<sup>c</sup>................(i)<br />
where K is a dimensionless constant<br />
Dimensions of the given&nbsp;quantities are<br />
<span class="math-tex">{tex}\\nu{/tex}</span>&nbsp;= [T<sup>-1</sup>], l = [L], T = [T], m =&nbsp;[ML<sup>-1&nbsp;</sup>and tension(T) =&nbsp;[MLT<sup>-2</sup>]<br />
Substituting these dimensions in equation (i), we get<br />
[T<sup>-1</sup>] = [L]<sup>a</sup>[ML<sup>-1</sup>]<sup>b</sup>[MLT<sup>-2</sup>]<sup>c</sup>&nbsp;<br />
Expanding the above equation we get<br />
[M<sup>0</sup>L<sup>0</sup>T<sup>-1</sup>] = [M<sup>b+c</sup>L<sup>a-b+c</sup>T<sup>-2c</sup>]<br />
Equate dimensions of M, L and T on both sides of equation (homogeneity rule), we get<br />
b + c = 0 ,a -b + c =0 and - 2c = -1<br />
on solving, a = -1,&nbsp;<span class="math-tex">{tex}b = - \\frac { 1 } { 2 } \\text { and } c = \\frac { 1 } { 2 }{/tex}</span>. Put these values in equation (i) we get<br />
<span class="math-tex">{tex}\\nu = K l ^ { - 1 } m ^ { - 1 / 2 } T ^ { 1 / 2 }{/tex}</span><br />
or,&nbsp;<span class="math-tex">{tex}\\nu = \\frac { K } { l } \\sqrt { \\frac { T } { m } }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Check the dimensional consistency of the following equations.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>de-Broglie wavelength,&nbsp;<span class="math-tex">{tex}\\lambda=\\frac{h}{m v}{/tex}</span></li>
	<li>&nbsp;Escape velocity,&nbsp; v =&nbsp;<span class="math-tex">{tex}\\sqrt{\\frac{2 G M}{R}}{/tex}</span></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Given,&nbsp;<span class="math-tex">{tex}\\lambda=\\frac{h}{m v}{/tex}</span><br />
	LHS as wavelength is a distance&nbsp;<span class="math-tex">{tex}\\lambda{/tex}</span>&nbsp;= [L]<br />
	Also RHS,&nbsp;<span class="math-tex">{tex}\\frac{h}{m v}=\\frac{\\text { Planck's constant }}{\\text { Mass } \\times \\text { Velocity }}{/tex}</span><br />
	=&nbsp;<span class="math-tex">{tex}\\frac{\\left[\\mathrm{ML}^2 \\mathrm{~T}^{-1}\\right]}{[\\mathrm{M}] \\times\\left[\\mathrm{LT}^{-1}\\right]}{/tex}</span>&nbsp;= [L]<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;LHS = RHS<br />
	Hence, the given equation is dimensionally correct.</li>
	<li>Here, v =&nbsp;<span class="math-tex">{tex}\\sqrt{\\frac{2 G M}{R}}{/tex}</span>&nbsp;<br />
	LHS v = [LT<sup>-1</sup>] RHS =&nbsp;<span class="math-tex">{tex}\\left[\\frac{2 G M}{R}\\right]^{1 / 2}{/tex}</span><br />
	G =&nbsp;<span class="math-tex">{tex}\\left[\\mathrm{M}^{-1} \\mathrm{~L}^3 \\mathrm{~T}^{-2}\\right], R=[\\mathrm{L}], M=[\\mathrm{M}]{/tex}</span><br />
	=&nbsp;<span class="math-tex">{tex}\\left[\\frac{M^{-1} \\mathrm{~L}^3 \\mathrm{~T}^{-2} \\mathrm{M}}{\\mathrm{L}}\\right]^{1 / 2}{/tex}</span>&nbsp;= [L<sup>2</sup>T<sup>-2</sup>]<sup>1/2</sup> = [LT<sup>-1</sup>]<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Dimensions of LHS = Dimensions of RHS<br />
	Hence, the equation is dimensionally correct.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A planet moves around the sun in nearly circular orbit. Its period of revolution T&nbsp;depends upon:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>radius <strong>r</strong> of orbit</li>
	<li>mass M&nbsp;of the sun and</li>
	<li>the gravitational constant G.<br />
	Show dimensionally that T<sup>2</sup> <span class="math-tex">{tex}\\propto{/tex}</span> r<sup>3</sup>.<br />
	Taking the proportionality constant as 2<span class="math-tex">{tex}\\pi{/tex}</span>, write the expression for T.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>it is given that, a planet moves around the sun in nearly circular orbitLet T = Kr<sup>a</sup> M<sup>b</sup> G<sup>c</sup><br />
where K = a dimensionless constant<br />
Dimensions of the various quantities are<br />
[T] = T,&nbsp;[r] = L, [M] = M<br />
[G] =&nbsp;<span class="math-tex">{tex}\\frac{F r^{2}}{m_{1} m_{2}}=\\frac{M L T^{-2}, L^{2}}{M M}{/tex}</span>&nbsp;=&nbsp;M<sup>-1</sup> L<sup>3</sup> T<sup>-2</sup><br />
Substituting these dimensions in equation (i), we get<br />
[T] = [L]<sup>a</sup> [M]<sup>b</sup> [M<sup>-1</sup>&nbsp;L<sup>3</sup>&nbsp;T<sup>-2</sup>]<sup>c</sup><br />
M<sup>0</sup>L<sup>0</sup>T<sup>1</sup> M<sup>b - c</sup> L<sup>a + 3c</sup> T<sup>-2c</sup><br />
Equating the dimensions of M, L and T, we get<br />
b - c = 0, a + 3c = 0, -2c = 1<br />
On solving,<br />
a =&nbsp;<span class="math-tex">{tex}\\frac{3}{2}{/tex}</span>, b =<span class="math-tex">{tex}-\\frac{1}{2}{/tex}</span>, c =&nbsp;<span class="math-tex">{tex}-\\frac{1}{2}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;T =&nbsp;Kr<sup>3/2</sup>&nbsp;M<sup>-1/2</sup> G<sup>-1/2</sup><br />
or T<sup>2</sup> =&nbsp;<span class="math-tex">{tex}\\frac{K^{2} r^{3}}{M G}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}T^{2} \\propto r^{3}{/tex}</span><br />
As K = 2<span class="math-tex">{tex}\\pi{/tex}</span>, so T =&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{r^{3}}{G M}}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The velocity v&nbsp;of water waves depends on the wavelength <span class="math-tex">{tex}\\lambda{/tex}</span>, density of water <span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;and the acceleration due to gravity g. Deduce by the method of dimensions the relationship between these quantities.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given that, the velocity v&nbsp;of water waves depends on the wavelength <span class="math-tex">{tex}\\lambda{/tex}</span>, density of water <span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;and the acceleration due to gravity g.</p>

<p>Let v = <span class="math-tex">{tex}K \\lambda^{a} \\rho^{b} g^{c}{/tex}</span>&nbsp;... (i)<br />
where K = a dimensionless constant.<br />
Dimensions of the various quantities are<br />
[v] = LT<sup>-1</sup>,&nbsp;[<span class="math-tex">{tex}\\lambda{/tex}</span>] = L,&nbsp;[<span class="math-tex">{tex}\\rho{/tex}</span>] = ML<sup>-3</sup>,&nbsp;[g] = LT<sup>-2</sup><br />
Substituting these dimensions in equation (i), we get<br />
[LT<sup>-1</sup>] = [L]<sup>a</sup>&nbsp;[ML<sup>-3</sup>]<sup>b</sup>[LT<sup>-2</sup>]<sup>c</sup><br />
M<sup>0</sup> L<sup>1</sup> T<sup>-1</sup> = M<sup>b</sup>L<sup>a - 3b + c</sup>&nbsp;T<sup>-2c</sup><br />
Equating the powers of M, L and T on both sides,<br />
b = 0, a - 3b + c = 1, -2c = - 1<br />
On solving, a =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>, b = 0, c =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;v =&nbsp;<span class="math-tex">{tex}K \\lambda^{\\frac{1}{2}} \\rho^{0} g^{\\frac{1}{2}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}K \\sqrt{\\lambda g}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Round off the following numbers as indicated:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>18.35 up to 3 digits</li>
	<li>143.45 up to 4 digits</li>
	<li>18967 up to 3 digits</li>
	<li>12.653 up to 3 digits</li>
	<li>248337 upto 3 digits</li>
	<li>321.135 upto 5 digits</li>
	<li>101.55 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>6</sup> upto 4 digits</li>
	<li>31.325 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup> upto 4 digits</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>18.4</li>
	<li>143.4</li>
	<li>19000</li>
	<li>12.7</li>
	<li>248000</li>
	<li>321.14</li>
	<li>101.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>6</sup></li>
	<li>31.32 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Obtain dimensions of:</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>impulse</li>
	<li>power</li>
	<li>surface energy</li>
	<li>coefficient of viscosity</li>
	<li>bulk modulus</li>
	<li>force constant</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>Impulse - [MLT<sup>-1</sup>]</li>
	<li>Power - [M<sup>1</sup>L<sup>2</sup>T<sup>-3</sup>]</li>
	<li>Surface tension - [M<sup>1</sup>T<sup>-2</sup>]</li>
	<li>Coefficient of viscosity - [M<sup>1</sup>L<sup>-1</sup>T<sup>-1</sup>]</li>
	<li>Bulk modulus - [M<sup>1</sup>L<sup>-1</sup>T<sup>-2</sup>]</li>
	<li>Force constant - [M<sup>1</sup>L<sup>0</sup>T<sup>-2</sup>]</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The frequency v of an oscillating drop may depend upon radius r of the drop, density <span class="math-tex">{tex}\\rho{/tex}</span> of the liquid and surface tension S of the liquid. Establish an expression for v dimensionally.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let =&nbsp;<span class="math-tex">{tex}v=K r^{a} \\rho^{b} S^{c}{/tex}</span>&nbsp;... (i)<br />
where K = a dimensionless constant.<br />
Dimensions of various quantities are<br />
[v] = T<sup>-1</sup>, [r] = L, [<span class="math-tex">{tex}\\rho{/tex}</span>] = ML<sup>-3</sup>, [S] = MT<sup>-2</sup><br />
Substituting these dimensions in equation (i), we get<br />
T<sup>-1</sup> = [L]<sup>a</sup> [ML<sup>-3</sup>]<sup>b</sup>&nbsp;[MT<sup>-2</sup>]<sup>c</sup><br />
or&nbsp;M<sup>0</sup>L<sup>0</sup>T<sup>-1</sup> = M<sup>b + c</sup> L<sup>a - 3b</sup> T<sup>-2c</sup><br />
By using principle of homogeneity of equations and Equating the powers of M, L and T on both sides,<br />
b + c = 0, a - 3b = 0, - 2c = -1<br />
On solving,<br />
a = <span class="math-tex">{tex}-\\frac{3}{2}{/tex}</span>,&nbsp;b = <span class="math-tex">{tex}-\\frac{1}{2}{/tex}</span>, c =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>, substituting these values in equation (i), we get<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}v=K r^{-3 / 2} \\rho^{-1 / 2} S^{1 / 2}=K \\sqrt{\\frac{S}{\\rho r^{3}}}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Deduce dimensional formulae for:</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>angle</li>
	<li>angular velocity</li>
	<li>angular acceleration</li>
	<li>torque</li>
	<li>angular momentum and</li>
	<li>moment of inertia.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Dimensional formulae of the following</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>angle - dimensionless</li>
	<li>angular velocity - [T<sup>-1</sup>]</li>
	<li>angular acceleration - [LT<sup>-2</sup>]</li>
	<li>torque - [MLT<sup>-2</sup>]</li>
	<li>angular momentum - [ML<sup>2</sup>T<sup>-1</sup>]</li>
	<li>moment of inertia - [ML<sup>2</sup>]</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Assuming that the mass M of the largest stone that can be moved by a flowing river depends upon v&nbsp;the velocity, <span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;the density of water and on g, the acceleration due to gravity. Show that M varies with the sixth power of the velocity of flow.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to question, the mass M of the largest stone that can be moved by a flowing river depends upon v&nbsp;the velocity, <span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;the density of water and on g, the acceleration due to gravity<br />
​​​​​​​Let M = Kv<sup>a</sup> <span class="math-tex">{tex}\\rho{/tex}</span><sup>b</sup> g<sup>c</sup><br />
where K = a dimensionless constant.<br />
Dimensions of the various quantities are<br />
[M] = M, [v]= LT<sup>-1</sup> [<span class="math-tex">{tex}\\rho{/tex}</span>] = ML<sup>-3</sup>, [g] = LT<sup>-2</sup><br />
Substituting these dimensions in equation&nbsp;(i), we get<br />
[M] = [LT<sup>-1</sup>]<sup>a</sup>[ML<sup>-3</sup>]<sup>b</sup> [LT<sup>-2</sup>]<sup>c</sup><br />
M<sup>1</sup> L<sup>0</sup> T<sup>0</sup> = M<sup>b</sup> L<sup>a - 3b + c</sup> T<sup> -a -2 c</sup><br />
Equating the powers of M, L and T, we get<br />
b = 1, a - 3b + c = 0, - a - 2c = 0<br />
On solving, a = 6, b = 1, c = -3<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;M =&nbsp;<span class="math-tex">{tex}K v^{6} \\rho^{1} g^{-3}{/tex}</span><br />
Hence M&nbsp;<span class="math-tex">{tex}\\propto{/tex}</span>&nbsp;v<sup>6</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A book with many printing errors contains four different formulas for the displacement y of a particle undergoing a certain periodic motion:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li><span class="math-tex">{tex}y = a \\sin \\left( \\frac { 2 \\pi t } { T } \\right){/tex}</span></li>
	<li><span class="math-tex">{tex}y = \\left( \\frac { a } { T } \\right) \\sin \\frac { t } { a }{/tex}</span></li>
	<li><span class="math-tex">{tex}y = ( a \\sqrt { 2 } ) \\left( \\sin \\frac { 2 \\pi t } { T } + \\cos \\frac { 2 \\pi t } { T } \\right){/tex}</span></li>
</ol>

<p>(a = maximum displacement of the particle, v = speed of the particle. T = time-period of motion). Rule out the wrong formulas on dimensional grounds.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>The given equation is:<br />
	<span class="math-tex">{tex}y = a \\sin \\frac { 2 \\pi t } { T }{/tex}</span><br />
	Dimension of y = M<sup>0</sup>L<sup>1</sup>T<sup>0</sup><br />
	Dimension of a = M<sup>0</sup>L<sup>1</sup>T<sup>0</sup><br />
	Dimension of <span class="math-tex">{tex}\\sin \\frac { 2 \\pi t } { T } = M ^ { 0 } L ^ { 0 } T ^ { 0 }{/tex}</span><br />
	<span class="math-tex">{tex}\\because{/tex}</span>&nbsp;Dimension of L.H.S = Dimension of R.H.S<br />
	Hence, the given formula is dimensionally correct.</li>
	<li>The given equation is:<br />
	<span class="math-tex">{tex}y = \\left( \\frac {a } { T } \\right) \\sin \\left( \\frac { t } { a} \\right){/tex}</span><br />
	Dimension of y = M<sup>0</sup>L<sup>1</sup>T<sup>0</sup><br />
	Dimension of&nbsp;<span class="math-tex">{tex}\\frac { a } { T } = M ^ { 0 } L ^ { 1 } T ^ { - 1 }{/tex}</span><br />
	Dimension of <span class="math-tex">{tex}\\frac { t } { a } = M ^ { 0 } L ^ { - 1 } T ^ { l }{/tex}</span><br />
	But the argument of the trigonometric function must be dimensionless, which is not so in the given case. Hence, the formula is dimensionally incorrect.</li>
	<li>The given equation is:<br />
	<span class="math-tex">{tex}y = (a \\sqrt { 2 } ) \\left( \\sin 2 \\pi \\frac { t } { T } + \\cos 2 \\pi \\frac { t } { T } \\right){/tex}</span><br />
	Dimension of y = M<sup>0</sup>L<sup>1</sup>T<sup>0</sup><br />
	Dimension of a = M<sup>0</sup>L<sup>1</sup>T<sup>0</sup><br />
	Dimension of <span class="math-tex">{tex}\\frac { t } { T } = M ^ { 0 } I ^ { 0 } T ^ { 0 }{/tex}</span><br />
	Since the argument of the trigonometric function must be dimensionless (which is true in the given case), the dimensions of y and a are the same. Hence, the given formula is dimensionally correct.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Give the definitions for SI unit of seven basic quantities.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The seven basic quantities are length, mass, time, electric current, thermodynamic temperature, amount of substance and luminous intensity.<br />
The&nbsp;symbols and&nbsp;definitions of SI units of seven basic quantities are:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li><strong>Length - </strong>Its SI unit is metre (m). A metre is defined as the length of the path travelled by light in a vacuum during a time interval of <span class="math-tex">{tex}\\frac{1}{299792458}{/tex}</span>of a second.<br />
	&nbsp;</li>
	<li><strong>Mass - </strong>Its SI unit is kilogram (kg).&nbsp;It is equal to the mass of the international prototype of kilogram (a platinum-iridium alloy cylinder) kept at International Bureau of Weights and Measures at Sevres, near Paris, France.<br />
	&nbsp;</li>
	<li><strong>Time- </strong>Its SI unit is&nbsp;second (s).&nbsp;A second is defined as the duration of 9,192,631,770 periods of the radiation corresponding to the transition between the two hyperfine levels of the ground state of the cesium-133 atom.<br />
	&nbsp;</li>
	<li><strong>Electric current- </strong>Its SI unit is&nbsp;ampere (A). The ampere is defined as that constant current which, if maintained in two straight parallel conductors of infinite length, of negligible circular cross-section, and placed 1 m apart in a vacuum, would produce a force between these conductors equal to 2 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-7</sup> N per metre of length.<br />
	&nbsp;</li>
	<li><strong>Thermodynamic temperature- </strong>Its SI unit is&nbsp;kelvin (K). The Kelvin is defined as the fraction&nbsp;<span class="math-tex">{tex}\\frac{1}{273.16}{/tex}</span> of the thermodynamic temperature of the triple point of water.<br />
	&nbsp;</li>
	<li><strong>Amount of substance- </strong>Its SI unit is&nbsp;mole (mol). The mole is defined as the amount of substance of a system, which contains as many elementary entities as there are atoms in 0.012 kg of carbon-12.<br />
	&nbsp;</li>
	<li><strong>Luminous intensity- </strong>Its SI unit is&nbsp;candela (cd). The candela is defined as the luminous intensity, in a given direction of a source that emits monochromatic radiation of frequency 540 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>12</sup> Hz and that has a radiant intensity in that direction of&nbsp;<span class="math-tex">{tex}\\frac{1}{683}{/tex}</span>&nbsp;watt per steradian.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The velocity of sound waves v through a medium may be assumed to depend on:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the density of the medium d&nbsp;and</li>
	<li>the modulus of elasticity E.<br />
	Deduce by the method of dimensions the formula for the velocity of sound. Take dimensional constant K = 1.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let the velocity of the sound waves be given by<br />
v = Kd<sup>a</sup>E<sup>b</sup>&nbsp;... (i)<br />
where, K is a dimensionless constant.<br />
Dimensions of the various quantities are given by&nbsp;</p>

<p><br />
[v] =&nbsp;LT<sup>-1</sup>,&nbsp;[d] = ML<sup>-3</sup><br />
[E] =&nbsp;<span class="math-tex">{tex}\\frac{\\text { stress }}{\\text { strain }}=\\frac{\\text { force }}{\\text { area } \\times \\text { strain }}=\\frac{{MLT}^{-2}}{{L}^{2} .1}{/tex}</span>&nbsp;=&nbsp;ML<sup>-1</sup>T<sup>-2</sup><br />
Substituting these dimensions in equation (i), we get<br />
[LT<sup>-1</sup>] = [ML<sup>-3</sup>]<sup>a</sup> [ML<sup>-1</sup>&nbsp;T<sup>-2</sup>]<sup>b</sup><br />
or&nbsp;M<sup>0</sup>L<sup>1</sup>T<sup>-1</sup> = M<sup>a+b</sup> L<sup>-3a - b</sup>T<sup>-2b</sup><br />
Equating the dimensions of M, L and T, we get<br />
a + b = 0, -3a - b = 1, -2b = -1<br />
On solving, a =&nbsp;<span class="math-tex">{tex}-\\frac{1}{2}{/tex}</span>, b =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;v = <span class="math-tex">{tex}kd^{\\frac{-1}{2}} E^{\\frac{1}{2}}{/tex}</span><br />
or v =&nbsp;<span class="math-tex">{tex}\\sqrt{\\frac{E}{d}}{/tex}</span>&nbsp;.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Explain this statement clearly:<br />
To call a dimensional quantity <strong>large</strong> or <strong>small</strong> is meaningless without specifying a standard for comparison. In view of this, reframe the following statements wherever necessary:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>atoms are very small objects.</li>
	<li>a jet plane moves with great speed.</li>
	<li>the mass of Jupiter is very large.</li>
	<li>the air inside this room contains a large number of molecules.</li>
	<li>a proton is much more massive than an electron.</li>
	<li>the speed of&nbsp;sound is much smaller than the speed of light.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Measurement is basically a comparison process. Without specifying a standard of comparison, it is not possible to get an exact idea about the magnitude of a dimensional quantity. For example, the mass of a human being&nbsp;is 40 kg, which is very small in comparison to the mass of the earth (6&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>24</sup> kg) but very large in comparison to the mass of an electron (9.1&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-31</sup> kg).</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>&nbsp;An atom is a very small object when we compare it with a cricket ball.</li>
	<li>A jet plane moves with a speed greater when we compare it with a motor bike.</li>
	<li>The mass of Jupiter is very large as compared to the mass of Venus.</li>
	<li>The air inside this room contains a large number of molecules than in one mole of air.</li>
	<li>The given statement is already correct.</li>
	<li>Speed of sound is less than the speed of light. Speed of sound 346 m/ sec while speed of light is 3 x 10<sup>8</sup>&nbsp;m / sec in air at 25&nbsp;<sup>0</sup>C, hence statement is true.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>By using dimensional analysis, derive an expression for the height (h) to which a liquid of density (<span class="math-tex">{tex}\\rho{/tex}</span>) and surface tension (S) will rise in a capillary tube of radius (r). Given acceleration due to gravity is g and h <span class="math-tex">{tex}\\propto{/tex}</span> <span class="math-tex">{tex}\\frac1r{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let h =&nbsp;<span class="math-tex">{tex}K \\rho^{a} S^{b} g^{c} \\times \\frac{1}{r}{/tex}</span>&nbsp;... (i)<br />
where K = a dimensionless constant.<br />
Dimensions of the various quantities are<br />
[h] = L, [<span class="math-tex">{tex}\\rho{/tex}</span>] = ML<sup>-3</sup>, [S]&nbsp;= MT<sup>-2</sup>, [g] = LT<sup>-2</sup>, [r] = L<br />
Substituting the dimensions of various quantities in&nbsp;(i), we get<br />
L = [ML<sup>-3</sup>]<sup>a</sup> [MT<sup>-2</sup>]<sup>b</sup> [LT<sup>-2</sup>]<sup>c</sup> [L<sup>-1</sup>]<br />
or M<sup>0</sup>L<sup>1</sup>T<sup>0</sup> = M<sup>a + b</sup> L<sup>-3a + c + 1</sup> T<sup>-2b - 2c</sup><br />
Equating the powers of M, L and T, we get<br />
a + b = 0, - 3a + c - 1 = 1, - 2b - 2c = 0<br />
On solving, a = -1, b = 1, c = -1<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;h =&nbsp;<span class="math-tex">{tex}K \\rho^{-1} S^{1} g^{-1} \\times \\frac{1}{r}{/tex}</span>&nbsp;or h =&nbsp;<span class="math-tex">{tex}K \\frac{S}{r \\rho g}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>How will you convert a physical quantity from one unit system to another by method of dimensions?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If a given quantity&nbsp;is measured in two different unit system, then Q = n<sub>1</sub>u<sub>1</sub> = n<sub>2</sub>u<sub>2</sub><br />
Let the dimensional formula of the quantity be&nbsp;<span class="math-tex">{tex}\\left[\\mathrm{M}^a \\mathrm{~L}^b \\mathrm{~T}^c\\right]{/tex}</span><br />
then we have n<sub>1</sub>&nbsp;<span class="math-tex">{tex}\\left[\\mathrm{M}_1^a \\mathrm{~L}_1^b \\mathrm{~T}_1^c\\right]=n_2\\left[\\mathrm{M}_2^a \\mathrm{~L}_2^b \\mathrm{~T}_2^c\\right]{/tex}</span><br />
Here M<sub>1</sub>,&nbsp;L<sub>1</sub>, T<sub>1</sub>&nbsp;are the fundamental unit of mass, length and time in first unit system and M<sub>2</sub>, L<sub>2</sub>, T<sub>2</sub> in the second unit system.<br />
Hence, n<sub>2</sub> = n<sub>1</sub><span class="math-tex">{tex}\\left[\\frac{\\mathrm{M}_1}{\\mathrm{M}_2}\\right]^a\\left[\\frac{\\mathrm{L}_1}{\\mathrm{~L}_2}\\right]^b\\left[\\frac{\\mathrm{T}_1}{\\mathrm{~T}_2}\\right]^c{/tex}</span><br />
This relation helps us to convert a physical quantity from one unit system to another.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Reynold number N<sub>R</sub> (a dimensionless quantity) determines the condition of laminar flow of a viscous liquid through a pipe. N<sub>R</sub> is a function of the density of the liquid <span class="math-tex">{tex}\\rho{/tex}</span>, its average speed v&nbsp;and coefficient of viscosity <span class="math-tex">{tex}\\eta{/tex}</span>. Given that N<sub>R</sub> is also directly proportional to D&nbsp;(the diameter of the pipe), show from dimensional considerations that N<sub>R</sub>&nbsp;<span class="math-tex">{tex}\\propto{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{\\rho v D}{\\eta}{/tex}</span>.&nbsp;The unit of <span class="math-tex">{tex}\\eta{/tex}</span> in SI system is kg m<sup>-1</sup>s<sup>-1</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>given that Reynold number N<sub>R</sub> (a dimensionless quantity) determines the condition of laminar flow of a viscous liquid through a pipe therefore</p>

<p>Let&nbsp;N<sub>R</sub> = <span class="math-tex">{tex}K \\rho^{a} v^{b} \\eta^{c} D{/tex}</span>&nbsp;... (i)<br />
where K = a dimensionless constant.<br />
Dimensions of various quantities are<br />
[N<sub>R</sub>] = 1 = M<sup>0</sup> L<sup>0</sup> T<sup>0</sup><br />
[<span class="math-tex">{tex}\\rho{/tex}</span>] = ML<sup>-3</sup>, [v] = LT<sup>-1</sup><br />
[<span class="math-tex">{tex}\\eta{/tex}</span>] = ML<sup>-1</sup> T<sup>-1</sup>, [D] = L<br />
Substituting these dimensions in equation (i), we get<br />
[M<sup>0</sup> L<sup>0</sup>&nbsp;T<sup>0</sup>] = [ML<sup>-3</sup>]<sup>a</sup> [LT<sup>-1</sup>]<sup>b</sup> [ML<sup>-1</sup> T<sup>-1</sup>]<sup>c</sup> [L]<br />
[M<sup>0</sup> L<sup>0</sup>&nbsp;T<sup>0</sup>] = M<sup><span style="font-size: 10.8333px;">a + c</span></sup>&nbsp;L<sup>-3 a+ </sup><sup>b - c + 1</sup> T<sup>-b - c</sup><br />
Equating the powers of M, L and T, we get<br />
a + c = 0, -3a + b - c + 1 = 0, -b - c = 0<br />
On solving, a = 1, b= 1, c = - 1<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;N<sub>R</sub> =&nbsp;<span class="math-tex">{tex}K \\rho^{1} v^{1} \\eta^{-1}{/tex}</span>&nbsp;D =&nbsp;<span class="math-tex">{tex}K \\frac{\\rho v D}{\\eta}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}N_{R} \\propto \\frac{\\rho v D}{\\eta}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The length, breadth and thickness of a rectangular sheet of metal are 4.234 m, 1.005m, and 2.01 cm respectively. Give the area and volume of the sheet to correct significant figures.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Length of sheet, l = 4.234 m<br />
Breadth of sheet, b = 1.005 m<br />
Thickness of sheet, h = 2.01 cm = 0.0201 m<br />
The given table lists the respective significant figures:</p>

<table border="1" cellpadding="3" cellspacing="0" style="width:100%;">
	<thead>
		<tr>
			<th scope="col">Qunatity</th>
			<th scope="col">Number</th>
			<th scope="col">Significant Figure</th>
		</tr>
	</thead>
	<tbody>
		<tr>
			<td style="text-align: center;">l</td>
			<td style="text-align: center;">4.234</td>
			<td style="text-align: center;">4</td>
		</tr>
		<tr>
			<td style="text-align: center;">b</td>
			<td style="text-align: center;">1.005</td>
			<td style="text-align: center;">4</td>
		</tr>
		<tr>
			<td style="text-align: center;">h</td>
			<td style="text-align: center;">0.0201</td>
			<td style="text-align: center;">3</td>
		</tr>
	</tbody>
</table>

<p>Hence, area and volume both must have at least 3 significant figures.<br />
Now, surface area of the sheet = 2 (l &times; b + b &times; h + h &times; l)<br />
= 2(4.234 &times; 1.005 + 1.005 &times; 0.0201 + 0.0201 &times; 4.234)<br />
= 2(4.25517 + 0.0202005 + 0.0851034)<br />
= 2 &times; 4.36<br />
= 8.72 m2 (three significant figures)<br />
Volume of the sheet =&nbsp;<span class="math-tex">{tex}=l\\times b \\times h{/tex}</span><br />
= 4.234 &times; 1.005 &times; 0.0201<br />
= 0.0855 m<sup>3&nbsp;</sup>&nbsp;(three significant figures)<br />
This number has only 3 significant figures i.e., 8, 5, and 5.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define dimensional formula. Give uses of dimensional analysis. Write down the limitations of dimensional analysis.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Dimension formula tells about which fundamental quantities are there in the physical quantity given.<br />
It is represented in square brackets. For example length is denoted as [L]<br />
If we know the physical quantities on which are used in the formula, dimensional analysis can be used to calculate the how the powers of these quantities will vary. For example if we know that the velocity depends upon length and time we can calculate the powers of the base quantities.<br />
[L<sup>1</sup>M<sup>0</sup>T<sup>&minus;1</sup>] = [L<sup>a</sup>M<sup>b</sup>T<sup>c</sup>] now a, b, c can be calculated.<br />
The very limitation of the dimensional analysis is if the given formula carries the sum of two quantities and if only one of those quantities is provided dimensional analysis can&rsquo;t be used to verify if the formula is correct or not.<br />
s = ut<br />
s = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> at<sup>2</sup><br />
Both are dimensionally correct but the formula is not correct form of equation of motion.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Derive dimensionally the relation: S = ut&nbsp;+&nbsp;<span class="math-tex">{tex}\\frac{1}{2} a t^{2}{/tex}</span></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let S = Ku<sup>x</sup> a<sup>y</sup>- t<sup>z</sup>,<br />
where K = a dimensionless constant.<br />
Putting dimensions of various quantities,<br />
L = [LT<sup>-1</sup>]<sup>x</sup> [LT<sup>-2</sup>]<sup>y</sup> [T]<sup>z</sup><br />
or L<sup>1</sup>T<sup>0</sup> =L<sup>x + y</sup>T<sup>x - 2y + z</sup><br />
Equating the powers of M, L and T, we get<br />
x + y = 1<br />
-x - 2y + z = 0<br />
These two equations cannot be solved for three unknowns x, y and z. The problem is split into two parts.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Suppose the body has no acceleration. Then<br />
	S = X<sub>1</sub> u<sup>x</sup> t<sup>z</sup><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;L = [LT<sup>-1</sup>]<sup>x</sup> [T]<sup>2</sup> = L<sup>x</sup>T<sup>-x</sup>X<sup>+z</sup><br />
	Equating the powers of L and T, x = 1, - x + z =0<br />
	On solving, x = 1, z = 1<br />
	Hence, S = k<sub>1</sub> ut</li>
	<li>Suppose the body has no initial velocity.<br />
	Then<br />
	S = K<sub> 2</sub>a<sup>y</sup> t<sup>z</sup><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;L = [LT<sup>-2</sup>]<sup>y</sup> [T]<sup>z</sup> =L<sup>y</sup>T<sup>-2y + z</sup><br />
	Equating the powers of L and T, y = 1, -2y + z = 0<br />
	On solving, y = 1, z = 2<br />
	Hence S = K<sub>2</sub> at<sup>2</sup></li>
	<li>Suppose the body has both acceleration and initial velocity.<br />
	Then<br />
	S = K<sub>1</sub> ut + K<sub>2</sub> at<sup>2</sup><br />
	It is found that K<sub>1</sub> = 1 and K<sub>2</sub> = <span class="math-tex">{tex}\\frac12{/tex}</span>. Therefore,<br />
	S = ut +&nbsp;<span class="math-tex">{tex}\\frac{1}{2} a t^{2}{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>If velocity of light C, Planck&rsquo;s constant h and gravitational constant G are taken as fundamental quantities then express mass in terms of dimensions of these quantities.<br />
<strong>Main concept used:&nbsp;</strong>Homogeneity of dimensions in R.H.S and L.H.S. of equation separately in each terms.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Dimension of h =&nbsp;<span class="math-tex">{tex}{E \\over \\nu } = {{[M{L^2}{T^{ - 2}}]} \\over {[{T^{ - 1}}]}} = [M{L^2}{T^{ - 1}}]{/tex}</span>&nbsp;&nbsp;<br />
Dimensions of c&nbsp;= [LT<sup>-1</sup>]<br />
Dimension of G = N-m<sup>2&nbsp;</sup>Kg<sup>-2&nbsp;</sup>= [MLT<sup>-2</sup>] [L<sup>2</sup>][M<sup>-2</sup>] = [M<sup>-1</sup>L<sup>3</sup>T<sup>-2</sup>]<br />
Let Mass m&nbsp;<span class="math-tex">{tex}\\alpha {/tex}</span> [h]<sup>a</sup>[c]<sup>b</sup>[G]<sup>c</sup><br />
[M<sup>1</sup>L<sup>0</sup>T<sup>0</sup>] = k [ML<sup>2</sup>T<sup>-1</sup>]<sup>a&nbsp;</sup>[LT<sup>-1</sup>]<sup>b</sup>[M<sup>-1</sup>L<sup>3</sup>T<sup>-2</sup>]<sup><span style="font-size: 12px;">c</span></sup><br />
[M<sup>1</sup>L<sup>0</sup>T<sup>0</sup>] = k [M<sup>a-c&nbsp;</sup>L<sup>2a+b+3c</sup>T<sup>-a-b-2c</sup>]<br />
On comparing the powers of M, L, T on both side we get<br />
a-c = 1 <span class="math-tex">{tex}\\Rightarrow{/tex}</span>a = c+1&nbsp;.........(i) &nbsp;<br />
2a+b+3c = 0&nbsp; ........(ii)<br />
-a -b -2c = 0&nbsp; ........(iii)<br />
a = c+1&nbsp; &nbsp; &nbsp; [from equation (i)]<br />
By putting the value of a in equation (ii) &amp; (iii), we get<br />
2(c+1)+b+3c = 0<br />
2c+2+b+3c = 0<br />
b+5c = -2 .........(iv)<br />
and -(c+1)-b-2c=0<br />
-b-3c = 1 ..........(v)<br />
From equations (iv) &amp; (v), we obtain on adding&nbsp;<br />
c =&nbsp;<span class="math-tex">{tex} - {1 \\over 2}{/tex}</span><br />
So,&nbsp;<span class="math-tex">{tex}a = c + 1{/tex}</span>&nbsp;<span class="math-tex">{tex}= - \\frac { 1 } { 2 } + 1 = \\frac { 1 } { 2 }{/tex}</span><br />
Put the value of c in equation (iv), we get<br />
<span class="math-tex">{tex} b + 5 \\left( - \\frac { 1 } { 2 } \\right) = - 2{/tex}</span><br />
<span class="math-tex">{tex}b = - 2 + \\frac { 5 } { 2 }{/tex}</span><br />
<span class="math-tex">{tex}b = \\frac { 1 } { 2 } , a = \\frac { 1 } { 2 } \\text { and } c = - \\frac { 1 } { 2 }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore m = k h ^ { \\frac { 1 } { 2 } } c ^ { \\frac { 1 } { 2 } } G ^ { - \\frac { 1 } { 2 } }{/tex}</span>&nbsp;&nbsp;<br />
<span class="math-tex">{tex}m = k\\sqrt {{{hc} \\over G}} {/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Write down the classification of physical quantities on the basis of dimension.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Dimension, an expression of the character of a derived quantity in relation to fundamental quantities, without regard for its numerical value. In any system of measurement, such as the metric system, certain quantities are considered fundamental, and all others are considered to be derived from them.<br />
Physical quantities are classified on the basis of dimension into two groups</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>Dimensional physical quantities: These are further classified into<br />
	Dimensional constants: These are the quantities which possess dimensions and have a fixed value.<br />
	Ex: Gravitational Constant<br />
	Dimensional variables: These are the quantities which possess dimensions and do not have a fixed value<br />
	For example, velocity, acceleration etc.</li>
	<li>Dimensionless physical quantities: These are further classified into<br />
	Dimensionless constants: These are the quantities which do not possess dimensions and have a fixed value.<br />
	For example <span class="math-tex">{tex}\\pi{/tex}</span> etc.<br />
	Dimensionless variables: These are the quantities which are dimensionless and do not have a fixed value.<br />
	For example Strain, Specific Gravity etc.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Show that the fractional error in the nth power of a quantity is equal to n times the fractional error in the quantity itself. State the general rule for evaluating the error in a combined calculation.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let the n<sup>th</sup> power of A is Z.<br />
Z = A<sup>n</sup><br />
The error <span class="math-tex">{tex}\\Delta Z{/tex}</span> in Z is given as,<br />
<span class="math-tex">{tex}Z \\pm \\Delta Z=(A \\pm \\Delta A)^{n}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{Z} \\pm \\Delta \\mathrm{Z}=\\mathrm{A}^{\\mathrm{n}}\\left(1 \\pm \\frac{\\Delta \\mathrm{A}}{\\mathrm{A}}\\right)^{\\mathrm{n}}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{Z} \\pm \\Delta \\mathrm{Z}=\\mathrm{Z}\\left(1 \\pm \\frac{\\Delta \\mathrm{A}}{\\mathrm{A}}\\right)^{\\mathrm{n}}{/tex}</span><br />
<span class="math-tex">{tex}1 \\pm \\frac{\\Delta Z}{Z}=\\left(1 \\pm n \\frac{\\Delta A}{A}\\right){/tex}</span><br />
<span class="math-tex">{tex}\\frac{\\Delta \\mathrm{Z}}{\\mathrm{Z}}=\\mathrm{n} \\frac{\\Delta \\mathrm{A}}{\\mathrm{A}}{/tex}</span><br />
It can be shown that the fractional error in the n<sup>th</sup> power of a quantity is n times the fractional error in that quantity.<br />
The general rule is given as,<br />
If <span class="math-tex">{tex}Z=\\frac{A^{p} B^{q}}{C^{r}}{/tex}</span>, then maximum fractional error in Z is given as,<br />
<span class="math-tex">{tex}\\frac{\\Delta \\mathrm{Z}}{\\mathrm{Z}}=\\mathrm{p} \\frac{\\Delta \\mathrm{A}}{\\mathrm{A}}+\\mathrm{q} \\frac{\\Delta \\mathrm{B}}{\\mathrm{B}}+\\mathrm{r} \\frac{\\Delta \\mathrm{C}}{\\mathrm{C}}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1342-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_MOTION_IN_A_STRAIGHT_LINE = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><html><body><p>The displacement-time graphs of two moving particles make angles of 30° and 45° with the time axis. The ratio of their velocities is:<br/>
<img alt="" data-imgur-src="PFTyTpC.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354874-mzy7rg.jpg" style="width: 150px; height: 127px;"/></p></body></html></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt 3{/tex}</span> : 2</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">1 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">1 : 2</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">1 : <span class="math-tex">{tex}\\sqrt 3{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><html><body><p>Slope of displacement-time graph gives velocity.<br/>
<span class="math-tex">{tex}\\therefore \\quad \\frac{v_{1}}{v_{2}}=\\frac{\\tan \\theta_{1}}{\\tan \\theta_{2}}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\tan 30^{\\circ}}{\\tan 45^{\\circ}}=\\frac{1}{\\sqrt{3}}{/tex}</span><br/>
<img alt="" data-imgur-src="nSf13jY.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354878-gv5cpz.jpg" style="width: 150px; height: 134px;"/> </p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>In uniform motion, magnitude of displacement is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">equal to distance</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>equal to distance</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">greater than distance</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">less than distance</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">greater or equal to distance</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The position x of a particle varies with time t as x = at<sup>2</sup> - bt<sup>3</sup>. The acceleration will be zero at time t equal to:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{a}{3 b}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>v = <span class="math-tex">{tex}\\frac{\\mathrm{dx}}{\\mathrm{dt}}{/tex}</span>&nbsp;= 2at - 3bt<sup>2</sup><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;a =&nbsp;<span class="math-tex">{tex}\\frac{d v}{d t}=\\frac{d^{2} x}{d t^{2}}{/tex}</span>&nbsp;= 2a -&nbsp;6bt<br />
a<sub>c</sub>&nbsp;= 0&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;2a - 6bt = 0<br />
t =&nbsp;<span class="math-tex">{tex}\\frac{a}{3 b}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{2a}{3 b}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{a}{b}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The displacement-time graph of a moving particle is shown ahead. The instantaneous velocity of the particle is negative at the point<br />
<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354890-x7raqs.jpg" style="height:84px; width:200px" /></p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">E</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Instantaneous velocity,<br />
<span class="math-tex">{tex}v=\\frac{d s}{d t}{/tex}</span><br />
= Slope of the displacement-time curve at any instant.<br />
Slope and hence instantaneous velocity is negative at point E.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">F</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">C</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">D</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which one of the following graphs represents uniform motion?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="6t13Dag.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1704892819-u2s3ne.jpg" style="height:87px; width:100px"/></p></body></html></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="f2j17UA.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1704892820-kr47hw.jpg" style="height:80px; width:100px"/></p></body></html></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="MFGWUBW.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1704892821-5uz9xu.jpg" style="height:86px; width:100px"/></p></body></html></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="x7hUuYb.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1704892822-ztpv6j.jpg" style="height:81px; width:100px"/></p></body></html></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As in uniform motion, the distance-time graph would be a straight line, because the equal distance is covered in equal units of time.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A body falling from rest describes distances s<sub>1</sub>, s<sub>2</sub> and s<sub>3</sub> in the first, second and third seconds of its fall, then the ratio s<sub>1</sub>: s<sub>2</sub>: s<sub>3</sub> is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">1 : 1 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">1 : 4 : 9</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">1 : 2 : 3</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">1 : 3 : 5</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Distance travelled by a particle in the <span class="math-tex">{tex}n^{\\text {th }}{/tex}</span> second,<br />
<span class="math-tex">{tex} S_n=u+\\frac{a}{2}(2 n-1){/tex}</span><br />
Here, <span class="math-tex">{tex}u=0, a=g{/tex}</span><br />
<span class="math-tex">{tex} S_1=0+\\frac{g}{2}(2 \\times 1-1)=\\frac{g}{2} {/tex}</span><br />
<span class="math-tex">{tex} S_2=0+\\frac{g}{2}(2 \\times 2-1)=\\frac{3 g}{2} {/tex}</span><br />
<span class="math-tex">{tex} S_3=0+\\frac{g}{2}(2 \\times 3-1)=\\frac{5 g}{2} {/tex}</span><br />
<span class="math-tex">{tex} \\therefore S_1: S_2: S_3=1: 3: 5 {/tex}</span><br />
&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>When a ball is thrown vertically upwards, at the maximum height</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">the velocity is zero and therefore there is no acceleration acting on the particle</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">the acceleration is present and therefore velocity is not zero</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">the acceleration depends on the velocity as a = <span class="math-tex">{tex}\\frac{d v}{d t}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">the acceleration is independent of the velocity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Velocity and acceleration are independent of each other.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Velocity of a body on reaching the point from which it was projected upwards, is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">v = 0</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">v = 0.5 u</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">v = 2 u</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">v = u</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Let the initial velocity of the body = u<br />
And final velocity at the initial point be v.<br />
Now the potential energy of the body at the point of projection is the same in both the upward and the downward journey. Since the total energy of the system has to be conserved, the kinetic energies at that point must also be the same in both journeys.<br />
<span class="math-tex">{tex}\\therefore \\frac{1}{2} m v^{2}=\\frac{1}{2} m u^{2} \\Rightarrow{/tex}</span>&nbsp;v = u</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The change in position or displacement (<span class="math-tex">{tex}\\Delta {\\rm{x}}{/tex}</span>) divided by the time intervals (<span class="math-tex">{tex}\\Delta {\\rm{t}}{/tex}</span>), in which the displacement occurs is known as</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">average velocity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Average velocity is the displacement of an object, divided by the time it took to cover that distance.<br />
<span class="math-tex">{tex}V_{average}= {∆x\\over ∆t}{/tex}</span><br />
Displacement is the straight line distance between the starting point and ending point of an object&#39;s motion.<br />
Velocity is referred to as a vector quantity because it has both magnitude and direction.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">acceleration</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">average acceleration </p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">speed</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the velocity of a particle is v = At + Bt<sup>2</sup>, where A and B are constants, then the distance travelled by it between 1s and 2 s is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac 32{/tex}</span>A + 4B</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">3A + 7B</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{3}{2} A+\\frac{7}{3} B{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>V = At + Bt<sup>2</sup>&nbsp;<span class="math-tex">{tex}\\Rightarrow \\frac{d x}{d t}{/tex}</span>&nbsp;= At + Bt<sup>2</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\int_{0}^{x} d x=\\int_{1}^{2}{/tex}</span>(At + Bt<sup>2</sup>)dt<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;x =&nbsp;<span class="math-tex">{tex}\\left[\\frac{A t^{2}}{2}+\\frac{B t^{3}}{3}\\right]_{1}^{2}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow x=\\frac{A}{2}\\left(2^{2}-1^{2}\\right)+\\frac{B}{3}\\left(2^{3}-1^{3}\\right){/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{3}{2} A+\\frac{7}{3} B{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{A}{2}+\\frac{B}{3}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Instantaneous velocity or simply velocity v at an&nbsp;instant t equals</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathop {\\lim }\\limits_{{\\rm{t}} \\to 0} \\frac{{\\Delta x}}{{\\Delta t}}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Instantaneous velocity is the velocity of an object in motion at a specific point in time. This is determined similarly to average velocity, but we narrow the period of time so that it approaches zero. The formula for instantaneous velocity is the limit as t approaches zero of the change in position over the change in t. Mathematically,<br />
<span class="math-tex">{tex}\\mathop {\\lim }\\limits_{{\\rm{t}} \\to 0} \\frac{{\\Delta x}}{{\\Delta t}}{/tex}</span><br />
The Instantaneous Velocity is expressed in m/s.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathop {\\lim }\\limits_{{\\rm{t}} \\to 1} \\frac{{\\Delta x}}{{\\Delta t}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathop {\\lim }\\limits_{{\\rm{t}} \\to \\infty } \\frac{{\\Delta x}}{ {\\Delta t}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathop {\\lim }\\limits_{{\\rm{t}} \\to 0} \\frac{{\\Delta x}}{{2\\Delta t}}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>No force is required for an object to be in uniform motion because</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">its acceleration is constant</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">its velocity is constant</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>its velocity is constant</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">its speed is constant</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">its position vector is constant</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>When a ball is thrown up vertically with velocity v<sub>0</sub>, it reaches a maximum height of h. If one wishes to triple the maximum height, then the ball should be thrown with velocity.</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{3} v_{0}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}0^{2}-v_{0}^{2}{/tex}</span>&nbsp;= 2(-g)h<br />
or&nbsp;<span class="math-tex">{tex}v_0^2{/tex}</span>&nbsp;= 2gh i.e.,&nbsp;<span class="math-tex">{tex}v_{0}^{2} \\propto h{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}v_{0}^{\\prime 2} \\propto 3 h{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\therefore \\frac{v_{0}^{\\prime 2}}{v_{0}^{2}}=\\frac{3 h}{h}=3{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}v_{0}^{\\prime}=\\sqrt{3} v_{0}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">3v<sub>0</sub></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">9v<sub>0</sub></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac {3 v_{0}} 2{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A body is travelling in a straight line with a uniformly increasing speed. Which one of the plots represents the changes in distance (s) travelled with time (t)?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="Lqzd7vz.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354783-gg8ppb.jpg" style="width: 100px; height: 79px;"/></p></body></html></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>s = ut +&nbsp;<span class="math-tex">{tex}\\frac{1}{2} a t^{2}{/tex}</span><br />
For u = 0, s =&nbsp;<span class="math-tex">{tex}\\frac{1}{2} a t^{2}{/tex}</span><br />
Hence, s-t graph is a parabola.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="r1rihwt.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354785-b2mdwk.jpg" style="width: 100px; height: 81px;"/></p></body></html></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="qUkLORd.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354787-a8q3w4.jpg" style="width: 100px; height: 81px;"/></p></body></html></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="VGeinTt.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354789-7r7ydx.jpg" style="width: 100px; height: 80px;"/></p></body></html></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A particle moves along the x-axis. The position x of the particle with respect to time t from the origin is&nbsp;given by x = b<sub>0</sub> + b<sub>1</sub>t + b<sub>2</sub>t<sup>2</sup>. The acceleration of the particle is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">b<sub>0</sub></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">b<sub>1</sub></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">b<sub>2</sub></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">2b<sub>2</sub></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>x = b<sub>0</sub> + b<sub>1</sub>t + b<sub>2</sub>t<sup>2</sup><br />
v =&nbsp;<span class="math-tex">{tex}\\frac{d x}{d t}{/tex}</span>&nbsp;=&nbsp;b<sub>1&nbsp;</sub>+ 2b<sub>2</sub>t<br />
a =&nbsp;<span class="math-tex">{tex}\\frac{d v}{d t}{/tex}</span>&nbsp;=&nbsp;2b<sub>2</sub></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>With the help of below velocity-time graph, find the<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683709516-6mmnjy.jpg" style="width: 200px; height: 139px;" /></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>displacement in first three seconds and</li>
	<li>acceleration for the above graph.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Displacement in first three seconds = Area of <span class="math-tex">{tex}\\triangle{/tex}</span>OAB<br />
	=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}(O B) \\times(O A){/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}(3) \\times(+30){/tex}</span>&nbsp;= +45&nbsp;m</li>
	<li>Acceleration = Slope of v - t graph<br />
	As, v - t graph is a straight line. So, consider the slope of line AB,<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Slope of line AB =&nbsp;<span class="math-tex">{tex}\\frac{y_2-y_1}{x_2-x_1}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{0 - 30}{3}{/tex}</span>&nbsp;= -10 m/s<sup>2</sup><br />
	So, the acceleration is negative.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>The displacement (in metre) of a particle&nbsp;moving along x-axis is given by x = 18t&nbsp;+ 15t<sup>2</sup>. Find the instantaneous velocity at t = 0 and t = 2 s.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The given displacement is, x = 18t + 15t<sup>2</sup><br />
Instantaneous velocity is the derivative of displacement with respect to time i.e.,<br />
<span class="math-tex">{tex}\\mathbf { v } _ { i } = \\frac { d \\mathbf { x } } { d t }{/tex}</span>&nbsp;= 18 + 30t .....(i)&nbsp;<br />
Instantaneous velocity at t = 0,&nbsp;<br />
v = 18 + 30&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;0 = 18 m/sec<br />
At t = 2 s, we have<br />
v = 18 + 30<span class="math-tex">{tex}\\times {/tex}</span>2 = 78 m/s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A body is moving in a straight line along x-axis. Its distance from the origin is given by the equation x = at<sup>2</sup> - bt<sup>3</sup>, where x is in metre and t is in second. Find</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the average speed of the body in the interval t = 0 and t =&nbsp;2</li>
	<li>its instantaneous speed at t = 2 s.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The given equation x = at<sup>2</sup> - bt<sup>3</sup></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>If time t = 0, x<sub>0</sub>&nbsp;= 0<br />
	If time t = 2 s, x<sub>2</sub>&nbsp;= 4a - 8b<br />
	the displacement &nbsp;= x<sub>2</sub>&nbsp;- x<sub>0</sub>&nbsp;= 4a - 8b -0 = 4a - 8b<br />
	Average speed in the given interval of time,( total displacement / total time)<br />
	<span class="math-tex">{tex}v _ { \\mathrm { av } } = \\frac { \\Delta x } { \\Delta t } = \\frac { 4 a - 8 b } { 2 }{/tex}</span>= 2a - 4b</li>
	<li>Instantaneous Speed is given by differentiation of x w.r.t time<br />
	<span class="math-tex">{tex}v = \\frac { d x } { d t } = \\frac { d } { d t } \\left( a t ^ { 2 } - b t ^ { 3 } \\right){/tex}</span>= 2at - 3bt<sup><span style="font-size: 10.8333px;">2</span></sup><br />
	At t = 2s, v = 4a - 12b m/s.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A ball is thrown vertically upwards with a velocity of 20 m/s&nbsp;from the top of a multistorey building. The height of the point from where the ball is thrown is 25&nbsp;m from the ground.</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>How high will the ball rise? and</li>
	<li>how long will it be before the ball hits the ground? Take g = 10 m/s<sup>2</sup>.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>Let us first consider the vertical upward motion of ball upto highest point, we have<br />
	initial velocity&nbsp;is,&nbsp;u = 20 m/s,&nbsp;final velocity is ,v = 0<br />
	and acceleration is, a = -10 m/s<sup>2</sup>, t = t<sub>1</sub>,<br />
	x = ?
	<p><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/rVuaIzW.png" style="height:137px; width:200px" /><br />
	Using the relation, v<sup>2</sup>&nbsp;= u<sup>2</sup>&nbsp;+ 2ax, we have<br />
	<span class="math-tex">{tex}x = \\frac { v ^ { 2 } - u ^ { 2 } } { 2 a } = \\frac { 0 - ( 20 ) ^ { 2 } } { 2 \\times ( - 10 ) }{/tex}</span>= 20 m.<br />
	Hence, the ball will rise upto 20m and height from the ground = 20 + 25 = 45 m.</p>
	</li>
	<li>
	<p>From the given figure, we have upward motion A to B in time(t<sub>1</sub>) and downward motion(B to C) in time(t<sub>2</sub>)<br />
	Also, Velocity&nbsp;at B is zero.<br />
	v = u -&nbsp;gt<br />
	From the top, the ball falls freely under acceleration due to gravity is given by ;<br />
	<span class="math-tex">{tex}\\therefore \\quad x = x _ { 0 } + u t + \\frac { 1 } { 2 } g t _ { 2 } ^ { 2 }{/tex}</span><br />
	Since x&nbsp; = 0, x<sub>0</sub>&nbsp;= 25&nbsp;m, u =20 and g = 10 m/s<sup>2</sup><br />
	Therefore, 25 + 20&nbsp;<span class="math-tex">{tex}\\times t- \\frac12 \\times10 \\times t^2=0{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow t^2-4t-5=0{/tex}</span><br />
	on solving, we get t = 5 and t = -1&nbsp;<br />
	Time taken by the ball to hit the ground&nbsp; is given by = 5 s&nbsp; &nbsp;(reject&nbsp;&nbsp;t = -1 )</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>From the top of a multi-storeyed building, 39.2 m tall, a boy projects a stone vertically upwards with an initial velocity of 9.8 ms<sup>-1</sup> such that it finally drops to the ground,</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>When will the stone reach the ground?</li>
	<li>When will it pass through the point of projection?</li>
	<li>What will be its velocity before striking the ground? Take g = 9.8 ms<sup>-2</sup>.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>s = ut + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>at<sup>2</sup><br />
	to reach ground s = 39.2<br />
	39.2 = (-9.8)t + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> &times; 9.8 &times; t<sup>2</sup><br />
	4 = -t + t<sup>2</sup>/2&nbsp;<br />
	t<sup>2</sup> - 2t - 8 = 0<br />
	t = 4</li>
	<li>For passing through same point.<br />
	s = 0<br />
	= (-9.8)t + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>(9.8)t<sup>2</sup><br />
	= t = 2</li>
	<li>v = u + at<br />
	= -9.8 + (9.8)4 = 29.4m/s</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Derive the three kinematic equations for uniformly accelerated motion graphically.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704791648-ypqyp5.jpg" style="height:213px; width:250px" /><br />
velocity-time graph of this motion is a straight line PQ, as shown in the figure.<br />
where, OP = u = RS<br />
OW = SQ = v and<br />
OS = PR = t</p>

<p><strong>For the first equation of motion:</strong> We know that the slope of velocity-time graph of uniformly accelerated motion represents the acceleration of the object.<br />
i.e., Acceleration = slope of the velocitytime graph PQ<br />
or <span class="math-tex">{tex}a=\\frac{Q R}{P R}=\\frac{Q R}{O S}{/tex}</span><br />
<span class="math-tex">{tex}a=\\frac{S Q-S R}{O S}=\\frac{v-u}{t}{/tex}</span><br />
or v - u = at<br />
or v = u + at...(i)<br />
This is the first equation of uniform acceterated motion.</p>

<p><strong>Second equation of motion</strong>: We know that the area under the velocity time graph for a given time interval represents the distance covered by the uniformly accelerated object in that interval of time.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> <strong>Distance (displacement) travelled by the object in time t is:</strong><br />
S = area of trapezium OSQP<br />
= area of rectangle OSRP + Area of triangle PRQ<br />
or S = OS <span class="math-tex">{tex}\\times{/tex}</span> OP + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> PR <span class="math-tex">{tex}\\times{/tex}</span> RQ<br />
(Area of rectangle = Length <span class="math-tex">{tex}\\times{/tex}</span> Breadth)<br />
(Area of triangle = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> Base <span class="math-tex">{tex}\\times{/tex}</span> Height)<br />
= t <span class="math-tex">{tex}\\times{/tex}</span> u + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> t <span class="math-tex">{tex}\\times{/tex}</span> (v - u)<br />
(From the first equation of motion v - u = at)<br />
= ut + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> t <span class="math-tex">{tex}\\times{/tex}</span> at<br />
Thus, S = ut + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> at<sup>2</sup>...(ii)<br />
This is the second equation of uniform accelerated motion.</p>

<p><strong>Third equation of motion:</strong> Distance travelled by the object in time interval t is<br />
S = area of trapezium OSQP<br />
= <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>(OP + SQ) <span class="math-tex">{tex}\\times{/tex}</span> OS<br />
<span class="math-tex">{tex}\\because{/tex}</span> OP = SR<br />
= <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>(SR + SQ) <span class="math-tex">{tex}\\times{/tex}</span> OS...(iii)<br />
Acceleration, a = slope of the velocity-time graph PQ<br />
or a = <span class="math-tex">{tex}\\frac{R Q}{P R}=\\frac{S Q-S R}{O S}{/tex}</span><br />
or <span class="math-tex">{tex}O S=\\frac{S Q-S R}{a}{/tex}</span>...(iv)<br />
Putting this value in equation (iii), we get<br />
<span class="math-tex">{tex}s=\\frac{1}{2}(S R+S Q)\\left(\\frac{S Q-S R}{a}\\right){/tex}</span><br />
or s = <span class="math-tex">{tex}\\frac{1}{2a}{/tex}</span>(SQ<sup>2</sup> - SR<sup>2</sup>)<br />
or s = <span class="math-tex">{tex}\\frac{1}{2a}{/tex}</span>(v<sup>2</sup> - u<sup>2</sup>)<br />
or v<sup>2</sup> - u<sup>2</sup> - 2as<br />
or v<sup>2</sup> = u<sup>2</sup> + 2as...(v)<br />
This is the third equation of uniform accelerated motion.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A woman starts from her home at 9.00 am, walks with a speed of 5 km h<sup>-1</sup> on a straight road up to her office 2.5 km away, stays at the office up to 5.00 pm, and returns home by an auto with a speed of 25 km h<sup>-1</sup>. Choose suitable scales and plot the x-t graph of her motion.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><u><strong>Given:</strong></u><strong>&nbsp;</strong>Speed of woman = 5 km/h<br />
Distance from home to office&nbsp;= 2.5 km<br />
Time &nbsp;<span class="math-tex">{tex}= \\frac { \\text { Distance covered } } { \\text { Speed of women } }{/tex}</span><br />
Time =&nbsp;<span class="math-tex">{tex} \\frac { 2.5 } { 5 } {/tex}</span>&nbsp;= 0.5 h = 30 min<br />
When she returned, she covers the same distance in the evening by an auto.<br />
Given Speed of auto&nbsp;= 25 km/h<br />
Time &nbsp;<span class="math-tex">{tex}= \\frac { \\text { Distance Covered } } { \\text { Speed of auto } }{/tex}</span><br />
Time =&nbsp;<span class="math-tex">{tex} \\frac { 2.5 } { 25 } = {/tex}</span>&nbsp;0.1 h = 6 min&nbsp;<br />
The woman is at rest from 9:30 am to 5:00 pm and during this time, speed is zero<br />
The x-t graph of the motion of women from home to office and office to home is shown below.&nbsp;<br />
<img id="Picture 4" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch03/3m/image075.png" style="height: 185px; width: 250px;" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Draw the following graphs (expected nature only) between distance and time of an object in case of</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>For a body at rest</li>
	<li>For a body moving with uniform velocity</li>
	<li>For a body moving with constant acceleration.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704860798-jznmuh.jpg" /><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704860841-e45pyu.jpg" /><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704860860-mv7yet.jpg" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Establish <span class="math-tex">{tex}s = u t + \\frac { 1 } { 2 } a t ^ { 2 }{/tex}</span> from velocity-time graph for a uniform accelerated motion?<br />
<img id="Picture 1" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch09/3m/image047.jpg" style="width: 150px; height: 105px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>From the velocity-time graph, OA = u = initial velocity of the particle, acceleration, a = slope of the graph = tan&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= <span class="math-tex">{tex}\\frac {DB} {AD}{/tex}</span>, time taken = OC = AD = t, final velocity, v = BC&nbsp;<br />
Displacement of the particle in time (t)<br />
S = area under <span class="math-tex">{tex}\\upsilon - t{/tex}</span> graph<br />
S = area trapezium OABC<br />
S = area of rectangle AODC + area of triangle&nbsp;ADB<br />
<span class="math-tex">{tex}\\Rightarrow S = (O A \\times O C) + \\frac { 1 } { 2 } (A D \\times B D){/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow S = u t + \\frac { 1 } { 2 } ( A D ) \\times \\left( \\frac { A D \\times D B } { A D } \\right){/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow S = u t + \\frac { 1 } { 2 } ( A D ) ^ { 2 } \\times \\left( \\frac { D B } { A D } \\right){/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow S = u t + \\frac { 1 } { 2 } ( t ) ^ { 2 } \\times \\left( \\frac { D B } { A D } \\right){/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow S = u t + \\frac { 1 } { 2 } ( t ) ^ { 2 } \\times ( a ){/tex}</span>&nbsp;<span class="math-tex">{tex}\\left[ \\because a = \\tan \\theta = \\frac { B D } { A D } \\right]{/tex}</span><br />
<span class="math-tex">{tex}\\therefore S = u t + \\frac { 1 } { 2 } a t ^ { 2 }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Establish the kinematic equation v<sup>2</sup> - u<sup>2</sup> = 2as from velocity-time graph for a uniformly accelerated motion.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img alt="" data-imgur-src="JTvRsvJ.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/JTvRsvJ.png" style="width: 250px; height: 153px;" /><br />
The velocity-time graph for uniformly accelerated motion has been shown in the figure&nbsp;with the initial velocity at t = 0 as u and final velocity at time t as v. Then magnitude of the total displacement in the given time is equal to the area under the v-t graph . Hence, displacement of moving a particle in time t is given by:<br />
s = area of trapezium OABC<br />
&nbsp; &nbsp; =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}(O A+C B) \\times O C{/tex}</span><br />
&nbsp; &nbsp; &nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}(u+v) \\times t{/tex}</span>&nbsp;..............................................................................(i)<br />
However, from the definition of acceleration, we know that<br />
a =&nbsp;<span class="math-tex">{tex}\\frac{v-u}{t}{/tex}</span>&nbsp;or t =&nbsp;<span class="math-tex">{tex}\\frac{v-u}{a}{/tex}</span><br />
Substituting this value of time t in equation (i), we get Displacement<br />
s =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}(u+v) \\times \\frac{(v-u)}{a}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{\\left(v^{2}-u^{2}\\right)}{2 a}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;2as = v<sup>2</sup> - u<sup>2</sup>&nbsp;or v<sup>2</sup>&nbsp;= u<sup>2</sup>&nbsp;+ 2as</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Look at the graphs (a) to (d) (figure) carefully and state, with reasons, which of these cannot possibly represent one-dimensional motion of a particle.</p>

<ol start="1" style="list-style-type:lower-alpha">
	<li><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/bJj3ieE.png" style="height:148px; width:148px" /></li>
	<li><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/8NpvdHt.png" style="height:154px; width:151px" /></li>
	<li><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/6TO9z8x.png" style="height:148px; width:159px" /></li>
	<li><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/fyFUznb.png" style="height:164px; width:161px" /><br />
	&nbsp;</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-alpha">
	<li>The given x-t graph, shown in (a), does not represent one-dimensional motion of the particle. This is because a particle cannot have two positions at the same instant of time.</li>
	<li>The given v-t graph, shown in (b), does not represent one-dimensional motion of the particle. This is because a particle can never have two values of velocity at the same instant of time.</li>
	<li>The given v-t graph, shown in (c), does not represent one-dimensional motion of the particle. This is because speed being a scalar quantity cannot be negative.</li>
	<li>The given v-t graph, shown in (d), does not represent one-dimensional motion of the particle. This is because the total path length travelled by the particle cannot decrease with time.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A food packet is released from a helicopter which is rising steadily at 2 ms<sup>-1</sup>. The food packet falls on the ground after 6 s. Find the height of the helicopter when</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the food packet was released from it, and</li>
	<li>when the food packet just reached the earth.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, helicopter is rising&nbsp;upwards steadily with a velocity, u = 2 ms<sup>-1</sup>.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>When the food packet is released, its initial velocity is same as the velocity of helicopter i.e., u = 2 ms<sup>-1</sup>. Time taken by the packet to reach ground, t = 6 s. Let h<sub>1</sub> be the height of the helicopter at the time of releasing the food packet.<sub>&nbsp;</sub>Using the second equation of motion, s&nbsp;= ut + <span class="math-tex">{tex}\\frac{1}{2} a t^{2}{/tex}</span> and considering downward direction as positive, we have&nbsp;<br />
	h<sub>1&nbsp;</sub>= (-2)&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;6 +&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(6)<sup>2</sup>&nbsp;= -12 + 176.4 = 164.4&nbsp;m</li>
	<li>During time, t = 6s, the helicopter has uniform motion and risen further with a distance h&#39; = ut = 2 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;6 = 12m. Hence, the height of the helicopter when food packet just reached&nbsp;the earth is,<br />
	h<sub>2</sub> = h<sub>1</sub> + h&#39; = 164.4&nbsp;+ 12 = 176.4 m.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Draw the following graphs (expected nature only) representing motion of an object under free fall. Neglect air resistance.</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>Variation of position with respect to time.</li>
	<li>Variation of velocity with respect to time.</li>
	<li>Variation of acceleration with respect to time.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704795233-g4j6uy.jpg" style="height:111px; width:100px" /></li>
	<li><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704795435-daj788.jpg" style="height:104px; width:150px" /></li>
	<li><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704795525-yukjvp.jpg" style="height:101px; width:150px" /></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Acceleration-time graph of a moving object is shown in figure. Draw the velocity- time graph and displacement-time graph corresponding to this type of motion.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704860411-ttfdak.jpg" style="height:153px; width:200px" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704860493-qshuzf.jpg" /><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704860516-jy2nct.jpg" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Draw the following graphs for an object projected upward with a velocity v<sub>0</sub>, which comes back to the&nbsp;same point after some time:</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>Acceleration versus time graph,</li>
	<li>Speed versus time graph,</li>
	<li>Velocity versus time graph.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704859892-6pxbec.jpg" style="height:178px; width:250px" /><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704859942-3n3t5d.jpg" style="height:213px; width:250px" /><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704859975-8xv837.jpg" style="height:220px; width:250px" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State which of the following situations are possible and give an example for each of these.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>An object with a constant acceleration but with zero velocity.</li>
	<li>An object moving in a certain direction with acceleration in the perpendicular direction.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Both the situations are possible</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>When an object is projected upwards, its velocity at the top-most point is zero even though the acceleration on itis 9.8 m /s<sup>2</sup>(g).</li>
	<li>When a stone tied to a string is whirled in a circular path, the acceleration acting on it is always at right angles i.e. perpendicular to the direction of motion of stone.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The velocity-displacement graph of a particle is shown in the figure.</p>

<p>&nbsp;<img data-imgur-src="T8oDDAY.png" id="Picture 14" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/T8oDDAY.png" /></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Write the relation between v and x.</li>
	<li>Obtain the relation between acceleration and displacement and plot it.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>In this question, we will use the equation of the straight line graph (linear equation).<br />
y = mx + c.<br />
In this equation, m is the slope of the graph and c is the interception on the y-axis.<br />
Now according to the problem, initial velocity&nbsp;= v<sub>0</sub><br />
Let the distance traveled in time&nbsp;t = x<sub>0</sub>.<br />
For the graph,&nbsp;<span class="math-tex">{tex}\\tan \\theta = \\frac { v _ { 0 } } { x _ { 0 } } = \\frac { v _ { 0 } - v } { x }{/tex}</span>&nbsp;...........(i)</p>

<p><img alt="" data-imgur-src="SCnBeCa.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/SCnBeCa.png" style="width: 141px; height: 130px;" />&nbsp;<br />
Where, v is velocity&nbsp;and x is displacement at any instant of time t.<br />
From Equation (i), we have<br />
<span class="math-tex">{tex}v _ { 0 } - v = \\frac { v _ { 0 } } { x _ { 0 } } x{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\quad v = \\frac { - v _ { 0 } } { x _ { 0 } } x + v _ { 0 }{/tex}</span><br />
We know that,<br />
Acceleration,&nbsp;<span class="math-tex">{tex}a = \\frac { d v } { d t } = \\frac { - v _ { 0 } } { x _ { 0 } } \\frac { d x } { d t } + 0{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\quad a = \\frac { - v _ { 0 } } { x _ { 0 } } ( v ){/tex}</span><br />
<span class="math-tex">{tex}= \\frac { - v _ { 0 } } { x _ { 0 } } \\left( \\frac { - v _ { 0 } } { x _ { 0 } } x + v _ { 0 } \\right) = \\frac { v _ { 0 } ^ { 2 } } { x _ { 0 } ^ { 2 } } x - \\frac { v _ { 0 } ^ { 2 } } { x _ { 0 } }{/tex}</span>&nbsp;........(ii)<br />
On comparing the equation (ii) with equation of a straight line&nbsp;y = mx + c we have<br />
<span class="math-tex">{tex}m=\\frac{v_{0}^{2}}{x_{0}^{2}}=+v e{/tex}</span>,&nbsp;<span class="math-tex">{tex}c=-\\frac{v_{0}^{2}}{x_{0}^{2}}{/tex}</span><br />
Graph of &#39;a&#39;&nbsp;versus x is given below.<br />
<img alt="" data-imgur-src="GH5kx7Q.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/GH5kx7Q.png" style="width: 150px; height: 93px;" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Stopping distance of vehicles: When brakes are applied to a moving vehicle, the distance it travels before stopping is called stopping distance. It is an important factor for road safety and depends on the initial velocity (v<sub>o</sub>) and the braking capacity, or deceleration, &ndash;a that is caused by the braking. Derive an expression for stopping distance of a vehicle in terms of v<sub>o</sub> and a.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let the distance traveled by the vehicle before it stops be d<sub>s</sub>. Then, using the equation of motion v<sup>2</sup> = v<sub>o</sub><sup>2</sup> + 2 ax, and noting that v = 0, we have the stopping distance&nbsp;<span class="math-tex">{tex}d_{s}=\\frac{-v_{0}^{2}}{2 a}{/tex}</span><br />
Thus, the stopping distance is proportional to the square of the initial velocity. Doubling the initial velocity increases the stopping distance by a factor of 4 (for the same deceleration). For the car of a particular make, the braking distance was found to be 10 m, 20 m, 34 m, and 50 m corresponding to velocities of 11, 15, 20, and 25 m/s which are nearly consistent with the above formula. Stopping distance is an important factor considered in setting speed limits, for example, in school zones.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Use integration technique to prove that the distance travelled in nth second, s<sub>nth</sub> = u + <span class="math-tex">{tex}\\frac a2{/tex}</span>(2n - 1).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><span class="math-tex">{tex}\\therefore{/tex}</span> Using the relation<br />
s<sub>t</sub> = ut + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>at<sup>2</sup>,<br />
We get by putting t = n and n - 1,<br />
s<sub>n</sub> = un + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>an<sup>2</sup>...(i)<br />
and s<sub>n-1</sub> = u(n - 1) + a(n -1)<sup>2</sup> ...(ii)<br />
If S<sub>n</sub> be the distance covered by the object in n<sup>th</sup> second, then<br />
S<sub>n</sub> = S<sub>n</sub> - S<sub>n-1</sub><br />
= un + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>an<sup>2 </sup>- [u(n - 1) + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>a(n - 1)<sup>2</sup><br />
= un + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>an<sup>2</sup> - [un - u + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>a(n<sup>2</sup> + 1 - 2n)]<sup> </sup><br />
= u - <span class="math-tex">{tex}\\frac{a}{2}{/tex}</span> (1 - 2n)<br />
or s<sub>nth</sub> = u + <span class="math-tex">{tex}\\frac a2{/tex}</span>(2n - 1) proved.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Suggest a suitable physical situation for each of the following graphs:</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683700199-ggtquz.jpg" style="width: 200px; height: 107px;" /></li>
	<li><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683700251-56hj5w.jpg" style="width: 150px; height: 120px;" /></li>
	<li><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683700323-zjjtsp.jpg" style="width: 150px; height: 116px;" /></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li style="text-align: justify;">The given x-t graph shows that initially a body was at rest. Then, its velocity increases with time and attains an instantaneous constant value. The velocity then reduces to zero with an increase in time. Then, its velocity increases with time in the opposite direction and acquires a constant value. A similar physical situation arises when a football (initially kept at rest) is kicked and gets rebound from a rigid wall so that its speed gets reduced. Then, it passes from the player who has kicked it and ultimately gets stopped after sometime.</li>
	<li style="text-align: justify;">In the given v-t graph, the sign of velocity changes and its magnitude decreases with a passage of time. A similar situation arises when a ball is dropped on the hard floor from a height. It strikes the floor with some velocity and upon rebound, its velocity decreases by a factor. This continues till the velocity of the ball eventually becomes zero.</li>
	<li style="text-align: justify;">The given a-t graph reveals that initially the body is moving with a certain uniform velocity. Its acceleration increases for a short interval of time, which again drops to zero. This indicates that the body again starts moving with the same constant velocity. A similar physical situation arises when a hammer moving with a uniform velocity strikes a nail.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The displacement (in metre) of a particle moving along the x-axis is given by x = 18t&nbsp;+ 5t<sup>2</sup>. Calculate:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the instantaneous velocity at t = 2 s,</li>
	<li>average velocity between t = 2 s and t =&nbsp;3 s,</li>
	<li>instantaneous acceleration.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given:&nbsp;x = 18t&nbsp;+ 5t<sup>2</sup></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Velocity, v = <span class="math-tex">{tex}\\frac{d x}{d t}=\\frac{d}{d t}{/tex}</span>(18t&nbsp;+ 5t<sup>2</sup>) = 18 + 10t<br />
	At t&nbsp;= 2 s, the instantaneous velocity = 18 + 10 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2 = 38 ms<sup>-1</sup></li>
	<li>Displacement at t&nbsp;= 2 s is x<sub>1</sub>&nbsp;= 18 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2 + 5 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2<sup>2</sup> = 56m<br />
	Displacement at t = 3 s is x<sub>2</sub> = 18 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;3 + 5 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;32 = 54 + 45 = 99 m<br />
	Average velocity,&nbsp;<span class="math-tex">{tex}\\bar{v}=\\frac{x_{2} \\ - \\ x_{1}}{t_{2} \\ - \\ t_{1}}=\\frac{99 \\ - \\ 56}{3 \\ - \\ 2}{/tex}</span>&nbsp;= 43 ms<sup>-1</sup></li>
	<li>Acceleration, a =&nbsp;<span class="math-tex">{tex}\\frac{d v}{d t}=\\frac{d}{d t}{/tex}</span>(18 + 10t) = 10 ms<sup>-2</sup></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A stone is thrown vertically upwards with a velocity of 4.9 ms<sup>-1</sup>. Calculate</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>the maximum height reached</li>
	<li>the time taken to reach the maximum height</li>
	<li>the velocity with which it returns to the ground and</li>
	<li>the time taken to reach the ground.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>Maximum height reach h = <span class="math-tex">{tex}\\frac{u^2}{2g}{/tex}</span> <span class="math-tex">{tex}= \\frac{4.9 \\times 4.9}{2 \\times 9.8}{/tex}</span> = 1.225 m</li>
	<li>Time taken to reach maximum height = v = u - gt<br />
	v = 0,<br />
	t = <span class="math-tex">{tex}\\frac{u}{g}{/tex}</span>&nbsp; = <span class="math-tex">{tex}\\frac{4.9}{9.8}{/tex}</span> = 0.5s</li>
	<li>It velocity with which it return to ground is 4.9</li>
	<li>Time taken 0.5 + 0.5 = 1s</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A particle is moving along a straight line and its position is given by the relation x = (t<sup>3</sup> - 6t<sup>2</sup> - 15t + 40)m<br />
Find</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>The time at which velocity is zero.</li>
	<li>Position &amp; Displacement at this point.</li>
	<li>Acceleration for the particle at the point.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The given equation is x = t<sup>3</sup> - 6t<sup>2</sup> - 15t + 40<br />
<span class="math-tex">{tex}\\therefore~\\upsilon = \\frac { d x } { d t } = \\left( 3 t ^ { 2 } - 12 t - 15 \\right) m/s{/tex}</span>&nbsp; &nbsp;<br />
and&nbsp;<span class="math-tex">{tex}a = \\frac { d v } { d t } = ( 6 t - 12 ) m/s^2 {/tex}</span><br />
i) Since , v = 0<br />
3t<sup>2</sup> - 12t - 15 = 0<br />
3t<sup>2</sup> - 15t + 3t - 15 = 0<br />
3t(t - 5) + 3(t - 5) = 0<br />
(3t + 3)(t - 5) = 0<br />
Either t = -1 or t = 5<br />
Time cannot be negative<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> t = 5 seconds.<br />
ii) Position at t = 5 s&nbsp;<br />
x = (5)<sup>3</sup> - 6(5)<sup>2</sup> - 15(5) + 40&nbsp;<br />
x = - 60m<br />
At t = 0 s,<br />
x = (0)<sup>3</sup>&nbsp;- 6x(0)<sup>2</sup>&nbsp;- 15x0 + 40&nbsp; = 40 m<br />
The displacement between t = 0 sec to t = 5 sec is given by:<br />
S = Final Position ( x<sub>5</sub>&nbsp;) - Initial Position ( x<sub>0</sub> )<br />
where x<sub>5</sub> = - 60m and x<sub>0</sub> = 40m<br />
s = - 60 - 40<br />
s = -100 m<br />
iii) Acceleration at t = 5s<br />
a = 6t - 12<br />
a = 6(5) - 12<br />
a = (30 - 12)<br />
a = 18 m/s<sup>2</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Establish the relation <span class="math-tex">{tex}S_{nth}=u+\\frac a2(2n-1){/tex}</span> where the letters have their usual meanings.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Distance traveled in n<sup>th</sup> second is given by<br />
<span class="math-tex">{tex}S_{nth}=S_n-S_{n-1}{/tex}</span>&nbsp;...(i)<br />
Distance traveled in n seconds&nbsp;<br />
<span class="math-tex">{tex}S_n=un+\\frac12an^2{/tex}</span>&nbsp;...(ii)<br />
distance traveled in (n-1)&nbsp; seconds<br />
<span class="math-tex">{tex}S_{n-1}=u(n-1)+\\frac12a(n-1{)^2}{/tex}</span>&nbsp;...(iii)<br />
Put equation (ii) and (iii) in&nbsp; equation (i)<br />
<span class="math-tex">{tex}{S_{nth}} = un + \\frac{1}{2}a{n^2} - u(n - 1) - \\frac{1}{2}a{(n - 1)^2}{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}S_{nth}={/tex}</span><sub>&nbsp;</sub><span class="math-tex">{tex} un + \\frac{1}{2}a{n^2} - un + u - \\frac{1}{2}a{n^2} - \\frac{1}{2}a + na{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}{{\\text{S}}_{{\\text{nth}}}} = {\\text{u}} - \\frac{1}{2}a + {\\text{na}}{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}S_{nth}{/tex}</span><span class="math-tex">{tex} = \\mathrm { u } + \\frac { a } { 2 } ( 2 n - 1 ){/tex}</span>&nbsp;<br />
Hence proved.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A 100 m sprinter uniformly increases his speed from rest at the rate of 1 ms<sup>-2</sup> up to <span class="math-tex">{tex}\\frac{3}{4}{/tex}</span>th of the&nbsp;total run and then covers the last quarter(<span class="math-tex">{tex}\\frac{1}{4}{/tex}</span>th) run with uniform speed. How much time does he take to complete the&nbsp;race?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given: Total distance covered, S&nbsp;= 100 m, u = 0<br />
For first&nbsp;<span class="math-tex">{tex}\\frac{3}{4}{/tex}</span>th of the run, distance S<sub>1</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{3}{4}{/tex}</span>S =&nbsp;<span class="math-tex">{tex}\\frac{3}{4}{/tex}</span><span class="math-tex">{tex}\\times{/tex}</span>100&nbsp;= 75 m, a = +1 ms<sup>-2&nbsp;</sup>. Let the&nbsp;time for this part of the run be t<sub>1</sub>, then using the second equation of motion,<br />
S<sub>1</sub> = ut<sub>1</sub> +&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>at<sub>1</sub><sup>2</sup><br />
75 = 0 +&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><span class="math-tex">{tex}\\times{/tex}</span>1<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;<span class="math-tex">{tex}t_{1}^{2}{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}t_{1}^{2}{/tex}</span>&nbsp;= 75&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2 = 150&nbsp;<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t<sub>1</sub> =&nbsp;<span class="math-tex">{tex}\\sqrt{150}{/tex}</span>&nbsp;= 12.25 s&nbsp;<br />
and final velocity v = u + at<sub>1</sub> = 0 + 1<span class="math-tex">{tex}\\times{/tex}</span>12.25 = 12.25 m s<sup>-1</sup>.<br />
For remaining <span class="math-tex">{tex}\\frac{1}{4}{/tex}</span>th run, distance S<sub>2</sub> = S&nbsp;- S<sub>1</sub> = 100 - 75 = 25 m, uniform velocity v = 12.25 m s<sup>-1</sup>&nbsp;<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Time for this run t<sub>2&nbsp;</sub>=&nbsp;<span class="math-tex">{tex}\\frac{S_{2}}{v}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{25}{12.25}{/tex}</span>&nbsp;= 2.04 s<br />
Thus, t​​​​otal time taken by the sprinter to complete the race is, t = t<sub>1</sub>&nbsp;+ t<sub>2</sub> = 12.25 s + 2.04 s = 14.29 s = 14.3 s.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The distance covered by an object between times t<sub>1</sub>&nbsp;and t<sub>2</sub> is given by the area under the v - t graph between t<sub>1</sub> and t<sub>2</sub>. Prove this statement for an object moving with negative acceleration and having a positive velocity at time t<sub>1</sub> and a negative velocity at time t<sub>2</sub>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>The velocity-time graph for the given motion of the object is as shown in Figure. Let u, be the velocity at time t<sub>1</sub> and - v<sub>2</sub> at time t<sub>2</sub>.<br/>
<img alt="" data-imgur-src="FYgszVV.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354740-3h6k37.jpg" style="width: 200px; height: 101px;"/><br/>
Area under v - t graph between times t<sub>1</sub> and t<sub>2</sub><br/>
= Area AA'B + Area CC'B<br/>
= <span class="math-tex">{tex}\\frac 12{/tex}</span>A'B <span class="math-tex">{tex}\\times{/tex}</span> AA' + <span class="math-tex">{tex}\\frac 12{/tex}</span>BC' <span class="math-tex">{tex}\\times{/tex}</span> CC'<br/>
= <span class="math-tex">{tex}\\frac 12{/tex}</span>(t' - t<sub>1</sub>)(v<sub>1</sub>) + <span class="math-tex">{tex}\\frac 12{/tex}</span>(t<sub>2</sub> - t') (-v<sub>2</sub>)<br/>
= <span class="math-tex">{tex}\\frac 12{/tex}</span>v<sub>1</sub>(t' - t<sub>1</sub>) - <span class="math-tex">{tex}\\frac 12{/tex}</span> v<sub>2</sub> (t<sub>2 </sub>- t')<br/>
Between times t<sub>1</sub> and t', the acceleration of the object is<br/>
a = Slope of v - t graph AB = <span class="math-tex">{tex}\\frac{0 \\ - \\ v_{1}}{t^{\\prime} \\ - \\ t_{1}}{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore t^{\\prime}-t_{1}=-\\frac{v_{1}}{a}{/tex}</span><br/>
Between times t' and t<sub>2</sub>, the acceleration of the object is<br/>
a = slope of v - t graph BC = <span class="math-tex">{tex}\\frac{-v_{2} \\ - \\ 0}{t_{2} \\ - \\ t^{\\prime}}{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore  t_{2}-t^{\\prime}=-\\frac{v_{2}}{a}{/tex}</span><br/>
Hence area under v - t graph between times t<sub>1</sub> and t<sub>2</sub><br/>
= <span class="math-tex">{tex}\\frac{1}{2} v_{1}\\left(-\\frac{v_{1}}{a}\\right)-\\frac{1}{2} v_{2}\\left(-\\frac{v_{2}}{a}\\right){/tex}</span><br/>
= <span class="math-tex">{tex}\\frac{v_{2}^{2} \\ - \\ v_{1}^{2}}{2 a}=\\frac{2 a s}{2 a}{/tex}</span> = s<br/>
= Distance covered by the object between times t<sub>1</sub> and t<sub>2</sub>.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>The speed-time graph of a particle moving along a fixed direction is shown in Fig. Find:<br/>
<img alt="" data-imgur-src="Zpy5MAX.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354687-yndazp.jpg" style="width: 200px; height: 126px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>distance travelled by the particle between 0 sec to 10 sec</li>
<li>average speed between this interval</li>
<li>the time when the speed was minimum</li>
<li>the time when speed was maximum.</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Distance travelled by the particle between 0 sec and 10 sec is<br />
	s = Area under speed-time graph =&nbsp;<span class="math-tex">{tex}\\frac 12{/tex}</span>(10 - 0) (12 - 0) = 60 m</li>
	<li>Average speed =&nbsp;<span class="math-tex">{tex}\\frac{\\text { Total distance travelled }}{\\text { Time taken }}{/tex}</span><br />
	=&nbsp;<span class="math-tex">{tex}\\frac{60}{10}{/tex}</span>&nbsp;= 6 ms<sup>-1</sup></li>
	<li>Speed is minimum at t = 0 s and f = 10 s</li>
	<li>Speed is maximum at t = 5</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>Figure shows the distance-time graphs of two trains, which start moving simultaneously in the same direction. From the graphs, find:<br/>
<img alt="" data-imgur-src="iz1lDt8.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354683-9zdxen.jpg" style="width: 200px; height: 151px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>How much ahead of A is B when the motion starts?</li>
<li>What is the speed of B?</li>
<li>When and where will A catch B?</li>
<li>What is the difference between the speeds of A and B?</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>B is ahead of A by the distance OP = 100 km, when the motion starts.</li>
	<li>Speed of B =&nbsp;<span class="math-tex">{tex}\\frac{Q R}{P R}=\\frac{150 \\ - \\ 100}{2 \\ - \\ 0}{/tex}</span>&nbsp;= 25 kmh<sup>-1</sup></li>
	<li>Since the two graphs intersect at point Q, so A will catch B after 2 hours and at a distance of 150 km from the origin.</li>
	<li>Speed of A =&nbsp;<span class="math-tex">{tex}\\frac{Q S}{OS}=\\frac{150 \\ - \\ 0}{2 \\ - \\ 0}{/tex}</span>&nbsp;= 75 kmh<sup>-1</sup><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Difference in speeds = 75 - 25 = 50&nbsp;kmh<sup>-1</sup></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>The position-time (x-t) graphs for two children A and B returning from their school O to their homes P and Q respectively are shown in Fig. Choose the correct entries in the brackets below;<br />
<img alt="" data-imgur-src="j3cN2Vd.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/j3cN2Vd.png" style="width: 235px; height: 205px;" /></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>(<span class="math-tex">{tex}\\frac AB{/tex}</span>) lives closer to the school than (<span class="math-tex">{tex}\\frac BA{/tex}</span>)</li>
	<li>(<span class="math-tex">{tex}\\frac AB{/tex}</span>) starts from the school earlier than (<span class="math-tex">{tex}\\frac BA{/tex}</span>)</li>
	<li>(<span class="math-tex">{tex}\\frac AB{/tex}</span>) walks faster than (<span class="math-tex">{tex}\\frac BA{/tex}</span>)</li>
	<li>A and B reach home at the (same/different) time</li>
	<li>(<span class="math-tex">{tex}\\frac AB{/tex}</span>) overtakes (<span class="math-tex">{tex}\\frac BA{/tex}</span>) on the road (once/twice).</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>A lives closer to school than B.&nbsp;In the given x-t graph, it can be observed that distance OP &lt; OQ. Hence, the distance of the school from the A&#39;s home is less than that from B&#39;s home.</li>
	<li>A starts from school earlier than B.&nbsp;In the given graph, it can be observed that for x = 0, t = 0 for A, whereas for x = 0, t has some finite value for B. Thus, A starts his journey from school earlier than B.</li>
	<li>B walks faster than A.&nbsp;In the given x-t graph, it can be observed that the slope of B is greater than that of A. Since the slope of the x-t graph gives the speed, a greater slope means that the speed of B is greater than the speed A.</li>
	<li>A and B reach home at the different&nbsp;time.&nbsp;It is clear from the given graph that both A and B reach their respective homes at the different time.</li>
	<li>B overtakes A once on the road.&nbsp;B moves later than A and his/her speed is greater than that of A. From the graph, it is clear that B overtakes A only once on the road.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>Figure shows the position-time graphs of three cars A, B and C. On the basis of the graphs, answer the following questions:<br/>
<img alt="" data-imgur-src="B5PEg85.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354702-mkhzb8.jpg" style="width: 200px; height: 150px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Which car has the highest speed and which the lowest?</li>
<li>Are the three cars ever at the same point on the road?</li>
<li>When A passes C, where is B?</li>
<li>How far did car A travel between the time it passed cars B and C?</li>
<li>What is the relative velocity of car C with respect to car A?</li>
<li>What is the relative velocity of car B with respect to car C?</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Slope of line C is highest and that of A is lowest.</li>
	<li>The lines do not meet at one point at any time</li>
	<li>A passes C at 0.6 h, at this time B is at 6 km from the origin.</li>
	<li>x(t = 1.2h)i - x(f&nbsp;= 0.6h) = (12 - 9) km = 3km</li>
	<li>v<sub>A</sub> = Slope&nbsp;of line A = <span class="math-tex">{tex}\\frac{14 \\ - \\ 6}{1.6 \\ - \\ 0}{/tex}</span>&nbsp;= 5 km h<sup>-1</sup></li>
	<li>v<sub>C</sub> = Slope&nbsp;of&nbsp;line C = <span class="math-tex">{tex}\\frac{14 \\ - \\ 2}{1.0 \\ - \\ 0}{/tex}</span>&nbsp;= 12&nbsp;km h<sup>-1</sup><br />
	Relative velocity of C w.r.t. A = v<sub>C</sub> - v<sub>A</sub> = 12 - 5 = 7 km h<sup>-1</sup>.</li>
	<li>v<sub>R&nbsp;</sub>= Slope of line B = <span class="math-tex">{tex}\\frac{14 \\ - \\ 0}{1.4 \\ - \\ 0}{/tex}</span> = 10 km h<sup>-1</sup><br />
	Relative velocity of B w.r.t. C = v<sub>B</sub> - v<sub>C</sub> = 10 - 12 = -2 km s<sup>-1</sup></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Figure gives a speed-time graph of a particle in motion along a constant direction. Three equal intervals of time are shown. In which interval is the average acceleration greatest in magnitude? In which interval is the average speed greatest? Choosing the positive direction as the constant direction of motion, give the signs of v and <span class="math-tex">{tex}a{/tex}</span>&nbsp;in the three intervals. What are the accelerations at the points A, B, C and D?<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683700025-g6cv3v.jpg" style="width: 200px; height: 119px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol>
	<li>As the change of speed is greatest in interval 2, So magnitude of the acceleration is greatest in interval 2.</li>
	<li>Height of the curve from the time-axis gives the average speed of the particle. It is apparent from the graph that height is the greatest in interval 3. Hence, the average speed of the particle is the greatest in interval 3.</li>
	<li>Velocity is positive in all the intervals. Acceleration is positive in interval 1 and 3 as speed is increasing while it is negative in interval 2 as speed is decreasing.</li>
	<li>Points A, B, C, and D are all parallel to the time-axis. Hence, the slope is zero at these points. Therefore, at points A, B, C, and D, acceleration of the particle is zero.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A hundred metre sprinter increases her speed from rest uniformly at the rate of 1 ms<sup>-2</sup> upto three quarters of the total run and covers the last quater with uniform speed. How much time does she take to cover the first half and the second half of the run?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>The situation is shown in Fig.<br/>
<img alt="" data-imgur-src="lKQ6hS6.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354675-b3bux7.jpg" style="width: 200px; height: 53px;"/><br/>
For the motion from A to B:<br/>
u = 0, a = 1 ms<sup>-2</sup>, s = 50m<br/>
As s = ut + <span class="math-tex">{tex}\\frac 12{/tex}</span> at<sup>2</sup><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> 50 = 0 + <span class="math-tex">{tex}\\frac{1}{2} \\times 1 \\times t_{1}^{2}{/tex}</span><br/>
or <span class="math-tex">{tex}t_{1}^{2}{/tex}</span> = 100<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> Time taken for first half run AB = t<sub>1</sub> = 10 s.<br/>
For the motion from A to C:<br/>
u = 0, a = 1 ms<sup>-2</sup>, s = 75 m<br/>
As s = ut + <span class="math-tex">{tex}\\frac 12{/tex}</span> at<sup>2</sup><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> 75 = 0 + <span class="math-tex">{tex}\\frac{1}{2} \\times 1 \\times t_{2}^{2}{/tex}</span><br/>
or t<sub>2</sub> = <span class="math-tex">{tex}\\sqrt{150}{/tex}</span> = 12.2 s<br/>
Time taken to run BC = 12.2 - 10 = 2.2 s<br/>
Again for part AC, u = 0, a = 1 ms<sup>-2</sup>, t = 12.2 s<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> v = u + at = 0 + 1 <span class="math-tex">{tex}\\times{/tex}</span> 12.2 = 12.2 m s<sup>-1</sup><br/>
For motion from C to D: This motion is uniform with speed equal to 12.2 ms<sup>-1</sup><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> Time taken = <span class="math-tex">{tex}\\frac{25 \\mathrm{~m}}{12.2 \\mathrm{~ms}^{-1}}{/tex}</span> = 2.04 s<br/>
Total time taken for 2nd half run BD = 2.2 + 2.04 = 4.24 s</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Two stones are thrown up simultaneously from the edge of a cliff 200 m high with initial speeds of 15 m/s and 30 m/s. Verify that the graph shown in figure correctly represents the time variation of the relative position of the second stone with respect to the first. Neglect air resistance and assume that the stones do not rebound after hitting the ground. Take g = 10 m/s<sup>2</sup>. Give the equations for the linear and curved parts of the plot.<br/>
<img alt="" data-imgur-src="Ed6D28Y.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1612842846-aupe86.jpg" style="width: 250px; height: 194px;"/></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>For the&nbsp;first stone, Initial velocity is given by,&nbsp;u<sub>1</sub> = 15 m/s<br />
and Acceleration is, a = -10 m/s<sup>2</sup>&nbsp;<br />
Now, using the second equation of motion, we get<br />
x<sub>1</sub> = x<sub>0</sub> + u<sub>1</sub>t + (<span class="math-tex">{tex}\\frac 12{/tex}</span>)at<br />
Here&nbsp;x<sub>0</sub>&nbsp;= 200 m&nbsp;is the height of the cliff.<br />
Therefore,&nbsp;x<sub>1&nbsp;</sub>= 200 + 15 t = 5t<sup>2</sup> ...(i)<br />
When stone hits the ground,&nbsp;x<sub>1&nbsp;</sub>= 0<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;-5t<sup>2</sup>&nbsp;+ 15t + 200 = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t<sup>2</sup>&nbsp;- 3t - 40 = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t<sup>2</sup>&nbsp;- 8t + 5t - 40 = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t(t - 8) + 5(t - 8) = 0<br />
i.e.,&nbsp;t = 8 s or t = -5 s<br />
t cannot be negative as the stone is projected at a certain time.<br />
Therefore, t = 8 sec<br />
For second stone, Initial velocity is given by, u<sub>2</sub>&nbsp;= 30 m/s<br />
&nbsp;and Acceleration is, a = -g = -10 m/s<sup>2</sup><br />
Now, using the second equation of motion, we get&nbsp;<br />
x<sub>2</sub>&nbsp;= x<sub>0</sub>&nbsp;+ x<sub>2</sub>t&nbsp;+ (<span class="math-tex">{tex}\\frac 12{/tex}</span>)at<sup>2</sup><br />
= 200 + 30t - 5t<sup>2</sup>...(ii)<br />
When stone hits the ground, x<sub>2</sub> = 0<br />
So,&nbsp;-5t<sup>2</sup>&nbsp;+ 30t + 200 = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t<sup>2</sup>&nbsp;- 6t - 40 = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t<sup>2</sup>&nbsp;- 10t + 4t + 40 = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t(t - 10) + 4(t - 10) = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t(t - 10)(t +&nbsp;10) = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;t = 10s ot t = -4 s<br />
t cannot be negative again.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;t = 10 s<br />
On subtracting equations (i) and (ii), we have<br />
x<sub>2</sub>&nbsp;-&nbsp;x<sub>1</sub>&nbsp;= (200 + 30t - 5t<sup>2</sup>)-(200 + 15t - 5t<sup>2</sup>)<br />
x<sub>2</sub>&nbsp;- x<sub>1&nbsp;</sub>= 15t....(iii)<br />
Equation (iii) represents the linear path of both stones.<br />
Due to this linear relation between&nbsp;(x<sub>2</sub>&nbsp;-&nbsp;x<sub>1</sub>)&nbsp;and t, the path remains a straight line till 8s.<br />
At t = 8 sec, stones are separated by a maximum distance. hence,<br />
(​​x<sub>2</sub>&nbsp;-&nbsp;x​​​​​<sub>1</sub>)<sub>max</sub>&nbsp;= 15&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;8 = 120 m<br />
this is in accordance with the given graph.<br />
After 8s, only second stone is in motion whose variation with times is given by the quadratic equation:<br />
x<sub>2</sub>&nbsp;-&nbsp;x​​​​​​​​​​​​<sub>1</sub>&nbsp;= 200 + 30t = 5t<sup>2</sup><br />
Therefore, the equation of the linear path is given by:<br />
x<sub>2</sub>&nbsp;-&nbsp;x​​​​​​​​​​​​<sub>1</sub>&nbsp;= 15t,<br />
and the equation of curved path is given by:<br />
​​​​​​​x<sub>2</sub>&nbsp;-&nbsp;x​​​​​​​​​​​​<sub>1</sub>&nbsp;= 200 + 30t - 5t<sup>2</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>If a body moving with uniform acceleration in a straight line describes successive equal distances in time intervals t<sub>1</sub>, t<sub>2</sub>, and t<sub>3</sub> then show that&nbsp;<span class="math-tex">{tex}\\frac{1}{t_{1}}-\\frac{1}{t_{2}}+\\frac{1}{t_{3}}=\\frac{3}{t_{1} \\ + \\ t_{2} \\ + \\ t_{3}}{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>As shown in Figure, let the three successive equal distances be represented by AB, BC and CD.<br/>
<img alt="" data-imgur-src="PalBSWg.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1635354742-rjc8ee.jpg" style="width: 300px; height: 70px;"/><br/>
Let each distance be x m. Let v<sub>A</sub>, v<sub>B</sub>, v<sub>C</sub> and v<sub>D </sub>be the velocities at points A, B, C and D respectively.<br/>
Average velocity between A and B = <span class="math-tex">{tex}\\frac{v_{A} \\ + \\ v_{B}}{2}{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore \\quad \\frac{v_{A} \\ + \\ v_{B}}{2} \\times t_{1}{/tex}</span> = x<br/>
or v<sub>A</sub> + v<sub>B</sub> = <span class="math-tex">{tex}\\frac{2 x}{t_{1}}{/tex}</span><br/>
Similarly, v<sub>B</sub> + v<sub>C</sub> = <span class="math-tex">{tex}\\frac{2 x}{t_{2}}{/tex}</span> and v<sub>C</sub> + v<sub>D</sub> = <span class="math-tex">{tex}\\frac{2 x}{t_{3}}{/tex}</span><br/>
Average velocity between A and D = <span class="math-tex">{tex}\\frac{v_{A} \\ + \\ v_{D}}{2}{/tex}</span><br/>
​​​​<span class="math-tex">{tex}\\therefore \\ \\frac{v_{A} \\ + \\ v_{D}}{2}{/tex}</span> (t<sub>1</sub> + t<sub>2</sub> + t<sub>3</sub>) = x + x + x<br/>
or v<sub>A</sub> + v<sub>D</sub> = <span class="math-tex">{tex}\\frac{6 x}{t_{1} \\ + \\ t_{2} \\ + \\ t_{3}}{/tex}</span><br/>
Hence v<sub>A</sub> + v<sub>D</sub> = (v<sub>A</sub> + v<sub>B</sub>) - (v<sub>B</sub> + v<sub>C</sub>) + (v<sub>C</sub> + v<sub>D</sub>)<br/>
or <span class="math-tex">{tex}\\frac{6 x}{t_{1} \\ + \\ t_{2} \\ + \\ t_{3}}=\\frac{2 x}{t_{1}}-\\frac{2 x}{t_{2}}+\\frac{2 x}{t_{3}}{/tex}</span><br/>
or <span class="math-tex">{tex}\\frac{3}{t_{1} \\ + \\ t_{2} \\ + \\ t_{3}}=\\frac{1}{t_{1}}-\\frac{1}{t_{2}}+\\frac{1}{t_{3}}{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A player throws a ball upwards with an initial speed of 29.4 ms<sup>-1</sup>.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>What is the direction of acceleration during the upward motion of the ball?</li>
	<li>What are the velocity and acceleration of the&nbsp;ball at the highest point of its motion?</li>
	<li>Choose the x = 0 m and t = 0 s to be the location and time of the ball at its highest point, vertically downward direction to be the positive direction of x-axis, and give the signs of position, velocity and acceleration of the ball during its upward, and downward motion.</li>
	<li>To what height does the ball rise and after how long does the ball return to the player&rsquo;s hands? (Take g =&nbsp;9.8 ms<sup>-2</sup> and neglect air resistance).</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Irrespective of the direction of motion of the ball, acceleration (which is actually acceleration due to gravity) always act in the downward direction towards the centre of the earth.</li>
	<li>At the highest point, the velocity of the ball becomes zero and acceleration is equal to the acceleration due to gravity = 9.8 ms<sup>-2</sup>&nbsp;in&nbsp;vertically downward direction.</li>
	<li>When the highest point is chosen as the location for&nbsp;x = 0&nbsp;and t = 0 and vertically downward direction to be the positive direction of x-axis and upward direction as negative direction of x-axis.<br />
	During upward motion, sign of position is negative, sign of&nbsp;velocity is negative and sign of acceieration is positive. During downward motion, sign of position is positive, sign of velocity is positive and sign of acceleration is also positive.</li>
	<li>Taking vertical upward motion of the ball, we have<br />
	u = - 29.4 ms<sup>-1</sup>, a = 9.8 ms<sup>-2</sup>, v = 0, s = S, t = ? (where t be the time taken by the ball to reach the highest point where height from ground be s)<br />
	As, v<sup>2</sup>&nbsp;- u<sup>2</sup>&nbsp;= 2as or v<sup>2</sup>&nbsp;- u<sup>2</sup>&nbsp;= 2gs<br />
	<span class="math-tex">{tex}\\therefore 0 - ( - 29.4 ) ^ { 2 } = 2 \\times 9.8 \\times S{/tex}</span><br />
	or S =&nbsp;<span class="math-tex">{tex}\\frac { - ( 29.4 ) ^ { 2 } } { 2 \\times 9.8 }{/tex}</span>=&nbsp;- 44.1 m<br />
	where negative sign shows that the distance is covered in upward direction.<br />
	Also we know that, v = u + at<br />
	<span class="math-tex">{tex}\\therefore 0 = - 29.4 + 9.8 \\times t{/tex}</span>&nbsp; or&nbsp;&nbsp;<span class="math-tex">{tex}t = \\frac { 29.4 } { 9.8 } = 3 \\mathrm { s }{/tex}</span><br />
	It means time of ascent = 3 seconds<br />
	Since the time of ascent&nbsp;is always equal to the time of descent when an object moves under the effect of gravity alone.<br />
	Hence, total time after which the ball returns to the player&rsquo;s hand = 3 + 3 = 6 seconds</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1343-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_MOTION_IN_A_PLANE = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The angle between the two vectors<br />
<span class="math-tex">{tex}\\vec{A}=3 \\hat{i}+4 \\hat{j}+5 \\hat{k}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\vec{B}=3 \\hat{i}+4 \\hat{j}-5 \\hat{k}{/tex}</span>&nbsp;will be</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">90°</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\vec{A}=3 \\hat{i}+4 \\hat{j}+5 \\hat{k}{/tex}</span><br />
<span class="math-tex">{tex}\\vec{B}=3 \\hat{i}+4 \\hat{j}-5 \\hat{k}{/tex}</span><br />
<span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}=3 \\times 3+4 \\times 4+5 \\times(-5){/tex}</span>&nbsp;= 0<br />
<span class="math-tex">{tex}\\Rightarrow \\vec{A} \\perp \\vec{B}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">180°</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">45°</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The angle between&nbsp;<span class="math-tex">{tex}A = \\hat i + \\hat j{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}B = \\hat i - \\hat j{/tex}</span> is&nbsp;</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">90<sup>o</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\cos (\\theta)=\\frac{\\vec{A} \\cdot \\vec{B}}{|\\vec{A}||\\vec{B}|}=\\frac{(\\hat{i}+\\hat{j}) \\cdot(\\hat{i}-\\hat{j})}{|\\sqrt{1^{2}+1^{2}}||\\sqrt{1^{2}+(-1)^{2}}|}=\\frac{1-1}{2}=0{/tex}</span><br />
<span class="math-tex">{tex}\\theta=\\cos ^{-1}(0)=\\frac{\\pi}{2}~ or ~90^{0}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span style="font-size: 13px;">45</span><sup>o</sup></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><sup><span style="font-size: 13px;"> </span></sup><span style="font-size: 13px;">- 45</span><sup>o</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">180<sup>o</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two vectors are perpendicular if</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}=1{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{A} \\times \\vec{B}=0{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}=0{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>For two perpendicular vectors<br />
<span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}{/tex}</span>&nbsp;= AB cos90<sup>o</sup> = 0</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}=A B{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p><span class="math-tex">{tex}\\vec{A}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\vec{B}{/tex}</span>&nbsp;are two vectors and&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;is the angle between them, if&nbsp;<span class="math-tex">{tex}|\\vec{A} \\times \\vec{B}|=\\sqrt{3}(\\vec{A} \\cdot \\vec{B}){/tex}</span>, the value of&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">45°</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">30°</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">90°</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">60°</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Given:&nbsp;<span class="math-tex">{tex}|\\vec{A} \\times \\vec{B}|=\\sqrt{3}(\\vec{A} \\cdot \\vec{B}){/tex}</span><br />
<span class="math-tex">{tex}\\therefore A B \\sin \\theta=\\sqrt{3} A B \\cos \\theta{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\tan \\theta=\\sqrt{3} \\Rightarrow \\theta=60^{\\circ}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If&nbsp;<span class="math-tex">{tex}\\vec{P}+\\vec{Q}=\\vec{R}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}|\\vec{P}|=|\\vec{Q}|=|\\vec{R}|{/tex}</span>, then angle between&nbsp;<span class="math-tex">{tex}\\vec{P}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\vec{Q}{/tex}</span>&nbsp;is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">30<sup>o</sup></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">60<sup>o</sup></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">90<sup>o</sup></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">120<sup>o</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As&nbsp;<span class="math-tex">{tex}\\vec{R}=\\vec{P}+\\vec{Q}{/tex}</span><br />
and&nbsp;<span class="math-tex">{tex}|\\vec{P}|=|\\vec{Q}|=|\\vec{R}|{/tex}</span>,<br />
R<sup>2</sup> = P<sup>2</sup> + Q<sup>2</sup> + 2 PQcos<span class="math-tex">{tex}\\theta{/tex}</span><br />
or P<sup>2</sup> = P<sup>2</sup> + P<sup>2</sup> + 2P<sup>2</sup> cos<span class="math-tex">{tex}\\theta{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\cos \\theta=-\\frac{1}{2}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\theta=120^{\\circ}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The horizontal range of projectile is <span class="math-tex">{tex}4 \\sqrt{3}{/tex}</span>&nbsp;times of its maximum height. The angle of projection will be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">40°</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">90°</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">30°</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\frac{u^{2} \\sin 2 \\theta}{g}=4 \\sqrt{3} \\times \\frac{u^{2} \\sin ^{2} \\theta}{2 g}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow 2 \\sin \\theta \\cos \\theta=2 \\sqrt{3} \\sin ^{2} \\theta{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\tan \\theta=\\frac{1}{\\sqrt{3}} \\Rightarrow \\theta=30^{\\circ}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">45°</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A particle is projected at an angle 45&deg;. The relation between range and maximum height attained by the particle is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">R = 4H</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}R=\\frac{u^{2} \\sin \\left(2 \\times 45^{\\circ}\\right)}{g}=\\frac{u^{2}}{g}{/tex}</span><br />
<span class="math-tex">{tex}H=\\frac{u^{2} \\sin ^{2} 45^{\\circ}}{2 g}=\\frac{u^{2}}{4 g}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span> R = 4H</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">4R = H</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">2H = R</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">2R = 4H</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If&nbsp;<span class="math-tex">{tex}|\\vec{A} \\times \\vec{B}|=|\\vec{A} \\cdot \\vec{B}|{/tex}</span>, then angle between&nbsp;<span class="math-tex">{tex}\\vec{A}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\vec{B}{/tex}</span>&nbsp;will be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">30<sup>o</sup></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">60<sup>o</sup></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">45<sup>o</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Given:&nbsp;<span class="math-tex">{tex}|\\vec{A} \\times \\vec{B}|=|\\vec{A} \\cdot \\vec{B}|{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;AB sin<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= AB cos<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;or tan<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 1<br />
<span class="math-tex">{tex}\\therefore \\theta=45^{\\circ}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">90<sup>o</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two equal vectors have a resultant equal to either. The angle between them is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">60°</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">90°</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">100°</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">120°</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Here P = Q = R<br />
As&nbsp;<span class="math-tex">{tex}R=\\sqrt{P^{2}+Q^{2}+2 P Q \\cos \\theta}{/tex}</span><br />
<span class="math-tex">{tex}P=\\sqrt{P^{2}+P^{2}+2 P . P \\cos \\theta}{/tex}</span><br />
or&nbsp;P<sup>2</sup> = 2 P<sup>2</sup> (1 + cos <span class="math-tex">{tex}\\theta{/tex}</span>)<br />
or&nbsp;<span class="math-tex">{tex}1+\\cos \\theta=\\frac{1}{2}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\cos \\theta=-\\frac{1}{2}{/tex}</span>&nbsp;= cos 120<sup>o</sup> or&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 120<sup>o</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A and B are two inclined vectors. R is their sum. Choose the correct figure for the given description.</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683799820-6qnmqj.jpg" style="width: 120px; height: 106px;"/></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683799914-r47xsg.jpg" style="width: 120px; height: 107px;"/></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683800256-vkykx3.jpg" style="width: 120px; height: 106px;"/></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline"><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683800146-4d9e2y.jpg" style="width: 120px; height: 107px;"/></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683800463-t9e4b4.jpg" style="width: 150px; height: 111px;" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The vectors&nbsp;<span class="math-tex">{tex}\\vec{A}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\vec{B}{/tex}</span>&nbsp;are such that&nbsp;<span class="math-tex">{tex}|\\vec{A}+\\vec{B}|=|\\vec{A}-\\vec{B}|{/tex}</span>.&nbsp;The angle between the two vectors is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">45°</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">90°</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Given:<br />
<span class="math-tex">{tex}|\\vec{A}+\\vec{B}|=|\\vec{A}-\\vec{B}|{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}|\\vec{A}+\\vec{B}|^{2}=|\\vec{A}-\\vec{B}|^{2}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}(\\vec{A}+\\vec{B}) \\cdot(\\vec{A}+\\vec{B}){/tex}</span>&nbsp;<span class="math-tex">{tex}=(\\vec{A}-\\vec{B}) \\cdot(\\vec{A}-\\vec{B}){/tex}</span>&nbsp;<span class="math-tex">{tex}\\left[\\because|\\vec{A}|^{2}=\\vec{A} \\cdot \\vec{A}\\right]{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\vec{A} \\cdot \\vec{A}+\\vec{A} \\cdot \\vec{B}+\\vec{B} \\cdot \\vec{A}+\\vec{B} \\cdot \\vec{B}{/tex}</span>&nbsp;<span class="math-tex">{tex}=\\vec{A} \\cdot \\vec{A}-\\vec{A} \\cdot \\vec{B}-\\vec{B} \\cdot \\vec{A}+\\vec{B} \\cdot \\vec{B}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}A^{2}+2 \\vec{A} \\cdot \\vec{B}+B^{2}{/tex}</span>&nbsp;<span class="math-tex">{tex}=A^{2}-2 \\vec{A} \\cdot \\vec{B}+B^{2}{/tex}</span>&nbsp;<span class="math-tex">{tex}[\\because \\vec{B} \\cdot \\vec{A}=\\vec{A} \\cdot \\vec{B}]{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}4 \\vec{A} \\cdot \\vec{B}=0{/tex}</span>&nbsp;or 4 AB cos&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 0<br />
As&nbsp;<span class="math-tex">{tex}\\vec{A}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\vec{B}{/tex}</span>&nbsp;are non-zero vectors, so<br />
cos&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 0 or&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 90<sup>o</sup></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">60°</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">75°</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The angle between the two vectors&nbsp;<span class="math-tex">{tex}\\vec{A}=5 \\hat{i}+5 \\hat{j}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\vec{B}=5 \\hat{i}-5 \\hat{j}{/tex}</span> will be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">90<sup>o</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}=(5 \\hat{i}+5 \\hat{j}) \\cdot(5 \\hat{i}-5 \\hat{j})=0{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\theta=90^{\\circ}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">45<sup>o</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">0<sup>o</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A unit vector is a vector&nbsp;having a magnitude of 1 and points in</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">any chosen direction</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>A unit vector is a vector that has a magnitude of 1 unit. A unit vector is also known as a direction vector. It is represented using a lowercase letter with a cap (&lsquo;^&rsquo;) symbol along with it. A vector can be represented in space using unit vectors. Any vector can become a unit vector by dividing it by the vector&rsquo;s magnitude as follows:<br />
<span class="math-tex">{tex}\\text { Unit vector} =\\frac{\\text { vector }}{\\text { magnitude of the vector }}{/tex}</span><br />
<span class="math-tex">{tex}\\hat i{/tex}</span>&nbsp;=&nbsp;a unit vector directed along the positive x-axis<br />
<span class="math-tex">{tex}\\hat j{/tex}</span>&nbsp;= a unit vector directed along the positive y-axis<br />
<span class="math-tex">{tex}\\hat k{/tex}</span> = a unit vector directed along the positive z-axis</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">x-direction</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">y-direction</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">z-direction</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two vectors are equal if</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">the magnitude and direction are the same for both.</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Equal vectors are vectors that have the same magnitude and the same direction. Equal vectors may start at different positions.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">the magnitude is the same for both.</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">the direction is the same for both.</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">the two vectors have opposite directions.</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If <span class="math-tex">{tex}|\\vec{A}+\\vec{B}|=|\\vec{A}|+|\\vec{B}|{/tex}</span>, then the angle between A and B will be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">90°</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">120°</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">0°</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>When&nbsp;<span class="math-tex">{tex}\\theta=0^{\\circ}{/tex}</span>,<br />
<span class="math-tex">{tex}|\\vec{A}+\\vec{B}|=\\sqrt{|\\vec{A}|^{2}+|\\vec{B}|^{2}+2|\\vec{A}||\\vec{B}| \\cos 0^{\\circ}}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}|\\vec{A}|+|\\vec{B}|{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">60°</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A cyclist starts from the centre O of a circular park of radius 1 km, reaches the edge P of the park, then cycles along the circumference, and returns to the centre along QO as shown in figure. If the round trip takes 10 min, what is the</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>net displacement,</li>
	<li>average velocity, and</li>
	<li>average speed of the cyclist?</li>
</ol>

<p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683711152-u7rppp.jpg" style="width: 150px; height: 153px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Displacement is given by the minimum&nbsp;distance between the initial and final&nbsp;positions of a body. In the given case,&nbsp;the cyclist comes to the starting point&nbsp;after cycling for 10 minutes.<br />
	Hence, his net displacement is zero.</li>
	<li>Average velocity is given by the relation:&nbsp;Average velocity&nbsp;<span class="math-tex">{tex}= \\frac { \\text {net displacement} } { \\text {total time interval} }{/tex}</span><br />
	Since the net displacement of the cyclist&nbsp;is zero, his average velocity will also be zero.</li>
	<li>Average speed of the cyclist is given by the relation:&nbsp;Average speed&nbsp;<span class="math-tex">{tex}= \\frac { \\text {total path length} } { \\text {time interval} }{/tex}</span><br />
	Total path length&nbsp;= OP + PQ + QO<br />
	Total path length&nbsp;<span class="math-tex">{tex}= 1 + \\frac { 1 } { 4 } ( 2 \\pi \\times 1 ) + 1 = 2 + \\frac { 1 } { 2 } \\pi = 3.570 \\mathrm { km }{/tex}</span><br />
	Time taken&nbsp;<span class="math-tex">{tex}= 10 \\mathrm { min } = \\frac { 10 } { 60 } = \\frac { 1 } { 6 } h{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Average speed&nbsp;<span class="math-tex">{tex}= \\frac { 3.570 } { \\frac { 1 } { 6 } } = 21.42 \\mathrm { km } / \\mathrm { h }{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define Angular velocity and Angular acceleration. Derive an expression for centripetal acceleration of a uniform circular motion of an object.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let a body is revolving with constant speed v in a circle and V<sub>1</sub> and V<sub>2</sub> are the velocities at A and B as shown in figure, therefore change in velocity is given as<br />
The force of a moving object can be written as<br />
F = ma ...(1)<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1700816746-qu2a9w.jpg" style="height:110px; width:260px" /><br />
Let a body is revolving with constant speed v in a circle and V<sub>1</sub> and V<sub>2</sub> are the velocities at A and B as shown in figure, therefore change in velocity is given as<br />
<span class="math-tex">{tex}\\overrightarrow{\\Delta V}{/tex}</span> = <span class="math-tex">{tex}\\overrightarrow{V_2}{/tex}</span> - <span class="math-tex">{tex}\\overrightarrow{V_1}{/tex}</span><br />
The triangles PQS and AOB are similar, therefore<br />
<span class="math-tex">{tex}\\frac{\\Delta V}{A B}{/tex}</span> = <span class="math-tex">{tex}\\frac{v}{r}{/tex}</span> (here v is the magnitude of velocity of body in circle)<br />
<span class="math-tex">{tex}\\frac{\\Delta V}{v \\triangle t}{/tex}</span> = <span class="math-tex">{tex}\\frac{v}{r}{/tex}</span><br />
<span class="math-tex">{tex}\\frac{\\Delta V}{\\triangle t}{/tex}</span> = <span class="math-tex">{tex}\\frac{v^2}{r}{/tex}</span><br />
acceleration = <span class="math-tex">{tex}\\frac{\\Delta V}{\\Delta t}{/tex}</span> = <span class="math-tex">{tex}\\frac{v^2}{r}{/tex}</span><br />
The acceleration is along the direction of <span class="math-tex">{tex}\\overrightarrow{\\triangle v}{/tex}</span> as for small <span class="math-tex">{tex}\\triangle{/tex}</span>t, <span class="math-tex">{tex}\\overrightarrow{\\triangle v}{/tex}</span> is perpendicular to the direction of v, therefore acceleration is directed perpendicular to the tan gent to the circle.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A plane is flying horizontally at a height of 1000 m with a velocity of 100 ms<sup>-1</sup>. when a bomb is released from it. Find</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the time taken by it to reach the ground</li>
	<li>the velocity with which the bomb hits the target and</li>
	<li>the distance of the target.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><img alt="" data-imgur-src="VncYzV7.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965333-t45wuw.jpg" style="width: 200px; height: 175px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Time Taken;<br/>
<span class="math-tex">{tex}T=\\sqrt{\\frac{2 H}{g}}=\\sqrt{\\frac{2 \\times 1000}{10}}{/tex}</span><br/>
	= <span class="math-tex">{tex}10 \\sqrt{2} \\mathrm{sec}{/tex}</span></li>
<li>When bomb hits the target, it will have 2 components,<br/>
	v<sub>x</sub> and v<sub>y</sub><br/>
	v<sub>x</sub> = 100m/s (<span class="math-tex">{tex}\\because{/tex}</span> a<sub>x</sub> = 0)<br/>
	Now, Time of Height<br/>
<span class="math-tex">{tex}T=\\sqrt{\\frac{2 H}{g}}=\\sqrt{\\frac{2 \\times 1000}{10}}{/tex}</span> <span class="math-tex">{tex}=\\sqrt{200} \\text { sec }=10 \\sqrt{2} se c{/tex}</span><br/>
	To find V<sub>y</sub><br/>
	In vertical direction, u<sub>y</sub> = 0, <span class="math-tex">{tex}t=10 \\sqrt{2}{/tex}</span>, a = -g s = -1000m<br/>
<span class="math-tex">{tex}\\therefore v_{y}^{2}-v_{y}^{2}=2 a_{y} s_{y}{/tex}</span><br/>
<span class="math-tex">{tex}v_{y}^{2}{/tex}</span>  = 2(-10)(-1000)<br/>
	v<sub>y</sub> = <span class="math-tex">{tex}100 \\sqrt{2}{/tex}</span> m/s<br/>
	v<sub>nef</sub> <span class="math-tex">{tex}=\\sqrt{v_{x}^{2}+v_{y}^{2}}{/tex}</span><br/>
<span class="math-tex">{tex}=\\sqrt{(100)^{2}+(100 \\sqrt{2})^{2}}{/tex}</span> <span class="math-tex">{tex}=100 \\sqrt{3}{/tex}</span> m/s</li>
<li>Range = (TOF) <span class="math-tex">{tex}\\times{/tex}</span> U<sub>x</sub><br/>
<span class="math-tex">{tex}=10 \\sqrt{2} \\times 100{/tex}</span> <span class="math-tex">{tex}=1000 \\sqrt{2} \\mathrm{~m}{/tex}</span></li>
</ol></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that there are two angles of projection for a projectile to have the same horizontal range. What will be the maximum heights attained in the two cases? Compare the two heights for <span class="math-tex">{tex}\\theta{/tex}</span> = 30&deg; and 60&deg;</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let <span class="math-tex">{tex}\\theta{/tex}</span> and (90 - <span class="math-tex">{tex}\\theta{/tex}</span>) be the angles of projection for a projectile thrown with same initial velocity u.<br />
Range of projectile = <span class="math-tex">{tex}\\frac{u^2\\sin^2\\theta}g{/tex}</span><br />
for angle <span class="math-tex">{tex}\\theta{/tex}</span> R<sub>1</sub> = <span class="math-tex">{tex}\\frac{u^2\\sin^2\\theta}g{/tex}</span> ...(1)<br />
for angle (90 - <span class="math-tex">{tex}\\theta{/tex}</span>), R<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2\\sin2(90-\\theta)}g{/tex}</span> = <span class="math-tex">{tex}\\frac{u^2\\sin(180-2\\theta)}g{/tex}</span> = <span class="math-tex">{tex}\\frac{u^2\\sin2\\theta}{g}{/tex}</span><br />
R<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2\\sin2\\theta}g{/tex}</span> ...(2)<br />
from (1) and (2), we get R<sub>1</sub> = R<sub>2</sub><br />
Maximum height for <span class="math-tex">{tex}\\theta{/tex}</span> angle of projection is<br />
H<sub>1</sub> = <span class="math-tex">{tex}\\frac{u^2\\sin^2\\theta}{2g}{/tex}</span><br />
Maximum height for (90 - <span class="math-tex">{tex}\\theta{/tex}</span>)​ angle of projection is​​​​​​<br />
H<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2\\sin^2(90-\\theta)}{2g}{/tex}</span> = <span class="math-tex">{tex}\\frac{u^2\\cos^2\\theta}{2g}{/tex}</span><br />
<span class="math-tex">for <span class="math-tex">{tex}\\theta{/tex}</span> = 30<sup>o</sup></span><br />
H<sub>1</sub> = <span class="math-tex">{tex}\\frac{u^2\\sin^230}{2g}{/tex}</span><span class="math-tex"> = <span class="math-tex">{tex}\\frac{u^2}{8g}{/tex}</span></span><br />
H<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2\\cos^230}{2g}{/tex}</span> = <span class="math-tex"><span class="math-tex">{tex}\\frac{3u^2}{8g}{/tex}</span><br />
for <span class="math-tex">{tex}\\theta{/tex}</span> = 60<sup>o</sup></span><br />
H<sub>1</sub> = <span class="math-tex">{tex}\\frac{u^2\\sin^260}{2g}{/tex}</span><span class="math-tex"> = <span class="math-tex">{tex}\\frac{3u^2}{8g}{/tex}</span></span><br />
H<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2\\cos^260}{2g}{/tex}</span> = <span class="math-tex"><span class="math-tex">{tex}\\frac{u^2}{8g}{/tex}</span></span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>unit vector</li>
	<li>null vector</li>
	<li>cross product of two vectors <span class="math-tex">{tex}\\vec{A}{/tex}</span>&nbsp;and <span class="math-tex">{tex}\\vec{B}{/tex}</span>.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>A unit vector is a vector of unit magnitude drawn in the direction of a given vector. A unit vector in the direction of a given vector is found by dividing the given vector by its modulus.</li>
	<li>A null vector is a vector that has magnitude equal to zero and is directionless. It is the resultant of two or more equal vectors that are acting opposite to each other.</li>
	<li>The vector or cross product of two vectors is defined as the vector whose magnitude is equal to the product of the magnitudes o f two vectors and sine of the angle between them and whose direction is perpendicular to the plane of the two vectors and is given by right hand rule.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Define time of flight and horizontal range.</li>
	<li>From a certain height above the ground, a stone A is dropped gently. Simultaneously another stone B is fired horizontally. Which of the two stones will arrive on the ground earlier?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><b>Projectile motion</b>&nbsp;is a form of&nbsp;motion&nbsp;experienced by an object or particle (a&nbsp;projectile) that is thrown near the Earth&#39;s surface and moves along a curved path under the action of&nbsp;gravity&nbsp;only (in particular, the effects of&nbsp;air resistance&nbsp;are assumed to be negligible).</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li><u><strong>Time of flight</strong></u> - The time taken by the projectile to complete its trajectory is called time of flight.

	<p><u><strong>Horizontal Range</strong></u> - The maximum horizontal distance covered by the projectile form the foot of the tower to the point where projectile hits the ground is called horizontal range.</p>
	</li>
	<li>
	<p>Both the stones will reach the ground simultaneously because the initial vertical velocity in both cases is zero and both are falling with same acceleration equal to acceleration due to gravity.</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A passenger arriving in a new town wishes to go from the station to a hotel located 10 km away on a straight road from the station. A dishonest cabman takes him along a circuitous path 23 km long and reaches the hotel in 28 min. What is</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>the average speed of the taxi?</li>
	<li>the magnitude of average velocity? Are the two equal?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Total distance travelled = 23 km<br />
	Total times taken = 28 min&nbsp;<span class="math-tex">{tex}= \\frac { 28 } { 60 } h{/tex}</span><br />
	Average speed of the taxi&nbsp;<span class="math-tex">{tex}= \\frac { \\text { total dis tan }ce \\text { travelled } } { \\text {time interval} }{/tex}</span><br />
	<span class="math-tex">{tex}s _ { a v } = \\frac { 23 } { \\frac { 28 } { 60 } } = 49.29 \\mathrm { km } / \\mathrm { h }{/tex}</span></li>
	<li>Distance between the hotel and the station = 10 km = Displacement of the car<br />
	Average velocity&nbsp;<span class="math-tex">{tex}= \\frac { \\text {displacement} } { \\text {time interval} } = \\frac { 10 } { \\frac { 28 } { 60 } } = 21.43 \\mathrm { km } / h{/tex}</span><br />
	Therefore, the two physical quantities (average speed and average velocity) are not equal.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State with reasons, whether the following algebraic operations with scalar and vector physical quantities are meaningful:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>adding any two scalars,</li>
	<li>adding a scalar to a vector of the same dimensions,</li>
	<li>multiplying any vector by any scalar,</li>
	<li>multiplying any two scalars,</li>
	<li>adding any two vectors,</li>
	<li>adding a component of a vector to the same vector.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>The addition of two scalar quantities is meaningful only if they both represent the same physical quantity.</li>
	<li>The addition of a vector quantity with a scalar quantity is not meaningful.</li>
	<li>A scalar can be multiplied with a vector. For example, force is multiplied with time to give impulse.</li>
	<li>A scalar, irrespective of the physical quantity, can be multiplied with another scalar having the same or different dimensions.</li>
	<li>The addition of two vector quantities is meaningful only if they both represent the same physical quantity.</li>
	<li>A component of a vector can be added to the same vector as they both have the same dimensions.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A particle has a displacement of 12 m towards east and 5 m towards the north and then 6 m vertically upward. Find the magnitude of the sum of these displacements.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>As shown in the figure, suppose initially the particle is at origin O. Then its displacement vectors are<br/>
<span class="math-tex">{tex}\\vec {O A}{/tex}</span> = 12 m, due east<br/>
<span class="math-tex">{tex}\\vec {A B}{/tex}</span> = 5m, due north<br/>
<span class="math-tex">{tex}\\vec {C D}{/tex}</span> = 6m, vertically upwards.<br/>
<img alt="" data-imgur-src="C3zx5Wm.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965346-qpy6je.jpg" style="width: 230px; height: 190px;"/><br/>
According to polygon law, <span class="math-tex">{tex}\\vec{O C}{/tex}</span> is the resultant displacement. From right <span class="math-tex">{tex}\\Delta{/tex}</span>OAB,<br/>
<span class="math-tex">{tex}O B=\\sqrt{O A^{2}+A B^{2}}=\\sqrt{12^{2}+5^{2}}{/tex}</span><br/>
<span class="math-tex">{tex}=\\sqrt{144+25}{/tex}</span> = 13 m<br/>
From right <span class="math-tex">{tex}\\Delta{/tex}</span>OBC,<br/>
<span class="math-tex">{tex}O C=\\sqrt{O B^{2}+B C^{2}}=\\sqrt{13^{2}+6^{2}}{/tex}</span><br/>
<span class="math-tex">{tex}=\\sqrt{169+36}=\\sqrt{205}{/tex}</span> = 14.32m</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A bullet fired at an angle of 30&deg; with the horizontal hits the ground 3.0 km away. By adjusting its angle of projection, can one hope to hit a target 5.0 km away? Assume the muzzle speed to the fixed, and neglect air resistance.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given: Horizontal Range, R = 3 km = 3000 m<br />
Angle of projection,&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span> = 30&deg;<br />
Acceleration due to gravity,&nbsp;<span class="math-tex">{tex}g = 9.8 \\mathrm { m } / \\mathrm { s } ^ { 2 }{/tex}</span><br />
Horizontal range for the projection velocity&nbsp;<span class="math-tex">{tex}u _ { 0 }{/tex}</span>, is given by the relation:<br />
<span class="math-tex">{tex}R = \\frac { u ^ { 2 } \\sin 2 \\theta } { g }{/tex}</span><br />
<span class="math-tex">{tex}3000 = \\frac { u _ { 0 } ^ { 2 } } { g } \\sin 60 ^ { \\circ }{/tex}</span><br />
<span class="math-tex">{tex}3000 = \\frac { u _ { 0 } ^ { 2 } } { g } \\times \\frac { \\sqrt { 3 } } { 2 }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { u _ { 0 } ^ { 2 } } { g } = 2 \\sqrt { 3 } \\times 1000{/tex}</span>&nbsp; .........(i)<br />
The maximum range (R<sub>max</sub> is achieved by the bullet when it is fired at an angle of&nbsp;<span class="math-tex">{tex}45 ^ { \\circ }{/tex}</span>&nbsp;with the horizontal)<br />
<span class="math-tex">{tex}\\mathrm { R } _ { \\max } = \\frac { \\mathrm { u } _ { 0 } ^ { 2 } } { g }{/tex}</span> .........(ii)<br />
On comparing equations (i) and (ii), we get:<br />
<span class="math-tex">{tex}R_\\max=2\\sqrt3\\;\\times1000=2\\times1.732\\times1000=3.46\\mathrm~{km}{/tex}</span><br />
Hence by keeping the same muzzle speed u, one can not hit a target which is 5 km away just by changing projection angle.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A ball is thrown at an angle <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;and another ball is thrown at an angle (90&deg; - <span class="math-tex">{tex}\\theta{/tex}</span>) with the horizontal direction from the same point with velocity 39.2 ms<sup>-1</sup>. The second ball reaches 50 m higher than the first ball. Find their individual heights. Take g = 9.8 ms<sup>-1</sup></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>For the first ball : Angle of projection = <span class="math-tex">{tex}\\theta{/tex}</span>, Velocity of projection, u = 39.2 ms<sup>-1</sup><br />
As maximum height,<br />
<span class="math-tex">{tex}H=\\frac{u^{2} \\sin ^{2} \\theta}{2 g}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore H=\\frac{(39.2)^{2} \\sin ^{2} \\theta}{2 \\times 9.8}{/tex}</span>&nbsp;..... (i)<br />
For the second ball: Angle of projection = 90&deg; -&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>, velocity of projection, u =39.2 ms<sup>-1</sup>, maximum height reached = (H + 50) m<br />
<span class="math-tex">{tex}\\therefore H+50=\\frac{(39.2)^{2} \\sin ^{2}\\left(90^{\\circ}-\\theta\\right)}{2 \\times 9.8}{/tex}</span><br />
or H +&nbsp;50&nbsp;<span class="math-tex">{tex}=\\frac{(39.2)^{2} \\sin ^{2}\\left(90^{\\circ}-\\theta\\right)}{2 \\times 9.8}{/tex}</span>&nbsp;..... (ii)<br />
Adding (i) and (ii), we get<br />
<span class="math-tex">{tex}2 H+50=\\frac{(39.2)^{2}}{2 \\times 9.8}\\left(\\sin ^{2} \\theta+\\cos ^{2} \\theta\\right){/tex}</span><br />
<span class="math-tex">{tex}=\\frac{(39.2)^{2}}{2 \\times 9.8}=78.4{/tex}</span><br />
or 2H = 78.4 - 50 = 28.4 or H = 14.2 m<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Height of first ball = H = 14.2 m<br />
Height of second ball<br />
= H + 50=14.2 + 50 = 64.2 m.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A machine gun is mounted on the top of a tower 100 m high. At what angle should the gun be inclined to cover a maximum range of firing on the ground below? The muzzle speed of the bullet is 150 ms<sup>-1</sup>, take g = 10 ms<sup>-2</sup></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let u be the muzzle speed of the bullet fired from the gun (on the top of the tower) at an angle <span class="math-tex">{tex}\\theta{/tex}</span> with the horizontal, as shown in Figure.<br/>
Clearly, the total range of firing on the ground is<br/>
<span class="math-tex">{tex}x=\\frac{u^{2} \\sin 2 \\theta}{g}+100 \\cot \\theta{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore \\quad \\frac{d x}{d \\theta}=\\frac{u^{2} \\times 2 \\cos 2 \\theta}{g}{/tex}</span><span class="math-tex">{tex}+100 \\times\\left(-\\operatorname{cosec}^{2} \\theta\\right){/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{2 u^{2}}{g}\\left(1-2 \\sin ^{2} \\theta\\right)-\\frac{100}{\\sin ^{2} \\theta}{/tex}</span><br/>
= 4500 - 9000 <span class="math-tex">{tex}\\sin ^{2} \\theta-\\frac{100}{\\sin ^{2} \\theta}{/tex}</span><br/>
<img alt="" data-imgur-src="4uJTgpp.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965322-qr8bpy.jpg" style="width: 250px; height: 187px;"/><br/>
For x to be maximum,<br/>
<span class="math-tex">{tex}\\frac{d x}{d \\theta}=0{/tex}</span><br/>
4500 - 9000 <span class="math-tex">{tex}\\sin ^{2} \\theta-\\frac{100}{\\sin ^{2} \\theta}=0{/tex}</span><br/>
<span class="math-tex">{tex}90 \\sin ^{4} \\theta-45 \\sin ^{2} \\theta+1=0{/tex}</span><br/>
or <span class="math-tex">{tex}\\sin ^{2} \\theta=\\frac{45 \\pm \\sqrt{(-45)^{2}-4 \\times 90 \\times 1}}{2 \\times 90}{/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{45 \\pm 40.80}{180}{/tex}</span><br/>
Taking only positive sign,<br/>
sin<sup>2</sup> <span class="math-tex">{tex}\\theta{/tex}</span> = 0.4767<br/>
or sin <span class="math-tex">{tex}\\theta{/tex}</span> = 0.6904<br/>
or <span class="math-tex">{tex}\\theta{/tex}</span> = 43.7<sup>o</sup></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State and explain polygon law of vector addition.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><u><strong>Polygon law of vector addition:</strong></u><strong>&nbsp;</strong>It states that if a number of vectors can be represented in magnitude and direction by the sides of a polygon taken in the same order, then their resultant is represented in magnitude and direction by the closing side of the polygon taken in the opposite order.<br />
Let us find the resultant of four vectors <span class="math-tex">{tex}\\vec{A}, \\vec{B}, \\vec{C}{/tex}</span> and <span class="math-tex">{tex}\\vec{D}{/tex}</span>.<br />
<img border="0" data-imgur-src="Polygon_law_of_vecto_addition.jpg" height="110" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/Polygon_law_of_vecto_addition.jpg" width="300" /></p>

<p>In triangle OKL, the vectors <span class="math-tex">{tex}\\vec{A} {/tex}</span> and <span class="math-tex">{tex}\\vec{B}{/tex}</span> are represented by the sides <span class="math-tex">{tex}\\overrightarrow{OK}{/tex}</span> and <span class="math-tex">{tex}\\overrightarrow{KL}{/tex}</span> taken in the same order. Therefore, from the triangle law of vector addition, the closing side <span class="math-tex">{tex}\\overrightarrow{OL}{/tex}</span> taken in the opposite order represents the resultant of vectors <span class="math-tex">{tex}\\overrightarrow{OK}{/tex}</span> and <span class="math-tex">{tex}\\overrightarrow{KL}{/tex}</span>.<br />
Thus, <span class="math-tex">{tex}\\overrightarrow{O K}+\\overrightarrow{K L}=\\overrightarrow{O L}{/tex}</span> .................(1)<br />
By applying the triangle law of vector addition to the triangle OLM, it shows that the side <span class="math-tex">{tex}\\overrightarrow{\\mathrm{OM}}{/tex}</span> is the resultant of vectors <span class="math-tex">{tex}\\overrightarrow{\\mathrm{OL}}{/tex}</span> and <span class="math-tex">{tex}\\overrightarrow{\\mathrm{LM}}{/tex}</span> i.e., <span class="math-tex">{tex}\\overrightarrow{\\mathrm{OL}}+\\overrightarrow{\\mathrm{LM}}=\\overrightarrow{\\mathrm{OM}}{/tex}</span>.<br />
Using eq (1), we get,<br />
<span class="math-tex">{tex}\\overrightarrow{\\mathrm{OK}}+\\overrightarrow{\\mathrm{KL}}+\\overrightarrow{\\mathrm{LM}}=\\overrightarrow{\\mathrm{OM}}{/tex}</span> ................... (2)<br />
Similarly, applying the triangle law of vector addition to the triangle OMN, we get,<br />
<span class="math-tex">{tex}\\overrightarrow{\\mathrm{OM}}+\\overrightarrow{\\mathrm{MN}}=\\overrightarrow{\\mathrm{ON}}{/tex}</span><br />
Using eq (2), we get,<br />
<span class="math-tex">{tex}\\overrightarrow{\\mathrm{OK}}+\\overrightarrow{\\mathrm{KL}}+\\overrightarrow{\\mathrm{LM}}+\\overrightarrow{\\mathrm{MN}}=\\overrightarrow{\\mathrm{ON}}{/tex}</span> ........................ (3)<br />
Now the vectors <span class="math-tex">{tex}\\overrightarrow{O K}=\\vec{A}, \\; \\overrightarrow{K L}=\\vec{B}, \\overrightarrow{L M}=\\vec{C}{/tex}</span> and <span class="math-tex">{tex}\\overrightarrow{\\mathrm{MN}}=\\overrightarrow{\\mathrm{D}}{/tex}</span>. Denoting the vector, <span class="math-tex">{tex}\\overrightarrow{O N}=\\vec{R}{/tex}</span>, the equation becomes,<br />
<span class="math-tex">{tex}\\vec{A}+\\vec{B}+\\vec{C}+\\vec{D}=\\vec{R}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>At what point of projectile motion (i) potential energy maximum (ii) Kinetic energy maximum (iii) total mechanical energy is maximum?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>(i) Potential Energy will be maximum at the highest point.</p>

<p>(P.E.) highest point = mgH, where H&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;maximum height above ground that projectile will attain.</p>

<p>maximum height&nbsp;<span class="math-tex">{tex}H = \\frac { u ^ { 2 } \\sin ^ { 2 } ( \\theta ) } { 2 g }{/tex}</span></p>

<p>(P.E.) highest point&nbsp;<span class="math-tex">{tex}m g \\left( \\frac { u ^ { 2 } \\sin ^ { 2 } ( \\theta ) } { 2 g } \\right) = \\frac { 1 } { 2 } m u ^ { 2 } \\sin ^ { 2 } ( \\theta ){/tex}</span></p>

<p>(ii) K.E will be maximum&nbsp;at the highest point</p>

<p><span class="math-tex">{tex}( K . E . ) _ { H } = \\frac { 1 } { 2 } m \\left( u_ { H } \\right) ^ { 2 }{/tex}</span></p>

<p>(Vertical component of velocity is zero)</p>

<p><span class="math-tex">{tex}(K.E.)_H=\\frac12mu^2\\cos^2\\theta{/tex}</span></p>

<p>(iii)&nbsp; Total mechanical energy=&nbsp; (K. E.)<sub>H</sub> + (P.E.)<sub>H</sub></p>

<p><sub><span class="math-tex">{tex}E=\\frac { 1 } { 2 } m u ^ { 2 } \\cos ^ { 2 } \\theta + \\frac { 1 } { 2 } m u ^ { 2 } \\sin ^ { 2 } \\theta{/tex}</span></sub></p>

<p><span class="math-tex">{tex}E=\\frac { 1 } { 2 } m u ^ { 2 } \\left( \\cos ^ { 2 } \\theta + \\sin ^ { 2 } \\theta \\right){/tex}</span></p>

<p><span class="math-tex">{tex}E=\\frac { 1 } { 2 } m u ^ { 2 }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A hunter aims his gun and fires a bullet directly at a monkey on a tree. At the instant the bullet leaves the barrel of the gun, the monkey drops. Will the bullet hit the monkey? Substantiate your answer with proper reasoning.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>As shown in Figure, the gun at O is directed towards the monkey at position M. Suppose the bullet leaves the barrel of the gun with velocity u at an angle <span class="math-tex">{tex}\\theta{/tex}</span> with the horizontal. Let the bullet cross the vertical line MB at A after time t. Horizontal distance travelled,<br/>
OB = x = <span class="math-tex">{tex}u \\cos \\theta \\cdot t{/tex}</span><br/>
or <span class="math-tex">{tex}t=\\frac{x}{u \\cos \\theta}{/tex}</span> ..... (i)<br/>
<img alt="" data-imgur-src="7xkaeej.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965326-82uqe5.jpg" style="width: 200px; height: 188px;"/><br/>
For motion of the bullet from O to B, the vertical range is<br/>
AB <span class="math-tex">{tex}=u \\sin \\theta \\cdot t-\\frac{1}{2} g t^{2}{/tex}</span> <span class="math-tex">{tex}=u \\sin \\theta \\cdot \\frac{x}{u \\cos \\theta}-\\frac{1}{2} g t^{2}{/tex}</span><br/>
<span class="math-tex">{tex}=x \\tan \\theta-\\frac{1}{2} g t^{2}{/tex}</span> [using (i)]<br/>
Also MB = x tan <span class="math-tex">{tex}\\theta{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> MA = MB - AB<br/>
<span class="math-tex">{tex}=x \\tan \\theta-\\left[x \\tan \\theta-\\frac{1}{2} g t^{2}\\right]=\\frac{1}{2} g t^{2}{/tex}</span><br/>
Thus in a time t the bullet passes through A a vertical distance <span class="math-tex">{tex}\\frac{1}{2} g t^{2}{/tex}</span> below M.<br/>
The vertical distance through which the monkey falls in time t<br/>
<span class="math-tex">{tex}=0+\\frac{1}{2} g t^{2}=\\frac{1}{2} g t^{2}{/tex}</span><br/>
Thus the bullet and the monkey will always reach the point A at the same time. Hence the bullet will always hit the monkey whatever be the velocity of the bullet.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two projectiles are thrown with different velocities and at different angles so as to cover the same maximum height. Show that the sum of the times taken by each to reach the highest point is equal to the total time taken by either of the projectiles.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If the two projectiles are thrown with velocities u<sub>1</sub> and u<sub>2</sub> at angle <span class="math-tex">{tex}\\theta_{1}{/tex}</span>&nbsp;and <span class="math-tex">{tex}\\theta_{2}{/tex}</span>&nbsp;with horizontal, then their maximum heights will be<br />
<span class="math-tex">{tex}H_{1}=\\frac{u_{1}^{2} \\sin ^{2} \\theta_{1}}{2 g}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}H_{2}=\\frac{u_{2}^{2} \\sin ^{2} \\theta_{2}}{2 g}{/tex}</span><br />
But H<sub>1</sub> = H<sub>2</sub><br />
<span class="math-tex">{tex}\\therefore \\frac{u_{1}^{2} \\sin ^{2} \\theta_{1}}{2 g}=\\frac{u_{2}^{2} \\sin ^{2} \\theta_{2}}{2 g}{/tex}</span><br />
or u<sub>1</sub>sin<span class="math-tex">{tex}\\theta_{1}{/tex}</span>&nbsp;= u<sub>2</sub> sin<span class="math-tex">{tex}\\theta_{2}{/tex}</span>&nbsp;..... (i)<br />
Times of flight for the two projectiles are<br />
<span class="math-tex">{tex}T_{1}=\\frac{2 u_{1} \\sin \\theta_{1}}{g}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}T_{2}=\\frac{2 u_{2} \\sin \\theta_{2}}{g}{/tex}</span><br />
Making use of equation (i), we get<br />
T<sub>1</sub> = T<sub>2</sub>&nbsp;<span class="math-tex">{tex}=\\frac{2 u_{1} \\sin \\theta_{1}}{g}=\\frac{2 u_{2} \\sin \\theta_{2}}{g}{/tex}</span><br />
Times taken to reach the highest point in the two cases will be<br />
<span class="math-tex">{tex}t_{1}=\\frac{u_{1} \\sin \\theta_{1}}{g}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}t_{2}=\\frac{u_{2} \\sin \\theta_{2}}{g}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;t<sub>1</sub> + t<sub>2</sub>&nbsp;<span class="math-tex">{tex}=\\frac{u_{1} \\sin \\theta_{1}}{g}+\\frac{u_{2} \\sin \\theta_{2}}{g}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{2 u_{1} \\sin \\theta_{1}}{g} \\text { or } \\frac{2 u_{2} \\sin \\theta_{2}}{g}{/tex}</span>&nbsp;[using (i)]<br />
or [t<sub>1</sub>&nbsp;+ t<sub>2</sub> = Time of flight of either projectile.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A ball is thrown from a rooftop at an angle of 45<sup>o</sup>&nbsp;above the horizontal. It hits the ground a few seconds later. At what point during its motion, does the ball have</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>greatest speed</li>
	<li>smallest speed</li>
	<li>greatest acceleration? Explain.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>A ball is projected from O at an angle of 45<sup><span style="font-size: 10.8333px;">o</span></sup> with horizontal. From O to A body rises up, height increases so its speed &amp; hence &nbsp;KE (speed) decreases. From A to B it&rsquo;s speed again increases as its height decreases and become equal to its&rsquo;s initial speed at O, because O and B are on the same horizontal line.<br />
<img id="Picture 6" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-04/image142.png" /><br />
From B to C, its height again decreases so its speed from B to C increases and become maximum at C<br />
<span class="math-tex">{tex}v _ { y } = v _ { x } = u \\cos ( 45 ) = \\frac { u } { \\sqrt { 2 } } m / s{/tex}</span>&nbsp;at Point B.<br />
Now for motion along BC,&nbsp;<span class="math-tex">{tex}v _ { x } ^ { \\prime } = \\frac { u } { \\sqrt { 2 } }{/tex}</span>&nbsp;remains constant but<br />
​​​​​​<span class="math-tex">{tex}v _ { y } ^ { \\prime } = v _ { y } + g t{/tex}</span>&nbsp;thus velocity along y - axis changes.<br />
net velocity&nbsp;<span class="math-tex">{tex}v = \\sqrt { \\left( v _ { x } ^ { \\prime } \\right) ^ { 2 } + \\left( v _ { y } ^ { \\prime } \\right) ^ { 2 } }{/tex}</span>&nbsp;become maximum at point C<br />
<span class="math-tex">{tex}v = \\sqrt { \\frac { u ^ { 2 } } { 2 } + \\frac { u ^ { 2 } } { 2 } + g ^ { 2 } t ^ { 2 } }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}v = \\sqrt { u ^ { 2 } + g ^ { 2 } t ^ { 2 } }{/tex}</span>&nbsp;<br />
Hence,</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Greatest speed of ball is at C .</li>
	<li>The smallest speed will be at A . Where at maximum height and&nbsp;<span class="math-tex">{tex}v _ { y } = 0{/tex}</span>&nbsp;and&nbsp;&nbsp;has the only horizontal speed of constant value u<sub>x</sub>=<span class="math-tex">{tex}\\frac{u}{\\sqrt{2}}{/tex}</span>.&nbsp;&nbsp;</li>
	<li>For motion between O to A, acceleration a = -g and for A to C acceleration a = +g and is constant during AC.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A cricket ball is thrown at a speed of 28 m s<sup>-1</sup> in a direction 30 above the horizontal. Calculate</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the maximum height</li>
	<li>the time taken by the ball to return to the same level and</li>
	<li>the distance from the thrower to the point where the ball returns to the same level.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>The maximum height attained by the ball is given by the equation,<br />
	<span class="math-tex">{tex}H _ { m } = \\frac { \\left( v _ { 0 } \\sin \\theta _ { 0 } \\right) ^ { 2 } } { 2 g }{/tex}</span><br />
	<span class="math-tex">{tex}= \\frac { \\left( 28 \\sin 30 ^ { \\circ } \\right) ^ { 2 } } { 2 ( 9.8 ) } = \\frac { 14 \\times 14 } { 2 \\times 9.8 }{/tex}</span>= 10.0 m</li>
	<li>The time taken by the ball to return to the same level, i.e. time of flight is given by the equation<br />
	T =<span class="math-tex">{tex}\\left( 2 v _ { 0 } \\sin \\theta _ { 0 } \\right) / g = \\left( 2 \\times 28 \\times \\sin 30 ^ { \\circ } \\right) / 9.8{/tex}</span><br />
	= 28/9.8 = 2.9 s</li>
	<li>The distance from the thrower to the point where the ball returns to the same level is the range of the projectile given by the relation<br />
	R =&nbsp;<span class="math-tex">{tex}\\frac { \\left( v _ { 0 } ^ { 2 } \\sin 2 \\theta _ { 0 } \\right) } { g } = \\frac { 28 \\times 28 \\times \\sin 60 ^ { \\circ } } { 9.8 }{/tex}</span>= 69.3 m</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Find the angle between the vectors A =&nbsp;<span class="math-tex">{tex}\\hat { \\mathbf { i } } - 2 \\hat { \\mathbf { j } } - \\hat { \\mathbf { k } }{/tex}</span>&nbsp;and B =&nbsp;<span class="math-tex">{tex}- \\hat { \\mathbf { i } } + \\hat { \\mathbf { j } } - 2 \\hat { \\mathbf { k } }{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given two vectors&nbsp;A =&nbsp;<span class="math-tex">{tex}\\hat { \\mathbf { i } } - 2 \\hat { \\mathbf { j } } - \\hat { \\mathbf { k } }{/tex}</span>&nbsp;and B =&nbsp;<span class="math-tex">{tex}- \\hat { \\mathbf { i } } + \\hat { \\mathbf { j } } - 2 \\hat { \\mathbf { k } }{/tex}</span></p>

<p>From the expression of dot product or scalar product.<br />
A.B = AB cos &theta;..........(i)<br />
The magnitude of <span class="math-tex">{tex}\\vec {A}{/tex}</span>&nbsp;is given by<br />
<span class="math-tex">{tex}A = \\sqrt { ( 1 ) ^ { 2 } + ( -2 ) ^ { 2 } + ( - 1 ) ^ { 2 } } = \\sqrt { 6 }{/tex}</span>..........(ii)<br />
The magnitude of <span class="math-tex">{tex}\\vec {B}{/tex}</span>&nbsp;is given by<br />
<span class="math-tex">{tex}B = \\sqrt { ( - 1 ) ^ { 2 } + ( 1 ) ^ { 2 } + ( - 2 ) ^ { 2 } } = \\sqrt { 6 }{/tex}</span>........(iii)<br />
Now solving&nbsp;LHS of Eq (i)<br />
A.B =&nbsp;<span class="math-tex">{tex}( \\hat { \\mathbf { i } } - 2 \\hat { \\mathbf { j } } - \\hat { \\mathbf { k } } ) \\cdot ( { - \\hat { \\mathbf { i } } } + \\hat { \\mathbf { j } } - 2 \\hat { \\mathbf { k } } ){/tex}</span><br />
<span class="math-tex">{tex}= ( 1 .- 1 ) ( \\hat { \\mathbf { i } } \\cdot \\hat { \\mathbf { i } } ) + ( 1 \\cdot 1 ) ( \\hat { \\mathbf { i } } \\cdot \\hat { j } ) + ( 1 \\cdot - 2 ) ( \\hat { \\mathbf { i } } \\cdot \\hat { \\mathbf { k } } ) + ( 2 \\cdot - 1 ){/tex}</span> <span class="math-tex">{tex}( \\hat { j } \\cdot \\hat { \\mathbf { i } } ) + ( -2 \\cdot 1 ) ( \\hat { \\mathbf { j } } \\cdot \\hat { \\mathbf { j } } ) + ( 2 \\cdot - 2 ) ( \\hat { \\mathbf { j } } \\cdot \\hat { \\mathbf { k } } ) + ( - 1 \\cdot - 1 ){/tex}</span><br />
<span class="math-tex">{tex}( \\hat { \\mathbf { k } } \\cdot \\hat { \\mathbf { i } } ) + ( - 1 \\cdot \\mathbf { 1 } ) ( \\hat { \\mathbf { k } } \\cdot \\hat { \\mathbf { j } } ) + ( - 1 \\cdot - 2 ) ( \\hat { \\mathbf { k } } \\cdot \\hat { \\mathbf { k } } ){/tex}</span><br />
A.B = -1<br />
Substituting the values of A from Eq. (ii) and B from Eq. (iii) and A.B = -1&nbsp;in Eq. (i), we get<br />
<span class="math-tex">{tex}-1 = ( \\sqrt { 6 } ) ( \\sqrt { 6 } ) \\cos \\theta{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\cos \\theta = \\frac { -1 } { 6 } \\Rightarrow \\theta = \\cos ^ { - 1 } \\left( \\frac { -1 } { 6 } \\right) = 80.44 ^ { \\circ }{/tex}</span>in the third quadrant</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The ceiling of a long hall is 25 m high. What is the maximum horizontal distance that a ball thrown with a speed of 40 ms<sup>-1</sup> can go without hitting the ceiling of the hall?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Speed of the ball, u = 40 m/s</p>

<p>Maximum height, h = 25 m</p>

<p>In Projectile motion, the maximum height reached by a body projected at an angle&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>, is given by the relation:<br />
<span class="math-tex">{tex}h = \\frac { u ^ { 2 } \\sin ^ { 2 } \\theta } { 2 g }{/tex}</span><br />
<span class="math-tex">{tex}25 = \\frac { ( 40 ) ^ { 2 } } { 2 \\times 9.8 }{/tex}</span><br />
<span class="math-tex">{tex}\\sin ^ { 2 } \\theta = 0.30625{/tex}</span><br />
<span class="math-tex">{tex}\\sin \\theta = 0.5534{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\theta = \\sin ^ { - 1 } ( 0.5534 ) = 33.60 ^ { \\circ }{/tex}</span><br />
Horizontal range, <span class="math-tex">{tex}R = \\frac { \\mathrm { u } ^ { 2 } \\sin 2 \\theta } { \\mathrm { g } }{/tex}</span><br />
<span class="math-tex">{tex}R= \\frac { ( 40 ) ^ { 2 } \\times \\sin( 2 \\times 33.60) } { 9.8 }{/tex}</span><br />
<span class="math-tex">{tex}R= \\frac { 1600 \\times \\sin( 67.2) } { 9.8 }{/tex}</span><br />
<span class="math-tex">{tex}R= \\frac { 1600 \\times 0.922 } { 9.8 } = 150.53 \\mathrm { m }{/tex}</span>&nbsp; &nbsp; so if ball is thrown at an angle smaller than&nbsp;<span class="math-tex">{tex}33.60^\\circ{/tex}</span>&nbsp;ball will not hit the ceiling and maximum horizontal distance the ball will cover is&nbsp;<span class="math-tex">{tex}\\approx150.53\\;m\\;\\;.{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Find the angle between the vectors<br />
<span class="math-tex">{tex}\\vec A{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>&nbsp;- 2<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>&nbsp;-&nbsp;<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>&nbsp;and <span class="math-tex">{tex}\\vec B{/tex}</span>&nbsp;= -<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>&nbsp;+&nbsp;<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>&nbsp;- 2<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The angle between two vectors is included in the expression of dot product or scalar product.<br />
<span class="math-tex">{tex}\\vec A \\cdot \\vec B{/tex}</span>&nbsp;= ABcos<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp; ...(i)<br />
<span class="math-tex">{tex}A = \\sqrt {(1)^2 + (-2)^2 + (-1)^2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\sqrt 6{/tex}</span>&nbsp; ...(ii)<br />
The magnitude of B is given by<br />
<span class="math-tex">{tex}B = \\sqrt {(-1)^2 + (1)^2 + (-2)^2} {/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\sqrt 6{/tex}</span>&nbsp;...(iii)<br />
We can separately evaluate the left side of Eq. (i) by writing the vectors in unit vector notation and using the distributive law.<br />
<span class="math-tex">{tex}\\vec A \\cdot \\vec B{/tex}</span>&nbsp;= (<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>&nbsp;+ 2<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>&nbsp;-&nbsp;<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>)&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;(-<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>&nbsp;+&nbsp;<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>&nbsp;- 2<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>)<br />
= (1&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;-1)(<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>) + (1&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;1)(<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>) + (1&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;-2)(<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>) + (2&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;-1)<br />
(<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>) + (2&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;1)(<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>) + (2&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;-2)(<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>) + (-1&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;-1)<br />
(<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text i}{/tex}</span>) + (-1&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;1)(<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text j}{/tex}</span>) + (-1&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;-2)(<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;<span class="math-tex">{tex}\\hat {\\text k}{/tex}</span>)<br />
<span class="math-tex">{tex}\\vec A \\cdot \\vec B{/tex}</span>&nbsp;= 3<span class="math-tex">{tex}\\left[\\begin{array}{rl} \\because \\hat{\\mathbf{i}} \\cdot \\hat{\\mathbf{i}} &amp; =1, \\hat{\\mathbf{i}} \\cdot \\hat{\\mathbf{j}}=0, \\hat{\\mathbf{i}} \\cdot \\hat{\\mathbf{k}}=0 \\\\ \\hat{\\mathbf{j}} \\cdot \\hat{\\mathbf{j}} &amp; =1, \\hat{\\mathbf{j}} \\cdot \\hat{\\mathbf{i}}=0, \\hat{\\mathbf{j}} \\cdot \\hat{\\mathbf{k}}=0 \\\\ \\hat{\\mathbf{k}} \\cdot \\hat{\\mathbf{k}} &amp; =1, \\hat{\\mathbf{k}} \\cdot \\hat{\\mathbf{i}}=0, \\hat{\\mathbf{k}} \\cdot \\hat{\\mathbf{j}}=0 \\end{array}\\right]{/tex}</span><br />
Substituting the values of A from Eq. (ii) and B from Eq. (iii) and <span class="math-tex">{tex}\\vec A \\cdot \\vec B{/tex}</span>&nbsp;= 6 in Eq. (i), we get<br />
3 =&nbsp;<span class="math-tex">{tex}(\\sqrt6){/tex}</span><span class="math-tex">{tex}(\\sqrt6){/tex}</span>&nbsp;cos&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;cos&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac 32{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac 12{/tex}</span>&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;cos<sup>-1&nbsp;</sup><span class="math-tex">{tex}(\\frac 12){/tex}</span>&nbsp;= 60<sup><span style="font-size: 10.8333px;">o</span></sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Find the angles between the following pairs of vectors:</p>

<ol start="1" style="list-style-type:lower-roman">
	<li><span class="math-tex">{tex}\\vec{A}=\\hat{i}+\\hat{j}+\\hat{k}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}=-2 \\hat{i}-2 \\hat{j}-2 \\hat{k}{/tex}</span></li>
	<li><span class="math-tex">{tex}\\vec{A}=-2 \\hat{i}+2 \\hat{j}-\\hat{k}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}=3 \\hat{i}+6 \\hat{j}+2 \\hat{k}{/tex}</span></li>
	<li><span class="math-tex">{tex}\\vec{A}=2 \\hat{i}-4 \\hat{j}+6 \\hat{k}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}=3 \\hat{i}+\\hat{j}+2 \\hat{k}{/tex}</span></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li><span class="math-tex">{tex}\\vec{A}=\\hat{i}+\\hat{j}+\\hat{k}{/tex}</span><br />
	<span class="math-tex">{tex}\\vec{B}=-2 \\vec{i}-2 \\vec{j}-2 \\vec{k}{/tex}</span><br />
	<span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}{/tex}</span>&nbsp;= -2 - 2 - 2 = -6<br />
	<span class="math-tex">{tex}A=\\sqrt{1^2+1^2+1^2}=\\sqrt{3}{/tex}</span><br />
	<span class="math-tex">{tex}B=\\sqrt{2^2+2^2+2^2}=\\sqrt{12}{/tex}</span><br />
	<span class="math-tex">{tex}\\cos \\theta=\\frac{\\vec{A} \\cdot \\vec{B}}{A B}=\\frac{-6}{\\sqrt{3} \\sqrt{12}}=-1{/tex}</span><br />
	<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 180<sup>o</sup></li>
	<li><span class="math-tex">{tex}\\vec{A}=-2 \\hat{i}+2 \\hat{j}-\\hat{k}{/tex}</span><br />
	<span class="math-tex">{tex}\\vec{B}=3 \\vec{i}+6 \\vec{j}+2 \\vec{k}{/tex}</span><br />
	<span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}{/tex}</span>&nbsp;= -6 + 12 - 2 = 4<br />
	<span class="math-tex">{tex}A=\\sqrt{2^2+2^2+1^2}=3{/tex}</span><br />
	<span class="math-tex">{tex}B=\\sqrt{3^2+6^2+2^2}=\\sqrt{49}=7{/tex}</span><br />
	<span class="math-tex">{tex}\\cos \\theta=\\frac{\\vec{A} \\cdot \\vec{B}}{A B}=\\frac{4}{3 \\times 7}=\\frac{4}{21}{/tex}</span><br />
	<span class="math-tex">{tex}\\theta=\\cos ^{-1}\\left(\\frac{4}{21}\\right){/tex}</span></li>
	<li><span class="math-tex">{tex}\\vec{A}=2 \\hat{i}-4 \\hat{j}+6 \\hat{k}{/tex}</span><br />
	<span class="math-tex">{tex}\\vec{B}=3 \\vec{i}+\\vec{j}+2 \\vec{k}{/tex}</span><br />
	<span class="math-tex">{tex}\\vec{A} \\cdot \\vec{B}{/tex}</span>&nbsp;= 6 - 4 + 12 = 14<br />
	<span class="math-tex">{tex}A=\\sqrt{2^2+4^2+6^2}=6{/tex}</span><br />
	<span class="math-tex">{tex}B=\\sqrt{3^2+1^2+2^2}=\\sqrt{14}{/tex}</span><br />
	<span class="math-tex">{tex}\\cos \\theta=\\frac{\\vec{A} \\cdot \\vec{B}}{A B}=\\frac{14}{6 \\times \\sqrt{14}}=\\frac{\\sqrt{14}}{6}{/tex}</span><br />
	<span class="math-tex">{tex}\\theta=\\cos ^{-1}\\left(\\frac{\\sqrt{14}}{6}\\right){/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A body is projected upwards with velocity u and at an angle <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;with the horizontal. Deduce the expressions for</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>maximum height attained,</li>
	<li>time of flight and</li>
	<li>horizontal range.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let us consider a ball projected at an angle <span class="math-tex">{tex}\\theta{/tex}</span> with respect to horizontal x-axis with the initial velocity u.<br/>
The point O is called the point of projection, <span class="math-tex">{tex}\\theta{/tex}</span> is the angle of projection and OB = horizontal range. The total time taken by the particle from reaching O to B is called the time of flight.<br/>
Now,</p>
<ol start="1" style="list-style-type: lower-roman;">
<li>The total time of flight is Resultant displacement is zero in Vertical direction.<br/>
	Therefore, by using equation of motion<br/>
	S = <span class="math-tex">{tex}u t-\\frac{1}{2} g t^{2}{/tex}</span><br/>
	gt = 2 sin <span class="math-tex">{tex}\\theta{/tex}</span><br/>
<span class="math-tex">{tex}\\mathrm{t}=\\frac{2 \\sin \\theta}{\\mathrm{g}}{/tex}</span></li>
<li>The horizontal range is<br/>
	Horizontal range OA = horizontal component of velocity <span class="math-tex">{tex}\\times{/tex}</span> total flight time<br/>
	R = <span class="math-tex">{tex}u \\cos \\theta \\times \\frac{2 u \\sin \\theta}{g}{/tex}</span><br/>
	R <span class="math-tex">{tex}=\\frac{\\mathrm{u}^{2} \\sin 2 \\theta}{\\mathrm{g}}{/tex}</span></li>
<li>The maximum height is<br/>
	It is the highest point of the trajectory point A.<br/>
	When the ball is at point A, the vertical component of the velocity will be zero.<br/>
	By using equation of motion<br/>
	v<sup>2</sup> = u<sup>2</sup> - 2as<br/>
	0 = u2sin2<span class="math-tex">{tex}\\theta{/tex}</span> - 2gH<br/>
	H = <span class="math-tex">{tex}\\frac{\\mathrm{u}^{2} \\sin ^{2} \\theta}{2 \\mathrm{~g}}{/tex}</span><br/>
	Hence, this is the required solution.</li>
</ol>
<p><img alt="" data-imgur-src="exQgxng.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965389-9e6vsw.jpg" style="width: 400px; height: 194px;"/></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that vectors A =&nbsp;<span class="math-tex">{tex}2 \\hat { \\mathbf { i } } - \\hat { \\mathbf { j } } - \\hat { \\mathbf { k } }{/tex}</span>&nbsp;and B =&nbsp;<span class="math-tex">{tex}- 6 \\hat { \\mathbf { i } } + 9 \\hat { \\mathbf { j } } + 3 \\hat { \\mathbf { k } }{/tex}</span>&nbsp;are parallel vectors.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The vectors are given by :-<br />
A =&nbsp;<span class="math-tex">{tex}2 \\hat { \\mathbf { i } } - \\hat { \\mathbf { j } } - \\hat { \\mathbf { k } }{/tex}</span><br />
and B =&nbsp;<span class="math-tex">{tex}- 6 \\hat { \\mathbf { i } } + 9 \\hat { \\mathbf { j } } + 3 \\hat { \\mathbf { k } }{/tex}</span>&nbsp;<br />
We know that, when&nbsp; the vectors are parallel, &nbsp;their cross product is zero, i.e.&nbsp;&theta; = 0,&nbsp;&nbsp;<span class="math-tex">{tex}\\mathbf { A } \\times \\mathbf { B } = 0{/tex}</span>.&nbsp;</p>

<p><br />
<span class="math-tex">{tex}\\therefore \\quad \\mathbf { A } \\times \\mathbf { B } = \\left| \\begin{array} { c c c } { \\hat { \\mathbf { i } } } &amp; { \\hat { \\mathbf { j } } } &amp; { \\hat { \\mathbf { k } } } \\\\ { 2 } &amp; { - 3 } &amp; { - 1 } \\\\ { - 6 } &amp; { 9 } &amp; { 3 } \\end{array} \\right|{/tex}</span><br />
<span class="math-tex">{tex}= \\hat { \\mathbf { i } } ( - 9 + 9 ) - \\hat { \\mathbf { j } } ( 6 - 6 ) + \\hat { \\mathbf { k } } ( 18 - 18 ) = 0{/tex}</span><br />
Now,&nbsp;&nbsp;<span class="math-tex">{tex}| \\mathbf { A } \\times \\mathbf { B } | = 0{/tex}</span>, but we know that vector A and B are non zero vectors.&nbsp;Therefore,<br />
<span class="math-tex">{tex}\\therefore \\sin \\theta = 0 \\text { or } \\theta = 0{/tex}</span><br />
Hence, the vectors A&nbsp;and B are parallel.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A projectile is projected horizontally with a velocity u. Show that its trajectory is parabolic. And obtain expressions for:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Time of flight</li>
	<li>&nbsp;Horizontal range</li>
	<li>Velocity at any instant t.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><strong>Projectile fired parallel to horizontal.</strong> As shown in figure, suppose a body is projected horizontally with velocity u from a point O at a certain height h above the ground level. The body is under the influence of two simultaneous independent motions:</p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Uniform horizontal velocity u.</li>
<li>Vertically downward accelerated motion with constant acceleration g.</li>
</ol>
<p>Under the combined effect of the above two motions, the body moves along the path OPA.<br/>
<img alt="" data-imgur-src="8mylJ6X.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965337-mpjuqv.jpg" style="width: 150px; height: 164px;"/><br/>
Trajectory of the projectile. After the time t, suppose the body reaches the point P (x, y).<br/>
The horizontal distance covered by the body in time t is<br/>
x = ut <span class="math-tex">{tex}\\therefore t=\\frac{x}{u}{/tex}</span><br/>
The vertical distance travelled by the body in time t is given by<br/>
s = <span class="math-tex">{tex}u t+\\frac{1}{2} a t^{2}{/tex}</span><br/>
or y <span class="math-tex">{tex}=0 \\times t+\\frac{1}{2} g t^{2}=\\frac{1}{2} g t^{2}{/tex}</span> [For vertical motion, u = 0]<br/>
or <span class="math-tex">{tex}y=\\frac{1}{2} g\\left(\\frac{x}{u}\\right)^{2}=\\left(\\frac{g}{2 u^{2}}\\right) x^{2}{/tex}</span> <span class="math-tex">{tex}\\left[\\because t=\\frac{x}{u}\\right]{/tex}</span><br/>
or y = kx<sup>2</sup> [Here k = <span class="math-tex">{tex}\\frac{g}{2 u^{2}}{/tex}</span> = a constant]<br/>
As y is a quadratic function of x, so the trajectory of the projectile is a parabola.<br/>
<strong>Time of flight.</strong> It is the total time for which the projectile remains in its flight (from O to A). Let T be its time of flight.<br/>
For the vertical downward motion of the body, we use<br/>
<span class="math-tex">{tex}s=u t+\\frac{1}{2} a t^{2}{/tex}</span> or h = <span class="math-tex">{tex}=0 \\times T+\\frac{1}{2} g T^{2}{/tex}</span><br/>
or <span class="math-tex">{tex}T-\\sqrt{\\frac{2 h}{g}}{/tex}</span><br/>
<strong>Horizontal range.</strong> It is the horizontal distance covered by the projectile during its time of flight. It is equal to OA = R. Thus<br/>
R = Horizontal velocity <span class="math-tex">{tex}\\times{/tex}</span> time of flight = u <span class="math-tex">{tex}\\times{/tex}</span> T<br/>
or R = <span class="math-tex">{tex}u\\sqrt{\\frac{2 h}{g}}{/tex}</span><br/>
<strong>Velocity of the projectile at any instant.</strong> At the instant t (when the body is at point P), let the velocity of the projectile be v. The velocity v has two rectangular components:<br/>
Horizontal component of velocity, v<sub>x</sub> = u<br/>
Vertical component of velocity, v<sub>y</sub> = 0 + gt = gt<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> The resultant velocity at point P is<br/>
<span class="math-tex">{tex}v=\\sqrt{v_{x}^{2}+v_{y}^{2}}=\\sqrt{u^{2}+g^{2} t^{2}}{/tex}</span><br/>
If the velocity v makes an angle p with the horizontal, then<br/>
<span class="math-tex">{tex}\\tan \\beta=\\frac{v_{y}}{v_{x}}=\\frac{g t}{u}{/tex}</span><br/>
or <span class="math-tex">{tex}\\beta=\\tan ^{-1}\\left(\\frac{g t}{u}\\right){/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State the parallelogram law of vector addition and find the magnitude and direction of the resultant of two vectors <span class="math-tex">{tex}\\vec{P}{/tex}</span>&nbsp;and <span class="math-tex">{tex}\\vec{Q}{/tex}</span>&nbsp;inclined at an angle <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;with each other. What happens, when <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 0&deg; and <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 90&deg;?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let us begin with the parallelogram law of vector addition.<br/>
The law states that if two vector quantities are represented by two adjacent sides of a parallelogram then the resultant of these two vectors will be the diagonal of the parallelogram.<br/>
Let us try and understand how this works:<br/>
<img alt="" data-imgur-src="dsK1VQ4.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965341-yvafjv.jpg" style="width: 250px; height: 186px;"/></p>
<p>Let the two vectors <span class="math-tex">{tex}\\vec{P}{/tex}</span> and <span class="math-tex">{tex}\\vec{Q}{/tex}</span> acting from the same point O be represented both in magnitude and direction as two adjacent sides OA and OD of a parallelogram OABD.<br/>
Let the angle between the two vectors be <span class="math-tex">{tex}\\theta{/tex}</span>.<br/>
According to our definition of the parallelogram law of vector addition, the diagonal of the parallelogram OB represents the resultant of <span class="math-tex">{tex}\\vec{P}{/tex}</span> and <span class="math-tex">{tex}\\vec{Q}{/tex}</span>. Thus, let the resultant of the two vectors be represented by <span class="math-tex">{tex}\\vec{R}{/tex}</span> that is at an angle <span class="math-tex">{tex}\\phi{/tex}</span> with <span class="math-tex">{tex}\\vec{P}{/tex}</span>.<br/>
<span class="math-tex">{tex}\\vec{R}=\\vec{P}+\\vec{Q}{/tex}</span><br/>
The sides AB = OD = <span class="math-tex">{tex}|Q|{/tex}</span> and OA = BD = <span class="math-tex">{tex}|P|{/tex}</span> and diagonal OB = <span class="math-tex">{tex}|R|{/tex}</span><br/>
Consider the right angle triangle OBC. From the Pythagorean theorem.<br/>
OB<sup>2</sup> = OC<sup>2</sup> + BC<sup>2</sup> = (OA + AC)<sup>2</sup> + BC<sup>2</sup><br/>
Consider the triangle ABC:<br/>
<span class="math-tex">{tex}\\cos \\theta=\\frac{A C}{A B}{/tex}</span> <span class="math-tex">{tex}\\Rightarrow{/tex}</span> AC = AB cos <span class="math-tex">{tex}\\theta{/tex}</span> = OD cos <span class="math-tex">{tex}\\theta{/tex}</span> <span class="math-tex">{tex}\\Rightarrow{/tex}</span> AC = <span class="math-tex">{tex}|Q| \\cos \\theta{/tex}</span><br/>
Also <span class="math-tex">{tex}\\sin \\theta=\\frac{B C}{A B}{/tex}</span> <span class="math-tex">{tex}\\Rightarrow{/tex}</span> BC = AB sin <span class="math-tex">{tex}\\theta{/tex}</span> = OD sin <span class="math-tex">{tex}\\theta{/tex}</span> <span class="math-tex">{tex}\\Rightarrow{/tex}</span> BC = <span class="math-tex">{tex}|Q \\mid \\sin \\theta{/tex}</span><br/>
Substituting the AC and BC expressions in the OB<sup>2</sup> Pythagorean theorem, we get:<br/>
<span class="math-tex">{tex}|R|^{2}=(|P|+|Q| \\cos \\theta)^{2}+(|Q| \\sin \\theta)^{2}{/tex}</span> <span class="math-tex">{tex}=|P|^{2}+2|P \\| Q| \\cos \\theta+|Q|^{2}\\left(\\cos ^{2} \\theta+\\sin ^{2} \\theta\\right){/tex}</span> <span class="math-tex">{tex}=|P|^{2}+2|P \\| Q| \\cos \\theta+|Q|^{2}{/tex}</span><br/>
Therefore, the magnitude of the resultant<br/>
<span class="math-tex">{tex}|R|=\\sqrt{|P|^{2}+2|P||Q| \\cos \\theta+|Q|^{2}}{/tex}</span><br/>
Now let us find the direction of the resultant:<br/>
From triangle ABC <span class="math-tex">{tex}\\tan \\phi=\\frac{B C}{O C}=\\frac{B C}{O A+A C}{/tex}</span> <span class="math-tex">{tex}=\\frac{|Q| \\sin \\theta}{|P|+|Q| \\cos \\theta}{/tex}</span><br/>
Therefore, the direction of the resultant with respect to <span class="math-tex">{tex}\\vec{P}{/tex}</span> is given by<br/>
<span class="math-tex">{tex}\\phi=\\tan ^{-1}\\left(\\frac{|Q| \\sin \\theta}{|P|+|Q| \\cos \\theta}\\right){/tex}</span><br/>
We have thus obtained the magnitude and direction of the resultant <span class="math-tex">{tex}\\vec{R}{/tex}</span><br/>
Now, when <span class="math-tex">{tex}\\theta=0^{\\circ}{/tex}</span>:<br/>
<span class="math-tex">{tex}|R|=\\sqrt{|P|^{2}+2|P||Q| \\cos 0+|Q|^{2}}{/tex}</span> <span class="math-tex">{tex}=\\sqrt{|P|^{2}+2|P||Q|+|Q|^{2}}=\\sqrt{(|P|+|Q|)^{2}}{/tex}</span> <span class="math-tex">{tex}\\Rightarrow|R|=|P|+|Q|{/tex}</span><br/>
<span class="math-tex">{tex}\\phi=\\tan ^{-1}\\left(\\frac{|Q| \\sin 0}{|P|+|Q| \\cos 0}\\right){/tex}</span> = tan<sup>-1</sup>(0) = 0<br/>
Thus, in this case, the magnitude of the resultant vector will be the sum of the magnitudes of the adjacent vectors and the resultant lies in the direction of <span class="math-tex">{tex}\\vec{P}{/tex}</span><br/>
And finally, when <span class="math-tex">{tex}\\theta{/tex}</span> = 90<sup>o</sup>:<br/>
<span class="math-tex">{tex}|R|=\\sqrt{|P|^{2}+2|P||Q| \\cos 90+|Q|^{2}}{/tex}</span> <span class="math-tex">{tex}=\\sqrt{|P|^{2}+|Q|^{2}}=\\sqrt{\\left(|P|^{2}+|Q|^{2}\\right)}{/tex}</span><br/>
<span class="math-tex">{tex}\\phi=\\tan ^{-1}\\left(\\frac{|Q| \\sin 90}{|P|+|Q| \\cos 90}\\right){/tex}</span> <span class="math-tex">{tex}=\\tan ^{-1}\\left(\\frac{Q}{P}\\right){/tex}</span><br/>
(since sin 0<sup>o</sup> = 0, cos 0<sup>o</sup> = 1, sin90<sup>o</sup> = 1, cos 90<sup>o</sup> = 0, tan 0<sup>o</sup> = 0)</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>On an open ground, a motorist follows a track that turns to his left by an angle of 60<sup>o</sup> after every 500 m. Starting from a given turn, specify the displacement of the motorist at the third, sixth and eighth turn. Compare the magnitude of the displacement with the total path length covered by the motorist in each case.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong><img src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch04/5m/image060.jpg" style="height:127px; width:170px" /></strong><br />
The path followed by the motorist is a regular hexagon with side 500 m, as shown in the given figure.<br />
Let the motorist start from point P. The motorist takes the third turn at S.<br />
Magnitude of displacement = PS = PV + VS = 500 + 500 = 1000 m&nbsp;<span class="math-tex">{tex}( \\because P V = Q R, V S = S R ){/tex}</span><br />
Total path length, d<sub>1</sub> = PQ + QR + RS = 500 + 500 + 500 = 1500 m<br />
The motorist take the sixth turn at point P, which is the starting point<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Magnitude of displacement = 0<br />
Total path length, d<sub>2</sub> = PQ + QR + RS + ST + TU + UP<br />
d<sub>2</sub> = 500 + 500 + 500&nbsp;+ 500 + 500+500 = 3000 m<br />
The motorist takes the eight turn at point R<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> Magnitude of displacement = PR<br />
<span class="math-tex">{tex}PR= \\sqrt { P Q ^ { 2 } + Q R ^ { 2 } + 2 ( P Q ) \\cdot ( Q R ) \\cos 60 ^ { \\circ } }{/tex}</span><br />
<span class="math-tex">{tex}PR= \\sqrt { 500 ^ { 2 } + 500 ^ { 2 } + \\left( 2 \\times 500 \\times 500 \\times \\cos 60 ^ { \\circ }) \\right. }{/tex}</span><br />
<span class="math-tex">{tex}PR= \\sqrt { 250000 + 250000 + \\left( 500000 \\times \\frac { 1 } { 2 } \\right) }{/tex}</span><br />
<span class="math-tex">{tex}PR=\\;866.03\\;m{/tex}</span><br />
<span class="math-tex">{tex}\\beta = \\tan ^ { - 1 } \\left( \\frac { 500 \\sin 60 ^ { \\circ } } { 500 + 500 \\cos 60 ^ { \\circ } } \\right) = 30 ^ { \\circ }{/tex}</span><br />
Therefore, the magnitude of displacement is 866.03 m at an angle of 30<sup>o</sup> with PR.<br />
Total path length = Circumference of the hexagon + PQ + QR<br />
Total path length= 6&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;500 + 500 + 500 = 4000 m<br />
The magnitude of displacement and the total path length corresponding to the required turns is shown in the given table</p>

<table border="1" cellpadding="3" cellspacing="0" style="width:100%">
	<tbody>
		<tr>
			<td>
			<p style="text-align:center"><strong>Turn</strong></p>
			</td>
			<td>
			<p style="text-align:center"><strong>Magnitude of displacement (m)</strong></p>
			</td>
			<td>
			<p style="text-align:center"><strong>Total path length (m)</strong></p>
			</td>
		</tr>
		<tr>
			<td>
			<p style="text-align:center">Third</p>
			</td>
			<td>
			<p style="text-align:center">1000</p>
			</td>
			<td>
			<p style="text-align:center">1500</p>
			</td>
		</tr>
		<tr>
			<td>
			<p style="text-align:center">Sixth</p>
			</td>
			<td>
			<p style="text-align:center">0</p>
			</td>
			<td>
			<p style="text-align:center">3000</p>
			</td>
		</tr>
		<tr>
			<td>
			<p style="text-align:center">Eighth</p>
			</td>
			<td>
			<p style="text-align:center">866.03; 30<sup>o</sup></p>
			</td>
			<td>
			<p style="text-align:center">4000</p>
			</td>
		</tr>
	</tbody>
</table></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>At what angle should a body be projected with a velocity 24 ms<sup>-1</sup> just to pass over the obstacle 16 m high at a horizontal distance of 32 m? Take g = 10 ms<sup>-2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>As shown in figure, if point of projection is taken as the origin of the coordinate system, the projected body must pass through a point having coordinates (32 m, 16 m). If u be the initial velocity of the projectile and <span class="math-tex">{tex}\\theta{/tex}</span> the angle of projection, then<br/>
Horizontal component of initial velocity, u<sub>x</sub> = u cos<span class="math-tex">{tex}\\theta{/tex}</span><br/>
Vertical component of initial velocity, u<sub>y</sub> = u sin<span class="math-tex">{tex}\\theta{/tex}</span><br/>
<img alt="" data-imgur-src="G6K4A3Z.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965320-uhz2zx.jpg" style="width: 250px; height: 98px;"/><br/>
If the body passes through point P after time t, then horizontal distance covered,<br/>
x = (u cos <span class="math-tex">{tex}\\theta{/tex}</span>)t<br/>
or 32 = (24 cos <span class="math-tex">{tex}\\theta{/tex}</span>)t ..... (i)<br/>
Similarly, vertical distance covered,<br/>
<span class="math-tex">{tex}y=(u \\sin \\theta) t-\\frac{1}{2} g t^{2}{/tex}</span><br/>
or 16 <span class="math-tex">{tex}=(24 \\sin \\theta) t-\\frac{1}{2} \\times 10 \\times t^{2}{/tex}</span><br/>
From equation (i), <span class="math-tex">{tex}t=\\frac{32}{24 \\cos \\theta}{/tex}</span><br/>
Putting this value of t in equation (ii), we get<br/>
<span class="math-tex">{tex}16=(24 \\sin \\theta) \\frac{32}{24 \\cos \\theta}-\\frac{1}{2}{/tex}</span><span class="math-tex">{tex}\\times 10 \\times\\left(\\frac{32}{24 \\cos \\theta}\\right)^{2}{/tex}</span><br/>
or 16 = 32 <span class="math-tex">{tex}\\tan \\theta-5 \\times \\frac{16}{9 \\cos ^{2} \\theta}{/tex}</span><br/>
or 1 = 2 tan <span class="math-tex">{tex}\\theta-\\frac{5}{9} \\sec ^{2} \\theta{/tex}</span><br/>
or 9 = 18 tan <span class="math-tex">{tex}\\theta{/tex}</span> - 5(1 + tan<sup>2</sup><span class="math-tex">{tex}\\theta{/tex}</span>)<br/>
or 5 tan<sup>2</sup><span class="math-tex">{tex}\\theta{/tex}</span> - 18 tan <span class="math-tex">{tex}\\theta{/tex}</span> + 14 = 0<br/>
<span class="math-tex">{tex}\\therefore \\tan \\theta=\\frac{18 \\pm \\sqrt{(18)^{2}-4 \\times 5 \\times 14}}{10}{/tex}</span><br/>
= 2.462 or 1.37<br/>
Hence <span class="math-tex">{tex}\\theta{/tex}</span> = 67<sup>o</sup>54' or 48<sup>o</sup>40'</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A fighter plane is flying horizontally at an altitude of 1.5 km with a speed of 720 km/h. At what angle of sight (w.r.t horizontal) when the target is seen, should the pilot drop the bomb in order to attack the target?<br />
<u><strong>Main concept used:</strong></u>&nbsp;u = 720 km/h =&nbsp;<span class="math-tex">{tex}720\\times\\frac{5}{18}{/tex}</span>m/s = 200m/s</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/static/review/8.png" style="width: 200px; height: 141px;" /><br />
Let the&nbsp;pilot drops the bomb in&nbsp;<strong>t</strong> second before the point <strong>Q</strong>, vertically up the target <strong>T</strong>.<br />
The horizontal velocity of the bomb will be&nbsp;equal to the velocity of the fighter plane, but the vertical component of it is zero.<br />
So, in time <strong>t</strong> bomb must cover the vertical distance <strong>TQ</strong> as free fall with the&nbsp;initial velocity zero.<br />
Given that :&nbsp;<span class="math-tex">{tex} u\\;=\\;0,\\;\\;H\\;=\\;1.5\\;km\\;=1500m\\;\\;,\\;\\;g\\;=+\\;10m/s^2{/tex}</span>&nbsp;<br />
By Using the equation,&nbsp;<span class="math-tex">{tex}H=ut+\\frac12gt^2{/tex}</span>&nbsp; , we get&nbsp;<br />
<span class="math-tex">{tex}1500=0+\\frac{1}{2}10t^{2}{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}t = \\sqrt { \\frac { 1500 } { 5 } } = \\sqrt { 300 } = 10 \\sqrt { 3 } s{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Distance covered by plane or bomb in this time <strong>t</strong>, is given by&nbsp; PQ = ut<br />
<span class="math-tex">{tex}PQ=200\\times10\\sqrt3=2000\\sqrt3\\;m{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\tan \\theta = \\frac { T Q } { P Q } = \\frac { 1500 } { 2000 \\sqrt { 3 } } \\cdot \\frac { \\sqrt { 3 } } { \\sqrt { 3 } } = \\frac { 15 \\sqrt { 3 } } { 20 \\times 3 } = \\frac { \\sqrt { 3 } } { 4 }{/tex}</span>&nbsp;​​​​​​​<br />
<span class="math-tex">{tex}\\tan \\theta = {{1.732} \\over 4} = 0.433 = {\\tan ^{ - 1}}{23^ \\circ }{/tex}</span>42<sup> &#39;&nbsp;</sup> &nbsp;​​​​​​​<br />
<span class="math-tex">{tex}\\Rightarrow \\theta = 23 ^ { \\circ } 42 ^ { \\prime }{/tex}</span>&nbsp;<br />
Thus&nbsp; the bomb should be thrown at an angle&nbsp;<span class="math-tex">{tex}23 ^ { \\circ } 42 ^ { \\prime }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State parallelogram law of vector addition. Show that resultant of two vectors <span class="math-tex">{tex}\\vec{A}{/tex}</span>&nbsp;and <span class="math-tex">{tex}\\vec{B}{/tex}</span>&nbsp;inclined at an angle <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;is R =&nbsp;<span class="math-tex">{tex}\\sqrt{A^{2}+B^{2}+2 A B \\cos \\theta}{/tex}</span></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let the two <span class="math-tex">{tex}\\vec A{/tex}</span> and <span class="math-tex">{tex}\\vec B{/tex}</span> inclined to each other at an angle <span class="math-tex">{tex}\\theta{/tex}</span> be represented both in magnitude and direction by the adjacent sides <span class="math-tex">{tex}\\vec {OP}{/tex}</span> and <span class="math-tex">{tex}\\vec {OQ}{/tex}</span> of the parallelogram OPSQ. Then according to the parallelogram law of vector addition, the resultant of <span class="math-tex">{tex}\\vec A{/tex}</span> and <span class="math-tex">{tex}\\vec B{/tex}</span> is represented both in magnitude and direction by the diagonal <span class="math-tex">{tex}\\vec {OS}{/tex}</span> of the parallelogram.<br/>
<img alt="" data-imgur-src="exQ5bda.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965399-trnq6y.jpg" style="width: 209px; height: 184px;"/><br/>
Magnitude of resultant <span class="math-tex">{tex}\\vec R{/tex}</span>. Draw SN perpendicular to OP produced.<br/>
Then <span class="math-tex">{tex}\\angle S P N=\\angle Q O P=\\theta{/tex}</span>, OP = A, PS = OQ = B, OS = R<br/>
From right angled <span class="math-tex">{tex}\\Delta{/tex}</span>SNP, we have<br/>
<span class="math-tex">{tex}\\frac{S N}{P S}=\\sin \\theta{/tex}</span> or SN = PS sin<span class="math-tex">{tex}\\theta{/tex}</span> = B sin<span class="math-tex">{tex}\\theta{/tex}</span><br/>
and <span class="math-tex">{tex}\\frac{P N}{P S}=\\cos \\theta{/tex}</span> or PN = PQ cos <span class="math-tex">{tex}\\theta{/tex}</span> = B cos <span class="math-tex">{tex}\\theta{/tex}</span><br/>
Using Pythagoras theorem in right angled <span class="math-tex">{tex}\\Delta{/tex}</span>ONQ,<br/>
We get<br/>
OQ<sup>2</sup> = ON<sup>2</sup> + QN<sup>2</sup><br/>
= (OP + PN)<sup>2</sup> + QN<sup>2</sup><br/>
or R<sup>2</sup> = (A + B cos <span class="math-tex">{tex}\\theta{/tex}</span>)<sup>2</sup> + (B sin <span class="math-tex">{tex}\\theta{/tex}</span>)<sup>2</sup><br/>
= A<sup>2</sup> + B<sup>2</sup> cos<sup>2</sup> <span class="math-tex">{tex}\\theta{/tex}</span> + 2 ABcos <span class="math-tex">{tex}\\theta{/tex}</span> + B<sup>2</sup> sin<sup>2</sup> <span class="math-tex">{tex}\\theta{/tex}</span><br/>
= A<sup>2</sup> + B<sup>2</sup>(cos<sup>2</sup> <span class="math-tex">{tex}\\theta{/tex}</span> + sin<sup>2</sup> <span class="math-tex">{tex}\\theta{/tex}</span>) + 2 ABcos <span class="math-tex">{tex}\\theta{/tex}</span><br/>
= A<sup>2</sup> + B<sup>2</sup> + 2 AB cos <span class="math-tex">{tex}\\theta{/tex}</span><br/>
or <span class="math-tex">{tex}R=\\sqrt{A^{2}+B^{2}+2 A B \\cos \\theta}{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A body is projected at an angle <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;with the horizontal.</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>Obtain the condition for the maximum horizontal range.</li>
	<li>Prove that the horizontal range of a projectile is same when fired at an angle <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;and (90&deg; - <span class="math-tex">{tex}\\theta{/tex}</span>) with the horizontal.</li>
	<li>Obtain an expression for velocity of projectile at any instant t.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1700822796-jkdqju.jpg" style="height:117px; width:200px" /><br />
Let a projectile is fired with velocity u at an theta as shown in figure.</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>R = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span><br />
	For maximum horizontal range<br />
	sin 2<span class="math-tex">{tex}\\theta{/tex}</span> = 1<br />
	or 2<span class="math-tex">{tex}\\theta{/tex}</span> = 90<sup>o</sup><br />
	<span class="math-tex">{tex}\\theta{/tex}</span> = <span class="math-tex">{tex}\\frac{90^0}{2}{/tex}</span> = 45<sup>0</sup><br />
	The range of projectile is given as</li>
	<li>Range of projectile when fired at angle<br />
	R = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g} {/tex}</span><br />
	horizontal range for angle of projection <span class="math-tex">{tex}\\theta{/tex}</span> is<br />
	R<sub>1</sub> = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span> ...(i)<br />
	horizontal range for angle of projection 90 - <span class="math-tex">{tex}\\theta{/tex}</span> is<br />
	R<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2 \\sin 2(90-\\theta)}{g}{/tex}</span> = <span class="math-tex">{tex}\\frac{u^2 \\sin (180-2 \\theta)}{g}{/tex}</span> = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span><br />
	R<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span> ...(ii)<br />
	from equation (i) and (ii) we get<br />
	R<sub>1</sub> = R<sub>2</sub></li>
	<li>Let the velocity of projectile be V at time t its horizontal component is given as<br />
	V<sub>x</sub> = u<sub>x</sub> + a<sub>x</sub>t ...(i)<br />
	a<sub>x</sub> = 0, u<sub>x</sub> = u<br />
	therefore V<sub>x</sub> = u<br />
	and vertical component is<br />
	V<sub>y</sub> = u<sub>y</sub> + a<sub>y</sub>t<br />
	V<sub>y </sub>= u sin <span class="math-tex">{tex}\\theta{/tex}</span> - gt ...(ii)<br />
	net velocity of the projectile at the instant t= <span class="math-tex">{tex}\\sqrt{v_x^2+v_y^2}{/tex}</span><br />
	= <span class="math-tex">{tex}\\sqrt{u^2+(u \\sin \\theta-g t)^2}{/tex}</span><br />
	= <span class="math-tex">{tex}\\sqrt{u^2+u^2 \\sin ^2 \\theta+(g t)^2-2 u \\sin \\theta g t}{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>Show that for two complementary angles of projection of a projectile thrown with the same velocity, the horizontal ranges are equal.</li>
	<li>For what angle of projection of a projectile, is the range maximum?</li>
	<li>For what angle of projection of a projectile, are the horizontal range and maximum height attained by the projectile equal?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>Range of projectile = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span><br />
	for angle <span class="math-tex">{tex}\\theta{/tex}</span>, Range R<sub>1</sub> = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span><br />
	for angle (90 - <span class="math-tex">{tex}\\theta{/tex}</span>), Range R<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2 \\sin 2(90-\\theta)}{g}{/tex}</span> = <span class="math-tex">{tex}\\frac{u^2 \\sin (180-2 \\theta)}{g}{/tex}</span> R<sub>2</sub> = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span><br />
	therefore R<sub>1</sub> = R<sub>2</sub> i.e., two complementary angle of projection of projectile thrown with the same velocity, the horizontal range is equal.</li>
	<li>Let <span class="math-tex">{tex}\\theta{/tex}</span> be the angles of projection for projectile thrown with speed v<br />
	Range of projectile = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span><br />
	for range to be maximum, sin 2<span class="math-tex">{tex}\\theta{/tex}</span> = 1<br />
	or 2<span class="math-tex">{tex}\\theta{/tex}</span> = 90<sup>o</sup><br />
	<span class="math-tex">{tex}\\theta{/tex}</span> = 45<sup>o</sup></li>
	<li>Range of projectile = <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span><br />
	height of projectile h = <span class="math-tex">{tex}\\frac{u^2 \\sin ^2 \\theta}{2 g} {/tex}</span><br />
	as Range = height of projectile<br />
	there fore, <span class="math-tex">{tex}\\frac{u^2 \\sin 2 \\theta}{g}{/tex}</span> = <span class="math-tex">{tex}\\frac{u^2 \\sin ^2 \\theta}{2 g}{/tex}</span><br />
	2 sin <span class="math-tex">{tex}\\theta{/tex}</span> cos <span class="math-tex">{tex}\\theta{/tex}</span> = <span class="math-tex">{tex}\\frac{\\sin ^2 \\theta}{2}{/tex}</span><br />
	tan <span class="math-tex">{tex}\\theta{/tex}</span> = 4<br />
	<span class="math-tex">{tex}\\theta{/tex}</span> = tan<sup>-1</sup>4</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define centripetal acceleration. Derive an expression for the centripetal acceleration of a body moving with uniform speed v along a circular path of radius r. Explain how it acts along the radius towards the centre of the circular path.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The rate of change of tangential velocity is called as the centripetal acceleration.&nbsp;In circular motion centripetal force is perpendicular to velocity. Also if the particles decrease or increase their speeds in circular motion then acceleration is generated which deviates the net acceleration from pointing towards the centre.</p>

<p><strong>Formula used:&nbsp;<span class="math-tex">{tex}a=\\frac{v^2}{r}{/tex}</span></strong></p>

<p>We know that the motions are two types: one is straight motion and the circular motion. Then we know that circular motion, though the magnitude of velocity is a constant, the direction of velocity is changing. A circle. It is also defined as rotation of an object along a circular path. It can be of two forms, uniform circular motion, with constant angular rate of rotation and constant speed, or non-uniform circular motion with a changing rate of rotation.</p>

<p><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1766928821-vvahz9.jpg" style="height:214px; width:300px" /></p>

<p>Consider a body of mass <span class="math-tex">{tex}m{/tex}</span> moving along the circumference of a circle. the radius of a circle <span class="math-tex">{tex}r{/tex}</span> with velocity <span class="math-tex">{tex}v{/tex}</span>, as shown in the figure. Then if a small force <span class="math-tex">{tex}F{/tex}</span> is applied on the body, then we know that the force is given as <span class="math-tex">{tex}F=m a{/tex}</span>.</p>

<p>Where, <span class="math-tex">{tex}a{/tex}</span> is the acceleration and is given as the rate of change of velocity <span class="math-tex">{tex}\\Delta v{/tex}</span> with respect to time. Consider the <span class="math-tex">{tex}\\triangle O A B{/tex}</span> and <span class="math-tex">{tex}\\triangle P Q R{/tex}</span>, then <span class="math-tex">{tex}\\frac{\\Delta v}{A B}=\\frac{v}{r}{/tex}</span><br />
Clearly, <span class="math-tex">{tex}A B=v \\Delta t{/tex}</span></p>

<p><span class="math-tex">{tex} \\Longrightarrow \\frac{\\Delta v}{v \\Delta t}=\\frac{v}{r} {/tex}</span><br />
<span class="math-tex">{tex} \\Longrightarrow \\frac{\\Delta v}{\\Delta t}=\\frac{v^2}{r} {/tex}</span><br />
<span class="math-tex">{tex} \\Longrightarrow a=\\frac{v^2}{r} {/tex}</span></p>

<p><br />
Thus, the acceleration due to centripetal force is given by, <span class="math-tex">{tex}a=\\frac{v^2}{r}{/tex}</span>. Clearly as the velocity <span class="math-tex">{tex}v{/tex}</span> and the radius <span class="math-tex">{tex}r{/tex}</span> of the circle are constant, acceleration <span class="math-tex">{tex}a{/tex}</span> will also remain a constant.</p>

<p>Conclusion: A body moving with uniform speed in a circular path must have a centripetal acceleration of magnitude <span class="math-tex">{tex}\\frac{v^2}{r}{/tex}</span>, which continuously changes the direction of velocity, keeping the body in circular motion.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is meant by resolution of a vector? Prove that a vector can be resolved along two given directions in one and only one way.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><strong>Resolution of a vector.</strong> It is the process of splitting a vector into two or more vectors in such a way that their combined effect is same as that of the given vector. The vectors into which the given vector is splitted are called component vectors.<br/>
A component of a vector in any direction gives a measure of the effect of the given vector in that direction. The resolution of a vector is just opposite to the process of vector addition.<br/>
<strong>Resolution of a vector along two given directions.</strong><br/>
Suppose we wish to resolve a vector <span class="math-tex">{tex}\\vec R{/tex}</span> in the direction of two coplanar and non-parallel vectors <span class="math-tex">{tex}\\vec A{/tex}</span> and <span class="math-tex">{tex}\\vec B{/tex}</span>, as shown in Figure.<br/>
<img alt="" data-imgur-src="T7EhS4l.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1636965393-5dqq4x.jpg" style="width: 250px; height: 127px;"/><br/>
Suppose <span class="math-tex">{tex}\\vec{OQ}{/tex}</span> represent vector <span class="math-tex">{tex}\\vec{R}{/tex}</span> in the directions of <span class="math-tex">{tex}\\vec{A}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}{/tex}</span>.<br/>
Q draw lines parallel to vectors <span class="math-tex">{tex}\\vec{A}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}{/tex}</span> respectively to meet at point P. From triangle law of vector addition.<br/>
<span class="math-tex">{tex}\\vec{O Q}=\\vec{O P}+\\vec{P Q}{/tex}</span><br/>
As <span class="math-tex">{tex}\\vec{O P} \\| \\vec{A}{/tex}</span> therefore, <span class="math-tex">{tex}\\vec{O P}=\\lambda \\vec{A}{/tex}</span><br/>
As <span class="math-tex">{tex}\\vec{P Q} \\| \\vec{B}{/tex}</span> therefore, <span class="math-tex">{tex}\\vec{P Q}=\\mu \\vec{B}{/tex}</span><br/>
Here <span class="math-tex">{tex}\\lambda{/tex}</span> and <span class="math-tex">{tex}\\mu{/tex}</span> are scalar. Hence<br/>
<span class="math-tex">{tex}\\vec{R}=\\lambda \\vec{A}+\\mu \\vec{B}{/tex}</span> .... (i)<br/>
Thus the vector <span class="math-tex">{tex}\\vec{R}{/tex}</span> has been resolved in the direction of <span class="math-tex">{tex}\\vec{A}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}{/tex}</span>. Here <span class="math-tex">{tex}\\lambda \\vec{A}{/tex}</span> is the component of <span class="math-tex">{tex}\\vec{R}{/tex}</span> in the direction <span class="math-tex">{tex}\\vec{A}{/tex}</span> and <span class="math-tex">{tex}\\mu \\vec{B}{/tex}</span> is the component in the direction of <span class="math-tex">{tex}\\vec{B}{/tex}</span>.<br/>
<strong>Uniqueness of resolution.</strong> Let us assume that <span class="math-tex">{tex}\\vec R{/tex}</span> can be resolved in the directions of <span class="math-tex">{tex}\\vec{A}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}{/tex}</span> in another way.<br/>
Then <span class="math-tex">{tex}\\vec{R}=\\lambda^{\\prime} \\vec{A}+\\mu^{\\prime} \\vec{B}{/tex}</span> .... (ii)<br/>
From equation (i) and (ii), we have<br/>
<span class="math-tex">{tex}\\lambda \\vec{A}+\\mu \\vec{B}=\\lambda^{\\prime} \\vec{A}+\\mu^{\\prime} \\vec{B}{/tex}</span><br/>
or <span class="math-tex">{tex}\\left(\\lambda-\\lambda^{\\prime}\\right) \\vec{A}=\\left(\\mu^{\\prime}-\\mu\\right) \\vec{B}{/tex}</span><br/>
But <span class="math-tex">{tex}\\vec{A}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}{/tex}</span> are non-zero vectors acting along different directions. The above equation is possible only if<br/>
<span class="math-tex">{tex}\\lambda-\\lambda^{\\prime}=0{/tex}</span> and <span class="math-tex">{tex}\\mu^{\\prime}-\\mu=0{/tex}</span><br/>
or <span class="math-tex">{tex}\\lambda^{\\prime}=\\lambda{/tex}</span> and <span class="math-tex">{tex}\\mu^{\\prime}=\\mu{/tex}</span><br/>
Hence there is one and only one way in which a vector <span class="math-tex">{tex}\\vec{R}{/tex}</span> can be resolved in the directions of vectors <span class="math-tex">{tex}\\vec{A}{/tex}</span> and <span class="math-tex">{tex}\\vec{B}{/tex}</span>.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A gun can fire shells with maximum speed&nbsp;<span class="math-tex">{tex}\\mathrm { v } _ { 0 }{/tex}</span>&nbsp;and the maximum horizontal range that can be achieved is R =<span class="math-tex">{tex}\\frac { v _ { 0 } ^ { 2 } } { g }{/tex}</span>. If a target farther away by distance&nbsp;<span class="math-tex">{tex}\\Delta x{/tex}</span>&nbsp;(beyond R) has to be hit with the same gun as shown in the figure here,&nbsp;show that it could be achieved by raising the gun to a height at least h =&nbsp;&nbsp;<span class="math-tex">{tex}\\Delta x \\left[ 1 + \\frac { \\Delta x } { R } \\right]{/tex}</span>&nbsp;<br />
<img id="Picture 20" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-04/image275.png" style="width: 150px; height: 92px;" /><br />
[Hint: This problem can be approached in two different ways:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Refer to the diagram: target T is at the horizontal distance&nbsp;<span class="math-tex">{tex}x = R + \\Delta x{/tex}</span>&nbsp;and below the point of projection y = - h.</li>
	<li>From point P in the diagram: Projection at speed&nbsp;<span class="math-tex">{tex}\\mathrm { v } _ { 0 }{/tex}</span>&nbsp;at an angle&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;below&nbsp;horizontal with height h and horizontal range<span class="math-tex">{tex}\\Delta x{/tex}</span>.]</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Maximum range of projectile<strong>,&nbsp;<span class="math-tex">{tex}R = \\frac{{{V_0}^2}}{g}{/tex}</span>&nbsp;</strong>.........(i)&nbsp;<br />
We know, maximum range is achieved at&nbsp;<span class="math-tex">{tex}θ = 45°​​​​​​​{/tex}</span><br />
Let&nbsp;the gun is raised to a height h from the horizontal level of target T, so that the projectile can hit the target&nbsp;T.<br />
Total range of projectile must be&nbsp;<span class="math-tex">{tex}R _ { \\text {total} } = R + \\Delta x{/tex}</span>&nbsp;<br />
Horizontal component of velocity at&nbsp;<span class="math-tex">{tex}A = v _ { 0 } \\cos ( \\theta ){/tex}</span>&nbsp;<br />
As A&nbsp;and P are on the same level, the magnitude of velocity will be the same at A and P.<br />
​​​​​But the direction of velocity will be below horizontal,<br />
So horizontal velocity at P,&nbsp;<span class="math-tex">{tex}v _ { x } = - v _ { 0 } \\cos ( \\theta ){/tex}</span>&nbsp;<br />
and vertical velocity at P,&nbsp;<span class="math-tex">{tex}v _ { y } = v _ { 0 } \\sin ( \\theta ){/tex}</span>&nbsp;<br />
Now&nbsp;<span class="math-tex">{tex}h = u t + \\frac { 1 } { 2 } a t ^ { 2 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}h = - v _ { 0 } \\sin \\theta ( t ) + \\frac { 1 } { 2 } g t ^ { 2 }{/tex}</span>&hellip;....(ii)<br />
Consider horizontal motion from A to T ,&nbsp;distance&nbsp;<span class="math-tex">{tex}( R + \\Delta x ) = v _ { 0 }{/tex}</span>cos&nbsp;<span class="math-tex">{tex}\\theta . t{/tex}</span>&nbsp;&nbsp;<br />
<span class="math-tex">{tex}t = \\frac { R + \\Delta x } { v _ { 0 } \\cos \\theta }{/tex}</span>&nbsp;<br />
Substitute t in (ii) we get<br />
&nbsp;<span class="math-tex">{tex}h = - v _ { 0 } \\sin \\theta \\left[ \\frac { R + \\Delta x } { \\nu _ { 0 } \\cos \\theta } \\right] + \\frac { 1 } { 2 } g \\frac { ( R + \\Delta x ) ^ { 2 } } { v _ { 0 } ^ { 2 } \\cos ^ { 2 } \\theta }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}h=-\\tan\\theta\\;(R+\\Delta x)+\\frac12\\left(\\frac g{v_0^2}\\right)\\frac{(R+\\Delta x)^2}{1/2}\\quad(\\because\\theta=45^\\circ\\Rightarrow\\;\\tan\\left(45\\right)=1){/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}h = - ( R + \\Delta x ) + \\frac { 1 } { R } \\left( R ^ { 2 } + \\Delta x ^ { 2 } + 2 R \\Delta x \\right) \\left[ \\because \\frac { g } { v _ { 0 } ^ { 2 } } = \\frac { 1 } { R } \\right]{/tex}</span>&nbsp;<br />
h &nbsp;<span class="math-tex">{tex}= - R - \\Delta x + R + \\frac { \\Delta x ^ { 2 } } { R } + 2 \\Delta x = \\Delta x + \\frac { \\Delta x ^ { 2 } } { R }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}h = \\Delta x \\left[ 1 + \\frac { \\Delta x } { R } \\right]{/tex}</span>&nbsp;<br />
Hence Proved.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1344-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_LAWS_OF_MOTION = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A body of mass M hits normally a rigid wall with velocity V and bounces back with the same velocity. The impulse experienced by the body is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">MV</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">1.5 MV</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">2 MV</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>| Impulse | = MV - (-MV) = 2 MV</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Inertia refers to:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">resistance to change</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Inertia is the resistance of any physical object to any change in its state of motion; this includes changes to its speed, direction, or state of rest. It is the tendency of objects to keep moving in a straight line at a constant velocity. Inertia is a property of matter by which it continues in its existing state of rest or uniform motion in a straight line unless that state is changed by an external force.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">ease of motion</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">dullness</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">slow motion</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A person is sitting in a lift accelerating upwards. The measured weight of a person will be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">less than the actual weight</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">equal to actual weight</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">more than actual weight</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Measured weight = m(g + a). It is more than actual weight (mg).</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A ball strikes a bat with velocity v. The ball has mass m and after striking it retraces its path. What is the impulse imparted by the bat?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">3 mv</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">mv</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">2 mv</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Impulse = Change in momentum<br />
= mv - (-mv) = 2mv</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A person is standing in an elevator. In which situation he finds his weightless?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">When the elevator moves upward with constant acceleration</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">When the elevator moves downward with constant acceleration</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>When the elevator moves downward with acceleration a, the apparent weight, W&#39; = m (g - a) &lt; W (= mg).</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">When the elevator moves upward with uniform velocity</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">When the elevator moves downward with uniform velocity</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The momentum of a body is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">a vector equal in magnitude to the product of mass and instantaneous velocity and direction being that of instantaneous velocity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\vec p=m\\vec v{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">a vector equal in magnitude to the product of mass and acceleration and direction being that of velocity</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">a scalar equal in magnitude to the product of mass and velocity</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">a vector equal in magnitude to the product of mass and average speed and direction being that of velocity</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>According to the first law of motion:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">body acted on by no net force moves with constant velocity (which may be zero) and zero acceleration</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>If net force act on a body then the acceleration of the body will also be zero. Hence velocity will not be changed i.e.&nbsp;it continues in its existing state of rest or uniform motion in a straight line.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">body acted on by net force moves with constant velocity (which may be zero)</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">body acted on by zero net force moves with non zero acceleration</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">body acted on by no net force moves with increasing velocity and negative acceleration</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>No force is required for</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">an object moving in straight line with constant velocity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>No force is required for an object moving in a straight line with constant velocity or for nonaccelerated motion.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">an object moving in circular motion</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">an object moving with constant acceleration</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">an object moving in elliptical path</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A person sitting in an open car moving at constant velocity throws a ball vertically into air, the ball falls</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">exactly in the hand of thrower</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Both the person and the ball share the horizontal velocity of the car. Hence the ball falls exactly in the hand of the thrower.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">outside the car</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">in the car ahead of the person</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">in the car behind the person</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If <span class="math-tex">{tex}\\mu_s{/tex}</span> is coefficient of static friction and <span class="math-tex">{tex}\\mu_k{/tex}</span> is coefficient of kinetic friction, then</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">there is no relation between <span class="math-tex">{tex}\\mu_s{/tex}</span> and <span class="math-tex">{tex}\\mu_k{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">generally <span class="math-tex">{tex}\\mu_{s}&gt;\\mu_{k}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>generally <span class="math-tex">{tex}\\mu_{s}&gt;\\mu_{k}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">generally, <span class="math-tex">{tex}\\mu_{s}=\\mu_{k}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">generally <span class="math-tex">{tex}\\mu_{s}&lt;\\mu_{k}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Dimensions of impulse are same as that of</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">force</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">momentum</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>[Impulse] = [Change in momentum]<br />
= [MLT<sup>-1</sup>]</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">energy</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">acceleration</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A particle revolves round a circular path. The acceleration of the particle is inversely proportional to</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">radius</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}a = \\frac{v^{2}}{r} {/tex}</span> i.e. <span class="math-tex">{tex}a \\propto \\frac{1}{r}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">velocity</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">mass of particle</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">both velocity and mass of particle</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which of the following is the dimension of coefficient of friction?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">[MLT<sup>-2</sup>]</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">[M<sup>0</sup>L<sup>0</sup>T<sup>0</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Being the ratio of two forces, coefficient of friction is a dimensionless quantity.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[M<sup>2</sup>LT<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">[M<sup>2</sup>LT]</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>In equilibrium of particle when net external force of the particle is zero. Then, the particle is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">at rest</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">moving with uniform velocity</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">moving with uniform acceleration</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">Both at rest and moving with uniform velocity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>In equilibrium, net force is zero, there force, acceleration is zero, hence particle is either at rest or in motion with uniform velocity.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>One end of a string of length l is connected to a particle of mass m and the other to a small peg on a smooth horizontal table. If the particle moves in a circle with speed v the net force on the particle (directed towards the centre) is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">T</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>According to Newton&#39;s third law of motion, the net force on a rotating particle is equal to Tension in the String. As the action (ie force towards the centre) and reaction (tension in the string) are equal in magnitude and opposite in direction.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathrm{T}-\\frac{\\mathrm{mv}^2}{\\mathrm{l}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathrm{T}+\\frac{\\mathrm{mv^{2 }}}{1}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">0</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>State Newton&#39;s second law of motion. Hence, derive the relation <span class="math-tex">{tex}\\vec F=m \\vec{a}{/tex}</span>, where the symbols have their usual meanings.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Newton&rsquo;s second law of motion states that the force exerted by a body is directly proportional to the rate of change of its momentum. For a body of mass &lsquo;m&rsquo;, whose velocity changes from u to v in time t, when force &lsquo;F&rsquo; is applied.<br />
<span class="math-tex">{tex}\\mathrm{F} \\propto \\frac{\\text { Change in momentum }}{\\text { Time }}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{F} \\propto \\frac{m v-m u}{t}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{F} \\propto m\\left(\\frac{v-u}{t}\\right){/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\mathrm{F} \\propto m a \\Rightarrow \\mathrm{F}=k m a\\left(\\because a=\\frac{v-u}{t}\\right){/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> F = ma (<span class="math-tex">{tex}\\because{/tex}</span> K = constant = 1)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>A mass of 20 kg is suspended by a rope of length 2 m from a ceiling. A force of 173.2 N in the horizontal direction is applied at the midpoint of the rope as shown in Figure. What is the angle the rope makes with the horizontal in equilibrium? Take g = 10 ms<sup>-2</sup>. Neglect mass of the rope.<br/>
<img alt="" data-imgur-src="1KDH8cX.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1705558048-7pjauk.jpg" style="height:195px; width:199px"/></p></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Tan <span class="math-tex">{tex}\\theta{/tex}</span> = 200<span class="math-tex">{tex}\\sqrt 3{/tex}</span><br />
Tan <span class="math-tex">{tex}\\theta{/tex}</span> = 20 <span class="math-tex">{tex}\\times{/tex}</span> 10 = 200<br />
Tan <span class="math-tex">{tex}\\theta{/tex}</span> <span class="math-tex">{tex}= \\frac{200}{200 \\sqrt3} = \\frac{1}{\\sqrt3}{/tex}</span><br />
The angle the rope makes with the horizontal in equilibrium<br />
<span class="math-tex">{tex}\\theta{/tex}</span> = 30<sup>o</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A constant force acting on a body of mass 3.0 kg changes its speed from 2.0 ms<sup>-1</sup> to 3.5 ms<sup>-1</sup> in 25 s. The direction of the motion of the body remains unchanged. What is the magnitude and direction of the force?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Mass of the body, m = 3 kg</p>

<p>Initial speed of the body, u = 2 m/s</p>

<p>Final speed of the body, v = 3.5 m/s</p>

<p>Time, t = 25 s</p>

<p>&nbsp;Acceleration&nbsp; is given by</p>

<p><span class="math-tex">{tex} \\space a = \\frac { v - u } { t }{/tex}</span></p>

<p><span class="math-tex">{tex}= \\frac { 3.5 - 2 } { 25 } = \\frac { 1.5 } { 25 } = 0 .06 \\mathrm { m } / \\mathrm { s^{-2} }{/tex}</span></p>

<p>Using Newton&#39;s second law of motion, force is given as:</p>

<p>F = ma</p>

<p>&nbsp;<span class="math-tex">{tex}\\therefore F=3 \\times 0.06=0.18N{/tex}</span></p>

<p>The force acts in the direction of the motion since the direction of the body remains unchanged.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Explain, why</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>The passengers are thrown forward from their seats, when a speeding bus stops suddenly.</li>
	<li>Does a cricketer move his hand backwards while holding a catch?</li>
	<li>Is the boat pushed away when a man jumps out of the boat?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>This happens due to inertia of motion. When the speeding bus stops suddenly, the lower part of the body in contact with the seat comes to rest at the very moment, but the upper part of the body of the passengers tends to maintain its uniform motion according to the inertia of motion. Hence the passengers are thrown forward from their seats.</li>
	<li>From 2nd law of motion, we have<br />
	F = ma =&nbsp;<span class="math-tex">{tex}m\\frac{{\\Delta v}}{{\\Delta t}}{/tex}</span><br />
	Where<br />
	&lsquo;F&rsquo; is the force experienced by the cricketer as he catches the ball.<br />
	&lsquo;m&rsquo; is the mass of the ball<br />
	&lsquo;<span class="math-tex">{tex}\\Delta{/tex}</span>t&rsquo; is the short time of the impact with the hand of a cricketer.<br />
	We can thus see from the equation that impact force is inversely proportional to the impact time, Thus, if the impact is for a shorter period of time then the force will be large.<br />
	It also shows that the force experienced by the cricketer decreases with the increase in the impact time.<br />
	Therefore, the cricketer moves his hand backwards while taking a catch to increase the impact time, and hence decrease the impact force on his hand and prevent it from getting hurt.</li>
	<li>Initially, the total momentum of the boat and the man is zero. As the man jumps out of the boat, he gains momentum in the forward direction. To conserve momentum, the boat also gains an equal and opposite momentum. So the boat moves away from the shore.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define angle of repose. Show that coefficient of limiting friction is equal to the tangent of angle of repose.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><u><strong>Angle of repose (θ):</strong></u> The minimum angle of the plane at which the body kept on it starts to slide due to its own weight is called angle of repose<br/>
<img alt="" data-imgur-src="2UTR0Ki.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/2UTR0Ki.png" style="width: 150px; height: 92px;"/></p>
<p>Consider a body of mass m placed over a surface of inclination angle equal to the angle of repose <span class="math-tex">{tex}\\phi{/tex}</span>. Various forces <j>acting have been shown in Figure. For equilibrium condition, we have<br/>
N = mg cos<span class="math-tex">{tex}\\phi{/tex}</span> ..................(1)<br/>
and friction force f = mg sin<span class="math-tex">{tex}\\phi{/tex}</span>..................(2)</j><br/>
In limiting case, when the body just starts sliding down, f = f<sub>l</sub>. Then dividing (2) by (1), we get<br/>
<span class="math-tex">{tex}\\frac { f _ { l } } { N } = \\tan \\phi{/tex}</span><br/>
or <span class="math-tex">{tex}\\mu _ { l } = \\tan \\phi{/tex}</span><br/>
where <span class="math-tex">{tex}\\mu _ { l } = \\frac { f _ { l } } { N }{/tex}</span> is the coefficient of limiting friction.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A pebble of mass 0.05 kg is thrown vertically upwards. Give the direction and magnitude of the net force on the pebble,</p>

<ol start="1" style="list-style-type:lower-alpha">
	<li>during its upward motion,</li>
	<li>during its downward motion,</li>
	<li>at the highest point where it is momentarily at rest. Do your answers change if the pebble was thrown at an angle of 45&deg; with the horizontal direction? Ignore air resistance.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>When an object is thrown vertically upward or it falls vertically downward under gravity then an acceleration g <span class="math-tex">{tex}=10m/s^{-2}{/tex}</span>&nbsp;acts downward due to the earth&rsquo;s gravitational pull.<br />
Mass of pebble (m) = 0.05 kg</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>During upward motion<br />
	Net force acting on pebble (F) = ma = 0.05 <span class="math-tex">{tex}\\times{/tex}</span>10&nbsp;<br />
	= 0.50N (vertically downward)</li>
	<li>During downward motion<br />
	Net force acting on pebble (F) = ma = 0.05 <span class="math-tex">{tex}\\times{/tex}</span>10&nbsp;<br />
	= 0.50N (vertically downward)</li>
	<li>At the highest point<br />
	Net force acting on pebble<br />
	(F) = ma = 0.05 <span class="math-tex">{tex}\\times{/tex}</span>10<br />
	= 0.50 N (vertically downward) If pebble was thrown at an angle of 45&deg; with the horizontal direction then acceleration acting on it and therefore force acting on it will remain unchanged, i.e., 0.50 N (vertically downward). In case , at the highest point the vertical component of velocity will be zero but horizontal component of velocity will not be zero.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is inertia? Discuss its types giving one example in each case.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The inability of objects to move on its own or change its state of motion is called inertia. Inertia means resistance to change its state.<br />
<strong>There are three types of inertia:</strong></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li><strong>Inertia of rest:</strong> The inability of an object to change its state of rest is called inertia of rest.<br />
	<strong>Example:</strong> When a stationary bus starts to move, the passengers experience a sudden backward push. A book lying on the table will remain at rest until it is moved by some external agencies.</li>
	<li><strong>Inertia of motion:</strong> The inability of an object to change its state of uniform speed (constant speed) on its own is called inertia of motion.<br />
	<strong>Example:</strong> When the bus is in motion, and if the brake is applied suddenly, passengers move forward and hit against the front seat. An athlete running in a race will continue to run even after reaching the finishing point.</li>
	<li><strong>Inertia of direction:</strong> The inability of an object to change its direction of motion on its own is called inertia of direction.<br />
	<strong>Example:</strong> When a stone attached to a string is in whirling motion, and if the string is cut suddenly, the stone will not continue to move in circular motion but moves tangential to the circle. When a bus moving along a straight line takes a turn to the right. The passengers are thrown towards left.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Briefly explain static friction, limiting friction and kinetic friction. How do they vary with the applied force?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img alt="" data-imgur-src="FXLiidV.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/FXLiidV.png" style="width: 200px; height: 112px;" /><br />
We know that when the applied force on a body is small enough, it does not move. It means that force of friction is just balancing the applied force. However, as the applied force is increased beyond a limit, the body starts moving. Force of friction is present when the given body is in motion. From these considerations we classify friction in case of sliding motion in following three categories:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li><strong>Static friction</strong>: Static friction&nbsp;is a self-adjusting force because it comes into play when the body is lying over the surface of another body without any motion. If we have not applied any force on a body to move the body, the frictional force also becomes zero. In Figure, the region OA of the graph is the region of static friction.</li>
	<li><strong>Limiting friction</strong>: It is the maximum value of static friction. Thus, limiting friction is the force of friction at the moment when a body just tends to slide over the surface of another body i.e, when that body overcomes the force of static friction, the maximum value of static friction is reached which is known as limiting friction.&nbsp;In the figure, frictional force corresponding to point A represents the limiting friction.</li>
	<li><strong>Kinetic friction</strong>: Kinetic friction is that opposing (or retarding) force which comes into play when a body actually slides over the surface of another body. The value of kinetic friction for a given pair of surfaces is less than the corresponding value of limiting friction. Moreover, the force of kinetic friction throughout remains constant for a given body and does not depend upon the speed of motion of the body. In the figure, the region BC of the graph is representing kinetic friction.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A body of mass 15 kg is hung by a spring balance in a lift. What would be the reading of the balance when</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>the lift is ascending with an acceleration of 2 ms<sup>-2</sup></li>
	<li>descending with the same acceleration</li>
	<li>descending with a constant velocity of 2 ms<sup>-1</sup>?<br />
	Take g = 10 ms<sup>-2</sup>.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>m = mass of the body hanged from spring balance = 15 kg<br />
	W = actual weight of the body hanged in downward direction = mg = 15 x 9.8 = 147 N<br />
	a = acceleration of the lift in upward direction = 2 m/s&sup2;<br />
	F = reading of the spring balance<br />
	force equation for the motion of the body hanged in the lift is given as<br />
	F - W = ma<br />
	F - 147 = 15 (2)<br />
	F = 177 N</p>
	</li>
	<li>
	<p>a = acceleration of the lift in downward direction = 2 m/s&sup2;<br />
	force equation for the motion of the body hanged in the lift is given as<br />
	W - F = ma<br />
	147 - F = 15 x 2<br />
	F = 117 N</p>
	</li>
	<li>
	<p>Since the lift is going at constant velocity<br />
	a = acceleration of the lift = 0 m/s&sup2;<br />
	W - F = 0<br />
	F = W</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A monkey of mass 40 kg climbs on a rope which can stand a maximum tension 600 N. In which of the following cases will the rope break?</p>

<p>The monkey</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>climbs up with an acceleration of 6m/s<sup>2</sup></li>
	<li>climbs down with an acceleration of 4m/s<sup>2</sup></li>
	<li>climbs up with a uniform speed of 5m/s</li>
	<li>falls down the rope freely under gravity. Take g = 10m/s<sup>2</sup> and ignore the mass of the rope.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>mass of the monkey, m = 40kg,</p>

<p>Tensile strength of the rope, T = 600N (max tension rope can hold without breaking)<br />
Here, the rope will break if reaction (R) exceeds the tension (T) applied, i.e. R &gt; T</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>a = 6m/s<sup>2</sup><br />
	For upward accelerated motion the net acceleration is (g&nbsp;+ a) instead of g, hence R = m (g + a) = 40 (10 + 6) = 640 N. Therefore the rope will break, as R &gt; T</li>
	<li>a = 4m/s<sup>2</sup><br />
	For downward&nbsp;accelerated motion the net acceleration is (g - a) instead of g, hence R = m (g &ndash; a) = 40 (10 &ndash; 6) = 240 N. Therefore the rope will not break as R &lt; T</li>
	<li>v= 5m/s (constant) a = 0<br />
	R = mg = 40 <span class="math-tex">{tex}\\times{/tex}</span>10 = 400 N. Therefore the rope will not break as R &lt; T</li>
	<li>For freefall, net acceleration on the body is zero, a = g;&nbsp;R = m (g &ndash; a) = m (g &ndash; g). Therefore R = zero (Rope will not break)</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Give the magnitude and direction of the net force acting on a stone of mass 0.1 kg,</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>just after it is dropped from the window of a stationary train,</li>
	<li>just after it is dropped from the window of a train running at a constant velocity of 36 km/h.</li>
	<li>just after it is dropped from the window of a train accelerating with1 ms<sup>-2</sup>,</li>
	<li>lying on the floor of a train which is accelerating with 1 ms<sup>-2</sup>, the stone being at rest relative to the train.</li>
</ol>

<p>Neglect air resistance throughout.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>When stone is dropped just after from the window of a stationary train,<br />
	Force on stone is given by, F = Force due to gravity = mg = 0.1 kg <span class="math-tex">{tex}\\times{/tex}</span> 10 m/s<sup>2</sup> = 1 N in the vertically downward direction.</li>
	<li>As the train is running with constant velocity, acceleration is zero in horizontal direction i.e. direction of motion of train. Hence no force in horizontal direction. So, only force due to gravity in vertically downward direction exists. In this case too, force is same as in (a) i.e., F = 1&nbsp;N downwards.</li>
	<li>Net Force is given by, F = Force due to gravity = mg = 0.1 k g <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10 m/s<sup>2</sup> = 1&nbsp;N&nbsp;<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;F = 1 N vertically downwards</li>
	<li>Here, acceleration is given by&nbsp; a = 1 ms<sup>-2</sup> in horizontal direction towards the motion of train and the stone being at rest relative to the train,<br />
	Hence, net force is given by&nbsp; F = ma = 0.1 <span class="math-tex">{tex}\\times{/tex}</span> 1 = 0.1 N.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is meant by coefficient of static friction and angle of friction? Establish the relation between the two.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Coefficient of static friction is defined as the ratio of static frictional force to the normal reaction.<br />
Angle of friction is the angle between the resultant of limiting friction and normal reaction with the normal reaction. Here in the figure below, the angle of friction is denoted by&nbsp;<span class="math-tex">{tex}\\alpha{/tex}</span>.<br />
<img id="Picture 14" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch05/3m/image031.jpg" style="height: 100px; width: 100px;" /><br />
<span class="math-tex">{tex}\\tan \\alpha = \\frac { F s } { R }{/tex}</span>&nbsp;...(i), F<sub>s</sub>&nbsp;= force of static friction, R = normal reaction<br />
Coefficient of static friction&nbsp;<br />
The limiting value of static frictional force is directly proportional to the normal reaction i.e.<br />
<span class="math-tex">{tex}F_s \\alpha R \\Rightarrow F _s = \\mu _s R{/tex}</span>&nbsp;,&nbsp;<span class="math-tex">{tex}\\mu_s{/tex}</span>&nbsp;= constant of proportionality here known as coefficient of static friction<br />
Or<br />
<span class="math-tex">{tex}\\mu_ s = \\frac {F_ s} {R}{/tex}</span> ...(ii)<br />
From (i) and (ii)<br />
<span class="math-tex">{tex}\\mu _s = \\tan \\alpha {/tex}</span>&nbsp;.<br />
This is the required relation between coefficient of static friction and angle of friction.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>An elevator weighs 3000kg. What is its acceleration when the in the tension supporting cable is 33000 N. Given that g = 9.8m/s<sup>2</sup>.<br />
<strong><img id="Picture 7" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch05/2m/image011.jpg" style="height:90px; width:72px" /></strong></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Net upward force on the elevator F = T - mg (<span class="math-tex">{tex}\\because{/tex}</span> F = ma)<br />
ma = T - mg<br />
T = m(a + g) ...(i)<br />
T = 33000 N; m = 3000 kg; g =9.8 m/s<sup>2</sup><br />
Substituting in Equation 1<br />
33000&nbsp;= 3000(a + 9.8)<br />
<span class="math-tex">{tex}a = \\frac { 33000 - 3000 \\times 9.8 } { 3000 }{/tex}</span><br />
a = 1.2 m/s<sup>2</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State the laws of limiting friction. Hence define coefficient of static friction.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The laws of limiting friction are as follows:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>The value of limiting friction depends on the nature of the two surfaces in contact and on the state of their smoothness.</li>
	<li>When two bodies are in contact the direction of the forces of Friction on one of them at its point of contact&nbsp;is opposite to the direction in which the point of contact tends to move relative to the other.</li>
	<li>The value of limiting friction is directly proportional to the normal reaction between the two given surfaces.</li>
	<li>For any two given surfaces and for a given value of normal reaction, the force of limiting friction is independent of the shape and surface area of surfaces in contact.</li>
	<li>If the bodies are in equilibrium, the force of Friction is just sufficient to prevent motion and may, therefore, be determined by applying the conditions of equilibrium of all the forces acting on the body.</li>
</ol>

<p>The coefficient of static (limiting) friction for two given surfaces in contact is defined as the ratio of the force of limiting friction f<sub>l</sub> between them and the force of normal reaction N i.e.<br />
<span class="math-tex">{tex}\\mu _ { s } = \\frac { f _ { l } } { N }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>Three identical blocks each having a mass m, are pushed by a force F on a frictionless table as shown in figure <br/>
<img alt="" data-imgur-src="cCfBFzu.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/cCfBFzu.png" style="width: 150px; height: 48px;"/><br/>
 What is the acceleration of the blocks? What is the net force on the block P? What force does P apply on Q. What force does Q apply on R?</p></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If a is the acceleration of the whole system containing three blocks, then F = mass of the system <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;acceleration of the system = (m + m + m) <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;a<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;F = 3 ma<br />
<span class="math-tex">{tex}\\therefore a = \\frac {F} {3m}{/tex}</span></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Net force on P,<br />
	<span class="math-tex">{tex}F _ { 1 } = m a = m \\times \\frac { F } { 3 m }{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow F _ { 1 } = \\frac {F} {3}{/tex}</span></li>
	<li>Force applied on Q by P = reaction force on P by Q,<br />
	F<sub>2</sub> = (m + m)a [since, the reaction force comes due to masses of Q and R]<br />
	<span class="math-tex">{tex}\\therefore {F_2} = 2m \\times a = 2m \\times \\frac{F}{{3m}}{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore F _ { 2 } = \\frac {2 F} {3}{/tex}</span></li>
	<li>Force applied on R by Q = reaction force on Q by R,<br />
	<span class="math-tex">{tex}F _ { 3 } = m \\times a = m \\times \\frac { F } { 3 m }{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore F _ { 3 } = \\frac {F} {3}{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two blocks of masses 50 kg and 30 kg connected by a massless string pass over a light frictionless pulley and rest on two smooth planes inclined; at angles 30&deg; and 60&deg; respectively with the horizontal. Determine the acceleration of the two blocks and the tension in the string. Take g = 10 ms<sup>-2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Suppose the mass of 50 kg slides down with an acceleration a. The forces acting on the two blocks are shown in figure. The components of the two weights perpendicular to the inclined planes are balanced by the normal reactions R<sub>1</sub> and R<sub>2</sub>.<br/>
<img alt="" data-imgur-src="oiAemkb.png" height="136" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1637065502-c4248y.jpg" width="286"/><br/>
The tension T of each part of the string is same and also the acceleration a of each block is same.<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> 50g sin 30° - T = 50a ...(i)<br/>
and T - 30 g sin 60° = 30a ....(ii)<br/>
Adding (i) and (ii), we get<br/>
(50 sin 30° - 30 sin 60°) g = (50 + 30) a<br/>
or <span class="math-tex">{tex}a=\\frac{(50 \\times 0.5-30 \\times 0.866) \\times 10}{80}{/tex}</span> = -0.12 ms<sup>-2</sup><br/>
The -ve sign indicates that the 50 kg block, instead of sliding down, actually slides up. Hence the 30 kg block slides down and that of 50 kg slides up the inclined plane with a = 0.12 ms<sup>-2</sup>.<br/>
From (i), T = 50 g sin 30° - 50 a<br/>
= 50 (10 <span class="math-tex">{tex}\\times{/tex}</span> 0.5 - 0.12) = 50 <span class="math-tex">{tex}\\times{/tex}</span> 4.88 = 244 N</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A metal block of mass 0.5 kg is placed on a plane inclined to the horizontal at an angle of 30&deg;. If the coefficient of friction is 0.2, what force must be applied</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>to just prevent the block from sliding down the inclined plane</li>
	<li>to just move the block up the inclined plane and</li>
	<li>to move it up the inclined plane with an acceleration of 20 cms<sup>-2</sup></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>i. To just prevent the block from sliding down the inclined plane:</strong></p>

<p>In this case, the applied force (F) must balance the force trying to pull the block down, which is the component of weight along the incline minus the frictional force.</p>

<p><span class="math-tex">{tex} W_{\\|}=m g \\sin \\theta=\\left(0.5 \\times 9.8 \\times \\sin 30^{\\circ}\\right)=2.45 {~N} {/tex}</span><br />
<span class="math-tex">{tex}W_{\\perp}=m g \\cos \\theta=\\left(0.5 \\times 9.8 \\times \\cos 30^{\\circ}\\right)=4.24 {~N} {/tex}</span><br />
<span class="math-tex">{tex}f=\\mu N=0.2 \\times 4.24=0.848 {~N} {/tex}</span></p>

<p>To prevent the block from sliding down:</p>

<p><span class="math-tex">{tex} F=W_{\\|}-f=2.45-0.848=1.602 {~N}{/tex}</span></p>

<p><strong>ii. To just move the block up the inclined plane:</strong></p>

<p>Here, the applied force must overcome both the component of weight acting down the incline and the frictional force, which now acts in the opposite direction (down the incline).</p>

<p><span class="math-tex">{tex} F=W_{\\|}+f=2.45+0.848=3.298 {~N}{/tex}</span></p>

<p><strong>iii. To move the block up the incline with an acceleration of <span class="math-tex">{tex}0.2 {~m} / {s}^2{/tex}</span> :</strong></p>

<p>The net force <span class="math-tex">{tex}(F){/tex}</span> required must provide enough force to overcome the weight component, the frictional force, and also accelerate the block. Using Newton&#39;s second law:</p>

<p><span class="math-tex">{tex} F-\\left(W_{\\|}+f\\right)=m a {/tex}</span><br />
<span class="math-tex">{tex}F=m a+W_{\\|}+f=(0.5 \\times 0.2)+2.45+0.848=0.1+2.45+0.848=3.398 {~N} {/tex}</span><br />
&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Define impulse. State its S.I. unit.</li>
	<li>State and prove impulse-momentum theorem.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>When a force acts on a body or on a system or on a particle for some time, then the product of the force and the time interval is called impulse.<br />
	Impulse <span class="math-tex">{tex}\\overline I = \\overline F \\times t{/tex}</span><br />
	S.I. Unit - NS<br />
	Impulse is a vector quantity directed along the average force <span class="math-tex">{tex}\\overline { F } a v{/tex}</span>.</li>
	<li>Impulse of a force is equal to the change in momentum of the body.<br />
	According to Newton&rsquo;s second law<br />
	<span class="math-tex">{tex}\\overline { F } = \\frac { d \\overline { p } } { d t }{/tex}</span><br />
	or <span class="math-tex">{tex}d \\overline { p } = \\overline { F } d t{/tex}</span><br />
	Say, due to application of a force <span class="math-tex">{tex}\\overline F{/tex}</span><sub>,&nbsp;</sub>the momentum of a body changes from <span class="math-tex">{tex}\\overline {P} _ {1}{/tex}</span>&nbsp;to <span class="math-tex">{tex}\\overline {P} _ {2}{/tex}</span>&nbsp;in the time interval 0 to t. i.e.&nbsp;At t = 0 <span class="math-tex">{tex}\\overline { P } = \\overline { P } _ { 1 }{/tex}</span> and at<br />
	<span class="math-tex">{tex}t = t \\; ,\\overline { P } = \\overline { P _ { 2 } }{/tex}</span><br />
	<span class="math-tex">{tex}\\int\\limits_{\\overline {{P_1}} }^{\\overline {{P_2}} } {d \\overline p} = \\int\\limits_0^t {\\overline Fdt} {/tex}</span><br />
	<span class="math-tex">{tex}\\overline { P } _ { 2 } - \\overline { P } _ { 1 } = \\overline F t{/tex}</span><br />
	<span class="math-tex">{tex}\\overline { P } _ { 2 } - \\overline { P } _ { 1 } = \\overline I{/tex}</span><br />
	<span class="math-tex">{tex}[ \\because \\overline F t = \\overline I ( \\text { Impulse } ) ]{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Obtain an expression for the centripetal force required to make a body of mass m moving with a speed v around a circular path of radius r.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>In order to maintain uniform circular motion of a particle, a force is needed because uniform circular motion is an accelerated motion. The force is known as the centripetal force. Thus, centripetal force is the force required in order to make an object move along a circular path with uniform speed. The force acts along the radius and is directed towards the centre of circular path.&nbsp;The centripetal force F acting on a particle moving uniformly in a circle may depend upon mass (m), velocity (v), and radius (r) of the circle.</p>

<p>We know that centripetal acceleration of a particle moving with a constant speed v along a circle of radius r is given by:<br />
<span class="math-tex">{tex}a _ { c } = \\frac { v ^ { 2 } } { r }{/tex}</span>&nbsp; &nbsp;...................(1)<br />
Hence, according to Newton&#39;s second law of motion, for a particle of mass m, we have<br />
The centripetal force F = ma<sub>c</sub>&nbsp;= <span class="math-tex">{tex}\\frac { m v ^ { 2 } } { r }{/tex}</span>&nbsp;[by using equation (1)]<br />
As v = r<span class="math-tex">{tex}\\omega{/tex}</span>, where <span class="math-tex">{tex}\\omega{/tex}</span> is the angular velocity of the particle, then<br />
F =&nbsp;<span class="math-tex">{tex}\\frac { m } { r } ( r \\omega ) ^ { 2 } = m r \\omega ^ { 2 }{/tex}</span><br />
which is the required expression for the centripetal force.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define coefficient of friction and angle of friction and hence derive a relation between them.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>The coefficient of friction between any two surfaces in contact is defined as the ratio of the force of limiting friction and normal reaction between them i.e., <br/>
<span class="math-tex">{tex}\\mu _ { \\mathrm { s } } = \\frac { f _ { l } } { N }{/tex}</span><b> </b></p>
<p><img alt="" data-imgur-src="AsVRz4R.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/AsVRz4R.png" style="width: 200px; height: 97px;"/><br/>
Angle of friction: Angle with the resultant of force of limiting friction <span class="math-tex">{tex}\\vec { f } _ { l }{/tex}</span> and normal reaction <span class="math-tex">{tex}\\vec { N }{/tex}</span> makes with the direction of normal reaction R is the angle of friction.<br/>
Relation between coefficient of friction and angle of friction:<br/>
In Figure, angle <span class="math-tex">{tex}\\theta{/tex}</span> is the angle of friction, where<br/>
<span class="math-tex">{tex}\\tan \\theta = \\frac { f _ { l } } { N }{/tex}</span><br/>
But by definition = <span class="math-tex">{tex}\\frac { f _ { l } } { N } = \\mu _ { l }{/tex}</span>= coefficient of limiting friction for given pair of surfaces.<br/>
Hence, we have <span class="math-tex">{tex}\\mu _ { l } = \\tan \\theta{/tex}</span>.<br/>
Thus, the tangent of the coefficient of friction is numerically equal to the coefficient of limiting friction.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State the law of conservation of linear momentum. Prove it by using the second law of motion. Give two situations where the linear momentum remains conserved.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If the net external force acting on a system of bodies is zero, then the momentum of the system remains constant. This is the basic law of conservation of linear momentum.&nbsp;Mathematically,&nbsp;<span class="math-tex">{tex}\\vec { F } _ { e x t } = 0{/tex}</span>, then<br />
<span class="math-tex">{tex}\\vec { p } = \\overrightarrow { p _ { 1 } } + \\overrightarrow { p _ { 2 } } + \\overrightarrow { p _ { 3 } } + \\ldots = \\sum \\overrightarrow { p _ { i } }{/tex}</span>= constant<br />
<u><strong>Proof:</strong></u> According to Newton&#39;s second law of motion, the rate of change of momentum of a system is equal to the net force applied on the system i.e.,<br />
<span class="math-tex">{tex}\\frac { \\overrightarrow { d p } } { d t } = \\vec { F } _ { \\mathrm { ext } }{/tex}</span>&nbsp; &nbsp; ...........................(1)<br />
If no net external force acts on a system (i.e. the system is a closed, isolated system) then <span class="math-tex">{tex}\\vec { F } _ { \\mathrm { ext } } = 0{/tex}</span>&nbsp;and hence&nbsp;<span class="math-tex">{tex}\\frac { \\overrightarrow { d p } } { d t } = \\overrightarrow { 0 }{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\quad \\vec { p } = {/tex}</span>&nbsp;constant (because the derivative of a constant term is zero)<br />
Thus, we find that for a closed, isolated system in the absence of a&nbsp;net external force, the total momentum of a system remains conserved.</p>

<p>Linear momentum remains conserved during (i) firing of a bullet from a gun, (ii) motion of jet plane, (iii) collision between two balls etc.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State law of conservation of momentum and prove it using third law of motion.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Law of conservation of momentum</strong>&nbsp;: It states that if a group of objects are interacting with each other, then their total momentum remains conserved before and after the interaction, provided no external force acts on them. Mathematically,&nbsp;<span class="math-tex">{tex}\\vec { F } _ { e x t } = 0{/tex}</span>, then<br />
<span class="math-tex">{tex}\\vec { p } = \\overrightarrow { p _ { 1 } } + \\overrightarrow { p _ { 2 } } + \\overrightarrow { p _ { 3 } } + \\ldots = \\sum \\overrightarrow { p _ { i } }{/tex}</span>= a constant<br />
It is known as the law of conservation of linear momentum. It is one of the most versatile law in nature, which never fails.</p>

<p>Consider two bodies A and B, with initial momenta <span class="math-tex">{tex}\\overrightarrow { p _ { A } }{/tex}</span> and <span class="math-tex">{tex}\\overrightarrow { p _ { B } }{/tex}</span> respectively.<br />
Let the two&nbsp;bodies collide, get apart and have final momentum&nbsp;<span class="math-tex">{tex}\\overrightarrow { p _ { A } ^ { \\prime } } \\text { and } \\overrightarrow { p _ { B } ^ { \\prime } }{/tex}</span>&nbsp;respectively. By the second law of motion -<br />
Change in momentum of body A, <span class="math-tex">{tex}\\overrightarrow { p _ { A } ^ { \\prime } } - \\overrightarrow { p _ { A } } = \\overrightarrow { F _ { A B } } \\Delta t{/tex}</span>&nbsp;..........................................(i)<br />
where <span class="math-tex">{tex}\\overrightarrow { F _ { A B } }{/tex}</span> is the force acting on A due to action of B for a time <span class="math-tex">{tex}\\Delta t{/tex}</span>.<br />
Similarly, change in momentum of body B,&nbsp;<span class="math-tex">{tex}\\overrightarrow { p _ { B } ^ { \\prime } } - \\vec { p } _ { B } = \\overrightarrow { F _ { B A } } \\Delta t{/tex}</span>&nbsp;............................................(ii)<br />
Here time <span class="math-tex">{tex}\\Delta{/tex}</span>t, the time for which two bodies A and B are in contact and interact, is same for both the forces.<br />
Moreover, from third law of motion <span class="math-tex">{tex}\\overrightarrow { F _ { A B } } = - \\overrightarrow { F _ { B A } }{/tex}</span><br />
Hence, adding (i) and (ii), we obtain<br />
<span class="math-tex">{tex}\\left( p _ { A } ^ { \\prime } - \\overrightarrow { p _ { A } } \\right) + \\left( p _ { B } ^ { \\vec { \\prime } } - \\overrightarrow { p _ { B } } \\right){/tex}</span><span class="math-tex">{tex}= \\overrightarrow { F _ { A B } } \\Delta t + \\overrightarrow { F _ { B A } } \\Delta t{/tex}</span><br />
<span class="math-tex">{tex}= - \\vec { F } _ { B A } \\Delta t + \\vec { F } _ { B A } \\Delta t = { 0 }{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\quad \\overrightarrow { p _ { A } ^ { \\prime } } + \\overrightarrow { p _ { B } ^ { \\prime } } = \\overrightarrow { p _ { A } } + \\overrightarrow { p _ { B } }{/tex}</span><br />
which shows that the total final momentum of the isolated system is exactly same as its initial momentum. Thus, it is proved that total momentum of an isolated system remains conserved.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State three basic laws of motion. Show that the first law of motion gives the definition of force and the second law of motion gives the measure of force.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Newton&rsquo;s&nbsp;First Law of Motion</strong>&nbsp;also known as&nbsp;<strong>Law of Inertia</strong>&nbsp;states that every object persists to stay in uniform motion in a straight line or in the state of rest unless an external force acts upon it. In a simpler form, the first law of motion may also be stated as&nbsp;&quot;If the net external force on a body is zero, its acceleration is zero. Acceleration can be non-zero only if there is a net external force on the body&quot;.<br />
<strong>Newton&rsquo;s Second Law of Motion</strong>&nbsp;states that force is equal to the change in momentum per change in time. For a constant mass, force equals mass times acceleration, i.e.<br />
F = ma<br />
Thus,&nbsp;<span class="math-tex">{tex}\\vec { F } \\propto \\frac { \\Delta \\vec { p } } { \\Delta t } \\text { or } \\vec { F } = k \\frac { \\Delta \\vec { p } } { \\Delta t }{/tex}</span>, where k is a constant of proportionality,&nbsp;<span class="math-tex">{tex}\\Delta p{/tex}</span> is the change in momentum and p = mv.<br />
<strong>Newton&rsquo;s Third Law of Motion:&nbsp;</strong>It states that &quot;For every action, there is an equal and opposite reaction&quot;.<br />
<br />
According to the first law of motion, in the absence of an external force, a body will maintain its position of rest or state of uniform motion along a straight line. Thus, to change the position of rest or uniform motion of a body, we shall have to apply an external force. If the external force is large enough, it may change the state of rest or of uniform motion. However, if the magnitude of the force is small then it may not be able to change that state. Hence, &ldquo;force is that external cause (push or pull) which changes or tries to change the state of rest or of uniform motion along a straight line of a given body&quot;.<br />
Also, we know that,<br />
F = ma<br />
where F is the vector sum of all forces acting on the body, m is the mass of body and equation can be regarded as a statement of Newton&#39;s 2nd law of motion.<br />
This relation can be used to have the measure of a force.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that Newton&#39;s third law of motion is contained in the second law.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let F<sub>ba</sub> be the force (action) exerted by A on B and&nbsp;<span class="math-tex">{tex}\\frac{d \\mathbf{p}_{B}}{d t}{/tex}</span>&nbsp;be the&nbsp;resulting change of the momentum of B.<br />
Let F<sub>AB</sub> be the force (reaction) exerted by B on A and&nbsp;<span class="math-tex">{tex}\\frac{d \\mathbf{p}_{A}}{d t}{/tex}</span>&nbsp;be the resulting change of momentum of A.<br />
According to Newton&rsquo;s second law, F =&nbsp;<span class="math-tex">{tex}\\frac{d \\mathbf{p}}{d t}{/tex}</span><br />
Then,&nbsp;<span class="math-tex">{tex}\\mathrm{F}_{B A}=\\frac{d \\mathbf{p}_{B}}{d t} \\text { and } \\mathbf{F}_{A B}=\\frac{d \\mathbf{p}_{A}}{d t}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\quad \\mathrm{F}_{B A}+\\mathrm{F}_{A B}=\\frac{d \\mathbf{p}_{B}}{d t}+\\frac{d \\mathbf{p}_{A}}{d t}=\\frac{d}{d t}\\left(\\mathbf{p}_{B}+\\mathbf{p}_{A}\\right){/tex}</span>&nbsp;...(i)<br />
In the absence of any external force, the rate of change of momentum of the whole system&nbsp;zero.<br />
i.e.&nbsp;<span class="math-tex">{tex}\\frac{d}{d t}\\left(\\mathbf{p}_{B}+\\mathbf{p}_{A}\\right)=0{/tex}</span><br />
So,&nbsp;F<sub>BA</sub> + F<sub>AB</sub>&nbsp;= 0 or F<sub>BA</sub>&nbsp;= - F<sub>AB</sub><br />
or&nbsp; Action = - reaction<br />
and it is a Newton&rsquo;s third law of motion.<br />
Hence, proved.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A small body tied to one end of the string is whirled in a vertical circle. Represent the forces on a diagram when the string makes an angle <span class="math-tex">{tex}\\theta{/tex}</span> with initial position below the fixed point. Find an expression for the tension in the string. Also, find the tension and velocity at the lowest and highest points respectively.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Consider a small body of mass m attached to one end of a string (of length l) and whirled in a vertical circle of radius &#39;r&#39;. Let body starts motion from its initial position A, just below the fixed point O, with a speed v<sub>o</sub>.</p>

<p><img alt="" data-imgur-src="jdas6zs.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/jdas6zs.png" style="width: 200px; height: 189px;" /><br />
The forces acting on the body, when the string makes an angle&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span> with the initial position are shown in the figure. Here, mg is the weight of body and T the tension in the string. If v be the instantaneous velocity at this point, then a centripetal force&nbsp;<span class="math-tex">{tex}F = \\frac { m v ^ { 2 } } { l }{/tex}</span> is required radially inward. From figure, it is clear that in equilibrium the centripetal force is provided by resultant of two forces i.e.,<br />
<span class="math-tex">{tex}T - m g \\cos \\theta = \\frac { m v ^ { 2 } } { l }{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}T = m g \\cos \\theta + \\frac { m v ^ { 2 } } { l }{/tex}</span>&nbsp;...(1)<br />
If the body has covered a vertical distance h, then from law of conservation of mechanical energy, we have<br />
<span class="math-tex">{tex}\\frac { 1 } { 2 } m v _ { 0 } ^ { 2 } = \\frac { 1 } { 2 } m v ^ { 2 } + m g h{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow v ^ { 2 } = v _ { 0 } ^ { 2 } - 2 g h{/tex}</span>&nbsp;...(ii)<br />
which is the required expression for the velocity of a particle at any point.<br />
At the lowest point <span class="math-tex">{tex}\\theta{/tex}</span> = 0&deg; and h = 0, hence we have<br />
v<sub>L</sub>&nbsp;= v = v<sub>o&nbsp;</sub>....[from (i) putting h = 0]<br />
Thus,<br />
<span class="math-tex">{tex}T _ { L } = m g \\cos 0 ^ { \\circ } + \\frac { m } { l } v _ { L } ^ { 2 } = m g + \\frac { m v _ { 0 } ^ { 2 } } { l }{/tex}</span><br />
and at the highest point&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;=&nbsp;180&deg; and h = 2<span class="math-tex">{tex}l{/tex}</span>. Hence,<br />
<span class="math-tex">{tex}v _ { H } ^ { 2 } = v^2 = v _ { 0 } ^ { 2 } - 4 g l{/tex}</span>&nbsp;[from (i) putting h = 2<span class="math-tex">{tex}l{/tex}</span>]<br />
or&nbsp;<span class="math-tex">{tex}v _ { H } = \\sqrt { v _ { 0 } ^ { 2 } - 4 g l }{/tex}</span><br />
and&nbsp;<span class="math-tex">{tex}T _ { H } = m g \\cos 180 ^ { \\circ } + \\frac { m v _ { H } ^ { 2 } } { l } = m g ( - 1 ) + \\frac { m } { l } \\left( v _ { 0 } ^ { 2 } - 4 g l \\right){/tex}</span><span class="math-tex">{tex}= \\frac { m v _ { 0 } ^ { 2 } } { l } - 5 m g{/tex}</span>&nbsp;<br />
which is the required expression for the Tension.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State and prove the principle of law of conservation of linear momentum.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The principle of conservation of linear momentum states that,&quot;If no external forces act on the system of two colliding objects, then the vector sum of the linear momentum of each body remains constant and is not affected by their mutual interaction.&quot; i.e. if&nbsp;<span class="math-tex">{tex}\\overline { F } e x t = 0 \\text { then } \\overline { P } = \\text { constant }{/tex}</span>.&nbsp; To prove this principle, we consider a collision between two spheres&nbsp;<strong>A</strong>&nbsp;and&nbsp;<strong>B</strong>&nbsp;having masses of&nbsp;<strong>m<sub>1</sub></strong>&nbsp;and&nbsp;<strong>m</strong><sub><strong>2</strong>&nbsp;</sub>respectively.Let&nbsp;<strong>u</strong><sub><strong>1</strong>&nbsp;</sub>and&nbsp;<strong>u<sub>2</sub></strong>&nbsp;be the velocities of the spheres before collision such that&nbsp;<strong>u</strong><sub><strong>1</strong>&nbsp;</sub>&gt;&nbsp;<strong>u</strong><sub><strong>2</strong>&nbsp;</sub>and moving on the same straight line . After collision, let their velocities be&nbsp;<strong>v</strong><sub><strong>1</strong>&nbsp;</sub>and&nbsp;<strong>v</strong><sub><strong>2</strong>&nbsp;</sub>on the same line. If they collide with each other for a short time interval&nbsp;<strong>t</strong>, each sphere exerts a force on the other sphere and so, the force experienced by&nbsp;<strong>A</strong>&nbsp;is given as &nbsp;&nbsp;<span class="math-tex">{tex}F_2 =\\frac{change \\space in \\space momentum }{time}= \\frac{m_1 v_1-m_1 u_1}{t}{/tex}</span></p>

<p>Similarly, force experienced by&nbsp;<strong>B</strong>&nbsp;is&nbsp; &nbsp;<span class="math-tex">{tex}F_1 =\\frac{change \\space in \\space momentum }{time}= \\frac{m_2 v_2-m_2 u_2}{t}{/tex}</span></p>

<p>According to Newton&#39;s third law of motion, the force experienced by&nbsp;<strong>A</strong>&nbsp;and&nbsp;<strong>B</strong>&nbsp;are equal and opposite, <span class="math-tex">{tex}\\vec{F_2}=-\\vec{F_1}{/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow m_2 v_2-m_2 u_2 = -(m_1 v_1-m_1 u_1 ){/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow m_2 v_2+m_1 v_1 = m_1 u_1+m_2u_2 {/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow{ P_f }={P_i} {/tex}</span></p>

<p>That is, total momentum before collision is equal to total momentum after collision if no external forces&nbsp;act on them which proves the principle of conservation of linear momentum.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is meant by banking of roads? What is the need for banking a road? Obtain an expression for the maximum speed with which a vehicle can safely negotiate a curved road banked at an angle <span class="math-tex">{tex}\\theta{/tex}</span>. The coefficient of friction between the wheels and the road is <span class="math-tex">{tex}\\mu{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Banking of road means raising the outer edge of the road with respect to inner edge so that the road makes an angle with the horizontal.<br/>
When a  vehicle moves along a curve, the force of friction provides the necessary centripetal force. But this force has a limit = <span class="math-tex">{tex}\\mu{/tex}</span>mg. When the speed of the vehicle increases beyond this maximum value, the banking of roads is necessary so that the component of normal reaction of the road towards the centre provides the necessary centripetal force.<br/>
From the  figure, for vertical  equilibrium:<br/>
Total upwards force = total downwards force<br/>
N cos<span class="math-tex">{tex}\\theta{/tex}</span> = mg + f sin<span class="math-tex">{tex}\\theta{/tex}</span><br/>
mg = N cos <span class="math-tex">{tex}\\theta{/tex}</span> - f sin <span class="math-tex">{tex}\\theta{/tex}</span> ...(i)<br/>
As the forces N sin <span class="math-tex">{tex}\\theta{/tex}</span>, f cos <span class="math-tex">{tex}\\theta{/tex}</span> provide the necessary centripetal force.<br/>
<span class="math-tex">{tex}\\frac{\\mathrm{mv}^{2}}{\\mathrm{r}}={N} \\sin \\theta+\\mathrm{f} \\cos \\theta{/tex}</span> ...(ii)<br/>
Thus dividing (ii) by (i),<br/>
<span class="math-tex">{tex}\\frac{\\frac{\\mathrm{mv}^{2}}{\\mathrm{r}}}{\\mathrm{mg}}=\\frac{\\mathrm{N} \\sin \\theta+\\mathrm{fcos} \\theta}{\\mathrm{N} \\cos \\theta-\\mathrm{f} \\sin \\theta}{/tex}</span><br/>
As f = <span class="math-tex">{tex}\\mu_s{/tex}</span>N<br/>
Thus,<br/>
<span class="math-tex">{tex}\\frac{v^{2}}{r g}=\\frac{\\sin \\theta+\\mu_{s} \\cos \\theta}{\\cos \\theta-\\mu_{s} \\sin \\theta}{/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{\\tan \\theta+\\mu_{s}}{1-\\mu_{s} \\tan \\theta}{/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{\\tan \\theta+\\tan \\lambda}{1-\\tan \\lambda \\tan \\theta}=\\tan (\\theta+\\lambda){/tex}</span><br/>
<span class="math-tex">{tex}{v}=\\sqrt{\\operatorname{rg} \\tan (\\theta+\\lambda)}{/tex}</span> where <span class="math-tex">{tex}\\tan \\lambda=\\mu_{s}{/tex}</span><br/>
<img alt="" data-imgur-src="SO7xElh.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1637065670-rwyjwa.jpg" style="width: 200px; height: 129px;"/><img alt="" data-imgur-src="1XdPJZv.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1637065672-fa2tfr.jpg" style="width: 200px; height: 148px;"/></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A man of mass 70 kg stands on a weighing scale in a lift which is moving</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>upwards with a uniform speed of 10 m/s?</li>
	<li>downwards with a uniform acceleration of 5 m/s<sup>2</sup>?</li>
	<li>upwards with a uniform acceleration of 5 m/s<sup>2</sup>.<br />
	What would be the readings on the scale in each case?</li>
	<li>What would be the reading if the lift mechanism failed and it hurtled down freely under gravity?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, the mass of man, m&nbsp;= 70 kg<br />
In each case, the weighing scale will read the reaction R for the action force W (weight of the man),<br />
i.e. the apparent weight of the man.</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>As lift is moving upward with a uniform speed, therefore, its acceleration a = 0<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Normal reaction W&nbsp;= R = m g = 70<span class="math-tex">{tex}\\times{/tex}</span>10 N = 700 N<br />
	W acts vertically downwards and R acts vertically upwards.<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Reading on weighing scale &nbsp;<span class="math-tex">{tex}=\\frac{700}{10}=70 \\mathrm{kg}{/tex}</span>&nbsp;force</li>
	<li>When the acceleration of the lift,&nbsp;<span class="math-tex">{tex}a=5 \\mathrm{m} / \\mathrm{s}^{2}(\\downarrow){/tex}</span>, then the net acceleration is (g - a) = 5m/s<sup>2&nbsp;</sup>&nbsp;by using newton second law of motion, we can write the equation of motion as-<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Normal reaction, R = m (g -a) = 70(10 - 5)N<br />
	<span class="math-tex">{tex}=70 \\times 5 \\mathrm{N}=350 \\mathrm{N}{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Reading on weighing scale =&nbsp;<span class="math-tex">{tex}\\frac{350 \\mathrm{N}}{10 \\mathrm{m} / \\mathrm{s}^{2}}=35 \\mathrm{kg}{/tex}</span>-force</li>
	<li>Acceleration of the lift, a = 5 m/s<sup>2</sup><span class="math-tex">{tex}(\\uparrow){/tex}</span>, then the net acceleration is (g + a) = 15 m/s<sup>2</sup><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;R = m ( g + a)<br />
	=&nbsp; 70(10 + 5) = 1050 N<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Reading on weighing scale =&nbsp;<span class="math-tex">{tex}\\frac{1050 \\mathrm{N}}{10 \\mathrm{m} / \\mathrm{s}^{2}}=105 {/tex}</span> kg-force<br />
	Acceleration of the lift when it is falling freely under the effect of gravity, then&nbsp;<br />
	<span class="math-tex">{tex}a=g(\\downarrow){/tex}</span><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;R = m(g - a) = m(g - g) = 0<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Reading on weighing scale = 0 kg-force</li>
	<li>When the lift moves freely under gravity, acceleration&nbsp;a = g<br />
	Using Newton&#39;s second law of motion, we can write the equation of motion as,<br />
	R + m g = ma<br />
	R = m( g - a)<br />
	= m(g-g)<br />
	= 0<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Reading on the weighing scale =&nbsp;<span class="math-tex">{tex}\\frac{0}{g}{/tex}</span>&nbsp;= 0 kg</li>
</ol>

<p>The man will be in a state of weightlessness.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>A mass of 5 kg is suspended by a rope of length 2 m from a ceiling. A force of 50 N in the horizontal direction is applied at the point P of the rope, as shown in figure.<br/>
<img alt="" data-imgur-src="tnXnwiz.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1704892823-m9ksb2.jpg" style="height:228px; width:156px"/></p>
<ol start="1" style="list-style-type:lower-roman">
<li>What is the angle the rope makes with the vertical in equilibrium? Take g = 10ms<sup>-2</sup>. Neglect the mass of the rope.</li>
<li>What is the tension in the rope?</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704712968-pbg94t.jpg" style="height:188px; width:150px" /><br />
	For equilibrium<br />
	F = T sin 0...(i)<br />
	and T cos<span class="math-tex">{tex}\\theta{/tex}</span> = 5 g ...(ii)<br />
	Taking ratio of (i) and (ii)<br />
	<span class="math-tex">{tex}\\frac{\\mathrm{T} \\sin \\theta}{\\mathrm{T} \\cos \\theta}=\\frac{\\mathrm{F}}{5 \\mathrm{~g}}=\\frac{50}{5 \\times 10}=1{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span> tan<span class="math-tex">{tex}\\theta{/tex}</span> = 1<br />
	<span class="math-tex">{tex}\\theta{/tex}</span> = 45<sup>o</sup><br />
	Thus angle made by rope with the vertical is <span class="math-tex">{tex}\\theta{/tex}</span> = 45<sup>o</sup></li>
	<li>Let <span class="math-tex">{tex}\\theta{/tex}</span> be the angle made by the rope with the vertical in equilibrium. Let T<sub>1</sub> and T<sub>2</sub> be the tension in the rope as shown in figure.<br />
	The free body diagram of 5 kg block<br />
	In equilibrium, <span class="math-tex">{tex}\\Rightarrow{/tex}</span> T&#39; = 5g = 5 <span class="math-tex">{tex}\\times{/tex}</span> 10 = 50N<br />
	The free body diagram of the point P<br />
	In equilibrium, <span class="math-tex">{tex}\\Rightarrow{/tex}</span> Tsin(<span class="math-tex">{tex}\\theta{/tex}</span>) = 50N ...(i)<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span> Tcos(<span class="math-tex">{tex}\\theta{/tex}</span>) = T&#39; = 50N ...(ii)<br />
	T = 50/sin45<br />
	T = 70.7106N</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Two bodies of masses 10 kg and 20 kg respectively kept on a smooth, horizontal surface are tied to the ends of a light string. A horizontal force F = 600 N is applied to</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>A,</li>
	<li>B along the direction of the string.</li>
</ol>

<p>What is the tension in the string in each case?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Horizontal force is given by, F = 60 kgf = 60&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> g N = 60&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10 N = 600 N<br />
Mass of body is given by A, m<sub>1</sub> = 10 kg<br />
Mass of body B is given by, m<sub>2</sub> = 20 kg<br />
Total mass of the system is given by, m = m<sub>1</sub>&nbsp;+ m<sub>2</sub> = 30 kg<br />
By Using Newton&#39;s second law of motion, the acceleration (a) produced in the system can be calculated as:<br />
F = ma<br />
<span class="math-tex">{tex}a = \\frac { F } { m } = \\frac { 600 } { 30 } = 20 m / s ^ { 2 }{/tex}</span></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Both the bodies A and B will move with this acceleration as shown in the image. Now when force F is applied on body A, say the tension acting in the string between A and B is T.<br />
	<img id="Picture 34" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch05/4m/image053.jpg" style="width: 150px; height: 36px;" /><br />
	The equation of motion can be written as:<br />
	F - T = m<sub>1</sub>a<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span> T = F - m<sub>1</sub>a<br />
	<span class="math-tex">{tex}= 600 - 10 \\times 20{/tex}</span> = 400 N ,Hence tension= 400N.</li>
	<li>In this case two bodies A and B will also move with the&nbsp;same acceleration,&nbsp;a = 20 m/s<sup>2&nbsp;</sup> but in the opposite direction as shown in the figure.&nbsp;Now when the force F is applied on body B, say the tension in the string between A and B is T&#39; in this case.<br />
	<img id="Picture 35" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch05/4m/image057.jpg" style="width: 150px; height: 38px;" /><br />
	The equation of motion can be written as:<br />
	F - T&#39; = m<sub>2</sub>a<br />
	T&#39; = F - m<sub>2</sub>a<br />
	<span class="math-tex">{tex}\\therefore T' = 600 - 20 \\times 20 = 200 \\mathrm { N }{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>Why are circular roads banked? Deduce an expression for the angle of banking.</li>
	<li>A 1000 kg car rounds a curve on a flat road of radius 50 m at a speed of 50 km h<sup>-1</sup> (14 ms<sup>-1</sup>). Will the car make the turn or will it skid if the coefficient of friction is 0.60? Justify.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>To avoid the risk of skidding as well as to reduce the wear and tear of the car tyres, the road surface at a bend is tilted inward, i.e., the outer side of the road is raised above its inner side. This is called banking of road.<br />
	F<sub>max</sub> = <span class="math-tex">{tex}\\mu_{\\mathrm{s}} \\mathrm{N}{/tex}</span> ...(i)<br />
	<span class="math-tex">{tex}\\therefore \\frac{\\mathrm{v}_{\\max }^2}{\\mathrm{rg}}=\\left[\\frac{\\mathrm{N} \\sin \\theta+\\mathrm{F}_{\\max } \\cos \\theta}{\\mathrm{N} \\cos \\theta-\\mathrm{F}_{\\max } \\sin \\theta}\\right]{/tex}</span><br />
	Dividing the numerator and denominator of equation (i) by N cos<span class="math-tex">{tex}\\theta{/tex}</span>, we have,<br />
	<span class="math-tex">{tex}v_{\\text {max }}^2=r g\\left[\\frac{\\frac{N \\sin \\theta}{N \\cos \\theta}+\\frac{F_{\\max } \\cos \\theta}{N \\cos \\theta}}{\\frac{N \\cos \\theta}{N \\cos \\theta}-\\frac{F_{\\max } \\sin \\theta}{N \\cos \\theta}}\\right]{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore v_{\\max }^2=r g\\left[\\frac{\\tan \\theta+\\frac{F_{\\max }}{N}}{1-\\frac{F_{\\max } \\tan \\theta}{N}}\\right]{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore v_{\\max }^2=\\operatorname{rg}\\left[\\frac{\\mu_{\\mathrm{s}}+\\tan \\theta}{1-\\mu_{\\mathrm{s}} \\tan \\theta}\\right]{/tex}</span> [<span class="math-tex">{tex}\\because{/tex}</span> F<sub>max</sub> = <span class="math-tex">{tex}\\mu_{\\mathrm{s}} \\mathrm{N}{/tex}</span>]<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span> <span class="math-tex">{tex}\\mathrm{v}_{\\max }=\\sqrt{\\operatorname{rg}\\left[\\frac{\\mu_{\\mathrm{s}}+\\tan \\theta}{1-\\mu_{\\mathrm{s}} \\tan \\theta}\\right]}{/tex}</span>...(ii)</li>
	<li>required centripetal force = <span class="math-tex">{tex}\\frac{mv^2}{r}{/tex}</span><br />
	<span class="math-tex">{tex}1000 \\times \\frac{(14)^2} {50}{/tex}</span> = 3920 Na<br />
	force of friction = 0.60 <span class="math-tex">{tex}\\times{/tex}</span> 1000 <span class="math-tex">{tex}\\times{/tex}</span> 9.8 = 5880 N<br />
	as the force of friction is greater then centripetal force, car will not skid</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Two masses 8 kg and 12 kg are connected at the two ends of a light, inextensible string that goes over a frictionless pulley. Find the acceleration of the masses and the tension in the string when the masses are released.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The given system of two masses 8 kg, 12 kg and a pulley can be represented as shown in the following figure. In this case, weights of the two masses act downwards and tension T in the two cases act upwards:<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch05/5m/image024.jpg" style="height:82px; width:100px" /><br />
Smaller mass is given by, m<sub>1</sub> = 8 kg<br />
Larger mass is given by, m<sub>2</sub> = 12 kg<br />
Tension in the string is given by = T<br />
When released, mass m<sub>2</sub>, owing to its weight, moves downward with acceleration a, and mass m<sub>1</sub> moves upward with the same acceleration (as they constitute a single system). Hence,<br />
By applying Newton&#39;s second law of motion to the system of masses:<br />
For mass m<sub>1</sub>:<br />
The equation of motion can be written as given below :<br />
T - m<sub>1</sub>g = ma . . .(i) (as the tension T exceeding the weight m<sub>1</sub>g causes the motion of mass m<sub>1</sub>)<br />
For mass m<sub>2</sub>:<br />
The equation of motion can be written as given below:<br />
m<sub>2</sub>g - T = m<sub>2</sub>a ...(ii)(here weight m<sub>2</sub>g exceeding the tension T causes motion of mass m<sub>2</sub>)<br />
Adding equations (i) and (ii), we get:<br />
(m<sub>2</sub> - m<sub>1</sub>)g = (m<sub>1</sub> + m<sub>2</sub>)a<br />
<span class="math-tex">{tex}\\therefore a = \\left( \\frac { m _ { 2 } - m _ { 1 } } { m _ { 1 } + m _ { 2 } } \\right) g{/tex}</span> ...(iii)​<br />
​​​​​​<span class="math-tex">{tex}= \\left( \\frac { 12 - 8 } { 12 + 8 } \\right) \\times 10 = \\frac { 4 } { 20 } \\times 10 = 2 m / s ^ { 2 }{/tex}</span>&nbsp;<br />
Thus, the acceleration of both masses is 2 m/s<sup>2</sup>.<br />
Substituting the value of &#39;a&#39; in equation (ii), we get:<br />
<span class="math-tex">{tex}m _ { 2 } g - T = m _ { 2 } \\times a{/tex}</span>&nbsp;<br />
T = m<sub>2</sub>&nbsp;(g-a)<br />
= 12 ( 10-2)<br />
=96 N<br />
Therefore, the tension in the string is given by&nbsp;96 N.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Derive an expression for velocity of a car on a banked circular road having coefficient of friction <span class="math-tex">{tex}\\mu{/tex}</span>. Hence write the expression for optimum velocity.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1705039174-nvunrx.jpg" style="height:138px; width:250px" /><br />
Force equations at maximum speed v, at threshold of sliding up incline.<br />
<span class="math-tex">{tex}\\Sigma F_x=m \\frac{v^2}{r}=N \\sin \\theta+\\mu_s N \\cos \\theta{/tex}</span><br />
<span class="math-tex">{tex}\\Sigma F_y{/tex}</span> = 0 = N cos<span class="math-tex">{tex}\\theta{/tex}</span> - <span class="math-tex">{tex}\\mu_{\\mathrm{s}} \\mathrm{N}{/tex}</span> sin<span class="math-tex">{tex}\\theta{/tex}</span> - mg<br />
Solving this pair of equations for the maximum speed v gives:<br />
<span class="math-tex">{tex}\\mathrm{v}_{\\max }=\\sqrt{\\frac{\\mathrm{rg}\\left(\\sin \\theta+\\mu_{\\mathrm{s}} \\cos \\theta\\right)}{\\cos \\theta-\\mu_{\\mathrm{s}} \\sin \\theta}}{/tex}</span><br />
The limiting cases are:<br />
<span class="math-tex">{tex}v_{\\text {max }}=\\sqrt{r g \\tan \\theta}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State Newton&#39;s Second law of motion. Derive a mathematical formula to calculate force if mass remains constant. Prove that it contains Newton&#39;s first law.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Newton&#39;s Second law of motion is given as the rate of change of momentum is directly proportional to the force applied on the system.<br />
It also gives us a relation between force F, mass m and acceleration of an object. Force applied is directly proportional to the product of mass and acceleration.<br />
Riding a bicycle is a good example of this second law of motion at work. If we consider that our bicycle is the mass. Our leg muscles push the pedals of our bicycle. When we push on the pedals, our bicycle accelerates. Therefore this shows that we are increasing the speed of the bicycle by applying force to the pedals.<br />
When the mass m is constant, the force applied on an object is given by:<br />
<span class="math-tex">{tex}F=\\frac{d p}{d t}{/tex}</span><br />
<span class="math-tex">{tex}\\because{/tex}</span> p = mv<br />
m = const.<br />
<span class="math-tex">{tex}\\frac{d p}{d t}=m \\frac{d v}{d t}+v \\frac{d m}{d t}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\frac{d p}{d t}=m \\frac{d v}{d t}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore F=m \\frac{d v}{d t}{/tex}</span><br />
So, we get the expression of force, when the mass of an object is constant.<br />
Now, as we know Newton&rsquo;s first law of motion, states that an object continues to be in rest or in motion in a particular direction until and unless any external force is applied on it, this is also known as law of inertia.<br />
Inertia is the tendency of an object to remain at rest or in motion; it is related to mass of an object.<br />
Therefore, in the above expression of force, where mass is constant, also proves the first law of motion, which is also called law of inertia.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Consider two masses m<sub>1</sub> and m<sub>2</sub>&nbsp;connected by a light and inextensible string passing over a smooth light pulley which is fixed by a rigid cord, from a rigid support as shown in figure. This device is also known as Atwood&#39;s machine. Find the tension in the rope and acceleration of each block.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1688034850-3hs4k2.jpg" style="width: 200px; height: 189px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>To study the motion of the blocks, let us draw the free body diagram (FBD) of various parts of the system, by assuming m<sub>2</sub> &gt; m<sub>1</sub>. FBD and dynamics of block m<sub>1</sub><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1688034931-kjxakd.jpg" style="width: 80px; height: 129px;" /><br />
T - m<sub>1</sub>g = m<sub>1</sub>a ...(i)<br />
FBD and dynamics of block m<sub>2</sub>,<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1688034963-cd8pft.jpg" style="width: 100px; height: 156px;" /><br />
m<sub>2</sub>g - T = m<sub>2</sub>a ...(ii)<br />
FBD of pulley<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1688035012-vnw4jb.jpg" style="width: 60px; height: 134px;" /><br />
R - 2T = 0 ...(iii)<br />
Where, R is reaction on teh axle of pulley. Since, pulley is fixed, therefore, a = 0 for it.<br />
From the solution of simulotaneous Eqs.(i), (ii) and (iii) we get, the value of acceleration a, tension T and pressure R on the axle of pulley.<br />
Thus, from adding Eqs. (i) and (ii), we get acceleration a<br />
T - m<sub>1</sub>g = m<sub>1</sub>a<br />
and m<sub>2</sub>g - T = m<sub>2</sub>a<br />
or T - m<sub>1</sub>g + m<sub>2</sub>g - T = m<sub>1</sub>a + m<sub>2</sub>a<br />
m<sub>2</sub>g -&nbsp;m<sub>1</sub>g = a(m<sub>1</sub> + m<sub>2</sub>)<br />
<span class="math-tex">{tex}a=\\frac{\\left(m_2-m_1\\right) g}{\\left(m_1+m_2\\right)}{/tex}</span>&nbsp;...(iv)<br />
On substituting a in Eqs.(i) or (ii), we get<br />
<span class="math-tex">{tex}T=\\left(\\frac{2 m_1 m_2 g}{m_1+m_2}\\right){/tex}</span>&nbsp;...(v)<br />
and pressure on pulley from eq. (iii), we get<br />
R = 2T<br />
R =&nbsp;<span class="math-tex">{tex}2\\times \\frac{2 m_1 m_2 g}{m_1+m_2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{4 m_1 m_2 g}{m_1+m_2}{/tex}</span>&nbsp;...(vi)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1345-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_WORK_ENERGY_AND_POWER = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>In which case is the work done zero?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">Force and displacement are perpendicular to each other</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Work done, W = Fdcos<span class="math-tex">{tex}\\theta{/tex}</span><br />
where&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;is the angle between F and d. If both are perpendicular then&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 90 degrees, so cos<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 0 &nbsp;and thus work done is zero.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Force and displacement are in the same direction</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Force and displacement are at an angle of 45<span class="math-tex">{tex}^\\circ {/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Force and displacement are at an angle of 75<span class="math-tex">{tex}^\\circ {/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two bodies with kinetic energies in the ratio of 4 : 1 are moving with equal linear momentum. The ratio of their masses is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">4 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">1 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">1 : 2</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">1 : 4</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>For same p,<br />
E&nbsp;<span class="math-tex">{tex}\\propto \\frac{1}{m}{/tex}</span>&nbsp;or m&nbsp;<span class="math-tex">{tex}\\propto \\frac{1}{E}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\frac{m_{1}}{m_{2}}=\\frac{E_{2}}{E_{1}}=\\frac{1}{4}{/tex}</span>,= 1 : 4</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two bodies of masses m<sub>1</sub> and m<sub>2</sub> have same momentum. The ratio of their KE is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{\\frac{m_2}{m_1}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{\\frac{m_1}{m_2}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{m_1}{m_2}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{m_2}{m_1}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\frac{m_2}{m_1}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two bodies of mass m and 4 m have equal kinetic energy. What is the ratio of their momentum?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">1 : 4</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">1 : 2</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>p =&nbsp;<span class="math-tex">{tex}\\sqrt{2 m K}{/tex}</span><br />
For same K, p&nbsp;<span class="math-tex">{tex}\\propto \\sqrt{m}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\frac{p_{1}}{p_{2}}=\\sqrt{\\frac{m_{1}}{m_{2}}}=\\sqrt{\\frac{m}{4 m}}=\\frac{1}{2}{/tex}</span> = 1 : 2</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">1 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">2 : 1</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Power can be expressed as</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{F} \\cdot \\vec{v}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>P =&nbsp;<span class="math-tex">{tex}\\vec{F} \\cdot \\vec{v}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2} \\vec{F} \\cdot v^{2}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{F}\\cdot{/tex}</span>t</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{F} \\times \\vec{v}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A body is initially at rest. It undergoes one-dimensional motion with constant acceleration. The power delivered to it at time t is proportional to</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">t<sup>1/2</sup></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">t</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>From Newton&rsquo;s first equation of motion,<br />
v = u + at<br />
where v is the final velocity<br />
u is the initial velocity, a is the acceleration of the body and<br />
t is the time taken<br />
Given, u = 0.<br />
So, v = at<br />
Power is given by<br />
P = F <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;v<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;P = ma <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;at&nbsp; &nbsp; &nbsp;...[ F = ma]<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;P = ma<sup>2</sup>t<br />
Since m and a are constant,<br />
P&nbsp;<span class="math-tex">{tex}\\propto{/tex}</span>&nbsp;t<br />
Hence, power is directly proportional to the time</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">t<sup>3/2</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">t<sup>2</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If F is a force and d is the displacement in the direction of force then the work done by the force is given by</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">F.d</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Work done is equal to force in the direction of displacement multiplied by displacement i.e.,&nbsp;<br />
<span class="math-tex">{tex}W = \\vec F.\\vec d{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">- F.d</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">2F.d</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">-2F.d</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>In an inelastic collision, what is conserved?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Kinetic energy</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">Momentum</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>In&nbsp;an inelastic collision, momentum is conserved and K.E. is not conserved.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Kinetic energy and Momentum</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Neither Kinetic energy nor momentum</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the kinetic energy of a body becomes four times of its initial value, then new momentum will</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">become twice its initial value</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>p =&nbsp;<span class="math-tex">{tex}\\sqrt{2 m K}{/tex}</span><br />
<span class="math-tex">{tex}p^{\\prime}=\\sqrt{2 m \\times 4 K}=2 \\sqrt{2 m K}{/tex}</span> = 2p</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">become thrice its initial value</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">become four times its initial value</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">remain constant</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the force and displacement of particle in the direction of force are doubled, then work done would be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">double</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">4 times</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\because{/tex}</span>&nbsp;Work = Force x Displacement ...(i)<br />
So, if the force and displacement of particle in the direction of force are doubled, then as per Eq. (i), their product will make the work done 4 times more than its initial value.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">half</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac 14{/tex}</span>times</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A body is moving along a circular path. How much work is done by the centripetal force?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">-1 J</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">-2 J</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">3 J</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">Zero</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>For a body moving along a circular path, the centripetal force acts along the radius while the displacement is tangential, i.e. <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= 90&deg;, therefore, W = Fs cos 90&deg; = 0.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The work done by a conservative forces depends</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">only on the end points</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>A force is said to be conservative if work done by this force is independent of path and is dependent only on end points.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">depends on the path</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">on the position of the forces</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">on both the end points as well as the path</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The work done by the force is defined to be</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">the product of component of the force in the direction of the displacement and the magnitude of the displacement</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Work done is given by&nbsp;</p>

<p>W = (Fcos<span class="math-tex">{tex}\\theta{/tex}</span>)d</p>

<p>here Fcos<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;is the component of applied force &nbsp;in direction of displacement and d is magnitude of displacement.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">the product of force and the magnitude of the displacement</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">the product of component of the force in the direction perpendicular to displacement and the magnitude of the displacement</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">the negative product of component of the force in the direction of the displacement and the magnitude of this displacement</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A bicyclist comes to a skidding stop in 10 m. During this process, the force on the bicycle due to the road is 200N and is directly opposed to the motion. The work done by the cycle on the road is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">+2000J</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">-200J</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">Zero</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As the road does not move at all, therefore, work done by the cycle on the road is zero.<br />
W = 0, because road cannot move.&nbsp;So, s = 0<br />
W = F&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> s = F&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 0 = 0J</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">-20,000J</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>State and explain work-energy theorem.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The work-energy theorem states that the work done by a force acting on a body is equal to the change produced in its kinetic energy. If work W is being done on a body of mass m and due to the work done, the speed of the body changes from u to v, then,<br />
Work done, W = Change in its kinetic energy</p>

<p><span class="math-tex">{tex}\\therefore W = \\Delta K = K _ { 2 } - K _ { 1 } = \\frac { 1 } { 2 } m v ^ { 2 } - \\frac { 1 } { 2 } m u ^ { 2 }{/tex}</span><br />
From the theorem, it is clear that if work done on a body is positive, the kinetic energy of the body must increase. On the other hand, if work done on a body is negative, its kinetic energy should decrease.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Derive an expression for the potential energy of an elastic stretched spring.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704868326-utgft5.jpg" style="height:152px; width:200px" /><br />
By Hooke&#39;s law:<br />
<span class="math-tex">{tex}\\vec{F}=-k \\vec{x}{/tex}</span><br />
<span class="math-tex">{tex}\\vec{\\mathrm{F}}_{e \\mathrm{xt}}=+\\mathrm{kx} {/tex}</span><br />
If the spring is stretched through a displacement&nbsp;dx<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> dw = <span class="math-tex">{tex}\\vec{\\mathrm{F}}_{\\mathrm{ext}} \\cdot \\mathrm{dx}{/tex}</span><br />
dw = F<sub>ext</sub> dx (Let <span class="math-tex">{tex}\\theta{/tex}</span> = 0<sup>o</sup>)<br />
dw = kx dx<br />
on Integrating, we get total work done<br />
so, <span class="math-tex">{tex} \\int d w=\\int k x d x{/tex}</span><br />
P.E&nbsp;= w =&nbsp;<span class="math-tex">{tex}\\text K {[\\frac { \\text x^2}{\\text 2}]}^{x}_{0}{/tex}</span>&nbsp;<span class="math-tex">{tex}=K\\left[\\frac{x^2}{2}-\\frac{0^2}{2}\\right]{/tex}</span>&nbsp;<span class="math-tex">{tex}=\\frac{1}{2} K x^2{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Define the term work and derive its SI unit. Write an expression for the kinetic energy of a body of mass m moving with a uniform speed v.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Work is said to be done only when a force applied to a body causes displacement in the direction of the applied force. SI unit of work is Joule (J).<br />
Suppose a stationary object of mass &lsquo;m&rsquo; moves because of an applied force. Let u&nbsp;be its initial velocity (here u = 0). Let the applied force be F. This generates an acceleration a in the object, and after time t, the velocity of the object becomes equal to v. The displacement during this time is s.<br />
S = 0 + <span class="math-tex">{tex}\\frac{1}{2} \\mathrm{at}^2{/tex}</span><br />
S = <span class="math-tex">{tex}\\frac{1}{2} \\mathrm{at}^2{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\text W= \\vec F \\cdot \\vec {\\text d}{/tex}</span><br />
W = ma <span class="math-tex">{tex}\\times{/tex}</span> <span class="math-tex">{tex}\\frac{1}{2} \\mathrm{at}^2{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span> W = <span class="math-tex">{tex}\\frac{1}{2} \\mathrm{~m} \\times(\\mathrm{at})^2{/tex}</span><br />
Using Newton&#39;s first equation of motion<br />
v = u + at<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> v = 0 + at<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> v = at<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> v<sup>2</sup> = a<sup>2</sup>t<sup>2</sup> = (at)<sup>2</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span> <span class="math-tex">{tex}W=\\frac{1}{2} m v^2{/tex}</span><br />
The kinetic energy gained by an object is the amount of work done on the object.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> K.E = W<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> K.E = <span class="math-tex">{tex}\\frac{1}{2}mv^2{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A body is moving unidirectionally under the influence of a source of constant power. Its displacement in time t is proportional to</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">t<sup>1/2</sup></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">t</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">t<sup>3/2</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>We know that<br />
Power, P = Fv = k (constant)<br />
Considering the dimensions,<br />
[P] = [F][v]<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;[P] = [MLT<sup>-2</sup>][LT<sup>-1</sup>]<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;[P] = [ML<sup>2</sup>T<sup>-3</sup>]<br />
So, [ML<sup>2</sup>T<sup>-3</sup>] = k<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;[L<sup>2</sup>T<sup>-3</sup>] = k&nbsp; &nbsp; ...[M is constant]<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;[L<sup>2</sup>/T<sup>3</sup>] = k<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;[L<sup>2</sup>] = k[T<sup>3</sup>]<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;[L<sup>2</sup>]&nbsp;<span class="math-tex">{tex}\\propto{/tex}</span>&nbsp;[T<sup>3</sup>]<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;[L]&nbsp;<span class="math-tex">{tex}\\propto{/tex}</span>&nbsp;[T<sup>3/2</sup>]<br />
&nbsp;Hence,&nbsp;L&nbsp;<span class="math-tex">{tex}\\propto{/tex}</span>&nbsp;t<sup>3/2</sup></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">t<sup>2</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>If the linear momentum of a body increases by 20%, what will be the % increase in the kinetic energy of the body?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Initial kinetic energy of the body,<br />
K =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;mv<sup>2</sup>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\frac{m^{2} v^{2}}{m}=\\frac{p^{2}}{2 m}{/tex}</span><br />
Increase in momentum = 20% of p =&nbsp;<span class="math-tex">{tex}\\frac{20}{100} \\times{/tex}</span>&nbsp;p =&nbsp;<span class="math-tex">{tex}\\frac{p}{5}{/tex}</span><br />
Final momentum = p +&nbsp;<span class="math-tex">{tex}\\frac{p}{5}=\\frac{6 p}{5}{/tex}</span><br />
Final kinetic energy of the body,<br />
<span class="math-tex">{tex}K^{\\prime}=\\frac{(6 p / 5)^{2}}{2 m}=\\frac{36}{25} \\frac{p^{2}}{2 m}=\\frac{36}{25} K{/tex}</span><br />
Increase in kinetic energy<br />
=&nbsp;<span class="math-tex">{tex}K^{\\prime}{/tex}</span>&nbsp;- K =&nbsp;<span class="math-tex">{tex}\\frac{36}{25}{/tex}</span>&nbsp;K - K =&nbsp;<span class="math-tex">{tex}\\frac{11}{25}{/tex}</span>&nbsp;K<br />
%&nbsp;Increase in K.E.<br />
<span class="math-tex">{tex}=\\frac{K^{\\prime}-K}{K} \\times{/tex}</span>&nbsp;100 =&nbsp;<span class="math-tex">{tex}\\frac{\\frac{11}{25} K}{K} \\times{/tex}</span> 100 = 44%.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>If the kinetic energy of a body increases by 300%, by what % will the linear momentum of the body increase?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Initial kinetic energy,<br />
K =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;mv<sup>2</sup>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\frac{m^{2} v^{2}}{m}=\\frac{p^{2}}{2 m}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Initial momentum, p =&nbsp;<span class="math-tex">{tex}\\sqrt{2 m K}{/tex}</span><br />
Increase in kinetic energy = 300% of K =3 K<br />
Final kinetic energy,<br />
<span class="math-tex">{tex}K^{\\prime}{/tex}</span>&nbsp;= K + 3K = 4K<br />
Final momentum,<br />
<span class="math-tex">{tex}p^{\\prime}=\\sqrt{2 m K^{\\prime}}=\\sqrt{2 m \\times 4 K}=2 \\sqrt{2 m K}{/tex}</span>&nbsp;= 2p<br />
% Increase in momentum<br />
<span class="math-tex">{tex}=\\frac{p^{-p}}{p} \\times{/tex}</span>&nbsp;100 =&nbsp;<span class="math-tex">{tex}\\frac{2 p-p}{p} \\times{/tex}</span> 100 = 100%.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A body falls towards earth in the air. Will its total mechanical energy be conserved during the fall? Justify.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If we neglect the air resistance then the total mechanical energy of the body is conserved but if there is some air resistance then a small part of its energy is utilized against resistive force of air, which is nonconservative force. So, the total mechanical energy of the body falling freely under gravity, in this case, is not conserved. In this condition, gain in KE &lt; loss&nbsp;in PE.<br />
Let E&nbsp;be the total mechanical energy.<br />
The initial mechanical energy of the body<br />
E = U<sub>i&nbsp;</sub>+ K<sub>i</sub><br />
The intermediate mechanical energy of the body will be<br />
E = U<sub>f&nbsp;</sub>+ K<sub>f&nbsp;</sub>- W<sub>air</sub><br />
So, U<sub>i&nbsp;</sub>+ K<sub>i&nbsp;</sub>&gt; U<sub>f&nbsp;</sub>+ K<sub>f</sub><br />
Hence, the total mechanical energy of the body will not be conserved as some work has to be done against the resistive force of air which is a non-conservative force.&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Consider the collision depicted in figure to be between two billiard balls with equal masses m<sub>1</sub> =m<sub>2</sub>. The first ball is called the cue while the second ball is called the target. The billiard player wants to sink the target ball in a corner pocket, which is at an angle <span class="math-tex">{tex}\\theta{/tex}</span><sub>2</sub> = 37<sup>0</sup>. Assume that the collision is elastic and that friction and rotational motion are not important. Obtain <span class="math-tex">{tex}\\theta{/tex}</span><sub>1</sub>.<br />
<img alt="" data-imgur-src="dWBmFOL.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/dWBmFOL.png" style="width: 330px; height: 169px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>From the law of conservation of linear momentum, we have<br />
mu<sub>1</sub>&nbsp;+ 0 = mv<sub>1</sub>+ mv<sub>2</sub><br />
or u<sub>1</sub>=v<sub>1</sub>+ v<sub>2</sub>&nbsp; .............................................................................(i)<br />
By conservation of energy, we have<br />
<span class="math-tex">{tex}\\frac{1}{2} m u_{1}^{2}=\\frac{1}{2} m v_{1}^{2}+\\frac{1}{2} m v_{2}^{2}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}u_{1}^{2}=v_{1}^{2}+v_{2}^{2}{/tex}</span><br />
From Equation&nbsp;(i), we obtain&nbsp;..............................................................(ii)<br />
u<sub>1</sub> <sup>.</sup> u<sub>1</sub>&nbsp;=(v<sub>1</sub>&nbsp;+ v<sub>2</sub>)<sup>.</sup>(v<sub>1</sub>&nbsp;+v<sub>2</sub>)<br />
= v<sub>1</sub>&nbsp;.v<sub>1</sub>&nbsp;+ v<sub>1</sub>&nbsp;. v<sub>2</sub> + v<sub>2</sub> . v<sub>1</sub>&nbsp;+ v<sub>2</sub>.&nbsp;v<sub>2</sub><br />
or&nbsp;<span class="math-tex">{tex}u_{1}^{2}=v_{1}^{2}+v_{2}^{2}+2 \\mathbf{v}_{1} \\cdot \\mathbf{v}_{2}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}u_{1}^{2}=u_{1}^{2}+2 \\mathbf{v}_{1} \\cdot \\mathbf{v}_{2}{/tex}</span>&nbsp; &nbsp; [by using Equatio&nbsp;(ii)]<br />
or v<sub>1</sub>.v<sub>2</sub> = 0<br />
or&nbsp;<span class="math-tex">{tex}\\theta_{1}+\\theta_{2}=90^{\\circ}{/tex}</span><br />
<span class="math-tex">{tex}\\theta_{1}=90^{\\circ}-\\theta_{2}{/tex}</span><br />
&nbsp; &nbsp; &nbsp;= 90 - 37<sup>0</sup>&nbsp; = 53<sup>0</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is a variable force? Find work done by a variable force graphically.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>A <b>variable force</b> is a force whose magnitude or direction or both vary during the displacement of a body on which it acts or a force whose direction or magnitude or both change with time. </p>
<p>The graphical representation is given as:</p>
<p><img alt="" data-imgur-src="hXC3nSm.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/hXC3nSm.png" style="width: 200px; height: 120px;"/><br/>
Consider a small displacement element <span class="math-tex">{tex}\\Delta s{/tex}</span> under force F, which is represented by a strip KLMN. As the displacement <span class="math-tex">{tex}\\Delta{/tex}</span>s is extremely small, hence force F for entire strip KLMN may be taken as constant.<br/>
Therefore, Work done during elementary expansion will be equal to</p>
<p>       <span class="math-tex">{tex}\\Delta W =F\\Delta x{/tex}</span>= area of strip KLMN   ....................................(A)<br/>
Total work done by the variable force can be calculated by dividing the whole path into such elementary parts and in each case the work done will be equal to area of small shaded strips like KLMN. Therefore, total work done for a given displacement is given by:<br/>
W = <span class="math-tex">{tex}\\sum \\Delta W=\\sum{/tex}</span> area of various strips = total area under F-s graph .......................................(B)<br/>
Thus, the work done by a variable force is given by the area under F-s curve.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Answer carefully, with reasons:</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>In an elastic collision of two billiard balls, is the total kinetic energy conserved during the short time of collision of the balls (i.e. when they are in contact)?</li>
	<li>Is the total linear momentum conserved during the short time of an elastic collision of two balls?</li>
	<li>What are the answers to (a) and (b) for an inelastic collision?</li>
	<li>If the potential energy of two billiard balls depends only on the separation distance between their centres, is the collision elastic or inelastic?<br />
	(Note, we are talking here of potential energy corresponding to the force during collision, not gravitational potential energy)</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>In an elastic collision of two billiard balls, the total kinetic energy is not conserved during the short time of collision of the balls. During this period, the kinetic energy of the balls is zero. All the energy is stored in the form of potential energy.</li>
	<li>The total linear momentum is always conserved during the entire duration of collision. The individual linear momenta change but the total linear momentum always remains constant.</li>
	<li>For an inelastic collision, kinetic energy is not conserved but the total linear momentum is conserved.</li>
	<li>The collision is elastic in nature. The forces involved are conservative in nature since potential energy depends on the separation of the centres.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A railway carriage of mass 9000 kg moving with a speed of 36 kmh<sup>-1</sup>&nbsp;collides with a stationary carriage of the same mass. After the collision, the carriages get coupled and move together. What is their common speed after collision? What type of collision is this?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here<br />
m<sub>1</sub>&nbsp;= 9000 kg, u<sub>1</sub>&nbsp;= 36 kmh<sup>-1</sup>&nbsp;= 10 ms<sup>-1</sup><br />
m<sub>2</sub>&nbsp;= 9000 kg, u<sub>2</sub>&nbsp;= 0,v<sub>1</sub>&nbsp;= v<sub>2</sub>&nbsp;= v = ?<br />
By conservation of momentum,<br />
m<sub>1</sub>u<sub>1</sub>&nbsp;+ m<sub>2</sub>u<sub>2</sub>&nbsp;= (m<sub>1</sub>&nbsp;+ m<sub>1</sub>)v<br />
9000&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10 + 0 = (9000+ 9000)v<br />
v =&nbsp;<span class="math-tex">{tex}\\frac{90000}{18000}{/tex}</span>&nbsp;= 5 ms<sup>-1</sup><br />
Total K.E. before collision<br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;m<sub>1</sub>&nbsp;<span class="math-tex">{tex}u_{1}^{2}+\\frac{1}{2}{/tex}</span>&nbsp;m<sub>2</sub>&nbsp;<span class="math-tex">{tex}u_{2}^{2}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\times{/tex}</span>&nbsp;9000&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10 + 0 = 450000 J<br />
Total K.E. after collision =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;(m<sub>1</sub>&nbsp;+ m<sub>2</sub>) v<sup>2</sup><br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9000&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;5<sup>2&nbsp;</sup>= 225000 J.<br />
Thus total K.E. after collision &lt; Total K.E. before the collision.<br />
Hence the collision is inelastic.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>The bob A of a pendulum released from horizontal to the vertical hits another bob B of the same mass at rest on a table as shown in figure.<br/>
If the length of the pendulum is 1m, calculate<br/>
<img alt="" data-imgur-src="PoDNG1n.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/PoDNG1n.png" style="width: 150px; height: 83px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>the height to which bob A will rise after collision.</li>
<li>the speed with which bob B starts moving. Neglect the size of the bobs and assume the collision to be elastic.</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>When a moving bob&nbsp;strike to an identical bob&nbsp;at rest then one bob&nbsp;transfers its&nbsp;momentum to other and itself become at rest.<br />
	When bob&nbsp;A reaches at the position of bob&nbsp;B. The PE of A converts into KE where bob&nbsp;A transfers its momentum to bob&nbsp;B and bob&nbsp;A becomes itself in rest after elastic collision. So there&nbsp;will be no rise in bob A.</li>
	<li>For speed of bob&nbsp;B<br />
	<img id="Picture 24" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-06/image163.png" /><br />
	<span class="math-tex">{tex}P.{E_{{A_1}}} = K.E{._{{A_2}}} = K.{E_{{B_2}}}{/tex}</span><br />
	<span class="math-tex">{tex}\\frac { 1 } { 2 } m v _ { 3 } ^ { 2 } = m g h{/tex}</span><br />
	<span class="math-tex">{tex}v _ { B } = \\sqrt { 2 g \\times 1 }{/tex}</span><span class="math-tex">{tex}= \\sqrt { 2 \\times 9.8 } = \\sqrt { \\frac { 2 } { 10 } \\times 2 \\times 49 }{/tex}</span>
	<p><span class="math-tex">{tex}= { 2 \\times 7 } \\frac { 1 } { \\sqrt { 10 } } = \\frac { 14 \\times \\sqrt { 10 } } { 10 }{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}= 1.4 \\times 3.16{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}v _ { B } = 4.42 \\mathrm { m } / \\mathrm { s }{/tex}</span></p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two identical ball bearings in contact with each other and resting on a frictionless table are hit head-on by another ball bearing of the same mass moving initially with a speed V. If the collision is elastic, which of the following figure is a possible result after collision?</p>

<ol start="1" style="list-style-type:lower-alpha">
	<li><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/BszQaee.png" style="height:64px; width:208px" /></li>
	<li><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/Wo145y8.png" style="height:59px; width:130px" /></li>
	<li><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/9gSeFdQ.png" style="height:67px; width:125px" /></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to the question&nbsp;in each case, it can be observed that the total momentum&nbsp;before and after the collision in each case is constant as external forces are absent and internal forces are conservative in nature.<br />
so initial momentum = final momentum<br />
p<sub>i</sub>&nbsp;= p<sub>f</sub><br />
For an elastic collision, the total kinetic energy of a system remains conserved before and after a collision while for an inelastic collision kinetic energy is not conserved as some energy is lost due to work done by the internal forces.<br />
Given the mass of ball bearings m, we can write:<br />
The total kinetic energy of the system before the collision is given by:<br />
<span class="math-tex">{tex}K.E. = \\frac { 1 } { 2 } m V ^ { 2 } + \\frac { 1 } { 2 } ( 2 m ) 0{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}K.E.= \\frac { 1 } { 2 } m V ^ { 2 }{/tex}</span>&nbsp;<br />
Now,<br />
In Case (a)<br />
The total kinetic energy of the system after the collision is given by:<br />
<span class="math-tex">{tex}K.E.= \\frac { 1 } { 2 } m \\times 0 + \\frac { 1 } { 2 } ( 2 m ) \\left( \\frac { V } { 2 } \\right) ^ { 2 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}K.E.= \\frac { 1 } { 4 } m V ^ { 2 }{/tex}</span>&nbsp;<br />
Hence, in case (a) the kinetic energy of the system is not conserved.<br />
In Case (b)<br />
The total kinetic energy of the system after the collision is given by:<br />
<span class="math-tex">{tex}K.E.= \\frac { 1 } { 2 } ( 2 m ) \\times 0 + \\frac { 1 } { 2 } m V ^ { 2 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}K.E.= \\frac { 1 } { 2 } m V ^ { 2 }{/tex}</span>&nbsp;<br />
Hence, in case (b) the kinetic energy of the system is conserved.<br />
In Case (c)<br />
The total kinetic energy of the system after the collision is given by:<br />
<span class="math-tex">{tex}K.E.= \\frac { 1 } { 2 } ( 3 m ) \\left( \\frac { V } { 3 } \\right) ^ { 2 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}K.E.= \\frac { 1 } { 6 } m V ^ { 2 }{/tex}</span>&nbsp;<br />
Hence, the total kinetic energy&nbsp;of the system is not conserved in case(b) &amp; case(c) in the process of collision.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The turbine pits at the Niagra falls are 50 m deep. The average horsepower developed is 500. If the efficiency of the generator is 85%, how much water passes through the turbines per minute? Take g = 10 ms<sup>-2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Useful power developed = 5000 hp<br />
Efficiency = 85%<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Total power generated<br />
=&nbsp;<span class="math-tex">{tex}\\frac{100}{85} \\times{/tex}</span>&nbsp;5000 hp =&nbsp;<span class="math-tex">{tex}\\frac{100 \\times 5000 \\times 746}{85}{/tex}</span>&nbsp;W<br />
Total work done by the falling water in 1 min or 60 s,<br />
W = Pt =&nbsp;<span class="math-tex">{tex}\\frac{100 \\times 5000 \\times 746}{85} \\times{/tex}</span>&nbsp;60 = 26.94&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>7</sup>&nbsp;J<br />
Now mgh = W<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;m =&nbsp;<span class="math-tex">{tex}\\frac{W}{g h}=\\frac{26.94 \\times 10^{7}}{10 \\times 50}{/tex}</span>&nbsp;= 5.39&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup> kg</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A curved surface is shown in figure. The portion BCD is free of friction. There are three spherical balls of identical radii and masses. Balls are released from rest one by one from A which is at a slightly greater height than C. With the surface AB, ball 1 has large enough friction to cause rolling down without slipping; ball 2 has a small friction and ball 3 has a negligible friction.<br />
<img id="Picture 31" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-06/image234.png" /></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li style="text-align: justify;">For which ball&nbsp;is total mechanical energy conserved?</li>
	<li style="text-align: justify;">Which ball (s) can reach D?</li>
	<li style="text-align: justify;">For balls which do not reach D, which of the balls can reach back A?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Ball (1) is rolling down without slipping, so zero (0) force of friction acts or no loss of energy, hence, the total mechanical energy is conserved.<br />
	Ball 3 has negligible friction hence there is no loss of energy, so total mechanical energy is conserved. Hence, mechanical energy is conserved for ball (1) and (3).</li>
	<li style="text-align: justify;">only ball 3 can reach D</li>
	<li style="text-align: justify;">ball 1 and 2 cannot reach point A.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A massless platform is kept on a light elastic spring. When a sand particle of mass 0.1 kg is dropped on the pan from a height of 0.24 m, the particle strikes the pan, and the spring compresses by 0.01 m. From what height should the particle be dropped to cause a compression of 0.04 m?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Here m = 0.1 kg, h = 0.24 m, x = 0.01 m, h' = ?, x' = 0.04 m<br/>
As the particle is dropped from a height h, it compresses the spring through distance x<br/>
<img alt="" data-imgur-src="fHNhNjj.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082689-swqe3c.jpg" style="width: 100px; height: 177px;"/><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> Total loss in P.E. of the particle = Total gain in P.E. of the spring.<br/>
or mg (h + x) = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> kx<sup>2</sup> ...(i)<br/>
and mg <span class="math-tex">{tex}\\left(h^{\\prime}+x^{\\prime}\\right){/tex}</span> = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}k x^{\\prime 2}{/tex}</span> ...(ii)<br/>
Dividing (ii) by (i), we get<br/>
<span class="math-tex">{tex}\\frac{h^{\\prime}+x^{\\prime}}{h+x}=\\left(\\frac{x^{\\prime}}{x}\\right)^{2}{/tex}</span><br/>
or <span class="math-tex">{tex}\\frac{h^{\\prime}+0.04}{0.24+0.01}=\\left(\\frac{0.04}{0.01}\\right)^{2}{/tex}</span><br/>
On solving , h' = 3.96 m</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A well 20 m deep and 3 m in diameter contains water to a depth of 14 metre. How long will a 5 hp engine take to empty it?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given that<br />
​​​​​​​Radius of the well, R =&nbsp;<span class="math-tex">{tex}\\frac{3}{2}{/tex}</span>&nbsp;m<br />
Area of cross-section of the well<br />
=&nbsp;<span class="math-tex">{tex}\\pi R^{2}=\\frac{22}{7} \\times\\left(\\frac{3}{2}\\right)^{2}=\\frac{99}{14}{/tex}</span>&nbsp;m<sup>2</sup><br />
Volume of the water in the well&nbsp;= Area of the cross-section <span class="math-tex">{tex}\\times{/tex}</span> depth of well&nbsp;<br />
=&nbsp;<span class="math-tex">{tex}\\frac{99}{14} \\times{/tex}</span>&nbsp;14 = 99 m<sup>3</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Mass of water in the well = Volume&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;density = 99&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;kg<br />
As the well is emptied, the height through which water has to be raised by the engine changes from (20 - 14)m in the beginning to (20 - 0) m at the end.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Average height raised =&nbsp;<span class="math-tex">{tex}\\frac{6+20}{2}{/tex}</span>&nbsp;= 13 m<br />
Work required to empty the well,<br />
W = mgh = 99&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;13 = 12612600 J<br />
Power, P = 5 hp = 5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;746 W<br />
Required time, t =&nbsp;<span class="math-tex">{tex}\\frac{W}{P}=\\frac{12612600}{5 \\times 746}{/tex}</span> = 3381.6 s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A large family uses 8 kW of power,</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Direct solar energy is incident on the horizontal surface at an average rate of 200 W per square meter. If 20% of this energy can be converted to useful electrical energy, how large an area is needed to supply 8 kW?</li>
	<li>Compare this area to that of the roof of a house constructed on a plot of size 20 m <span class="math-tex">{tex}\\times{/tex}</span> 15 m with a permission to cover upto 70%</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Let the area needed to supply 8 kW = A m<sup>2</sup><br />
	Energy incident per unit area = 200 W<br />
	Energy incident on area A = 200 <span class="math-tex">{tex}\\times{/tex}</span> A W<br />
	= 20% of 200&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;A = 40 A W<br />
	But 40 A W = 8 kW = 8000 W<br />
	or A =&nbsp;<span class="math-tex">{tex}\\frac{8000}{40}{/tex}</span>&nbsp;= 200 m<sup>2</sup></li>
	<li>Area of the roof of the given house,<br />
	A&#39; = 70% of 20m&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;15m<br />
	=&nbsp;<span class="math-tex">{tex}\\frac{70 \\times 20 \\times 15}{100}{/tex}</span>&nbsp;= 210 m<sup>2</sup><br />
	Required ratio =&nbsp;<span class="math-tex">{tex}\\frac{A}{A^{\\prime}}=\\frac{200}{210}{/tex}</span>&nbsp;= 20 : 21</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A body of mass of 2 kg initially at rest moves under the action of an applied horizontally force of 7 N on a table with coefficient of kinetic friction = 0.1. Compute the</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>work done by the applied force in 10 s,</li>
	<li>work done by friction in 10 s,</li>
	<li>work done by the net force on the body in 10 s,</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here, applied force F = 7 N<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683806458-ws4mzs.jpg" style="width: 190px; height: 101px;" /><br />
and opposing friction force,&nbsp;<span class="math-tex">{tex}f=\\mu_k \\cdot N=\\mu_k \\cdot m g{/tex}</span><br />
= 0.1 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8 = 1.96 N<br />
<span class="math-tex">{tex}\\because{/tex}</span>&nbsp;Net accelerating force = F - f = 7 - 1.96 = 5.04 N<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Acceleration, a =&nbsp;<span class="math-tex">{tex}\\frac{\\text { force }}{\\text { mass }}=\\frac{5.04 \\mathrm{~N}}{2 \\mathrm{~kg}}{/tex}</span>&nbsp;= 2.52 ms<sup>-2</sup></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Distance covered in 10 s (assuming u = 0)<br />
	s = 0 +&nbsp;<span class="math-tex">{tex}\\frac{1}{2} a t^2=\\frac{1}{2} {/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 2.52 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(10)<sup>2</sup> = 126 m<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Work done by the applied force<br />
	W = Fs = 7 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;126 = +882 J</li>
	<li>Work done by friction in 10 s<br />
	W&#39; = f s cos 180<sup>o</sup> = - 1.196 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;126 = - 247 J</li>
	<li>Work done by net force in&nbsp;<br />
	10 s = W - W&#39; = 882 - 247 = +635 J&nbsp;</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A car of mass 1000 kg accelerates uniformly from rest to a velocity of 54 km h<sup>-1</sup> in 5 s. Calculate</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>its acceleration,</li>
	<li>its gain in kinetic energy,</li>
	<li>average power of the engine during this period. Neglect friction.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here m = 1000 kg, u = 0, v = 54 knh<sup>-1</sup>&nbsp;= 15 ms<sup>-1</sup>, t = 5 s</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Acceleration, a =&nbsp;<span class="math-tex">{tex}\\frac{v-u}{t}=\\frac{15-0}{5}{/tex}</span>&nbsp;= 3 ms<sup>-2</sup></li>
	<li>Gain in K.E. =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;m (v<sup>2</sup>&nbsp;- u<sup>2</sup>) =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;1000 (15<sup>2</sup>&nbsp;- 0)<br />
	= 1.125&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup>&nbsp;J</li>
	<li>Power, P =&nbsp;<span class="math-tex">{tex}\\frac{W}{t}=\\frac{1.125 \\times 10^{5}}{5}{/tex}</span> = 22500 W</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A bullet weighing 10&nbsp;g is fired with a velocity of 800 ms<sup>-1</sup>. After passing through a mud wall 1 m thick, its velocity decreases to 100 ms<sup>-1</sup>. Find the average resistance offered by the mud wall.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Mass of bullet, m = 10 g = 0.01 kg<br />
Velocity of bullet before passing through mud wall,<br />
u = 800 ms<sup>-1</sup><br />
Velocity of the bullet after passing through mud wall,<br />
v = 100 ms<sup>-1</sup><br />
Distance covered by the bullet,<br />
s = 1 m<br />
Let average resistance offered by the wall = F<br />
According to work-energy theorem,&nbsp;Work done by the resistance offered by mud wall<br />
= Decreases in K.E.<br />
or Fs =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;m (u<sup>2</sup>&nbsp;- v<sup>2</sup>)<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;F =&nbsp;<span class="math-tex">{tex}\\frac{m\\left(u^{2}-v^{2}\\right)}{2 s}=\\frac{0.01 \\times\\left(800^{2}-100^{2}\\right)}{2 \\times 1}{/tex}</span> = 3150 N.&nbsp;<br />
&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that total mechanical energy of a freely falling body remains constant throughout the fall.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>As per principle of conservation of mechanical energy if there is no dissipation of mechanical energy, then total mechanical energy of a system must remain constant. Of course, potential energy may be converted into kinetic energy or vice versa but sum of the kinetic energy and potential energy of a system must remain unchanged.<br />
<img alt="" data-imgur-src="aEaeGkn.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/aEaeGkn.png" style="width: 100px; height: 141px;" /><br />
Now consider a small sized object of mass m falling from a point A situated at a height h.<br />
<strong>At point A</strong>: Since the object is at rest i.e., u = 0<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>K.E. of object at point A, K<sub>A</sub> = 0<br />
and P.E. of object U<sub>A</sub> = mgh<br />
E<sub>A</sub> = K<sub>A</sub> + U<sub>A</sub> = 0 + mgh = mgh ............................................................................(i)<br />
<strong>At point B</strong>: Let the objects fall freely through a distance y so as to reach B, where its velocity v is given by<br />
<span class="math-tex">{tex}v = \\sqrt { 2 g y }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;KE at point B<br />
<span class="math-tex">{tex}K _ { B } = \\frac { 1 } { 2 } m v ^ { 2 } = \\frac { 1 } { 2 } m \\cdot 2 g y{/tex}</span>= mgy<br />
and PE at point B, U<sub>B</sub>&nbsp;= mg(h - y)<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;E<sub>B</sub>&nbsp;= K<sub>B</sub>&nbsp;+ U<sub>B</sub>&nbsp;= mgy + mg(h - y) = mgh..............................................................(ii)<br />
<strong>At point C:&nbsp;</strong>Let the object just reaches the ground at point C, where its final velocity V is given by :<br />
<span class="math-tex">{tex}V = \\sqrt { 2 g h }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;K.E at point C,&nbsp;<span class="math-tex">{tex}K _ { C } = \\frac { 1 } { 2 } m V ^ { 2 } = \\frac { 1 } { 2 } m \\cdot 2 g h = m g h{/tex}</span><br />
and P.E at point C, U<sub>C</sub>&nbsp;= 0<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;E<sub>C</sub>&nbsp;= K<sub>C</sub> + U<sub>C</sub> = mgh = 0 = mgh<br />
A simple comparison shows that<br />
E<sub>A</sub> = E<sub>B</sub> = E<sub>C</sub> = mgh = a constant<br />
A graph showing variation of K.E., P.E. and total energy of a freely falling body is shown below:<br />
<img alt="" data-imgur-src="5UEY3Hc.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/5UEY3Hc.png" style="width: 200px; height: 126px;" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Prove that in an elastic collision in one dimension the relative velocity of approach before impact is equal to the relative velocity of separation after impact.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img id="Picture 4" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch06/3m/image001.jpg" style="width: 300px; height: 85px;" /><br />
According to the question the collision is elastic in nature<br />
so,= P<sub>f</sub>&nbsp;<span style="font-size: 10.8333px;"> </span>( as per law of conservation of momentum)<br />
<span style="font-size: 10.8333px;">and&nbsp; (K.E)i =&nbsp;(&nbsp;K.E)f</span>( Kinetic Energy remains conserved during elastic collision)<br />
As per conservation of momentum<br />
<span class="math-tex">{tex}m _ { 1 } u _ { 1 } + m _ { 2 } u _ { 2 } = m _ { 1 } v _ { 1 } + m _ { 2 } v _ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}m _ { 1 } \\left( u _ { 1 } - v _ { 1 } \\right) = m _ { 2 } \\left( v _ { 2 } - u _ { 2 } \\right){/tex}</span> ...(i)<br />
K.E. also remains conserved during the elastic collision<br />
<span class="math-tex">{tex}\\frac { 1 } { 2 } m _ { 1 } u _ { 1 } ^ { 2 } + \\frac { 1 } { 2 } m _ { 2 } u _ { 2 } ^ { 2 } = \\frac { 1 } { 2 } m _ { 1 } v _ { 1 } ^ { 2 } + \\frac { 1 } { 2 } m _ { 2 } v _ { 2 } ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex} m _ { 1 } \\left( u _ { 1 } ^ { 2 } - v _ { 1 } ^ { 2 } \\right) = m _ { 2 } \\left( v _ { 2 } ^ { 2 } - u _ { 2 } ^ { 2 } \\right){/tex}</span> ...(ii)<br />
Dividing equation&nbsp; (2) by equation (1), we get&nbsp;<br />
<span class="math-tex">{tex}u _ { 1 } - v _ { 1 } = v _ { 2 } + u _ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}u _ { 1 } - u _ { 2 } = v _ { 2 } - v _ { 1 }{/tex}</span><br />
Relative velocity of approach = Relative velocity of separation.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A body of mass m moving with speed v collides elastically head-on with another body of mass m initially at rest. Show that the moving body will come to a stop as a result of this collision.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>By Principle of conservation of momentum,<br />
m&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;v + m&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;0 = mv<sub>1</sub>&nbsp;+ mv<sub>2</sub><br />
or&nbsp; v - v<sub>1</sub>&nbsp;= v<sub>2</sub>&nbsp;...(1)<br />
By Principle of conservation &nbsp;of kinetic energy,<br />
<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;mv<sup>2</sup>&nbsp;+ 0 =&nbsp;<span class="math-tex">{tex}\\frac{1}{2} m v_{1}^{2}+\\frac{1}{2} m v_{2}^{2}{/tex}</span><br />
or v<sup>2</sup>&nbsp;=&nbsp;<span class="math-tex">{tex}v_{1}^{2}+v_{2}^{2}{/tex}</span><br />
or (v + v<sub>1</sub>) (v - v<sub>1</sub>) =&nbsp;<span class="math-tex">{tex}v_{2}^{2}{/tex}</span>&nbsp;...(2)<br />
Dividing (2) by (1), we get<br />
v + v<sub>1</sub>&nbsp;= v<sub>2</sub> .............(3)<br />
Solving equation (1) and (3),<br />
v<sub>1</sub>&nbsp;= 0 and v<sub>2</sub>&nbsp;= v<br />
As a result of the collision, the moving body comes to a stop and the stationary body begins to move with the speed of the first body.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Prove that when a particle suffers an oblique elastic collision with another particle of equal mass and initially at rest, the two particles would move in mutually perpendicular directions after collisions.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Assume that a particle A of mass m and having velocity u collides with particle B ( which is at rest )&nbsp;of equal mass.&nbsp;Let the collision be oblique elastic collision and after collision the balls A and B move with velocities V<sub>1</sub> and V<sub>2</sub> respectively inclined at an angle&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span> from each other.<br />
<img alt="" data-imgur-src="ss1XSib.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/ss1XSib.png" style="width: 350px; height: 153px;" /><br />
Applying the principle of conservation of linear momentum, we have<br />
mu = mv<sub>1</sub> + mv<sub>2</sub> or u = V<sub>1</sub> + v<sub>2</sub><br />
or&nbsp;u<sup>2 </sup>=(v<sub>1</sub>&nbsp;+ v<sub>2</sub>) . (v<sub>1</sub> + v<sub>2</sub>)<br />
<span class="math-tex">{tex}=v_{1}^{2}+v_{2}^{2}+2 v_{1} v_{2} \\cos \\theta{/tex}</span>&nbsp; &nbsp; ........................................................................(i)<br />
Again as total KE before collision = total KE after collision<br />
<span class="math-tex">{tex}\\therefore \\quad \\frac{1}{2} m u^{2}=\\frac{1}{2} m v_{1}^{2}+\\frac{1}{2} m v_{2}^{2}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\quad u^{2}=v_{1}^{2}+v_{2}^{2}{/tex}</span>&nbsp; &nbsp; &nbsp;.............................................................................(ii)<br />
By comparing Equations&nbsp;(i) and (ii), we obtain</p>

<p>&nbsp; 2v<sub>1</sub>v<sub>2</sub> cos 0 = 0</p>

<p>As in an oblique collision both v<sub>1</sub> and v<sub>2</sub> are finite, hence cos&nbsp;<span class="math-tex">{tex}\\theta=0{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\quad \\theta=\\cos ^{-1}(0)=\\frac{\\pi}{2}{/tex}</span><br />
Thus, the particles A and B are moving in mutually perpendicular directions after the collision.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define elastic potential energy. An elastic spring of force constant k is compressed by an amount x. Show that its potential energy is <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> kx<sup>2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Elastic potential energy is the energy stored by stretching or compressing an elastic object by an external force.<br />
Let the distance be x then F = -kx<br />
Potential energy = work done to get that configuration<br />
So we basically have to calculate the work done by us in compressing the spring by a distance x.<br />
W = Force.Distance<br />
Let us compress the spring by a small distance dx, then small work done in doing so<br />
dW = kx. dx<br />
Total work done will be equal to integrating all the small works dW from x = 0 to x = x<br />
&int;dW = &int;k x.dx = <span class="math-tex">{tex}\\frac{k(x^2)}{2}{/tex}</span> [from x = 0 to x = x]<br />
W = <span class="math-tex">{tex}\\frac{k(x^2)}{2}{/tex}</span><br />
Therefore Potential energy stored in the spring = W = <span class="math-tex">{tex}\\frac{k(x^2)}{2}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A body of mass 0.3 kg is taken up an inclined plane length 10 m and height 5 m and then allowed to slide down the bottom again. The coefficient of friction between the body and the plane is 0.15. What is the</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>work done by gravitational force over the round trip?</li>
	<li>work done by the applied force over the upward journey?</li>
	<li>work done by the frictional force over the round trip?</li>
	<li>kinetic energy of the body at the end of trip? (g = 10 ms<sup>-2</sup>)<br />
	<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704258663-pvwp6p.jpg" style="height:115px; width:175px" /></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Upward journey<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704258663-pvwp6p.jpg" style="height:115px; width:175px" /><br />
Let us calculate work done by different forces over<br />
upward journey.<br />
W<sub>1</sub>&nbsp;= (mg sin<span class="math-tex">{tex}\\theta{/tex}</span>) s cos 180<sup>o</sup><br />
W<sub>1</sub>, =0.3 <span class="math-tex">{tex}\\times{/tex}</span> 10 sin30<sup>o</sup> <span class="math-tex">{tex}\\times{/tex}</span> 10(-1)<br />
W<sub>1 </sub>= -15J<br />
Work done by force of friction =<br />
W<sub>2</sub> = <span class="math-tex">{tex} (\\mu \\;mg\\;\\cos \\,\\,\\theta )s\\,\\cos \\,{180^0} {/tex}</span><br />
W<sub>2</sub> = <span class="math-tex">{tex}0.15 \\times 0.3 \\times 10 \\cos 30^{\\circ} \\times 10[-1]{/tex}</span><br />
W<sub>2</sub> = -3.879 J<br />
Work done by external force<br />
<span class="math-tex">{tex}W_{3}=F_{\\mathrm{ext}} \\times s \\times \\cos 0^{\\circ}{/tex}</span><br />
<span class="math-tex">{tex}W_{3}=[m g \\sin \\theta+\\mu m g \\cos \\theta] \\times 10 \\times 1{/tex}</span><br />
W<sub>3</sub> = 18.897 J<br />
Let us consider the Downward journey<br />
mg sin 30<sup>o</sup> &gt; <span class="math-tex">{tex}\\mu{/tex}</span> mg cos 30<sup>o</sup><br />
Work done by the gravitational force<br />
W<sub>4</sub> = mg sin 30<sup>o</sup> <span class="math-tex">{tex}\\times{/tex}</span> s cos 0<sup>o</sup><br />
<span class="math-tex">{tex}W_{4}=0.3 \\times 10 \\times \\frac{1}{2} \\times 10=+15 J{/tex}</span><br />
Work done by the force of friction is shown below<br />
<span class="math-tex">{tex}W_{5}=\\mu m g \\cos 30^{\\circ} \\times s \\cos 180^{\\circ}{/tex}</span><br />
<span class="math-tex">{tex}=0.15 \\times 0.3 \\times \\frac{10 \\sqrt{3}}{2} \\times 10 \\times(-1){/tex}</span><br />
= -3-897 J</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>Work done by gravitational force over the round trip<br />
	= W<sub>5</sub> + W4 = 0J</li>
	<li>Work done by applied force over upward journey = W<sub>3</sub> = 18.897 J</li>
	<li>Work done by frictional force over the round trip W<sub>2</sub> + W<sub>5</sub> = -3.897 + (-3.897) = -7.794 J</li>
	<li>Kinetic energy of the body at the end of the trip W<sub>4</sub> + W<sub>5 </sub>= 11.103 J</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define the terms Elastic collision and Inelastic collision. What is the difference between an inelastic collision and a completely inelastic collision?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>A collision in which there is absolutely no loss Of kinetic energy is called elastic collision.<br />
Characteristics:</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>The linear momentum is conserved.</li>
	<li>Total energy of the system is conserved.</li>
</ol>

<p>Inelastic collision:<br />
A collision in which there is some loss of kinetic energy is called inelastic collision.<br />
Characteristics:</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>Linear momentum is conserved.</li>
	<li>Total energy is conserved.</li>
</ol>

<p>An inelastic collision is one in which kinetic energy is not conserved. A perfectly inelastic collision (also sometimes called completely or maximally inelastic) is one in which objects stick together after impact, and the maximum amount of kinetic energy is lost.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is the meaning of <strong>Collision</strong> in physics? Differentiate between elastic and inelastic collision. Give one example each.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Collision, in physics, the sudden, forceful coming together in direct contact of two bodies, such as, for example, two billiard balls, a golf club and a ball, a hammer and a nail head, two railroad cars when being coupled together, or a falling object and a floor.</p>

<table border="1" cellpadding="3" cellspacing="0" style="width:100%">
	<tbody>
		<tr>
			<td>Elastic collision</td>
			<td>Inelastic collision</td>
		</tr>
		<tr>
			<td>The total kinetic energy is conserved in elastic collision.</td>
			<td>The total kinetic energy at the beginning and the end of the collision is different in case of inelastic collision.</td>
		</tr>
		<tr>
			<td>No conversion of energy take place.</td>
			<td>Kinetic energy change into other energy such as sound and heat energy.</td>
		</tr>
		<tr>
			<td>Highly unlikely in the real world.</td>
			<td>This is the normal form of collision in real world.</td>
		</tr>
		<tr>
			<td>Eg: When a ball at a billiard table hits another ball.</td>
			<td>Eg: collision of two car.</td>
		</tr>
	</tbody>
</table></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Draw the graph of equation F<sub>s</sub> = -kx, where F<sub>s</sub> is the spring force and x is the displacement of a block from the equilibrium position. Using the graph, show that maximum work done by the spring at x<sub>m</sub> is W<sub>s</sub> = <span class="math-tex">{tex}-\\frac{-k x_{m}^{2}}{2}{/tex}</span> (k = spring constant).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704876353-86jqpg.jpg" style="height:169px; width:234px" /></p>

<ol start="1" style="list-style-type:lower-alpha">
	<li>According to Hooke&#39;s law, the spring force for an extension x is<br />
	F<sub>s</sub> = - kx<br />
	Adjacent graph shows F<sub>s</sub> v/s x graph</li>
	<li>The work done by the spring force for an extension x is<br />
	W<sub>s</sub> = Area of <span class="math-tex">{tex}\\Delta{/tex}</span>OBA = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> AB <span class="math-tex">{tex}\\times{/tex}</span> OB<br />
	<span class="math-tex">{tex}=\\frac{1}{2} F_s \\times x=\\frac{1}{2}(-k x) \\times x=-\\frac{1}{2} k^2{/tex}</span><br />
	Work done bu spring force is equal to negative times change in potential energy so<br />
	W<sub>s</sub> = -[U<sub>f</sub> - U<sub>i</sub>]<br />
	or <span class="math-tex">{tex}-\\frac{1}{2} \\mathrm{kx}^2{/tex}</span> = -[U - 0] or U = <span class="math-tex">{tex}\\frac{1}{2} \\mathrm{kx}^2{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What are conservative forces? Show that gravitational force is a conservative force.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>A conservative force is a force done in moving a particle from one point to another, such that the force is independent of the path taken by the particle. It depends only on the initial and final position of the particle. Gravitational force and elastic spring forces are two such examples of conservation forces.</p>
<p><br/>
Suppose a body of mass m be taken from A to B along different paths as shown in the figure.<br/>
<img alt="" data-imgur-src="mVPrKgL.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1658320515-dan7k9.jpg" style="width: 200px; height: 160px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Work done if body is taken up straight along AB,<br/>
	W<sub>1</sub> = <span class="math-tex">{tex}m \\vec{g} \\cdot \\vec{h}{/tex}</span> = -mgh</li>
<li>Work done by gravity if body is taken up along path ACB,<br/>
	W<sub>2</sub> = W<sub>AC</sub> + W<sub>CB</sub><br/>
	W<sub>AC</sub> = <span class="math-tex">{tex}m \\vec{g} \\cdot \\vec{A C}{/tex}</span> = -mg (AC) cos (90 - <span class="math-tex">{tex}\\theta{/tex}</span>)<br/>
	= -mg AC sin <span class="math-tex">{tex}\\theta{/tex}</span> = -mg (AB) = -mgh<br/>
	W<sub>BC</sub> = <span class="math-tex">{tex}m \\vec{g} \\cdot \\vec{C B}{/tex}</span><br/>
	= -mg (CB) cos (90) = 0<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> W<sub>2</sub> = -mgh</li>
<li>Work done by gravity along the path ADEFGHB is,<br/>
	W<sub>3</sub> = W<sub>AD</sub> + W<sub>DE</sub> + W<sub>EF</sub> + W<sub>FG</sub> + W<sub>GH</sub> + W<sub>HB</sub><br/>
	Here the displacements <span class="math-tex">{tex}\\vec{D E}, \\vec{F G}{/tex}</span> and <span class="math-tex">{tex}\\vec{J B}{/tex}</span> are perpendicular to gravity, therefore<br/>
	W<sub>DE</sub> = W<sub>FG</sub> = W<sub>HB</sub> = 0<br/>
	and W<sub>AD</sub> = <span class="math-tex">{tex}(m \\vec{g}) \\cdot \\vec{A D}{/tex}</span> = -mg(AD)<br/>
	W<sub>EF</sub> = <span class="math-tex">{tex}(m \\vec{g}) \\cdot \\vec{E F}{/tex}</span> = -mg(EF)<br/>
	W<sub>GH</sub> = <span class="math-tex">{tex}(m \\vec{g}) \\cdot \\vec{G H}{/tex}</span> = -mg(GH)<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> W<sub>3</sub> = -mg (AD + EF + GH) = -mgh<br/>
	Since W<sub>1</sub> = W<sub>2</sub> = W<sub>3</sub><br/>
	Therefore gravitational force is conservative.</li>
</ol></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define elastic collision. Two bodies of masses m<sub>1</sub> and m<sub>2</sub> moving with velocities u<sub>1</sub> and u<sub>2 </sub>undergo one- dimensional elastic collision. Determine their velocities after the collision.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Elastic collision: The collisions in which both momentum and kinetic energy of the system are conserved are called elastic collisions.<br />
Two bodies of masses m<sub>1</sub> and m<sub>2 </sub>moving with velocities u<sub>1</sub> and u<sub>2 </sub>undergo one- dimensional elastic collision there velocities after collision is<br />
Let (m<sub>1</sub>, m<sub>2</sub>), (u<sub>1</sub>, u<sub>2</sub>), and (v<sub>1</sub>, v<sub>2</sub>) be the masses, initial velocities and final velocities of the two colliding particles, respectively.<br />
Therefore, m<sub>1</sub>u<sub>1</sub> + m<sub>2</sub>u<sub>2</sub> = m<sub>1</sub>v<sub>1</sub> + m<sub>2</sub>v<sub>2</sub><br />
Kinetic energy is conserved,<br />
<span class="math-tex">{tex}\\frac{1 }{2} {/tex}</span>m<sub>1</sub>u<sub>1</sub><sup>2</sup> + <span class="math-tex">{tex}\\frac{1 }{2} {/tex}</span>m<sub>2</sub>u<sub>2</sub><sup>2</sup> = <span class="math-tex">{tex}\\frac{1 }{2} {/tex}</span>m<sub>1</sub>v<sub>1</sub><sup>2</sup> + <span class="math-tex">{tex}\\frac{1 }{2} {/tex}</span>m<sub>2</sub>v<sub>2</sub><sup>2</sup><br />
m<sub>1</sub>u<sub>1</sub><sup>2 </sup>+ m<sub>2</sub>u<sub>2</sub><sup>2 </sup>= m<sub>1</sub>v<sub>1</sub><sup>2 </sup>+ m<sub>2</sub>v<sub>2</sub><sup>2</sup> (Factoring out <span class="math-tex">{tex}\\frac{1 }{2} {/tex}</span>)<br />
Rearranging it we get: m<sub>1</sub>u<sub>1</sub><sup>2</sup> - m<sub>1</sub>v<sub>1</sub><sup>2</sup> = m<sub>2</sub>v<sub>2</sub><sup>2</sup> - m<sub>2</sub>u<sub>2</sub><sup>2</sup><br />
Therefore, m<sub>1</sub>(u<sub>1</sub><sup>2</sup> - v<sub>1</sub><sup>2</sup>) = m<sub>2</sub>(v<sub>2</sub><sup>2 </sup>- u<sub>2</sub><sup>2</sup>)<br />
m<sub>1</sub>(u<sub>1</sub> + v<sub>1</sub>)(u<sub>1</sub> - v<sub>1</sub>) = m<sub>2</sub>(v<sub>2</sub> + u<sub>2</sub>)(v<sub>2 </sub>- u<sub>2</sub>)<br />
By conservation of momentum equation,<br />
m<sub>1</sub>u<sub>1</sub> + m<sub>2</sub>u<sub>2</sub> = m<sub>1</sub>v<sub>1</sub> + m<sub>2</sub>v<sub>2</sub><br />
m<sub>1</sub>u<sub>1</sub> - m<sub>1</sub>v<sub>1</sub> = m<sub>2</sub>v<sub>2</sub> - m<sub>2</sub>u<sub>2</sub><br />
m<sub>1</sub>(u<sub>1 </sub>- v<sub>1</sub>) = m<sub>2</sub>(v<sub>2</sub> - u<sub>2</sub>)<br />
Divide two equations:<br />
m<sub>1</sub>(u<sub>1 </sub>+ v<sub>1</sub>)(v<sub>2</sub> - u<sub>2</sub>) = <span class="math-tex">{tex}\\frac{m_2\\left(v_2+u_2\\right)\\left(v_2-u_2\\right) }{ m_1\\left(u_1-v_1\\right)}=m_2\\left(v_2-u_2\\right){/tex}</span><br />
We get, u<sub>1</sub> + v<sub>1</sub> = v<sub>2</sub> + u<sub>2</sub><br />
Now, v<sub>1</sub> = v<sub>2</sub> + u<sub>2</sub> - u<sub>1</sub><br />
By using this value of v<sub>1</sub> in equation of conservation momentum we get:<br />
<span class="math-tex">{tex}v_2=\\frac{\\left[(2 m_1 u_1+u_2\\left(m_2-m_1\\right)\\right] }{\\left(m_1+m_2\\right)}{/tex}</span><br />
Now using the value of v<sub>2</sub> in equation v<sub>1</sub> = v<sub>2</sub> + u<sub>2</sub> - u<sub>1</sub><br />
v<sub>1</sub> = <span class="math-tex">{tex}\\frac{\\left.[2 m_1 u_1+u_2\\left(m_2-m_1 \\right)\\right] }{\\left(m_1+m_2\\right)+u_2-u_1}{/tex}</span><br />
v<sub>1</sub> = <span class="math-tex">{tex}\\frac{\\left[2 m_1 u_1+u_2\\left(m_2-m_1\\right)+u_2\\left(m_1+m_2\\right)-u_1\\left(m_1+m_2\\right)\\right] }{\\left(m_1+m_2\\right)}{/tex}</span><br />
We finally get:<br />
<span class="math-tex">{tex}v_1=\\frac{\\left[2 m_2 u_2+u_1\\left(m_2-m_1\\right)\\right] }{\\left(m_1+m_2\\right)}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A body of mass 0.3 kg is taken up an inclined plane to length 10 m and height 5 m, and then allowed to slide down to the bottom again. The coefficient of friction between the body and the plane is 0.15. What is the</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>work done by the gravitational force over the round trip,</li>
	<li>work done by the applied force over the upward journey,</li>
	<li>work done by frictional force over the round trip,</li>
	<li>kinetic energy of the body at the end of the trip?</li>
</ol>

<p>How is the answer to (iv) related to the first three answers?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>given that<br/>
​​​​​​​ mass of the body m = 0.3 kg, l =10 m, h = 5 m,  = 0.15<br/>
sin <span class="math-tex">{tex}\\theta=\\frac{h}{l}=\\frac{5}{10}=\\frac{1}{2}{/tex}</span> = 0.5<br/>
<span class="math-tex">{tex}\\therefore\\theta{/tex}</span> = 30<sup>o</sup><br/>
<img alt="" data-imgur-src="w9SxkQ0.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1658320520-fcqh7p.jpg" style="width: 200px; height: 134px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Work done  in moving the body up the inclined plane, by the gravitational force,<br/>
	W = Fs = -mg sin <span class="math-tex">{tex}\\theta \\times{/tex}</span> l<br/>
	= -0.3 <span class="math-tex">{tex}\\times{/tex}</span> 9.8 <span class="math-tex">{tex}\\times{/tex}</span> 0.5 <span class="math-tex">{tex}\\times{/tex}</span> 10 = -14.7 J<br/>
	Work done in moving the body down the inclined plane by the gravitational force ,<br/>
	W' = Fs = +mg sin <span class="math-tex">{tex}\\theta \\times{/tex}</span> l = +14.7 J<br/>
	Work done by the gravitational force over the round trip,<br/>
	W<sub>1</sub> = W + W' = -14.7 + 14.7 = 0<br/>
	his is in similarity with the way that the work done by a  conservative force (e.g., gravitational force) over one round trip is zero.</li>
<li>Force needed to move the body up the inclined plane,<br/>
	F = mg sin <span class="math-tex">{tex}\\theta{/tex}</span> + f<sub>k</sub> = mg sin <span class="math-tex">{tex}\\theta+\\mu_{k}{/tex}</span> R<br/>
	= mg sin <span class="math-tex">{tex}\\theta+\\mu_{k}{/tex}</span> mg cos <span class="math-tex">{tex}\\theta{/tex}</span><br/>
	= mg (sin <span class="math-tex">{tex}\\theta+\\mu_{k}{/tex}</span> cos <span class="math-tex">{tex}\\theta{/tex}</span>)<br/>
	Work done by the applied force over the upward journey,<br/>
	W<sub>2</sub> = F <span class="math-tex">{tex}\\times{/tex}</span> l = mg (sin <span class="math-tex">{tex}\\theta+\\mu_{k}{/tex}</span> cos <span class="math-tex">{tex}\\theta{/tex}</span>) l<br/>
	= 0.3 <span class="math-tex">{tex}\\times{/tex}</span> 9.8 (0.5 + 0.15 <span class="math-tex">{tex}\\times{/tex}</span> 0.866) <span class="math-tex">{tex}\\times{/tex}</span> 10 = 18.5 J</li>
<li>Work done by the frictional force over the round trip,<br/>
	W<sub>3</sub> = -f<sub>k</sub> (l + l) = -2 f<sub>k</sub> <span class="math-tex">{tex}\\times{/tex}</span> l<br/>
	= <span class="math-tex">{tex}-2 \\mu_{k}{/tex}</span> mg cos <span class="math-tex">{tex}\\theta \\times l{/tex}</span><br/>
	= -2 <span class="math-tex">{tex}\\times{/tex}</span> 0.15 <span class="math-tex">{tex}\\times{/tex}</span> 0.3 <span class="math-tex">{tex}\\times{/tex}</span> 9.8 <span class="math-tex">{tex}\\times{/tex}</span> cos 30<sup>o</sup> <span class="math-tex">{tex}\\times{/tex}</span> 10 = -7.6 J</li>
<li>Kinetic energy of the body at the end of round trip<br/>
	= Work done by the net force in moving the body down the inclined plane<br/>
	= (mg sin <span class="math-tex">{tex}\\theta-\\mu_{k}{/tex}</span> mg cos <span class="math-tex">{tex}\\theta{/tex}</span>) <span class="math-tex">{tex}\\times{/tex}</span> l<br/>
	= mg (sin <span class="math-tex">{tex}\\theta-\\mu_{k}{/tex}</span> cos <span class="math-tex">{tex}\\theta{/tex}</span>) l<br/>
	= 0.3 <span class="math-tex">{tex}\\times{/tex}</span> 9.8 <span class="math-tex">{tex}\\times{/tex}</span> (0.5 - 0.13) <span class="math-tex">{tex}\\times{/tex}</span> 10 = 10.9 J<br/>
	From answers to (i), (ii) and (iii), net work done on the body<br/>
	= 0 + 18.5 - 7.6 = 10.9 J = K.E. of the body<br/>
	Thus kinetic energy of the body is equal to the net work done on the body.</li>
</ol></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A rain drop of radius 2 mm falls from a height of 500 m above the ground. It falls with decreasing acceleration (due to viscous resistance of the air) until at half its original height, it attains its maximum (terminal) speed, and moves with uniform speed thereafter. What is the work done by the gravitational force on the drop in the first and second half of its journey? What is the work done by the resistive force in the entire journey if its speed on reaching the ground is 10 ms<sup>-1</sup>?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to Work energy theorem,&nbsp;the net work done on a body is equal to change in kinetic energy of the body. This is known as Work Energy Theorem.<br />
Work done by all the forces = Change in Kinetic Energy<br />
W<sub>g</sub>&nbsp;+ W<sub>N</sub>&nbsp;+ W<sub>f</sub>&nbsp; =K<sub>f</sub>&nbsp;&ndash; K<sub>i</sub><br />
Where, W<sub>g</sub>&nbsp;= work done by gravity<br />
W<sub>N</sub>&nbsp;= work done by normal force<br />
W<sub>f</sub>&nbsp;= work done by friction<br />
K<sub>f</sub>&nbsp;= final kinetic energy<br />
K<sub>i</sub>&nbsp;= initial kinetic energy<br />
Data Given -<br />
Radius of the rain drop, r = 2 mm = <span class="math-tex">{tex}2 \\times 10 ^ { - 3 }{/tex}</span>m<br />
Volume of the rain drop, <span class="math-tex">{tex}V = \\frac { 4 } { 3 } \\pi r ^ { 3 }{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{4}{3} \\times{/tex}</span>&nbsp;3.14&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>)<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;kg<br />
Density of water, <span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;= 10<sup>3</sup>kg m<sup>-3</sup><br />
Mass of the rain drop, m = <span class="math-tex">{tex}\\rho{/tex}</span>V<br />
<span class="math-tex">{tex}=\\frac{4}{3} \\times{/tex}</span>&nbsp;3.14&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>)<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;kg<br />
Gravitational force, F = mg<br />
<span class="math-tex">{tex}=\\frac{4}{3} \\times{/tex}</span>&nbsp;3.14&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>)<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8 N<br />
The work done by the gravitational force on the drop in the first half of its journey:<br />
W<sub>1</sub> = Fs<br />
<span class="math-tex">{tex}=\\frac{4}{3} \\times{/tex}</span>&nbsp;3.14&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>)<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;250<br />
= 0.082 J<br />
This amount of work is equal to the work done by the gravitational force on the drop in the second half of its journey, i.e., W<sub>II</sub>, = 0.082 J<br />
As per the law of conservation of energy, if no resistive force is present, then the total energy of the rain drop will remain the same.<br />
&there4;Total energy at the top:<br />
E<sub>T</sub> = mgh + 0<br />
<span class="math-tex">{tex}=\\frac{4}{3} \\times{/tex}</span>&nbsp;3.14&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>)<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;500&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-5</sup>&nbsp;<br />
= 0.164 J<br />
Due to the presence of a resistive force, the drop hits the ground with a velocity of 10 m/s.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> Total energy at the ground:<br />
E<sub>0</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;mv<sup>2</sup>&nbsp;+ 0<br />
<span class="math-tex">{tex}=\\frac{1}{2} \\times \\frac{4}{3} \\times{/tex}</span>&nbsp;3.14&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>)<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(10)<sup>2</sup><br />
= 1.675&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;J<br />
&nbsp;Work done by the Resistive force = E<sub>G</sub> - E<sub>T</sub> = - 0.162 J<br />
here negative work done shows that energy was dissipated during the process and 0.162 Joule energy was lost during journey of the droplet.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>A bob of mass m is suspended by a light string of length L. It is imparted a horizontal velocity v<sub>0</sub> at the lowest point A such that it completes a semi-circular trajectory in the vertical plane with the string becoming slack only on reaching the topmost point, C. This is shown in the figure. Obtain an expression for<br/>
<img alt="" data-imgur-src="MAOCzYu.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1613450434-vt22aj.jpg" style="width: 157px; height: 166px;"/></p>
<ol start="1" style="list-style-type: lower-alpha;">
<li>v<sub>o</sub></li>
<li>the speeds at points B and C</li>
<li>the ratio of the kinetic energies (K<sub>B</sub>/K<sub>C</sub>) at B and C. Comment on the nature of the trajectory of the bob after it reaches the point C.</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>There are two external forces on the bob: gravity and the tension (T) in the string. The latter does no work since the displacement of the bob is always normal to the string. The potential energy of the bob is thus associated with the gravitational force only. The total mechanical energy E of the system is conserved. We take the potential energy of the system to be zero at the lowest point A. Thus, at A :<br />
	<span class="math-tex">{tex}E=\\frac{1}{2} m v_{0}^{2}{/tex}</span>&nbsp;.... (i)<br />
	<span class="math-tex">{tex}T_{A}-m g=\\frac{m v_{0}^{2}}{L}{/tex}</span>&nbsp;[Newton&#39;s Second Law]<br />
	where T<sub>A</sub> is the tension in the string at A. At the highest point C, the string slackens, as the tension in the string (T<sub>C</sub>) becomes zero.<br />
	Thus, at C<br />
	<span class="math-tex">{tex}E=\\frac{1}{2} m v_{c}^{2}+2 m g L{/tex}</span>&nbsp;.... (ii)<br />
	<span class="math-tex">{tex}m g=\\frac{m v_{c}^{2}}{L}{/tex}</span>&nbsp;[Newton&#39;s Second Law] .... (iii)<br />
	where vc is the speed at C. From eqs. (ii) and (iii)<br />
	<span class="math-tex">{tex}E=\\frac{5}{2} m g L{/tex}</span><br />
	Equating this to the energy at A<br />
	<span class="math-tex">{tex}\\frac{5}{2} m g L=\\frac{m}{2} v_{o}^{2}{/tex}</span><br />
	or,&nbsp;<span class="math-tex">{tex}v_{0}=\\sqrt{5 g L}{/tex}</span></li>
	<li>It is clear from eq. (ii)<br />
	<span class="math-tex">{tex}v_{C}=\\sqrt{g L}{/tex}</span><br />
	At B, the energy is<br />
	<span class="math-tex">{tex}E=\\frac{1}{2} m v_{B}^{2}+m g L{/tex}</span><br />
	Equating this to the energy at A and employing the result from (i), namely&nbsp;<span class="math-tex">{tex}v_{o}^{2}=5 g L{/tex}</span><br />
	<span class="math-tex">{tex}\\frac{1}{2} m w_{B}^{2}+m g L=\\frac{1}{2} m v_{0}^{2}{/tex}</span><br />
	<span class="math-tex">{tex}=\\frac{5}{2} m g L{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore v_{B}=\\sqrt{3 g L}{/tex}</span></li>
	<li>The ratio of the kinetic energies at B and C is:<br />
	<span class="math-tex">{tex}\\frac{K_{B}}{K_{C}}=\\frac{\\frac{1}{2} m v_{B}^{2}}{\\frac{1}{2} m v_{C}^{2}}=\\frac{3}{1}{/tex}</span></li>
</ol>

<p>At point C, the string becomes slack and the velocity of the bob is horizontal and to the left. If the connecting string is cut at this instant, the bob will execute a projectile motion with horizontal projection akin to a rock kicked horizontally from the edge of a cliff. Otherwise, the bob will continue on its circular path and complete the revolution.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State work-energy theorem. Prove it for a variable force.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Work energy theorem-<br />
It states that the work done by the net force acting on a body is equal to the changed produced in kinetic energy of the body.<br />
Let F be the variable force<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> Work done by this variable force, W <span class="math-tex">{tex}=\\int\\limits_{x_f}^{x_f} F \\cdot d x{/tex}</span><br />
where x<sub>i</sub> is the initial position and x<sub>f</sub> is final position.<br />
Also Kinetic energy of an object, K = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>mv<sup>2</sup><br />
<span class="math-tex">{tex}\\Rightarrow \\frac{\\mathrm{dK}}{\\mathrm{dt}}=\\mathrm{mv} \\frac{\\mathrm{dv}}{\\mathrm{dt}}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex}\\frac{\\mathrm{dK}}{\\mathrm{dt}}=\\mathrm{ma} \\frac{\\mathrm{dx}}{\\mathrm{dt}}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex}\\frac{\\mathrm{dK}_{\\mathrm{F}}}{\\mathrm{dt}} \\frac{\\mathrm{dx}}{\\mathrm{dt}}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> dK = Fdx<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex}\\int\\limits_{\\mathrm{K}_{\\mathrm{i}}}^{\\mathrm{K}_{\\mathrm{f}}} \\mathrm{dK}=\\int\\limits_{\\mathrm{x}_{\\mathrm{i}}}^{\\mathrm{x}_{\\mathrm{f}}} \\mathrm{F} \\cdot \\mathrm{dx}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex}\\Delta{/tex}</span>K = W<br />
Where <span class="math-tex">{tex}\\Delta{/tex}</span>is the change in kinetic energy.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1346-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_SYSTEM_OF_PARTICLES_AND_ROTATIONAL_MOTION = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>For which of the following does the centre of mass lie outside the body ?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">A pencil</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">A shotput</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">A dice</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">A bangle</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As centre of mass of bangle is in centre of its body which is outside the body of bangle.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>For n particles in a space, the suitable expression for the x-coordinate of the centre of mass of the system is<br />
Here, M is the total mass of the system.</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\sum m_i x_i}{m_i}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\Sigma m_i x_i}{M}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>For system of n- particles in space, the centre of mass of such a system is at (X, Y, Z), where<br />
<span class="math-tex">{tex}X=\\frac{\\sum m_i x_i}{M},{/tex}</span>&nbsp;<span class="math-tex">{tex} Y=\\frac{\\sum m_i y_i}{M}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}Z=\\frac{\\sum m_i z_i}{M}{/tex}</span><br />
Here, M = <span class="math-tex">{tex}\\sum m_i{/tex}</span><span style="font-size: 10.8333px;">&nbsp;</span>is the total mass of the system. The index i runs from 1 to n.<br />
m<sub>i</sub> <span class="math-tex">{tex}\\rightarrow{/tex}</span> Mass of the ith particle and position of i<sup>th</sup> particle is (x<sub>i</sub>, y<sub>i</sub>, z<sub>i</sub>).</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\Sigma m_i y_i}{M}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\Sigma m_i z_i}{M}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The centre of mass of a system of particles does not depend on</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">forces acting on the particles</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The centre of mass of a system of particles does not depend on the forces acting on the particles.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">position of the particles</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">relative distance between the particles</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">masses of the particles</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Three identical metal balls, each of the radius r are placed touching each other on a horizontal surface such that an equilateral triangle is formed when centres of three balls are joined. The centre of the mass of the system is located at</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">point of intersection of the medians</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The centre of mass of the system lies at the point of intersection of the medians i.e., at the centroid of the equilateral triangle.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">line joining centres of any two balls</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">centre of one of the balls</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">horizontal surface</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two bodies, A and B initially, at rest, move towards each other under mutual force of attraction. At the instant when the speed of A is v and that of B is 2v, the speed of the centre of mass of the bodies is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As there is no external force and the two bodies move due to mutual force of attraction, so v<sub>CM&nbsp;</sub>= 0.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">3v</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">2v</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">1.5v</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which is a vector quantity?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">Angular momentum</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Of the given quantities, only angular momentum is a vector quantity.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Work</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Potential energy</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Electric current</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Let r<sub>i</sub> be the position vector of the i<sup>th</sup> particle having mass m<sub>i</sub> and R be the position vector of the centre of mass. The formula for R is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}R=\\frac{\\sum m_1 \\cdot r_i}{\\sum m_1}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Let us consider a system consisting of&nbsp; N &ndash; particles of masses m<sub>1</sub>, m<sub>2</sub>,&hellip;.. &nbsp;m<sub>N</sub>&nbsp; having position vectors&nbsp;<span class="math-tex">{tex}{\\vec r_1},{\\vec r_2}{/tex}</span>,......&nbsp;<span class="math-tex">{tex} {\\vec r_N} {/tex}</span>&nbsp;respectively.<br />
<span style="font-size:10.0pt">The total mass M&nbsp; of the system is given by </span><br />
M = m&shy;<sub>1</sub> +m<sub>2</sub> +&hellip;&hellip;.+ m<sub>N</sub><span style="font-size:10.0pt"> </span><br />
We can generalize the definition of the position of centre of mass consisting of N particles, hence the position vector of centre of mass is given below:-<br />
<span style="font-size: 11.1111px;"><span style="font-size: 11.1111px;"><span class="math-tex">{tex}\\vec{R}=\\frac{m_1 \\vec{r}_1+m_2 \\vec{r}_2+\\ldots \\ldots \\ldots+m_N \\vec{r}_N}{m_1+m_2+\\ldots \\ldots+m_N}=\\frac{\\sum_\\limits{i=1}^N m_i \\vec{r}_i}{\\sum_\\limits{i=1}^N m_i}=\\frac{\\sum_\\limits{i=1}^N m_i \\vec{r}_i}{M}{/tex}</span></span></span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathbf{R}=\\frac{\\sum^{m_1} \\mathbf{r}_{\\mathbf{i}}}{\\sum^{m_2}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathbf{R}=\\frac{\\sum^{m_1} \\mathbf{r}_{\\mathbf{i}}}{\\sum^{m_3}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\mathbf{R}=\\frac{\\sum^{m_1} \\mathbf{r}_{\\mathbf{i}}}{\\sum^{m_1}}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A projectile is fired at an angle and it was following a parabolic path. Suddenly, it explodes into fragments. Choose the correct option regarding this situation.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683871819-cpfv8y.jpg" style="height:122px; width:250px" /></p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Due to explosion CM shifts upwards</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Due to explosion CM shifts downwards</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">Due to explosion CM traces its path back to origin</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Due to explosion CM traces its path back to origin</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Due to explosion CM traces its path away from the origin</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If <span class="math-tex">{tex}\\vec{F}{/tex}</span> is force and <span class="math-tex">{tex}\\vec{r}{/tex}</span> is the radius vector, then torque is given by</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{r} \\times \\vec{F}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\vec{\\tau}=\\vec{r} \\times \\vec{F}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{r} \\cdot \\vec{F}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}|\\vec{r}||\\vec{F}|{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec{r} + \\vec{F}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The reduced mass of two particles having masses m and 2m is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{{2m}}{3}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Reduced mass<br />
<span class="math-tex">{tex}=\\frac{m \\times 2 m}{m+2 m}=\\frac{2 m}{3}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">2m</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">3m</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{m}{2}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The radius of gyration of a solid disc about one of its diameter is given by:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{R}{2}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Moment of inertia of an axis passing through its center and perpendicular to its plane:<br />
I = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> MR<sup>2</sup><br />
Using perpendicular axis theorem &nbsp; Ix +Iy = Iz, so &nbsp;2I<sub>d</sub> = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> MR<sup>2</sup><br />
Moment of inertia of along its diameter &nbsp;I<sub>d</sub> =&nbsp;<span class="math-tex">{tex}\\frac{1}{4}{/tex}</span>MR<sup>2</sup><br />
And the radius of gyration&nbsp;MK<sup>2 &nbsp;</sup>=&nbsp;<span class="math-tex">{tex}\\frac{1}{4}{/tex}</span>MR<sup>2 &nbsp;&nbsp;<br />
K =&nbsp;<span class="math-tex">{tex}\\frac{R}{2}{/tex}</span></sup></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt {2} {/tex}</span>R</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">2R</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{R}{{\\sqrt 2 }}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The angular momentum of a system of particles is conserved</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">when no external torque acts upon the system</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Angular momentum of a system is conserved only when no external torque acts on it.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">when no external force acts upon the system</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">when no external impulse acts upon the system</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">when axis of rotation remains same</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A ladder is leaned against a smooth wall and it is allowed to slip on a frictionless floor. Which figure represents trace of its centre of mass?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="3JJ8OMt.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1657625468-8fztxa.jpg"/></p></body></html></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The centre of mass remains at the centre of the ladder. Hence Fig. (a) represents the correct trace of CM.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="iTCtVC4.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1657625470-f75aq7.jpg"/></p></body></html></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="GqnEU9h.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1657625471-83w3et.jpg" style="width: 103px; height: 98px;"/></p></body></html></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="Jh0O9uk.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1657625473-s3qspw.jpg"/></p></body></html></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The density of a non-uniform rod of length 1m is given by <span class="math-tex">{tex}\\rho{/tex}</span>(x) = a(1 + bx<sup>2</sup>) where a and b are constants and 0&nbsp;<span class="math-tex">{tex}\\leq{/tex}</span>&nbsp;x&nbsp;<span class="math-tex">{tex}\\leq{/tex}</span>&nbsp;1. The centre of mass of the rod will be at</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{3(2+b)}{4(3+b)}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Given: p(x) = a(1 + bx<sup>2</sup>)<br />
<span class="math-tex">{tex}\\frac{\\text { mass }}{\\text { length }}{/tex}</span>&nbsp;= density of rod<br />
dm = p(x) dx<br />
= a(1 + bx<sup>2</sup>) dx<br />
As we know that<br />
Centre of mass =&nbsp;<span class="math-tex">{tex}\\frac{\\int \\mathrm{xdm}}{\\int \\mathrm{dm}}=\\frac{\\int \\operatorname{ax}\\left(1+\\mathrm{x}^{2}\\right) \\mathrm{d} \\mathrm{x}}{\\int \\mathrm{a}\\left(1+\\mathrm{x}^{2}\\right) \\mathrm{d} \\mathrm{x}}{/tex}</span><br />
=<span class="math-tex">{tex}\\frac{\\frac{a}{2}+\\frac{a b}{4}}{a+\\frac{a b}{3}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{3(2+b)}{4(3+b)}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{4(2+b)}{3(3+b)}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{3(3+b)}{4(2+b)}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{4(3+b)}{3(2+b)}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which one is a vector quantity?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">Torque</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Torque is a vector while energy is a scalar.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Energy</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Both of torque and energy</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Work</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Give the location of the centre of mass of a</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>sphere,</li>
	<li>cylinder,</li>
	<li>ring, and</li>
	<li>cube, each of uniform mass density.</li>
</ol>

<p>Does the centre of mass of a body necessarily lie inside the body?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The centre&nbsp;of mass (C.M.) is a point where the mass of the whole body is supposed to be concentrated. For the given geometric shapes having a uniform mass density, the C.M. lies at their respective geometric centers.</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>geometrical centre</li>
	<li>the midpoint of its axis of symmetry</li>
	<li>geometrical centre</li>
	<li>at the point of intersection of its diagonals</li>
</ol>

<p>The centre&nbsp;of mass of a body need not necessarily lie within it. For example, the Center of the mass&nbsp;of bodies such as a ring, a hollow sphere, etc., lies outside the body.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Three particles of masses 0.50 kg, 1.0 kg and 1.5 kg are placed at the comers of a right angle triangle, as shown in Fig. Locate the centre of mass of the system.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704792623-vancqh.jpg" style="height:167px; width:231px" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let us take the 4.0 cm line as the x-axis and the 3.0 cm line as the Y-axis. The coordinates of the three particles are as follows:</p>

<table border="1" cellpadding="3" cellspacing="0" style="width:100%">
	<thead>
		<tr>
			<th scope="col">m</th>
			<th scope="col">x</th>
			<th scope="col">y</th>
		</tr>
	</thead>
	<tbody>
		<tr>
			<td style="text-align:center">0.5 kg</td>
			<td style="text-align:center">0</td>
			<td style="text-align:center">0</td>
		</tr>
		<tr>
			<td style="text-align:center">1.0 kg</td>
			<td style="text-align:center">4.0 cm</td>
			<td style="text-align:center">0</td>
		</tr>
		<tr>
			<td style="text-align:center">1.5 kg</td>
			<td style="text-align:center">0</td>
			<td style="text-align:center">3.0</td>
		</tr>
	</tbody>
</table>

<p>The x-coordinate of the centre of mass is<br />
<span class="math-tex">{tex}x=\\frac{m_1 x_1+m_2 x_2+m_3 x_3}{m_1+m_2+m_3}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{(0.50 \\mathrm{~kg}) \\cdot 0+(1.0 \\mathrm{~kg}) \\cdot(4.0 \\mathrm{~cm})+(1.5 \\mathrm{~kg}) \\cdot 0}{0.50 \\mathrm{~kg}+1.0 \\mathrm{~kg}+1.5 \\mathrm{~kg}}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{4 \\mathrm{~kg} \\cdot \\mathrm{cm}}{3 \\mathrm{~kg}}=1.3 \\mathrm{~cm}{/tex}</span><br />
They y-coordinate of the centre of mass is<br />
<span class="math-tex">{tex}y=\\frac{m_1 y_1+m_2+m_3 y_3}{m_1+m_2+m_3}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{(0.50 \\mathrm{~kg}) .0+(1.0 \\mathrm{~kg}) .0+(1.5 \\mathrm{~kg})(3.0 \\mathrm{~cm})}{0.50 \\mathrm{~kg}+1.0 \\mathrm{~kg}+1.5 \\mathrm{~kg}}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{4.5 \\mathrm{~kg} \\cdot \\mathrm{cm}}{3 \\mathrm{~kg}}=1.5 \\mathrm{~cm}{/tex}</span><br />
Thus, the centre of mass is 1.3 cm right and 1.5 cm above the 0.5 kg particle.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Establish a relation between torque and angular momentum for a system of particles.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>For a system of n particles, the total angular momentum is given by<br />
<span class="math-tex">{tex}\\vec{L}=\\vec{l}_{1}+\\vec{l}_{2}+\\ldots \\ldots \\ldots+\\vec{l}_{n}{/tex}</span>=&nbsp;<span class="math-tex">{tex}\\sum_{i=1}^{n} \\vec{l}_{i}{/tex}</span>, where&nbsp;<span class="math-tex">{tex}\\overrightarrow{l_{i}}=\\overrightarrow{r_{i}} \\times \\overrightarrow{p_{i}}{/tex}</span><br />
<span class="math-tex">{tex}\\vec{L}=\\sum_{i=1}^{n} \\overrightarrow{l_{i}}=\\sum_{i=1}^{n} \\overrightarrow{r_{i}} \\times \\overrightarrow{p_{i}}{/tex}</span>&nbsp;&nbsp;<br />
For a single particle in rotational motion, we have, <span class="math-tex">{tex}l{/tex}</span>&nbsp;= r&nbsp;&times; p, and after differentiating this equation we get<br />
<span class="math-tex">{tex}\\frac{\\overrightarrow{d l}}{d t}=\\frac{d}{d t}(\\vec{r} \\times \\vec{p}){/tex}</span>=&nbsp;<span class="math-tex">{tex}\\frac{d}{d t}[\\vec{r} \\times(m \\vec{v})]{/tex}</span>=&nbsp;<span class="math-tex">{tex}\\frac{\\overrightarrow{d r}}{d t} \\times(m \\vec{v})+\\vec{r} \\times m \\frac{\\overrightarrow{d v}}{d t}{/tex}</span>.................................................(1)<br />
But&nbsp;<span class="math-tex">{tex}\\frac{d \\vec{r}}{d t}=\\vec{v}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\vec{v} \\times(m \\vec{v}){/tex}</span>&nbsp;must be zero. Also,&nbsp;<span class="math-tex">{tex}\\frac{\\overrightarrow{d v}}{d t}=\\vec{a}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}m \\vec{a}=\\vec{F}{/tex}</span><br />
Therefore, from equation (1) we have</p>

<p><span class="math-tex">{tex}\\frac{\\overrightarrow{d l}}{d t}=[\\vec{r} \\times \\vec{F}]=\\vec{\\tau}{/tex}</span>&nbsp; &nbsp;.........................................(2)<br />
Hence, for the whole system, we obtain<br />
<span class="math-tex">{tex}\\frac{\\overrightarrow{d L}}{d t}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{d}{d t} \\sum_{i=1}^{n} \\vec{l}_{i}=\\sum_{i=1}^{n} \\frac{\\overrightarrow{d l_{i}}}{d t}{/tex}</span>=&nbsp;<span class="math-tex">{tex}\\sum_{i=1}^{n} \\vec{\\tau}_{i}{/tex}</span><br />
The force <span class="math-tex">{tex}\\vec{F}_{i}{/tex}</span>&nbsp;on i<sup>th</sup> particle is the vector sum of external forces <span class="math-tex">{tex}\\vec {F_{i}^{{e x t}}}{/tex}</span>&nbsp;acting on the particle and internal forces <span class="math-tex">{tex}\\vec {F_{i}^{i n t}}{/tex}</span>&nbsp;acting on the particle, hence<br />
<span class="math-tex">{tex}\\vec{\\tau}=\\sum \\vec{\\tau}_{i}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\sum \\tau_{i}^{\\vec{e} t}+\\Sigma \\tau_{i}^{\\vec{i} n t}{/tex}</span>=&nbsp;<span class="math-tex">{tex}\\sum \\vec{r}_{i} \\times F_{i}^{\\overrightarrow{e x t}}+\\Sigma \\overrightarrow{r_{i}} \\times \\overrightarrow{F_{i}^{i n t}}{/tex}</span><br />
However, as per Newton&#39;s third law of motion, the contribution of the internal forces to the total torque on the system is zero, since the torque resulting from each action-reaction pair is zero. Thus,<br />
<span class="math-tex">{tex}\\vec{\\tau}_{i n t}=\\sum \\tau_{i}^{{i n t}}=0{/tex}</span>&nbsp;and<br />
<span class="math-tex">{tex}\\vec{\\tau}=\\sum \\tau_{i}^{{e x t}}=\\vec\\tau_{e x t}{/tex}</span><br />
Hence, the relation between <span class="math-tex">{tex}\\vec{L}{/tex}</span>&nbsp;and <span class="math-tex">{tex}\\vec{\\tau}{/tex}</span>&nbsp;may be expressed as<br />
<span class="math-tex">{tex}\\frac{\\overrightarrow{d L}}{d t}=\\sum \\vec \\tau_{i}^{{e x t}}{/tex}</span>&nbsp; &nbsp; ..............................(3)<br />
Hence, we can say, that time rate of the total angular momentum of the system of particles about a point is equal to the sum of the external torques acting on the system taken about the same point.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>If three point masses m<sub>1</sub>, m<sub>2</sub>&nbsp;and m<sub>3</sub>&nbsp;are situated at the vertices of an equilateral triangle of side a, then what will be the co-ordinates of the centre of mass of this system?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let the point mass m<sub>1</sub> lie at the origin of the co-ordinate system, as shown in Fig.<br/>
<img alt="" data-imgur-src="1tpgcvo.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082692-t2xzq2.jpg" style="width: 200px; height: 124px;"/><br/>
Then<br/>
Co-ordinates of m<sub>1 </sub>: x<sub>1 </sub>= 0, y<sub>1 </sub>= 0<br/>
Co-ordinates of m<sub>2 </sub>: x<sub>2 </sub>= a, y<sub>2</sub>= 0<br/>
Co-ordinates of m<sub>3</sub> : <span class="math-tex">{tex}x_{3}=\\frac{a}{2}, y_{3}=\\frac{\\sqrt{3}}{2} a{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore \\quad x_{C M}=\\frac{m_{1} x_{1}+m_{2} x_{2}+m_{3} x_{3}}{m_{1}+m_{2}+m_{3}}{/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{m_{1} \\times 0+m_{2} a+m_{3}(a / 2)}{m_{1}+m_{2}+m_{3}}{/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{m_{2} a+m_{3}(a / 2)}{m_{1}+m_{2}+m_{3}}{/tex}</span> and <span class="math-tex">{tex}y_{C M}=\\frac{m_{1} y_{1}+m_{2} y_{2}+m_{3} y_{3}}{m_{1}+m_{2}+m_{3}}{/tex}</span><br/>
= <span class="math-tex">{tex} \\frac{{{m_1} \\times 0 + {m_2} \\times 0 + {m_3}(\\frac{{\\sqrt 3 a}}{2})}}{{{m_1} + {m_2} + {m_3}}}{/tex}</span><br/>
= <span class="math-tex">{tex}\\frac{m_{3} \\sqrt{3} a}{2\\left(m_{1}+m_{2}+m_{3}\\right)}{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>In the HCl molecule, the separation between the nuclei of the two atoms is about 1.27&nbsp;<span class="math-tex">{tex}\\mathop {\\text{A}}\\limits^{\\text{o}} \\left( {{\\text{1}}\\mathop {\\text{A}}\\limits^{\\text{o}} {\\text{ = 1}}{{\\text{0}}^{{\\text{ - 10}}}}{\\text{m}}} \\right){/tex}</span>. Find the approximate location of the C.M of the molecule, given that a chlorine atom is about 35.5 times as massive as a hydrogen atom and nearly all the mass of an atom is concentrated in its nucleus.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The&nbsp;centre of mass&nbsp;is a position defined relative to an object or system of objects. It is the average position of all the parts of the system, weighted according to their masses. The given situation can be shown as:<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch07/3m/image035.jpg" style="height:65px; width:150px" /><br />
Distance between H and Cl atoms = 1.27<span class="math-tex">{tex}\\mathop {\\text{A}}\\limits^{\\text{o}} {/tex}</span><br />
Mass of H atom = m<br />
Mass of Cl atom = 35.5 m<br />
Let the centre of mass of the system lie at a distance x from the Cl atom.<br />
Distance of the centre of mass from the H atom = (1.27 - x)<br />
Let us assume that the centre of mass of the given molecule lies at the origin. Therefore, we can have:<br />
<span class="math-tex">{tex}\\frac { m ( 1.27 - x ) + 35.5 m x } { m + 35.5 m } = 0{/tex}</span><br />
m (1.27 - x) + 35.5 mx = 0<br />
1.27 - x = -35.5 mx<br />
<span class="math-tex">{tex}\\therefore x = \\frac { - 1.27 } { ( 35.5 - 1 ) } = - 0.037 \\mathop {\\text{A}}\\limits^{\\text{o}} {/tex}</span><br />
Here, the negative sign indicates that the centre of mass lies at the left of the Cl atom.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A metre stick is balanced on a knife edge at its centre. When two coins, each of mass 5 g are put one on top of the other at the 12.0 cm mark, the stick is found to be balanced at 45.0 cm. What is the mass of the metre stick?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let W and W&#39; be the respective weights of the meter stick and both the coins.<br />
<img id="Picture 81" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch07/3m/image050.jpg" /><br />
The mass of the meter stick is concentrated at its mid-point, i.e., at the 50 cm mark.<br />
Let the&nbsp;mass of the meter stick = M<br />
Mass of each coin, m = 5 g<br />
When the coins are placed 12 cm away from the end P, due to the weights of the coin, the center of mass gets shifted by 5 cm from point R toward the end P. The center of mass is located at a distance of 45 cm from point P.<br />
According to the principle of moments, for equilibrium net torque on the system about the center of mass S should be zero. Hence<br />
-10 <span class="math-tex">{tex}\\times{/tex}</span> g(45 - 12) +&nbsp;m&#39;g(50 - 45) = 0&nbsp;(Using the convention; clockwise torque = -ve and anticlockwise = +ve)<br />
hence the mass of the stick&nbsp;<br />
<span class="math-tex">{tex}\\therefore m ^ { \\prime } = \\frac { 10 \\times 33 } { 5 } = 66 g{/tex}</span><br />
Hence, the mass of the metre stick is 66 g.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define centre of mass of a n-particle system. State the coordinates of centre of mass of a&nbsp;n-particle system.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The centre of mass (CoM) is the point relative to the system of particles in an object. This is that point of the system of particles that embarks the average position of the system in relation to the mass of the object. At the centre of mass,&nbsp;the&nbsp;weighted&nbsp;mass&nbsp;gives a sum&nbsp;equal to zero.<br />
If in an n-particle system particle of masses m<sub>1</sub>, m<sub>2</sub> ... m<sub>n</sub> be situated at <span class="math-tex">{tex}\\overrightarrow{r_{1}}, \\overrightarrow{r_{2}}, \\ldots, \\overrightarrow{r_{n}}{/tex}</span>&nbsp;respectively, then the position vector of the centre of mass <span class="math-tex">{tex}\\vec r_{cm}{/tex}</span>&nbsp;is given by,<br />
<span class="math-tex">{tex}\\vec r_{cm}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{m_{1} \\vec{r}_{1}+m_{2} \\overrightarrow{r_{2}}+\\ldots+m_{n} \\vec{r}_{n}}{m_{1}+m_{2}+\\ldots+m_{n}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{m_{1} \\vec{r}_{1}+m_{2} \\overrightarrow{r_{2}}+\\ldots+m_{n} r_{n}}{M}{/tex}</span>&nbsp; &nbsp;.......(1)<br />
As position vector r in terms of coordinates may be expressed as <span class="math-tex">{tex}\\vec{r}=x \\hat{i}+y \\hat{j}+z \\hat{k}{/tex}</span> , hence in coordinate forms, the centre of mass of n-particle system may be specified as,<br />
<span class="math-tex">{tex}X_{c m}=\\frac{m_{1} x_{1}+m_{2} x_{2}+\\ldots+m_{n} x_{n}}{M}{/tex}</span>,&nbsp;<span class="math-tex">{tex}Y_{c m}=\\frac{m_{1} y_{1}+m_{2} y_{2}+\\ldots+m_{n} y_{n}}{M}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}Z_{c m}=\\frac{m_{1} z_{1}+m_{2} z_{2}+\\ldots+m_{n} z_{n}}{M}{/tex}</span>&nbsp;.........(2)<br />
where, M = m<sub>1</sub> + m<sub>2</sub> + ... + m<sub>n</sub> = the total mass of entire n-particle system.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two masses of 3 kg and 5 kg are placed at 30 cm and 70 cm marks respectively on a light wooden metre scale, as shown in Fig. What will the moment of inertia of the system about an axis through (i) 0 cm mark and (ii) 100 cm mark, and perpendicular to the metre scale?<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1704862679-wqnf5a.jpg" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>at axis (0 cm mark)<br />
	<span class="math-tex">{tex}m_1 r_1^2+m_2 r_2^2{/tex}</span> = 3(0.3)<sup>2</sup> + 5(0.7)<sup>2</sup><br />
	= 0.27 + 2.45<br />
	= 2.72 kgm<sup>2</sup></li>
	<li>at axis (100 cm mark)<br />
	<span class="math-tex">{tex}m_1 r_1^2+m_2 r_2^2{/tex}</span> = 5(0.3)<sup>2</sup> + 3(0.7)<sup>2</sup><br />
	= 0.45 + 1.47<br />
	= 2.72 kgm<sup>2</sup></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>From a uniform circular disc of diameter D, a circular disc or hole of diameter <span class="math-tex">{tex}\\frac{D}{6}{/tex}</span> and having its centre at a distance of from&nbsp;the centre of the disc is scooped out. Determine the centre of mass of the remaining portion.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let mass per unit area of the disc = m<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> Total mass of the disc, <span class="math-tex">{tex}M=\\pi\\left(\\frac{D}{2}\\right)^{2} m=\\frac{\\pi m D^{2}}{4}{/tex}</span><br/>
Mass of the scooped out portion of the disc,<br/>
<span class="math-tex">{tex}M^{\\prime}=\\pi\\left(\\frac{D}{12}\\right)^{2} m=\\frac{\\pi m D^{2}}{144}{/tex}</span><br/>
We take the centre O of the disc as the origin. The masses M and M' can be supposed to be concentrated at the centres of the disc and scooped out portion respectively. The mass M' of the removed portion is taken negative.<br/>
<img alt="" data-imgur-src="X2EDHDd.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082756-nuypye.jpg"/><br/>
Then x-coordinate of the CM of the remaining portion of the disc will be<br/>
<span class="math-tex">{tex}x_{C M}=\\frac{M x_{1}-M x_{2}}{M-M}=\\frac{M \\times 0-M(D / 4)}{\\frac{\\pi m D^{2}}{4}-\\frac{\\pi m D^{2}}{144}}{/tex}</span><br/>
<span class="math-tex">{tex}=-\\frac{M D}{4} \\times \\frac{144}{35 \\pi m D^{2}}{/tex}</span><br/>
<span class="math-tex">{tex}=-\\frac{\\pi m D^{2}}{144} \\times \\frac{D}{4} \\times \\frac{144}{35 \\pi m D^{2}}=-\\frac{D}{140}{/tex}</span><br/>
Thus, the centre of mass of the remaining portion lies at a distance of D/140 towards the left of the centre O of the disc.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Four masses are rotated about an axis as shown. Find radius of gyration of the system.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683866227-ert4t5.jpg" style="width: 200px; height: 196px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Moment of InertIa of a mass about axIs = mass <span class="math-tex">{tex}\\times{/tex}</span> (dIstance)<sup>2</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Moments of InertIa of masses are<br />
I<sub>1</sub> = 2mr<sup>2</sup><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;I<sub>2</sub> = 3m&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;r<sup>2</sup><br />
I<sub>3</sub> = 2m&nbsp;<span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;r<sup>2</sup><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;I<sub>4</sub> = m <span class="math-tex">{tex}\\cdot{/tex}</span>&nbsp;r<sup>2</sup><br />
So, total moment of InertIa of system of masses<br />
= I<sub>1</sub> + I<sub>2</sub> + I<sub>3</sub> + I<sub>4</sub> = 8mr<sup>2</sup><br />
Total mass of system = 8m<br />
If radIus of gyratIon Is K, then I = MK<sup>2</sup><br />
or K<sup>2</sup> =&nbsp;<span class="math-tex">{tex}\\frac 1M{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{8 \\mathrm{mr}^2}{8 \\mathrm{~m}}{/tex}</span><br />
or = K = r</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>If the earth were to suddenly contract to half of its present radius (without any external torque on it), by what duration would the day be decreased? Assume earth to be a perfect solid sphere of the moment of inertia.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Present radius of the earth,&nbsp;R<sub>1</sub>&nbsp;= R<br />
New radius of the earth after&nbsp;contraction&nbsp;<span class="math-tex">{tex}{{\\text{R}}_{\\text{2}}}{\\text{ = }}\\frac{R}{2}{/tex}</span><br />
T<sub>1&nbsp;</sub>= 24 h, T<sub>2&nbsp;</sub>= ?<br />
By conservation of angular momentum,<br />
<span class="math-tex">{tex}I_{1} \\omega_{1}=I_{2} \\omega_{2}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{2}{5} M R_{1}^{2} \\cdot \\frac{2 \\pi}{T_{1}}=\\frac{2}{5} M R_{2}^{2} \\cdot \\frac{2 \\pi}{T_{2}}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}T_{2}=\\left(\\frac{R_{2}}{R_{1}}\\right)^{2} \\cdot T_{1}=\\left(\\frac{R / 2}{R}\\right)^{2} \\times 24=\\frac{1}{4} \\times 24{/tex}</span>&nbsp;= 6h<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Decrease in the duration of the day<br />
= 24 - 6 = 18 h</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two particles, each of mass m and speed v, travel in opposite directions along parallel lines separated by a distance d. Show that the vector angular momentum of the two particle system is the same whatever be the point about which the angular momentum is taken.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let at a certain instant two particles be at points P and Q between two parallel lines and d is the perpendicular distance between them, as shown in the following figure.<br />
<img id="Picture 25" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch07/4m/image043.jpg" style="width: 150px; height: 73px;" /><br />
The angular momentum of the system about point P:<br />
<span class="math-tex">{tex}\\vec { L } _ { p } = m v \\times 0 + m v \\times d{/tex}</span>,<br />
= mvd &hellip;.(i)<br />
The angular momentum of the system about point Q:<br />
<span class="math-tex">{tex}\\vec { L } _ { Q } = m v \\times d + m v \\times 0{/tex}</span><br />
= mvd &hellip;.(ii)<br />
Consider a point R, which is at a distance y from point Q, i.e.,<br />
QR = y<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> PR = d - y<br />
The angular momentum of the system about point R:<br />
<span class="math-tex">{tex}\\vec { L } _ { R } = m v \\times ( d - y ) + m v \\times y{/tex}</span><br />
= mvd - mvy + mvy<br />
= mvd &hellip;(iii)<br />
Comparing equations (i), (ii), and (iii), we get:<br />
<span class="math-tex">{tex}\\vec { L } _ { p } = \\vec { L } _ { Q } = \\vec { L } _ { R }{/tex}</span>&nbsp;&hellip;(iv)<br />
We infer from equation (iv) that the angular momentum of a system does not depend on the point about which it is taken. So the total angular momentum is expressed as L = mvd.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define angular acceleration. Establish its relation with linear acceleration.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Angular acceleration.</strong> The time rate of change of angular velocity of a particle is called its angular acceleration. If <span class="math-tex">{tex}\\Delta \\omega{/tex}</span>&nbsp;is the change in angular velocity in time <span class="math-tex">{tex}\\Delta t{/tex}</span>, then the average angular acceleration is<br />
<span class="math-tex">{tex}\\bar{\\alpha}=\\frac{\\Delta \\omega}{\\Delta t}{/tex}</span><br />
The instantaneous acceleration is equal to the limiting value of the average acceleration&nbsp;<span class="math-tex">{tex}\\frac {\\Delta \\omega}{\\Delta t}{/tex}</span>&nbsp;when&nbsp;<span class="math-tex">{tex}\\Delta t{/tex}</span>&nbsp;approaches zero. it is given by<br />
<span class="math-tex">{tex}\\alpha=\\lim _\\limits{\\Delta t \\rightarrow 0} \\frac{\\Delta \\omega}{\\Delta t}=\\frac{d \\omega}{d t}{/tex}</span><br />
The angular acceleration is measured in radian per second<sup>2</sup> (rads<sup>-2</sup>) and has the dimensions [M&deg;L&deg;T<sup>-2</sup>].<br />
The relation between linear velocity v and angular velocity&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;is v = r<span class="math-tex">{tex}\\omega{/tex}</span><br />
Differentiating both sides w.r.t. time t, we get<br />
<span class="math-tex">{tex}\\frac{d v}{d t}=\\frac{d}{d t}(r \\omega){/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{d v}{d t}=r\\left(\\frac{d \\omega}{d t}\\right){/tex}</span>&nbsp;[<span class="math-tex">{tex}\\because{/tex}</span>&nbsp;r is constant]<br />
or a =&nbsp;<span class="math-tex">{tex}\\alpha{/tex}</span>r<br />
Linear acceleration = Angular acceleration&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;radius<br />
In vector notation, we have the relation<br />
<span class="math-tex">{tex}\\vec{a}=\\vec{\\alpha} \\times \\vec{r}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What will be the duration of the day, if earth suddenly shrinks to <span class="math-tex">{tex}\\frac{1}{{64}}{/tex}</span> of its original volume, mass remaining the same?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Original volume of the earth,&nbsp;<span class="math-tex">{tex}V=\\frac{4}{3} \\pi R^{3}{/tex}</span><br />
Volume of the earth after shrinking,&nbsp;<span class="math-tex">{tex}V^{\\prime}=\\frac{V}{64}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{4}{3} \\pi R^{3}=\\frac{1}{64} \\times \\frac{4}{3} \\pi R^{3}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}R^{\\prime}=\\frac{R}{4}{/tex}</span><br />
By conservation of angular momentum,&nbsp;<span class="math-tex">{tex}I^{\\prime} \\omega^{\\prime}=I \\omega{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{2}{5} M R^{\\prime 2} \\times \\frac{2 \\pi}{T^{\\prime}}=\\frac{2}{5} M R^{2} \\times \\frac{2 \\pi}{T}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}T^{\\prime}=\\left(\\frac{R^{\\prime}}{R}\\right)^{2} \\cdot T=\\left(\\frac{R / 4}{R}\\right)^{2} \\times 24{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{16} \\times 24{/tex}</span>&nbsp;= 1.5 h</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>How torque is expressed as the vector product of two vectors? State the rule for determining the direction of torque.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><strong>The torque acting on a particle:</strong> Consider a particle P in the X-Y plane. Suppose its position vector is <span class="math-tex">{tex}\\overrightarrow{O P}=\\vec{r}{/tex}</span> with respect to the origin O of an inertial frame, as shown in Fig. Let <span class="math-tex">{tex}\\vec{F}{/tex}</span> be the force acting on the particle. The torque acting on the particle is defined as the vector product of position and force vectors. Thus the torque of F about O is defined as<br/>
<span class="math-tex">{tex}\\vec{\\tau}=\\vec{r} \\times \\vec{F}{/tex}</span><br/>
<img alt="" data-imgur-src="nPmVICt.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082775-fybd7n.jpg"/></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A circular ring of diameter 40cm and mass 1kg is rotating about an axis normal to its plane and passing through the centre with a frequency of 10 rotations per second. Calculate the angular momentum about its axis of rotation.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><span class="math-tex">{tex}R = \\frac { 40 } { 2 } = 20 c m = 0.2 m{/tex}</span><br />
m = 1 kg,&nbsp;&nbsp;<span class="math-tex">{tex}v{/tex}</span>= 10 rotations/sec.<br />
Moment of Inertia, I = MR<sup>2</sup> = 1 <span class="math-tex">{tex}\\times{/tex}</span> (0.2)<sup>2</sup> = 0.04 kg-m<sup>2</sup><br />
<span class="math-tex">{tex}w = 2 \\pi v = 2 \\times \\pi \\times 10 = 20 \\pi r a d / s{/tex}</span></p>

<p>Angular momentum of a system is a product of its moment of inertia and its angular velocity.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> L = I*<span class="math-tex">{tex}w{/tex}</span><br />
<span class="math-tex">{tex}L = 0.04 \\times 20 \\pi{/tex}</span><br />
L = 251 kg-m<sup>2</sup>/s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Find the centre of mass of three particles at the vertices of an equilateral triangle. The masses of the particles are 100g, 150g, and 200g respectively. Each side of the equilateral triangle is 0.5m long.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><span class="math-tex">{tex}\\textbf{Given:}{/tex}</span><br />
Three particles are placed at the vertices of an equilateral triangle of side<br />
<span class="math-tex">{tex}a = 0.5,\\text{m}{/tex}</span><br />
with masses<br />
<span class="math-tex">{tex}m_1 = 100,\\text{g}, m_2 = 150,\\text{g}, m_3 = 200,\\text{g}{/tex}</span></p>

<p><span class="math-tex">{tex}\\textbf{Step 1: Coordinate system}{/tex}</span></p>

<p>Choose the vertices as:<br />
<span class="math-tex">{tex}A(0,0), B(a,0) = (0.5,0), C\\left(\\frac{a}{2}, \\frac{\\sqrt{3}a}{2}\\right) = \\left(0.25, \\frac{\\sqrt{3}}{4}\\right){/tex}</span></p>

<p><span class="math-tex">{tex}\\textbf{Step 2: Total mass}{/tex}</span><br />
<span class="math-tex">{tex}M = m_1 + m_2 + m_3 = 100 + 150 + 200 = 450,\\text{g}{/tex}</span></p>

<p><span class="math-tex">{tex}\\textbf{Step 3: Centre of mass coordinates}{/tex}</span></p>

<p><span class="math-tex">{tex}x_{\\text{CM}} = \\frac{m_1x_1 + m_2x_2 + m_3x_3}{M}{/tex}</span></p>

<p><span class="math-tex">{tex}x_{\\text{CM}} = \\frac{100(0) + 150(0.5) + 200(0.25)}{450}{/tex}</span></p>

<p><span class="math-tex">{tex}x_{\\text{CM}} = \\frac{75 + 50}{450} = \\frac{125}{450} = \\frac{5}{18}{/tex}</span></p>

<p><span class="math-tex">{tex}x_{\\text{CM}} = 0.278,\\text{m}{/tex}</span></p>

<p><span class="math-tex">{tex}y_{\\text{CM}} = \\frac{m_1y_1 + m_2y_2 + m_3y_3}{M}{/tex}</span></p>

<p><span class="math-tex">{tex}y_{\\text{CM}} = \\frac{100(0) + 150(0) + 200\\left(\\frac{\\sqrt{3}}{4}\\right)}{450}{/tex}</span></p>

<p><span class="math-tex">{tex}y_{\\text{CM}} = \\frac{50\\sqrt{3}}{450} = \\frac{\\sqrt{3}}{9}{/tex}</span></p>

<p><span class="math-tex">{tex}y_{\\text{CM}} = 0.192,\\text{m}{/tex}</span></p>

<p>Coordinates are measured from the vertex carrying the (100 g) mass, with the base along the (x)-axis.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Four particles of mass 1 kg, 2 kg, 3 kg and 4 kg are placed at the four vertices A, B, C and D of square of side 1m. Find the position of centre of mass of the particle.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1688097758-ah43tu.jpg" style="width: 200px; height: 171px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Centre of mass of a system is a special point on which whole mass of the system is supposed to be concentrated.<br />
Hence m<sub>1</sub> = 1 kg (x<sub>1</sub>, y<sub>1</sub>) = (0, 0)<br />
m<sub>2</sub> = 2 kg (x<sub>2</sub>, y<sub>2</sub>) = (1, 0)<br />
m<sub>3</sub> = 3 kg (x<sub>3</sub>, y<sub>3</sub>) = (1, 1)<br />
m<sub>4</sub> = 4 kg (x<sub>4</sub>, y<sub>4</sub>) = (0, 1)<br />
<span class="math-tex">{tex}X= \\frac { m _ { 1 } x _ { 1 } + m _ { 2 } x _ { 2 } + m _ { 3 } x _ { 3 } + m _ { 4 } x _ { 4 } } { m _ { 1 } + m _ { 2 } + m _ { 3 } + m _ { 4 } }{/tex}</span>&nbsp;<br />
X = (0+2+3+0)/10<br />
X = 0.5 m<br />
<span class="math-tex">{tex}Y= \\frac { m _ { 1 } y _ { 1 } + m _ { 2 } y _ { 2 } + m _ { 3 } y _ { 3 } + m _ { 4 } y _ { 4 } } { m _ { 1 } + m _ { 2 } + m _ { 3 } + m _ { 4 } }{/tex}</span>&nbsp;<br />
Y = (<span class="math-tex">{tex}\\frac{0+0+3+4}{10}{/tex}</span>)<br />
Y = 0.7 m<br />
Thus centre of mass is at (0.5m, 0.7m) on which whole 10 kg mass is supposed to be acting and it lies in XY plane.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define angular momentum. Derive the relation between angular momentum and torque.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Relation between torque and angular momentum. We know that<br />
Torque,&nbsp;<span class="math-tex">{tex}\\vec{\\tau}=\\vec{r} \\times \\vec{F}{/tex}</span><br />
Angular momentum,&nbsp;<span class="math-tex">{tex}\\vec{L}=\\vec{r} \\times \\vec{p}{/tex}</span><br />
Differentiating both sides w.r.t. time t, we get<br />
<span class="math-tex">{tex}\\frac{d \\vec{L}}{d t}=\\frac{d}{d t}(\\vec{r} \\times \\vec{p})=\\frac{d \\vec{r}}{d t} \\times \\vec{p}+\\vec{r} \\times \\frac{d \\vec{p}}{d t}{/tex}</span><br />
<span class="math-tex">{tex}=\\vec{v} \\times \\vec{p}+\\vec{r} \\times \\vec{F}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left[\\because \\frac{d \\vec{p}}{d t}=\\vec{F}\\right]{/tex}</span><br />
<span class="math-tex">{tex}=0+\\vec{\\tau} \\quad[\\because \\vec{v} \\times \\vec{p}=\\vec{v} \\times m \\vec{v}=0]{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\quad \\vec{\\tau}=\\frac{d \\vec{L}}{d t}{/tex}</span><br />
Thus the torque acting on a particle is equal to its rate of change of angular momentum. This equation is the rotational analogue of Newton&#39;s second law of linear motion which states that the rate of change of linear momentum of a particle is equal to the force acting on it i.e.,<br />
<span class="math-tex">{tex}\\vec{F}=\\frac{d \\vec{p}}{d t}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>From a uniform disk of radius R, a circular hole of radius <span class="math-tex">{tex}\\frac{R}{2}{/tex}</span>&nbsp;is cut out. The centre of the hole is at&nbsp;<span class="math-tex">{tex}\\frac{R}{2}{/tex}</span> from the centre of the original disc. Locate the centre of gravity of the resulting flat body.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The centre of mass of an object is the point at which the object can be balanced. Mathematically, it is the point at which the torques from the mass elements of an object sum to zero. The centre of mass is useful because problems can often be simplified by treating a collection of masses as one mass at their common centre of mass. The weight of the object then acts through this point.<br />
To solve this problem, first we assume that the whole disc was present whose centre of mass lies at the origin from which a small disc was cut out. So CM of remaining portion and cut out disc will lie exactly at the origin i.e Centre of Mass of the original disc at x = 0<br />
Mass per unit area of the original disc = <span class="math-tex">{tex}\\sigma{/tex}</span><br />
Radius of the original disc = R<br />
Mass of the original disc, <span class="math-tex">{tex}M = \\pi R ^ { 2 } \\sigma{/tex}</span><br />
The disc with the cut portion is shown in the following figure:<br />
<img id="Picture 74" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch07/5m/image106.jpg" style="width: 150px; height: 106px;" /><br />
Radius of the smaller disc <span class="math-tex">{tex}= \\frac { R } { 2 }{/tex}</span><br />
Mass of the smaller disc, <span class="math-tex">{tex}M ^ { \\prime } = \\pi \\left( \\frac { R } { 2 } \\right) ^ { 2 } \\sigma = \\frac { 1 } { 4 } \\pi R ^ { 2 } \\sigma = \\frac { M } { 4 }{/tex}</span><br />
Let O and O&#39; be the respective centers of the original disc and the disc cut off from the original. As per the definition of the centre of mass, the centre of mass of the original disc is supposed to be concentrated at O, while that of the smaller disc is supposed to be concentrated at O&#39;.<br />
It is given that:<br />
<span class="math-tex">{tex}O O ^ { \\prime } = { \\frac { R } { 2 } }{/tex}</span><br />
After the smaller disc has been cut from the original, the remaining portion is considered to be a system of two masses. The two masses are:<br />
M (concentrated at O), and<br />
&nbsp;<span class="math-tex">{tex}\\left(-M' = \\frac { M } { 4 } \\right){/tex}</span> concentrated at O&#39;<br />
(The negative sign indicates that this portion has been removed from the original disc.)<br />
Let x be the distance through which the centre of mass of the remaining portion shifts from point O.<br />
The relation between the centers of masses of two masses is given as:<br />
<span class="math-tex">{tex}x = \\frac { m _ { 1 } r _ { 1 } + m _ { 2 } r _ { 2 } } { m _ { 1 } + m _ { 2 } }{/tex}</span><br />
For the given system<br />
<span class="math-tex">{tex}x = \\frac { M \\times 0 - M \\times \\left( \\frac { R } { 2 } \\right) } { M + \\left( - M ^ { \\prime } \\right) }{/tex}</span>&nbsp; &nbsp; (here M&#39; is M/4 )<br />
<span class="math-tex">{tex}= \\frac { \\frac { - M } { 4 } \\times \\frac { R } { 2 } } { M - \\frac { M } { 4 } } = \\frac { - M R } { 8 } \\times \\frac { 4 } { 3 M } = \\frac { - R } { 6 }{/tex}</span></p>

<p>Note that shift in Centre of Mass is very less(only 0.16 R or <span class="math-tex">{tex}\\frac{R}{6}{/tex}</span>) as removed portion has very less mass as compared to the remaining portion.<br />
(The negative sign indicates that the centre of mass gets shifted toward the left of point O and lies at <span class="math-tex">{tex}\\frac{R}{6}{/tex}</span>&nbsp;left towards origin.)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A car weighs 1800 kg. The distance between its front and back axles is 1.8 m. Its centre of gravity is 1.05 m behind the front axle. Determine the force exerted by the level ground on each front wheel and each back wheel.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Weight of car = 1800 Kg<br />
Distance of COG from front axle = 1.05 m&nbsp;<br />
Distance of COG from back axle = 1.8 - 1.05 = 0.75 m&nbsp;<br />
Vertical forces are balanced ,&nbsp;<br />
So,At translational equilibrium:<br />
R<sub>1</sub> + R<sub>2</sub> = mg&nbsp;<br />
R<sub>1</sub> + R<sub>2</sub> = 1800 <sub><span class="math-tex">{tex}\\times{/tex}</span></sub>&nbsp;9.8 = 17640<br />
<img id="Picture 36" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch07/5m/image049.jpg" style="width: 185px; height: 94px;" /><br />
R<sub>1</sub> and R<sub>2</sub> are the forces exerted by the level ground on the front and back wheels respectively.<br />
Angular momentum about centre of gravity is zero.<br />
So,&nbsp;<br />
R<span style="font-size: 10.8333px;">1</span>(1.05) = R<span style="font-size: 10.8333px;">2</span>(1.8 - 1.05)<br />
<span class="math-tex">{tex}R _ { 1 } \\times 1.05 = R _ { 2} \\times 0.75{/tex}</span><br />
<span class="math-tex">{tex}\\frac { R _ { 1 } } { R _ { 2 } } = \\frac { 0.75 } { 1.05 } = \\frac { 5 } { 7 }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { R _ { 1 } } { R _ { 2 } } = \\frac { 7 } { 5 }{/tex}</span><br />
R<sub><span style="font-size: 10.8333px;">1</span></sub>&nbsp;= 1.4 R<sub><span style="font-size: 10.8333px;">2</span>&nbsp;</sub>&hellip;..(ii)<br />
Solving equations (i) and (ii), we get:<br />
1.4 R<sub><span style="font-size: 10.8333px;">2</span></sub>&nbsp;+ R<sub><span style="font-size: 10.8333px;">2</span></sub>&nbsp;= 17640<br />
<span class="math-tex">{tex}R _ { 2 } = \\frac { 17640 } { 2.4 } = 7350 \\mathrm { N }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span> R<sub><span style="font-size: 10.8333px;">1</span></sub>&nbsp;= 17640 - 7350 = 10290 N<br />
Therefore, the force exerted on each front wheel <span class="math-tex">{tex}=\\frac { R_1 } { 2 }= \\frac { 7350 } { 2 } = 3675 N{/tex}</span>, and<br />
The force exerted on each back wheel <span class="math-tex">{tex}= \\frac { R_2 } { 2 }=\\frac { 10290 } { 2 } = 5145 N{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>If two particles of masses m<sub>1</sub>&nbsp;= 2 kg and m<sub>2&nbsp;</sub>= 3 kg have position vectors <span class="math-tex">{tex}\\vec {r_1}{/tex}</span> =&nbsp;<span class="math-tex">{tex}\\hat i{/tex}</span>&nbsp;+2t<sup>3</sup><span class="math-tex">{tex}\\hat j{/tex}</span>&nbsp;+ 2t<span class="math-tex">{tex}\\hat k{/tex}</span>&nbsp;and <span class="math-tex">{tex}\\vec {r_2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\hat i{/tex}</span>+ +2t<sup>3</sup><span class="math-tex">{tex}\\hat j{/tex}</span>&nbsp;+ 5<span class="math-tex">{tex}\\hat k{/tex}</span>&nbsp;a&nbsp;respectively, then the position vector of r<sub>1</sub> and r<sub>2</sub> is in meters and time is in seconds. Calculate the velocity and acceleration of centre of mass of two particles system.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here, <span class="math-tex">{tex}m_1=2 \\mathrm{~kg}, m_2=3 \\mathrm{~kg} {/tex}</span>and position vectors<br />
<span class="math-tex">{tex}\\mathbf{\\vec r_1}=t \\hat{\\mathbf{i}}+2 t^2 \\hat{\\mathbf{j}}+2 t \\hat{\\mathbf{k}}{/tex}</span><br />
and&nbsp;<span class="math-tex">{tex} \\mathbf{\\vec r_2}=\\hat{\\mathbf{i}}+2 t^3 \\hat{\\mathbf{j}}+5 \\hat{\\mathbf{k}}{/tex}</span><br />
Now, velocity of first particle, <span class="math-tex">{tex}{v}_1=\\frac{d}{d t}\\left(\\mathbf{r}_1\\right){/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{d}{d t}\\left(t \\hat{\\mathrm{i}}+2 t^2 \\hat{\\mathrm{j}}+2 t \\hat{\\mathrm{k}}\\right){/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\hat {i}+4 t \\hat{j}+2 \\hat{k}{/tex}</span><br />
Velocity of second particle,<br />
<span class="math-tex">{tex}{v}_2 =\\frac{d}{d t}\\left({r}_2\\right){/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{d}{d t}\\left(\\hat{\\mathbf{i}}+2 t^3 \\hat{\\mathbf{j}}+5 \\hat{\\mathbf{k}}\\right)=6 t^2 \\hat{\\mathbf{j}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore {/tex}</span>&nbsp;Velocity of centre of mass of two particles system is<br />
<span class="math-tex">{tex}\\mathbf{v}_{\\mathrm{CM}} =\\frac{m_1 \\mathbf{v}_1+m_2 \\mathbf{v}_2}{m_1+m_2} {/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{2 \\times(\\hat{\\mathbf{i}}+4 t \\hat{\\mathbf{j}}+2 \\hat{\\mathbf{k}})+3 \\times\\left(6 t^2 \\hat{\\mathbf{j}}\\right)}{2+3}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{2 \\hat{\\mathbf{i}}+\\left(8 t+18 t^2\\right) \\hat{\\mathbf{j}}+4 \\hat{\\mathbf{k}}}{5}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\left[\\frac{2}{5} \\hat{\\mathbf{i}}+\\frac{\\left(8 t+18 t^2\\right)}{5} \\hat{\\mathbf{j}}+\\frac{4}{5} \\hat{\\mathbf{k}}\\right] \\mathrm{m} / \\mathrm{s}{/tex}</span><br />
Now, acceleration of first particle,<br />
<span class="math-tex">{tex}\\mathrm{a}_1=\\frac{a}{d t}\\left(\\mathrm{v}_1\\right)=\\frac{a}{d t}(\\hat{\\mathrm{i}}+4 t \\hat{\\mathrm{j}}+2 \\hat{\\mathbf{k}})=4 \\hat{\\mathbf{j}}{/tex}</span><br />
Acceleration of second particle<br />
<span class="math-tex">{tex}\\mathbf{a}_2=\\frac{d}{d t}\\left(\\mathbf{v}_2\\right)=\\frac{d}{d t}\\left(6 t^2 \\hat{\\mathbf{j}}\\right)=12 t \\hat{\\mathbf{j}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore {/tex}</span>&nbsp;Acceleration of centre of mass of two particles system is calculated as<br />
<span class="math-tex">{tex}\\mathbf{a}_{\\mathrm{CM}} =\\frac{m_1 \\mathbf{a}_1+m_2 \\mathbf{a}_2}{m_1+m_2}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{2(4 \\hat{\\mathbf{j}})+3(12 t \\hat{\\mathrm{j}})}{2+3}{/tex}</span><br />
<span class="math-tex">{tex}\\mathbf{a}_{\\mathrm{CM}} =\\left[\\frac{(8+36 t)}{5} \\hat{\\mathrm{j}}\\right] \\mathrm{m} / \\mathrm{s}^2 {/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A metal bar 70 cm long and 4.00 kg in mass supported on two knife-edges placed 10 cm from each end. A 6.00 kg load is suspended at 30 cm from one end. Find the reactions at the knife-edges. (Assume the bar to be of uniform cross-section and homogeneous).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><img alt="" data-imgur-src="0t7WOPP.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1613452654-q55zt9.jpg" style="width: 300px; height: 106px;"/><br/>
The figure shows the rod AB, the positions of the knife edges K<sub>1</sub> and K<sub>2</sub>, the centre of gravity of the rod at G, and the suspended load at P.<br/>
Note the weight of the rod W acts at its centre of gravity G. The rod is uniform in cross-section and homogeneous; hence G is at the centre of the rod; AB = 70 cm. AG = 35 cm, AP = 30 cm, PG = 5 cm, AK<sub>1 </sub>= BK<sub>2</sub> = 10 cm and K<sub>1</sub>G = K<sub>2</sub>G = 25 cm. Also, W = weight of the rod = 4.00 kg and W<sub>1</sub>= suspended load = 6.00 kg;<br/>
R<sub>1</sub> and R<sub>2</sub> are the normal reactions of the support at the knife edges.<br/>
For translational equilibrium of the rod,<br/>
R<sub>1 </sub>+ R<sub>2</sub> - W<sub>1</sub> - W = 0 ..... (i)<br/>
Note W<sub>1</sub> and W act vertically down and R<sub>1</sub> and R<sub>2</sub> act vertically up.<br/>
For considering rotational equilibrium, we take moments of the forces. A convenient point to take moments about is G. The moments of R<sub>2</sub> and W<sub>1</sub> are anticlockwise (+ve), whereas the moment of R<sub>1</sub> is clockwise (-ve).<br/>
For rotational equilibrium,<br/>
-R<sub>1</sub>(K<sub>1</sub>G) + W<sub>1</sub>(PG) + R<sub>2</sub>(K<sub>2</sub>G) = 0 .... (ii)<br/>
It is given that W = 4.00g N and W<sub>1</sub> = 6.00g<br/>
N, where g = acceleration due to gravity. We take g = 9.8 m/s<sup>2</sup>.<br/>
With numerical values inserted, from (i)<br/>
R<sub>1</sub> + R<sub>2</sub> - 4.00g – 6.00g = 0<br/>
or R<sub>1</sub> + R<sub>2</sub> = 10.00g N ....(iii)<br/>
= 98.00 N<br/>
From (ii), -0.25 R<sub>1</sub> + 0.05 W<sub>1</sub> + 0.25 R<sub>2</sub> = 0<br/>
or R<sub>1</sub> - R<sub>2</sub> = 1.2g N = 11.76 N ....(iv)<br/>
From (iii) and (iv), R<sub>1</sub> = 54.88 N,<br/>
R<sub>2</sub> = 43.12 N<br/>
Thus the reactions of the support are about 55 N at K<sub>1</sub> and 43 N at K<sub>2</sub>.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>Four particles of masses 4 kg, 7 kg, 3 kg and 5 kg are respectively located at the four corners A, B, C and D of a square of side 1 m, as shown in Fig. Calculate the moment of inertia of the system about<br/>
<img alt="" data-imgur-src="2Gmb9ka.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082715-hkud7u.jpg" style="width: 150px; height: 140px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>an axis passing through the point of intersection of the diagonals and perpendicular to the plane of the square,</li>
<li>the side AB, and</li>
<li>the diagonal BD.</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here AB = BC = CD = DA = 1 m<br />
<span class="math-tex">{tex}O A=O B=O C=O D=\\frac{1}{2} \\sqrt{1^{2}+1^{2}}=\\frac{1}{\\sqrt{2}} \\mathrm{~m}{/tex}</span></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>M.I. of the system about an axis through O and perpendicular to the plane of the square,<br />
	I = 4(OA)<sup>2&nbsp;</sup>+ 2(O B<sup>2</sup>) + 3(OC)<sup>2&nbsp;</sup>+ 5(OD)<sup>2</sup><br />
	=&nbsp;<span class="math-tex">{tex}(4+2+3+5) \\times\\left(\\frac{1}{\\sqrt{2}}\\right)^{2}=14 \\times \\frac{1}{2}{/tex}</span>&nbsp;= 7 kg m<sup>2</sup></li>
	<li>M.I. of the system about the side AB,<br />
	I = 3(BC)<sup>2&nbsp;</sup>+ 5 (AD)<sup>2&nbsp;</sup>= 3 <span class="math-tex">{tex}\\times{/tex}</span> 1 + 5 <span class="math-tex">{tex}\\times{/tex}</span> 1 = 8 kg&nbsp;m<sup>2</sup></li>
	<li>M.I. of the system about the diagonal BD,<br />
	I = 4 (OA)<sup>2&nbsp;</sup>+ 3(OC)<sup>2</sup><br />
	=&nbsp;<span class="math-tex">{tex}4 \\times \\frac{1}{2}+3 \\times \\frac{1}{2}{/tex}</span>&nbsp;= 3.5 kg m<sup>2</sup></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type: lower-alpha;">
	<li>A child stands at the centre of a turntable with his two arms outstretched. The turntable is set rotating with an angular speed of 40 rev/min. How much is the angular speed of the child if he folds his hands back and thereby reduces his moment of inertia to 2/5 times the initial value? Assume that the turntable rotates without friction.</li>
	<li>Show that the child&#39;s new kinetic energy of rotation is more than the initial kinetic energy of rotation. How do you account for this increase in kinetic energy?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Initial angular velocity,&nbsp;<span class="math-tex">{tex}\\omega _ 1{/tex}</span> = 40 rev/min<br />
	Final angular velocity = <span class="math-tex">{tex}\\omega _ { 2 }{/tex}</span><br />
	The moment of inertia of the boy with stretched hands = I<sub>1</sub><br />
	The moment of inertia of the boy with folded hands = I<sub>2</sub><br />
	The two moments of inertia are related as:<br />
	<span class="math-tex">{tex}I _ { 2 } = \\frac { 2 } { 5 } I _ { 1 }{/tex}</span><br />
	Since no external force and hence external torque acts on the boy, the angular momentum L of the boy is a constant.<br />
	Hence, for the two situations, we can write:<br />
	<span class="math-tex">{tex}I _ { 2 } \\omega _ { 2 } = I _ { 1 } \\omega _ { 1 }{/tex}</span>&nbsp; &nbsp; ( angular momentum L=Iw)<br />
	<span class="math-tex">{tex}\\omega _ { 2 } = \\frac { I _ { 1 } } { I _ { 2 } } \\omega _ { 1 }{/tex}</span><br />
	<span class="math-tex">{tex}= \\frac { I _ { 1 } } { \\frac { 2 } { 5 } I _ { 1 } } \\times 40 = \\frac { 5 } { 2 } \\times 40{/tex}</span><br />
	= 100 rev/min</li>
	<li>&nbsp;The final kinetic energy of rotation, <span class="math-tex">{tex}E _ { F } = \\frac { 1 } { 2 } I _ { 2 } \\omega _ { 2 } ^ { 2 }{/tex}</span><br />
	The initial kinetic energy of rotation, <span class="math-tex">{tex}E _ { I } = \\frac { 1 } { 2 } I _ { 1 } \\omega _ { 1 } ^ { 2 }{/tex}</span><br />
	<span class="math-tex">{tex}\\frac { E _ { F } } { E _ { I } } = \\frac { \\frac { 1 } { 2 } I _ { 2 } \\omega _ { 2 } ^ { 2 } } { \\frac { 1 } { 2 } I _ { 1 } \\omega _ { 1 } ^ { 2 } }{/tex}</span>&nbsp; &nbsp; &nbsp; &nbsp;<br />
	<span class="math-tex">{tex}= \\frac { 2 I _ { 1 } ( 100 ) ^ { 2 } } { 5 I _ { 1 } ( 40 ) ^ { 2 } }{/tex}</span> (given&nbsp;<span class="math-tex">{tex}I _ { 2 } = \\frac { 2 } { 5 } I _ { 1 }{/tex}</span>&nbsp;)<br />
	<span class="math-tex">{tex}= \\frac { 2 } { 5 } \\times \\frac { 100 \\times 100 } { 40 \\times 40 }{/tex}</span><br />
	<span class="math-tex">{tex}= \\frac { 5 } { 2 } = 2.5{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore {/tex}</span>E<sub>F</sub> = 2.5 E<sub>1</sub>&nbsp; Hence, it is clear that final kinetic energy of rotation is more than initial kinetic energy of rotation.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Calculate the moment of inertia of uniform circular disc of mass 500 g, radius 10 cm about</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>diameter of the disc</li>
	<li>the axis tangent to the disc and parallel to its diameter and</li>
	<li>the axis through the centre of the disc and perpendicular to its plane.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>M.I. of the disc about any diameter,<br />
	<span class="math-tex">{tex}I_{d}=\\frac{1}{4} M R^{2}=\\frac{1}{4} \\times 500 \\times(10)^{2}{/tex}</span>&nbsp;= 12500 g cm<sup>2</sup></li>
	<li>By theorem of parallel axes, M.I. of the disc about a tangent parallel to the diameter of the disc,<br />
	I = I<sub>d</sub> + MR<sup>2</sup> =&nbsp;<span class="math-tex">{tex}I=I_{d}+M R^{2}=\\frac{5}{4} M R^{2}=\\frac{5}{4} \\times 500 \\times(10)^{2}{/tex}</span><br />
	= 62500 g cm<sup>2</sup></li>
	<li>M.I. of the disc about an axis through its centre and perpendicular to its plane,<br />
	<span class="math-tex">{tex}I=\\frac{1}{2} M R^{2}=\\frac{1}{2} \\times 500 \\times(10)^{2}{/tex}</span><br />
	= 25000 g cm<sup>2</sup></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A tube of length L is filled completely with an incompressible liquid of mass M and closed at both the ends. The tube is then rotated in a horizontal plane about one of its ends with a uniform angular velocity <span class="math-tex">{tex}\\omega{/tex}</span>. Determine the force exerted by the liquid at the other end.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Consider a small element of the liquid of length dx at a distance x from one end.<br/>
<img alt="" data-imgur-src="gk2EFmd.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082757-kvjrbh.jpg" style="width: 200px; height: 90px;"/><br/>
Mass of the small element = <span class="math-tex">{tex}\\frac{M}{L} d x{/tex}</span><br/>
Centripetal force associated with the element<br/>
<span class="math-tex">{tex}d F=\\left(\\frac{M}{L} d x\\right) x \\omega^{2}{/tex}</span> <span class="math-tex">{tex}\\left[\\because F=m r \\omega^{2}\\right]{/tex}</span><br/>
Force exerted by the liquid = Total centripetal force at the other end<br/>
F = <span class="math-tex">{tex}\\int d F=\\int_{0}^{L} \\frac{M}{L} \\omega^{2} x d x=\\frac{M}{L} \\omega^{2}\\left[\\frac{x^{2}}{2}\\right]_{0}^{L}{/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{M}{L} \\omega^{2} \\frac{L^{2}}{2}=\\frac{1}{2} M \\omega^{2} L{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Find the centre of mass of a uniform</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>half-disc,</li>
	<li>quarter-disc.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let mass of half disc is M.<br />
<img id="Picture 3" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-07/image183.png" /></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>&nbsp;&nbsp;Area of element&nbsp;<span class="math-tex">{tex}= \\frac { \\pi } { 2 } \\left[ ( r + d r ) ^ { 2 } - r ^ { 2 } \\right]{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}= \\frac { \\pi } { 2 } \\left[ r ^ { 2 } + d r ^ { 2 } + 2 r d r - r ^ { 2 } \\right]{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}= \\pi r d r{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Mass of elementary Ring&nbsp;<span class="math-tex">{tex}d m = \\frac { 2 M } { \\pi R ^ { 2 } } . \\pi r d r{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\mathrm { dm } = \\frac { 2 M } { R ^ { 2 } } r. d r{/tex}</span><br />
	Let&nbsp;<span class="math-tex">{tex}( x , y ){/tex}</span>&nbsp;are the co-ordinates of c.m. of this strip&nbsp;<span class="math-tex">{tex}( x , y ) = \\left( 0 , \\frac { 2 r } { \\pi } \\right){/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}x = x _ { c m } = \\frac { 1 } { M } \\int _ { 0 } ^ { R } x d m = \\int _ { 0 } ^ { R } 0 d m = 0{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}y _ { c m } = \\frac { 1 } { M } \\int _ { 0 } ^ { R } y d m = \\frac { 1 } { M } \\int _ { 0 } ^ { R } \\frac { 2 r } { \\pi } \\times \\frac { 2 M } { R ^ { 2 } } r d r{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}= \\frac { 1 } { m } \\cdot \\frac { 4 M } { \\pi R ^ { 2 } } \\int _ { 0 } ^ { R } r ^ { 2 } d r = \\frac { 4 } { \\pi R ^ { 2 } } \\left[ \\frac { r ^ { 3 } } { 3 } \\right] _ { 0 } ^ { R } = \\frac { 4 } { 3 \\pi R ^ { 2 } } \\cdot R ^ { 3 }{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}y _ { c m } = \\frac { 4 R } { 3 \\pi }{/tex}</span>&nbsp;<br />
	So centre of mass of circular half disc <span class="math-tex">{tex}= \\left( 0 , \\frac { 4 R } {3 \\pi } \\right){/tex}</span></li>
	<li>Mass per unit area of quarter disc<br />
	<span class="math-tex">{tex}\\sigma= \\frac { M } { \\frac { \\pi R ^ { 2 } } { 4 } } = \\frac { 4 M } { \\pi R ^ { 2 } }{/tex}</span>.<br />
	<img id="Picture 16" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-07/image198.png" /><br />
	Area of element =&nbsp;<span class="math-tex">{tex}1\\over2 {/tex}</span><br />
	dm =&nbsp;&nbsp;&nbsp;<span class="math-tex">{tex}1\\over2 {/tex}</span><span class="math-tex">{tex}\\pi rdr{/tex}</span><span class="math-tex">{tex}\\times \\sigma{/tex}</span>&nbsp;&nbsp; <span class="math-tex">{tex}= \\frac{ 2Mr} { R^2} dr{/tex}</span>&nbsp;<br />
	X<sub>cm</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\int\\limits_0^Rxdm{/tex}</span><span class="math-tex">{tex}= \\frac {4R}{3\\pi}{/tex}</span>&nbsp;<br />
	Similarly&nbsp; Y<sub>cm</sub>&nbsp;&nbsp;<span class="math-tex">{tex}= \\frac {4R}{3\\pi}{/tex}</span>&nbsp;<br />
	center of mass = (<span class="math-tex">{tex}\\frac {4R}{3\\pi},\\frac {4R}{3\\pi}{/tex}</span>)</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>A particle of mass m is released from point P at x = x<sub>0</sub> on the X-axis from origin O and falls vertically along the Y-axis, as shown in Fig.<br/>
<img alt="" data-imgur-src="lfXCevJ.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082708-zb8nc9.jpg" style="width: 150px; height: 148px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Find the torque t acting on the particle at a time t when it is at point Q with respect to O.</li>
<li>Find the angular momentum L of the particle about O at this time t.</li>
<li>Show that <span class="math-tex">{tex}\\tau=\\frac{d L}{d t}{/tex}</span> in this example.</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>The force of gravity, F= mg&nbsp;produces the torque <span class="math-tex">{tex}\\tau{/tex}</span>. Let <span class="math-tex">{tex}\\vec{r}{/tex}</span> be the position vector of Q. Then the magnitude of the torque is given by<br />
	<span class="math-tex">{tex}\\tau=r F \\sin \\theta{/tex}</span><br />
	<span class="math-tex">{tex}=r \\times m g \\times \\frac{x_{0}}{r}=m g x_{0}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left[\\because \\sin \\theta=\\frac{x_{0}}{r}\\right]{/tex}</span><br />
	The direction of the torque is directed into the plane of paper and perpendicular to it, as shown by&nbsp;<span class="math-tex">{tex}\\otimes{/tex}</span>.</li>
	<li>The magnitude of the angular momentum is&nbsp;<span class="math-tex">{tex}L=r p \\sin \\theta=r m v \\sin \\theta{/tex}</span><br />
	But the velocity v at point Q is given by&nbsp;v = u + at = 0 + gt = gt<br />
	<span class="math-tex">{tex}\\therefore \\quad L=r m g t . \\frac{x_{0}}{r}=m g x_{0} t{/tex}</span><br />
	The direction of angular momentum is the same as that of torque.</li>
	<li>Now L = mgx<sub>0</sub>t<br />
	Differentiating both sides with respect to f, we get<br />
	<span class="math-tex">{tex}\\frac{d L}{d t}=\\frac{d}{d t}\\left(m g x_{0} t\\right)=m g x_{0}=\\tau{/tex}</span><br />
	Hence the relation&nbsp;<span class="math-tex">{tex}\\tau=\\frac{d L}{d t}{/tex}</span>&nbsp;holds in this example.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Obtain an expression for the linear acceleration of a cylinder rolling down an inclined plane and hence find the condition for the cylinder to roll down without slipping.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let M <span class="math-tex">{tex}\\rightarrow{/tex}</span> mass of the solid cylinder R <span class="math-tex">{tex}\\rightarrow{/tex}</span> Radius of the cylinder, <span class="math-tex">{tex}\\theta{/tex}</span> <span class="math-tex">{tex}\\rightarrow{/tex}</span> Angle of inclination of the plane, <span class="math-tex">{tex}\\omega{/tex}</span>-<br />
Angular acceleration of the cylinder.<br />
Various forces acting on the cylinder are:<br />
R - mg cos<span class="math-tex">{tex}\\omega_r{/tex}</span> F = Frictional force acting upwards<br />
<span class="math-tex">{tex}\\omega{/tex}</span> = Net force in the downward directions = f = ma = mg sin<span class="math-tex">{tex}\\omega{/tex}</span> - F<br />
The torque required for the rolling motion of the cylinder is due to frictional forces, which acts tangential to the surface.<br />
<span class="math-tex">{tex}\\tau=r \\times F{/tex}</span> Also <span class="math-tex">{tex}\\tau=I \\alpha=\\frac{I a}{r}[\\therefore a=r \\alpha], \\frac{I a}{r}=r F \\therefore F=\\frac{I a}{r^2}{/tex}</span><br />
<span class="math-tex">{tex}m a-m g \\sin \\theta-\\frac{I a}{r^2} \\rightarrow a\\left(m+\\frac{I}{r^2}\\right){/tex}</span> - mg sin<span class="math-tex">{tex}\\theta{/tex}</span><br />
<span class="math-tex">{tex}\\rightarrow a-\\frac{m g \\sin \\theta}{m+\\frac{I}{r^2}}{/tex}</span><br />
For a solid cylinder, M.I. about the axis <span class="math-tex">{tex}I=\\frac{M r^2}{2} \\therefore a=\\frac{m g \\sin \\theta}{m+\\frac{m r^2}{2} \\times \\frac{1}{r^2}}=\\frac{2}{3} g \\sin \\theta{/tex}</span><br />
Frictional force <span class="math-tex">{tex}=F=\\frac{I a}{r^2}=\\frac{I}{r^2} \\frac{.2}{3} g \\sin \\theta=\\frac{1}{3} n g \\sin \\theta{/tex}</span><br />
Coefficient of friction <span class="math-tex">{tex}=\\frac{F}{R}=\\frac{\\frac{1}{3} m g \\sin \\theta}{m g \\cos \\theta} \\Rightarrow \\mu=\\frac{1}{3} \\tan \\theta{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>The two sides of a step ladder BA and CA are 1.6 m long and hinged at A. A rope DE, 0.5 m is tied half way up. A weight 40 kg is suspended from a point F, 1.2 m from B along the ladder BA. Assuming the floor to be frictionless and neglecting the weight of the ladder, find the tension in the rope and forces exerted by the floor on the ladder. (Take g = 9.8 m/s<sup>2</sup>)<br />
(Hint: Consider the equilibrium of each side of the ladder separately.)<br />
<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/ZMNnO1r.png" style="width: 150px; height: 155px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The given situation can be shown as:<br />
<img id="Picture 107" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch07/5m/image157.jpg" style="width: 200px; height: 119px;" /><br />
N<sub>B</sub> = Force exerted on the ladder by the floor point B<br />
N<sub>C</sub> = Force exerted on the ladder by the floor point C<br />
T = Tension in the rope<br />
BA = CA = 1.6 m<br />
DE = 0. 5 m<br />
BF = 1.2 m<br />
Mass of the weight, m = 40 kg<br />
Draw a perpendicular from A on the floor BC. This intersects DE at mid-point H.<br />
<span class="math-tex">{tex} \\Delta{/tex}</span>ABI and <span class="math-tex">{tex} \\Delta{/tex}</span>AIC are similar<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> BI = IC<br />
Hence, I is the mid-point of BC.<br />
DE || BC<br />
BC = 2 <span class="math-tex">{tex}\\times{/tex}</span> DE = 1 m<br />
AF = BA - BF = 0.4 m &hellip;(i)<br />
D is the mid-point of AB.<br />
Hence, we can write:<br />
<span class="math-tex">{tex}A D = \\frac { 1 } { 2 } \\times B A = 0.8 \\mathrm { m }{/tex}</span> &hellip;.(ii)<br />
Using equations (i) and (ii), we get:<br />
FE = 0.4 m<br />
Hence, F is the mid-point of AD.<br />
FG || DH and F is the mid-point of AD. Hence, G will also be the mid-point of AH.<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>AFG and <span class="math-tex">{tex}\\Delta{/tex}</span>ADH are similar<br />
<span class="math-tex">{tex}\\therefore \\frac { F G } { D H } = \\frac { A F } { A D }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { F G } { D H } = \\frac { 0.4 } { 0.8 } = \\frac { 1 } { 2 }{/tex}</span><br />
<span class="math-tex">{tex}F G = \\frac { 1 } { 2 } D H{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } \\times 0.25 = 0.125{/tex}</span><br />
In <span class="math-tex">{tex}\\Delta{/tex}</span>ADH:<br />
<span class="math-tex">{tex}A H = \\sqrt { A D ^ { 2 } - D H ^ { 2 } }{/tex}</span><br />
<span class="math-tex">{tex}= \\sqrt { ( 0.8 ) ^ { 2 } - ( 0.25 ) ^ { 2 } } = 0.76 m{/tex}</span><br />
For translational equilibrium of the ladder, the upward force should be equal to the downward force.<br />
N<sub>C</sub> + N<sub>B</sub> = mg = 392 &hellip;(iii)<br />
For rotational equilibrium of the ladder, the net moment about A is:<br />
<span class="math-tex">{tex}- N _ { B } \\times B I + m g \\times F G + N _ { c } \\times C I + T \\times A G - T \\times A G = 0{/tex}</span><br />
<span class="math-tex">{tex}- N _ { B } \\times 0.5 + 40 \\times 9.8 \\times 0.125 + N _ { c } \\times ( 0.5 ) = 0{/tex}</span><br />
<span class="math-tex">{tex}\\left( N _ { c } - N _ { B } \\right) \\times 0.5 = 49{/tex}</span><br />
N<sub>c</sub> - N<sub>B</sub> = 98<br />
Adding equations (iii) and (iv), we get:<br />
N<sub>C</sub> = 245 N<br />
N<sub>B</sub> = 147 N<br />
For rotational equilibrium of the side AB, consider the moment about A.<br />
<span class="math-tex">{tex}- N _ { B } \\times B I + m g \\times F G + T \\times A G = 0{/tex}</span><br />
<span class="math-tex">{tex}- 245 \\times 0.5 + 40 + 9.8 \\times 0.125 + T \\times 0.76 = 0{/tex}</span><br />
0.76 T = 122.5 - 49<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> T = 96.7 N<br />
Hence, tension in the given question will be 96.7 N from the above calculation.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A metre scale AB is held vertically with its one end A on the floor and is then allowed to fall.&nbsp;Find the speed of the other end B when it strikes the floor, assuming that the end on the floor does not slip.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let M be the mass and Lbe the length of the metre scale. When the upper end of the rod strikes the floor, its centre of gravity falls through height <span class="math-tex">{tex}\\frac{L}{2}{/tex}</span>.<br/>
<img alt="" data-imgur-src="eyJp5t6.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082718-pmgtjt.jpg" style="width: 200px; height: 100px;"/><br/>
M.I. of the scale about the lower end A, I = M.I. of the scale about the parallel axis through CG + Md<sub>2</sub><br/>
<span class="math-tex">{tex}=I_{0}+M d^{2}=\\frac{M L^{2}}{12}+\\frac{M L^{2}}{4}=\\frac{M L^{2}}{3} \\quad\\left[\\because d=\\frac{L}{2}\\right]{/tex}</span><br/>
Also, <span class="math-tex">{tex}\\omega=\\frac{v}{r}=\\frac{v}{L}{/tex}</span><br/>
Gain in rotational K.E. <br/>
<span class="math-tex">{tex}=\\frac{1}{2} I \\omega^{2}=\\frac{1}{2} \\cdot \\frac{M L^{2}}{3} \\cdot \\frac{v^{2}}{L^{2}}=\\frac{M v^{2}}{6}{/tex}</span><br/>
Now, Gain in rotational K.E. = Loss in P.E.<br/>
<span class="math-tex">{tex}\\frac{M v^{2}}{6}=M g \\cdot \\frac{L}{2} \\quad \\text { or } \\quad v^{2}=3 g l{/tex}</span><br/>
or <span class="math-tex">{tex}v=\\sqrt{3 g L}=\\sqrt{3 \\times 9.8 \\times 1}=5.4 \\mathrm{~ms}^{-1}{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A uniform square plate S (side c) and a uniform rectangular plate R (sides b, a) have identical areas and masses (Figure).<br />
<img id="Picture 21" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-07/image262.png" /><br />
Show that</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li><span class="math-tex">{tex}\\frac { I _ { x R } } { I _ { x s } } &lt; 1{/tex}</span></li>
	<li><span class="math-tex">{tex}\\frac { I _ { y R } } { I _ { y s } } &gt; 1{/tex}</span></li>
	<li><span class="math-tex">{tex}\\frac { I _ { z R } } { I _ { z s } } &gt; 1{/tex}</span></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Moment of inertia, in&nbsp;physics, quantitative measure of the&nbsp;rotational inertia&nbsp;of a body- i.e., the opposition that the body exhibits to having its speed of rotation about an axis altered by the application of a torque (turning force). The axis may be internal or external and may or may not be fixed. The moment of inertia (<em>I</em>), however, is always specified with respect to that axis and is defined as the sum of the products obtained by multiplying the mass of each particle of matter in a given body by the square of its distance from the axis. The unit of moment of inertia is a composite unit of measure. In the International System (SI),&nbsp;m&nbsp;is expressed in kilograms and&nbsp;<em>r</em>&nbsp;in metres, with&nbsp;I&nbsp;(moment of inertia) having the&nbsp;dimension&nbsp;kilogram-metre square.<br />
<span class="math-tex">{tex}m _ { R } = m _ { S } = m{/tex}</span>&nbsp;<br />
Area of square = Area of rectangle<br />
<span class="math-tex">{tex}c ^ { 2 } = a b{/tex}</span>&nbsp;&hellip;(i)<br />
<img id="Picture 23" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-07/image268.png" /></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li><span class="math-tex">{tex}\\because I = m r ^ { 2 }{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\frac { I _ { x R } } { I _ { x z } } = \\frac { m \\cdot \\left( \\frac { b } { 2 } \\right) ^ { 2 } } { m \\left( \\frac { c } { 2 } \\right) ^ { 2 } } = \\frac { b ^ { 2 } } { 4 } \\frac { 4 } { c ^ { 2 } } = \\frac { b ^ { 2 } } { c ^ { 2 } }{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\because c &gt; b{/tex}</span>&nbsp;&nbsp; [from (i)]<br />
	Or&nbsp;<span class="math-tex">{tex}c ^ { 2 } &gt; b ^ { 2 }{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}1 &gt; \\frac { b ^ { 2 } } { c ^ { 2 } } : \\frac { I _ { x R } } { I _ { x s } } &lt; 1{/tex}</span><br />
	Hence proved.</li>
	<li><span class="math-tex">{tex}\\frac { I _ { y R } } { I _ { y s } } = \\frac { m \\left( \\frac { a } { 2 } \\right) ^ { 2 } } { m \\left( \\frac { c } { 2 } \\right) ^ { 2 } } = \\frac { a ^ { 2 } } { 4 } \\cdot \\frac { 4 } { c ^ { 2 } } = \\frac { a ^ { 2 } } { c ^ { 2 } }{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\because a &gt; c \\Rightarrow \\frac { a ^ { 2 } } { c ^ { 2 } } &gt; 1{/tex}</span><br />
	<span class="math-tex">{tex}\\frac { I _ { y R } } { I _ { y s } } &gt; 1{/tex}</span></li>
	<li><span class="math-tex">{tex}I _ { \\mathrm { zR } } - L _ { z s } = m \\left( \\frac { d _ { R } } { 2 } \\right) ^ { 2 } - m \\left( \\frac { d s } { 2 } \\right) ^ { 2 }{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}I _ { z R } - I _ { z S } = \\frac { m } { 4 } \\left[ d _ { R } ^ { 2 } - d _ { S } ^ { 2 } \\right] = \\frac { m } { 4 } \\left[ a ^ { 2 } + b ^ { 2 } - 2 c ^ { 2 } \\right]{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore I _ { z R } - I _ { z S } = \\frac { m } { 4 } \\left( a ^ { 2 } + b ^ { 2 } - 2 a b \\right) = \\frac { m } { 4 } ( a - b ) ^ { 2 }{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left( c _ { 2 } = a b \\right){/tex}</span><br />
	<span class="math-tex">{tex}\\therefore I _ { z R } - I _ { z S } &gt; 0 \\because \\frac { m } { 4 } ( a - b ) ^ { 2 } &gt; 0{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\Rightarrow \\frac { I _ { \\mathrm { zR } } } { I _ { z S } } &gt; 1{/tex}</span>Hence proved.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A man stands on a rotating platform, with his arms stretched horizontally holding a 5 kg weight in each hand. The angular speed of the platform is 30 revolutions per minute. The man then brings his arms close to his body with the distance of each weight from the axis changing from 90cm to 20cm. The moment of inertia of the man together with the platform may be taken to be constant and equal to 7.6 kg m<sup>2</sup>.</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>What is his new angular speed? (Neglect friction.)</li>
	<li>Is kinetic energy conserved in the process? If not, from where does the change come about?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>THE&nbsp;<b>LAW OF CONSERVATION OF ANGULAR MOMENTUM</b>&nbsp;STATES THAT: &quot;When the net external torque acting on a system about a given axis is. zero , the total&nbsp;<b>angular momentum</b>&nbsp;of the system about that axis remains constant.&quot; Mathematically, If then <span class="math-tex">{tex}Iw{/tex}</span>= constant.</p>

<p>In this problem,as all the forces are&nbsp; conservative in nature and external torque on the system is zero so angular momentum of the system will remain conserved although energy of the system may not remain constant if external forces are acting on the system.</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Moment of inertia of the man-platform system I= 7.6 kg m<sup>2</sup><br />
	Moment of inertia when the man stretches his hands to a distance of 90 cm:<br />
	<span class="math-tex">{tex}2 \\times m r ^ { 2 }{/tex}</span><br />
	<span class="math-tex">{tex}= 2 \\times 5 \\times ( 0.9 ) ^ { 2 }{/tex}</span><br />
	= 8.1 kg m<sup>2</sup><br />
	Initial moment of inertia of the system,<span class="math-tex">{tex}I _ { i } = 7.6 + 8.1 = 15.7 \\mathrm { kg } \\mathrm { m } ^ { 2 }{/tex}</span><br />
	Angular speed, <span class="math-tex">{tex}\\omega _ { 1 } = 300 \\text { rev } / \\mathrm { min }{/tex}</span><br />
	Angular momentum, <span class="math-tex">{tex}L _ { i } = I _ { i } \\omega _ { i } = 15.7 \\times 30{/tex}</span> &hellip;&hellip;(i)<br />
	Moment of inertia when the man folds his hands to a distance of 20 cm:<br />
	<span class="math-tex">{tex}2 \\times m ^ { 2 }{/tex}</span><br />
	<span class="math-tex">{tex}= 2 \\times 5 ( 0.2 ) ^ { 2 } = 0.4 \\mathrm { kg } \\mathrm { m } ^ { 2 }{/tex}</span><br />
	Final moment of inertia, <span class="math-tex">{tex}I _ { f } = 7.6 + 0.4 = 8 k g m ^ { 2 }{/tex}</span><br />
	Final angular speed = <span class="math-tex">{tex}\\omega _ { f }{/tex}</span><br />
	Final angular momentum, <span class="math-tex">{tex}L _ { f } = I _ { f } \\omega _ { f } = 0.79 \\omega _ { f }{/tex}</span>&hellip; (<em>ii</em>)<br />
	From the conservation of angular momentum, we have:<br />
	<span class="math-tex">{tex}I _ { i } \\omega _ { i } = I _ { f } \\omega _ { f }{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore \\omega _ { f } = \\frac { 15.7 \\times 30 } { 8 } = 58.88 r e v / \\mathrm { min }{/tex}</span></li>
	<li>Kinetic energy is not conserved in the given process. In fact, with the decrease in the moment of inertia, kinetic energy increases. The additional kinetic energy comes from the work done by the man to fold his hands toward himself.(muscular work done by the man will be converted into kinetic energy)</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A uniform disc of radius <em>R</em>, is resting on a table on its rim. The coefficient of friction between disc and table is <span class="math-tex">{tex}\\mu{/tex}</span> (Figure).<br/>
<img alt="" data-imgur-src="HNQ3RlM.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1613364811-nsj4td.jpg" style="width: 176px; height: 67px;"/><br/>
Now the disc is pulled with a force <span class="math-tex">{tex}\\vec { F }{/tex}</span> as shown in the figure. What is the maximum value of F for which the disc rolls without slipping?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>&nbsp;</strong>Let&nbsp; a = is the linear&nbsp; acceleration of the disc<br />
<span class="math-tex">{tex}\\alpha= {/tex}</span>&nbsp;is the angular acceleration of the disc.<br />
&nbsp;For linear motion, using newton&nbsp;second law of motion we get equation :-<br />
<strong><span class="math-tex">{tex}F - f = M a{/tex}</span>&nbsp;</strong>&hellip;(i)&nbsp;<br />
<img id="Picture 25" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-07/image285.png" style="width: 100px; height: 81px;" /><br />
M&nbsp; = &nbsp;mass of the disc. and&nbsp; f = is the&nbsp; force of friction.<br />
force of friction is responsible for torque. But torque due to F is zero as F is along &lsquo;O&rsquo;.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Torque to disc&nbsp;<span class="math-tex">{tex}\\tau = I _d\\alpha{/tex}</span>&nbsp;<br />
Moment of inertia of the disc,&nbsp;<span class="math-tex">{tex}I _ d = \\frac { 1 } { 2 } M R ^ { 2 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}f \\times R = \\frac { 1 } { 2 } M R ^ { 2 } \\times \\frac { a } { R }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\because a = R \\alpha{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}f R = \\frac { 1 } { 2 } M R a \\Rightarrow M a = 2 f \\rightarrow f = \\frac{Ma}{2}{/tex}</span>&nbsp;&hellip;(ii)<br />
<span class="math-tex">{tex}F - f = 2f \\rightarrow F = 3f \\rightarrow f = \\frac{F}{3}{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\because N = M g{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}f = \\mu M g = \\frac { F } { 3 }{/tex}</span>&nbsp; &nbsp;Hence ,<br />
<span class="math-tex">{tex}F = 3 \\mu M g{/tex}</span>&nbsp;is the maximum force applied on disc to roll on surface without slipping.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1347-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_GRAVITATION = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The effective value of acceleration due to gravity is&nbsp;<span class="math-tex">{tex}\\frac{g}{4}{/tex}</span>&nbsp;at the depth(in respect of R = radius of earth):</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{{3R}}{4}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>we know :<br />
g&prime; =&nbsp;<span class="math-tex">{tex}g\\left( {1 - \\frac{d}{R}} \\right){/tex}</span><br />
<span class="math-tex">{tex} \\Rightarrow \\frac{g}{4} = g\\left( {1 - \\frac{d}{R}} \\right){/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow d = \\frac{{3R}}{4}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">R</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{R}{2}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{R}{4}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>According to Kepler&#39;s laws, which of the following is correct?&nbsp;(where T is the time period of rotation around sun and R is the average distance between planet and sun.)</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}T \\propto R^{\\frac 3 2}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>According to Kepler&#39;s law of periods,<br />
<span class="math-tex">{tex}T^2 \\propto R^{3}{/tex}</span><br />
i.e.,&nbsp;<span class="math-tex">{tex}T \\propto R^{\\frac 3 2}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}T \\propto R^{3}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}T \\propto R^{\\frac 23}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}T \\propto R^{2}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The acceleration due to gravity at a depth d in terms of g(acceleration due to gravity) at radius of the earth R<sub>E</sub> is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}g(d) = g(1 + \\frac{d}{R_E}){/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}g(d) = g(1 - \\frac{d}{ R_E}){/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Acceleration due to gravity at the surface of the earth of radius R<sub>E</sub><br />
<span class="math-tex">{tex}g = G\\frac{M}{{{R_E^2}}} = \\frac{4}{3}\\pi \\rho GR_E{/tex}</span>&nbsp;...(1)<br />
Acceleration due to gravity at depth d from the surface of the earth&nbsp;<br />
<span class="math-tex">{tex}g(d) = \\frac{4}{ 3}\\pi \\rho G(R - d){/tex}</span>&nbsp;...(2)<br />
From (1) &amp; (2), we get<br />
<span class="math-tex">{tex}g(d) = g(1 - \\frac{d}{R_E}){/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}g(d) = g(1 - \\frac{2d}{R_E}){/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}g(d) = g(1 + \\frac{d}{2R_E}){/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>When a body is taken from poles to the equator on the earth, its weight:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">increases</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">decreases</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>g<sub>p</sub>&nbsp;= g and g<sub>e</sub>&nbsp;= g - R<span class="math-tex">{tex}\\omega^2{/tex}</span>&nbsp;&lt; g<sub>p</sub></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">remains the same</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">increases at south pole and decreases at north pole</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the gravitation force on body 1 due to 2 is given by <span class="math-tex">{tex}\\vec {F_{12}}{/tex}</span> and on body 2 due to 1 is given as <span class="math-tex">{tex}\\vec {F_{21}}{/tex}</span>, then</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec {F_{12}}{/tex}</span> = <span class="math-tex">{tex}\\vec {F_{21}}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec {F_{12}}{/tex}</span> = <span class="math-tex">{tex}-\\vec {F_{21}}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Since, gravitational forces are attractive <span class="math-tex">{tex}\\vec {F_{12}}{/tex}</span>&nbsp;is directed opposite to <span class="math-tex">{tex}\\vec {F_{21}}{/tex}</span>&nbsp;and they are also equal in magnitude.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1683876077-kyredk.jpg" style="height:120px; width:200px" /><br />
Hence, <span class="math-tex">{tex}\\vec {F_{21}}{/tex}</span><sub>&nbsp;</sub>=&nbsp;<span class="math-tex">{tex}-\\vec {F_{12}}{/tex}</span><br />
or <span class="math-tex">{tex}\\vec {F_{12}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}-\\vec {F_{21}}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec {F_{12}}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathbf{F}_{21}}{4}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\vec {F_{12}}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathbf{F}_{21}}{2}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>At what altitude (h) above the earth&#39;s surface would the acceleration due to gravity be one-fourth of its value at the earth&#39;s surface?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">h = R</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>At h = R the acceleration due to gravity would be one forth of its value on earth surface.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">h = 4R</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">h = 2R</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">h = 16R</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The height at which the weight of a body becomes <span class="math-tex">{tex}\\frac 1{16}{/tex}</span>th, its weight on the surface of earth (radius R), is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">5R</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">15R</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">3R</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Acceleration due to gravity at a height $h$ from the surface of earth is<br />
<span class="math-tex">{tex}g^{\\prime}=\\frac{g}{\\left(1+\\frac{h}{R}\\right)^{2}}{/tex}</span> ...(i)<br />
where g&nbsp;is the acceleration due to gravity at the surface of earth and R&nbsp;is the radius of earth. Multiplying by m (mass of the body) on both sides in (i),<br />
we get<br />
m <span class="math-tex">{tex}g^{\\prime}=\\frac{m g}{\\left(1+\\frac{h}{R}\\right)^{2}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Weight of body at height h, <span class="math-tex">{tex}W^{\\prime}=m g^{\\prime}{/tex}</span><br />
Weight of body at surface of earth, W = mg<br />
According to question,&nbsp;<span class="math-tex">{tex}W^{\\prime}=\\frac{1}{16} W{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\quad \\frac{1}{16}=\\frac{1}{\\left(1+\\frac{h}{R}\\right)^{2}}{/tex}</span><br />
<span class="math-tex">{tex}\\left(1+\\frac{h}{R}\\right)^{2}=16 \\text { or } 1+\\frac{h}{R}{/tex}</span>&nbsp;= 4<br />
or <span class="math-tex">{tex}\\frac{h}{R}{/tex}</span>&nbsp;= 3&nbsp;or h = 3 R</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">4R</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The escape velocity on a planet is v. If the radius of the planet contracts to <span class="math-tex">{tex}\\frac 14{/tex}</span>th of present value without any change in its mass, the escape velocity will be:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">halved</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">doubled</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Escape speed, v<sub>min</sub> = <span class="math-tex">{tex}\\sqrt{2gR}{/tex}</span><br />
Since we talking about another planet with different radius, gravitational force also changes.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">quadrupled</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">one-fourth</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The ratio of escape velocity at earth (v<sub>e</sub>) to the escape velocity at a planet (u<sub>p</sub>) whose radius and mean density are twice as that of earth is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">1 : 2</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">1 : 2<span class="math-tex">{tex}\\sqrt 2{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}v_{e}=\\sqrt{2 g R}=R \\sqrt{\\frac{8}{3} \\pi G p}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\quad \\frac{\\nu_{s}}{v_{p}}=\\frac{R \\sqrt{\\rho}}{R_{p} \\sqrt{P_{p}}}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{R \\sqrt{\\rho}}{2 R \\ \\times \\ \\sqrt{2 p}}=\\frac{1}{2 \\sqrt{2}}{/tex}</span><br />
= 1 :&nbsp;2<span class="math-tex">{tex}\\sqrt 2{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">1 : 4</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">1 : <span class="math-tex">{tex}\\sqrt 2{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two spheres of masses m and M are situated in air and the gravitational force between them is F. The space around the masses is now filled with a liquid of specific gravity 3.<br />
The gravitational force will now be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">3F</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">F</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The gravitational force between two bodies is independent of the nature of the medium between them.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac F3{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac F9{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the mass of the earth is doubled and its radius halved, then new acceleration due to the gravity g&#39; is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">g '= 4 g</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">g' = 8g</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>g&#39; = 8g</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">g' = g</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">g'= 16g</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the density of earth is doubled keeping its radius constant, then acceleration due to gravity g is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">19.6 m/s<sup>2</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Thus when density of earth is doubled, the acceleration due gravity also doubles and becomes = 9.8m/s<sup>2</sup> <span class="math-tex">{tex}\\times{/tex}</span> 2 = 19.6m/s<sup>2</sup></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">10 m/s<sup>2</sup></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">5 m/s<sup>2</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">2.5 m/s<sup>2</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Escape velocity from a planet is v<sub>e</sub>. If its mass is increased to 8 times and its radius is increased to 2&nbsp;times, then the new escape velocity would be:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">v<sub>e</sub></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{2} v_{e}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">2v<sub>e</sub></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The velocity of projection of the body, at which the body goes out or gravitational field of earth or planet and never returns, is called escape velocity.<br />
v<sub>e&nbsp;</sub>= <span class="math-tex">{tex}\\sqrt{\\frac{2 G M}{R}}{/tex}</span> where G is gravitational constant, M is mass of plant and R<sub>e</sub> is the radius.<br />
When M = 8M, R = 2R,<br />
then v<sub>e&nbsp;</sub>= <span class="math-tex">{tex}\\sqrt{\\frac{2 G(8 M)}{(2 R)}}{/tex}</span>&nbsp;v<sub>e&nbsp;</sub>= <span class="math-tex">{tex}2 \\sqrt{\\frac{2 G M}{R}}{/tex}</span> v<sub>e&nbsp;</sub>= 2v<sub>e</sub>.<br />
Note: Escape velocity is independent of the mass of the body.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}2 \\sqrt{2} v_{e}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Kepler&#39;s second law is based on:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Newton's first law</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Newton's second law</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Special theory of relativity</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">Conservation of angular momentum</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Kepler&#39;s second law states that the radius vector drawn from the sun to a planet sweepts out equal areas in equal intervals of time. It is based on the law of conservation of angular momentum.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The total energy of a satellite is E. What is its P.E.?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">2E</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Potential energy of satellite U = <span class="math-tex">{tex}-\\frac{G M m}{r}{/tex}</span> and total energy of satellite E = <span class="math-tex">{tex}-\\frac{G M m}{2r}{/tex}</span><br />
Therefore, U = 2E</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">-2E</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">E</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">-E</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A body weighs 63 N on the surface of the earth. What is&nbsp;the&nbsp;gravitational force on it due to the earth at a height equal&nbsp;to half the radius of the earth?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Suppose g<sub>h</sub> be the acceleration due to gravity at a height&nbsp;equal to half the radius of the earth h =&nbsp;<span class="math-tex">{tex}\\frac{R}{2}{/tex}</span><br />
As we know,<br />
&nbsp;<span class="math-tex">{tex}\\frac{g_{h}}{g}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\left(\\frac{R}{R+h}\\right)^{2}{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}\\frac{g_{h}}{g}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\left(\\frac{R}{R+\\frac{R}{2}}\\right)^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\left(\\frac{2}{3}\\right)^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{4}{9}{/tex}</span><br />
W =&nbsp;the weight of the body on the surface of the earth<br />
W<sub>h</sub>&nbsp;=&nbsp;the weight of the body at height h.<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>,&nbsp;<span class="math-tex">{tex}\\frac{W_{h}}{W}{/tex}</span>=&nbsp;<span class="math-tex">{tex}\\frac{m g_{h}}{m g}{/tex}</span>=&nbsp;<span class="math-tex">{tex}\\frac{g_{h}}{g}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{4}{9}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow {/tex}</span>&nbsp;W<sub>h=&nbsp;<span class="math-tex">{tex}\\frac{4}{9}W=   \\frac{4}{9} \\times 63 N = 28 N{/tex}</span></sub></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>The escape speed of a projectile on the earth&rsquo;s&nbsp;surface is 11.2 km/s. A body is projected out with&nbsp;thrice this speed. What is the speed of the body&nbsp;far away from the earth? Ignore the presence of&nbsp;the sun and other planets.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>v<sub>e</sub> = escape velocity<br />
v = velocity of the&nbsp;body outside the gravitational field of the earth.<br />
According to the law of conservation of energy,<br />
Initial KE of the body = energy spent by the body in&nbsp;crossing the earth&rsquo;s gravitational field + kinetic energy left&nbsp;with the body once outside the earth&rsquo;s gravitational field,<br />
<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><span class="math-tex">{tex}m(3v_e)^2 ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><span class="math-tex">{tex}m{/tex}</span><span class="math-tex">{tex}v_{e}^{2}{/tex}</span>&nbsp;+&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><span class="math-tex">{tex}mv^2{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow {/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{9}{2}{/tex}</span>m<span class="math-tex">{tex}v_{e}^{2}{/tex}</span>&nbsp;- &nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><span class="math-tex">{tex}m{/tex}</span><span class="math-tex">{tex}v_{e}^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><span class="math-tex">{tex}mv^2{/tex}</span><sup>&nbsp;</sup><br />
<span class="math-tex">{tex}\\Rightarrow {/tex}</span> <span class="math-tex">{tex}v^2 = 8{/tex}</span><span class="math-tex">{tex}v_{c}^{2}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow {/tex}</span> <span class="math-tex">{tex}v ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\sqrt{8 v_{e}^{2}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}2 \\sqrt{2} v_{e}{/tex}</span><br />
As <span class="math-tex">{tex}v_e = 11.2 km/s{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\Rightarrow {/tex}</span>&nbsp;<span class="math-tex">{tex}v ={/tex}</span>&nbsp;<span class="math-tex">{tex}2 \\sqrt{2}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;<span class="math-tex">{tex}11.2 km/s{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow {/tex}</span> v = 31.7 km/s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define the term orbital speed. Establish a relation for orbital speed of a satellite orbiting very close to the surface of the Earth. Find the ratio of this orbital speed and escape speed.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The orbital speed is defined as the speed with which a satellite is revolving in its orbit around a planet.<br />
If a satellite is revolving&nbsp;in a circular orbit having radius r around the Earth of mass M and radius R, then its orbital speed is given by:<br />
<span class="math-tex">{tex}{{\\text{v}}_{{\\text{orb}}}}{\\text{ = }}\\sqrt {\\frac{{{\\text{GM}}}}{{\\text{r}}}} {/tex}</span><br />
If a satellite orbit is very close to the surface of the Earth r&nbsp;<span class="math-tex">{tex} \\simeq{/tex}</span>&nbsp;R = radius of the Earth and then we have<br />
<span class="math-tex">{tex}{{\\text{v}}_{{\\text{orb}}}}{\\text{ = }}\\sqrt {\\frac{{{\\text{GM}}}}{{\\text{R}}}} {\\text{ = }}\\sqrt {{\\text{gR}}} {/tex}</span>&nbsp;&nbsp;<span class="math-tex">{tex}\\left[ {\\therefore \\,\\,g = \\frac{{GM}}{{{R^2}}}} \\right]{/tex}</span>&nbsp; ............(i)<br />
Furthermore, we know that the escape speed of an object is given by:<br />
<span class="math-tex">{tex}{{\\text{v}}_{{\\text{es}}}}{\\text{ = }}\\sqrt {\\frac{{{\\text{2GM}}}}{{\\text{R}}}} {\\text{ = }}\\sqrt {{\\text{2gR}}} {/tex}</span>&nbsp; .............(ii)&nbsp;</p>

<p>From (i) and (ii), we have<br />
<span class="math-tex">{tex}\\frac{{{{\\text{v}}_{{\\text{orb}}}}}}{{{{\\text{v}}_{\\text{s}}}}}{\\text{ = }}\\frac{{\\text{1}}}{{\\sqrt {\\text{2}} }}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Discuss the variation of acceleration due to gravity &lsquo;g&#39; with depth. What happens to the value of g at the centre of the earth?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img alt="" data-imgur-src="hdwhjbd.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/hdwhjbd.png" style="width: 150px; height: 164px;" /><br />
We know that value of acceleration due to gravity g at a point A (say A) on the surface of Earth is given by<br />
<span class="math-tex">{tex}g = \\frac { G M } { R ^ { 2 } } = \\frac { G } { R ^ { 2 } } \\left( \\frac { 4 } { 3 } \\pi R ^ { 3 } \\rho \\right) = \\frac { 4 } { 3 } \\pi G R \\rho{/tex}</span>&nbsp; (<span class="math-tex">{tex}\\because M=\\frac { 4 } { 3 } \\pi R ^ { 3 } \\rho {/tex}</span>&nbsp;)&nbsp; &nbsp;...........(i)<br />
where <span class="math-tex">{tex}\\rho{/tex}</span> is the density of Earth.<br />
Let g<sub>d</sub> be the acceleration due to gravity at any point (say B) at a depth d below the surface of Earth. Then, the force due to the outer shell of thickness d is zero and the gravitational force is only due to the part of Earth having a radius (R - d). If M&#39; be the mass of this part of the sphere, then<br />
<span class="math-tex">{tex}g _ { d } = \\frac { G M ^ { \\prime } } { ( R - d ) ^ { 2 } } = \\frac { G } { ( R - d ) ^ { 2 } } \\cdot \\frac { 4 } { 3 } \\pi ( R - d ) ^ { 3 } \\rho = \\frac { 4 } { 3 } \\pi G ( R - d ) \\rho{/tex}</span>..........(ii)<br />
From (i) and (ii), we have<br />
<span class="math-tex">{tex}\\frac { g _ { d } } { g } = \\frac { R - d } { R } = 1 - \\frac { d } { R } \\Rightarrow g _ { d } = g \\left( 1 - \\frac { d } { R } \\right){/tex}</span><br />
At the centre of Earth, d = R, hence<br />
<span class="math-tex">{tex}g _ { \\text { centre } } = g \\left( 1 - \\frac { R } { R } \\right) = 0{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define acceleration due to gravity. Show that gravity decreases with depth.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The acceleration of freely falling bodies due the force of attraction of the other body is called Acceleration due to gravity. It is a constant quantity for a given attracting body at a given place. Like for earth on or near its surface, the average value of acceleration due to gravity is 9.8 m/s<sup>2</sup>.<br />
<span class="math-tex">{tex}F_{\\text {surface }}=m g=\\frac{G M m}{R^2}{/tex}</span> where M is the total mass of earth and R is the radius of earth.<br />
But <span class="math-tex">{tex}M=\\frac{4 \\pi R^3 \\rho}{3}{/tex}</span><br />
Substituting for M.<br />
<span class="math-tex">{tex}m g=\\frac{4 \\pi G_{p m} R}{3}{/tex}</span><br />
or <span class="math-tex">{tex}g=\\frac{4 \\pi G \\rho R}{3}{/tex}</span> ...(i)<br />
When the object is at a depth d below the surface of earth, it is attracted by the sphere of radius (<strong>R - d</strong>) only as the attraction due to the rest of earth cancel out.<br />
(At the centre of earth, the object would be attracted equally in all directions and the net force experienced by the object and hence the value of g would be zero)<br />
The force on the body. F<sub>depth<sup> </sup></sub>=<sub><sup> </sup> </sub><span class="math-tex">{tex}m g^{\\prime}=\\frac{G M^{\\prime} m}{(R-d)^2}{/tex}</span><br />
<span class="math-tex">{tex}M'=\\frac{4 \\pi \\rho}{3}(R-d)^3{/tex}</span><br />
Substituting for M and simplifying as above, we get<br />
<span class="math-tex">{tex}g^{\\prime}=\\frac{4 \\pi G \\rho}{3}(R-d){/tex}</span> ...(ii)<br />
<span class="math-tex">{tex}\\frac{(2)}{(1)} \\rightarrow \\frac{g^{\\prime}}{g}=\\frac{R-d}{R}=1-\\frac{d}{R}{/tex}</span><br />
or<br />
<span class="math-tex">{tex}g^{\\prime}=g\\left(1-\\frac{d}{R}\\right){/tex}</span><br />
This equation shows that the value of acceleration due to gravity decreases as we go deeper.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>State Kepler&#39;s laws of planetary motion.</li>
	<li>Suppose there existed a planet that went round the sun twice as fast as the earth. What will be its orbital size as compared to that of the earth.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>Kepler&#39;s laws apply: First Law: Planetary orbits are elliptical with the sun at a focus.</li>
	<li>Time taken by the Earth to complete one revolution around the Sun, T<sub>e</sub> = 1 year<br />
	Time taken by the planet to complete one revolution around the Sun,<br />
	<span class="math-tex">{tex}\\mathrm{T}_{\\mathrm{P}}=\\frac{1}{2} \\mathrm{~T}_{\\mathrm{e}}=\\frac{1}{2} \\text { year }{/tex}</span><br />
	Orbital radius of the planet = R<sub>p</sub><br />
	From Kepler&#39;s third law of planetary motion, we can write:<br />
	<span class="math-tex">{tex}\\left(\\frac{\\mathrm{R}_{\\mathrm{p}}}{\\mathrm{R}_{\\mathrm{e}}}\\right)^3=\\left(\\frac{\\mathrm{T}_{\\mathrm{p}}}{\\mathrm{T}_{\\mathrm{e}}}\\right)^2{/tex}</span><br />
	<span class="math-tex">{tex}\\left(\\frac{\\mathrm{R}_{\\mathrm{p}}}{\\mathrm{R}_{\\mathrm{e}}}\\right)=\\left(\\frac{\\mathrm{T}_{\\mathrm{p}}}{\\mathrm{T}_{\\mathrm{e}}}\\right)^{\\frac{2 }{ 3}}{/tex}</span><br />
	<span class="math-tex">{tex}=0.5^{(\\frac{2 }{ 3})}{/tex}</span> = 0.63 R<sub>e</sub><br />
	Hence, the orbital radius of the planet will be 0.63 times of the Earth.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Assuming the earth to be a sphere of uniform&nbsp;mass density, how much would body weigh halfway down to the centre of the earth if it&nbsp;weighted 250 N on the surface?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Weight of the body at the earth&rsquo;s surface<br />
w = mg = 250 N ...(i)<br />
Acceleration due to gravity at depth d from the earth&rsquo;s surface<br />
<span class="math-tex">{tex}g' = g{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left(1-\\frac{d}{R}\\right){/tex}</span><br />
here, <span class="math-tex">{tex}d ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{R}{2}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}g' = g{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left(1-\\frac{R / 2}{R}\\right){/tex}</span>&nbsp;= g&nbsp;<span class="math-tex">{tex}\\left(1-\\frac{1}{2}\\right){/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}g' ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{g}{2}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span> The weight of the body at depth d<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}w' = mg' ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{m g}{2}{/tex}</span><br />
Using Eq. (i) we get<br />
<span class="math-tex">{tex}w' ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{250}{2}{/tex}</span>&nbsp;= 125 N<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Weight of the body will be 125 N.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Discuss the variation of <strong>g</strong></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>with altitude</li>
	<li>with depth</li>
	<li>with latitude: Rotation of earth</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>Variation of Acceleration Due to Gravity with heightThe value of acceleration due to gravity is inversely proportional to the height above the earth&#39;s surface, so it gets reduced with increasing height.</li>
	<li>Gravitational acceleration varies linearly with depth. It decreases with depth and eventually becomes zero at the centre of the Earth.</li>
	<li>Due to rotation of earth centrifugal force acts on the bodies. This opposes acceleration due to gravity. Centrifugal force is maximum at equator and minimum at poles. So g is minimum at equator and maximum at poles.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What do you mean by gravitational potential energy of a body? Obtain an expression for it for a body of mass m lying at distance r from the centre of the earth. Hence write the expression for gravitational potential.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The work obtained in bringing a body from infinity to a point in gravitationa field is called gravitational potential energy.<br />
Force of attraction between the earth and the object when an object is at the distance a from the center of the earth.<br />
<span class="math-tex">{tex}\\mathrm{F}=\\frac{\\mathrm{GmM}}{\\mathrm{x}^2}{/tex}</span><br />
Consider the dW is the small amount of work done in bringing the body without acceleration through the very small distance dx.<br />
dW = Fdx<br />
And total work done to bring the body from infinity to point p which is at distance r from the center of the earth.<br />
<span class="math-tex">{tex}\\mathrm{w}=\\int\\limits_{\\infty}^{\\mathrm{r}} \\frac{\\mathrm{GmM}}{\\mathrm{x}^2} \\mathrm{dx}=-\\frac{\\mathrm{GMm}}{\\mathrm{r}}{/tex}</span><br />
Hence, the gravitational potential energy = <span class="math-tex">{tex}-\\frac{\\mathrm{GMm}}{\\mathrm{r}}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State the universal law of gravitation. Establish the relationship M<sub>e</sub> = <span class="math-tex">{tex} \\frac {gR_e^2}{G}{/tex}</span>, where M<sub>e</sub>&nbsp;and R<sub>e</sub> are the mass and radius of the earth respectively.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The universal law of gravitation states that everybody in the universe attracts every other body with a force which is directly proportional to their masses and inversely proportional to the square of distance between them.<br />
<span class="math-tex">{tex}F \\propto \\frac{m_{1} m_{2}}{r^{2}}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\mathrm{F}=\\frac{G m_{1} m_{2}}{r^{2}}{/tex}</span><br />
For the body of mass&nbsp;m<strong> </strong>on earth.<br />
F = m<sub>g</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{G M_{e} m}{R_{e}^{2}}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}M_e = \\frac {gR_e^2}{G}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Three equal masses of m kg each are fixed at the vertices of an equilateral triangle ABC (in the figure)<br/>
<img alt="" data-imgur-src="Tl7NdFZ.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1612842843-ne7c55.jpg" style="width: 150px; height: 134px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>What is the force acting on a mass 2 m placed at the centroid G of the triangle?</li>
<li>What is the force, if the mass at vertex A is doubled? (Take, AG = BG = CG = 1 m)</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>
	<p>In the given figure,&nbsp;<span class="math-tex">{tex}\\triangle{/tex}</span>&nbsp;ABC<br />
	<img alt="" data-imgur-src="24wXR0n.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/24wXR0n.png" style="width: 200px; height: 167px;" /><br />
	Mass of each body A, B and C = m<br />
	<span class="math-tex">{tex}F_1 ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{G \\times m \\times 2 m}{(1)^{2}}{/tex}</span><span class="math-tex">{tex}= 2Gm^2{/tex}</span><sup>&nbsp;</sup>along GA<br />
	<span class="math-tex">{tex}F_2 ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{G \\times m \\times 2 m}{(1)^{2}}{/tex}</span><span class="math-tex">{tex}= 2Gm^2{/tex}</span> along GB<br />
	<span class="math-tex">{tex}F_3 ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{G \\times m \\times 2 m}{(1)^{2}}{/tex}</span><span class="math-tex">{tex}= 2Gm^2{/tex}</span> along GC<br />
	Then,&nbsp;<span class="math-tex">{tex}\\angle {/tex}</span><span class="math-tex">{tex}EGC ={/tex}</span> <span class="math-tex">{tex}\\angle {/tex}</span><span class="math-tex">{tex}DGB = 30^o{/tex}</span><br />
	Resolving F<sub>2</sub> and F<sub>3</sub> into x and y-axes components.&nbsp;<span class="math-tex">{tex}F_2 cos 30°{/tex}</span> along GD and <span class="math-tex">{tex}F_2 sin 30°{/tex}</span> along GH&nbsp;and <span class="math-tex">{tex}F_3 cos 30°{/tex}</span> along GE and F<sub>3</sub> sin 30&deg; along GH&nbsp;Resultant force on the mass 2m at G.&nbsp;Force at G is <span class="math-tex">{tex}F_1 - (F_2 sin 30° + F_3 sin 30°){/tex}</span><br />
	<span class="math-tex">{tex}F = 2Gm^2 -{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left(2 G m^{2} \\times \\frac{1}{2}+2 G m^{2} \\times \\frac{1}{2}\\right){/tex}</span>&nbsp;= 0</p>
	</li>
	<li>
	<p>When mass at A is&nbsp;2m, then gravitational force on mass&nbsp;2m&nbsp;at G due to mass&nbsp;2m&nbsp;at A is<br />
	Net force, F<sub>1&nbsp;</sub>is G&nbsp;<span class="math-tex">{tex}\\frac{2 m \\times 2 m}{1^{2}}{/tex}</span>&nbsp;= 4Gm<sup>2</sup> along GA<br />
	Net force getting at G due to masses A, B and&nbsp;C is given by:<br />
	<span class="math-tex">{tex}= F_1 - (F_2 sin 30^o + F_3 sin 30^o){/tex}</span><br />
	= <span class="math-tex">{tex}4 Gm^2 -{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left(2 G m^{2} \\times \\frac{1}{2}+2 G m^{2} \\times \\frac{1}{2}\\right){/tex}</span><br />
	<span class="math-tex">{tex}= 2 Gm^2{/tex}</span><sup>&nbsp;</sup>along GA.</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A satellite orbits the earth at a height of 400 km above the surface. How much energy must be expended to rocket the satellite out of the earth&#39;s gravitational influence? Mass of the satellite = 200 kg; mass of the earth = <span class="math-tex">{tex}6.0 \\times 10 ^ { 24 }{/tex}</span> kg; radius of the earth = <span class="math-tex">{tex}6.4 \\times 10 ^ { 6 }{/tex}</span> m; G = <span class="math-tex">{tex}6.67 \\times 10 ^ { - 11 } \\mathrm { N } \\mathrm { m } ^ { 2 } \\mathrm { kg } ^ { - 2 }{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>&nbsp;Me = 6.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>24</sup>&nbsp;kg<br />
Mass of the satellite, m = 200 kg<br />
R<span style="font-size: 10.8333px;">e =&nbsp;</span>6.4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;m<span style="font-size: 10.8333px;">&nbsp;</span><br />
G =&nbsp;6.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-11</sup>&nbsp;Nm<sup>2</sup> kg<sup>-2</sup><br />
Height of the satellite, h = 400 km = 4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup>&nbsp;m = 0.4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup> m<br />
Total energy of the satellite at height h =Kinectic energy + Potential energy<br />
Total energy of the satellite at height h&nbsp;<span class="math-tex">{tex}= \\frac { 1 } { 2 } m v ^ { 2 } + \\left( \\frac { - G M _ { e } m } { R _ { e } + h } \\right){/tex}</span><br />
Orbital velocity of the satellite, <span class="math-tex">{tex}v = \\sqrt { \\frac { G M _ { e } } { R _ { x } + h } }{/tex}</span><br />
Total energy=<span class="math-tex">{tex}\\frac { 1 } { 2 } m \\left( \\frac { G M _ { e } } { R _ { e } + h } \\right) - \\frac { G M _ { e } m } { R _ { e } + h } = - \\frac { 1 } { 2 } \\left( \\frac { G M _ { e } m } { R _ { e } + h } \\right){/tex}</span><br />
Energy required to send the satellite out of its orbit = -(Bound energy)<br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } \\frac { G M _ { e } m } { \\left( R _ { e } + h \\right) }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } \\times \\frac { 6.67 \\ \\times \\ 10 ^ { - 11 } \\ \\times\\ 6.0 \\ \\times \\ 10 ^ { 24 } \\ \\times \\ 200 } { \\left( 6.4 \\ \\times \\ 10 ^ { 6 } \\ + \\ 0.4 \\ \\times \\ 10 ^ { 6} \\right) }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } \\times \\frac { 6.67 \\ \\times \\ 10 ^ { - 11 } \\ \\times \\ 12 \\ \\times \\ 10 ^ { 26 } } { \\left( 6.8 \\ \\times \\ 10 ^ { 6 } \\right) }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } \\times \\frac { 6.67 \\ \\times \\ 12 \\ \\times \\ 10^9 } { 6.8 \\ \\times \\ 10 ^ { 6 } } = 5.9 \\times 10 ^ { 9 } J{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Calculate the escape velocity for an atmospheric particle 1600 km above the earth&#39;s surface, given that the radius of the earth is 6400 km and acceleration due to gravity on the surface of earth is 9.8 ms<sup>-2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>At a height h above the earth&#39;s surface, we have<br />
<span class="math-tex">{tex}v_{e}=\\sqrt{2 g_{h}(R+h)}, g_h=\\frac{g R^{2}}{(R \\ + \\ h)^{2}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\quad v_{e}=\\sqrt{\\frac{2 \\ \\times \\ g R^{2}}{(R+h)^{2}} \\times(R \\ + \\ h)}=\\sqrt{\\frac{2 g R^{2}}{R \\ + \\ h}}{/tex}</span><br />
But g = 9.8 ms<sup>-2</sup>, R = 6.4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;m<br />
h = 1600 km = 1.6&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;m<br />
R + h = (6.4 + 1.6)&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;= 8&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;m<br />
<span class="math-tex">{tex}\\therefore \\quad v_{e}=\\sqrt{\\frac{2 \\ \\times \\ 9.8 \\ \\times\\left(6.4 \\ \\times \\ 10^{6}\\right)^{2}}{8 \\ \\times \\ 10^{6}}}{/tex}</span><br />
= 10.02&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;ms<sup>-1</sup>&nbsp;= 10.02&nbsp;ms<sup>-1</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>Two uniform solid spheres of equal radii R, but mass M and 4M have a centre to centre separation 6R, as shown in Fig. The two spheres are held fixed. A projectile of mass m is projected from the surface of the sphere of mass M directly towards the centre of the second sphere. Obtain an expression for the minimum speed v of the projectile so that it reaches the surface of the second sphere.<br/>
<img alt="" data-imgur-src="XXsOWty.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1613454090-zdw9hw.jpg" style="width: 253px; height: 102px;"/></p></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The projectile is acted upon by two mutually opposing gravitational forces of the two&nbsp;spheres. The neutral point N (see Fig.) is defined as the position where the two forces cancel each other exactly. If ON = r, we have<br />
<span class="math-tex">{tex}\\frac{G M m}{r^{2}}=\\frac{4 G M m}{(6 R-r)^{2}}{/tex}</span><br />
(6R - r)<sup>2</sup> = 4r<sup>2</sup><br />
6R - r =&nbsp;<span class="math-tex">{tex}\\pm{/tex}</span>2r<br />
r = 2R or - 6R<br />
The neutral point r = &ndash; 6R does not concern us in this example. Thus ON = r = 2R. It is sufficient to project the particle with a speed that would enable it to reach N. Thereafter, the greater gravitational pull of 4M would suffice. The mechanical energy at the surface of M is<br />
<span class="math-tex">{tex}E_{l}=\\frac{1}{2} m v^{2}-\\frac{G M m}{R}-\\frac{4 G M m}{5 R}{/tex}</span><br />
At the neutral point N, the speed approaches zero. The mechanical energy at N is purely potential.<br />
<span class="math-tex">{tex}E_{N}=-\\frac{G M m}{2 R}-\\frac{4 G M m}{4 R}{/tex}</span><br />
From the principle of conservation of mechanical energy<br />
<span class="math-tex">{tex}\\frac{1}{2} v^{2}-\\frac{G M}{R}-\\frac{4 G M}{5 R}=-\\frac{G M}{2 R}-\\frac{G M}{R}{/tex}</span><br />
or&nbsp;<br />
<span class="math-tex">{tex}v^{2}=\\frac{2 G M}{R}\\left(\\frac{4}{5}-\\frac{1}{2}\\right){/tex}</span><br />
<span class="math-tex">{tex}v=\\left(\\frac{3 G M}{5 R}\\right)^{1 / 2}{/tex}</span><br />
A point to note is that the speed of the projectile is zero at N, but is nonzero when it strikes the heavier sphere 4M.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is escape velocity? Obtain the expression for the escape velocity on Earth. Why is it that there is no atmosphere on the Moon? Explain.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The minimum velocity needed by an object to escape from the gravitational force of the earth is known as the escape velocity and moon also have gravity and atmosphere.<br />
Mathematically, Escape speed <span class="math-tex">{tex}v _ { \\mathrm { ss } } = \\sqrt { \\frac { 2 G M } { R } } = \\sqrt { 2 g } R{/tex}</span>, where M = mass of Earth and R = radius of the Earth. Value of escape speed from Earth&#39;s surface is found to have a value of 11.2 km s<sup>-1</sup><br />
Value of g and consequently value of escape velocity at Moon surface is quite small. So, gas molecules slowly and steadily escaped from the Moon&#39;s atmosphere and with the passage of time practically no atmosphere is left on the Moon&#39;s surface.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Derive an expression for g (acceleration due to gravity) at a depth d from the surface of earth. Consider the earth as a sphere of uniform mass density. What happens to <strong>g</strong> at the centre of earth.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Consider M as the mass of the earth, R be the radius of the earth, g<sub>d</sub> be acceleration due to gravity at depth &prime;d&prime; from the earth&#39;s surface, and g be gravitational acceleration on the earth&#39;s surfaces, be the density of the earth.&prime;p&#39; be the point inside the earth at depth &prime;d&prime; from earth surfaces.<br />
<span class="math-tex">{tex}F_{\\text {surface }}=m g=\\frac{G M m}{R^2}{/tex}</span> where M is the total mass of earth and R is the radius of earth.<br />
But <span class="math-tex">{tex}M=\\frac{4 \\pi R^3 \\rho}{3}{/tex}</span><br />
Substituting for M.<br />
<span class="math-tex">{tex}m g=\\frac{4 \\pi G_{p m} R}{3}{/tex}</span><br />
or <span class="math-tex">{tex}g=\\frac{4 \\pi G \\rho R}{3}{/tex}</span> ...(i)<br />
When the object is at a depth d below the surface of earth, it is attracted by the sphere of radius (<strong>R - d</strong>) only as the attraction due to the rest of earth cancel out.<br />
(At the centre of earth, the object would be attracted equally in all directions and the net force experienced by the object and hence the value of g would be zero)<br />
The force on the body. F<sub>depth<sup> </sup></sub>=<sub><sup> </sup> </sub><span class="math-tex">{tex}m g^{\\prime}=\\frac{G M^{\\prime} m}{(R-d)^2}{/tex}</span><br />
<span class="math-tex">{tex}M'=\\frac{4 \\pi \\rho}{3}(R-d)^3{/tex}</span><br />
Substituting for M and simplifying as above, we get<br />
<span class="math-tex">{tex}g^{\\prime}=\\frac{4 \\pi G \\rho}{3}(R-d){/tex}</span> ...(ii)<br />
<span class="math-tex">{tex}\\frac{(2)}{(1)} \\rightarrow \\frac{g^{\\prime}}{g}=\\frac{R-d}{R}=1-\\frac{d}{R}{/tex}</span><br />
or<br />
<span class="math-tex">{tex}g^{\\prime}=g\\left(1-\\frac{d}{R}\\right){/tex}</span><br />
This equation shows that the value of acceleration due to gravity decreases as we go deeper.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Obtain an expression for escape velocity from energy considerations.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Consider a body of mass m projected from the surface of Earth with a speed v<sub>es</sub>, which is just sufficient to take the body up to infinite distance away.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\text{initial K.E. of body }K_1 ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{1}{2}mv_{es}^2{/tex}</span><br />
<span class="math-tex">{tex}\\text{ initial P.E. of body}\\ U_1 ={/tex}</span> -<span class="math-tex">{tex}\\frac{GMm}{R}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Total energy of the body at the surface of Earth <span class="math-tex">{tex}= K_1 + U_1 ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{1}{2}mv_{es}^2{/tex}</span>&nbsp;-&nbsp;<span class="math-tex">{tex}\\frac{GMm}{R}{/tex}</span><br />
When the body reaches&nbsp; infinity, its final velocity&nbsp; and hence kinetic energy is zero i.e.<span class="math-tex">{tex} K{/tex}</span><sub><span class="math-tex">{tex}\\infty{/tex}</span></sub>= 0<br />
Also <span class="math-tex">{tex}U{/tex}</span><sub><span class="math-tex">{tex}\\infty{/tex}</span>&nbsp;</sub>= -<span class="math-tex">{tex}\\frac{GMm}{\\infty}{/tex}</span>= 0<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Total energy of body at infinity = 0<br />
<span class="math-tex">{tex}\\text{According to the conservation law of mechanical energy, }{/tex}</span><br />
<span class="math-tex">{tex}\\frac{1}{2}mv_{es}^2{/tex}</span>&nbsp;-&nbsp;<span class="math-tex">{tex}\\frac{GMm}{R}{/tex}</span>&nbsp;= 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{1}{2}mv_{es}^2{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{GMm}{R}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}v_{es} ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\sqrt {\\frac{{{\\text{2GM}}}}{{\\text{R}}}} {/tex}</span><br />
As g =&nbsp;<span class="math-tex">{tex}\\frac{GM}{R^2}{/tex}</span>,</p>

<p><span class="math-tex">{tex}\\Rightarrow {/tex}</span> <span class="math-tex">{tex}v_{es} ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\sqrt {{\\text{2gR}}} {/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define orbital velocity. Derive an expression for the orbital velocity of a satellite revolving around a planet.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Orbital velocity is the velocity at which a body revolves around the other body. Objects that travel in the uniform circular motion around the Earth are called to be in orbit.<br />
For circular orbit<br />
F = <span class="math-tex">{tex}\\frac{m V_0^2}{r}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\frac{G M m}{r^2}=\\frac{m v^2}{r}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow V_0=\\sqrt{\\frac{G M}{r}}{/tex}</span><br />
Now for satellite very new to earth surface<br />
<span class="math-tex">{tex} r \\approx R {/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow V_e=\\sqrt{\\frac{G M}{R}}{/tex}</span><br />
Now escape velocity at earth surface<br />
<span class="math-tex">{tex}V_e=\\sqrt{\\frac{2 G M}{R}}=\\sqrt{2} V_0{/tex}</span><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1705052332-npaegz.jpg" style="height:138px; width:143px" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define gravitational potential energy of a body. Derive an expression for the gravitational potential energy of body of mass &#39;m&#39; located at a distance &#39;r&#39; from the centre of the Earth.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><u><strong>Gravitational potential energy</strong></u>: The gravitational potential energy of a body at a point is defined as the amount of work done is bringing the body from infinity to that point in the gravitational field of Earth.<br />
Let us find the gravitational potential energy of a body of mass m situated at a point A at a distance r from centre of Earth of mass M and radius R.<br />
Let at any instant the body be at point P situated at a distance x from centre of Earth, then gravitational force acting on the body is given as:<br />
F =&nbsp;<span class="math-tex">{tex}\\frac{GMm}{x^2}{/tex}</span><br />
If the body be moved through an infinitesimally small distance dx from point P to Q, then work done can be written as:<br />
dW = F dx =&nbsp;<span class="math-tex">{tex}\\frac{GMm}{x^2}{/tex}</span>dx .................(i)<br />
Therefore,&nbsp;Total work done in bringing the body from&nbsp;<span class="math-tex">{tex}\\infty{/tex}</span>&nbsp;to point A (i,e., x = r) is<br />
<span class="math-tex">{tex}{\\text{W = }}\\smallint {\\text{dW = }}\\mathop {\\mathop \\smallint \\limits_{{\\text{x}}\\,{\\text{ = }}\\,\\infty } }\\limits^{{\\text{x}}\\,{\\text{ = }}\\,{\\text{r}}} \\frac{{{\\text{GMm}}}}{{{{\\text{x}}^{\\text{2}}}}}{\\text{dx = }}\\left[ {{\\text{ - }}\\frac{{{\\text{GMm}}}}{{\\text{x}}}} \\right]_{\\infty}^{\\text{r}}{\\text{ = - }}\\frac{{{\\text{GMm}}}}{{\\text{r}}}{/tex}</span>&nbsp; &nbsp;[by integrating equation (i)]<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;gravitational potential energy of the given body is given by:</p>

<p>&nbsp; &nbsp;U = -<span class="math-tex">{tex}\\frac{GMm}{r}{/tex}</span>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define acceleration due to gravity. Derive expression for the variation of <strong>g</strong> with height from the surface of the earth.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The acceleration of freely falling bodies due the force of attraction of the other body is called Acceleration due to gravity. It is a constant quantity for a given attracting body at a given place. Like for earth on or near its surface, the average value of acceleration due to gravity is 9.8 m/s<sup>2</sup>.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1705925701-84sn6t.jpg" style="height:183px; width:120px" /><br />
<span class="math-tex">{tex}g^{\\prime}=\\frac{\\mathrm{GM}}{\\left(\\mathrm{R}_e+h\\right)^2} ; g^{\\prime}=\\frac{\\mathrm{GM}}{\\mathrm{R}_e^2\\left(1+\\frac{h}{\\mathrm{R}}\\right)^2}{/tex}</span><br />
<span class="math-tex">{tex}g^{\\prime}=\\frac{\\mathrm{GM}}{\\mathrm{R}_e^2}\\left(1+\\frac{h}{\\mathrm{R}_e}\\right)^{-2}{/tex}</span><br />
If h &lt; &lt; R<sub>e</sub>: We can use Binomial expansion. Taking the terms up to first order<br />
(1 + x)<sup>n</sup> = 1 + nx<br />
<span class="math-tex">{tex}\\left[1+\\frac{h}{\\mathrm{R}_e}\\right]^{-2}=\\left[1-2\\left(\\frac{h}{\\mathrm{R}_e}\\right)\\right]{/tex}</span><br />
Replacing this value and we get<br />
<span class="math-tex">{tex}g^{\\prime}=\\frac{\\mathrm{GM}}{\\mathrm{R}_e^2}\\left[1-\\frac{2 h}{\\mathrm{R}_e}\\right]{/tex}</span><br />
<span class="math-tex">{tex}g^{\\prime}=g\\left(1-2 \\frac{h}{\\mathrm{R}_e}\\right){/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that the velocity with which an object is to be projected from the surface of the Earth so that it may just overcome the gravitational pull of the Earth&nbsp;is&nbsp;<span class="math-tex">{tex}\\sqrt {\\frac{{{\\text{2GM}}}}{{\\text{R}}}} {/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let us consider the particle is at any moment situated at point P at a distance x from the centre of Earth.<br/>
The attractive force <span class="math-tex">{tex}\\mathop {\\text{F}}\\limits^ \\to {/tex}</span> exerted by the Earth on the body is given by <span class="math-tex">{tex}\\mathop {\\text{F}}\\limits^ \\to {/tex}</span> = <span class="math-tex">{tex}\\frac{GMm}{x^2}{/tex}</span> along OP.<br/>
Therefore, force applied against the gravitational force <span class="math-tex">{tex}\\mathop {\\text{F}}\\limits^ \\to {/tex}</span>' = - <span class="math-tex">{tex}\\mathop {\\text{F}}\\limits^ \\to {/tex}</span> = <span class="math-tex">{tex}-\\frac{GMm}{x^2}{/tex}</span> along OP.<br/>
If the given particle is moved from P to Q through a small distance dx, then<br/>
Work done by the particle against the gravitational force is given by<br/>
<span class="math-tex">{tex}dW ={/tex}</span> - <span class="math-tex">{tex}\\mathop {\\text{F}}\\limits^ \\to {/tex}</span>' . dx = <span class="math-tex">{tex}\\frac{GMm}{x^2}{/tex}</span> dx<br/>
<img alt="" data-imgur-src="F3PV9rv.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/F3PV9rv.png" style="width: 100px; height: 200px;"/></p>
<p>Total work done to displace the body from the surface of the earth to infinity can be obtained by integrating the above equation.<br/>
Therefore, <span class="math-tex">{tex}{\\text{W = }}\\mathop {\\mathop \\smallint \\limits_{{\\text{x}}\\,{\\text{ = }}\\,{\\text{R}}} }\\limits^{{\\text{x}}\\,{\\text{ = }}\\,\\infty } \\frac{{{\\text{GMm}}}}{{{{\\text{x}}^{\\text{2}}}}}{\\text{dx}}\\,{\\text{ = }}\\,{\\text{ - }}\\left[ {\\frac{{{\\text{GMm}}}}{{\\text{x}}}} \\right]_{\\text{R}}^\\infty {\\text{ = }}\\frac{{{\\text{GMm}}}}{{\\text{R}}}\\,{/tex}</span><br/>
Due to this work done, the kinetic energy of the body decreases. In the limiting case, the initial kinetic energy of the body is just sufficient to do work to take the body from Earth's surface to infinity. Hence<br/>
<span class="math-tex">{tex}\\frac{{\\text{1}}}{{\\text{2}}}{\\text{mv}}_{{\\text{es}}}^{\\text{2}}{\\text{ = }}\\frac{{{\\text{GMm}}}}{{\\text{R}}}{/tex}</span><br/>
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex}v_{es} ={/tex}</span> <span class="math-tex">{tex}\\sqrt {\\frac{{{\\text{2GM}}}}{{\\text{R}}}}{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is meant by acceleration due to gravity? Obtain an expression for it in terms of mass of the earth and gravitational constant. Explain how the mass and the density of the earth can be obtained from the knowledge of G.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ul>
	<li>Acceleration due to gravity is the acceleration gained by an object due to gravitational force. Its SI unit is m/s<sup>2</sup>.</li>
	<li>The force (F) of gravitational attraction on a body of mass m due to earth of mass M and radius R is given by<br />
	<span class="math-tex">{tex}F=G \\frac{m M}{R^2}{/tex}</span> ...(i)<br />
	We know from Newton&#39;s second law of motion that the force is the product of mass and acceleration.<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span> F = ma<br />
	But the acceleration due to gravity is represented by the symbol g. Therefore, we can write<br />
	F = mg ...(ii)<br />
	From the equation (i) and (ii), we get<br />
	<span class="math-tex">{tex}m g=G \\frac{m M}{R^2}{/tex}</span> or <span class="math-tex">{tex}g=\\frac{G M}{R^2}{/tex}</span>...(iii)<br />
	When body is at a distance &#39;r&#39; from centre of the earth then g <span class="math-tex">{tex}=\\frac{G M}{r^2}{/tex}</span>.</li>
	<li>The acceleration due to gravity on earth surface is given as<br />
	<span class="math-tex">{tex}\\mathrm{g}_{\\mathrm{e}}=\\frac{\\mathrm{GM}_{\\mathrm{e}}}{\\mathrm{R}_{\\mathrm{e}}^2}{/tex}</span><br />
	or <span class="math-tex">{tex}M_e=\\frac{g_s R_e^2}{G}=\\frac{9.8 \\times\\left(6.37 \\times 10^6\\right)^2}{6.67 \\times 10^{-11}}{/tex}</span><br />
	= 6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>24</sup> kg</li>
</ul></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Three mass points each of mass m are placed at the vertices of an equilateral triangle of side l. What is the gravitational field and potential due to three masses at the centroid of the triangle?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>In Figure, three mass points, each of mass m, are placed at three vertices of an equilateral <span class="math-tex">{tex}\\triangle{/tex}</span> ABC of side l. If O is the centroid of the triangle, then<br/>
OA = OB = OC.<br/>
<img alt="" data-imgur-src="tFzvoIG.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082772-3vujbz.jpg" style="width: 150px; height: 155px;"/><br/>
From the right <span class="math-tex">{tex}\\triangle{/tex}</span>ODB,<br/>
<span class="math-tex">{tex}\\cos 30^{\\circ}=\\frac{B D}{O B}=\\frac{\\frac l 2}{O B}{/tex}</span><br/>
or OB = <span class="math-tex">{tex}\\frac{\\frac 1 2}{\\cos 30^{\\circ}}=\\frac{\\frac l 2}{\\frac {\\sqrt{3}}2}=\\frac{l}{\\sqrt{3}}{/tex}</span><br/>
Gravitational fields at O due to mass points at A, B and C are as follows:<br/>
E<sub>1</sub> = <span class="math-tex">{tex}\\frac{G m}{(O A)^{2}}=\\frac{G m}{(\\frac l {\\sqrt{3}})^{2}}=\\frac{3 G m}{l^{2}}{/tex}</span>, along <span class="math-tex">{tex}\\vec{O A}{/tex}</span><br/>
E<sub>2</sub> = <span class="math-tex">{tex}\\frac{G m}{(O B)^{2}}=\\frac{3 G m}{l^{2}}{/tex}</span>, along <span class="math-tex">{tex}\\vec{O B}{/tex}</span><br/>
E<sub>3</sub> = <span class="math-tex">{tex}\\frac{G m}{(O C)^{2}}=\\frac{3 G m}{l^{2}}{/tex}</span>, along <span class="math-tex">{tex}\\vec{O C}{/tex}</span><br/>
Angle between <span class="math-tex">{tex}\\vec{E}_{1} \\text { and } \\vec{E}_{2}{/tex}</span> is 120°. Their Resultant is<br/>
E = <span class="math-tex">{tex}\\sqrt{E_{1}^{2}+E_{2}^{2}+2 E_{1} E_{2} \\cos 120^{\\circ}}{/tex}</span><br/>
= <span class="math-tex">{tex}\\frac{3 G m}{l^{2}} \\sqrt{1+1+2 \\times\\left(-\\frac{1}{2}\\right)}=\\frac{3 G m}{l^{2}}{/tex}</span>, along <span class="math-tex">{tex}\\vec {OF}{/tex}</span><br/>
Clearly, <span class="math-tex">{tex}\\vec{E}{/tex}</span> is equal and opposite to <span class="math-tex">{tex}\\vec{E}_3{/tex}</span>, hence the resultant gravitational field at O is zero.<br/>
As the gravitational potential is a scalar quantity, so the total gravitational potential at O is<br/>
V = V<sub>1</sub> + V<sub>2</sub> + V<sub>3</sub> = <span class="math-tex">{tex}-\\frac{G m}{O A}-\\frac{G m}{O B}-\\frac{G m}{O C}{/tex}</span><br/>
= <span class="math-tex">{tex}-\\frac{3 G m}{O A}=-\\frac{3 G m}{\\frac l{\\sqrt{3}}} \\quad\\left[\\because O A=O B=O C=\\frac{l}{\\sqrt{3}}\\right]{/tex}</span><br/>
or V = <span class="math-tex">{tex}-3 \\sqrt{3} \\frac{G m}{l}{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A rocket is fired from the earth towards the sun. At what distance from the earth&#39;s centre is the gravitational force on the rocket zero? Mass of the sun = <span class="math-tex">{tex} 2 \\times 10 ^ { 30 }{/tex}</span> kg, mass of the earth = <span class="math-tex">{tex} 6 \\times 10 ^ { 24 }{/tex}</span> kg. Neglect the effect of other planets etc. (orbital radius = <span class="math-tex">{tex} 1.5 \\times 10 ^ { 11 }{/tex}</span> m).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>There is a point called the La-Grange L1 point roughly in a million miles from earth towards the sun. It&nbsp;could be considered that the net gravitational&nbsp;force at this point is zero. Practically it can never be zero. However, there are places where there is so little gravity that it becomes an insignificant factor, and we consider gravity at that point to be zero.<br />
Given parameters are:<br />
Mass of the Sun, <span class="math-tex">{tex}M _ { s } = 2 \\times 10 ^ { 30 } \\mathrm { kg }{/tex}</span><br />
Mass of the Earth, <span class="math-tex">{tex}M _ { \\theta } = 6 \\times 10 ^ { 24 } \\mathrm { kg }{/tex}</span><br />
Orbital radius, <span class="math-tex">{tex}r = 1.5 \\times 10 ^ { 11 } \\mathrm { m }{/tex}</span><br />
Mass of the rocket = m<br />
<img id="Picture 22" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch08/5m/image029.jpg" style="width: 150px; height: 67px;" /><br />
Let&#39;s suppose that x be the distance from the centre of the Earth where the gravitational force acting on satellite P becomes zero.<br />
From Newton&#39;s law of gravitation, we can equate gravitational forces acting on satellite P under the influence of the Sun and the Earth as:<br />
<span class="math-tex">{tex}\\frac { G m M _ { s } } { ( r - x ) ^ { 2 } }= \\frac { GmM _ { \\theta } } { x ^ { 2 } }{/tex}</span><br />
<span class="math-tex">{tex}\\left( \\frac { r - x } { x } \\right) ^ { 2 } = \\frac { M _ { s } } { M _ { \\theta } }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { r - x } { x } = \\left( \\frac { 2 \\times 10 ^ { 30 } } { 6\\times 10 ^ { 24 } } \\right) ^ { \\frac { 1 } { 2 } } = 577.35{/tex}</span><br />
1.5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>11</sup>&nbsp;- x = 577.35 x<br />
577.35 x&nbsp;= 1.5&nbsp;&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>11</sup><br />
<span class="math-tex">{tex}x = \\frac { 1.5 \\ \\times \\ 10 ^ { 11 } } { 578.35 }{/tex}</span>&nbsp;= 2.59 &nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>8 </sup>m.<br />
Now we can say that this is the distance at which the gravitational force on the rocket from earth&#39;s centre is zero.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Two heavy spheres each of mass 100 kg and radius 0.10 m are placed 1.0 m apart on a horizontal table. What is the gravitational force on a sphere of mass m placed at midpoint of the line joining spheres? What is the potential at the mid-point of the line joining the centers of the spheres? Is an object placed at that point in equilibrium? If so, is the equilibrium stable or unstable?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The situation is represented in the given figure:<br />
<img alt="" data-imgur-src="EfC31SH.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/EfC31SH.png" style="width: 150px; height: 65px;" /><br />
Mass of each sphere, M = 100 kg.&nbsp;Separation between spheres r =1.0 m.&nbsp; X is the midpoint between the spheres. Gravitational force on mass m,&nbsp;<span class="math-tex">{tex}{\\;{F_{net}} = {F_A} + {F_B}}{/tex}</span>&nbsp;where&nbsp;<span class="math-tex">{tex}{{F_A} = \\frac{{GMm}}{{\\frac{r}{2}}}}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}{\\;{F_B} = \\frac{{GMm}}{{\\frac{r}{2}}}}{/tex}</span> &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<br />
Both the forces are attractive. They are equal in magnitude and opposite in direction. Hence net force on &#39;m&#39; is zero.&nbsp; gravitational potential at X:<br />
<span class="math-tex">{tex}V=\\frac{-GM}x\\;here\\;x=\\frac r2{/tex}</span>&nbsp;for each&nbsp;sphere<br />
<em><span class="math-tex">{tex}V_{net}=\\frac{-GM}{\\left(\\frac r2\\right)}-\\frac{GM}{\\left(\\frac r2\\right)}=-4\\frac{GM}r{/tex}</span>&nbsp;</em><br />
<em><span class="math-tex">{tex}V_{net}=\\frac{4\\times6.67\\times10^{-11}\\times100}r{/tex}</span></em>&nbsp;<br />
<em><span class="math-tex">{tex}V_{net}=-2.67\\times10^{-3}J/kg{/tex}</span>&nbsp;&nbsp;</em><br />
​​​​​​​Any object placed at point X will be in equilibrium state, but the equilibrium is unstable. This is because any change in the position of the object will change the effective force in that direction.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Show the nature of the following graph for a satellite orbiting the&nbsp;earth.<br />
<img id="Picture 7" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-08/image092.png" /></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>K.E.&nbsp;<em>versus&nbsp;</em>orbital radius&nbsp;<em>R</em>.</li>
	<li>P.E.&nbsp;<em>versus&nbsp;</em>orbital radius&nbsp;<em>R</em>.</li>
	<li>T.E.&nbsp;<em>versus&nbsp;</em>orbital radius&nbsp;<em>R.</em></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Mass of earth&nbsp;<span class="math-tex">{tex}= M _ { e }{/tex}</span><br />
Radius of orbit of satellite= R<br />
Mass of satellite = m<br />
Orbital Velocity&nbsp;<span class="math-tex">{tex}\\nu _ { 0 } = \\sqrt { \\frac { G M } { R } }{/tex}</span>&nbsp;</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>E<sub>K</sub>&nbsp;versus R:<br />
	<span class="math-tex">{tex}K E _ { k } = \\frac { 1 } { 2 } m v _ { 0 } ^ { 2 } = \\frac { 1 } { 2 } m \\cdot \\frac { G M } { R } = \\frac { G M m } { 2 R }{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}E _ { K } \\propto \\frac { 1 } { R }{/tex}</span>&nbsp;we can say that kinetic energy is inversely proportional to R. It means the KE decreases exponentially with radius. The graph will be a rectangular hyperbola. Hence, the variation of kinetic energy versus orbital radius is shown in graph.<span class="math-tex">{tex}i . e . , E _ { k }{/tex}</span>&nbsp;decreases exponentially with R.</li>
	<li>E<sub>p</sub>&nbsp;versus R:<strong>&nbsp;</strong>potential energy is twice of kinetic energy and negative sign implies that graph is downward hyperbola.&nbsp;<span class="math-tex">{tex}E _ { p } = \\frac { - G M m } { R }{/tex}</span>&nbsp;<span class="math-tex">{tex}E _ { p } \\propto - \\frac { 1 } { R }{/tex}</span></li>
	<li>T.E. versus R:&nbsp;Negative total energy, E signifies that earth and the satellite is a bounded system.<br />
	If E &ge; U, the satellite will be free from earth&rsquo;s gravity<strong>&nbsp;<span class="math-tex">{tex}{/tex}</span></strong></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A rocket is fired &#39;vertically&#39; from the surface of mars with a speed of 2 km s<sup>-1</sup>. If 20% of its initial energy is lost due to Martian atmospheric resistance, how far will the rocket go from the surface of mars before returning to it? Mass of mars =&nbsp;<span class="math-tex">{tex}6.4 \\times 10 ^ { 23 }{/tex}</span> kg; radius of mars = 3395 km; <span class="math-tex">{tex}G = 6.67 \\times 10 ^ { - 11 } \\mathrm { Nm } ^ { 2 } \\mathrm { kg } ^ { - 2 }{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Initial velocity of the rocket is given by, v = 2 km/s = <span class="math-tex">{tex}2 \\times 10 ^ { 3 }{/tex}</span>m/s<br />
Mass of Mars is given by, <span class="math-tex">{tex}M = 6.4 \\times 10 ^ { 23 } \\mathrm { kg }{/tex}</span><br />
Radius of Mars is given by, R = 3395 km =&nbsp;<span class="math-tex">{tex}3.395 \\times 10 ^ { 6 }{/tex}</span> m<br />
<span class="math-tex">{tex}G = 6.67 \\times 10 ^ { - 11 } \\mathrm { Nm } ^ { 2 } \\mathrm { kg } ^ { - 2 }{/tex}</span><br />
Mass of the rocket is given by = m<br />
K. E<sub>i</sub>&nbsp;<span class="math-tex">{tex}= \\frac { 1 } { 2 } m v ^ { 2 }{/tex}</span><br />
P. E<sub>i</sub><span class="math-tex">{tex}= \\frac { - G M m } { R }{/tex}</span><br />
Total initial energy is&nbsp;&nbsp;<span class="math-tex">{tex}= (\\frac { 1 } { 2 } m v ^ { 2 } - \\frac { G M m } { R }) {/tex}</span><br />
If 20 % of initial kinetic energy is lost due to Martian atmospheric resistance, then only 80 % of its kinetic energy helps in reaching a height.<br />
Total initial energy available&nbsp; is&nbsp;<span class="math-tex">{tex}= [\\frac { 80 } { 100 }] [ \\frac { 1 } { 2 } m v ^ { 2 }] - [\\frac { G M m } { R }] = 0.4 m v ^ { 2 } - \\frac { G M m } { R }{/tex}</span><br />
At the height h, the velocity and hence, the kinetic energy of the rocket will become zero.<br />
Total energy of the rocket at height h is&nbsp;&nbsp;<span class="math-tex">{tex}=\\frac{−GMm}{R+h}{/tex}</span><br />
Applying the law of conservation of energy<br />
<span class="math-tex">{tex}0.4 m v ^ { 2 } - \\frac { G M m } { R } = \\frac { - G M m } { ( R + h ) }{/tex}</span><br />
<span class="math-tex">{tex}0.4 v ^ { 2 } = \\frac { G M } { R } - \\frac { G M } { R + h }{/tex}</span><br />
<span class="math-tex">{tex}= G M \\left( \\frac { 1 } { R } - \\frac { 1 } { R + h } \\right){/tex}</span><br />
<span class="math-tex">{tex}= G M \\left( \\frac { R + h - R } { R ( R + h ) } \\right){/tex}</span><br />
<span class="math-tex">{tex}= \\frac { G M h } { R ( R + h ) }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { R + h } { h } = \\frac { G M } { 0.4 v ^ { 2 } R }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { R } { h } + 1 = \\frac { G M } { 0.4 v ^ { 2 } R }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { R } { h } = \\frac { G M } { 0.4 v ^ { 2 } R } - 1{/tex}</span><br />
<span class="math-tex">{tex}\\frac { R } { h } = \\frac { R } { \\frac { G M } { 0.4 v ^ { 2 } R } - 1 }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 0.4 R ^ { 2 } v ^ { 2 } } { G M - 0.4 v ^ { 2 } R }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 0.4 \\times \\left( 3.395 \\times 10 ^ { 6 } \\right) ^ { 2 } \\times \\left( 2 \\times 10 ^ { 3 } \\right) ^ { 2 } } { 6.67 \\times 10 ^ { - 11 } \\times 6.4 \\times 10 ^ { 23 } - 0.4 \\times \\left( 2 \\times 10 ^ { 3 } \\right) ^ { 2 } \\times \\left( 3.355 \\times 10 ^ { 6 } \\right) }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 18.442 \\times 10 ^ { 18 } } { 42.688 \\times 10 ^ { 12 } - 53432 \\times 10 ^ { 12 } }{/tex}</span><br />
<span class="math-tex">{tex}= 495 \\times 10 ^ { 3 } \\mathrm { m } = 495 \\mathrm { km }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A rocket is fired vertically with a speed of 5 km s<sup>-1</sup> from the earth&#39;s surface. How far from the earth does the rocket go before returning to the earth? Mass of the earth =&nbsp;<span class="math-tex">{tex}6.0 \\times 10 ^ { 24 }{/tex}</span> kg; mean radius of the earth = <span class="math-tex">{tex}6.4 \\times 10 ^ { 6 }{/tex}</span>m; <span class="math-tex">{tex}G = 6.67 \\times 10 ^ { - 11 } \\mathbf { N } m ^ { 2 } k g ^ { - 2 }{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Data Given:<br />
Velocity of the rocket, v = 5 km/s =&nbsp;<span class="math-tex">{tex}5 \\times 10 ^ { 3 }{/tex}</span> m/s<br />
Mass of the Earth, <span class="math-tex">{tex}M _ { \\varepsilon } = 6.0 \\times 10 ^ { 24 } \\mathrm { kg }{/tex}</span><br />
Radius of the Earth,<span class="math-tex">{tex}R _ { \\varepsilon } = 6.4 \\times 10 ^ { 6 } \\mathrm { m }{/tex}</span><br />
Height reached by rocket of mass&nbsp;m is&nbsp;h<br />
At the surface of the Earth,<br />
Total energy of the rocket = Kinetic energy + Potential energy<br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } m v ^ { 2 } + \\left( \\frac { - G M _ { \\varepsilon } m } { R _ { \\varepsilon } } \\right){/tex}</span><br />
At highest point h, v&nbsp;= 0<br />
And, Potential energy <span class="math-tex">{tex}- \\frac { G M _ { \\varepsilon } m } { R _ { \\varepsilon } + h }{/tex}</span><br />
Total energy of the rocket <span class="math-tex">{tex}= 0 + \\left( - \\frac { G M _ { \\varepsilon } m } { R _ { \\varepsilon } + h } \\right) = - \\frac { G M _ { \\varepsilon } m } { R _ { \\varepsilon } + h }{/tex}</span><br />
From the law of conservation of energy, we have<br />
Total energy of the rocket at the Earth&#39;s surface = Total energy at height h<br />
<span class="math-tex">{tex}\\frac { 1 } { 2 } m v ^ { 2 } + \\left( - \\frac { G M _ { \\varepsilon } m } { R _ { \\varepsilon } + h } \\right){/tex}</span> <span class="math-tex">{tex}= - \\frac { G M _ { \\varepsilon } m } { R _ { \\varepsilon } + h }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { 1 } { 2 } v ^ { 2 } = G M _ { \\varepsilon } \\left( \\frac { 1 } { R _ { \\varepsilon } } - \\frac { 1 } { R _ { \\varepsilon } + h } \\right){/tex}</span><br />
<span class="math-tex">{tex}G M _ { \\varepsilon } \\left( \\frac { R _ { \\varepsilon } \\ + \\ h \\ - \\ R _ { \\varepsilon } } { R _ { \\varepsilon } \\left( R _ { \\varepsilon } \\ + \\ h \\right) } \\right){/tex}</span><br />
<span class="math-tex">{tex}\\frac { 1 } { 2 } v ^ { 2 }{/tex}</span> <span class="math-tex">{tex}= \\frac { G M _ { \\varepsilon } h } { R _ { \\varepsilon } \\left( R _ { \\varepsilon } \\ + \\ h \\right) } \\times \\frac { R _ { \\varepsilon } } { R _ { \\varepsilon } }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { 1 } { 2 } v ^ { 2 } = \\frac { g R_ {\\varepsilon} h } { R _ { \\varepsilon } + h }{/tex}</span><br />
Where&nbsp;<span class="math-tex">{tex}g = \\frac { G M } { R _ { \\varepsilon } ^ { 2 } } = 9.8 \\mathrm { m } / \\mathrm { s } ^ { 2 }{/tex}</span> Acceleration due to gravity on the Earth&rsquo;s surface)<br />
<span class="math-tex">{tex}\\therefore v ^ { 2 } \\left( R _ { \\varepsilon } + h \\right) = 2 g R _ { \\varepsilon } h{/tex}</span><br />
<span class="math-tex">{tex}v ^ { 2 } R _ { \\varepsilon } = h \\left( 2 g R _ { \\varepsilon } - v ^ { 2 } \\right){/tex}</span><br />
<span class="math-tex">{tex}h = \\frac { R _ { \\varepsilon } v ^ { 2 } } { 2 g R _ { \\varepsilon } \\ -\\ v ^ { 2 } }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 6.4 \\ \\times \\ 10 ^ { 6 } \\ \\times \\ \\left( 5 \\ \\times \\ 10 ^ { 3 } \\right) ^ { 2 } } { 2 \\ \\times \\ 9.8 \\ \\times \\ 6.4 \\ \\times \\ 10 ^ { 6 } - \\left( 5 \\ \\times \\ 10 ^ { 3 } \\right) ^ { 2 } }{/tex}</span><br />
h =&nbsp;<span class="math-tex">{tex}\\frac { 6.4 \\ \\times \\ 25 \\ \\times \\ 10 ^ { 12 } } { 100.44 \\ \\times \\ 10 ^ { 6} }{/tex}</span>&nbsp;=&nbsp;= 1.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>6</sup> m<br />
Height achieved by the rocket with respect to the centre of the Earth<br />
<span class="math-tex">{tex}= R _ { \\varepsilon } + h{/tex}</span><br />
= 6.4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>6</sup> + 1.6&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>6</sup>&nbsp;m<br />
= 8.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>6</sup>&nbsp;m</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Obtain an expression for the acceleration due to gravity on the surface of the earth in terms of mass of the earth and its radius. Discuss the variation of acceleration due to gravity with altitude and depth. If a body is taken to a height <span class="math-tex">{tex}\\frac R4{/tex}</span> from the surface of the earth, find percentage decrease in the weight of the body? Here R is the radius of the earth.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The force (F) of gravitational attraction on a body of mass m due to earth of mass M and radius R is given by<br />
<span class="math-tex">{tex}F=G \\frac{m M}{R^2}{/tex}</span> ...(i)<br />
We know from Newton&#39;s second law of motion that the force is the product of mass and acceleration.<br />
F = ma<br />
But the acceleration due to gravity is represented by the symbol g. Therefore, we can write<br />
F = mg ...(ii)<br />
From the equation (i) and (ii), we get<br />
<span class="math-tex">{tex}m g=G \\frac{m M}{R^2}{/tex}</span> or <span class="math-tex">{tex}g=\\frac{G M}{R^2}{/tex}</span>...(iii)<br />
When body is at a distance &#39;r&#39; from centre of the earth then <span class="math-tex">{tex}g=\\frac{G M}{R^2}{/tex}</span>.</p>

<ol start="1" style="list-style-type:lower-alpha">
	<li>The acceleration due to gravity on the earth is given by<br />
	<span class="math-tex">{tex}\\mathrm{g}=\\frac{\\mathrm{GM}}{\\mathrm{R}^2}{/tex}</span> i.e. GM = R<sup>2</sup>g ...(1)<br />
	The acceleration due to gravity at height &#39;h&#39; from the surface of the earth is given by<br />
	<span class="math-tex">{tex}g_h=\\frac{G M}{(R+h)^2}{/tex}</span> i.e. GM = (R + h)<sup>2</sup>gh ...(2)<br />
	From (1) and (2) we have,<br />
	<span class="math-tex">{tex}\\frac{g_h}{g}=\\frac{R^2}{(R+h)^2}{/tex}</span><br />
	<span class="math-tex">{tex}\\frac{g_h}{g}=\\left(1-\\frac{2 h}{R}\\right){/tex}</span></li>
	<li>The acceleration due to gravity on the surface of the earth is given by.<br />
	g = <span class="math-tex">{tex}\\frac{GM}{R^2}{/tex}</span> ...(i)<br />
	let &#39;Q&#39; be the density of the material of the earth.<br />
	Now, mass = volume <span class="math-tex">{tex}\\times{/tex}</span> density<br />
	M <span class="math-tex">{tex}=\\frac{4}{3} \\pi R^3 \\times \\rho{/tex}</span><br />
	Substituting in equation (1) we get<br />
	<span class="math-tex">{tex}\\mathrm{g}=\\frac{\\mathrm{G}}{\\mathrm{R}^2} \\times \\frac{4}{3} \\pi \\mathrm{R}^3 \\times \\rho=\\frac{4}{3} \\pi \\mathrm{GR} \\rho{/tex}</span><br />
	<span class="math-tex">{tex}g=\\frac{4}{3} \\pi G R \\rho{/tex}</span> ...(ii)<br />
	<span class="math-tex">{tex}g_d=\\frac{4}{3} \\pi G(R-d) \\rho{/tex}</span> ...(iii)<br />
	dividing equation (iii) by (ii) we get<br />
	<span class="math-tex">{tex}\\frac{g_d}{g}=\\frac{R-d}{R}=\\left(1-\\frac{d}{R}\\right){/tex}</span><br />
	<span class="math-tex">{tex}g_d=g\\left(1-\\frac{d}{R}\\right){/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Two stars each of one solar mass =<span class="math-tex">{tex}2 \\times 10 ^ { 30 }{/tex}</span> kg are approaching towards each other for collision. When they are at a distance of&nbsp;10<sup>9</sup> km, their speeds are negligible. What is the speed with which they collide? The radius of each star is 10<sup>4</sup> km. Assume the stars to remain undistorted until they collide. (Use the known value of G).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Mass of each star, M = 2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>30</sup> kg<br />
Radius of each star,&nbsp;R = 10<sup>4</sup> km = 10<sup>7</sup> m<br />
Distance between the stars,&nbsp;r =&nbsp;10<sup>9</sup> km = 10<sup>12</sup> m<br />
For negligible speeds, v = 0<br />
total energy of two stars separated at distance r<br />
<span class="math-tex">{tex}= \\frac { - G M M } { r } + \\frac { 1 } { 2 } m v ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { - G M M } { r } + 0{/tex}</span> &hellip;.(i)<br />
Consider the case when the stars are about to collide:<br />
Velocity of the stars&nbsp;= v|<br />
Distance between the centers of the stars = 2R<br />
Total kinetic energy of both stars <span class="math-tex">{tex}= \\frac { 1 } { 2 } M v ^ { 2 } + \\frac { 1 } { 2 } M v ^ { 2 } = M v ^ { 2 }{/tex}</span><br />
Total potential energy of both stars <span class="math-tex">{tex}= \\frac { - G M M } { 2 R }{/tex}</span><br />
Total energy of the two stars&nbsp;<span class="math-tex">{tex}= M v ^ { 2 } - \\frac { G M M } { 2 R }{/tex}</span> &hellip;..(ii)<br />
Using the law of conservation of energy,&nbsp;<br />
&nbsp;<span class="math-tex">{tex}\\Rightarrow M v ^ { 2 } - \\frac { G M M } { 2 R } = \\frac { - G M A } { R }{/tex}</span><br />
<span class="math-tex">{tex}v ^ { 2 } = \\frac { - G M } { r } + \\frac { G M } { 2 R } = G M \\left( - \\frac { 1 } { r } + \\frac { 1 } { 2 R } \\right){/tex}</span><br />
= 6.67&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-10</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-10</sup>&nbsp;<span class="math-tex">{tex}[ - \\frac { 1 } { 10 ^ { 12 } } + \\frac { 1 } { 2 \\ \\times \\ 10 ^ { 7 } }]{/tex}</span><br />
= 13.34&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>19</sup>[-10<sup>-12</sup> + 5 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-8</sup>]</p>

<p><span class="math-tex">{tex}= 13.34 \\times 10 ^ { 19 } \\left[ - 10 ^ { - 12 } + 5 \\times 10 ^ { - 8 } \\right]{/tex}</span><br />
= 13.34&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>19</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-8 </sup>= 6.67&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>12</sup><br />
v =&nbsp;<span class="math-tex">{tex}\\sqrt { 6.67 \\times 10 ^ { 12 } }{/tex}</span>&nbsp;=&nbsp;2.58 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>6</sup>&nbsp;m/s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What are geostationary satellites? Find the expression of total energy of a satellite around the surface of the earth. What is the significance of negative sign in the expression? Write the expression of angular momentum of a satellite.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Satellite that appears to be located at a fixed point in space when viewed from the earth&#39;s surface.<br />
<span class="math-tex">{tex}\\mathrm{U}=\\mathrm{GMm} \\int\\limits_{\\infty}^r \\frac{1}{x^2} d x{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{U}=\\mathrm{GMm}\\left|-\\frac{1}{x}\\right|_{\\infty}^r{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{U}=\\mathrm{GMm}\\left[-\\frac{1}{r}+\\frac{1}{\\infty}\\right]{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{U}=-\\frac{G M m}{r}{/tex}</span><br />
Kinetic energy KE = <span class="math-tex">{tex}\\frac{1}{2} m v^2{/tex}</span><br />
But <span class="math-tex">{tex}v=\\sqrt{\\frac{G M}{r}}{/tex}</span><br />
<span class="math-tex">{tex}\\text { K. } \\mathrm{E}=\\frac{1}{2} m\\left(\\frac{G M}{r}\\right){/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{KE}=\\frac{G M m}{2 r}{/tex}</span><br />
Total energy of satellite E = U + v<br />
<span class="math-tex">{tex}\\mathrm{E}=-\\frac{G M m}{r}+\\frac{G M m}{2 r}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{E}=-\\frac{G M m}{2 r}{/tex}</span><br />
T.E. &lt; 0 or negative, this means the satellite is bound to the earth through gravity.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1705060710-4y66jw.jpg" style="height:123px; width:135px" /><br />
<span class="math-tex">{tex}F_c=\\frac{m v^2}{r}{/tex}</span><br />
<span class="math-tex">{tex}\\frac{G M m}{r^2}=\\frac{m v^2}{r}{/tex}</span><br />
<span class="math-tex">{tex}v=\\sqrt{\\frac{G M}{r}}{/tex}</span><br />
Angular momentum, L = mvr = <span class="math-tex">{tex}m \\sqrt{\\frac{G M}{r}} \\times r=\\sqrt{G M m^2 r}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{L}=\\sqrt{\\mathrm{GMm^{2 }}} \\times \\sqrt{r} {/tex}</span> or <span class="math-tex">{tex}\\mathrm{L} \\propto \\sqrt{r}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>Define escape velocity.</li>
	<li>Derive expression for the escape velocity of an object from the surface of a planet.</li>
	<li>Does it depend on location from where it is projected?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>(i) Escape velocity is the minimum velocity with which a body must be projected vertically upward so that it may just escape the surface of the Earth.<br />
(ii) Expression for escape velocity:<br />
Let a body of mass m&nbsp;be escaped from the gravitational field of the earth.<br />
During the course of motion, let at any instant, body be at a distance r from the centre of the earth.<br />
<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082629-ep4jwf.jpg" style="height:150px; width:77px" /><br />
The gravitational force between body and the earth is,<br />
F =&nbsp;<span class="math-tex">{tex}\\frac{\\mathrm{CMm}}{\\mathrm{r}^{2}} \\mathrm{dr}{/tex}</span><br />
Work done to raise the body by distance dr is,<br />
dW =&nbsp;<span class="math-tex">{tex}\\frac{\\mathrm{GMm}}{\\mathrm{r}^{2}} \\mathrm{dr}{/tex}</span><br />
Total work done, W in raising the body from the surface of the earth to infinity is,<br />
W =&nbsp;<span class="math-tex">{tex}\\int_{R}^{\\infty} \\frac{G M m}{r^{2}} d r=G M m\\left[-\\frac{1}{r}\\right]_{R}^{\\infty}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\operatorname{CMm}\\left[-\\frac{1}{\\infty}+\\frac{1}{R}\\right]{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{\\mathrm{GMm}}{\\mathrm{R}}{/tex}</span><br />
If we throw the body upward with a velocity v<sub>e</sub>, then work done to raise the body from the surface of the earth to infinity is done by kinetic energy.<br />
Therefore,&nbsp;<span class="math-tex">{tex}\\frac{\\mathrm{GMm}}{\\mathrm{R}}=\\frac{1}{2} \\mathrm{mv}_{\\mathrm{e}}^{2}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\quad v_{e}=\\sqrt{\\frac{2 G M}{R}}=\\sqrt{2 g R}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\quad v_{e}=\\sqrt{2 g R}{/tex}</span>&nbsp;...(i)<br />
Substituting the values in equation (i), we have<br />
g = 9.81 m/sec&nbsp;and R = 6.4 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>6</sup> m<br />
Escape velocity is given by,<br />
v<sub>e&nbsp;</sub>=&nbsp;<span class="math-tex">{tex}\\sqrt{9.81 \\times 6.4 \\times 10^{6}}{/tex}</span><br />
= 11200 m/s<br />
= 11.2&nbsp;m/s</p>

<p>(iii)&nbsp;Yes, escape velocity&nbsp;<em>does</em>&nbsp;depend slightly on the location&nbsp;because it&#39;s determined by the distance from the planet&#39;s center (altitude/height) and latitude, affecting the local gravitational potential, though it doesn&#39;t depend on the launch direction or the object&#39;s mass; higher altitudes or locations closer to the equator require slightly less escape velocity.&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>Derive an expression for the acceleration due to gravity <strong>g</strong> at a depth d from the centre of the earth. What happens to <strong>g</strong> at the centre of the earth.</li>
	<li>At what height above the earth&#39;s surface, is the value of <strong>g</strong> same as in a mine 80 km deep?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li><span class="math-tex">{tex}g=\\frac{G M}{(R+h)^2}=\\frac{G M}{R^2\\left(1+\\frac{h}{R}\\right)^2}{/tex}</span><br />
	<span class="math-tex">{tex}\\mathrm{g}=\\frac{\\mathrm{GM}}{\\mathrm{R}^2}\\left(1+\\frac{\\mathrm{h}}{\\mathrm{R}}\\right)^{-2}{/tex}</span><br />
	Now, <span class="math-tex">{tex}\\frac{\\mathrm{GM}}{\\mathrm{R}^2}=\\mathrm{g}_0{/tex}</span> (surface value)<br />
	<span class="math-tex">{tex}\\therefore g=g_0\\left(1+\\frac{h}{R}\\right)^{-2}{/tex}</span> [which &lt; &lt; R]<br />
	<span class="math-tex">{tex}g \\approx g_0\\left(1-\\frac{2 h}{R}\\right){/tex}</span><br />
	[Using binomial theorem (1 + x)n <span class="math-tex">{tex}\\approx{/tex}</span> 1 + nx when |x| &lt; &lt; 1.]<br />
	If we go inside the earth at depth h</li>
	<li>As depth of mine is &lt; &lt; R<br />
	Hence we can use approximation formula<br />
	Let height be h<br />
	We know that for variation of g with height,<br />
	<span class="math-tex">{tex}g=g_0\\left(1-\\frac{2 h}{R}\\right){/tex}</span> ...(i)<br />
	And for variation in g with depth<br />
	<span class="math-tex">{tex}g=g_0\\left(1-\\frac{d}{R}\\right){/tex}</span> ...(ii)<br />
	Where d is the depth.<br />
	According to the question<br />
	<span class="math-tex">{tex}g_0\\left(1-\\frac{2 h}{R}\\right)=g_0\\left(1-\\frac{d}{R}\\right){/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow \\frac{2 h}{R}=\\frac{d}{R}{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow \\mathrm{h}=\\frac{\\mathrm{d}}{2}=\\frac{80}{2}=40 \\mathrm{~km}{/tex}</span><br />
	<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1705058610-x4jhe4.jpg" style="height:140px; width:250px" /></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define Gravitational potential energy. Hence, deduce&nbsp;an expression for gravitational potential energy of a body placed at a point near the surface of the earth?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>It is defined as the work done in bringing a body from infinity to that point.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch08/5m/image001.png" style="height: 95px; width: 250px;" /><br />
A body of mass (m) lying at a distance x from earth of mass (m). Hence, Gravitational force between the two is<br />
<span class="math-tex">{tex}F = \\frac { G M m } { x ^ { 2 } }{/tex}</span>&nbsp;<br />
Where G is universal gravitational constant<br />
M is mass of the planet&nbsp;and m is a mass of the body&nbsp;to be shifted from infinity to distance r<br />
r is the distance of the body&nbsp;<br />
If the body is displaced through a distance dx then (small amount of work done in bringing an object from C to B)dw = Fdx <span class="math-tex">{tex}= \\frac { G M m } { x ^ { 2 } } d x{/tex}</span><br />
Total&nbsp; amount of work &nbsp;done in bringing an object from infinity to r<br />
<span class="math-tex">{tex}\\int\\limits_\\infty ^ {r} {\\frac{{GMm}}{{{x^2}}}dx} {/tex}</span><br />
<span class="math-tex">{tex}w = GMm\\int\\limits_\\infty ^{r} {\\frac{1}{{{x^2}}}dx} {/tex}</span><br />
<span class="math-tex">{tex}w = \\operatorname { GMm } \\left| \\frac { - 1 } { x } \\right| _ { \\infty } ^ { r }{/tex}</span><br />
<span class="math-tex">{tex}w = - G M m \\left| \\frac { 1 } { r } - \\frac { 1 } { \\infty } \\right|{/tex}</span><br />
<span class="math-tex">{tex}w = \\frac { - G M m } { r }{/tex}</span><br />
This work done is equal to the gravitational potential energy.<br />
&nbsp;i.e.<br />
<span class="math-tex">{tex}w = U _ { g } = \\frac { - G M m } { r }{/tex}</span>&nbsp;, the negative sign indicates that it is attractive in nature.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define orbital velocity and time period of a satellite. Derive expressions for these.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Orbital velocity</strong>:- Orbital velocity of a satellite is the velocity required to put the satellite into its orbit around the earth.<br />
<strong>Expression for orbital velocity</strong><br />
<span class="math-tex">{tex}\\frac{\\mathrm{GM}_e m}{(\\mathrm{R}+h)^2}=\\frac{m v^2}{\\mathrm{R}+h}{/tex}</span><br />
or, <span class="math-tex">{tex}v=\\sqrt{\\frac{(\\mathrm{R}+h)^3}{g}}{/tex}</span><br />
As <span class="math-tex">{tex}g=\\frac{\\mathrm{GM}_e}{\\mathrm{R}^2}{/tex}</span><br />
<span class="math-tex">{tex}v=\\sqrt{\\frac{g \\mathrm{R}^2}{\\mathrm{R}+h}}{/tex}</span><br />
<strong>Time period of a satellite</strong>:- The time period of a satellite is the time taken by it to go once around the earth.<br />
<strong>Expression for time period<br />
<span class="math-tex">{tex}\\mathrm{T}=\\frac{\\text { Circumference of the orbit }}{\\text { Orbital velocity }}{/tex}</span></strong><br />
or, <strong><span class="math-tex">{tex}\\mathrm{T}=\\frac{2 \\pi(\\mathrm{R}+h)}{v}{/tex}</span></strong><br />
Putting <span class="math-tex">{tex}v=\\sqrt{\\frac{g \\mathrm{R}^2}{\\mathrm{R}+h}}{/tex}</span><br />
We get <span class="math-tex">{tex}\\mathrm{T}=\\frac{2 \\pi}{\\mathrm{R}} \\sqrt{\\frac{(\\mathrm{R}+h)^3}{g}}{/tex}</span><br />
Putiing <span class="math-tex">{tex}v=\\sqrt{\\frac{\\mathrm{GM}_e}{\\mathrm{R}+h}}{/tex}</span><br />
We get <span class="math-tex">{tex}\\mathrm{T}=2 \\pi \\sqrt{\\frac{(\\mathrm{R}+h)^3}{\\mathrm{GM}_e}}{/tex}</span> ...(ii)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1348-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_MECHANICAL_PROPERTIES_OF_SOLIDS = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The dimensional formula of modulus of rigidity is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>-2</sup>T<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>-3</sup>T<sup>-2</sup>]</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>2</sup>T<sup>-2</sup>]</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">[ML<sup>-1</sup>T<sup>-2</sup>]</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>[<span class="math-tex">{tex}\\eta{/tex}</span>] =&nbsp;<span class="math-tex">{tex}\\frac{F}{A} \\cdot \\frac{l}{\\Delta l}=\\frac{\\mathrm{MLT}^{-2} \\cdot \\mathrm{L}}{\\mathrm{L}^{2} \\cdot \\mathrm{L}}{/tex}</span>&nbsp;<br />
= [ML<sup>-1</sup>T<sup>-2</sup>]</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>According to Hooke&#39;s law of elasticity, if stress is increased, the ratio of stress to strain</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">increases</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">decreases</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">becomes zero</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">remains constant</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>According to Hooke&#39;s law,<br />
<span class="math-tex">{tex}\\frac{\\text { Stress }}{\\text { Strain }}{/tex}</span> = Constant (within the elastic limit)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>According to Hooke&#39;s law of elasticity, if stress is increased, the ratio of stress to strain</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">increases</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">decreases</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">becomes zero</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">remains constant</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>We know that within the elastic limit, the stress set up in an elastic body is directly proportional to the strain produced. Therefore, the ratio of stress to strain remains constant.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A wire is stretched to double its length. The strain is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">2</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">1</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\text { Strain }=\\frac{\\text { Change in length }}{\\text { Original length }}=\\frac{2 L-L}{L}=1{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">0.5</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Energy stored in stretching a string per unit volume is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2} \\times \\text { stress } \\times \\text { strain }{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Energy stored per unit volume = Work done per unit volume<br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\times \\text { Stress } \\times \\text { strain }{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">stress <span class="math-tex">{tex}\\times{/tex}</span> strain</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Y(Strain)<sup>2</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>Y(Stress)<sup>2</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>What will be the energy stored in a strained wire?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> load <span class="math-tex">{tex}\\times{/tex}</span> extension</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> stress <span class="math-tex">{tex}\\times{/tex}</span> strain</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Total work done in stretching a string<br />
<span class="math-tex">{tex}=\\frac{1}{2}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> stress <span class="math-tex">{tex}\\times{/tex}</span> strain <span class="math-tex">{tex}\\times{/tex}</span> volume<br />
Hence, the work per unit volume is <span class="math-tex">{tex}=\\frac{1}{2}{/tex}</span>(stress <span class="math-tex">{tex}\\times{/tex}</span> strain). This work is stored as the potential energy in the string.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> load <span class="math-tex">{tex}\\times{/tex}</span> strain</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> load <span class="math-tex">{tex}\\times{/tex}</span> stress</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A and B are two wires. The radius of A is twice that of B. They are stretched by the same load. Then, the stress on B is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">equal to that on A</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">four times that on A</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>four times that on A</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">two times that on A</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">half that on A</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>According to Hooke&rsquo;s law:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">for small deformations, the stress and strain are proportional to each other.</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>By definition of Hooke&#39;s law within the elastic limit, the stress developed is directly proportional to the strain produced in a body stress&nbsp;<span class="math-tex">{tex}\\propto {/tex}</span>&nbsp;strain.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">for large deformations, the stress and strain are proportional to each other.</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">for small deformations, the stress and strain are inversely proportional to each other.</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">for small deformations, the stress is proportional to the square of strain.</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The Bulk Modulus for an incompressible liquid is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">unity</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">infinity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>We know that the bulk modulus is,<br />
<span class="math-tex">{tex}B=-\\frac{d p V}{\\Delta V}{/tex}</span> [Here, p = Pressure (stress) and <span class="math-tex">{tex}-\\frac{\\Delta V}{V}={/tex}</span> Volume strain]<br />
But liquid is incompressible, so<br />
<span class="math-tex">{tex}\\Delta V=0{/tex}</span><br />
Hence, <span class="math-tex">{tex}B=-\\frac{p V}{0}=\\infty{/tex}</span><br />
or <span class="math-tex">{tex}B=\\infty{/tex}</span> (infinity)</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">between 0 and 1</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The work done per unit volume in deforming a body is given by</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">stress <span class="math-tex">{tex}\\times{/tex}</span> strain</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>(stress <span class="math-tex">{tex}\\times{/tex}</span> strain)</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>W = Average force&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;extension<br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} F \\times \\Delta l=\\frac{1}{2} \\frac{F}{A} \\cdot \\frac{\\Delta l}{l} \\cdot A l{/tex}</span>&nbsp;<br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\times{/tex}</span>Stress&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;Strain&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;volume of wire&nbsp;<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Workdone per unit volume =&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\times {/tex}</span>&nbsp;Stress&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> strain</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{stress}{strain}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{strain}{stress}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The Young&#39;s modulus of a wire of length L and radius r is Y newton per square metre. If the length is reduced to <span class="math-tex">{tex}\\frac{L}{2}{/tex}</span> and radius <span class="math-tex">{tex}\\frac{r}{2}{/tex}</span>, its Young&#39;s modulus will be</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{Y}{2}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">Y</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Young&#39;s modulus depends on the nature of the material.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">2Y</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">4Y</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The S.I. unit of stress is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">Pascal</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As Stress = <span class="math-tex">{tex}Force \\over Area{/tex}</span><br />
Putting units, we get<br />
Stress&nbsp;= N/m<sup>2</sup><br />
= Nm<sup><font>-2</font> </sup>or Pascal&nbsp;<br />
So SI Unit of Stress is Pascal</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Newton</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Joule</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Watt</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two wires are made of the same material and have the same volume. The first wire has cross-sectional area A and the second wire has cross-sectional area 3A. If the length of the first wire is increased by <span class="math-tex">{tex}\\Delta l{/tex}</span> on applying a force F, how much force is needed to stretch the second wire by the same amount?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">9 F</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}Y=\\frac{F l}{A \\Delta l}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow F=\\frac{Y A \\Delta l}{l}{/tex}</span><br />
<span class="math-tex">{tex}F^{\\prime}=\\frac{Y(3 \\mathrm{~A}) \\Delta l}{(l / 3)}{/tex}</span><br />
= 9 F</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">F</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">4 F</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">6 F</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which of the following has no dimensions?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">strain</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As strain is ratio of two like quantities, it has no dimensions.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">angular velocity</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">momentum</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">angular momentum</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A wire of length L and cross-sectional area A is made of a material of Young&#39;s modulus Y. If the wire is stretched by the amount x, the work done is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{Y A x^{2}}{2 L}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Young&#39;s Modulus =&nbsp;<span class="math-tex">{tex}\\frac{\\text{Normal Stress}}{\\text{Longitudinal Strain}}{/tex}</span>&nbsp;<br />
F = Force, A = Area, l = change in length, L = original Length<br />
x = change in Length (Given)<br />
Average extension = 0 +&nbsp;<span class="math-tex">{tex}\\frac{x}{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{x}{2}{/tex}</span><br />
Now, work done = Force&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;Average extension<br />
Now, y =&nbsp;<span class="math-tex">{tex}\\frac{F L}{A l}{/tex}</span>&nbsp;<br />
F =&nbsp;<span class="math-tex">{tex}\\frac{Y A l}{L}{/tex}</span>&nbsp;<br />
Workdone =&nbsp;<span class="math-tex">{tex}\\frac{Y A l}{L} \\cdot \\frac{x}{2}{/tex}</span>&nbsp;<br />
=&nbsp;<span class="math-tex">{tex}\\frac{Y A x}{L} \\cdot \\frac{x}{2}{/tex}</span>&nbsp;(l = x (given))<br />
Workdone =&nbsp;<span class="math-tex">{tex}\\frac{Y A x^{2}}{2 L}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{Y A x^{2}}{L}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Yax<sup>2</sup>L</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{Y A x}{2 L}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Draw a stress-strain curve for a loaded wire. On the graph mark:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Hooke&#39;s law region</li>
	<li>Elastic limit</li>
	<li>Yield point</li>
	<li>Breaking point</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><img alt="" data-imgur-src="Rp6Vr7R.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1657888496-jutkdg.jpg" style="width: 300px; height: 288px;"/></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Figure shows the strain-stress curve for a given material. What are</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Young&#39;s modulus and</li>
	<li>approximate yield strength for this material?</li>
</ol>

<p><img id="Picture 4" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch09/2m/image065.jpg" style="width: 250px; height: 189px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>It is clear from the given graph that for stress(F/A)&nbsp;=150 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup> N/m<sup>2</sup>,&nbsp; the value of strain(<span class="math-tex">{tex}\\frac {\\Delta l}{l}{/tex}</span>) is 0.002 m.<br />
	We know that,&nbsp;Young&#39;s modulus, <span class="math-tex">{tex}Y = \\frac { \\text { Stress } } { \\text { Strain } } = \\frac {\\frac {F}{A}}{\\frac {\\Delta l}{l}}{/tex}</span><br />
	<span class="math-tex">{tex}= \\frac { 150 \\times 10 ^ { 6 } } { 0.002 } = 7.5 \\times 10 ^ { 10 } N / \\mathrm { m } ^ { 2 }{/tex}</span><br />
	Hence, Young&#39;s modulus for the given material is given by&nbsp;<span class="math-tex">{tex}7.5 \\times 10 ^ { 10 } \\mathrm { N } / \\mathrm { m } ^ { 2 }{/tex}</span>.</li>
	<li>The yield strength of a material is the maximum stress that the material can sustain without crossing the elastic limit.<br />
	It is clear from the given graph that the approximate yield strength of this material is&nbsp;<span class="math-tex">{tex}300 \\times 10 ^ { 6 } \\mathrm { N/m } ^ { 2 } \\text { or } 3 \\times 10 ^ { 8 } \\mathrm { N } / \\mathrm { m } ^ { 2 }{/tex}</span>, when the corresponding strain value is showing 0.004 m from the given graph and the material is just crossing elastic limit over there.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Which is more elastic rubber or steel? Explain.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let length and area of rubber and steel rod = l and a respectively<br />
Let Yr = Young&rsquo;s modulus of elasticity for rubber<br />
Ys = Young&rsquo;s modulus of elasticity for steel when Stretching force F is applied, Let<br />
<span class="math-tex">{tex}\\Delta l r{/tex}</span> Extension in rubber<br />
<span class="math-tex">{tex}\\Delta{/tex}</span> ls = Extension in steel<br />
Now, <span class="math-tex">{tex}\\Delta l r{/tex}</span> will be greater that ∆ls.<br />
Now <span class="math-tex">{tex}Y = \\frac { F l } { a \\Delta l } = \\frac { \\text { Normal stress } } { \\text { Longitudinal strain } }{/tex}</span><br />
So, <span class="math-tex">{tex}\\mathrm { Yr } = \\frac { F l } { a \\Delta l r } ; \\mathrm { Ys } = \\frac { F l } { a \\Delta {l} s }{/tex}</span><br />
Since <span class="math-tex">{tex}\\Delta l r &gt; \\Delta l s{/tex}</span><br />
So, Y<sub>r</sub> &lt; Y<sub>s</sub><br />
Hence more the modulus of elasticity more elastic is the material, so, steel is more elastic than rubber.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A steel wire of length 5.0 m and cross-section 3.0 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup> m<sup>2</sup> stretches by the same amount as a copper wire of length 3.0 m and cross-section 4.0 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup> m<sup>2</sup> under a given load. What is the ratio of Young&#39;s modulus of steel to that of copper?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Length of steel wire = Ls = 5m<br />
area of cross-section As = 3 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup>m<sup>2</sup><br />
length of copper wire = Lc = 3.0 m<br />
area of cross-section Ac = 4 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup>m<sup>2</sup><br />
So, from Hooke&#39;s law, we know that stress is directly proportional to strain.<br />
<span class="math-tex">{tex}\\sigma \\propto \\varepsilon{/tex}</span><br />
This gives us the relationship between <span class="math-tex">{tex}\\sigma {/tex}</span>, <span class="math-tex">{tex}\\varepsilon{/tex}</span>, and E, that is<br />
<span class="math-tex">{tex}\\sigma{/tex}</span> = E<span class="math-tex">{tex}E\\varepsilon{/tex}</span><br />
or, <span class="math-tex">{tex}E=\\frac{\\sigma}{\\epsilon}{/tex}</span><br />
Now, since stress, <span class="math-tex">{tex}\\sigma=\\frac{P}{A}{/tex}</span> and strain, <span class="math-tex">{tex}\\epsilon=\\frac{\\Delta l}{l}{/tex}</span>,<br />
where, P is the load that is being applied over a cross-sectional area A, which causes a change <span class="math-tex">{tex}\\Delta l{/tex}</span> in original length l.<br />
So, <span class="math-tex">{tex}E=\\frac{P}{\\frac{A \\Delta l}{l}}=\\frac{P l}{A \\Delta l}{/tex}</span><br />
Now, for other parameters being constant,<br />
&rArr; E &prop; <span class="math-tex">{tex}\\frac{l}{A}{/tex}</span><br />
Now, for steel wire,<br />
<span class="math-tex">{tex}(E)_{\\text {steel }}=\\frac{l_{\\text {steel }}}{A_{\\text {steel }}}{/tex}</span><br />
Similarly, for copper wire,<br />
<span class="math-tex">{tex}(E)_{\\text {copper }}=\\frac{l_{\\text {copper }}}{A_{\\text {copper }}}{/tex}</span><br />
To determine the ratio of Young&#39;s modulus of steel to that of copper, dividing the above equations, that is <span class="math-tex">{tex}\\frac{E_{\\text {steel }} }{ E_{\\text {copper }}}{/tex}</span>, we get,<br />
<span class="math-tex">{tex}\\frac{(E)_{\\text {steel }}}{(E)_{\\text {copper }}}=\\frac{l_{\\text {pted }}}{A_{\\text {ateel }}} \\times\\frac{A_{\\text {copper }}}{l_{\\text {copper }}}{/tex}</span><br />
Substituting the given values for respective terms, we get,<br />
<span class="math-tex">{tex}\\frac{(E)_{\\text {steel }}}{(E)_{\\text {copper }}}=\\frac{6}{3 \\times10^{-5}}\\times \\frac{5 \\times10^{-5}}{4}{/tex}</span><br />
On simplifying the above expression, we get,<br />
<span class="math-tex">{tex}\\frac{(E)_{\\text {steel }}}{(E)_{\\text {copper }}}=2.5{/tex}</span><br />
Therefore, the ratio of Young&#39;s modulus of steel to that of copper will be 2.5.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A structural steel rod has a radius of 10 mm and a length of 1.0 m. A 100 kN force stretches it along its length. Calculate</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>stress</li>
	<li>elongation, and</li>
	<li>strain on the rod</li>
</ol>

<p>Young&rsquo;s&nbsp; Modulus, of structural steel is 2.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>11</sup>N m<sup>-2</sup></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>We assume that the rod is held by a clamp at one end, and the force F is applied at the other end, parallel to the length of the rod. Then the stress on the rod is given by<br />
Stress&nbsp;<span class="math-tex">{tex}=\\frac{F}{A}=\\frac{F}{\\pi r^{2}}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{100 \\times 10^{3} \\mathrm{N}}{3.14 \\times\\left(10^{-2} \\mathrm{m}\\right)^{2}}{/tex}</span><br />
<span class="math-tex">{tex}=3.18 \\times 10^{8} \\mathrm{Nm}^{-2}{/tex}</span><br />
The elongation.<br />
<span class="math-tex">{tex}\\Delta L=\\frac{(F / A) L}{Y}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{\\left(3.18 \\times 10^{8} \\mathrm{N} \\mathrm{m}^{-2}\\right)(\\mathrm{lm})}{2 \\times 10^{11} \\mathrm{N} \\mathrm{m}^{-2}}{/tex}</span><br />
<span class="math-tex">{tex}=1.59 \\times 10^{-3} \\mathrm{m}{/tex}</span><br />
= 1.59 mm<br />
The strain is given by<br />
Strain&nbsp;<span class="math-tex">{tex}= \\frac {\\Delta L}{L}{/tex}</span><br />
<span class="math-tex">{tex}= \\frac {(1.59 \\times 10^{-3}m)}{(1m)}{/tex}</span><br />
<span class="math-tex">{tex}=1.59 \\times 10^{-3}{/tex}</span><br />
= 0.16%</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>What do you mean by bulk modulus? Find an expression for it.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>When a body is subjected to normal forces on the whole of its exposed surface,&nbsp;Within elastic limit, the ratio of normal (hydraulic) stress to the corresponding volume strain is called &#39;bulk modulus&#39;.&nbsp;It causes a change in volume of the body. The relative change in the volume of a body produced by a unit compressive or tensile stress acting uniformly over its surface.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}Bulk\\ modulus\\ B ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{hydraulic \\ stress}{volumetric \\ strain}{/tex}</span>= <span class="math-tex">{tex}-\\frac{p}{\\frac{\\Delta V}{V}}{/tex}</span><br />
Here, the -ve sign indicates the fact that within an increase in pressure a decrease in volume takes place.&nbsp;Value of bulk modulus B is always positive.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Show that the elastic potential energy stored per unit volume of a stretched wire is equal to <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> &nbsp;stress <span class="math-tex">{tex}\\times{/tex}</span> strain.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Energy Density <span class="math-tex">{tex}= \\frac { \\text { Energy } } { \\text {Volume} } = \\frac { \\frac { 1 } { 2 } \\frac { A Y } { L } x ^ { 2 } } { A L }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } \\left( \\frac { A y x } { A L } \\right) \\times \\frac { x } { L } {/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } { Stress } \\times {Strain}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The stress-strain graphs for materials A and B&nbsp;are shown in figure.<br />
&nbsp;<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/mex8Sgr.png" /><br />
The graphs are drawn to the same scale.</p>

<ol start="1" style="list-style-type:lower-alpha">
	<li>Which of the materials has greater Young&rsquo;s modulus?</li>
	<li>Which of the two is the stronger material?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-alpha">
	<li>Slope of Stress Vs Strain graph gives the value of Young&#39;s modulus of a material. The slope of the graph in Fig. (a) is&nbsp;greater than the slope of the graph in Fig. (b), Therefore, material&nbsp;A has greater Young&#39;s modulus.&nbsp;</li>
	<li>Material A&nbsp;can&nbsp;withstand more load without breaking. Therefore, it is stronger than material B. For material&nbsp;A, the break even point (D) is higher.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>The stress-strain graphs for materials A and B are shown in the figure.<br/>
<img alt="" data-imgur-src="ynBLer3.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082614-9mbzre.jpg" style="width: 300px; height: 153px;"/><br/>
The graphs are drawn to the same scale.</p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Which of the material has greater Young's modulus?</li>
<li>Which material is more ductile?</li>
<li>Which is more brittle?</li>
<li>Which of the two is stronger material?</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Young&#39;s modulus =&nbsp;<span class="math-tex">{tex}\\frac{\\text { Stress }}{\\text { Strain }}{/tex}</span>&nbsp;= slope of stress-strain graph.<br />
	As the slope of the stress-strain graph for material A is higher than that for material B, so <strong>material A has a greater Young&#39;s modulus than B</strong>.</li>
	<li><strong>Material A is more ductile than B</strong>&nbsp;because it has a larger range of plastic extension between its elastic limit and fracture point.</li>
	<li><strong>Material B is more brittle than A</strong>&nbsp;because its plastic range of extension is very small.</li>
	<li><strong>Material A is stronger than B</strong>&nbsp;because it can withstand greater stress before breaking.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define the terms stress and strain and also state their SI units. Draw the stress versus strain graph for a metallic wire, when stretched upto the breaking point.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><strong>Stress:</strong> The restoring force set up per unit area of a deformed body is called stress.<br/>
Stress = <span class="math-tex">{tex}\\frac{\\text { Restoring force }}{\\text { Area }}=\\frac{\\text { Applied force }}{\\text { Area }}=\\frac{F}{A}{/tex}</span> <br/>
The SI unit of stress is Nm<sup>-2</sup> and the CGS unit is dyne cm<sup>-2</sup>.<br/>
<strong>Strain:</strong> The ratio of the change in any dimension produced in the body to the original dimension is called strain.<br/>
Strain = <span class="math-tex">{tex}\\frac{\\text { Change in dimension }}{\\text { Original dimension }}{/tex}</span><br/>
As strain is the ratio of two like quantities, it has no units and dimensions.<br/>
<img alt="" data-imgur-src="Rp6Vr7R.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082618-ujgtxx.jpg" style="width: 300px; height: 288px;"/></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Stress strain curve for two wires of material A and B are as shown in Figure.<br />
<img id="Picture 6" src="https://media-mycbseguide.s3.amazonaws.com/images/cbse/11/Physics/impq/ch07/01/image046.png" style="width: 120px; height: 84px;" /></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Which material is more ductile?</li>
	<li>Which material has greater value of young&#39;s modulus?</li>
	<li>Which of the two is stronger material?</li>
	<li>Which material is more brittle?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Wire A is more ductile&nbsp;because it has a greater plastic range.</li>
	<li>
	<p>&nbsp;For a given strain, the stress for material A is more than it is for material B, as shown in the&nbsp;graph.</p>

	<p><span class="math-tex">{tex}Young’s\\ modulus = \\frac{Stress}{Strain}{/tex}</span></p>

	<p>For a given strain, if the stress for a material is more, then Young&rsquo;s modulus is also greater for that material.</p>

	<p>Therefore, Young&rsquo;s modulus for material A is greater than it is for material B.&nbsp;</p>
	<span class="math-tex">{tex}Y_A &gt; Y_B{/tex}</span></li>
	<li>
	<p>Strength of the material is determined by the amount of stress required to cause fracture. Fracture point is the extreme point in a stress-strain curve.</p>

	<p>It can be observed that material A can withstand more strain than material B. Hence, material A is stronger than material B.</p>
	</li>
	<li>Material with smaller plastic range&nbsp;is more brittle, therefore B is more brittle than A</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define stress and strain and derive their units. What is Hooke&#39;s law? Write its one limitation.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Stress :-</p>

<p>It is the restoring force per unit area in the body when it is being deformed by external forces. Mathematically, it&nbsp;is equal to force applied per unit area i.e., stress&nbsp;<span class="math-tex">{tex}= \\frac { \\text { Force } } { \\text { area } } = \\frac { F } { A }{/tex}</span></p>

<p>SI unit = <span class="math-tex">{tex}N m^{-2}{/tex}</span> or <span class="math-tex">{tex}Pa{/tex}</span> and its dimensional formula is <span class="math-tex">{tex}[M^1L^{-1}T^{-2}]{/tex}</span>.</p>

<p>Strain :-</p>

<p>It is defined as the ratio of the change in dimension of a body to its original dimension. It is a unitless and dimensionless quantity.</p>

<p>Hooke&#39;s Law :-</p>

<p>It states that within the limit of elasticity, the stress induced (&sigma; ) in the solid due to some external force is always in proportion with the strain</p>

<p>Hooke&#39;s law is applicable only up to elastic limit.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>The stress-strain graph for a metal wire is given in the figure. Up to the point B, the wire returns to its original state O along the curve BAO, when it is gradually unloaded. Point E corresponds to the fracture point of the wire.<br/>
<img alt="" data-imgur-src="JSVCLrM.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/JSVCLrM.png" style="width: 200px; height: 201px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Up to which point of curve, is Hooke's law obeyed? This point is also called 'Proportionality limit'.</li>
<li>Which point on the curve corresponds to elastic limit and yield point of the wire?</li>
<li>Indicate the elastic and plastic regions of the stress-strain curve.</li>
<li>What change happens when the wire is loaded up to a stress corresponding to point C on curve, and then unloaded gradually?</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Hooke&#39;s law is followed&nbsp;up to point A.</li>
	<li>Point B corresponds to&nbsp;elastic limit and yield point of given wire.</li>
	<li>&nbsp;<span class="math-tex">{tex}OB{/tex}</span> represents the elastic region while <span class="math-tex">{tex}BD{/tex}</span> represents the plastic region.</li>
	<li>When the given wire is loaded up to a stress corresponding to point C&nbsp;and then unloaded, it does not regain its original configuration even on complete unloading. The material has some strain left <span class="math-tex">{tex}(OO'){/tex}</span>, which is called a permanent set.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>The stress-strain graph for a metal wire is given in the figure. Up to the point B, the wire returns to its original state O along the curve BAO, when it is gradually unloaded. Point E corresponds to the fracture point of the wire.</p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Up to which point of the curve, is Hook's law obeyed? This point is also called 'Proportionality limit'.</li>
<li>Which point on the curve corresponds to elastic limit and yield point of the wire?</li>
<li>Indicate the elastic and plastic regions of the stress-strain curve.</li>
<li>What change happens when the wire is loaded up to a stress corresponding to point C on a curve, and then unloaded gradually?<br/>
<img alt="" data-imgur-src="3IIfvT4.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/3IIfvT4.png" style="width: 140px; height: 150px;"/></li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Hooke&#39;s law is obeyed up to point A of the stress-strain curve.</li>
	<li>Point B on the curve corresponds to elastic limit and yield point of a given wire.</li>
	<li>The region OB on the stress-strain curve represents the elastic region. The region BD on the stress-strain curve represents the plastic region.</li>
	<li>When the given wire is loaded up to a stress corresponding to point C on the curve and then unloaded gradually, it does not regain its original configuration even on complete unloading. The material has some strain left (OO&#39;), which is called a permanent set.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Consider a solid cube which is subjected to a pressure of&nbsp;6&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup> N/m<sup>2</sup>. Due to this pressure, each side of the cube is&nbsp;shortened by 2%. Find&nbsp;out the Volumetric Strain of the cube.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Suppose L be the initial length of each side of the cube.<br />
Volume,<span class="math-tex">{tex}V = L\\times  L\\times  L =L^3 {/tex}</span><br />
= Initial volume (V<sub>i</sub>&nbsp;say)<br />
If each side of the cube is shortened by 2%, then final&nbsp;length of the cube =<span class="math-tex">{tex} L - 2\\text%\\ of\\ L {/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\left(L-\\frac{2 L}{100}\\right)=L\\left(1-\\frac{2}{100}\\right){/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Final volume, <span class="math-tex">{tex}V_f = L^3{/tex}</span><sup>&nbsp;</sup><span class="math-tex">{tex}\\left(1-\\frac{2}{100}\\right)^{3}=V\\left(1-\\frac{2}{100}\\right)^{3}{/tex}</span><br />
Change in volume,&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span><span class="math-tex">{tex}V = V_f - V_i = V{/tex}</span><span class="math-tex">{tex}\\left(1-\\frac{2}{100}\\right)^{3}{/tex}</span>&nbsp;<span class="math-tex">{tex}- V {/tex}</span><br />
&nbsp;<span class="math-tex">{tex}=V\\left[\\left(1-\\frac{2}{100}\\right)^{3}-1\\right]{/tex}</span><br />
<span class="math-tex">{tex}\\frac{\\Delta V}{V}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\left(1-\\frac{2}{100}\\right)^{3}{/tex}</span>&nbsp;- 1 =&nbsp;<span class="math-tex">{tex}\\left[1-\\frac{2 \\times 3}{100}\\right]{/tex}</span>-1&nbsp; [<span class="math-tex">{tex}\\because{/tex}</span>&nbsp;<span class="math-tex">{tex}(1-x)^n = 1 -nx\\ for\\ x &lt;&lt;1{/tex}</span>]<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Volumetric strain =&nbsp;<span class="math-tex">{tex}\\frac{\\Delta V}{V}{/tex}</span>&nbsp;<span class="math-tex">{tex}= 1 - 0.06 - 1{/tex}</span>&nbsp;= -0.06&nbsp;(take positive sign)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State Hooke&#39;s law. How can it be verified experimentally?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to Hooke&#39;s law, within elastic limit, the stress is directly proportional to strain. Mathematically,<br />
<span class="math-tex">{tex}stress \\propto strain{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac { \\text { stress } } { \\text { strain } }{/tex}</span>=&nbsp;E, which is called the modulus of elasticity.<br />
<img alt="" data-imgur-src="qhsJblW.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/qhsJblW.png" style="width: 200px; height: 140px;" /></p>

<p>Suspend a spring from a rigid support and attach a pan and a sharp pointer P at its lower end. The pointer slides over a vertical scale. On placing weights in the pan, length of spring increases. It is found that increase in length of spring on placing weights is directly proportional to the weight (load applied). Graph between load and extension comes out to be a straight line which verifies Hooke&#39;s law.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A rubber block 1cm <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;3 cm <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10&nbsp;cm is clamped at one end with its 10 cm side vertical. A horizontal force of 30 N is applied to the free surface. What is the horizontal displacement of the top face?&nbsp;Modulus of rigidity of rubber = 1.4 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>5</sup> Nm<sup>-2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Area of the upper face, A = 1 cm <span class="math-tex">{tex}\\times{/tex}</span> 3 cm = 3 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-4</sup> m<sup>2</sup> <br/>
F = 30 N, <span class="math-tex">{tex}\\eta{/tex}</span> = 1.4 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>5</sup> Nm<sup>-2</sup>, l = 10 cm = 0.10 m<br/>
<img alt="" data-imgur-src="vRz7WNi.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082796-pzb5y4.jpg" style="width: 300px; height: 317px;"/><br/>
As <span class="math-tex">{tex}\\eta=\\frac{F}{A} \\cdot \\frac{l}{\\Delta l}{/tex}</span> <br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> <span class="math-tex">{tex}\\Delta l{/tex}</span> = <span class="math-tex">{tex}\\frac{F}{A} \\cdot \\frac{l}{\\eta}=\\frac{30 \\times 0.10}{3 \\times 10^{-4} \\times 1.4 \\times 10^{5}}{/tex}</span> <br/>
= <span class="math-tex">{tex}\\frac{1}{14}{/tex}</span> = 0.0714 m = 7.14 cm</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Explain the following:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Concrete beams used in large buildings have greater depth than breadths.</li>
	<li>Load bearing bars are generally made in I-section.</li>
	<li>Pillar with distributed ends is preferred over a pillar with rounded ends.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><ol start="1" style="list-style-type: lower-roman;">
<li> The major function of beam is to resist moment generated by applied load or to resist the deflection which generates again high Moment on beam. So this applied Moment is resisted through the special property of beam “EI” which includes type of material (Modulus of Elasticity) and dimensions of beam (width &amp; depth). Concrete beams are commonly used in large buildings to support the weight of roof. It is found that depression of a beam of length l, breadth b and depth d when loaded at the centre by a load W and supported at the ends on walls in the middle is given by<br/>
<span class="math-tex">{tex}\\delta=\\frac{W l^{3}}{4 b d^{3} \\gamma}{/tex}</span><br/>
	Thus, to have less depression we prefer a beam of greater depth (because <span class="math-tex">{tex}\\delta \\propto \\frac{1}{d^{3}}{/tex}</span>).</li>
<li>A bar of rectangular section with large depth may buckle as shown in Fig. (b), when the load W is not at the right place. To avoid this, we use a I-section beam. It provides a large load bearing surface, enough depth to prevent bending. The shape reduces the weight of the beam without sacrificing the strength and hence reduces the cost.<br/>
<img alt="" data-imgur-src="u61N7j1.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/u61N7j1.png" style="width: 140px; height: 103px;"/></li>
<li>A pillar with distributed ends, as shown in Fig. (b) is preferred over a pillar with rounded ends because it supports much more load than a pillar with rounded ends.<br/>
<img alt="" data-imgur-src="L9PxIKd.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/L9PxIKd.png" style="width: 91px; height: 110px;"/></li>
</ol></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two strips of metal are riveted together at their ends by four rivets, each of diameter 6.0 mm. What is the maximum tension that can be exerted by the riveted strip if the shearing stress on the rivet is not to exceed 2.3 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup>&nbsp;Pa? Assume that each rivet is to carry one-quarter of the load.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Let the tension exerted by riveted strip = F <br/>
This tension would provide shearing force on the four rivets, which share it equally.<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> Shearing force on each rivet = <span class="math-tex">{tex}\\frac{F}{4}{/tex}</span> <br/>
and shearing stress on each rivet = <span class="math-tex">{tex}\\frac{F / 4}{A}=\\frac{F}{4 A}{/tex}</span> <br/>
<img alt="" data-imgur-src="fgaZwnz.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082616-5tm5kk.jpg" style="width: 150px; height: 40px;"/><br/>
As the maximum shearing stress on each rivet is given to be 2.3 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup> Pa, so we have<br/>
<span class="math-tex">{tex}\\frac{F_{\\max }}{4 A}=2.3 \\times 10^{9}{/tex}</span> <br/>
or F<sub>max</sub> = <span class="math-tex">{tex}4 A \\times 2.3 \\times 10^{9}{/tex}</span> = <span class="math-tex">{tex}4 \\times \\pi r^{2} \\times 2.3 \\times 10^{9}{/tex}</span> <br/>
= <span class="math-tex">{tex}4 \\times \\frac{22}{7} \\times\\left(3.0 \\times 10^{-3}\\right)^{2} \\times 2.3 \\times 10^{9}{/tex}</span> <br/>
= 260.2 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>3</sup> N = 260 kN</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Four identical hollow cylindrical columns of mild steel support a big structure of mass 50,000 kg. The inner and outer radii of each column are 30 cm and 60 cm respectively. Assuming the load distribution to be uniform, calculate the compressional strain of each column.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given</p>

<p>M = 50,000 kg<br />
Inner radius of the column, r = 30 cm = 0.3 m<br />
Outer radius of the column, R = 60 cm = 0.6 m<br />
young&#39;s modulus Y = <span class="math-tex">{tex}2 \\times 10 ^ { 11 }{/tex}</span> pa<br />
Total force exerted, F = Mg = 50000 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8 N<br />
Stress = Force on one column=5000x9.8/4=122500&nbsp;N&nbsp;<br />
&nbsp;<span class="math-tex">{tex}Y = \\frac { \\text { Stress } } { \\text { Strain } }{/tex}</span><br />
<br />
cross section area of column&nbsp;<span class="math-tex">{tex}A = \\pi \\left( R ^ { 2 } - r ^ { 2 } \\right) = \\pi \\left( ( 0.6 ) ^ { 2 } - ( 0.3 ) ^ { 2 } \\right){/tex}</span></p>

<p>Compressive strain <span class="math-tex">{tex} = \\frac { 122500 } { \\pi \\left[ ( 60 ) ^ { 2 } - ( 0.30 ) ^ { 2 } \\right] \\times 2 \\times 10 ^ { 11 } }{/tex}</span><br />
<span class="math-tex">{tex}= 7.22 \\times 10 ^ { - 7 }{/tex}</span>&nbsp;.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A steel wire and a copper wire of equal length and equal cross-sectional area are joined end to end and the combination is subjected to a tension. Find the ratio of (a) the stresses developed in the two wires, (b) the strains developed in two wires. Given that Y of steel = 2.0 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>11</sup> N/m<sup>2</sup> and Y of copper = 1.1 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>11</sup> N/m<sup>2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, <span class="math-tex">{tex}L_1 = L_2, A_1 = A_2{/tex}</span> and F is same.</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Stress&nbsp;<span class="math-tex">{tex}\\sigma = \\frac { F } { A }{/tex}</span>&nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span> stress in steel wire and in copper wire are equal.</li>
	<li>Strain&nbsp;<span class="math-tex">{tex}\\varepsilon = \\frac { \\Delta L } { L } = \\frac { \\text { stress } } { Y }{/tex}</span>and stress is equal.<br />
	<span class="math-tex">{tex}\\frac { \\varepsilon _ { \\text { steel } } } { \\varepsilon _ { \\text { copper } } } = \\frac { Y _ { \\text {copper} } } { Y _ { \\text { steel } } } = \\frac { 1.1 \\times 10 ^ { 11 } } { 2.0 \\times 10 ^ { 11 } } = \\frac { 11 } { 20 } = 0.55 : 1{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A piece of copper having a rectangular cross-section of 15.2 mm <span class="math-tex">{tex}\\times{/tex}</span> 19.1 mm is pulled intension with 44,500 N force, producing only elastic deformation. Calculate the resulting strain?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Length of the piece of copper is,&nbsp;<span class="math-tex">{tex}l = 19.1 \\mathrm { mm } = 19.1 \\times 10 ^ { - 3 } \\mathrm { m }{/tex}</span><br />
Breath of the piece of copper is,&nbsp;<span class="math-tex">{tex}b = 15.2 \\mathrm { mm } = 15.2 \\times 10 ^ { - 3 } \\mathrm { m }{/tex}</span><br />
Area of the copper piece is given by :&nbsp;<span class="math-tex">{tex}A = l \\times b = 19.1 \\times 15.2 \\times 10 ^ { - 6 } m ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}A = 2.9 \\times 10 ^ { - 4 } m ^ { 2 }{/tex}</span><br />
Tension force applied on the piece of copper is, F = 44500 N<br />
Shear modulus of copper,&nbsp;<span class="math-tex">{tex}G = 42 \\times 10 ^ { 9 } N m ^ { - 2 }{/tex}</span><br />
Shear Modulus&nbsp;<span class="math-tex">{tex}G = \\frac { \\text { shearing stress } } { \\text { shearing strain } } = \\frac { \\frac { F } { A } } { \\text {strain} }{/tex}</span><br />
since&nbsp;<span class="math-tex">{tex}strain =\\frac{F}{A\\eta}{/tex}</span><br />
strain =<span class="math-tex">{tex}\\frac { 44500 } { 42 \\times 10 ^ { 9 } \\times 2.9 \\times 10 ^ { - 4 } }{/tex}</span><br />
Hence, strain is given by&nbsp;&nbsp;<span class="math-tex">{tex}= 3.65 \\times 10 ^ { - 3 }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is the percentage increase in the length of a&nbsp;wire of diameter 2.5 mm stretched by a force of&nbsp;100 kg weight. Young&rsquo;s modulus of elasticity of&nbsp;wire is 12.5 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>11</sup> dyne/sq cm.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here&rsquo; <span class="math-tex">{tex}2r = 2.5 mm = 0.25 cm{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}r = 0.125 cm{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;a = <span class="math-tex">{tex}\\pi{/tex}</span>r<sup>2&nbsp;</sup>=&nbsp;<span class="math-tex">{tex}\\frac{22}{7}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;<span class="math-tex">{tex}(0.125)^2 sq. cm{/tex}</span><br />
<span class="math-tex">{tex}F = 100 kg = 100\\times  1000 g{/tex}</span><br />
<span class="math-tex">{tex}p = 10\\times  1000\\times  980\\ dyne{/tex}</span><br />
<span class="math-tex">{tex}Y = 12.5 \\times10^{11}\\ dyne/sq. cm{/tex}</span><br />
As Y =&nbsp;<span class="math-tex">{tex}\\frac{F \\times l}{a \\times \\Delta l}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{\\Delta l}{l}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{F}{a Y}{/tex}</span><br />
Hence, % increase in length<br />
=&nbsp;<span class="math-tex">{tex}\\frac{\\Delta l}{l}{/tex}</span><span class="math-tex">{tex}\\times{/tex}</span>&nbsp;100 =&nbsp;<span class="math-tex">{tex}\\frac{F}{a Y}{/tex}</span><span class="math-tex">{tex}\\times{/tex}</span>100<br />
=&nbsp;<span class="math-tex">{tex}\\frac{(100 \\times 1000 \\times 980) \\times 7 \\times 100}{22 \\times(0.125)^{2} \\times 12.5 \\times 10^{11}}{/tex}</span><br />
<span class="math-tex">{tex}= 0.1812\\text%{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>After a fall, a 95 kg rock climber finds himself dangling from the end of a rope that had been 15 m long and 9.6 mm in diameter but has stretched by 2.8 cm. For the rope, calculate</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>the strain,</li>
	<li>the stress and</li>
	<li>the modulus of elasticity.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here, <span class="math-tex">{tex}L =1500 cm{/tex}</span> is the unstretched length of the rope,&nbsp;<br />
<span class="math-tex">{tex}\\Delta{/tex}</span><span class="math-tex">{tex}L = 2.8 cm{/tex}</span> is the amount of length stretches.<br />
The strain&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{\\Delta L}{L}=\\frac{28 \\mathrm{cm}}{1500 \\mathrm{cm}}{/tex}</span>&nbsp;= 1.9&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup><br />
<span class="math-tex">{tex}Stress =\\frac{ Force}{ Area}{/tex}</span>&nbsp;<br />
Force, F = force of gravity on the rock climber&nbsp;<br />
<span class="math-tex">{tex}= mg = 95\\times  9.8 N{/tex}</span><br />
Area, A =&nbsp;<span class="math-tex">{tex}\\pi{/tex}</span>r<sup>2</sup>&nbsp;=&nbsp;<span class="math-tex">{tex}\\pi{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left(\\frac{D}{2}\\right)^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\pi{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left(\\frac{9.6}{2} \\times 10^{-3} \\mathrm{m}\\right)^{2}{/tex}</span><br />
Stress =&nbsp;<span class="math-tex">{tex}\\frac{95 \\times 9.8}{\\pi \\times(4.8)^{2} \\times 10^{-6}}{/tex}</span>&nbsp;<span class="math-tex">{tex}= 1.29\\times  10^7 N/m^2{/tex}</span><br />
Hence, E =&nbsp;<span class="math-tex">{tex}\\frac{\\text { Stress }}{\\text { Strain }}=\\frac{1.3 \\times 10^{7}}{1.9 \\times 10^{-3}}{/tex}</span>&nbsp;<span class="math-tex">{tex}= 6.84\\times  10^9 N/m^2{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Consider a steel rod having a radius of 8 mm and&nbsp;the length&nbsp;of 2m: If&nbsp;a force of 150 kN stretches it along its length,&nbsp;then calculate the stress and&nbsp;percentage strain in&nbsp;the rod if&nbsp;the elongation in length is 7.46 mm.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If the rod fetches along its&nbsp;length then the stress&nbsp;produced is the tensile stress whereas the strain&nbsp;produced is a longitudinal strain.<br />
Radius =&nbsp;8 mm&nbsp;=&nbsp;8&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>10<sup>-3</sup>&nbsp;m<br />
Length,&nbsp;L = 2 m<br />
Force, F = 150 kN&nbsp; = 15&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>4</sup>&nbsp;N<br />
Area, A = <span class="math-tex">{tex}\\pi{/tex}</span>r<sup>2</sup> =&nbsp;<span class="math-tex">{tex}\\pi{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;<span class="math-tex">{tex}(8\\times 10^{-3})^2 {/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}201\\times  10^{-6} m^2{/tex}</span><br />
<span class="math-tex">{tex}\\Delta L=7.46 \\mathrm{mm}{/tex}</span>&nbsp;<span class="math-tex">{tex}= 7.46 \\times 10^{-3} m{/tex}</span>, percentage strain = ?<br />
Stress =&nbsp;<span class="math-tex">{tex}\\frac{F}{A}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{15 \\times 10^{4}}{201 \\times 10^{-6}}{/tex}</span>&nbsp;= 0.0746&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>10</sup> N/m<sup>2</sup><br />
= 7.46&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>8</sup>&nbsp;N/m<sup>2</sup><br />
Longitudinal strain =&nbsp;<span class="math-tex">{tex}\\frac{\\Delta L}{L}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{7.46 \\times 10^{-3}}{2}{/tex}</span>&nbsp;= 3.73&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup><br />
Percentage strain = 3.73&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-</sup><sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;100 = 0.37%</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>A rod of length 1.05 m having negligible mass is supported at its ends by two wires of steel (wire A) and aluminium (wire B) of equal lengths as shown in Figure. The cross-sectional areas of wires A and B are 1.0 mm<sup>2</sup> and 2.0 mm<sup>2</sup>, respectively. At what point along the rod should a mass m be suspended in order to produce<br/>
<img alt="" data-imgur-src="CvBh6YK.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614338799-hca4fn.jpg" style="width: 200px; height: 163px;"/></p>
<ol start="1" style="list-style-type: lower-alpha;">
<li>equal stresses and</li>
<li>equal strains in both steel and aluminium wires</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>For steel wire A, l<sub>1</sub> = l; A<sub>z</sub> = 1 mm<sup>2</sup>; Y<sub>1</sub> = 2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>11 </sup>Nm<sup>-2</sup><br />
For aluminium wire B, l<sub>2</sub> = l; A<sub>2</sub> = 2mm<sup>2</sup>; Y<sup>2</sup> = 7&nbsp;<span class="math-tex">{tex}\\times {/tex}</span>&nbsp;10<sup>10 </sup>Nm<sup>-2</sup></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Let mass m&nbsp;be suspended from the rod at distance x&nbsp;from the end where wire A&nbsp;is connected. Let F<sub>1</sub>&nbsp;and F<sub>2</sub>&nbsp;be the tensions in two wires and there is equal stress in two wires, then<br />
	<span class="math-tex">{tex}\\frac{F_{1}}{A_{1}}=\\frac{F_{2}}{A_{2}} \\Rightarrow \\frac{F_{1}}{F_{2}}=\\frac{A_{1}}{A_{2}}=\\frac{1}{2}{/tex}</span>&nbsp;.... (i)<br />
	Taking moment of forces about the point of suspension of mass from the rod, we have<br />
	F<sub>1</sub>x = F<sub>2</sub>(1.05 - x) or&nbsp;<span class="math-tex">{tex}\\frac{1.05-x}{x}=\\frac{F_{1}}{F_{2}}=\\frac{1}{2}{/tex}</span><br />
	or 2.10 - 2x = x&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;x = 0.70 m = 70 cm</li>
	<li>Let mass m be suspended from the rod at distance x&nbsp;from the end where wire A&nbsp;is connected. Let F<sub>1</sub>&nbsp;and F<sub>2</sub>&nbsp;be the tension in the wires and there is equal strain in the two wires i.e.<br />
	<span class="math-tex">{tex}\\frac{F_{1}}{A_{1} Y_{1}}=\\frac{F_{2}}{A_{2} Y_{2}} \\Rightarrow \\frac{F_{1}}{F_{2}}{/tex}</span><span class="math-tex">{tex}=\\frac{A_{1} Y_{1}}{A_{2} Y_{2}}=\\frac{1}{2} \\times \\frac{2 \\times 10^{11}}{7 \\times 10^{10}}=\\frac{10}{7}{/tex}</span><br />
	As the rod is stationary, so F<sub>1</sub>x = F<sub>2</sub>(1.05 - x) or&nbsp;<span class="math-tex">{tex}\\frac{1.05-x}{x}=\\frac{F_{1}}{F_{2}}=\\frac{10}{7}{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;10x = 7.35 - 7x or x = 0.4324m = 43.2 cm</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A solid cube is subjected to a pressure of 5 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>5</sup> Nm<sup>-2</sup>. Each side of the cube is shortened by 1%. Find the volumetric strain and bulk modulus of elasticity of the cube.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let l&nbsp;be the initial length of each side of the cube.<br />
Final length of the cube = l - 1% of l =&nbsp;<span class="math-tex">{tex}\\left(1-\\frac{1}{100}\\right) l{/tex}</span>&nbsp;<br />
Initial volume, V<sub>i</sub> = l<sup>3</sup> = V (say)<br />
Final volume,<br />
V<sub>f</sub> =&nbsp;<span class="math-tex">{tex}\\left(1-\\frac{1}{100}\\right)^{3} l^{3}=\\left(1-\\frac{1}{100}\\right)^{3} V{/tex}</span>&nbsp;<br />
Change in volume,<br />
<span class="math-tex">{tex}\\Delta V{/tex}</span>&nbsp;= V<sub>f</sub> - V<sub>i</sub> =&nbsp;<span class="math-tex">{tex}V\\left[\\left(1-\\frac{1}{100}\\right)^{3}-1\\right]{/tex}</span><br />
Volumetric strain<br />
=&nbsp;<span class="math-tex">{tex}\\frac{\\Delta V}{V}=\\left(1-\\frac{1}{100}\\right)^{3}-1{/tex}</span>&nbsp;<span class="math-tex">{tex}\\simeq\\left[1-3 \\times \\frac{1}{100}\\right]-1{/tex}</span>&nbsp;[(1 - x)n&nbsp;<span class="math-tex">{tex}\\simeq{/tex}</span>&nbsp;1 - nx for x &lt;&lt; 1]<br />
=&nbsp;<span class="math-tex">{tex}-\\frac{3}{100}{/tex}</span>&nbsp;= -0.03<br />
Normal stress = Applied pressure = 5 <span class="math-tex">{tex}\\times{/tex}</span> 10 Nm<sup>-2</sup><br />
Bulk modulus,<br />
<span class="math-tex">{tex}\\kappa=\\frac{\\text { Normal stress }}{\\text { Volumetric strain }}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{5 \\times 10^{5}}{0.03}{/tex}</span>&nbsp;= 1.67&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>7</sup> Nm<sup>-2</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is elastic potential energy? Derive an expression for the elastic potential energy of a stretched wire. Prove that its elastic energy density is equal to <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>stress <span class="math-tex">{tex}\\times{/tex}</span> strain.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Elastic potential energy:</strong>&nbsp;When a wire is stretched, interatomic forces come into play that opposes the change. Work has to be done against these restoring forces. The work done in stretching the wire is stored in it as its elastic potential energy.<br />
The expression for elastic potential energy. Suppose a force F applied on a wire of length l increases its length by <span class="math-tex">{tex}\\Delta l{/tex}</span>. Initially, the internal restoring force in the wire is zero. When the length is increased by <span class="math-tex">{tex}\\Delta l{/tex}</span>, the internal force increases from zero to F (= applied force).<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Average internal force for an increase in the length <span class="math-tex">{tex}\\Delta l{/tex}</span> of wire<br />
=&nbsp;<span class="math-tex">{tex}\\frac{0+F}{2}=\\frac{F}{2}{/tex}</span>&nbsp;<br />
Work done on the wire is<br />
W = Average force <span class="math-tex">{tex}\\times{/tex}</span> increase in length =&nbsp;<span class="math-tex">{tex}\\frac{F}{2} \\times \\Delta l{/tex}</span>&nbsp;<br />
This work done is stored as elastic potential energy U in the wire.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;U =&nbsp;<span class="math-tex">{tex}\\frac{1}{2} F \\times \\Delta l{/tex}</span>&nbsp;<br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;Stretching force&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;increase in length<br />
Let A be the area of the cross-section of the wire. Then<br />
U =&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\frac{F}{A} \\times \\frac{\\Delta l}{l} \\times A l{/tex}</span>&nbsp;<br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;Stress&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;strain&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;volume of wire<br />
Elastic potential energy per unit volume of the wire or elastic energy density is<br />
u =&nbsp;<span class="math-tex">{tex}\\frac{U}{\\text { Volume }}{/tex}</span>&nbsp;<br />
or u =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;stress&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;strain<br />
But stress = Young&#39;s modulus&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;strain<br />
&nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;u =&nbsp;<span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>&nbsp;Young&#39;s modulus&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;strain<sup>2</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define Young&#39;s modulus, bulk modulus and modulus of rigidity. Write mathematical expressions for these moduli. What is compressibility?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Young&#39;s modulus of elasticity:</strong>&nbsp;It is defined as the ratio of longitudinal stress to the longitudinal strain within the elastic limit.<br />
It is given by<br />
Y =&nbsp;<span class="math-tex">{tex}\\frac{\\text { Longitudinal stress }}{\\text { Longitudinal strain }}=\\frac{F / A}{\\Delta l / l}=\\frac{F}{A} \\cdot \\frac{l}{\\Delta l}{/tex}</span><br />
<strong>Bulk modulus of elasticity:</strong>&nbsp;It is defined as the ratio of normal stress to volumetric strain within the elastic limit.<br />
It is given by<br />
<span class="math-tex">{tex}\\kappa=\\frac{\\text { Normal stress }}{\\text { Volumetric strain }}=-\\frac{F / A}{\\Delta V / V}{/tex}</span>&nbsp;<br />
=&nbsp;<span class="math-tex">{tex}-\\frac{p}{\\Delta V / V}=-\\frac{p V}{\\Delta V}{/tex}</span>&nbsp;<br />
The negative sign shows that the volume decreases with the increase in stress.<br />
<strong>Modulus of rigidity:</strong> It is defined as the ratio of tangential stress to shear strain within the elastic limit. It is given by<br />
<span class="math-tex">{tex}\\eta=\\frac{\\text { Tangential stress }}{\\text { Shear strain }}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{F / A}{\\theta}=\\frac{F / A}{\\Delta l / l}=\\frac{F}{A} \\cdot \\frac{l}{\\Delta l}{/tex}</span>&nbsp;<br />
<strong>Units of moduli of elasticity:</strong>&nbsp;As strain is a pure ratio, the unit of elasticity is the same as that of stress. So SI unit of Y, <span class="math-tex">{tex}\\kappa{/tex}</span> or <span class="math-tex">{tex}\\eta{/tex}</span> is Nm<sup>-2</sup> and the CGS unit is dyne cm<sup>-2</sup>.<br />
<strong>Compressibility:</strong>&nbsp;The reciprocal of the bulk modulus of a material is called its compressibility. Compressibility =&nbsp;<span class="math-tex">{tex}\\frac{1}{\\kappa}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>The stress-strain graph for a metal wire is shown in the figure. Upto point E, the wire returns to its original state O along the curve EPO when it is gradually unloaded. Point B corresponds to the fracture of the wire.<br/>
<img alt="" data-imgur-src="SSf4kBB.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082799-6gya3h.jpg" style="width: 250px; height: 224px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Up to which point on the curve is Hooke's law obeyed? This point is sometimes called the Proportionality limit.</li>
<li>Which point on the curve corresponds to the elastic limit and yield point of the wire?</li>
<li>Indicate the elastic and plastic regions of the stress-strain graph.</li>
<li>Describe what happens when the wire is loaded up to a stress corresponding to point A on the graph and then unloaded gradually. In particular, explain the dotted curve.</li>
<li>What is peculiar about the portion of the stress-strain graph from C to B? Up to what stress can the wire be subjected without causing fracture?</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Hooke&#39;s law is obeyed upto the point P, because upto this point, stress <span class="math-tex">{tex}\\propto{/tex}</span> strain.</li>
	<li>Point E corresponds to the elastic limit because the wire returns to the original state Oalong EPO if it is gradually unloaded.</li>
	<li>The elastic region is from O to E and the plastic region is from E to B.</li>
	<li>Upto point P, stress is proportional to strain. Between P and E, strain increases more rapidly than stress, and Hooke&#39;s law is not obeyed. When the wire is unloaded at any point A beyond E, the wire does not retrace the curve AEPObut follows the dashed curve AO&#39;. When the stress becomes zero, a residual strain OO&#39; is left in the wire.</li>
	<li>Between C and B, the wire virtually flows out, i.e., the strain increases even when the wire is being unloaded. Fracture takes place at point B. The stress can be applied to the value corresponding to point C without causing a fracture.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Describe stress-strain relationship for a loaded steel wire and hence explain the terms elastic limit, yield point, tensile strength.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The material&rsquo;s stress-strain curve gives its stress-strain relationship. In a stress-strain curve, the stress and its corresponding strain values are plotted. An example of a stress-strain curve is given below.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1705044296-ppvj7x.jpg" style="height:244px; width:250px" /><br />
<strong>Tensile Strain</strong><br />
The deformation or elongation of a solid body due to applying a tensile force or stress is known as Tensile strain. In other words, tensile strain is produced when a body increases in length as applied forces try to stretch it.<br />
<strong>Elastic Limit</strong><br />
It is the point in the graph up to which the material returns to its original position when the load acting on it is completely removed. Beyond this limit, the material doesn&rsquo;t return to its original position, and a plastic deformation starts to appear in it.<br />
<strong>Yield Point</strong><br />
The yield point is defined as the point at which the material starts to deform plastically. After the yield point is passed, permanent plastic deformation occurs. There are two yield points</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>upper yield point</li>
	<li>lower yield point.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define Young&#39;s modulus of elasticity. Describe an experiment for the determination of Young&#39;s modulus of the material of a wire.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><strong>Young's modulus of elasticity:</strong> Within the elastic limit, the ratio of longitudinal stress to the longitudinal strain is called Young's modulus of the material of the wire.<br/>
Experiment to determine Young's modulus of the material of a wire: A simple experimental arrangement used for the determination of Young's modulus of the material of a wire is shown in the figure. It consists of two long straight wires of the same length and equal radius suspended side by side from a fixed rigid support. Wire A called the reference wire carries the main milliammeter scale M and below it a heavy fixed load. This load keeps the wire taught and free from kinks. Wire B, called the experimental wire, carries a vernier scale at its bottom. The vernier scale can slide against the main scale attached to the reference wire. A hanger is attached at the lower end of the vernier scale. Slotted half kg weights can be slipped into this hanger.<br/>
<img alt="" data-imgur-src="IvSizaK.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082625-efpzf8.jpg" style="width: 150px; height: 195px;"/><br/>
A graph is plotted between the load applied and the extension produced. It will be a straight line passing through the origin, as shown in the figure.<br/>
The slope of the load extension line = <span class="math-tex">{tex}\\tan \\theta=\\frac{\\Delta L}{M g}{/tex}</span> <br/>
Stress = <span class="math-tex">{tex}\\frac{M g}{\\pi r^{2}}{/tex}</span> <br/>
Strain = <span class="math-tex">{tex}\\frac{\\Delta L}{L}{/tex}</span> <br/>
The Young's modulus of the material of the experimental wire will be<br/>
Y = <span class="math-tex">{tex}\\frac{\\text { Stress }}{\\text { Strain }}=\\frac{M g}{\\pi r^{2}} \\cdot \\frac{L}{\\Delta L}=\\frac{L}{\\pi r^{2} \\tan \\theta}{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A typical experimental arrangement to determine the Young&#39;s modulus of a material of wire under tension is shown in figure. It consists of two long straight wires of the same length and equal radii suspended side-by-side from a fixed rigid support. The wire A (called the reference wire) carries a millimeter main scale M and a pan to place a weight.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658484677-d2g659.jpg" style="height:160px; width:300px" /><br />
The wire B (Called the experimental wire) of uniform area of cross-section also carries a pan in which known weights can be placed, vernier scale is attached to a pointer at the bottom of experimental wire B and main scale is fixed to the reference wire A.</p>

<ol>
	<li>When a weight is placed in the pan, which type of stress is produced?&nbsp;<strong>(1)</strong></li>
	<li>Suppose M be the mass of wire that produced an elongation&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>L in the wire, then how much force should required to produced this elongation.&nbsp;<strong>(1)</strong></li>
	<li>Write the formula of Young&#39;s modulus of an experimental wire?&nbsp;<strong>(2)</strong></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>The weights placed in the pan exert a downward force and stretch the experimental wire under a&nbsp;tensile stress.</li>
	<li>Mg&nbsp;force&nbsp;required to produced <span class="math-tex">{tex}\\Delta{/tex}</span>L&nbsp;elongation.</li>
	<li>Formula of Young&#39;s modulus of an experimental wire&nbsp;is&nbsp;<span class="math-tex">{tex}Mg \\times \\frac {L}{(\\pi r^2 \\times \\Delta L)}{/tex}</span>.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A steel wire of length 4.7 m and cross-sectional area <span class="math-tex">{tex}3.0 \\times 10 ^ { - 5 } \\mathrm { m } ^ { 2 }{/tex}</span> stretches by the same amount as a copper wire of length 3.5 m and cross-sectional area of <span class="math-tex">{tex}4.0 \\times 10 ^ { - 5 } \\mathrm { m } ^ { 2 }{/tex}</span> under a given load. What is the ratio of the Young&#39;s modulus of steel to that of copper?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Length of the steel wire, L<sub>1</sub> = 4.7&nbsp;m<br />
Area of cross-section of the steel wire,&nbsp;<span class="math-tex">{tex}A _ { 1 } = 3.0 \\times 10 ^ { - 5 } m ^ { 2 }{/tex}</span><br />
Length of the copper wire, L<sub>2</sub> = 3.5&nbsp;m<br />
Area of cross-section of the copper wire,&nbsp;<span class="math-tex">{tex}A _ { 2 } = 4.0 \\times 10 ^ { - 5 } m ^ { 2 }{/tex}</span><br />
Change in length in both wires is same. Thus<br />
<span class="math-tex">{tex}\\triangle L _ { 1 } = \\triangle L _ { 2 } = \\triangle L{/tex}</span><br />
Force applied in both the cases&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;F<br />
Young&#39;s modulus of the steel wire:&nbsp;<span class="math-tex">{tex}Y _ { 1 } = \\frac { F L _ { 1 } } { A _ { 1 } \\triangle L } = \\frac { F \\times 4.7 } { 3.0 \\times 10 ^ { - 5 } \\times \\triangle L }{/tex}</span> ........ (i)<br />
Young&#39;s modulus of the copper wire:&nbsp;<span class="math-tex">{tex}Y _ { 2 } = \\frac { F L _ { 2 } } { A _ { 2 } \\triangle L } = \\frac { F \\times 3.5 } { 4.0 \\times 10 ^ { - 5 } \\times \\triangle L }{/tex}</span> ....... (ii)<br />
Dividing (i) by (ii), we get:&nbsp;<span class="math-tex">{tex}\\frac { Y _ { 1 } } { Y _ { 2 } } = \\frac { 4.7 \\times 4.0 \\times 10 ^ { - 5 } } { 3.0 \\times 10 ^ { - 5 } \\times 3.5 }{/tex}</span><br />
<span class="math-tex">{tex}\\frac { Y _ { 1 } } { Y _ { 2 } } = 1.79 : 1{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Derive an expression for the elastic potential energy stored in a stretched wire under stress. Define the terms elastic after effect and elastic fatigue.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The work done in stretching a wire will be stored as its potential energy.<br />
Let us find the work done in stretching a wire<br />
Consider a wire of length L and cross-section area A<br />
stretched by a force F along its length.<br />
When the wire is stretched the strain and stress both increases proportionately.<br />
At equilibrium:<br />
The Young&#39;s modulus of the material of wire, <span class="math-tex">{tex}\\mathrm{Y}=\\frac{F L}{A X}{/tex}</span><br />
where x is the increase in the length of the wire.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> We can write F = <span class="math-tex">{tex}\\frac{Y A X}{L}{/tex}</span><br />
So the work done to extend the wire by an additional amount <span class="math-tex">{tex}\\Delta{/tex}</span>x will be:<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>W = F.<span class="math-tex">{tex}\\Delta{/tex}</span>x<br />
<span class="math-tex">{tex}\\Delta W=\\frac{Y A X}{L} \\Delta X{/tex}</span><br />
Therefore the total work done in extending the wire by an amount I is:<br />
<span class="math-tex">{tex} W=\\int\\limits_0^l \\frac{Y A X}{L} \\mathrm{dx} {/tex}</span><br />
<span class="math-tex">{tex}W=\\frac{Y A}{L}\\left[\\frac{x^2}{2}\\right]_0^l{/tex}</span><br />
<span class="math-tex">{tex}W=\\frac{1}{2} \\frac{V A l}{L} \\times l{/tex}</span><br />
This can be written as:<br />
<span class="math-tex">{tex}W=\\frac{1}{2} \\times F \\times I{/tex}</span> ...(i)<br />
i.e <span class="math-tex">{tex}W=\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> Stretching force <span class="math-tex">{tex}\\times{/tex}</span> extension<br />
This work done to deform the body is stored in the body as elastic potential energy Equation (i) can be written as<br />
<span class="math-tex">{tex}\\mathrm{W}=\\frac{1}{2} \\times \\frac{F}{A} \\times \\frac{l}{L} \\times A L{/tex}</span> (multiply and divide AL in numerator and denomenator)<br />
We know that <span class="math-tex">{tex}\\frac{F}{A}{/tex}</span>= stress and <span class="math-tex">{tex}\\frac{I}{A}{/tex}</span> = strain<br />
W = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> stress <span class="math-tex">{tex}\\times{/tex}</span> strain <span class="math-tex">{tex}\\times{/tex}</span> AL<br />
AL is the volume of the wire<br />
So work done per unit volume can be written as:<br />
<span class="math-tex">{tex}\\frac{\\mathrm{W}}{A L}-\\frac{1}{2} \\times \\text { stress } \\times \\text { strain }{/tex}</span><br />
This is the energy stored per unit volume of the wire.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>The potential energy stored per unit volume of the wire = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> stress <span class="math-tex">{tex}\\times{/tex}</span> strain<br />
Elastic after effect = The delay of certain substances in regaining their original shape after being deformed within their elastic limits.<br />
Elastic fatigue = The temporary loss of elastic properties because of the action of repeated alternating deforming force is called elastic fatigue.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1349-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_MECHANICAL_PROPERTIES_OF_FLUIDS = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The SI unit of coefficient of viscosity is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{Nm}{s}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\mathrm{Nm}^{2}}{\\mathrm{s}}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\mathrm{N}} {\\left(\\mathrm{m}^{2} \\mathrm{~s}^{-1}\\right)}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\eta=\\frac{F}{A} \\cdot \\frac{d x}{d v}{/tex}</span><br />
S.I. unit of&nbsp;<span class="math-tex">{tex}\\eta=\\frac{\\mathrm{N}}{\\mathrm{m}^{2}} \\cdot \\frac{\\mathrm{m}}{\\mathrm{ms}^{-1}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{\\mathrm{N}} {\\left(\\mathrm{m}^{2} \\mathrm{~s}^{-1}\\right)}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Nms<sup>2</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Hydraulic press is based on:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Archimedes’ principle</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Bernoulli’s equation</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">Pascal’s law</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Hydraulic press is based on Pascal&rsquo;s law.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Reynold’s law</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If a liquid does not wet glass, its angle of contact is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">obtuse</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The angle of contact is obtuse for a liquid that does not wet glass.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">acute</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">right angle</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>As the temperature of water increases, its viscosity</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">remain unchanged</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">decreases</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>decreases</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">increases</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">increases or decreases depending on the external pressure</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>In a hydraulic lift, the force applied on the smaller cylinder of area A<sub>1</sub> is F<sub>1</sub>. If the area of the larger cylinder is A<sub>2&nbsp;</sub>the maximum weight that can be lifted is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{A_2}{A_1} F_1{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>According to Pascal&#39;s Law,<br />
Pressure applied to any point inside the liquid is transmitted equally in all direction so,<br />
Pressure applied to the smaller cylinder is equal to the pressure on the other cylinder, which is given by<br />
<span class="math-tex">{tex}\\frac{F_1}{A_1}=\\frac{F_2}{A_2}{/tex}</span>&nbsp;<br />
So,<br />
Maximum force on the other side is,<br />
F<sub>2</sub> =&nbsp;<span class="math-tex">{tex}\\frac{A_2}{A_1} \\times F_1{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{A_1}{A_2} F_1{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}{F_1}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">F<sub>1</sub>A<sub>2</sub></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Bernoulli&#39;s equation is an example of conservation of</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">energy</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Bernoulli&#39;s equation is based on the conservation of energy.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">momentum</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">angular momentum</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">mass</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>An open tank filled with water (depsity <span class="math-tex">{tex}\\rho{/tex}</span>) has a narrow hole at a depth of h below the water surface. The velocity of water flowing out is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">h<span class="math-tex">{tex}\\rho{/tex}</span>g</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">2gh</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{2 g h}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Velocity of efflux, v =&nbsp;<span class="math-tex">{tex}\\sqrt{2 g h}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">gh</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Pressure applied to an enclosed fluid is transmitted undiminished to every point of the fluid and the walls of containing vessel. This law was first formulated by:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Reynolds</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Bernoulli</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">Pascal</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The given law was first formulated by Pascal.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Torricelli</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which of the following diagrams (Fig.) does not represent a streamline flow?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614246080-6gubyy.jpg" style="height:132px; width:175px"/></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The following diagram does not represent a streamline flow.<br />
<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614246720-k7mr94.jpg" style="height:132px; width:175px" /><br />
A streamline can be straight or curved and tangent at which gives the direction of the flow.<br />
As two streamlines cannot cross each other, the given diagram does not represent a streamline.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614246084-6hgkaa.jpg" style="height:124px; width:173px"/></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614246088-j99xpy.jpg" style="height:151px; width:133px"/></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614246092-4d7w4d.jpg" style="height:149px; width:110px"/></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>According to Pascal&rsquo;s Law:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">pressure in a fluid at rest is the same at all points if they are at the same height</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>According to Pascal&#39;s Law,<br />
P-P<sub>0 </sub>= hdg<br />
from above<br />
Change in pressure is directly proportional to a depth from the free surface.<br />
At the same horizontal line, all points are at the same depth and have the same value of acceleration due to gravity and density of water as well.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">pressure in a fluid increases with temperature</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">pressure in a fluid decreases with temperature</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">pressure in a fluid at rest is the same at all points if they are at different heights</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If a pipe carrying incompressible liquid has an area A<sub>1</sub> and velocity V<sub>1</sub> at one point A<sub>2</sub> nd V<sub>2</sub> at another point, the equation of continuity gives the relation:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">A<sub>1</sub>V<sub>1 </sub>= A<sub>2</sub>V<sub>2</sub></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/DtW2b4I.gif" style="width: 200px; height: 75px;" /><br />
we apply the principle of mass conservation. Since there is no flow through the sidewalls of the duct, what mass comes in overA<sub>1</sub> goes out of A<sub>2</sub>, &nbsp;Over a short time interval&nbsp;<span class="math-tex">{tex}\\Delta t{/tex}</span>&nbsp;<br />
Volume flow in over A<sub>1</sub> = A<sub>1</sub>V<sub>1</sub><span class="math-tex"><span class="math-tex">{tex}\\Delta{/tex}</span></span>t<br />
Volume flow out over A<sub>2</sub> = A<sub>2</sub>V<sub>2</sub><span class="math-tex"><span class="math-tex">{tex}\\Delta{/tex}</span></span>t<br />
Therefore<br />
mass in over A =&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>A<sub>1</sub>V<sub>1</sub><span class="math-tex"><span class="math-tex">{tex}\\Delta{/tex}</span></span>t<br />
mass out over A =&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>A<sub>2</sub>V<sub>2</sub><span class="math-tex"><span class="math-tex">{tex}\\Delta{/tex}</span></span>t<br />
So:<span class="math-tex">{tex}\\rho{/tex}</span> A<sub>1</sub>V<sub>1</sub> =&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>A<sub>2</sub>V<sub>2</sub><span class="math-tex"><span class="math-tex">{tex}\\Delta{/tex}</span></span>t<br />
As volume is the same so this equation can be written as|<br />
A<sub>1</sub>V<sub>1&nbsp;</sub>= A<sub>2</sub>V<sub>2</sub><br />
This equation is called the continuity equation for steady one-dimensional flow.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">A<sub>1</sub> = A<sub>2</sub>V<sub>2</sub></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">A<sub>1</sub>V<sub>1</sub> = A<sub>1</sub>V<sub>2</sub></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">A<sub>1</sub>V<sub>1</sub> = 2A<sub>2</sub>V<sub>2</sub></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The ratio of radius of two bubbles is 2 : 1. What is the ratio of excess pressure inside them?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">1 : 2</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>p&nbsp;<span class="math-tex">{tex}\\propto \\frac{1}{r}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\frac{p_{1}}{p_{2}}=\\frac{r_{2}}{r_{1}}=\\frac{1}{2}{/tex}</span> = 1 : 2</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">1 : 4</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">2 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">4 : 1</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A steel ball is dropped in oil, then</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">the ball attains constant velocity after some time</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The ball attains constant velocity after falling through some distance in oil when the weight of the ball gets balanced by upthrust and the upward viscous force.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">the ball stops</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">the speed of ball will keep on increasing</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">the speed of ball will keep on decreasing</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>An aeroplane gets its upward lift due to a phenomenon described by the</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Archemedes' principle</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">Bernoulli's principle</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>An aeroplane gets a dynamic upward lift in accordance with Bernoulli&#39;s principle.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Buoyancy principle</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Pascal law</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Dynamic lift is related to</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">Bernoulli's theorem</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Dynamic lift is in accordance with Bernoulli&#39;s equation.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Archemedes' principle</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Equation of continuity</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Pascal's law</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>The terminal velocity of a copper ball of radius 2.0 mm falling through a tank of oil at 20&deg;C is 6.5 cms<sup>-1</sup>. Compute the viscosity of the oil at 20&deg;C. The density of oil is 1.5 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3&nbsp;</sup>kg m<sup>-3</sup>, the density of copper is 8.9 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3&nbsp;</sup>kg m<sup>-3</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, v<sub>1</sub>&nbsp;= 6.5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-2</sup>&nbsp;<span class="math-tex">{tex}\\frac{m}{s}{/tex}</span><br />
r = 2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3 </sup>mg = 9.8&nbsp;<span class="math-tex">{tex}\\frac{m}{s^{2}}{/tex}</span><br />
<span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;= 8.9&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\frac{kg}{m^{3}}{/tex}</span>,&nbsp;<span class="math-tex">{tex}\\sigma{/tex}</span>&nbsp;= 1.5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup><br />
<span class="math-tex">{tex}\\rho{/tex}</span>-<span class="math-tex">{tex}\\sigma{/tex}</span>&nbsp;= 8.9 <span class="math-tex">{tex}\\times{/tex}</span>10<sup>3</sup> -1.5<span class="math-tex">{tex}\\times{/tex}</span>10<sup>3</sup><br />
= 7.4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\frac{kg}{m^{3}}{/tex}</span><br />
As, we know terminal velocity<br />
i.e. v<sub>1&nbsp;</sub>=&nbsp;<span class="math-tex">{tex}\\frac{2}{9} \\frac{r^{2}(\\rho-\\sigma)}{\\eta} g{/tex}</span><br />
<span class="math-tex">{tex}\\eta=\\frac{2}{9} \\times \\frac{\\left(2 \\times 10^{-3}\\right)^{2} \\times 9.8}{\\left(6.5 \\times 10^{-2}\\right)}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>7.4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup><br />
<span class="math-tex">{tex}\\eta{/tex}</span>&nbsp;= 9.9&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-1</sup>&nbsp;<span class="math-tex">{tex}\\frac{kg}{ms}{/tex}</span><br />
&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>State and derive Torricelli&#39;s law of efflux.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The Torricelli&#39;s law of efflux states that the speed of efflux of a fluid through a sharp-edged hole at the bottom of the tank filled to a depth is the same as the speed that a body would acquire in falling freely from a height , i.e. , where is the acceleration due to gravity.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1705318110-cettxx.jpg" style="height:170px; width:250px" /><br />
<span class="math-tex">{tex}\\frac{P_{\\mathrm{L}}}{\\rho}+g h_{\\mathrm{L}}+\\frac{1}{2} v_{\\mathrm{L}}^2=\\frac{P_{\\mathrm{M}}}{\\rho}+g h_{\\mathrm{M}}+\\frac{1}{2} v_{\\mathrm{M}}^2{/tex}</span><br />
or <span class="math-tex">{tex}\\frac{P_{\\mathrm{L}}-P_{\\mathrm{M}}}{\\rho}+\\frac{1}{2}\\left(v_{\\mathrm{L}}{ }^2-v_{\\mathrm{M}}{ }^2\\right)=g\\left(h_{\\mathrm{M}}-h_{\\mathrm{L}}\\right){/tex}</span><br />
or <span class="math-tex">{tex}0+\\frac{1}{2} v^2=g h{/tex}</span><br />
or <span class="math-tex">{tex}v=\\sqrt{2 g h}{/tex}</span><br />
When a body falls freely by height h its velocity V is also.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is terminal velocity and derive an expression for it?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Terminal velocity is the maximum constant velocity acquired by the body which is falling freely in a viscous medium, due to the balanced net downward force acting on the body with the upward resistive viscous force offered by the medium on the body.</p>

<p>When a small spherical body falls freely through a viscous medium then 3 forces act on it:-</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Weight of body acting vertically downwards.</li>
	<li>Up thrust due to buoyancy = weight of fluid displaced by the body, acting upwards.</li>
	<li>Viscous drag (F<sub>V</sub>) or resistive viscous force acting in the direction opposite to the motion of body.</li>
</ol>

<p>Let&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span> = Density of the material of the spherical body</p>

<p>r = Radius of the spherical body</p>

<p><span class="math-tex">{tex}\\sigma{/tex}</span>&nbsp;= Density of the viscous medium.</p>

<p><span class="math-tex">{tex}\\therefore{/tex}</span> True weight of the body = W = volume of the body&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> density of the body&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> g</p>

<p><span class="math-tex">{tex}\\therefore W = \\frac { 4 } { 3 } \\pi r ^ { 3 } {\\rho } g{/tex}</span></p>

<p>Up ward thrust by the fluid, F<sub>T</sub> = weight of medium displaced by the spherical body = volume of the body &times; density of the viscous medium &times; g</p>

<p><span class="math-tex">{tex}= \\frac { 4 } { 3 } \\pi r ^ { 3 } {\\sigma}g{/tex}</span></p>

<p>Say,&nbsp;<span class="math-tex">{tex}v_T{/tex}</span> = Terminal velocity of body</p>

<p>According to Stoke&rsquo;s law, viscous drag or viscous force,</p>

<p><span class="math-tex">{tex}F _ {V} = 6\\pi \\eta v_T{/tex}</span>(<span class="math-tex">{tex}\\eta {/tex}</span>&nbsp;being coefficient of viscosity of the medium)</p>

<p>When the body attains terminal velocity <span class="math-tex">{tex}v_T{/tex}</span>, then</p>

<p>F<sub>T</sub> + F<sub>V</sub> = W</p>

<p><span class="math-tex">{tex}\\Rightarrow \\frac { 4 } { 3 } \\pi r ^ { 3 } {\\sigma}g + 6 \\pi \\eta r {v_T} = \\frac { 4 } { 3 } \\pi r ^ { 3 } {\\rho} g{/tex}</span></p>

<p><span class="math-tex">{tex}\\therefore v_T = \\frac { 2 r ^ { 2 } \\left( {\\rho} -{\\sigma} \\right) g } { 9 \\eta }{/tex}</span></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li><span class="math-tex">{tex}v_T{/tex}</span>&nbsp;directly depends on radius of body and difference of the pressure of material and medium.</li>
	<li><span class="math-tex">{tex}v_T{/tex}</span>&nbsp;inversely depends of co-efficient of viscosity of the medium.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is Bernoulli&rsquo;s theorem? Show that sum of pressure, potential and kinetic energy in the streamline flow is constant?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Acc. to&nbsp;Bernoulli &rsquo;s theorem, for the streamline flow of an ideal liquid, the total energy that is sum of pressure energy, potential energy and kinetic energy per unit mass remains constant at every cross-section throughout the flow. Consider a tube A B of varying cross-section.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch10/3m/image053.png" style="height: 98px; width: 300px;" /><br />
p<sub>1</sub> = Pressure applied on liquid at A<br />
p<sub>2</sub> = Pressure applied on liquid at B<br />
a<sub>1</sub>, a<sub>2 </sub>= Area of cross - section at A &amp; B<br />
h<sub>1</sub>&nbsp; h<sub>2</sub> = height of section A and B from the ground.<br />
v<sub>1</sub>, v<sub>2</sub> = Normal velocity of liquid at A and B<br />
s = Density of ideal liquid<br />
Let P<sub>1 </sub>&gt; P<sub>2 </sub>&nbsp;&nbsp;<br />
m = Mass of liquid crossing per second through any section of tube.<br />
a<sub>1 </sub>v<sub>1</sub> s = a<sub>2</sub> v<sub>2</sub> s = m<br />
or a<sub>1</sub> v<sub>1</sub> = a<sub>2</sub> v<sub>2</sub> = <span class="math-tex">{tex}\\frac { m } { s } {/tex}</span> = v<br />
As a<sub>1</sub> &gt; a<sub>2</sub> <span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;v<sub>2</sub> &gt;v<sub>1 </sub><br />
Force of on liquid at A = p<sub>1</sub> a<sub>1</sub><br />
Force on liquid at B =<sub> </sub>p<sub>2</sub> a<sub>2</sub>&nbsp;<br />
Work done/second on liquid at A = p<sub>1</sub> a<sub>1</sub>\` <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;v<sub>1</sub> = p<sub>1</sub>V<br />
Work done/second on liquid at B = p<sub>2</sub> V<br />
Net work done | second by pressure energy in moving the liquid from A to B = p<sub>1</sub> v - p<sub>2</sub> v <span class="math-tex">{tex}\\to{/tex}</span> (1)<br />
If &lsquo;m&rsquo; mass of liquid flows in one second from A to B then Increases in potential energy&nbsp; per second from A to B = mgh<sub>2</sub> - mgh<sub>1</sub> <span class="math-tex">{tex}\\to{/tex}</span>(2)<br />
Increase in kinetic energy/second of liquid from A to B = <span class="math-tex">{tex}\\frac { 1 } { 2 } m v _ { 2 } ^ { 2 } - \\frac { 1 } { 2 } m v _ { 1 } ^ { 2 } \\rightarrow ( 3 ){/tex}</span>&nbsp;<br />
From, work energy principle:-<br />
Work done by pressure energy = Increase in P. E. /sec + Increase in K. E/sec<br />
From equation 1, 2, &amp; 3<br />
P<sub>1</sub> v - p<sub>2</sub> v = (mgh<sub>2</sub> - mgh<sub>1</sub>) + <span class="math-tex">{tex}\\frac { 1 } { 2 } m v _ { 2 } ^ { 2 } - \\frac { 1 } { 2 } m v _ { 1 } ^ { 2 }{/tex}</span> &nbsp;<br />
P<sub>1 </sub>v + mgh<sub>1</sub> + <span class="math-tex">{tex}\\frac { 1 } { 2 } m v _ { 1 } ^ { 2 } = p _ { 2 } v + \\frac { 1 } { 2 } m v _ { 2 } ^ { 2 } + m g h _ { 2 }{/tex}</span>&nbsp;<br />
Dividing throughout by m <span class="math-tex">{tex}\\to{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\frac { p _ { 1 } v } { m } + g h _ { 1 } + \\frac { 1 } { 2 v } v _ { 1 } ^ { 2 } \\pm \\frac { p _ { 2 } v } { m } + \\frac { 1 } { 2 } v _ { 2 } ^ { 2 } + g h _ { 2 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\frac { p _ { 1 } } { s } + g h _ { 1 } + \\frac { 1 } { 2 } v _ { 1 } ^ { 2 } = \\frac { p _ { 2 } } { s } + \\frac { 1 } { 2 } v _ { 2 } ^ { 2 } + g h _ { 2 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}s 1 = \\frac { m } { v }{/tex}</span>&nbsp;Density<br />
Hence, <span class="math-tex">{tex}\\to{/tex}</span> 4)<br />
<span class="math-tex">{tex}\\frac { p } { \\rho } + g h + \\frac { 1 } { 2 } v ^ { 2 } ={/tex}</span> Constant<br />
<span class="math-tex">{tex}\\frac { p } { \\rho} ={/tex}</span>&nbsp;Pressure energy per unit mass<br />
gh = potential energy per unit mass<br />
<span class="math-tex">{tex}\\frac { 1 } { 2 } v ^ { 2 }{/tex}</span> = kinetic energy per unit mass&nbsp;<br />
<span class="math-tex">{tex}\\frac { p } { \\rho } + g h + \\frac { 1 } { 2 } v ^ { 2 } ={/tex}</span>&nbsp;constant</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State Pascal&#39;s law. Explain the working of a hydraulic lift.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to Pascal&#39;s principle,<br />
In a fluid at rest in a closed container, a pressure change in one part is transmitted without loss to every portion of the fluid and to the walls of the container.<br />
Hydraulic lift is designed on the principle of Pascal&#39;s law of transmission of pressure.<br />
A force <span class="math-tex">{tex}F_1{/tex}</span> applied on the smaller piston of area A<sub>1</sub> means an additional pressure of P =&nbsp;<span class="math-tex">{tex}\\frac{F_1}{A_1}{/tex}</span>&nbsp;on the fluid, which is transmitted undiminished on the bigger piston.&nbsp;<br />
F<sub>2</sub>&nbsp;= PA<sub>2</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{F_1 A_2}{A_1}{/tex}</span><br />
Therefore, we can lift a heavy load by applying a less force.<br />
Mechanical advantage of hydraulic lift<br />
=&nbsp;<span class="math-tex">{tex}\\frac{Load \\ to \\ be \\ raised \\ (W = F_2)}{Effort \\ (force) \\ to \\ be \\ applied \\ (F_1)}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{Cross-section \\ area \\ of \\ bigger \\ piston \\ (A_2)}{Cross-section \\ area \\ of \\ smaller \\ piston \\ (A_1)}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>At a depth of 1000 m in an ocean</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>what is the absolute pressure?</li>
	<li>What is the gauge pressure?</li>
	<li>Find the force acting on the window of area 20 cm <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;20 cm of a submarine at this depth, the interior of which is maintained at sea level atmospheric pressure.<br />
	(The density of sea water is 1.03 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup> kg m<sup>-3</sup>,&nbsp;g = 10 ms<sup>-2</sup>.)</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here h = 1000m and&nbsp;<span class="math-tex">{tex}\\rho=1.03 \\times 10^{3} \\mathrm{kg} \\mathrm{m}^{3}{/tex}</span></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Eq.&nbsp;<span class="math-tex">{tex}P_{2}-P_{1}=\\rho g h{/tex}</span>, absolute pressure<br />
	<span class="math-tex">{tex}P=P_{\\mathrm{a}}+\\rho g h{/tex}</span><br />
	<span class="math-tex">{tex}=1.01 \\times 10^{5} \\mathrm{Pa}{/tex}</span><br />
	<span class="math-tex">{tex}+1.03 \\times 10^{3} \\mathrm{kg} \\mathrm{m}^{-3}{/tex}</span><span class="math-tex">{tex}\\times 10 \\mathrm{m} \\mathrm{s}^{-2} \\times 1000 \\mathrm{m}{/tex}</span><br />
	<span class="math-tex">{tex}=104.01 \\times 10^{5} \\mathrm{Pa}{/tex}</span><br />
	<span class="math-tex">{tex}\\approx 104 \\mathrm{atm}{/tex}</span></li>
	<li>Gauge pressure is&nbsp;<span class="math-tex">{tex}P-P_{\\mathrm{a}}=\\rho g h=P_{\\mathrm{g}}{/tex}</span><br />
	<span class="math-tex">{tex}P_{g}=1.03 \\times 10^{3} \\mathrm{kg} \\mathrm{m}^{-3} \\times{/tex}</span><span class="math-tex">{tex}10 \\mathrm{ms}^{2} \\times 1000 \\mathrm{m}{/tex}</span><br />
	<span class="math-tex">{tex}=103 \\times 10^{5} \\mathrm{Pa}{/tex}</span><br />
	<span class="math-tex">{tex}\\approx 103 \\text { atm }{/tex}</span></li>
	<li>The pressure outside the submarine is P = P<sub>a</sub>+ <span class="math-tex">{tex}\\rho g h{/tex}</span>&nbsp;and the pressure inside it is P<sub>a</sub>.&nbsp;Hence, the net pressure acting on the window is gauge pressure, P<sub>g&nbsp;</sub>= <span class="math-tex">{tex}\\rho g h{/tex}</span>.&nbsp;Since the area of the window is A = 0.04 m<sup>2</sup>,&nbsp;the force acting on it is<br />
	<span class="math-tex">{tex}F=P_{8} A=103 \\times 10^{5} \\mathrm{Pa} \\times 0.04 \\mathrm{m}^{2}{/tex}</span><span class="math-tex">{tex}=4.12 \\times 10^{5} \\mathrm{N}{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State the principle on which Hydraulic lift work and explain its working?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Hydraulic lift works on the principle of the Pascal&rsquo;s law. According to this law,&nbsp;in a fluid at rest in a closed container, a change in pressure in one part is transmitted without loss to every portion of the fluid and to the walls of the container.<br />
Working of Hydraulic effect: &nbsp;<br />
<img data-imgur-src="Pg7mrCf.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/Pg7mrCf.png" style="height: 166px; width: 300px;" /><br />
a = Area of cross-section of piston at C<br />
A = Area of cross-section of piston at D.<br />
Let a downward force f be applied on the piston C. Then the pressure exerted on the liquid, <span class="math-tex">{tex}P = \\frac { f } { a }{/tex}</span>&nbsp;<br />
According to Pascal&rsquo;s law, this pressure is transmitted equally to piston of cylinder D.&nbsp;<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> Upward fore acting on the piston of cylinder D will be :<br />
F = Pressure exerted by the smaller piston &times; area of cross-section of the larger piston = P <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;A<br />
<span class="math-tex">{tex}= \\frac { f } { a } A{/tex}</span>&nbsp;<br />
= <span class="math-tex">{tex}f × \\frac {A}{a}{/tex}</span>&nbsp;<br />
Now, as A ≫ a, hence F ≫ f<br />
i.e. small fore applied on the smaller piston will be appearing as a very large force on the large piston. As a result of which heavy load placed on larger piston is easily lifted upwards.<br />
These lifts are used in automotive, shipping, construction, waste removal, mining, and retail industries as they&#39;re an effective means of raising&nbsp;and lowering people, goods, and equipment.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is equation of continuity? Water plows through a horizontal pipe of radius, 1cm at a speed of 2m/s. What should be the diameter of nozzle if water is to come out at a speed of 10m/s?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The Navier&ndash;Stokes equations form a vector continuity equation describing the conservation of linear momentum. If the fluid is an incompressible flow (&rho; is constant), the&nbsp;mass&nbsp;continuity equation simplifies to a volume continuity equation: which means that the divergence of velocity field is zero everywhere. Consider a non-viscous liquid in streamline flow through a tube A B of varying cross-section<br />
​​​​​​<img src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch10/3m/image045.png" style="height: 59px; width: 180px;" /><br />
Let a<sub>1</sub>, a<sub>2</sub> = area of cross-section at A and B<br />
V<sub>1</sub>, V<sub>2</sub> = Velocity of flow of liquid at A and B<br />
S<sub>1</sub>, S<sub>2</sub> = Density of liquid at A and B<br />
Volume of liquid entering per second at A = a<sub>1</sub> v<sub>1</sub><br />
Mass of liquid entering per second at A = a<sub>1</sub> v<sub>1</sub> s<sub>1</sub><br />
Moss of liquid entering per second at B = a<sub>1</sub> v<sub>1</sub> s<sub>2</sub>.<br />
If there is no loss of liquid in tube and flow is steady, then<br />
Mass of liquid entering per second at A = Mass of liquid leaving per second at B<br />
a<sub>1</sub> v<sub>1</sub> s<sub>1</sub> = a<sub>2</sub> v<sub>2</sub> s<sub>2&nbsp; </sub><br />
If the liquid is incompressible,<br />
s<sub>1</sub> = s<sub>2 </sub>= s<br />
a<sub>1</sub> v<sub>1</sub> s = a<sub>2</sub>v<sub>2</sub>s<br />
a<sub>1 </sub>v<sub>1</sub> = a<sub>2</sub> v<sub>2</sub><br />
or a v = constant<br />
i. e V <span class="math-tex">{tex}\\propto \\frac { 1 } { a }{/tex}</span>&nbsp;<br />
It means the larger the area of cross-section, the smaller will be the flow of liquid.<br />
Here 1 D<sub>1</sub> = 2r<sub>1 </sub>= 2<span class="math-tex">{tex}\\times{/tex}</span>1 = 2cm<br />
D<sub>2 </sub>= ?<br />
V<sub>1 </sub>= 2m|s<br />
V<sub>2</sub> = 10m|s<br />
D<sub>1</sub> = Diameter<br />
R<sub>1</sub> = Radius<br />
V<sub>1</sub> = velocity<br />
<span class="math-tex">{tex}a = \\pi r ^ { 2 }{/tex}</span>, D=2r<br />
<span class="math-tex">{tex}= \\pi \\frac { d ^ { 2 } } { 4 } , \\frac { D } { 2 } = r{/tex}</span>&nbsp;<br />
From equation of continuity<br />
a<sub>1</sub> v<sub>1</sub> = a<sub>2</sub> v<sub>2</sub><br />
<span class="math-tex">{tex}\\Rightarrow \\left( \\pi \\frac { D _ { 1 } ^ { 2 } } { 4 } \\right) ^ { 2 } \\quad x \\nu _ { 1 } = \\left( \\pi \\frac { D _ { 2 } ^ { 2 } } { 4 } \\right) \\nu _ { 2 }{/tex}</span>&nbsp;<br />
D<sub>2</sub> = D<sub>1</sub> <span class="math-tex">{tex}\\left( \\frac { v _ { 1 } } { v _ { 2 } } \\right) ^ { \\frac { 1 } { 2 } }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}= 2 \\left( \\frac { 2 } { 10 } \\right) ^ { \\frac { 1 } { 2 } }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}= 2 \\times { \\frac { 1 } { \\sqrt { 5 } } }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}= 2 \\times { \\frac { 1 } { 2.236 } }{/tex}</span>&nbsp;<br />
D<sub>2</sub> = 0.894 cm<br />
Hence, diameter of the outer opening is 0.894 cm as flow rate through this area is high as compared to initial one.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Explain why?</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>The blood pressure in humans is greater at the feet than the brain.</li>
	<li>Atmospheric pressure at a height of about 6 km decreases to nearly half its value at the sea level through the height of the atmosphere is more than 100 km.</li>
	<li>Hydrostatic pressure is a scalar quantity even though the pressure is force divided by area.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>&nbsp;The pressure of the liquid column is given by p = h<span class="math-tex">{tex}\\rho{/tex}</span>g, where h is depth, <span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;is density and g is the acceleration due to gravity.<br />
	The pressure of the liquid column increases with depth. The height of the blood column in the human body is more at feet than at the brain,&nbsp;that is why the blood exerts more pressure at the feet than at the brain.</li>
	<li>The atmospheric pressure at a height of about 6 km decreases to nearly half of its value at the sea level because the density of air is maximum near the surface of the earth and decreases rapidly with height. At a height of 6 km, the density of air decreases to nearly half of its value at the sea level. Beyond 6 km height, the density of air decreases very slowly with height.&nbsp;</li>
	<li>Hydrostatic pressure is a scalar quantity because when force is applied on a liquid, the pressure is transmitted equally in all directions inside the liquid. Therefore, it&nbsp;has no fixed direction.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Figures&nbsp;(a) and (b) refer to the steady flow of a (non-viscous) liquid. Which of the two figures is incorrect? Why?<br />
<img alt="" data-imgur-src="nOv3kzQ.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/nOv3kzQ.png" style="width: 200px; height: 91px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img alt="" data-imgur-src="MykbehL.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/MykbehL.png" style="width: 100px; height: 103px;" /><br />
Take the case given in figure (b).<br />
Where, A<sub>1</sub>&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Area of pipe 1<br />
A<sub>2</sub>&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Area of pipe 2<br />
V<sub>1</sub>&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Speed of the fluid in pipe&nbsp;1<br />
V<sub>2</sub>&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Speed of the fluid in pipe&nbsp;2<br />
From the equation of continuity, we have:<br />
A<sub>1</sub>V<sub>1</sub> = A<sub>2</sub>V<sub>2</sub><br />
As the area of cross-section in the middle of the venturi meter is small,<br />
the speed of the flow of liquid through this part should be more.<br />
According to Bernoulli&#39;s&nbsp;principle for a flow in uniform horizontal tube,&nbsp;<span class="math-tex">{tex}P + \\frac { 1 } { 2 } \\rho v ^ { 2 }{/tex}</span>&nbsp;= constant<br />
Thus if speed is more, the pressure should be less.<br />
pressure is directly proportional to height of liquid column. Hence, the level of water in pipe 2 is less.<br />
Therefore, figure (a) is not possible.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Briefly explain the construction and working of a hydraulic brake.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Hydraulic Brakes: Hydraulic brakes used in vehicles are based on Pascal's principle of transmission of pressure in the liquid.</p>
<p>Construction:<br/>
It consists of following main parts: (i) Master cylinder (ii) Wheel cylinder (iii) Brake fluid (or brake oil) pipelines.<br/>
Master cylinder is connected to four cylinders through a pipeline. The wheel cylinder consists of brakes and shoe arrangement.  <br/>
<br/>
Principle: It works on the principle of Pascal's law, which states that the confined liquid transmits pressure intensity equally in all directions.<br/>
<br/>
Working: When the driver presses pedal, the effort is transmitted through rod to piston in master cylinder. The piston moves in the cylinder and compress return spring forcing out the fluid from the cylinder into brake line through a by-pass. Piston of a brake cylinders are acted upon by the fluid and press against shoes, bringing their linings tightly against the working surfaces of the drums as soon as the pedal is released, the return spring pushes piston back. At the same time, the compression springs of the brake shoe move pistons to their initial position and the fluid begins to the flow in the reverse direction.</p>
<p><br/>
<img alt="" data-imgur-src="urQStqW.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/urQStqW.png" style="width: 200px; height: 135px;"/></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two soap bubbles have radii in the ratio 2 : 3. Compare the excess of pressure inside these bubbles. Also compare the works done in blowing these bubbles.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If R<sub>1</sub> and R<sub>2</sub>&nbsp;are the radii of the two bubbles, then&nbsp;<span class="math-tex">{tex}\\frac{R_{1}}{R_{2}}=\\frac{2}{3}{/tex}</span><br />
Let&nbsp;<span class="math-tex">{tex}\\sigma{/tex}</span>&nbsp;be the surface tension of the soap solution.<br />
Excess pressure inside the bubble of radius R<sub>1</sub>,<br />
p<sub>1</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{4 \\sigma}{R_{1}}{/tex}</span><br />
Excess pressure inside the bubble of radius R<sub>2</sub>,<br />
p<sub>2</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{4 \\sigma}{R_{2}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\frac{p_{1}}{p_{2}}=\\frac{4 \\sigma}{R_{1}} \\times \\frac{R_{2}}{4 \\sigma}=\\frac{R_{2}}{R_{1}}=\\frac{3}{2}{/tex}</span>&nbsp;= 3 : 2<br />
Work done in blowing up the two soap bubbles is<br />
W<sub>1</sub>&nbsp;= 2&nbsp;<span class="math-tex">{tex}\\times 4 \\pi R_{1}^{2} \\times \\sigma{/tex}</span><br />
and W<sub>2</sub>&nbsp;= 2&nbsp;<span class="math-tex">{tex}\\times 4 \\pi R_{2}^{2} \\times \\sigma{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\frac{W_{1}}{W_{2}}=\\frac{R_{1}^{2}}{R_{2}^{2}}=\\left(\\frac{2}{3}\\right)^{2}{/tex}</span> = 4 : 9</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>In a given Figure&nbsp;(a) shows a thin liquid film supporting a small weight <span class="math-tex">{tex}= 4.5 \\times 10 ^ { - 2 }{/tex}</span> N. What is the weight supported by a film of the same liquid at the same temperature in Fig. (b) and (c)? Explain your answer physically.<br />
<img alt="" data-imgur-src="ZGGpuXd.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/ZGGpuXd.png" style="width: 300px; height: 136px;" /><br />
&nbsp;</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>In case &quot;a&quot;-<br />
The length of the liquid film supported by the weight is given by, l = 40cm = 0.4cm<br />
The weight supported by the film is given by,&nbsp;<span class="math-tex">{tex}W = 4.5 \\times 10 ^ { - 2 } N{/tex}</span><br />
A liquid film has two free surfaces thus<br />
Surface tension is given by&nbsp;&nbsp;<span class="math-tex">{tex}S = \\frac { W } { 2 l } = \\frac { 4.5 \\times 10 ^ { - 2 } } { 2 \\times 0.4 } = 5.625 \\times 10 ^ { - 2 } \\mathrm { Nm } ^ { - 1 }{/tex}</span><br />
In all the three figures, the liquid is the same. Temperature is also the same for each case.<br />
Hence, the surface tension in figure (b) and figure (c) is the same as in figure (a) i.e.&nbsp;<span class="math-tex">{tex}S = 5.625 \\times 10 ^ { - 2 } N m ^ { - 1 }{/tex}</span><br />
Since the length of the film in all the cases is 40 cm, hence the total weight supported in each case is given by&nbsp;<span class="math-tex">{tex}4.5 \\times 10 ^ { - 2 } N{/tex}</span>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What amount of energy will be liberated if 1000 droplets of water, each of diameter 10<sup>-8</sup> m, coalesce to form a bigger drop? Surface tension of water is 0.072 Nm<sup>-1</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Radius of a droplet,<br />
r =&nbsp;<span class="math-tex">{tex}\\frac{10^{-8}}{2}{/tex}</span>&nbsp;= 0.5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-8</sup>m<br />
Volume of bogger drop = Volume of 1000 droplets<br />
<span class="math-tex">{tex}\\frac{4}{3} \\pi{/tex}</span>R<sup>3</sup>&nbsp;= 1000&nbsp;<span class="math-tex">{tex}\\times \\frac{4}{3} \\pi{/tex}</span>r<sup>3</sup><br />
or R = 10r = 10&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;0.5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-8</sup>&nbsp;= 5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-8</sup>m<br />
Decrease in surface area<br />
= 1000&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;4<span class="math-tex">{tex}\\pi{/tex}</span>r<sup>2</sup>&nbsp;- 4<span class="math-tex">{tex}\\pi{/tex}</span>R<sup>2</sup>&nbsp;= 4<span class="math-tex">{tex}\\pi{/tex}</span>&nbsp;[1000 r<sup>2</sup>&nbsp;- R<sup>2</sup>]<br />
= 4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;3.14 [1000&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(0.5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-8</sup>)<sup>2</sup>&nbsp;- (5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-8</sup>)<sup>2</sup>]<br />
= 4&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;3.14&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;225&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-16</sup>m<sup>2</sup>&nbsp;= 2826&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-16&nbsp;</sup>m<sup>2</sup><br />
Energy liberated<br />
= Surface tension&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;Decrease in surface area<br />
= 0.072&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2826&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-16</sup>&nbsp;= 2.035&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-14</sup>J.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A vertical off-shore structure is built to withstand a maximum stress of 10<sup>9</sup> Pa. Is the structure suitable for putting up on top of an oil well in the ocean? Take the depth of the ocean to be roughly 3 km, and ignore ocean currents.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The maximum allowable stress for the structure is, P = 10<sup>9</sup>&nbsp;Pa<br />
Depth of the ocean is given by, <em>d</em> = 3 km= 3&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;m<br />
Density of water is given by, <span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;= 10<sup>3&nbsp;</sup><span class="math-tex">{tex}\\frac{\\mathrm{kg}}{\\mathrm{m}^{3}}{/tex}</span><br />
Acceleration due to gravity is, g = 9.8&nbsp;<span class="math-tex">{tex}\\frac{\\mathrm{m}}{\\mathrm{s}^{2}}{/tex}</span><br />
The pressure exerted at depth , d =&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>dg<br />
= 3&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8<br />
= 2.94&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>7</sup>&nbsp;Pa<br />
The maximum allowable stress for the structure (10<sup>9</sup>&nbsp;Pa) is greater than the pressure of the sea water (2.94&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>7</sup>&nbsp;Pa). The pressure exerted by the ocean is less than the pressure that the structure can withstand. Hence, the structure is suitable for putting up on top of an oil well in the ocean.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Briefly discuss the use of Bernoulli&#39;s principle in working of an atomiser (i.e., the spray gun used for perfumes etc.).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>An atomiser or sprayer is used to spray very fine drops of liquids and their vapours in perfumes and deodorant bottles.<br />
<img alt="" data-imgur-src="V2YPoeU.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/V2YPoeU.png" style="width: 200px; height: 126px;" /></p>

<p>It works&nbsp;on Bernoulli&#39;s principle.</p>

<p>In an atomiser, a horizontal tube is joined to a reservoir bulb&nbsp;through a stem. One end of horizontal tube is in the form of a fine nozzle and a piston or a rubber bulb is attached to its other end.<br />
When the piston is pushed inwards, the air in the tube rushes out through the nozzle with large flow speed and reduces the pressure in the tube. This creates a pressure difference. Due to which the liquid rises in the stem. The liquid is mixed up with air on the top of the stem and the mixture is blown away through the nozzle in the form of a fine spray.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>On the basis of Bernoulli&#39;s principle, explain the lift of an aircraft wing.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Aerofoil: Lift of an aircraft wing. Aerofoil is the name given to a solid object shaped to provide an upward vertical force as it moves horizontally through air. This upward force (dynamic lift) makes aeroplanes fly.<br/>
As shown in Fig., the cross-section of the wing of an aeroplane looks like an aerofoil. The wing is so designed that its upper surface is more curved (and hence longer) than the lower surface and the front edge is broader than the rear edge. As the aircraft moves, the air moves faster over the upper surface of the wing than on the bottom. According to Bernoulli's principle, the air pressure above the upper surface decreases below the atmospheric pressure and that on the lower surface increases above the atmospheric pressure. The difference in pressure provides an upward lift, called dynamic lift, to the aircraft.<br/>
<img alt="" data-imgur-src="rkczDLF.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082699-gn9vef.jpg" style="width: 250px; height: 148px;"/></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Briefly explain how does Bernoulli&#39;s principle help in explaining blood flow in human beings. What is the cause of a heart attack?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The blood flow in artery of a human being can be easily explained on the basis of Bernoulli&#39;s principle. The heart applies a pressure to maintain blood flow through the arteries.</p>

<p>In&nbsp;persons suffering with advanced heart condition, the artery gets constricted due to the accumulation of plaque on its inner walls.&nbsp; In order to drive the blood through this constriction a greater activity of the heart is required. The speed of the flow of the blood in this region is raised which lowers the pressure inside, and the artery may collapse due to this external pressure.</p>

<p>The heart exerts further pressure to open this artery and forces the blood through. As the blood rushes through the opening, the internal pressure once again drops leading to a repeat collapse. This may result in heart attack.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The lower end of a capillary tube of diameter 2 mm is dipped 8 cm below the surface of water in a beaker. What is the pressure required in the tube in order to blow a hemispherical bubble at its end in water? The surface tension of water at temperature of the experiments is 7.30 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-2</sup>Nm<sup>-1</sup>,&nbsp;atm = 1.01 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup>Pa, density of water = 1000 kg/m<sup>3</sup>, g = 9.80 ms<sup>-2</sup>. Also, calculate the excess pressure.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, h = 0.08m,<br />
d = 1000&nbsp;<span class="math-tex">{tex}\\frac {\\mathrm{kg}}{\\mathrm{m}^{3}}{/tex}</span><br />
g = 9.80&nbsp;<span class="math-tex">{tex}\\frac {\\mathrm{m}}{\\mathrm{s}^{2}}{/tex}</span>,<br />
As we know, p<sub>0</sub>&nbsp;= p<sub>a</sub>&nbsp;+ hdg<br />
p<sub>0</sub> is outside pressure p<sub>0</sub>&nbsp;= 1.01&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup>&nbsp;Pa + 0.08m&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;1000&nbsp;<span class="math-tex">{tex}\\frac {\\mathrm{kg}}{\\mathrm{m}^{3}}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.80&nbsp;<span class="math-tex">{tex}\\frac {\\mathrm{m}}{\\mathrm{s}^{2}}{/tex}</span><br />
p<sub>0</sub>&nbsp;= 1.01784&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;Pa<br />
Calculate inside pressure required in tube in order to blow a hemispherical bubble<br />
p<sub>1</sub> = p<sub>0&nbsp;</sub>+&nbsp;<span class="math-tex">{tex}\\frac{2 S}{r}{/tex}</span>, where s = 7.30&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-2</sup> pa-m<br />
p<sub>1&nbsp;</sub>= 1.01784<span class="math-tex">{tex}\\times{/tex}</span>10<sup>5&nbsp;</sup>+&nbsp;<span class="math-tex">{tex}\\frac{2 \\times 7.3 \\times 10^{-2}}{10^{-3}}{/tex}</span><br />
= (1.01784 + 0.00146) 10<sup>5</sup>&nbsp;Pa <span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;p<sub>1</sub>&nbsp;=&nbsp;1.02&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup>&nbsp;Pa<br />
where the radius of the bubble is taken to be equal to the radius of the capillary tube. Since the bubble is hemispherical. The excess pressure in the bubble is 146 Pa.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State and prove the equation of continuity for steady flow of an ideal fluid.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><strong><img alt="" data-imgur-src="oZPQieH.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/oZPQieH.png" style="width: 200px;"/></strong><br/>
According to the equation of continuity, if there is no source or sink along the length of a pipe then for steady flow of an ideal fluid the mass of the fluid crossing any section of the pipe per unit time is always constant. Mathematically,<br/>
<span class="math-tex">{tex}A _ { 1 } v _ { 1 } p _ { 1 } = A _ { 2 } v _ { 2 } \\rho _ { 2 }{/tex}</span> = a constant</p>
<p>Consider steady flow of an ideal fluid through a pipe (or tube) PRQ of varying cross-section. Let us consider flow of fluid across any two transverse sections, say at P and Q, of the pipe having areas A<sub>1</sub> and A<sub>2</sub>, where velocity of fluid flow is v<sub>1</sub> and v<sub>2</sub>, respectively.<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> Volume of fluid crossing the area A<sub>1</sub> per unit time at section P = A<sub>1</sub>v<sub>1</sub><br/>
Similarly, volume of fluid crossing the area A<sub>2</sub> per unit time at section Q = A<sub>2</sub>v<sub>2</sub>.<br/>
If <span class="math-tex">{tex}\\rho{/tex}</span><sub>1</sub> and <span class="math-tex">{tex}\\rho{/tex}</span><sub>2</sub> be the densities of the given fluid at two sections, the mass of the fluid entering per unit time at section P is m<sub>1</sub> = A<sub>1</sub>v<sub>1</sub><span class="math-tex">{tex}\\rho{/tex}</span><sub>1</sub> and mass of the fluid leaving per unit time at section Q is m<sub>2</sub> = A<sub>2</sub>v<sub>2</sub> <span class="math-tex">{tex}\\rho{/tex}</span><sub>2</sub><br/>
If there is no source or sink of fluid within the pipe, i.e., the flow is steady one, then from the law of conservation of matter, it follows that<br/>
m<sub>1</sub> = m<sub>2</sub><br/>
<span class="math-tex">{tex}\\therefore A _ { 1 } v _ { 1 } \\rho _ { 1 } = A _ { 2 } v _ { 2 } \\rho _ { 2 }{/tex}</span> .......(1)<br/>
which is the general form of the equation of continuity.<br/>
For flow of an ideal incompressible liquid, the liquid density at both the cross-sections remains constant i.e., <span class="math-tex">{tex}\\rho _ { 1 } = \\rho _ { 2 }{/tex}</span>.<br/>
Thus, equation of continuity may be expressed as <span class="math-tex">{tex}A _ { 1 } v _ { 1 } = A _ { 2 } v _ { 2 }{/tex}</span> .................(2)<br/>
From this equation, it is clear that at narrower portion of a pipe the velocity of flow increases and vice-versa.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that if n equal rain droplets falling through air with equal steady velocity of 10 cms<sup>-1</sup> coalesces, the resultant drop attains a new terminal velocity of 10 <span class="math-tex">{tex}n^{\\frac{2}{3}}{/tex}</span>cms<sup>-1</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Volume of a bigger drop = n <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;Volume of a smaller droplet<br />
or&nbsp;<span class="math-tex">{tex}\\frac{4}{3} \\pi{/tex}</span><span class="math-tex">{tex}R^3 = n{/tex}</span><sup>&nbsp;</sup><span class="math-tex">{tex}\\times{/tex}</span><sup>&nbsp;</sup><span class="math-tex">{tex}\\frac{4}{3} \\pi{/tex}</span><span class="math-tex">{tex}R^3\\ or\\ R^3 = nr^3{/tex}</span><br />
or R =&nbsp;<span class="math-tex">{tex}n^{\\frac{1}{3}}r{/tex}</span><br />
Terminal velocity of a small droplet is given by<br />
<span class="math-tex">{tex}v_1 ={/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{2}{9} \\frac{r^{2}}{\\eta}{/tex}</span>&nbsp;(<span class="math-tex">{tex}\\rho-\\rho^{\\prime}{/tex}</span>) <span class="math-tex">{tex}g{/tex}</span><br />
Terminal velocity of a bigger drop is given by<br />
v<sub>1</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{2}{9} \\frac{R^{2}}{\\eta}\\left(\\rho-\\rho^{\\prime}\\right) g{/tex}</span>&nbsp;<br />
Dividing Eq. (ii) by Eq. (i), we get<br />
<span class="math-tex">{tex}\\frac{v_{b}}{v_{s}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{R^{2}}{r^{2}}{/tex}</span><br />
But R =&nbsp;<span class="math-tex">{tex}n^{\\frac{1}{3}}r{/tex}</span><br />
and v<sub>s</sub>&nbsp;= 10&nbsp;<span class="math-tex">{tex}\\frac{cm}{s}{/tex}</span><br />
v<sub>b</sub>&nbsp;= v<sub>s</sub>&nbsp;<span class="math-tex">{tex}\\times\\left(\\frac{R^{2}}{r^{2}}\\right){/tex}</span>&nbsp;= 10&nbsp;<span class="math-tex">{tex}\\times \\frac{n^{2 / 3} r^{2}}{r^{2}}{/tex}</span><br />
v<sub>b</sub>&nbsp;= 10&nbsp;<span class="math-tex">{tex}n^{\\frac{2}{3}}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{cm}{s}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A soap bubble of radius 4 cm and surface tension 30 dyne cm<sup>-1</sup> is blown at the end of a tube of length 10 cm and internal radius 0.20 cm. If the viscosity of air is 1.89 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-4</sup>&nbsp;poise, find the time taken by the bubble to be reduced to a radius of 2 cm.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let R be the radius of the bubble at any instant. Its volume is<br />
V =&nbsp;<span class="math-tex">{tex}\\frac{4}{3} \\pi{/tex}</span>R<sup>3</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Rate of flow of air<br />
=&nbsp;<span class="math-tex">{tex}\\frac{d V}{d t}=\\frac{4}{3} \\pi \\times{/tex}</span>&nbsp;3R<sup>2</sup>&nbsp;<span class="math-tex">{tex}\\frac{d R}{d t}{/tex}</span>&nbsp;= 4<span class="math-tex">{tex}\\pi{/tex}</span>R<sup>2</sup>&nbsp;<span class="math-tex">{tex}\\frac{d R}{d t}{/tex}</span><br />
But&nbsp;<span class="math-tex">{tex}\\frac{d V}{d t}=\\frac{\\pi p r^{4}}{8 \\eta l}{/tex}</span>&nbsp;and for a soap bubble, p =&nbsp;<span class="math-tex">{tex}\\frac{4 \\sigma}{R}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\frac{d V}{d t}=\\frac{\\pi r^{4}}{8 \\eta l} \\cdot \\frac{4 \\sigma}{R}{/tex}</span>&nbsp;= 4<span class="math-tex">{tex}\\pi{/tex}</span>R<sup>2</sup>&nbsp;<span class="math-tex">{tex}\\frac{d R}{d t}{/tex}</span>&nbsp;or dt =&nbsp;<span class="math-tex">{tex}\\frac{8 \\ln }{\\sigma r^{4}}{/tex}</span>&nbsp;R<sup>3</sup>&nbsp;dR<br />
Time taken by the bubble when its radius changes from R<sub>1</sub> to R<sub>2</sub> is<br />
&nbsp;<span class="math-tex">{tex}t=\\int d t=\\frac{8 \\ln }{\\sigma r^{4}} \\int_\\limits{R_{2}}^{R_{1}} R^{3} d R=\\frac{8 \\ln }{\\sigma r^{4}}\\left(\\frac{R_{1}^{4}-R_{2}^{4}}{4}\\right){/tex}</span><br />
But R<sub>1</sub>&nbsp;= 4 cm, R<sub>2</sub>&nbsp;= 2 cm,&nbsp;<span class="math-tex">{tex}\\sigma{/tex}</span>&nbsp;= 30 dyne cm<sup>-1</sup>, l = 10 cm, r = 0.2 cm,&nbsp;<span class="math-tex">{tex}\\eta{/tex}</span>&nbsp;= 1.85&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-4</sup>&nbsp;poise<br />
<span class="math-tex">{tex}\\therefore t=\\frac{8 \\times 10 \\times 1.85 \\times 10^{-4}}{30 \\times(0.2)^{4}} \\times\\left(\\frac{4^{4}-2^{2}}{4}\\right){/tex}</span>&nbsp;= 296 s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that a liquid at rest exerts a force perpendicular to the surface of the container at every point.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Consider a liquid contained in a vessel in the equilibrium state of rest. As shown in Fig., suppose the liquid exerts a force F on the bottom surface in an inclined direction OA. The surface exerts an equal reaction R to water along OB.<br/>
<img alt="" data-imgur-src="09BG6sc.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082703-3kctys.jpg" style="width: 200px; height: 167px;"/><br/>
The reaction R along OB has two rectangular components:</p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Tangential component, OC = R cos <span class="math-tex">{tex}\\theta{/tex}</span></li>
<li>Normal component, OD = R sin <span class="math-tex">{tex}\\theta{/tex}</span></li>
</ol>
<p>Since a liquid cannot resist any tangential force, the liquid near O should begin to flow along OC. But the liquid is at rest, the force along OC must be zero.<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> R cos <span class="math-tex">{tex}\\theta{/tex}</span> = 0<br/>
As R <span class="math-tex">{tex}\\neq{/tex}</span> 0, so cos <span class="math-tex">{tex}\\theta{/tex}</span> = 0 or <span class="math-tex">{tex}\\theta{/tex}</span> = 90<sup>o</sup><br/>
Hence a liquid always exerts a force perpendicular to the surface of the container at every point.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that the Reynold&#39;s number represents the ratio of the inertial force per unit area to the viscous force per unit area.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The physical significance of Reynold&#39;s number. Consider a narrow tube having a cross-sectional area A Suppose a fluid flows through it with a velocity v for a time interval&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>t.<br />
Length of the fluid = Velocity <span class="math-tex">{tex}\\times{/tex}</span> time = v&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>t<br />
The volume of the fluid flowing through the tube in time&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>t = Av&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>t<br />
Mass of the fluid,<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>m =&nbsp;Volume <span class="math-tex">{tex}\\times{/tex}</span> density = Av&nbsp;<span class="math-tex">{tex}\\Delta t \\times \\rho{/tex}</span><br />
The inertial force acting per unit area of the fluid<br />
=&nbsp;<span class="math-tex">{tex}\\frac{F}{A}=\\frac{\\text { Rate of change of momentum }}{A}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{\\Delta m \\times v}{\\Delta t \\times A}=\\frac{A v \\Delta t \\rho \\times v}{\\Delta t \\times A}=\\rho v^{2}{/tex}</span><br />
Viscous force per unit area of the fluid<br />
=&nbsp;<span class="math-tex">{tex}\\eta \\times{/tex}</span>&nbsp;velocity gradient =&nbsp;<span class="math-tex">{tex}\\eta \\frac{v}{D}{/tex}</span><br />
<span class="math-tex">{tex}\\frac{\\text { Inertial force per unit area }}{\\text { Viscous force per unit area }}=\\frac{\\rho v^{2}}{\\eta v / D}=\\frac{\\rho v D}{\\eta}{/tex}</span>&nbsp;= R<sub>e</sub><br />
Thus Reynold&#39;s number represents the ratio of the inertial force per unit area to the viscous force per unit area.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State Bernoulli&#39;s theorem. With the help of suitable diagram, establish Bernoulli&#39;s equation for liquid flow. Give two practical applications of it.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>According to Bernoulli's theorem, the sum of the energies possessed by a flowing ideal liquid at a point is constant provided that the liquid is incompressible and non-viseous and flow in streamline.<br/>
<img data-imgur-src="8IQVf78.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1707470168-c6e6nh.jpg" style="height:133px; width:135px"/><br/>
Therefore, the work done is W = F<sub>A</sub>d = P<sub>A</sub>a<sub>A</sub>v<sub>A</sub>t<br/>
But a<sub>A</sub>v<sub>A</sub>t = a<sub>A</sub>d = V, volume of the liquid entering at A.<br/>
Thus, the work done is the pressure energy (at A), W = F<sub>A</sub>d = P<sub>A</sub>V<br/>
Pressure energy per unit volume at A = <span class="math-tex">{tex}\\frac{\\text { Pressure energy }}{\\text { Volume }}=\\frac{\\mathrm{P}_{\\mathrm{A}} \\mathrm{V}}{\\mathrm{V}}=\\mathrm{P}_{\\mathrm{A}}{/tex}</span><br/>
Pressure energy per unit mass at A <span class="math-tex">{tex}=\\frac{\\text { Pressure energy }}{\\text { Mass }}=\\frac{\\mathrm{P}_{\\mathrm{A}} \\mathrm{V}}{m}=\\frac{\\mathrm{P}_{\\mathrm{A}}}{\\frac{m}{\\mathrm{~V}}}=\\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}{/tex}</span><br/>
since m is the mass of the liquid entering at A in a given time, therefore, pressure energy of the liquid at A is<br/>
liquid at A is<br/>
E<sub>PA</sub> = P<sub>A</sub>V = <span class="math-tex">{tex}\\mathrm{P}_{\\mathrm{A}} \\mathrm{V} \\times\\left(\\frac{m}{m}\\right)=m \\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}{/tex}</span><br/>
Potential energy of the liquid at A,<br/>
PE<sub>A</sub> = mg h<sub>A</sub><br/>
Due to the flow of liquid, the kinetic energy of the liquid at A,<br/>
<span class="math-tex">{tex}\\mathrm{KE}_{\\mathrm{A}}=\\frac{1}{2} m v_{\\mathrm{A}}^2{/tex}</span><br/>
E<sub>A</sub> = E<sub>PA</sub> + KE<sub>A</sub> + PE<sub>A</sub><br/>
<span class="math-tex">{tex}\\mathrm{E}_{\\mathrm{A}}=m \\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}+\\frac{1}{2} m v_{\\mathrm{A}}^2+m g h_{\\mathrm{A}}{/tex}</span><br/>
<span class="math-tex">{tex}\\mathrm{E}_{\\mathrm{B}}=m \\frac{\\mathrm{P}_{\\mathrm{B}}}{\\rho}+\\frac{1}{2} m v_{\\mathrm{B}}^2+m g h_{\\mathrm{B}}{/tex}</span><br/>
From the law of conservation of energy, E<sub>A</sub> = E<sub>B</sub><br/>
<span class="math-tex">{tex}m \\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}+\\frac{1}{2} m v_{\\mathrm{A}}^2+m g h_{\\mathrm{A}}=m \\frac{\\mathrm{P}_{\\mathrm{B}}}{\\rho}+\\frac{1}{2} m v_{\\mathrm{B}}^2+m g h_{\\mathrm{B}}{/tex}</span><br/>
<span class="math-tex">{tex}\\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}+\\frac{1}{2} v_{\\mathrm{A}}^2+g h_{\\mathrm{A}}=\\frac{\\mathrm{P}_{\\mathrm{B}}}{\\rho}+\\frac{1}{2} v_{\\mathrm{B}}^2+g h_{\\mathrm{B}}{/tex}</span> = constant<br/>
Thus, the above equation can be written as<br/>
<span class="math-tex">{tex}\\frac{\\mathrm{P}}{\\rho g}+\\frac{1}{2} \\frac{v^2}{g}+h{/tex}</span> = constant<br/>
Bernoulli's principle has numerous applications. Some of it include airplanes, sailboats, and entrainment devices.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Explain why</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>To keep a piece of paper horizontal, you should blow&nbsp;over, not under, it.</li>
	<li>When we try to close a water tap with our fingers, fast jets of water gush through the openings between our fingers.</li>
	<li>The size of the needle of a syringe controls flow rate better than the thumb pressure exerted by a doctor while administering an injection.</li>
	<li>A fluid flowing out of a small hole in a vessel results in a backward thrust on the vessel.</li>
	<li>A spinning cricket ball in air does not follow a parabolic trajectory.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>When we blow over the paper, the velocity of air increases and hence pressure of air decreases in accordance with Bernoulli&#39;s principle. But the pressure below the paper (atmospheric pressure) is high which keeps the paper horizontal.</li>
	<li>According to the equation of continuity, velocity is inversely proportional to the area of cross-section. Since area between two fingers is very small as compared to the area of water tap above it, hence fast jets of water gush out through openings between the fingers.</li>
	<li>According to Bernoulli&#39;s principle,<br />
	p +&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>gh +&nbsp;<span class="math-tex">{tex}\\frac{1}{2}\\rho{/tex}</span>v<sup>2</sup>&nbsp;= constant<br />
	Thus the total energy of the injectable medicine depends upon second power of the velocity and first power of the pressure. It means that total energy of the injectable medicine has greater dependence on its velocity. Therefore, a doctor adjusts the flow rate of the medicine with the help of the size of the needle of the syringe (a<sub>1</sub>v<sub>1</sub>&nbsp;= a<sub>2</sub>v<sub>2</sub>) rather than the thumb pressure, while administering an injection.</li>
	<li>Due to small area of cross-section of the hole, the fluid flows out of the vessel with a large speed and hence with a large linear momentum. As no external force acts on the system, in order to conserve the linear momentum, the vessel acquires a backward momentum and hence a backward thrust acts on the vessel.</li>
	<li>A spinning cricket ball would have followed a parabolic trajectory has there been no air. But because of air the Magnus effect takes place. Due to the Magnus effect the spinning cricket ball deviates from its parabolic trajectory.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>State Bernoulli&#39;s equation.</li>
	<li>Name the physical quantity corresponding to each term of this equation.</li>
	<li>What type of liquid flow obeys this equation?</li>
	<li>Show that this equation is same as the equation due to Pascal&#39;s law in the presence of gravity if a liquid or gas is at rest.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>According to Bernoulli&rsquo;s theorem, the sum of pressure energy, kinetic energy, and potential energy per unit mass of an incompressible, non-viscous fluid in a streamlined flow remains a constant. Mathematically,<br />
	<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1706012306-nne59w.jpg" style="height:173px; width:200px" /></li>
	<li>P is the pressure, V is the velocity, <span class="math-tex">{tex}\\rho{/tex}</span> is the density, z is the distance, g is the acceleration due to gravity</li>
	<li>Bernoulli&#39;s equation is valid for ideal fluids: those that are incompressible, irrotational, inviscid, and subjected to conservative forces.</li>
	<li>Bernoulli&#39;s equation P + <span class="math-tex">{tex}\\rho{/tex}</span>gh + <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>Pv<sup>2</sup> = constant<br />
	at liquid rest v = 0<br />
	P + <span class="math-tex">{tex}\\rho{/tex}</span>gh = 0<br />
	p = <span class="math-tex">{tex}\\rho{/tex}</span>gh This is pascal&#39;s law</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Explain why:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>The angle of contact of mercury with glass is obtuse, while that of water with glass is acute.</li>
	<li>Water on a clean glass surface tends to spread out while mercury on the same surface tends to form drops. (Put differently, water wets the glass while mercury does not).</li>
	<li>Surface tension of a liquid is independent of the area of the surface.</li>
	<li>Water with detergent disolved in it should have small angles of contact.</li>
	<li>A drop of liquid under no external forces is always spherical in shape.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>The cohesive force between molecules of mercury is more as compared to the adhesive force between mercury and glass molecules. Due to which meniscus of mercury is convex and hence angle of contact is obtuse. On the other side, the adhesive force between water and glass molecules is greater in comparison to the cohesive force between water molecules. So the meniscus of water is concave and hence angle of contact is acute.</li>
	<li>The adhesive force between water and glass molecules is greater than the cohesive force between water molecules. So water tends to spread on a clean glass surface. On the other hand, the cohesive force between mercury molecules is greater than the adhesive force between mercury and glass molecules. So mercury tends to form drops.</li>
	<li>Surface tension may be defined as the force acting per unit length of a line imagined tangential to a liquid surface at rest. It depends on the nature of the liquid and its temperature while it&nbsp; is independent of the area of the liquid surface.</li>
	<li>The detergents should have a small angle of contact so that they have low surface tension and hence a greater ability to wet a surface. Moreover, if <span class="math-tex">{tex}\\theta{/tex}</span> is small, cos <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;will be large and hence detergent will penetrate&nbsp;<span class="math-tex">{tex}\\left(h=\\frac{2 \\sigma \\cos \\theta}{r \\rho g}\\right){/tex}</span>&nbsp;more in the narrow spaces in the cloth and will easily remove the dirt.</li>
	<li>The free surface of liquid at rest tends to acquire minimum surface area. In the absence of any external force due to property of surface tension. Therefore a liquid drop becomes spherical in shape because for a given volume, a sphere has a minimum surface area.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is meant by Streamline flow? State the equation of Continuity. Write the properties of an ideal fluid. Establish Bernoulli&#39;s equation as applied to an ideal fuel.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Streamline flow in fluids is defined as the flow in which the fluids flow in parallel layers such that there is no disruption or intermixing of the layers and at a given point, the velocity of each fluid particle passing by remains constant with time.<br />
The equation of continuity is simply a mass balance of a fluid flowing through a stationary volume element. It states that the rate of mass accumulation in this volume element equals the rate of mass in minus the rate of mass out.<br />
An ideal fluid (also called a perfect fluid) is a fluid that has no viscosity, incompressible, and has zero surface tension.<br />
Bernoulli&#39;s equation as applied to an ideal fluid.<br />
We make the following assumptions for the bernoulli&#39;s equation to be used.<br />
The flow must be steady<br />
The flow must be incompressible<br />
Friction by viscous forces must be negligible.<br />
Bernoulli&#39;s equation can be written as<br />
<span class="math-tex">{tex}\\frac{v^2}{2}+g z+\\frac{p}{\\rho}{/tex}</span> = constant<br />
v is the fluid flow speed at a point on a streamline, g is the acceleration due to gravity.<br />
z is the elevation of the point above a reference plane.<br />
p is the pressure at the chosen point.<br />
<span class="math-tex">{tex}\\rho{/tex}</span> is the density of the fluid at all points in the fluid.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Consider the flow at two regions 1 (i.e. BC) and 2 (i.e. DE). Consider the fluid initially lying between B and D. In an infinitesimally time interval <span class="math-tex">{tex}\\Delta{/tex}</span>t, this fluid would have moved. Suppose v<sub>1</sub> is the speed at which fluid would have moved. Suppose v<sub>1</sub> is the speed at B and v<sub>2</sub> at D, then fluid initially at B has moved a distance v<sub>1</sub><span class="math-tex">{tex}\\Delta{/tex}</span>t to C (v<sub>1</sub><span class="math-tex">{tex}\\Delta{/tex}</span>t is small enough to assume constant cross-section along BC).<br />
In the same interval <span class="math-tex">{tex}\\Delta{/tex}</span>t, the fluid initially at D moves to E, a distance equal to v<sub>2</sub><span class="math-tex">{tex}\\Delta{/tex}</span>t. Pressures p<sub>1</sub> and p<sub>2</sub> act as shown on the plane faces of areas A<sub>1</sub> and A<sub>2 </sub>binding the two regions as shown in figure<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658486442-9p92zy.jpg" style="height:144px; width:200px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>How much&nbsp;work done applied on the fluid at BC.&nbsp;<strong>(1)</strong></li>
	<li>How much work done applied on the fluid of DE.&nbsp;<strong>(1)</strong></li>
	<li>Write the expression of Bernoulli&#39;s equation.&nbsp;<strong>(2)</strong></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>The work done on the fluid at BC is p<sub>1</sub><span class="math-tex">{tex}\\Delta{/tex}</span>v.</li>
	<li>The work done on the fluid of DE is -p<sub>2</sub><span class="math-tex">{tex}\\Delta{/tex}</span>v.</li>
	<li>Expression of Bernoulli&#39;s equation is&nbsp;<span class="math-tex">{tex}\\frac 12 \\rho{/tex}</span>v<sup>2</sup>&nbsp;+&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>gh = constant.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Hydraulic lift is an application of Pascal&#39;s law. It is used to lift heavy loads. It is a force multiplier. So, when small forces applied on the smaller piston (acting downward) will be appearing as a very large force (acting upward) on the larger piston. As a result of it, a heavy load placed on the larger piston is easily lifted upwards.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658488237-6usy8e.jpg" style="height:151px; width:200px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>What states that the pressure at a point in a fluid at rest is the same in all directions? <strong>(1)</strong></p>
	</li>
	<li>
	<p>Pressure is applied to an enclosed fluid as shown in the above figure. It is&nbsp;<strong>(1)</strong></p>

	<ol>
		<li>
		<p>increased and applied to every part of the fluid</p>
		</li>
		<li>
		<p>diminished and transmitted to the walls of the container</p>
		</li>
		<li>
		<p>increased in proportion to the mass of the fluid and then transmitted</p>
		</li>
		<li>
		<p>transmitted unchanged to every portion of the fluid and the walls of container</p>
		</li>
	</ol>
	</li>
	<li>
	<p>A hydraulic lift has 2 limbs of areas A and 2A. Force F is applied over limb of area A to lift a heavy car. If distance moved by piston P<sub>1</sub> is x, find the distance moved by piston P<sub>2</sub>.&nbsp;<strong>(2)</strong><br />
	<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658488854-2h9yp7.jpg" style="height:144px; width:180px" /></p>
	</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>Pascal also discovered that the pressure at a point in a fluid at rest is the same in all directions; the pressure would be the same on all planes passing through a specific point. This fact is also known as Pascal&#39;s principle, or Pascal&#39;s law.</p>
	</li>
	<li>
	<p>transmitted unchanged to every portion of the fluid and the walls of container</p>
	</li>
	<li>
	<p>n a hydraulic lift, since the volume of fluid pushed down on the left side equals the volume of fluid that is lifted up on the right side<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span> Volume of P<sub>1</sub> = Volume of P<sub>2</sub><br />
	Since Volume = Length <span class="math-tex">{tex}\\times{/tex}</span> area<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;x<span class="math-tex">{tex}\\cdot{/tex}</span>A = y<span class="math-tex">{tex}\\cdot{/tex}</span>2A<br />
	or y =&nbsp;<span class="math-tex">{tex}\\frac{x}{2}{/tex}</span>&nbsp;</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Consider the flow at two regions 1 (i.e. BC) and 2 (i.e. DE). Consider the fluid initially lying between B and D. In an infinitesimally time interval <span class="math-tex">{tex}\\Delta{/tex}</span>t, this fluid would have moved. Suppose v<sub>1</sub> is the speed at which fluid would have moved. Suppose v<sub>1</sub> is the speed at B and v<sub>2</sub> at D, then fluid initially at B has moved a distance v<sub>1</sub><span class="math-tex">{tex}\\Delta{/tex}</span>t to C (v<sub>1</sub><span class="math-tex">{tex}\\Delta{/tex}</span>t is small enough to assume constant cross-section along BC).<br />
In the same interval <span class="math-tex">{tex}\\Delta{/tex}</span>t, the fluid initially at D moves to E, a distance equal to v<sub>2</sub><span class="math-tex">{tex}\\Delta{/tex}</span>t. Pressures p<sub>1</sub> and p<sub>2</sub> act as shown on the plane faces of areas A<sub>1</sub> and A<sub>2 </sub>binding the two regions as shown in figure<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658486442-9p92zy.jpg" style="height:144px; width:200px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>How much&nbsp;work done applied on the fluid at BC.</p>
	</li>
	<li>
	<p>How much work done applied on the fluid of DE.</p>
	</li>
	<li>
	<p>Find the total work done on the fluid.</p>
	</li>
	<li>
	<p>What should be the change in its kinetic energy?</p>
	</li>
	<li>
	<p>Write the expression of Bernoulli&#39;s equation.</p>
	</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>The work done on the fluid at BC is p<sub>1</sub><span class="math-tex">{tex}\\Delta{/tex}</span>v.</p>
	</li>
	<li>
	<p>The work done on the fluid of DE is -p<sub>2</sub><span class="math-tex">{tex}\\Delta{/tex}</span>v.</p>
	</li>
	<li>
	<p>Total work done on the fluid is (p<sub>1 -&nbsp;</sub>p<sub>2</sub>)&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>v.</p>
	</li>
	<li>
	<p>The change in its kinetic energy is&nbsp;<span class="math-tex">{tex}\\frac 12 \\rho \\Delta V (v_2^2 - v_1^2){/tex}</span>.</p>
	</li>
	<li>
	<p>Expression of Bernoulli&#39;s equation is&nbsp;<span class="math-tex">{tex}\\frac 12 \\rho{/tex}</span>v<sup>2</sup>&nbsp;+&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>gh = constant.</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State and prove Bernoulli&#39;s principle for the flow of non-viscous, incompressible liquid in streamlined flow. Give its limitations.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Bernoulli&rsquo;s theorem: According to Bernoulli&rsquo;s theorem, the sum of pressure energy, kinetic energy, and potential energy per unit mass of an incompressible, non-viscous fluid in a streamlined flow remains a constant. Mathematically,<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1705395124-hfnk7s.jpg" style="height:140px; width:208px" /><br />
<span class="math-tex">{tex}\\frac{\\mathrm{P}}{\\rho}+\\frac{1}{2} v^2+g h{/tex}</span> = constant<br />
Let us consider a flow of liquid through a Flow of liquid through a pipe AB pipe AB. Let V be the volume of the liquid when it enters A in a time t which is equal to the volume of the liquid leaving B in the same time. Let a<sub>A</sub>, v<sub>A</sub> and P<sub>A</sub> be the area of cross section of the tube, velocity of the liquid and pressure exerted by the liquid at A respectively. Let the force exerted by the liquid at A is F<sub>A </sub>= P<sub>A</sub>a<sub>A </sub><br />
Therefore, the work done is W = F<sub>A</sub>d = P<sub>A</sub>a<sub>A</sub>v<sub>A</sub>t<br />
But a<sub>A</sub>v<sub>A</sub>t = a<sub>A</sub>d = V, volume of the liquid entering at A.<br />
Thus, the work done is the pressure energy (at A), W = F<sub>A</sub>d = P<sub>A</sub>V<br />
Pressure energy per unit volume at A = <span class="math-tex">{tex}\\frac{\\text { Pressure energy }}{\\text { Volume }}=\\frac{\\mathrm{P}_{\\mathrm{A}} \\mathrm{V}}{\\mathrm{V}}=\\mathrm{P}_{\\mathrm{A}}{/tex}</span><br />
Pressure energy per unit mass at A <span class="math-tex">{tex}=\\frac{\\text { Pressure energy }}{\\text { Mass }}=\\frac{\\mathrm{P}_{\\mathrm{A}} \\mathrm{V}}{m}=\\frac{\\mathrm{P}_{\\mathrm{A}}}{\\frac{m}{\\mathrm{~V}}}=\\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}{/tex}</span><br />
since m is the mass of the liquid entering at A in a given time, therefore, pressure energy of the liquid at A is<br />
liquid at A is<br />
E<sub>PA</sub> = P<sub>A</sub>V = <span class="math-tex">{tex}\\mathrm{P}_{\\mathrm{A}} \\mathrm{V} \\times\\left(\\frac{m}{m}\\right)=m \\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}{/tex}</span><br />
Potential energy of the liquid at A,<br />
PE<sub>A</sub> = mg h<sub>A</sub><br />
Due to the flow of liquid, the kinetic energy of the liquid at A,<br />
<span class="math-tex">{tex}\\mathrm{KE}_{\\mathrm{A}}=\\frac{1}{2} m v_{\\mathrm{A}}^2{/tex}</span><br />
E<sub>A</sub> = E<sub>PA</sub> + KE<sub>A</sub> + PE<sub>A</sub><br />
<span class="math-tex">{tex}\\mathrm{E}_{\\mathrm{A}}=m \\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}+\\frac{1}{2} m v_{\\mathrm{A}}^2+m g h_{\\mathrm{A}}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{E}_{\\mathrm{B}}=m \\frac{\\mathrm{P}_{\\mathrm{B}}}{\\rho}+\\frac{1}{2} m v_{\\mathrm{B}}^2+m g h_{\\mathrm{B}}{/tex}</span><br />
From the law of conservation of energy, E<sub>A</sub> = E<sub>B</sub><br />
<span class="math-tex">{tex}m \\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}+\\frac{1}{2} m v_{\\mathrm{A}}^2+m g h_{\\mathrm{A}}=m \\frac{\\mathrm{P}_{\\mathrm{B}}}{\\rho}+\\frac{1}{2} m v_{\\mathrm{B}}^2+m g h_{\\mathrm{B}}{/tex}</span><br />
<span class="math-tex">{tex}\\frac{\\mathrm{P}_{\\mathrm{A}}}{\\rho}+\\frac{1}{2} v_{\\mathrm{A}}^2+g h_{\\mathrm{A}}=\\frac{\\mathrm{P}_{\\mathrm{B}}}{\\rho}+\\frac{1}{2} v_{\\mathrm{B}}^2+g h_{\\mathrm{B}}{/tex}</span> = constant<br />
Thus, the above equation can be written as<br />
<span class="math-tex">{tex}\\frac{\\mathrm{P}}{\\rho g}+\\frac{1}{2} \\frac{v^2}{g}+h{/tex}</span> = constant</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State and prove Bernoulli&#39;s theorem.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Bernoulli's principle states that an increase in the speed of a fluid occurs simultaneously with a decrease in static pressure or a decrease in the fluid's potential energy.<br/>
To prove Bernoulli's theorem, consider a fluid of negligible viscosity moving with laminar flow. as shown in Figure.<br/>
Let the velocity, pressure and area of the fluid cloumn be p<sub>1</sub>, v<sub>1</sub> and A<sub>1</sub> at Q and p<sub>2</sub>, v<sub>2</sub> and A<sub>2</sub> at R. Let the  volume bounded by Q and R move to S and T where QS = L<sub>1</sub>, and RT = L<sub>2</sub><br/>
<img alt="" data-imgur-src="ajIJECU.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082712-nnd96t.jpg" style="width: 250px; height: 88px;"/><br/>
If the fluid is incompressible:<br/>
The work done by the pressure difference per unit volume = gain in kinetic energy per unit volume + gain in potential energy per unit volume. Now:<br/>
A<sub>1</sub>L<sub>1</sub> = A<sub>2</sub>L<sub>2</sub><br/>
Work done is given by:<br/>
W = F <span class="math-tex">{tex}\\times{/tex}</span> d = p <span class="math-tex">{tex}\\times{/tex}</span> volume<br/>
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> W<sub>net</sub> = p<sub>1</sub> - p<sub>2</sub><br/>
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> K.E = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>mv<sup>2</sup> = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>V <span class="math-tex">{tex}\\rho{/tex}</span>v<sup>2</sup> = <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span><span class="math-tex">{tex}\\rho{/tex}</span>v<sup>2</sup> (<span class="math-tex">{tex}\\because{/tex}</span> V = 1)<br/>
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> K.E<sub>gained</sub> = <span class="math-tex">{tex}\\frac{1}{2} \\rho\\left(v_{2}^{2}-v_{1}^{2}\\right){/tex}</span><br/>
P<sub>1</sub> + <span class="math-tex">{tex}\\frac{1}{2} \\rho v_{1}^{2}{/tex}</span> + <span class="math-tex">{tex}\\rho{/tex}</span>gh<sub>1</sub> = P<sub>2</sub> + <span class="math-tex">{tex}\\frac{1}{2} \\rho v_{2}^{2}{/tex}</span> + <span class="math-tex">{tex}\\rho{/tex}</span>gh<sub>2</sub><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> P + <span class="math-tex">{tex}\\frac{1}{2} \\rho v^{2}{/tex}</span> + <span class="math-tex">{tex}\\rho{/tex}</span>gh = const.<br/>
For a horizontal tube<br/>
<span class="math-tex">{tex}\\because{/tex}</span> h<sub>1</sub> = h<sub>2</sub><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> P + <span class="math-tex">{tex}\\frac{1}{2} \\rho v^{2}{/tex}</span> = const.<br/>
Therefore, this proves Bernoulli's theorem. Here we can see that if there is an increase in velocity there must be a decrease in pressure and vice versa.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is capillarity? Derive an expression for the height to which the liquid rises in a capillary tube of radius r with angle of contact <span class="math-tex">{tex}\\theta{/tex}</span>. Give two examples of capillarity from daily life.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>A tube of very fine bore is called capillary. The phenomenon of rise or fall of a liquid in a capillary tube is called capillarity.<br/>
<img data-imgur-src="CjW5tOs.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1707470171-s94shu.jpg" style="height:140px; width:184px"/><br/>
Lets say capillary of radius r is placed in a beaker containing a liquid of density &amp; and water rises in the capillary the height h,<br/>
P<sub>B</sub> - P<sub>C</sub> = <span class="math-tex">{tex}\\frac{2 T}{R}{/tex}</span> ...(1)&amp;<br/>
P<sub>B</sub> = P<sub>O</sub> ...(3)<br/>
P<sub>A</sub> = P<sub>O</sub> ...(4)<br/>
P<sub>C</sub> + <span class="math-tex">{tex}\\rho {/tex}</span>gh = P<sub>A</sub> ...(2)<br/>
From (1), (2) &amp; (3), (4) press are gradient<br/>
<span class="math-tex">{tex}P_o-\\frac{2 T}{R}=P \\rho g h{/tex}</span><br/>
<span class="math-tex">{tex}\\frac{2 T}{R}=\\rho g h \\Rightarrow h=\\frac{2 T}{R \\rho g}=\\frac{2 T \\cos \\theta}{\\rho g r}{/tex}</span></p>
<p><strong>Application of capillarity:</strong></p>
<ul>
<li>In pen, ink rises due to capillarity.</li>
<li>In plants, the water is transferred to the leaves from the roots by capillarity.</li>
<li>Cotton clothes absorb water by capillarity.</li>
</ul></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1350-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_THERMAL_PROPERTIES_OF_MATTER = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If boiling point of a liquid is 95 &deg;F, what will be the reading at Celsius scale?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">7<sup>o</sup>C</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">65<sup>o</sup>C</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">63<sup>o</sup>C</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">35<sup>o</sup>C</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>C =&nbsp;<span class="math-tex">{tex}\\frac{5}{9}(F-32){/tex}</span><br />
<span class="math-tex">{tex}=\\frac{5}{9}(95-32)=35^{\\circ} \\mathrm{C}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>At which temperature, the centigrade and Fahrenheit scales are equal?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">40<sup>o</sup></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">-40<sup>o</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\frac{C}{5}=\\frac{F-32}{9}{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}\\frac{C}{5}=\\frac{C-32}{9}{/tex}</span><br />
4C = -160<br />
or&nbsp;C = F = &minus;40<sup>o</sup></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">37<sup>o</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">-80<sup>o</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Molar Specific Heat capacity has units of:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">J/mol.K</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Q = nC<span class="math-tex">{tex}\\Delta {/tex}</span>T<br />
C = <span class="math-tex">{tex}Q\\over{n\\Delta T}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">J/kg.K</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">J.ohm/sec. K<sup>2</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">W/m.K</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If m mass of a substance undergoes a phase change, then amount of heat required will be</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>Q = mL</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\Delta{/tex}</span>Q = mL</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>Q = mc<sub>p</sub><span class="math-tex">{tex}\\Delta{/tex}</span>T</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span> = m<sub>s</sub><span class="math-tex">{tex}\\Delta{/tex}</span>T</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>Q = mC<sub>v</sub><span class="math-tex">{tex}\\Delta{/tex}</span>T</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>When temperature of water is raised from 0<sup>o</sup>C to 4<sup>o</sup>C, it</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">expands</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">contracts</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>contracts</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">expands upto 2<sup>o</sup>C and then contracts upto 4<sup>o</sup>C</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">contracts upto 2<sup>o</sup>C and then expands upto 4<sup>o</sup>C</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Heat travels through vacuum by</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">conduction</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">convention</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">radiation</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Heat travels through vacuum due to radiation.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">both conduction and convention</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Thermal conductivity has units of:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">Wm<sup>-1</sup> K<sup>-1</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}H=\\frac{K A \\Delta \\theta}{l}{/tex}</span><br />
<span class="math-tex">{tex}K=\\frac{H l}{A \\Delta \\theta}{/tex}</span><br />
k- coefficient of thermal conductivity,<br />
H - heat flowing per unit time,<br />
l - length of solid material,<br />
A- area of cross section, <span class="math-tex">{tex}\\Delta \\theta{/tex}</span>&nbsp;- temperature difference</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">J ohm sec<sup>-2</sup> K<sup>-2</sup></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">J m<sup>-1</sup> K<sup>-1</sup></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">J kg<sup>-1</sup> K<sup>-1</sup></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The Celsius temperature at absolute zero is equal to:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">-273<sup>o</sup> C</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}{{{T_C} - 0} \\over {100 - 0}} = {{{T_K} - 273.15} \\over {373.15 - 273.15}}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">100<sup>o</sup> C</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">-100<sup>o</sup> C</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">273<sup>o</sup> C</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The two ends of a rod of length Land a uniform cross-sectional area A are kept at two temperatures T<sub>1</sub> and T<sub>2</sub>(T<sub>1&nbsp;</sub>&gt; T<sub>2</sub>). The rate of heat transfer, <span class="math-tex">{tex}\\frac{d Q}{d t}{/tex}</span> through the rod in a steady state is given by:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{d Q}{d t}=\\frac{K\\left(T_{1}-T_{2}\\right)}{L A}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{d Q}{d t}{/tex}</span> = KLA(T<sub>1</sub>−T<sub>2</sub>)</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{d Q}{d t}=\\frac{K A\\left(T_{1}-T_{2}\\right)}{L}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\frac{d Q}{d t}=\\frac{K A\\left(T_{1}-T_{2}\\right)}{L}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{d Q}{d t}=\\frac{K L\\left(T_{1}-T_{2}\\right)}{A}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Amount of heat required to raise the temperature of a body through 1K is called its</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">specific heat</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">Thermal capacity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The amount of heat required to raise the temperature of a body through 1 K is called its thermal capacity.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">water equivalent</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">entropy</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The ratio of thermal conductivity of two rods of different materials is 5 : 4. The two rods of same area of cross-section and same thermal resistance will have the lengths in the ratio</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">4 : 5</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">9 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">1 : 9</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">5 : 4 </p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Thermal resistance =&nbsp;<span class="math-tex">{tex}\\frac{d}{K A}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{d_{1}}{K_{1} A}=\\frac{d_{2}}{K_{2} A}{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}\\frac{d_{1}}{d_{2}}=\\frac{K_{1}}{K_{2}}=\\frac{5}{4}{/tex}</span>&nbsp;= 5 : 4</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>On a cold morning, a metal surface will feel colder to touch than a wooden surface, because</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">metal has high specific heat</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">metal has high thermal conductivity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Due to higher thermal conductivity of metal than wood, heat begins to flow readily from our body to the metal surface and so we feel colder.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">metal has low specific heat</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">metal has low thermal conductivity</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If wavelength at 4500 K is <span class="math-tex">{tex}\\lambda_{m}{/tex}</span>, the wavelength at 1500 K is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}3 \\lambda_{m}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\lambda_{m}^{\\prime} T^{\\prime}=\\lambda_{m} T{/tex}</span><br />
<span class="math-tex">{tex}\\lambda_{m}^{\\prime} \\times 1500=\\lambda_{m} \\times 4500{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\lambda_{m}^{\\prime}=3 \\lambda_{m}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\lambda_{\\mu}^{\\prime}=3 \\lambda_{m}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\lambda_{m} }{ 3}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}9 \\lambda_{m}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac {\\lambda_{m} }{ 9}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A brass spring has a spring constant k. When the spring is heated, the spring constant will:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">decrease</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>on heating spring will be expand<br />
<span class="math-tex">{tex}k \\propto {1 \\over l}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">increase</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">remain the same</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">increase, then decrease</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Temperature of atmosphere in Kashmir falls below -10<sup>o</sup>C in winter. Due to this water animal and plant life of Dal-lake</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">is destroyed in winters</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">frozen in winter and regenerated in summers</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">survives as only top layer of lake in frozen</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>survives as only top layer of lake in frozen</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">survives as only lower layer of lake in frozen</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>When 0.15 kg of ice at 0 &deg;C is mixed with 0.30 kg of water at 50&deg;C in a container, the resulting temperature is 6.7&deg;C. Calculate the heat of fusion of ice. (s<sub>water</sub> = 4186 J kg<sup>-1</sup> K<sup>-1</sup>)</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Heat lost by water =&nbsp;<span class="math-tex">{tex}=m s_{w}\\left(\\theta_{1}-\\theta_{1}\\right)_{w}{/tex}</span><br />
= (0.30 kg)(4186 J kg<sup>-1</sup> K<sup>-1</sup>) (50.0&deg;C -&nbsp;6.7&deg;C)<br />
= 54376.14 J<br />
Heat required to melt ice = m<sub>2</sub>L<sub>f</sub> = (0.15 kg) L<sub><span style="font-size: 10.8333px;">f</span></sub><br />
Heat required to raise temperature of ice water to final temperature&nbsp;<span class="math-tex">{tex}=m_{1} s_{w}\\left(\\theta_{f}-\\theta_{1}\\right)_{1}{/tex}</span><br />
= (0.15 kg) (4186 J kg<sup>-1</sup> K<sup>-1</sup>) (6.7&deg;C -&nbsp;0&deg;C)<br />
= 4206.93 J<br />
Heat lost = heat gained<br />
54376.14 J = (0.15 kg) Lf + 4206.93 J<br />
L<sub>f</sub> = 3.34 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup> J kg<sup>-1</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A copper block of mass 2.5 kg is heated in a furnace to a temperature of 500 &deg;C and then placed on a large ice block. What is the maximum amount of ice that can melt? (Specific heat of copper = 0.39 J g<sup>-1</sup> K<sup>-1</sup>; heat of fusion of water = 335 Jg<sup>-1</sup>).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Mass of copper block, m = 2.5 kg = 2.5 =&nbsp;&nbsp;<span class="math-tex">{tex}2.5\\;\\times1000{/tex}</span>&nbsp;= 2500 g<br />
Increase in the temperature , <span class="math-tex">{tex}\\Delta \\theta = 500 ^ { \\circ } \\mathrm { C }{/tex}</span><br />
Specific heat of copper, C = 0.39 J g<sup>-1</sup> C<sup>-1</sup><br />
Latent heat of fusion for water, L = 335 J g<sup>-1</sup><br />
&nbsp;Heat lost by the copper block =&nbsp;Q = mC<span class="math-tex">{tex}\\Delta \\theta{/tex}</span><br />
= 2500 <span class="math-tex">{tex}\\times{/tex}</span> 0.39 <span class="math-tex">{tex}\\times{/tex}</span> 500<br />
= 487500 J<br />
Let m<sub>1</sub>&nbsp;is the amount of ice that melts on absorbing heat by copper block.<br />
heat gained by&nbsp;melting of m<sub>1</sub>&nbsp;gram of ice, Q = m<sub>1</sub>L<br />
<span class="math-tex">{tex}\\therefore m _ { 1 } = \\frac { Q } { L } = \\frac { 487500 } { 335 } = 1455.22 g{/tex}</span><br />
Hence, 1.45 Kg of maximum ice can get melt on placing the copper block on ice cube.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Discuss the anomalous expansion of water. Give its practical importance.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Water contracts on heating from 0<sup>o</sup> to 4<sup>o</sup>. This is called anomalous expansion of water. It has minimum volume and maximum density at 4<sup>o</sup>C.&nbsp;Water at the bottom of the lakes remains at 4<sup>o</sup>C&nbsp;even if it freezes from the top. This protects the entire aquatic animal and plant life.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define the three modes of transfer of heat from one object to another. Also cite one example for each one of them.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>&nbsp;There are three possible modes of transfer of heat energy.&nbsp;These&nbsp;are&nbsp;conduction,&nbsp;convection, and&nbsp;radiation.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Conduction is the process in&nbsp;which heat energy is transmitted&nbsp;from hot surfaces to cold surfaces without the actual transfer of the particles themselves. Heat transfer In metallic solids generally takes place through conduction.</li>
	<li>Convection is the process in&nbsp;which heat is transmitted from one place&nbsp;to another due to the bodily motion of the heated particles of the system. In fluids (i.e., liquids and gases) heat transfer generally takes place by convection.</li>
	<li>Radiation is the process in&nbsp;which heat energy is transmitted directly without the presence of any medium from one place to another without heating the intervening medium (if any). Energy from the Sun is transmitted to earth by this method only. Thermal radiation does not need any material medium for their propagation and travel with a speed of 3 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>8</sup> ms<sup>-1</sup> i.e., the same as the speed of light.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Distinguish between conduction, convection and radiation.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Three modes of heat transmission are conduction, convection, and radiation. Their main points of distinctions are as follows:</p>

<table border="1" cellpadding="3" cellspacing="0" style="width:100%;">
	<thead>
		<tr>
			<th scope="col">Conduction</th>
			<th scope="col">Convention&nbsp;</th>
			<th scope="col">Radiation</th>
		</tr>
	</thead>
	<tbody>
		<tr>
			<td>In conduction, heat transfer takes place between objects by direct contact.</td>
			<td>In convection, the heat transfer takes within the fluid.</td>
			<td>In radiation, heat transfer occurs through electromagnetic waves without involving particles.</td>
		</tr>
		<tr>
			<td>The heat transfer takes place due to the difference in temperature.</td>
			<td>The heat transfer occurs due to the difference in density.</td>
			<td>The heat transfer occurs in all objects with a temperature greater than 0 K.</td>
		</tr>
		<tr>
			<td>The heat transfer in conduction is slow.</td>
			<td>The heat transfer in convection is faster.</td>
			<td>The heat transfer in radiation is the fastest.</td>
		</tr>
		<tr>
			<td>The heat transfer occurs through a heated solid object.</td>
			<td>The heat transfer occurs through intermediate objects. For example, heat transfer between air and water.</td>
			<td>The heat transfer occurs through electromagnetic waves.</td>
		</tr>
		<tr>
			<td>It does not follow the laws of reflection and refraction.</td>
			<td>It does not follow the laws of reflection and refraction.</td>
			<td>It follows the laws of reflection and refraction.</td>
		</tr>
	</tbody>
</table></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define the terms specific heat and molar specific heat. Give their SI units.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Specific heat:</strong>&nbsp;The specific heat of a substance may be defined as the amount of heat required to raise the temperature of unit mass of the substance through one degree. It depends on the nature of the substance and its temperature.<br />
If an amount of heat <span class="math-tex">{tex}\\Delta{/tex}</span>Q is needed to raise the temperature of M mass of a substance through <span class="math-tex">{tex}\\Delta{/tex}</span>T, then specific heat is given by<br />
<span class="math-tex">{tex}c=\\frac{\\Delta Q}{M \\times \\Delta T}{/tex}</span><br />
The CGS unit of specific heat is cal g<sup>-1</sup> &deg;C<sup>-1</sup> and the SI unit is Jkg<sup>-1</sup>K<sup>-1</sup>.<br />
Clearly, the amount of heat required to raise the temperature of M mass of a substance through <span class="math-tex">{tex}\\Delta{/tex}</span>T is<br />
<span class="math-tex">{tex}\\Delta Q=M c \\Delta T{/tex}</span>.<br />
<strong>Molar specific heat:</strong>&nbsp;The molar specific heat of a substance is defined as the amount of heat required to raise the temperature of one mole of the substance through one degree. It depends on the nature of the substance and its temperature.<br />
If an amount of heat <span class="math-tex">{tex}\\Delta{/tex}</span>Q is required to raise the temperature of nmoles of a substance through <span class="math-tex">{tex}\\Delta{/tex}</span>T, then molar specific heat is given by<br />
<span class="math-tex">{tex}C=\\frac{\\Delta Q}{n \\Delta T}{/tex}</span><br />
The CGS unit of molar specific heat is cal mol<sup>-1</sup> &deg;C<sup>-1</sup> and SI unit is J mol<sup>-1</sup> K<sup>-1</sup>.<br />
Therefore, the amount of heat required to raise the temperature of n moles of a substance through <span class="math-tex">{tex}\\Delta{/tex}</span>T is<br />
<span class="math-tex">{tex}\\Delta Q=n C \\Delta T{/tex}</span>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>From Newton&#39;s law of cooling show that temperature of a hot liquid, when allowed to cool, falls exponentially.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to Newton&#39;s law of cooling rate of fall of temperature is given as&nbsp;<br />
<span class="math-tex">{tex}-\\frac{d T}{d t}=K\\left(T-T_{0}\\right){/tex}</span><br />
where K is a constant&nbsp;<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{d T}{T-T_{0}}=-K d t{/tex}</span>&nbsp;<br />
On integrating,&nbsp;&nbsp;<span class="math-tex">{tex}\\log _{e}\\left(T-T_{0}\\right){/tex}</span>&nbsp;= -Kt + c, where c is constant of integration.<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;&nbsp;<span class="math-tex">{tex}T-T_{0}={/tex}</span>&nbsp;<span class="math-tex">{tex}e^{(-K t+c)}{/tex}</span>&nbsp;= e<sup>-Kt</sup>. e<sup>c&nbsp;</sup>=&nbsp;<span class="math-tex">{tex}C_{0} \\cdot e^{-K t}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}T=T_{0}+C_{0} e^{-K t}{/tex}</span>&nbsp;where C<sub>0&nbsp;</sub>= e<sup>c</sup> = a constant.<br />
According to this equation, the temperature of hot liquid falls exponentially with time. The temperature versus time plot&nbsp;is shown in Figure.<br />
<img alt="" data-imgur-src="CrwN8y3.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/CrwN8y3.png" style="width: 200px; height: 170px;" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A clock with an iron pendulum keeps the correct time at 20<sup>o</sup> C. How much will it lose or gain if the temperature changes to 40<sup>o</sup>C? Coefficient of cubical expansion of iron = 36&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-6</sup>&nbsp;<sup>o</sup>C<sup>-1</sup>.&nbsp;</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Time period of simple pendulum,<br />
T<sub>20</sub> = 2 s<br />
Let T<sub>40</sub> be the time period at 40&deg;C. If l<sub>0</sub>, l<sub>20</sub>, l<sub>40</sub> be the lengths of the pendulum at 0&deg;C, 20&deg;C and 40&deg;C respectively, then<br />
<span class="math-tex">{tex} l_{20}=l_{0}(1+20 \\alpha) {/tex}</span><br />
<span class="math-tex">{tex} l_{40}=l_{0}(1+40 \\alpha) {/tex}</span><br />
<span class="math-tex">{tex} T_{20}=2 \\pi \\sqrt{\\frac{l_{20}}{g}}=2 \\pi \\sqrt{\\frac{l_{0}(1+20 \\alpha)}{g}} {/tex}</span><br />
<span class="math-tex">{tex}T_{40}=2 \\pi \\sqrt{\\frac{l_{40}}{g}}=2 \\pi \\sqrt{\\frac{l_{0}(1+40 \\alpha)}{g}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\frac{T_{40}}{T_{20}}=\\sqrt{\\frac{1+40 \\alpha}{1+20 \\alpha}}=(1+40 \\alpha)^{1 / 2}(1+20 \\alpha)^{-1 / 2}{/tex}</span><br />
<span class="math-tex">{tex}=\\left(1+\\frac{1}{2} \\times 40 \\alpha\\right)\\left(1-\\frac{1}{2} \\times 20 \\alpha\\right){/tex}</span>&nbsp;[Using Binomial theorem]<br />
<span class="math-tex">{tex}=(1+20 \\alpha)(1-10 \\alpha)=1+10 \\alpha{/tex}</span><br />
Fractional loss in time<br />
<span class="math-tex">{tex}=\\frac{T_{40}-T_{20}}{T_{20}}=10 \\alpha{/tex}</span><br />
= 10 <span class="math-tex">{tex}\\times{/tex}</span> 1.2 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>&minus;5&nbsp;</sup>= 1.2 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>&minus;4</sup><br />
As the temperature increases, time period also increases. The clock runs slow.<br />
Time lost in 24 hours<br />
= 1.2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-4</sup> <span class="math-tex">{tex}\\times{/tex}</span> 24 <span class="math-tex">{tex}\\times{/tex}</span> 3600 = 10.368 s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Explain the following&nbsp;</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Hot tea cools rapidly when poured into the saucer from the cup.</li>
	<li>Temperature of a hot liquid falls rapidly in the begining&nbsp;but slowly afterwards.</li>
	<li>A hot liquid cools faster if outer surface of the container is blackened.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>The tea will cool faster in the saucer as surface area increases on pouring hot tea in saucer from the cup and the rate of loss of heat is directly proportional to surface area of the radiating surface</li>
	<li>A hot liquid&nbsp;cools rapidly in the beginning but slowly afterward because the temperature of a hot liquid falls exponentially in&nbsp;accordance with Newton&rsquo;s law of cooling. In other&nbsp;words, the rate of cooling is directly proportional to the&nbsp;temperature difference between hot liquid and the&nbsp;surroundings.&nbsp;</li>
	<li>When the outer surface of the container is blackened, the surface becomes good emitter of heat and so the hot liquid in it cools faster.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is calorimetry? Briefly explain its principle.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Calorimetry is a branch of physics that deals with the measurement of the quantity of heat being transferred from one substance to another.<br />
The principle of calorimetry follows&nbsp;the law of conservation of energy. According to the principle of calorimetry, if two chemically non-reactive substances maintained at different temperatures are brought in thermal contact so as to share heat, the hotter substance transfers heat to the colder substance and the heat exchange continues till the temperature of both the substances become same. In such a situation if there is no heat energy dissipated due to radiation loss etc., then, we have<br />
Total heat transferred from the hotter body = Total heat transferred to the colder body.&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is meant by a triple point of water? What is the advantage of taking the triple point of water as the fixed point for a temperature scale?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>The triple point of water:</strong>&nbsp;The triple point of water is the state at which the three phases of water namely ice, liquid water, and water vapor are equally stable and co-exist in equilibrium. It is unique because it occurs at a specific temperature of 273.16 K and a specific pressure of 0.46 cm of Hg column. Thus for water.<br />
P<sub>tr</sub> = 0.46 cm of Hg<br />
T<sub>tr</sub> = 273.16 K or 0.01&deg;C<br />
In modern thermometry, the triple point of water is chosen to be one of the fixed points. As it is characterized by a unique temperature and pressure, it is preferred over the conventional fixed points namely the melting point of ice and boiling point of water. The melting point of ice and the boiling point of water both change with pressure. Moreover, the presence of impurities changes their values. But the triple point of water is independent of external factors.<br />
In the absolute Kelvin scale, the triple point of water is assigned the value 273.16 K. The absolute zero is taken as the other fixed point on this scale.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Briefly explain, what do you mean by the terms thermal strain and thermal stress? Write expressions for them.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>When a metal rod, whose ends are rigidly fixed so as to prevent the rod from expansion or contraction, undergoes a change in temperature, thermal strains and thermal stresses are developed in the rod.<br />
The <strong>thermal strain</strong> or deformation for an unrestricted thermal expansion can be defined as the ratio of change in length to the original length.<br />
<strong>Thermal Stress</strong> occurs when restricted expansion is converted to stress.<br />
If a rod of length l&nbsp;is heated by a temperature <span class="math-tex">{tex}\\Delta{/tex}</span>T, then increase in length of the rod is,&nbsp;<span class="math-tex">{tex}\\Delta l=l \\cdot \\alpha \\cdot \\Delta T{/tex}</span><br />
But due to being fixed at ends, the rod does not expand and a compressive thermal strain is developed in&nbsp;it which is given by,<br />
Thermal (compressive) strain =&nbsp;<span class="math-tex">{tex}\\frac{\\Delta l}{l}=\\alpha . \\Delta T{/tex}</span>, here <span class="math-tex">{tex}\\alpha{/tex}</span>&nbsp;= linear expansion coefficient of the material of rod.<br />
Due to this strain, thermal stress is developed in the rod.&nbsp;<br />
Thermal stress = Y <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;thermal strain = Y.&nbsp;<span class="math-tex">{tex}\\alpha{/tex}</span>&nbsp;. <span class="math-tex">{tex}\\Delta{/tex}</span>T<br />
Thus, the&nbsp;force (tension) exerted by the rod on the supports will be,<br />
<span class="math-tex">{tex}F=Y \\alpha \\cdot \\Delta T \\cdot A{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Mention three applications of thermal conductivity in daily life.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Some applications of conductivity in daily life:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li><strong>In winter, a metallic handle appears colder than the wooden door.</strong> In winter, the human body is at a higher temperature than the surrounding objects. As we touch the metallic handle (good conductor), heat flows from our body to the handle and feels cold. But no heat flows from our body to the wooden door (bad conductor), so it does not feel that cold as the metallic handle.</li>
	<li><strong>Cooking utensils are provided with wooden handles. </strong>Wood is a bad conductor of heat. A wooden handle does not allow heat to be conducted from the hot utensil to the hand. So we can easily hold the hot utensils with the help of wooden handles.</li>
	<li><strong>A new quilt is warmer than an old quilt. </strong>A new quilt contains more air in its pores as compared to the old quilt. As air is a bad conductor of heat, it does not allow heat to be conducted away from our body to the surroundings and we feel warmer in it.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Calculate the stress developed inside a tooth cavity filled with copper when hot tea at temperature of 57<sup>o</sup>C is drunk. You can take body (tooth) temperature to be 37<sup>o</sup>&nbsp;C and <span class="math-tex">{tex}\\alpha{/tex}</span> = 1.7 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup>/K. Bulk modulus for copper = 140 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup>N/m<sup>2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>First of all, the stress on the object(tooth) developed over here is dependent on bulk modulus of the material and the temperature difference. That&#39;s the stress is called a thermal stress over here.<br />
Now, change in temperature&nbsp;<span class="math-tex">{tex}\\Delta T = 57 - 37 = 20 ^ { \\circ } C{/tex}</span>&nbsp;= 20 K (since temperature difference is same here in both the scales)<br />
Coefficient of linear expansion&nbsp;<span class="math-tex">{tex}\\alpha{/tex}</span>&nbsp;of (tooth) body&nbsp;= 1.7 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup>&nbsp;K<sup>-1</sup>&nbsp;<br />
Cubical expansion&nbsp;<span class="math-tex">{tex}\\gamma = 3 \\alpha = 3 \\times 1.7 \\times 10 ^ { - 5 } = 5.1 \\times 10 ^ { - 5 } K ^ { - 1 }{/tex}</span>&nbsp;, [As,&nbsp;<span class="math-tex">{tex}\\alpha = \\frac {\\gamma}{3}{/tex}</span>]<br />
Let the volume of the cavity be V and its volume increased by&nbsp;<span class="math-tex">{tex}\\Delta V{/tex}</span>&nbsp;due to increase in temperature&nbsp;<span class="math-tex">{tex}\\Delta T{/tex}</span>.<br />
Then from the defination of coefficient of volume expansion,<br />
<span class="math-tex">{tex}\\Delta V = \\gamma V \\cdot \\Delta T{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\frac { \\Delta V } { V } = \\gamma \\Delta T{/tex}</span><br />
Thermal stress produced = Bulk modulus&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;Volume strain&nbsp;<br />
<span class="math-tex">{tex}= B × \\frac { \\Delta V } { V } = B × \\gamma× \\Delta T{/tex}</span><br />
Hence, thermal stress&nbsp;= 140 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 5.1 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 20 = 14280 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>4</sup>&nbsp;N/m<sup>2</sup>&nbsp;, as bulk modulus = 140 &times; 10<sup>9</sup>&nbsp;N/m<sup>2</sup>(given)<br />
= 1.428 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>8</sup>&nbsp;Nm<sup>-2</sup><br />
This stress is about&nbsp;<span class="math-tex">{tex}10 ^ { 3 }{/tex}</span>&nbsp;times of atmospheric pressure i.e.,&nbsp;1.013 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>5</sup>&nbsp;Nm<sup>-2</sup>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A thin rod having length L<sub>0</sub>&nbsp;at 0&deg;C and coefficient of linear expansion <span class="math-tex">{tex}\\alpha{/tex}</span> &nbsp;has its two ends maintained at temperatures <span class="math-tex">{tex}\\theta_1{/tex}</span> and&nbsp;&nbsp;<span class="math-tex">{tex}\\theta_2{/tex}</span>, respectively. Find its new length.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>As the temperature of rod varies from&nbsp;<span class="math-tex">{tex}\\theta _ { 1 }{/tex}</span> to&nbsp;<span class="math-tex">{tex}\\theta _ { 2 }{/tex}</span>&nbsp;from one end to another. So mean temperature of rod,&nbsp;<span class="math-tex">{tex}\\theta = \\frac {(\\theta _1 + \\theta_2 )}{2}{/tex}</span>&nbsp;<br />
<img alt="" data-imgur-src="p5ddlye.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/p5ddlye.png" style="width: 200px; height: 60px;" /><br />
So rate of flow of heat from A to C to B are equal<br />
<strong><span class="math-tex">{tex}\\because \\theta _ { 1 } &gt; \\theta &gt; \\theta _ { 2 }{/tex}</span>&nbsp;</strong><br />
From defination of thermal conductivity we get,<br />
<strong><span class="math-tex">{tex}\\therefore \\quad \\frac { d \\theta } { d t } = \\frac { K A \\left( \\theta _ { 1 } - \\theta \\right) } { L _ { 0 } / 2 }{/tex}</span></strong>(A = area of cross-section of the rod, L<sub>0</sub>&nbsp;= length of the rod)<br />
again,<span class="math-tex">{tex}~ \\frac {d \\theta}{dt}= \\frac { K A \\left( \\theta - \\theta _ { 2 } \\right) } { L _ { 0 } / 2 }{/tex}</span>(since same amount of heat flows from A to B via C in unit time)<br />
K is coefficient of thermal conductivity of the material of the rod.<br />
<span class="math-tex">{tex}\\therefore \\theta _ { 1 } - \\theta = \\theta - \\theta _ { 2 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\therefore \\theta = \\frac { \\theta _ { 1 } + \\theta _ { 2 } } { 2 }{/tex}</span>&nbsp;<br />
Hence the final length of the rod,​​​​​​​<br />
<span class="math-tex">{tex}L = L _ { 0 } ( 1 + \\alpha \\theta ) = L _ { 0 } \\left[ 1 + \\alpha \\left( \\frac { \\theta _ { 1 } + \\theta _ { 2 } } { 2 } \\right) \\right]{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Calculate the maximum amount of heat that may be lost per second by radiation by a sphere 14 cm in diameter at a temperature of 227&deg; C, when placed in an enclosure at 27&deg; C.<br />
Given Stefan&#39;s constant = 5.7 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-8</sup> Wm<sup>-2</sup> K<sup>-4</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Temperature of sphere,<br />
T = 227 + 273 = 500 K<br />
Temperature of surroundings,<br />
T<sub>0 </sub>= 27 + 273 = 300K<br />
Radius of sphere, r = 7 cm = 0.07 m<br />
Area of sphere,<br />
A =&nbsp;<span class="math-tex">{tex}4 \\pi r^{2}=4 \\times \\frac{22}{7} \\times(0.07)^{2}=6.16 \\times 10^{-2} \\mathrm{~m}^{2}{/tex}</span><br />
According to Stefan-Boltzmann law, the net heat lost per second by the sphere,<br />
<span class="math-tex">{tex}E=\\sigma\\left(T^{4}-T_{0}^{4}\\right) \\times A{/tex}</span><br />
= 5.7 <span class="math-tex">{tex}\\times {/tex}</span> 10<sup>&minus;8</sup>(500<sup>4&nbsp;</sup>&minus; 300<sup>4</sup>) <span class="math-tex">{tex}\\times {/tex}</span> 6.16 <span class="math-tex">{tex}\\times {/tex}</span> 10<sup>&minus;2</sup>Js<sup>&minus;1&nbsp;</sup><br />
= 5.7 <span class="math-tex">{tex}\\times {/tex}</span> 6.16 <span class="math-tex">{tex}\\times {/tex}</span> 10<sup>&minus;10</sup> <span class="math-tex">{tex}\\times {/tex}</span> 100<sup>4</sup>(5<sup>4&nbsp;</sup>&minus; 3<sup>4</sup>)Js<sup>&minus;1</sup><br />
= 5.7 <span class="math-tex">{tex}\\times {/tex}</span> 6.16 <span class="math-tex">{tex}\\times {/tex}</span> 10<sup>&minus;2</sup> <span class="math-tex">{tex}\\times {/tex}</span> 544Js<sup>&minus;1</sup><br />
<span class="math-tex">{tex}=\\frac{5.7 \\times 6.16 \\times 10^{-2} \\times 544}{4.2}{/tex}</span>&nbsp;= 45.48&nbsp;cal&nbsp;s<sup>-1</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define the terms</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>absorptive power,</li>
	<li>emissive power and</li>
	<li>emissivity.</li>
</ol>

<p>Write their SI units, if any.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Absorptive power:&nbsp;</strong>The absorptive power of a body for a given wavelength <span class="math-tex">{tex}\\lambda{/tex}</span> is defined as the ratio of amount of heat energy absorbed in a certain time to the total heat energy incident on it in the same time within a unit wavelength range around the wavelength <span class="math-tex">{tex}\\lambda{/tex}</span>. It is denoted by <span class="math-tex">{tex}a_{\\lambda}{/tex}</span>. A perfect black body absorbs all the heat radiations incident upon it. So its absorptive power is unity.<br />
If the radiant energy dQ in wavelength range <span class="math-tex">{tex}\\lambda{/tex}</span> and <span class="math-tex">{tex}\\lambda{/tex}</span>&nbsp;+ d <span class="math-tex">{tex}\\lambda{/tex}</span> is incident on a body of absorptive power <span class="math-tex">{tex}a_{\\lambda}{/tex}</span>, then amount of radiant energy absorbed by the body =<span class="math-tex">{tex}a_{\\lambda}{/tex}</span> dQ<br />
The absorptive power is a dimensionless quantity.<br />
<strong>Emissive power:</strong>&nbsp;The amount of heat energy radiated by a body per second depends upon</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the area of its surface,</li>
	<li>the temperature of its surface and</li>
	<li>the nature of its surface. The strength of emission is measured by a quantity called emissive power. The emissive power of a body at a given temperature and for a given wavelength <span class="math-tex">{tex}\\lambda{/tex}</span> is defined as the amount of radiant energy emitted per unit time per unit surface area of the body</li>
</ol>

<p>If heat radiation of wavelength range <span class="math-tex">{tex}\\lambda{/tex}</span> to <span class="math-tex">{tex}\\lambda{/tex}</span>&nbsp;+ d <span class="math-tex">{tex}\\lambda{/tex}</span> is incident on the surface of a body of emissive power <span class="math-tex">{tex}e_{2}{/tex}</span>, then the amount of radiant energy emitted per second per unit area =&nbsp;<span class="math-tex">{tex}e_{\\lambda} d \\lambda{/tex}</span><br />
The SI unit of emissive power is Js<sup>&minus;1</sup>&nbsp;m<sup>&minus;2 </sup>or Wm<sup>&minus;2</sup>.<br />
<strong>Emissivity:&nbsp;</strong>The emissivity of a body is defined as the ratio of the heat energy radiated per unit time per unit area by the given body to the amount of heat energy radiated per unit time per unit area by a perfect black body of the same temperature i.e., it is the ratio of the emissive power (e) of a body to the emissive power (E) of a black body at the same temperature. It is denoted by <span class="math-tex">{tex}\\varepsilon{/tex}</span>.<br />
Thus&nbsp;<span class="math-tex">{tex}\\varepsilon=\\frac{e}{\\varepsilon}{/tex}</span><br />
It is dimensionless quantity. Its value lies between 0 and 1. The emissivity of a perfect black body is 1. The emissivities of polished copper, polished aluminium and lamp black are 0.018, 0.05 and 0.95 respectively.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>When 0.45 kg of ice at 0<sup>o</sup>C is mixed with 0.9 kg of water at 55<sup>o</sup>C in a container, the resulting temperature is 10<sup>o</sup>C. Calculate the heat of fusion of ice. Specific heat capacity of water = 4186 J kg<sup>-1</sup> K<sup>-1</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>mass of ice (M<sub>i&nbsp;</sub>)&nbsp;= 0.45 kg, mass of water (M<sub>w&nbsp;</sub>)&nbsp;= 0.9 kg, initial temperature of ice T<sub>1</sub> = 0<sup>o</sup>C, initial temperature of water T<sub>2</sub> = 55<sup>o</sup>C, temperature of mixture T = 10<sup>o</sup>C&nbsp;and specific heat c<sub>w&nbsp;</sub>= 4186 J kg<sup>-1</sup> K<sup>-1</sup>.<br />
Let latent heat of fusion of ice be L<sub>f</sub>.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;heat&nbsp;absorbed by ice to melt at 0 <sup>o</sup>C =&nbsp;M<sub>i</sub> L<sub>f</sub> = 0.45 L<sub>f</sub>&nbsp; ........(1)<br />
Heat absorbed by molten water for rising in temperature = M<sub>i</sub> c<sub>w</sub> (T - T<sub>1</sub>)&nbsp;=&nbsp;<span class="math-tex">{tex}0.45 \\times 4186 \\times(10-0)=18837 J{/tex}</span>&nbsp; .....(2)<br />
and heat given by warm water while cooling =&nbsp;<span class="math-tex">{tex}M_{w} c_w\\left(T_{2}-T\\right){/tex}</span>=&nbsp;<span class="math-tex">{tex}0.9 \\times 4186 \\times(55-10){/tex}</span>=&nbsp;169533 J ......(3)<br />
According to the principle of calorimetery, Total heat gained = Total heat lost<br />
From equation (1), (2) and (3) we have,<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}0.45 L_{f}+18837{/tex}</span>&nbsp;= 169533&nbsp;<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}\\ L_{f}=\\frac{169533-18837}{0.45}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}3.35 \\times 10^{5} \\mathrm{J} \\mathrm{kg}^{-1}{/tex}</span><br />
So the heat of fusion of ice will be&nbsp;<span class="math-tex">{tex}3.35 \\times 10^{5} \\mathrm{J} \\mathrm{kg}^{-1}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The coefficient of volume expansion of glycerin is <span class="math-tex">{tex}49 \\times 10 ^ { - 5 } \\mathrm { K } ^ { - 1 }{/tex}</span>. What is the fractional change in its density for a 30 &deg;C rise in temperature?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Coefficient of volume expansion of glycerin, <span class="math-tex">{tex}\\alpha _ { V } = 49 \\times 10 ^ { - 5 } \\mathrm { K } ^ { - 1 }{/tex}</span><br />
Rise in temperature, <span class="math-tex">{tex}\\Delta T = 30 ^ { \\circ } \\mathrm { C }{/tex}</span><br />
Fractional change in its volume <span class="math-tex">{tex}= \\frac { \\Delta V } { V }{/tex}</span><br />
This change is related with the change in temperature as:<br />
<span class="math-tex">{tex}\\frac { \\Delta V } { V } = a _ { v } \\Delta T{/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow\\frac {V_{T_2} - V_{T_1}} {V_{T_1}} = {\\alpha _V} {\\Delta T}{/tex}</span>&nbsp;(<span class="math-tex">{tex}{V_T}_{_2}{/tex}</span>&nbsp;and <span class="math-tex">{tex}{V_T}_{_1}{/tex}</span>&nbsp;are the volumes of glycerin at absolute temperatures T<sub>2</sub>&nbsp;and T<sub>1</sub>&nbsp;respectively)<br />
<span class="math-tex">{tex}\\therefore V _ { T _ { 2 } } - V _ { T _ { 1 } } = {V _ { T _ { 1 }} \\times} \\alpha _ { v } \\Delta T{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\frac { m } { \\rho _ { T _ { 2 } } } - \\frac { m } { \\rho _ { T _ { 1 } } } = \\frac { m } { \\rho _ { T _ { 1 } } } \\times \\alpha _ { v } \\Delta T{/tex}</span>&nbsp;<br />
Where,<br />
m = Mass of glycerine<br />
<span class="math-tex">{tex}{ \\rho } _ { T _ { 1 } }{/tex}</span> = Initial density at T<sub>1</sub>&nbsp;when volume was&nbsp;<span class="math-tex">{tex}V_{T_1}{/tex}</span><br />
<span class="math-tex">{tex}\\rho _ { T _ { 2 } }{/tex}</span> = Final density at T<sub>2</sub>&nbsp;when volume becomes&nbsp;<span class="math-tex">{tex}V_{T_2}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\frac { \\rho _ { T _ { 1 } } - \\rho _ { T _ { 2 } } } { \\rho _ { T _ { 2 } } } = \\alpha_ { v } \\Delta T{/tex}</span><br />
Where,<br />
<span class="math-tex">{tex}\\frac { \\rho _ { T _ { 1} } - \\rho _ { T _ { 2 } } } { \\rho _ { T _ { 2 } } }{/tex}</span> = Fractional change in density<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> Fractional change in the density of glycerin <span class="math-tex">{tex}= 49 \\times 10 ^ { - 5 } \\times 30 = 1.47 \\times 10 ^ { - 2 }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>In an experiment on the specific heat of a metal, a 0.20 kg block of the metal at 150<sup>o</sup>C is dropped in a copper calorimeter (of water equivalent 0.025 kg) containing 150 cm<sup>3</sup> of water at 27<sup>o</sup>C. The final temperature is 40<sup>o</sup>C. Compute the specific heat of the metal. If heat losses to the surroundings are not negligible, is your answer greater or smaller than the actual value for specific heat of the metal?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given: Mass of metal, m<sub>1</sub>&nbsp;= 0.2 kg = 200 g<br />
The temperature of the metal block (T<sub>1</sub>) = 150<sup>o</sup>C<br />
The temperature of the calorimeter (T<sub>2</sub>) = 27<sup>o</sup>C<br />
The final temperature of the mixture (T) = 40<sup>o</sup>C<br />
The volume of water in the calorimeter = 150 cm<sup>3</sup><br />
Specific heat of water, S<sub>w</sub> = 4.186 J/g/<sup>o</sup>K<br />
Mass of water in calorimeter, m<sub>2</sub> = volume <span class="math-tex">{tex}\\times{/tex}</span> density&nbsp;<br />
= 150&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;1 = 150 g<br />
Water equivalent of calorimeter, w = 0.025 kg = 25 g<br />
Let S&nbsp;is the specific heat of the metal block.<br />
Heat loss by metal,&nbsp;∆Q<sub>1</sub> = m<sub>1</sub>S(T<sub>1</sub> - T)<br />
= 200&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;S&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(150 - 40)&nbsp;<br />
Now,&nbsp;<br />
Heat gained&nbsp;by calorimeter and water,<br />
∆Q<sub><span style="font-size: 10.8333px;">2</span></sub>&nbsp;= (m<sub>2</sub> + w)S<sub>w</sub>(T&nbsp;- T<sub>2</sub>)<br />
= (150 + 25)&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;4.186&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(40 - 27) = 175&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;4.186&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;13<br />
According&nbsp;to Calorimeter principle,<br />
∆Q<sub>1</sub>&nbsp;=&nbsp;∆Q<sub><span style="font-size: 10.8333px;">2</span></sub><br />
200&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;S&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(150 - 40)&nbsp;&nbsp;= 175&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;4.186&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;13<br />
Thus, S = 0.43&nbsp;J/g/<sup>o</sup>K<br />
If some heat is lost to the surroundings, then the value of C will be smaller than the actual value.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A 10 kW drilling machine is used to drill a bore in a small aluminium block of mass 8.0 kg. How much is the rise in temperature of the block in 2.5 minutes, assuming 50% of power is used up in heating the machine itself or lost to the surroundings. Specific heat of aluminium = 0.91 J g<sup>-1</sup> K<sup>-1</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Power of the drilling machine, P = 10 kW = <span class="math-tex">{tex}10 \\times 10 ^ { 3 }{/tex}</span> W =10<sup>4&nbsp;</sup>W<br />
Mass of the aluminum block, m= 8.0 kg = 8000 g<br />
Time, t = 2.5 min = 2.5 <span class="math-tex">{tex}\\times{/tex}</span> 60 = 150 s<br />
Specific heat of aluminium, c= 0.91 J g<sup>-1</sup>K<sup>-1</sup><br />
&nbsp;Let rise in the temperature of the block after drilling = <span class="math-tex">{tex}\\delta{/tex}</span>T<br />
Total energy of the drilling machine = <span class="math-tex">{tex}P\\;\\times\\;T{/tex}</span><br />
<span class="math-tex">{tex}= 10 \\times 10 ^ { 3 } \\times 150{/tex}</span>&nbsp;<span class="math-tex">{tex}= 1.5 \\times 10 ^ { 6 } J{/tex}</span></p>

<p>As only 50% of the energy is useful as per the question&nbsp;<br />
so useful energy , <span class="math-tex">{tex}\\Delta Q = \\frac { 50 } { 100 } \\times 1.5 \\times 10 ^ { 6 } = 7.5 \\times 10 ^ { 5 } J{/tex}</span><br />
But <span class="math-tex">{tex}\\Delta Q = m c \\Delta T{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\Delta T = \\frac { \\Delta Q } { m c }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 7.5 \\times 10 ^ { 5 } } { 8 \\times 10 ^ { 3 } \\times 0.91 }{/tex}</span>&nbsp; &nbsp;= 103&deg;C<br />
Therefore, temperature of block increases by 103<sup>0&nbsp;</sup>C in drilling for&nbsp;2.5 minutes.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A steel tape 1m long is correctly calibrated for a temperature of 27.0 &deg;C. The length of a steel rod measured by this tape is found to be 63.0 cm on a hot day when the temperature is 45.0 &deg;C. What is the actual length of the steel rod on that day? What is the length of the same steel rod on a day when the temperature is 27.0 &deg;C? Coefficient of linear expansion of steel = 1.20<span class="math-tex">{tex}\\times{/tex}</span>10<sup>-5</sup> K<sup>-1</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here,&nbsp;<br />
Length of steel tape at 27&deg;C (&nbsp;<span class="math-tex">{tex}L_0{/tex}</span>) = 1m or 100 cm&nbsp;<br />
temperature Change( ∆T) = 45&deg; - 27&deg; = 18&deg;C&nbsp;<br />
Coefficient of linear expansion of steel ( a) = 1.2 &times; 10<sup>-5</sup> /&deg;C&nbsp;<br />
Length of steel tape at 45&deg;C ,&nbsp;<br />
Use expansion formula,&nbsp;<br />
<span class="math-tex">{tex}L = L_o( 1 + a∆T){/tex}</span><br />
= 100( 1 + 1.2 &times; 10<sup>-5</sup> &times; 18)&nbsp;<br />
= 100 (1.000216)<br />
= 100.0216 cm&nbsp;<br />
So, length of 1 cm at 45&deg;C = 100.0216/100 = 1.000216 cm&nbsp;<br />
So, length of 63cm at 45&deg;C = 1.000216 &times; 63 = 63.0136 cm.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A <strong>thermacole</strong>&nbsp;icebox is a cheap and efficient method for storing small quantities of cooked food in summer in particular. A cubical icebox of side 30 cm has a thickness of 5.0 cm. If 4.0 kg of ice is put in the box, estimate the amount of ice remaining after 6 h. The outside temperature is 45<sup>o</sup>C, and co-efficient of thermal conductivity of thermacole is 0.01 J s<sup>-1</sup>m<sup>-1</sup>K<sup>-1</sup>. [Heat of fusion of water&nbsp;= 335 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;J kg<sup>-1</sup>]</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Side of the given cubical ice box is given by, s = 30 cm = 0.3 m<br />
Thickness of the ice box is given by, <span class="math-tex">{tex}l{/tex}</span>&nbsp;= 5.0 cm = 0.05 m<br />
Mass of ice kept in the ice box is given by, m = 4 kg<br />
Time gap, t = 6 h <span class="math-tex">{tex}= 6 \\times 60 \\times 60 s{/tex}</span><br />
Outside temperature is given by, T<sub>1</sub>= 45&deg;C<br />
Inside temperature, T<sub>2</sub>&nbsp;= temperature of ice = 0℃<br />
Coefficient of thermal conductivity of thermacole is given by, K = 0.01 J s<sup>-1</sup>m<sup>-1</sup>K<sup>-1</sup><br />
Latent heat of fusion of water is given by, <span class="math-tex">{tex}L = 335 \\times 10 ^ { 3 } J \\mathrm { kg } ^ { - 1 }{/tex}</span><br />
Let m&#39; be the total amount of ice that melts in 6 h.<br />
Total amount of heat lost,&nbsp;<span class="math-tex">{tex}\\theta {/tex}</span> in 6 hours&nbsp;by the food(mathematical form of the equation comes from the definition of the thermal conductivity):<br />
<span class="math-tex">{tex}\\theta = \\frac { K A ( T_1 - T_2 ) t } { l }{/tex}</span><br />
Where,<br />
A= Total surface area of the box = 6 &times; Surface area of each surface of the box=&nbsp;<span class="math-tex">{tex}6 s ^ { 2 } = 6 \\times ( 0.3 ) ^ { 2 } = 0.54 \\mathrm { m } ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\theta = \\frac { 0.01 \\times 0.54 \\times ( 45 ) \\times 6 \\times 60 \\times 60 } { 0.05 } = 104976 J{/tex}</span><br />
But <span class="math-tex">{tex}\\theta = m ^ { \\prime } L{/tex}</span>, from the definition of latent heat of melting of ice.<br />
<span class="math-tex">{tex}\\therefore m ^ { \\prime } = \\frac { \\theta } { L }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 104976 } { 335 \\times 10 ^ { 3 } } = 0.313 \\mathrm { kg }{/tex}</span><br />
Mass of ice left is given by&nbsp;&nbsp;= Mass of ice initially kept inside the box - Mass of ice melted in 6hrs = 4 - 0.313 = 3.687 kg<br />
Hence, the amount of ice remaining after 6 h is 3.687 kg.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The sun is a black body of surface temperature about 6000 K. If the sun&#39;s radius is 7 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>8</sup> m, calculate the energy per second radiated from its surface. Given that Stefan&#39;s constant&nbsp;<span class="math-tex">{tex}\\sigma=5.67 \\times 10^{-8} \\mathrm{W} \\mathrm{m}^{-2} \\mathrm{K}^{-4}{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>As per question surface temperature of sun T = 6000 K, the radius of sun R = 7 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>8</sup> m and stefen&#39;s constant,&nbsp;<span class="math-tex">{tex}\\sigma=5.67\\times10^{-8}Wm^{-2}K^{-4}{/tex}</span><br />
According to Stefen&#39;s law, energy is given as<br />
E =&nbsp;<span class="math-tex">{tex}A \\sigma T^{4}{/tex}</span>&nbsp;<br />
=&nbsp;<span class="math-tex">{tex}4 \\pi R^{2} \\sigma T{/tex}</span><sup>4</sup><br />
=&nbsp;<span class="math-tex">{tex}4 \\times 3.14 \\times\\left(7 \\times 10^{8}\\right)^{2} \\times 5.67 \\times 10^{-8} \\times(6000)^{4}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}4.52 \\times 10^{26} \\mathrm {W}{/tex}</span><br />
&nbsp;The total&nbsp;energy radiated from the sun&#39;s surface per unit time is&nbsp;<span class="math-tex">{tex}4.52 \\times 10^{26} \\mathrm {W}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that the coefficient of volume expansion for a solid substance is three times its coefficient of linear expansion.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Consider a solid in the form of a rectangular parallelopiped of sides a, b, and c respectively <span class="math-tex">{tex}\\therefore{/tex}</span> its volume <span class="math-tex">{tex}V = abc{/tex}</span>.<br />
If the solid is heated so that its temperature rises by <span class="math-tex">{tex}\\Delta{/tex}</span>T, then increase in its sides will be&nbsp;<br />
<span class="math-tex">{tex}\\Delta a=a \\cdot \\alpha \\cdot \\Delta T{/tex}</span>,&nbsp;<span class="math-tex">{tex}\\Delta b=b \\cdot \\alpha \\cdot \\Delta T{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}\\Delta c=c \\cdot \\alpha \\cdot \\Delta T{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}a^{\\prime}=a+\\Delta a=a(1+\\alpha \\cdot \\Delta T){/tex}</span>,&nbsp;<span class="math-tex">{tex}b^{\\prime}=b+\\Delta b{/tex}</span>,&nbsp;<span class="math-tex">{tex}\\ b(1 + \\alpha . \\Delta T){/tex}</span>&nbsp;and c&#39; = c +&nbsp;<span class="math-tex">{tex}\\Delta c{/tex}</span>&nbsp;= c( 1 +&nbsp;<span class="math-tex">{tex}\\alpha . \\Delta T{/tex}</span>)<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;New volume <span class="math-tex">{tex}V' = V +{/tex}</span>&nbsp;<span class="math-tex">{tex}\\Delta V{/tex}</span><span class="math-tex">{tex} = a' b' c'  = abc(1 + {/tex}</span><span class="math-tex">{tex}\\alpha . \\Delta T{/tex}</span><span class="math-tex">{tex})^3{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Increase in volume&nbsp;<span class="math-tex">{tex}\\Delta V=V^{\\prime}-V{/tex}</span>=&nbsp;<span class="math-tex">{tex}\\left[a b c(1+\\alpha \\cdot \\Delta T)^{3}-a b c\\right]{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Coefficient of volume expansion&nbsp;<span class="math-tex">{tex}\\gamma=\\frac{\\Delta V}{V \\cdot \\Delta T}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{a b c(1+\\alpha \\cdot \\Delta T)^{3}-a b c}{a b c \\cdot \\Delta T}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\gamma=\\frac{(1+\\alpha \\cdot \\Delta T)^{3}-1}{\\Delta T}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{\\left(1+3 \\alpha \\cdot \\Delta T+3 \\alpha^{2} \\cdot \\Delta T^{2}+\\alpha^{3} \\cdot \\Delta T^{3}\\right)-1}{\\Delta T}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}3 \\alpha+3 \\alpha^{2} \\Delta T+\\alpha^{3} \\cdot \\Delta T^{2}{/tex}</span><br />
As we know that <span class="math-tex">{tex}\\alpha{/tex}</span> has an extremely small value for solids</p>

<p><span class="math-tex">{tex}\\therefore{/tex}</span><span class="math-tex">{tex}\\gamma=3 \\alpha{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow {/tex}</span> the coefficient of volume expansion of a solid is three times of its coefficient of linear expansion.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Give the Newton&#39;s law of cooling. Derive Newton&#39;s law of cooling using Stefan&#39;s law.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Newton&#39;s law of cooling&nbsp;states that the rate of heat loss of a body is directly proportional to the difference in the temperatures between the body and its surroundings.&nbsp;<br />
Newton&#39;s law of cooling can be obtained from Stefan&#39;s law as given below:<br />
If a hot body of surface area A is maintained at a temperature T and the surroundings be at temperature T<sub>o</sub>, then, as per Stefan&#39;s law, energy radiated by the hot body per unit surface area per unit time is<br />
<span class="math-tex">{tex}E=\\sigma\\left(T^{4}-T_{0}^{4}\\right){/tex}</span>where <span class="math-tex">{tex}\\sigma{/tex}</span>&nbsp;is Stefan&#39;s constant<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;The total rate of loss of heat energy is given by<br />
<span class="math-tex">{tex}-\\frac{d Q}{d t}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}E A=\\sigma A\\left(T^{4}-T_{0}^{4}\\right){/tex}</span><br />
Let T = T<sub>0</sub>&nbsp;+ <span class="math-tex">{tex}\\Delta{/tex}</span>T, where <span class="math-tex">{tex}\\Delta{/tex}</span>T is small as compared to T<sub>0</sub>, then<br />
<span class="math-tex">{tex}-\\frac{d Q}{d t}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\sigma A\\left[{(T_o+\\triangle T)}^4-T_o^4\\right]{/tex}</span><br />
<span class="math-tex">{tex}-\\frac{d Q}{d t}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\sigma A T_{0}^{4}\\left[(1+\\frac{\\Delta T}{T_{0}})^4-1\\right]{/tex}</span><br />
<span class="math-tex">{tex}-\\frac{d Q}{d t}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\sigma A T_{0}^{4}\\left[1+4 \\cdot \\frac{\\Delta T}{T_{0}}-1\\right]{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}4 \\sigma A T_{0}^{3} \\cdot \\Delta T{/tex}</span><br />
As <span class="math-tex">{tex}4 \\sigma A T_{0}^{3}{/tex}</span> is a constant quantity (say k), we can write the above relation as :-<br />
<span class="math-tex">{tex}-\\frac{d Q}{d t}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}k . \\Delta T{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}-\\frac{d Q}{d t}{/tex}</span>&nbsp;= k(T -T<sub>0</sub>)<br />
which states Newton&#39;s law of cooling.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two rods of the same area of cross-section, but of lengths l<sub>1</sub> and l<sub>2</sub> and conductivities K<sub>1</sub> and K<sub>2</sub> are joined in series. Show that&nbsp;the combination is equivalent of a material of conductivity&nbsp;<span class="math-tex">{tex}{\\text{K}}\\,{\\text{ = }}\\,\\frac{{{{\\text{l}}_{\\text{1}}}\\,{\\text{ + }}\\,{{\\text{l}}_{\\text{2}}}}}{{\\left( {\\frac{{{{\\text{l}}_{\\text{1}}}}}{{{{\\text{K}}_{\\text{1}}}}}} \\right)\\,\\left( {\\frac{{{{\\text{l}}_{\\text{2}}}}}{{{{\\text{K}}_{\\text{2}}}}}} \\right)}}{/tex}</span></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>It is given conductivities <span class="math-tex">{tex}K_1\\ and\\ K_2{/tex}</span> are in series, Therefore rate of flow of heat energy is same.<br/>
<img alt="" data-imgur-src="1c6evVc.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1c6evVc.png" style="width: 200px; height: 65px;"/><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> (<span class="math-tex">{tex}\\theta{/tex}</span><sub>1</sub> - <span class="math-tex">{tex}\\theta{/tex}</span>) + (<span class="math-tex">{tex}\\theta{/tex}</span> - <span class="math-tex">{tex}\\theta{/tex}</span><sub>2</sub>) = (<span class="math-tex">{tex}\\theta{/tex}</span><sub>1</sub> - <span class="math-tex">{tex}\\theta{/tex}</span><sub>2</sub>)<br/>
i,e. <span class="math-tex">{tex}\\frac{\\theta}{t}{/tex}</span><span class="math-tex">{tex}\\frac{l_1}{K_1 A}+ \\frac{\\theta}{t} \\frac{l_2}{K_2 A}= \\frac{\\theta}{t}. \\frac{(l_1 + l_2)}{K_eq A}{/tex}</span><br/>
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex}\\frac{l_1}{K_1} + \\frac{l_2}{K_2} = \\frac{l_1 + l_2}{K_{eq}}{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> <span class="math-tex">{tex}K_{eq} ={/tex}</span> <span class="math-tex">{tex}\\frac{{{{\\text{l}}_{\\text{1}}}{\\text{ + }}{{\\text{l}}_{\\text{2}}}}}{{\\left( {\\frac{{{{\\text{l}}_{\\text{1}}}}}{{{{\\text{K}}_{\\text{1}}}}}{\\text{ + }}\\frac{{{{\\text{l}}_{\\text{2}}}}}{{{{\\text{K}}_{\\text{2}}}}}} \\right)}}{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Develop a relation between the co-efficient of linear expansion, co-efficient superficial expansion and coefficient of cubical expansion of a solid.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Since, co-efficient of linear expansion,&nbsp;<span class="math-tex">{tex}\\alpha{/tex}</span> = <span class="math-tex">{tex}\\frac { \\Delta L } { L \\Delta T }{/tex}</span><br />
<span class="math-tex">{tex}\\Delta L{/tex}</span> = change in length<br />
L = length<br />
<span class="math-tex">{tex}\\Delta T{/tex}</span> = change in temperature, for an infinitesimally small change in temperature&nbsp;<br />
<span class="math-tex">{tex}\\alpha = \\frac{dL}{LdT}{/tex}</span><br />
Similarly, co-efficient of superficial expansion,&nbsp;<span class="math-tex">{tex}\\beta{/tex}</span> = <span class="math-tex">{tex}\\frac {d S } { S dT }{/tex}</span><br />
dS = infinitesimal change in area<br />
S = original area<br />
dT = infintesimaly change in temperature<br />
S = L<sup>2</sup>,<sup>&nbsp;</sup><span class="math-tex">{tex}\\beta= \\frac{1}{L^2}\\frac{dL^2}{dT} = 2L\\frac{dL}{dT}{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\beta = 2\\alpha{/tex}</span>&nbsp;<br />
Similarly, co-efficient of cubical expansion,&nbsp;<span class="math-tex">{tex}\\gamma = \\frac {dV}{VdT}{/tex}</span><br />
dV = infinitesimal change in volume<br />
V = original volume<br />
dT = infinitesimal change in temperature<br />
<span class="math-tex">{tex}\\gamma = \\frac{1}{L^3}\\frac{dL^3}{dT} = 3\\frac{1}{L}\\frac{dL}{dT} =3\\alpha{/tex}</span><br />
<span class="math-tex">{tex}\\alpha = \\frac { \\beta } { 2 } = \\frac { \\gamma } { 3 }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A hole is drilled in a copper sheet. The diameter of the hole is 4.24 cm at 27.0 &deg;C. What is the change in the diameter of the hole when the sheet is heated to 227 &deg;C? Coefficient of linear expansion of copper <span class="math-tex">{tex}= 1.70 \\times 10 ^ { - 5 } \\mathrm { K } ^ { - 1 }{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Initial temperature, T<sub>1</sub>&nbsp; = 27.0&deg;C<br />
Diameter of the hole at temperature T<sub>1 </sub>&nbsp;= d<sub>1</sub> = 4.24 cm<br />
Final temperature, T<sub>2</sub> = 227&deg;C<br />
Diameter of the hole at temperature T<sub>2</sub> = d<sub>2</sub><br />
Co-efficient of linear expansion of copper, <span class="math-tex">{tex}\\alpha _ { C u } = 1.70 \\times 10 ^ { - 5 } K ^ { - 1 }{/tex}</span><br />
By using superficial expansion relation<br />
<span class="math-tex">{tex}\\frac { \\text { Changein area } ( \\Delta A ) } { \\text { Original area } ( A ) } = \\beta { \\Delta } T{/tex}</span>&nbsp; &nbsp;---(1)<br />
<span class="math-tex">{tex}\\frac { \\left( \\pi \\frac { d _ { 2 } ^ { 2 } } { 4 } - \\pi \\frac { d _ { 1 } ^ { 2 } } { 4 } \\right) } { \\left( \\pi \\frac { d _ { 1 } ^ { 2 } } { 4 } \\right) } = \\frac { \\Delta A } { A }{/tex}</span>&nbsp; &nbsp; &nbsp; &nbsp; .....(2)<br />
<span class="math-tex">{tex}\\therefore \\frac { \\Delta A } { A } = \\frac { d _ { 2 } ^ { 2 } - d _ { 1 } ^ { 2 } } { d _ { 1 } ^ { 2 } }{/tex}</span></p>

<p>from (1) and (2)<br />
<br />
<span class="math-tex">{tex}\\frac{d_2^2-d_1^2}{d_1^2}=\\beta\\triangle T{/tex}</span>&nbsp; &nbsp; ........(3)</p>

<p>Using&nbsp;<span class="math-tex">{tex}\\beta=2\\alpha{/tex}</span>&nbsp;in equation (3)<br />
<span class="math-tex">{tex}\\frac { d _ { 2 } ^ { 2 } } { d _ { 1 } ^ { 2 } } - 1 = 2 a \\left( T _ { 2 } - T _ { 1 } \\right){/tex}</span><br />
<span class="math-tex">{tex}\\frac { d _ { 2 } ^ { 2 } } { d ( 4.24 ) ^ { 2 } } = 2 \\times 1.7 \\times 10 ^ { - 5 } ( 227 - 27 ) + 1{/tex}</span><br />
<span class="math-tex">{tex}d _ { 2 } ^ { 2 } = 17.98 \\times 1.0068 = 18.1{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span> d<sub>2</sub> = 4.2544 cm<br />
Change in diameter = d<sub>2</sub> - d<sub>1</sub> = 4.2544 - 4.24 = 0.0144 cm<br />
Hence, the increase in diametre&nbsp; =&nbsp;<span class="math-tex">{tex}1.44 \\times 10 ^ { - 2 }{/tex}</span> cm.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A large steel wheel is to be fitted on to a shaft of the same material. At 27 &deg;C, the outer diameter of the shaft is 8.70 cm and the diameter of the central hole in the wheel is 8.69 cm. The shaft is cooled using &#39;dry ice&#39;. At what temperature of the shaft does the wheel slip on the shaft? Assume the coefficient of linear expansion of the steel to be constant over the required temperature range:<span class="math-tex">{tex}\\alpha _ { \\mathrm { steel } } = 1.20 \\times 10 ^ { - 5 } \\mathrm { K } ^ { - 1 }{/tex}</span></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The given temperature is, T = 27&deg;C = 27 + 273 = 300 K<br />
Outer diameter of the steel shaft at temperature&nbsp;&nbsp;T&nbsp; is =&nbsp;d<sub>1</sub> = 8.70 cm<br />
The diameter of the hole in the wheel at centre, at temperature&nbsp;T is = d<sub>2</sub> = 8.69 cm<br />
Coefficient of linear expansion of steel is given by&nbsp; =&nbsp;<span class="math-tex">{tex}\\alpha _ { \\mathrm { steel } } = 1.20 \\times 10 ^ { - 5 } \\mathrm { K } ^ { - 1 }{/tex}</span><br />
Let after cooling the shaft its temp. gets T<sub>1.</sub><br />
change in diameter of the hole is given by, <span class="math-tex">{tex}\\Delta{/tex}</span>d = 8.69 - 8.70<br />
= - 0.01 cm<br />
by using the relation, we get<br />
<span class="math-tex">{tex}\\Delta d = d _ { 1 } \\alpha _ { steel } \\left( T _ { 1 } - T \\right){/tex}</span><br />
-0.01 = <span class="math-tex">{tex}8.70 \\times 1.20 \\times 10 ^ { - 5 } {/tex}</span>(T<sub>1</sub> - 300)<br />
(T<sub>1</sub> - 300) = -95.78<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> T<sub>1</sub>&nbsp; = 204.21 K<br />
= 204.21 - 273.16 = -68.95&deg;C<br />
Therefore, if temperature of the shaft is -69<sup>0&nbsp;</sup>C, wheel will slip on the shaft.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>An iron bar (L<sub>1</sub> = 0.1 m, A<sub>1</sub> = 0.02 m<sup>2</sup>, K<sub>1</sub> = 79 W m<sup>-1</sup> K<sup>-1</sup>) and a brass bar (L<sub>2</sub> = 0.1 m, A<sub>2</sub> = 0.02 m<sup>2</sup>, K<sub>2</sub> = 109 W m<sup>-1</sup>K<sup>-1</sup>) are soldered end to end as shown in Figure. The free ends of the iron bar and brass bar are maintained at 373 K and 273 K respectively. Obtain expressions for and hence compute<br/>
<img alt="" data-imgur-src="VdaKgDV.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614338830-dgjd8m.jpg" style="width: 300px; height: 66px;"/></p>
<ol start="1" style="list-style-type: lower-alpha;">
<li>the temperature of the junction of the two bars</li>
<li>the equivalent thermal conductivity of the compound bar, and</li>
<li>the heat current through the compound bar</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given,&nbsp;L<sub>1</sub> = L<sub>2</sub>= L = 0.1 m, A<sub>1</sub> = A<sub>2&nbsp;</sub>= A = 0.02 m<sup>2</sup><br />
K<sub>1</sub> = 79 W m<sup>-1</sup> K<sup>-1</sup>, K<sub>2</sub> = 10<sup>9</sup> W m<sup>-1</sup> K<sup>-1</sup>,<br />
T<sub>1</sub> = 373 K, and T<sub>2</sub> = 273 K.<br />
Under the steady-state conditions, the heat current (H<sub>1</sub>) through the iron bar is equal to the heat current (H<sub>2</sub>) through the brass bar.<br />
So, H = H<br />
<span class="math-tex">{tex}=\\frac{K_{1} A_{1}\\left(T_{1}-T_{0}\\right)}{L_{1}}=\\frac{K_{2} A_{2}\\left(T_{0}-T_{2}\\right)}{L_{2}}{/tex}</span><br />
For A<sub>1</sub> = A<sub>2</sub> = A and L<sub>1</sub> = L<sub>2</sub> = L, this equation<br />
leads to<br />
K<sub>1</sub> (T<sub>1</sub>&nbsp;-&nbsp;T<sub>0</sub>) = K<sub>2</sub> (T<sub>0</sub>&nbsp;-&nbsp;T<sub>2</sub>)<br />
Thus, the junction temperature T0 of the two bars is<br />
<span class="math-tex">{tex}T_{0}=\\frac{\\left(K_{1} T_{1}+K_{2} T_{2}\\right)}{\\left(K_{1}+K_{2}\\right)}{/tex}</span><br />
Using this equation, the heat current H through either bar is<br />
<span class="math-tex">{tex}H=\\frac{K_{1} A\\left(T_{1}-T_{0}\\right)}{L}=\\frac{K_{2} A\\left(T_{0}-T_{2}\\right)}{L}{/tex}</span><br />
<span class="math-tex">{tex}K^{\\prime}=\\frac{2 K_{1} K_{2}}{K_{1}+K_{2}}{/tex}</span></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li><span class="math-tex">{tex}T_{0}=\\frac{\\left(K_{1} T_{1}+K_{2} T_{2}\\right)}{\\left(K_{1}+K_{2}\\right)}{/tex}</span><br />
	<span class="math-tex">{tex}=\\frac{\\left(79 W \\mathrm{m}^{-1} \\mathrm{K}^{-1}\\right)(373 \\mathrm{K})+\\left(109 \\mathrm{W} \\mathrm{m}^{-1} \\mathrm{K}^{-1}\\right)(273 \\mathrm{K})}{79 \\mathrm{W} \\mathrm{m}^{-1} \\mathrm{K}^{-1}+109 \\mathrm{W} \\mathrm{m}^{-1} \\mathrm{K}^{-1}}{/tex}</span><br />
	= 315 K</li>
	<li><span class="math-tex">{tex}K^{\\prime}=\\frac{2 K_{1} K_{2}}{K_{1}+K_{2}}{/tex}</span><br />
	<span class="math-tex">{tex}=\\frac{2 \\times\\left(79 \\mathrm{W} \\mathrm{m}^{-1} \\mathrm{K}^{-1}\\right) \\times\\left(109 \\mathrm{W} \\mathrm{m}^{-1} \\mathrm{K}^{-1}\\right)}{79 \\mathrm{W} \\mathrm{m}^{-1} \\mathrm{K}^{-1}+109 \\mathrm{W} \\mathrm{m}^{-1} \\mathrm{K}^{-1}}{/tex}</span><br />
	= 91.6 W m<sup>-1</sup>K<sup>-1</sup></li>
	<li><span class="math-tex">{tex}H^{\\prime}=H=\\frac{K^{\\prime} A\\left(T_{1}-T_{2}\\right)}{2 L}{/tex}</span><br />
	<span class="math-tex">{tex}=\\frac{\\left(91.6 \\mathrm{W} \\mathrm{m}^{-1} \\mathrm{K}^{-1}\\right) \\times\\left(0.02 \\mathrm{m}^{2}\\right) \\times(373 \\mathrm{K}-273 \\mathrm{K})}{2 \\times(0.1 \\mathrm{m})}{/tex}</span><br />
	= 916.1 W</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Calculate the heat required to convert 3 kg of ice at -12&deg;C kept in a calorimeter to steam at 100 &deg;C at atmospheric pressure. Given specific heat capacity of ice = 2100 J kg<sup>-1</sup>K<sup>-1</sup>, specific heat capacity of water = 4186 J kg<sup>-1</sup> K<sup>-1</sup>, latent heat of fusion of ice = 3.35 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup> J kg<sup>-1</sup> and latent heat of steam = 2.256 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup> J kg<sup>-1</sup></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>We have<br />
Mass of the ice, m = 3 kg<br />
specific heat capacity of ice, s<sub>ice</sub><br />
= 2100 J kg<sup>-1</sup> K<sup>-1</sup><br />
specific heat capacity of water, swater<br />
= 4186 J kg<sup>-1</sup> K<sup>-1</sup><br />
latent heat of fusion of ice, L<sub>f ice</sub><br />
= 3.35 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup> J kg<sup>-1</sup><br />
latent heat of steam, L<sub>steam</sub><br />
= 2.256 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup> J kg<sup>-1</sup><br />
Now, Q = heat required to convert 3kg of ice at -12<sup>o</sup>C to steam at 100<sup>o</sup>C,<br />
Q<sub>1</sub> = heat required to convert ice at -12 &deg;C to ice at 0 &deg;C.<br />
= m s<sub>ice</sub> <span class="math-tex">{tex}\\Delta{/tex}</span>T<sub>1</sub> = (3 kg) (2100 J kg<sup>-1&nbsp;</sup>K<sup>-1</sup>) [0-(-12)]&deg;C = 75600 J<br />
Q<sub>2</sub> = heat required to melt ice at 0&deg;C to water at 0&deg;C<br />
= mL<sub>f ice</sub> = (3 kg) (3.35 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup> J kg<sup>-1</sup>)<br />
= 1005000 J<br />
Q<sub>3</sub> = heat required to convert water at 0&deg;C to water at 100&deg;C.<br />
= ms<sub>w</sub> <span class="math-tex">{tex}\\Delta{/tex}</span>T<sub>2</sub> = (3kg) (4186J kg<sup>-1</sup> K<sup>-1</sup>)(100&deg;C)<br />
= 1255800 J<br />
Q<sub>4</sub> = heat required to convert water at 100 &deg;C to steam at 100 &deg;C.<br />
= m L<sub>steam</sub> = (3 kg) (2.256 &times; 10<sup>6</sup> Jkg<sup>-1</sup>)<br />
= 6768000 J<br />
So, Q = Q<sub>1</sub> + Q<sub>2</sub> + Q<sub>3</sub> + Q<sub>4</sub><br />
= 75600J + 1005000 J + 1255800 J + 6768000 J<br />
= 9.1&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>J</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Show that the coefficient of area expansion, <span class="math-tex">{tex}\\frac {\\frac {\\Delta A}{A}}{\\Delta T}{/tex}</span>, of a rectangular sheet of the solid is twice its linear expansivity, <span class="math-tex">{tex}\\alpha_1{/tex}</span>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img alt="" data-imgur-src="Qtn6e2p.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614338817-fq6v5k.jpg" style="width: 250px; height: 163px;"/><br/>
Consider a rectangular sheet of the solid material of length a and breadth b (Figure).<br/>
When the temperature increases by <span class="math-tex">{tex}\\Delta T{/tex}</span>, 'a' increases by <span class="math-tex">{tex}\\Delta a=\\alpha_{1} a \\Delta T{/tex}</span> and b increases by <span class="math-tex">{tex}\\Delta b = \\alpha_1 b \\ \\Delta T{/tex}</span><br/>
From Figure, the increase in area<br/>
<span class="math-tex">{tex}\\Delta A=\\Delta A_{1}+\\Delta A_{2}+\\Delta A_{3}{/tex}</span><br/>
<span class="math-tex">{tex}\\Delta A=a \\Delta b+b \\Delta a+(\\Delta a)(\\Delta b){/tex}</span><br/>
<span class="math-tex">{tex}=a \\alpha_{1} b \\Delta T+b \\alpha_{1} a \\Delta T{/tex}</span><span class="math-tex">{tex}+\\left(\\alpha_{1}\\right)^{2} a b(\\Delta T)^{2}{/tex}</span><br/>
<span class="math-tex">{tex}=\\alpha_{1} a b \\Delta T\\left(2+\\alpha_{1} \\Delta T\\right){/tex}</span><span class="math-tex">{tex}=\\alpha_{1} A \\Delta T\\left(2+\\alpha_{1} \\Delta T\\right){/tex}</span><br/>
Since <span class="math-tex">{tex}\\alpha_{1} \\simeq 10^{-5} \\mathrm{K}^{-1}{/tex}</span>, from Table the product <span class="math-tex">{tex}\\alpha_1 \\Delta T{/tex}</span> for fractional temperature is small in comparison with 2 and may be neglected.</p>
<table border="1" cellpadding="3" cellspacing="0" style="width:100%;">
<thead>
<tr>
<th scope="col">Material</th>
<th scope="col"><span class="math-tex">{tex}\\alpha_1 (10^{-5} K^{-1}){/tex}</span></th>
</tr>
</thead>
<tbody>
<tr>
<td>Aluminium</td>
<td style="text-align: center;">2.5</td>
</tr>
<tr>
<td>Brass</td>
<td style="text-align: center;">1.8</td>
</tr>
<tr>
<td>Iron</td>
<td style="text-align: center;">1.2</td>
</tr>
<tr>
<td>Copper</td>
<td style="text-align: center;">1.7</td>
</tr>
<tr>
<td>Silver</td>
<td style="text-align: center;">1.9</td>
</tr>
<tr>
<td>Gold</td>
<td style="text-align: center;">1.4</td>
</tr>
<tr>
<td>Glass (pyrex)</td>
<td style="text-align: center;">0.32</td>
</tr>
<tr>
<td>Lead</td>
<td style="text-align: center;">0.29</td>
</tr>
</tbody>
</table>
<p>Hence,<br/>
<span class="math-tex">{tex}\\left(\\frac{\\Delta A}{A}\\right) \\frac{1}{\\Delta T} \\simeq 2 \\alpha_{l}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is meant by coefficient of linear expansion, superficial expansion and cubical expansion? Derive the relationship between them.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Coefficient of Linear Expansion is the rate of change of unit length per unit degree change in temperature.<br />
The ratio of increase in the area of the body per degree rise in temperature to its unit area is called the coefficient of superficial expansion.<br />
The coefficient of cubical expansion is the increase in volume per unit original volume per unit rise in temperature.<br />
<span class="math-tex">{tex}\\Delta S{/tex}</span> = change in area<br />
S = original area<br />
<span class="math-tex">{tex}\\Delta T{/tex}</span> = change in temperature<br />
Co-efficient of cubical expansion, = Y <span class="math-tex">{tex}=\\frac{\\Delta V}{V \\Delta T}{/tex}</span><br />
<span class="math-tex">{tex}\\Delta V{/tex}</span> = change in volume<br />
V = original volume<br />
<span class="math-tex">{tex}\\Delta T{/tex}</span> = change in temperature.<br />
Now, <span class="math-tex">{tex}\\Delta{/tex}</span>L = <span class="math-tex">{tex}\\alpha{/tex}</span>L<span class="math-tex">{tex}\\Delta{/tex}</span>T<br />
L + <span class="math-tex">{tex}\\Delta L{/tex}</span> = L + <span class="math-tex">{tex}\\alpha L{/tex}</span> <span class="math-tex">{tex}\\Delta T{/tex}</span><br />
L + <span class="math-tex">{tex}\\Delta L{/tex}</span> = L(1 + <span class="math-tex">{tex}\\alpha \\Delta T{/tex}</span>) <span class="math-tex">{tex}\\rightarrow{/tex}</span> (i)<br />
Similarly V + <span class="math-tex">{tex}\\Delta V{/tex}</span> = V(1 + Y<span class="math-tex">{tex}\\Delta T{/tex}</span>) <span class="math-tex">{tex}\\rightarrow{/tex}</span> (ii)<br />
And S + <span class="math-tex">{tex}\\Delta{/tex}</span>S = S(1 + <span class="math-tex">{tex}\\beta \\Delta T{/tex}</span>) <span class="math-tex">{tex}\\rightarrow{/tex}</span> (iii)<br />
Also, (V + <span class="math-tex">{tex}\\Delta V{/tex}</span>) = (L + <span class="math-tex">{tex}\\Delta{/tex}</span>L)<sup>3</sup><br />
V + <span class="math-tex">{tex}\\Delta V{/tex}</span> = [L(1 + <span class="math-tex">{tex}\\alpha{/tex}</span><span class="math-tex">{tex}\\Delta{/tex}</span>T)]<sup>3</sup><br />
<span class="math-tex">{tex}\\mathrm{V}+\\Delta \\mathrm{V}=\\mathrm{L}^3\\left(1+3 \\alpha \\Delta T+3 \\alpha^2 \\Delta T^2+\\alpha^3 T^3\\right){/tex}</span><br />
Since <span class="math-tex">{tex}\\alpha^2{/tex}</span>, <span class="math-tex">{tex}\\alpha^3{/tex}</span> are negligible, so,<br />
V + <span class="math-tex">{tex}\\gamma{/tex}</span> V<span class="math-tex">{tex}\\Delta{/tex}</span>T = V(1 + 3<span class="math-tex">{tex}\\alpha{/tex}</span><span class="math-tex">{tex}\\Delta{/tex}</span>T)[as L<sup>3</sup> = V]<br />
So, V + <span class="math-tex">{tex}\\gamma{/tex}</span> V<span class="math-tex">{tex}\\Delta{/tex}</span>T = V + V3<span class="math-tex">{tex}\\alpha{/tex}</span><span class="math-tex">{tex}\\Delta{/tex}</span>T<br />
<span class="math-tex">{tex}\\gamma{/tex}</span> V<span class="math-tex">{tex}\\Delta{/tex}</span>T = 3<span class="math-tex">{tex}\\alpha{/tex}</span><span class="math-tex">{tex}\\Delta{/tex}</span>T<br />
Y = 3<span class="math-tex">{tex}\\alpha{/tex}</span><br />
Similarly, <span class="math-tex">{tex}\\beta{/tex}</span> = 2<span class="math-tex">{tex}\\alpha{/tex}</span> [using L<sup>2</sup> = S (Area)]<br />
So, <span class="math-tex">{tex}\\alpha=\\frac{\\beta}{2}=\\frac{\\gamma}{3}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State:</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>Stefan&#39;s law and</li>
	<li>Wein&#39;s displacement law.</li>
</ol>

<p>How you will derive Newton&#39;s law of cooling from Stefan&#39;s law?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>The law states that, &ldquo;The total energy emitted/radiated per unit surface area of a blackbody across all wavelengths per unit time is directly proportional to the fourth power of the black body&#39;s thermodynamic temperature.</li>
	<li>Wien&#39;s law or Wien&#39;s displacement law, named after Wilhelm Wien, was derived in the year 1893 which states that black body radiation has different peaks of temperature at wavelengths that are inversely proportional to temperatures.</li>
</ol>

<p>Consider a hot body with a temperature T<sub>1</sub> placed in a uniform temperature encloser with temperature T<sub>2</sub>.<br />
According to Stefan&#39;s law.<br />
E = <span class="math-tex">{tex}\\varepsilon \\sigma\\left(T_1{ }^4-T_2{ }^4\\right){/tex}</span><br />
where E = Tate of cooling<br />
<span class="math-tex">{tex}\\varepsilon{/tex}</span> = The emissivity of the surface of the hot body.<br />
E = <span class="math-tex">{tex}\\varepsilon \\sigma\\left(\\mathrm{T}_1-\\mathrm{T}_2\\right)\\left(\\mathrm{T}_1{ }^3+\\mathrm{T}_1{ }^2 \\mathrm{~T}_2+\\mathrm{T}_1 \\mathrm{~T}_2{ }^2+\\mathrm{T}_2{ }^3\\right){/tex}</span><br />
As (T<sub>1</sub> - T<sub>2</sub>) is small. T<sub>1</sub> can be taken approximately equal to T<sub>2</sub>.<br />
Then <span class="math-tex">{tex}\\mathrm{E}=\\varepsilon \\sigma\\left(\\mathrm{T}_1-\\mathrm{T}_2\\right)\\left(\\mathrm{T}_2{ }^3-2 \\mathrm{~T}_2{ }^3+\\mathrm{T}_2{ }^3\\right){/tex}</span><br />
E = <span class="math-tex">{tex}4 \\varepsilon \\sigma \\mathrm{T}_2{ }^3\\left(\\mathrm{~T}_1-\\mathrm{T}_2\\right){/tex}</span><br />
As <span class="math-tex">{tex}4 \\varepsilon \\sigma \\mathrm{T}_2{ }^3{/tex}</span> = constant<br />
E <span class="math-tex">{tex}\\propto{/tex}</span> (T<sub>1</sub> - T<sub>2</sub>)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1351-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_THERMODYNAMICS = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Choose the correct option.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Zeroth law gives the concept of temperature</li>
	<li>Temperature measures the &lsquo;hotness&rsquo; of the body</li>
	<li>Heat flows from higher temperature to lower temperature until thermal equilibrium is attained</li>
	<li>All of the above</li>
</ol></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Statement (i) is correct.</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Statement (ii) is correct.</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Statement (iii) is correct.</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">Statement (iv) is correct.</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1684129330-4ymvmb.jpg" style="width: 150px; height: 46px;" /><br />
Heat flows from body A to body B because temperature of body A is higher. At thermal equilibrium, T<sub>A</sub>&#39; = T<sub>B</sub>&#39;<br />
A in equilibrium with C, B in equilibrium with C <span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;A in equilibrium with B zeroth law.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><html><body><p>In P-V diagram shown below:<br/>
<img alt="" data-imgur-src="AekHGx2.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1676890154-fazn47.jpg" style="width: 150px; height: 149px;"/></p></body></html></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">AB represents adiabatic process</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">AB represents isothermal process</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">AB represents isobaric process</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">AB represents isochoric process</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>In the given diagram, the AB line is parallel to pressure axis and is constant for all volumes. Therefore, for the process AB, <span class="math-tex">{tex}\\Delta{/tex}</span>V = 0, i.e., it is an isochoric process, while BC represents an isobaric process.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>AB = isothermal, BC = isochoric, AC = adiabatic. Which of the graphs correctly represents them?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="zJ8d8f4.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1628509512-3c46d5.jpg" style="width: 100px; height: 103px;"/></p></body></html></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Adiabatic curve (AC)&nbsp;is steeper than isothermal curve (AB). Isochoric curve AB&nbsp;is a vertical line i.e., V = constant.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="PwuesMS.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1628509514-gdbf7y.jpg" style="width: 100px; height: 100px;"/></p></body></html></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="7ksnAvx.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1628509516-4zshy7.jpg" style="width: 100px; height: 96px;"/></p></body></html></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><html><body><p><img alt="" data-imgur-src="NLKKdWy.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1628509519-zx8g47.jpg" style="width: 100px; height: 92px;"/></p></body></html></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>For an adiabatic process,</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>S = 0</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>U = 0</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>Q = 0</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>In an adiabatic process, no heat is exchanged between the system and surroundings. Hence total heat of the system remains constant.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">W = 0</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><html><body><p>A system is taken from state A to B through three different paths 1, 2, 3. The work done is maximum in:<br/>
<img alt="" data-imgur-src="GaDPA8k.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1676890157-m7grq4.jpg" style="width: 200px; height: 172px;"/></p></body></html></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">process 1</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The work done can be calculated as the work done under the P-V curve.<br />
The area under the P-V curve is maximum for process 1 and is minimum for process 3.<br />
Therefore, work done is maximum for process 1.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">process 2</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">process 3</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">equal in all processes</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>First Law of Thermodynamics is based on the&nbsp; law of:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"> conservation of energy </p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The&nbsp;first law of thermodynamics&nbsp;is the application of the conservation of energy principle to heat and thermodynamic&nbsp;processes<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>Q =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U +&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"> conservation of mass </p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"> conservation of momentum </p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"> conservation of angular momentum </p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If C<sub>P</sub> and C<sub>V</sub> are molar heats at constant pressure and constant volume respectively and R is gas constant for 1 mole, then the correct relation is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">C<sub>p</sub> - C<sub>v</sub> = R</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The correct relation between molar heat at constant pressure and volume and R (gas constant) is C<sub>p</sub> - C<sub>v</sub> = R</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">C<sub>p</sub> - C<sub>v</sub> &lt; R</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">C<sub>p</sub> - C<sub>v</sub> &gt; R</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">C<sub>p</sub> - C<sub>v</sub> = 0</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>(<span class="math-tex">{tex}\\Delta{/tex}</span>Q -&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W) is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">path dependent</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">path independent</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">equal to <span class="math-tex">{tex}\\Delta{/tex}</span>U</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">Both path independent and equal to <span class="math-tex">{tex}\\Delta{/tex}</span>U</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Both path independent and equal to&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p><span class="math-tex">{tex}\\Delta{/tex}</span>U +&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W = 0 is valid for:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">adiabatic process</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>For an adiabatic process,&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>Q =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U +&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W = 0</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">isothermal process</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">isobaric process</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">isochoric process</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If two systems are in thermal equilibrium with each other, it means their</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">masses are equal, temperatures may be unequal</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">temperatures are equal</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>If two systems are in thermal equilibrium with each other, it means their temperatures must be same. Masses may be equal or unequal.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">masses and temperatures are equal</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">masses and temperatures are unequal</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A gas expands under constant pressure P from volume V<sub>1</sub> to V<sub>2</sub>. The work done by the gas is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">P(V<sub>2</sub> - V<sub>1</sub>)</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Work done during expansion, W = P<span class="math-tex">{tex}\\Delta{/tex}</span>V =&nbsp;P(V<sub>2</sub> - V<sub>1</sub>)</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">P(V<sub>1</sub> - V<sub>2</sub>)</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}P\\left(V_{1}^{\\gamma}-V_{2}^{\\gamma}\\right){/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}P\\left(\\frac{1}{V_{1}}-\\frac{1}{V_{2}}\\right){/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><html><body><p>In the following figures (1) to (4), variation of volume by change of pressure is shown. A gas is taken along the path ABCDA. The change in internal energy of the gas will be:<br/>
<img alt="" data-imgur-src="Tis67Xq.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1676890156-hsmvwx.jpg" style="width: 285px; height: 250px;"/></p></body></html></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">positive in all cases from (1) to (4) </p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">positive in cases (1), (2) and (3) but zero in case (4)</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">negative in cases (1), (2) and (3) but zero in case (4)</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">zero in all the four cases</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>In all given cases, process is cyclic and in cyclic process <span class="math-tex">{tex}\\Delta{/tex}</span>U = 0</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Universal gas constant is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{C_{P}}{C_{V}}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">C<sub>P</sub> - C<sub>V</sub></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Universal gas constant is C<sub>p</sub> + C<sub>v</sub>.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">C<sub>P</sub> + C<sub>V</sub></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{C_{V}}{C_{P}}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>We consider a thermodynamic system. If <span class="math-tex">{tex}\\Delta{/tex}</span>U&nbsp;represents the increase in its internal energy and W, the work done by the system; which of the following statements is true?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>U = -W in an isothermal process</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>U = W in an isothermal process</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>U = -W in an adiabatic process</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>In an adiabatic process,&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>Q = 0<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>Q -&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W = 0 -W = -W</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\Delta{/tex}</span>U = W in an adiabale process</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The increase in internal energy of a system is equal to the work done on the system. Which process does the system undergo?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Isochoric</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">Adiabatic</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As work done on a system is negative, so&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U = -&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W<br />
or&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U +&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W = 0<br />
or&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>Q = 0<br />
Hence the system undergoes an adiabatic process.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Isobaric</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Isothermal</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A thermodynamic system is taken from an original state to an intermediate state by the linear process shown in figure.<br />
<img alt="14159831808627.jpg" id="Picture 12" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncert/11/physics/ch11/image041.jpg" style="height: 145px; width: 150px;" /><br />
Its volume is then reduced to the original value from E to F by an isobaric process. Calculate the total work done by the gas from D to E to F.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Total work done by the gas from D to E to F = Area of &Delta;DEF<br />
Area of <span class="math-tex">{tex}\\Delta D E F = \\frac { 1 } { 2 } D E \\times E F{/tex}</span>&nbsp;<br />
Where,<br />
DF = Change in pressure<br />
<span class="math-tex">{tex}= 600 N / m ^ { 2 } - 300 N / m ^ { 2 }{/tex}</span>&nbsp;<br />
= 300 N/m<sup>2</sup><br />
FE = Change in volume<br />
= 5.0 m<sup>3</sup> - 2.0 m<sup>3</sup> = 3.0 m<sup>3</sup><br />
Area of <span class="math-tex">{tex}\\Delta D E F = \\frac { 1} { 2} \\times 300 \\times 3{/tex}</span> = 450 J<br />
Therefore, the total work done by the gas from D to E to F is 450 J.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>An electric heater supplies heat to a system at a rate of 100W. If system performs work at a rate of 75 Joules per second. At what rate is the internal energy increasing?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Heat is supplied to the system at a rate of 100 W.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> Heat supplied, Q = 100 J/s<br />
The system performs at a rate of 75 J/s.<br />
<span class="math-tex">{tex}\\therefore {/tex}</span> Work done, W = 75 J/s<br />
From the first law of thermodynamics, we have:<br />
Q = U + W<br />
Where,<br />
U = Internal energy<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> U = Q - W<br />
= 100 - 75<br />
= 25 J/s<br />
= 25 W<br />
Therefore, the internal energy of the given electric heater increases at a rate of 25 W.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Calculate the work done for adiabatic expansion of a gas.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Consider an ideal gas (say <span class="math-tex">{tex}\\mu{/tex}</span>&nbsp;mole), which is undergoing an adiabatic expansion. Let the gas expands by an infinitesimally small volume dV, at a constant pressure p, then the infinitesimally small work done given by<br />
dW = pdV<br />
The net work done from an initial volume V<sub>1</sub> to final volume V<sub>2</sub>&nbsp;of the gas is given by,<br />
<span class="math-tex">{tex}W = \\int _ { V _ { 1 } } ^ { V _ { 2 } } p d V{/tex}</span><br />
Now we know that for an adiabatic process,<br />
<span class="math-tex">{tex}p = \\frac { K } { V ^ { \\gamma } } = K V ^ { - \\gamma }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore W = \\int _ { V _ { 1 } } ^ { V _ { 2 } } \\left( K V ^ { - \\gamma } \\right) d V = K \\left[ \\frac { V ^ { - \\gamma + 1 } } { - \\gamma + 1 } \\right] _ { V _ { 1 } } ^ { V _ { 2 } }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { K V _ { 2 } ^ { - \\gamma + 1 } - K V _ { 1 } ^ { - \\gamma + 1 } } { ( 1 - \\gamma ) }{/tex}</span>&nbsp;.....(i)<br />
Now using the basic formula for an adiabatic process,<br />
<span class="math-tex">{tex}K = p _ { 1 } V _ { 1 } ^ { \\gamma } = p _ { 2 } V _ { 2 } ^ { \\gamma }{/tex}</span>, K being a constant, we get from equation (i)<br />
<span class="math-tex">{tex} \\quad W = \\frac { p _ { 2 } V _ { 2 } ^ { \\gamma } \\cdot V _ { 2 } ^ { - \\gamma + 1 } - p _ { 1 } V _ { 1 } ^ { \\gamma } \\cdot V _ { 2 } ^ { - \\gamma + 1 } } { ( 1 - \\gamma ) }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { ( 1 - \\gamma ) } \\left( p _ { 2 } V _ { 2 } - p _ { 1 } V _ { 1 } \\right){/tex}</span><br />
Now for an ideal gas,&nbsp;<span class="math-tex">{tex}p _ { 1 } V _ { 1 } = \\mu R T _ { 1 } \\text { and } p _ { 2 } V _ { 2 } = \\mu R T _ { 2 }{/tex}</span>. So, we have<br />
<span class="math-tex">{tex}W = \\frac { 1 } { ( 1 - \\gamma ) } \\left[ \\mu R T _ { 2 } - \\mu R T _ { 1 } \\right]{/tex}</span><br />
<span class="math-tex">{tex} = \\frac { \\mu R } { ( \\gamma - 1 ) } \\left[ T _ { 1 } - T _ { 2 } \\right]{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A geyser heats water flowing at the rate of 3.0 liters per minute from 27 &deg;C to 77 &deg;C. If the geyser operates on a gas burner, what is the rate of consumption of the fuel if its heat of combustion is&nbsp;<span class="math-tex">{tex}4.0 \\times 10 ^ { 4 }{/tex}</span> J/g?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Rate of flow of water&nbsp; is = 3.0 liter/min.<br />
Initial temperature of water is&nbsp; =&nbsp;T<sub>1</sub> = 27&deg;C<br />
Final temperature of water is =&nbsp;T<sub>2</sub> = 77&deg;C<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> increase in temperature of water is given by&nbsp; =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>T = T<sub>2</sub> - T<sub>1&nbsp;</sub>= 77 - 27 = 50&deg;C<br />
Specific heat for water =&nbsp;c = 4.2 J g<sup>-1</sup> &deg;C<sup>-1</sup><br />
Mass of water =&nbsp;m = 3.0 liter/min = 3000 g/min}<br />
By using<br />
<span class="math-tex">{tex}\\Delta Q = m c \\Delta T{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}3000 \\times 4.2 \\times 50{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}6.3 \\times 10 ^ { 5 } J / \\mathrm { min }{/tex}</span>&nbsp;<br />
Heat of combustion of water&nbsp; = <span class="math-tex">{tex}4 \\times 10 ^ { 4 }{/tex}</span>J/g<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> Rate of consumption is given by&nbsp;&nbsp;<span class="math-tex">{tex}= \\frac { 6.3 \\times 10 ^ { 5 } } { 4 \\times 10 ^ { 4 } }{/tex}</span> = 15.75 g/min</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State and explain First Law of Thermodynamics.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to First Law of Thermodynamics, if an amount of heat <span class="math-tex">{tex}\\Delta{/tex}</span>Q is supplied to a thermodynamic system, a part of it may increase the internal energy of the system by <span class="math-tex">{tex}\\Delta{/tex}</span>U and the remaining part is used up as the external work done <span class="math-tex">{tex}\\Delta{/tex}</span>W by the system.<br />
Thus, we have <span class="math-tex">{tex}\\Delta Q = \\Delta U + \\Delta W{/tex}</span></p>

<p>First Law of Thermodynamics follows the conservation law of energy and establishes an exact relation between heat transferred and mechanical work done. It provides a valuable concept of internal energy. It&nbsp;is applicable to every process in nature and to all the three states of matter i.e., solid, liquid and gases. Moreover, change in internal energy of a system may be due to any cause like change in translational or rotational or vibrational kinetic energy or molecular potential energy etc.&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>Why a gas has two principal specific heat capacities?</li>
	<li>Which one is greater and why?</li>
	<li>Of what significance is the difference between these two specific heat capacities and their ratio?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>In case of a gas, both the pressure and volume change on heating. Therefore, specific heat of a gas is defined either at constant volume or at constant pressure and hence a gas has two specific heats.</li>
	<li>Specific heat at constant pressure is more than the specific heat at constant volume because the gas can expand in the first case, causing more absorption of heat as compared to other one.</li>
	<li>Heat capacity ratio is defined for compressible substances because&nbsp;only compressible substances have two specific heats C<sub>p</sub>(heat capacity at constant pressure) and C<sub>v&nbsp;</sub>(heat capacity constant volume). For in compressible substances we have only single specific heat</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A sample of gas (<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= 1.5)&nbsp;is compressed adiabatically from a volume of 1600 cm<sup>3</sup> to 400 cm<sup>3</sup>. If the initial pressure is 150 kPa, what is the final pressure, and how much work is done on the gas in the process?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here&nbsp;<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= 1.5, V<sub>1</sub>&nbsp;= 1600 cm<sup>3</sup>, V<sub>2</sub>&nbsp;= 400 cm<sup>3</sup>, P<sub>1</sub>&nbsp;= 150 kPa, P<sub>2</sub>&nbsp;= ?<br />
For an adiabatic process,<br />
<span class="math-tex">{tex}P_{2} V_{2}^{\\gamma}=P_{1} V_{1}^{\\gamma}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\quad P_{2}=P_{1}\\left(\\frac{V_{1}}{V_{2}}\\right)^{\\gamma}=150\\left(\\frac{1600}{400}\\right)^{1.5}{/tex}</span>&nbsp;= 1200 kPa<br />
Work done in the adiabatic compression,<br />
W<sub>adi</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{P_{1} V_{1} \\ - \\ P_{2} V_{2}}{\\gamma \\ - \\ 1}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{150 \\ \\times \\ 10^{3} \\ \\times \\ 1600 \\ \\times \\ 10^{-6} \\ - \\ 1200 \\ \\times \\ 10^{3} \\ \\times \\ 400 \\ \\times \\ 10^{-6}}{1.5 \\ - \\ 1}{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{240 \\ - \\ 480}{0.5}{/tex}</span>&nbsp;= -480 J</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>In the given p-V&nbsp;diagram s, Find which curve represents</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>isothermal process,</li>
	<li>adiabatic process for&nbsp;
	<ol start="1" style="list-style-type: lower-alpha;">
		<li>monoatomic&nbsp;</li>
		<li>diatomic</li>
		<li>Triatomic gas</li>
	</ol>
	</li>
</ol>

<p><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1684133558-p49uj9.jpg" style="width: 150px; height: 120px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>For isothermal process, <span class="math-tex">{tex}pV^\\gamma{/tex}</span>&nbsp;= constant<br />
For adiabatic process, &nbsp;= constant<br />
<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= <span class="math-tex">{tex}\\frac 53{/tex}</span>&nbsp;for monoatomic gas = 1.66<br />
<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= <span class="math-tex">{tex}\\frac 75{/tex}</span>&nbsp;1.4 for diatomic gas<br />
<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= <span class="math-tex">{tex}\\frac 8 6 {/tex}</span>&nbsp;=&nbsp;1.33 for triatomic gas<br />
and slope increases with <span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;so,<br />
For&nbsp;Ist,&nbsp;<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= 1, an isotherm<br />
For IInd,&nbsp;<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;=1.33<br />
For IIIrd,&nbsp;<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= 1.4<br />
For IVth,&nbsp;<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= 1.66<br />
So, graph I is isothermal,<br />
Graph II is triatomic adiabatic,<br />
Graph III is diatomic adiabatic,<br />
Graph IV is monoatomic adiabatic.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Describe Carnot&#39;s cycle.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Carnot cycle is defined as an ideal reversible closed thermodynamic cycle. Four successive operations are involved: isothermal expansion, adiabatic expansion, isothermal compression, and adiabatic compression.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1709105075-xxw62c.jpg" style="height:183px; width:281px" /><br />
In (a), the process is reversible isothermal gas expansion. In this process, the amount of heat absorbed by the ideal gas is q<sub>in</sub> from the heat source at a temperature of T<sub>h</sub> The gas expands and does work on the surroundings.<br />
In (b), the process is reversible adiabatic gas expansion. Here, the system is thermally insulated, and the gas continues to expand and work is done on the surroundings. Now the temperature is lower, T<sub>l</sub><br />
In (c), the process is a reversible isothermal gas compression process. Here, the heat loss q<sub>out</sub> occurs when the surroundings do the work at temperature T<sub>l</sub>.<br />
In (d), the process is reversible adiabatic gas compression. Again the system is thermally insulated. The temperature again rises back to T<sub>h</sub> as the surrounding continue to do their work on the gas.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>1.0 m<sup>3</sup>&nbsp;of water is converted into 1671 m<sup>3</sup>&nbsp;of steam at atmospheric pressure and&nbsp;100&deg;C temperature. The latent heat of the vaporization of water is 2.3&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;J kg<sup>-1</sup>. If 2.0 kg of water be converted into steam at atmospheric pressure and&nbsp;100&deg;C temperature, then how much will be the increase in its internal energy? Density of water 1.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>3</sup>&nbsp;kg m<sup>-3</sup>, atmospheric pressure = 1.01&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup>&nbsp;Nm<sup>-2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Heat gained by 2.0 kg of water in changing into steam,<br />
Q = mL = 2.0 kg&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2.3&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;J kg<sup>-1</sup>&nbsp;= 4.6&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;J<br />
The volume of 2.0 kg of water<br />
=&nbsp;<span class="math-tex">{tex}\\frac{\\text { Mass }}{\\text { Density }}=\\frac{2.0 \\mathrm{~kg}}{10^{3} \\mathrm{~kg} \\mathrm{~m}^{-3}}{/tex}</span>&nbsp;= 2.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;m<sup>3</sup><br />
The volume of steam formed by 1.0 m<sup>3</sup> of water = 1671 m<sup>3</sup><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;The volume of steam formed by 2.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;m<sup>3</sup>&nbsp;of water<br />
= 1671&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;= 3342&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;m<sup>3</sup><br />
When 2.0 kg of water changes into steam, the increase in volume is<br />
dV = 3342&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;- 2.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;= 3340&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;m<sup>3</sup><br />
The external work done against the atmospheric pressure,<br />
dW = PdV = 1.01&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5&nbsp;</sup><span class="math-tex">{tex}\\times{/tex}</span>&nbsp;3340&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>&nbsp;= 0.337&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6&nbsp;</sup>J<br />
From the first law of thermodynamics, the increase in internal energy is<br />
dU = Q - dW = 4.6&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;- 0.337&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup><br />
= 4.263&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6&nbsp;</sup>J<br />
The positive value of dU indicates that the internal energy of ice increases on melting.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>5 moles of oxygen are heated at constant volume from 10&deg;C to 20&deg;C. What will be the change in the internal energy of the gas? The gram molecular specific heat of oxygen at constant pressure, C<sub>p&nbsp;</sub>= 8&nbsp;cal mole<sup>-1&nbsp;</sup>&deg;C<sup>-1</sup>&nbsp;and R = 8.36 J mole<sup>-1&nbsp;</sup>&deg;C<sup>-1</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here&nbsp;C<sub>p&nbsp;</sub>= 8&nbsp;cal mole<sup>-1&nbsp;</sup>&deg;C<sup>-1</sup>, R = 8.36 J&nbsp;mole<sup>-1&nbsp;</sup>&deg;C<sup>-1</sup><br />
=&nbsp;<span class="math-tex">{tex}\\frac{8.36}{4.18}{/tex}</span>&nbsp;= 2&nbsp;cal mole<sup>-1&nbsp;</sup>&deg;C<sup>-1</sup><br />
As C<sub>p</sub> - C<sub>v</sub> = R<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;C<sub>v</sub> =&nbsp;C<sub>p</sub> - R = 8 - 2 = 6&nbsp;cal mole<sup>-1&nbsp;</sup>&deg;C<sup>-1</sup><br />
Heat gained by 5 moles of oxygen when heated from&nbsp;10&deg;C to 20&deg;C,<br />
Q = nC<sub>v</sub>&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>T = 5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(20 - 10) = 300 cal<br />
As the gas is heated at constant volume, the external work done,<br />
dW = PdV = P&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;0 = 0<br />
From first law of thermodynamics, the increase in internal energy is<br />
dU = Q - dW = 300 - 0 = 300 cal</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>If for hydrogen C<sub>P</sub> - C<sub>V</sub> = a and for oxygen C<sub>P</sub> - C<sub>V</sub> = b where C<sub>P</sub> &amp; C<sub>V</sub> refer to specific heat at constant pressure and volume then what is the relation between a and b?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let</p>

<p>C<sub>P</sub> = Specific heat at constant pressure<br />
C<sub>V</sub> = Specific heat at constant Volume</p>

<p>M = Molar mass</p>

<p>For an ideal gas , C<sub>p</sub> - C<sub>v</sub> = R</p>

<p>for other gases,&nbsp;&nbsp;<span class="math-tex">{tex}C_P - C_V = \\frac {R} {M}{/tex}</span></p>

<p>For H<sub>2</sub>, C<sub>P</sub> - C<sub>V</sub> = a<br />
<br />
For O<sub>2</sub> = C<sub>P</sub> - C<sub>V</sub> = b</p>

<p>So, for <span class="math-tex">{tex}H _ { 2 } \\Rightarrow C _ { P } - C _ { V } = a = \\frac { R } { 2 }{/tex}</span><br />
<span class="math-tex">{tex}M _ { H 2 } = 2 \\left| C _ { P } - C _ { V } = a = \\frac { R } { 2 }\\right.{/tex}</span> ...(i)<br />
For <span class="math-tex">{tex}\\mathrm { O } _ { 2 } \\Rightarrow \\mathrm { C } _ { \\mathrm { P } } - \\mathrm { C } _ { \\mathrm { V } } = \\mathrm { b } = \\frac { R } { 32 \\mathrm { } }{/tex}</span> ...(ii)<br />
from equation (i)<br />
<span class="math-tex">{tex}2 a = R{/tex}</span><br />
from equation (ii)<br />
<span class="math-tex">{tex}32 b = R{/tex}</span></p>

<p><span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;2a = 32 b<br />
a = 16 b</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Deduce the work done in the following complete cycle.<br />
<img data-imgur-src="zTuhDdz.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/zTuhDdz.png" style="width: 200px; height: 150px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img data-imgur-src="f1L11uq.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/f1L11uq.png" style="width: 150px; height: 113px;" /><br />
BC = KL =&nbsp; 4 - 1 = 3&nbsp;<span class="math-tex">{tex}litre{/tex}</span>&nbsp;= 3 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup>m<span style="font-size: 10.8333px;"><sup>3</sup>&nbsp; (<span class="math-tex">{tex}\\because 1m^3 = 1000 litre{/tex}</span>)</span><br />
AC = 4 - 2 = 2 pa&nbsp;<br />
LC = 2 - 0 = 2 pa</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Let&nbsp; W<sub>AB</sub>&nbsp;is the work done during the process from A to B<br />
	Now, Work done = Area under the P - V curve<br />
	W<sub>AB</sub> = area (ABKLA )<br />
	= area of <span class="math-tex">{tex}\\Delta{/tex}</span>ABC + area of rectangle&nbsp;BKLC<br />
	<span class="math-tex">{tex}= \\left( \\frac { 1 } { 2 } \\times B C \\times A C \\right) + ( K L \\times L C ){/tex}</span><br />
	<span class="math-tex">{tex}W_{AB}= \\left( \\frac { 1 } { 2 } \\times 3 \\times 10 ^ { - 3 } \\times 2 \\right) + \\left( 3 \\times 10 ^ { - 3 } \\times 2 \\right){/tex}</span><br />
	<span class="math-tex">{tex}= 3 \\times 10 ^ { - 3 } + 6 \\times 10 ^ { - 3 }{/tex}</span><br />
	<span class="math-tex">{tex}W _ { A B } = 9 \\times 10 ^ { - 3 } J{/tex}</span><br />
	Since gas expands during this process, hence,&nbsp;W<sub>AB</sub> is positive</li>
	<li>Let work done during process(compression) B to C is W<sub>BC</sub><br />
	W<sub>BC</sub> =&nbsp;- area of rectangle BCLK<br />
	(Negative because gas compresses during BC)<br />
	= - KL <span class="math-tex">{tex}\\times{/tex}</span> LC<br />
	<span class="math-tex">{tex}W _ { B C } = - 3 \\times 10 ^ { - 3 } \\times 2{/tex}</span><br />
	<span class="math-tex">{tex}= - 6 \\times 10 ^ { - 3 } J{/tex}</span></li>
	<li>Let W<sub>CA</sub> be the work done during the process&nbsp;from C to A:-<br />
	As there is no change in volume of gas in this process, W<sub>CA</sub> = O<br />
	So, net work done during the complete cycle = W<sub>AB</sub> + W<sub>BC </sub>+ W<sub>CA</sub><br />
	<span class="math-tex">{tex}= 9 \\times 10 ^ { - 3 } - 6 \\times 10 ^ { - 3 } + 0{/tex}</span><br />
	Net work done <span class="math-tex">{tex}= 3 \\times 10 ^ { - 3 } J{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What amount of heat must be supplied to <span class="math-tex">{tex}2.0 \\times 10 ^ { - 2 }{/tex}</span> kg of nitrogen (at room temperature) to raise its temperature by 45 &deg;C at constant pressure? (Molecular mass of N<sub>2</sub> = 28; R = 8.3 J mol<sup>-1</sup> K<sup>-1</sup>.)</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Mass of nitrogen, m = 2.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-2</sup> kg =&nbsp;2.0&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-2</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;1000&nbsp;= 20 g<br />
Increase in temperature of gas =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>T = 45&deg;C<br />
Molecular mass of nitrogen =&nbsp;M = 28 gram gas constant, R = 8.3 J mol<sup>-1</sup> K<sup>-1</sup><br />
if m is mass of gas in grams<br />
Number of moles = n =&nbsp;<span class="math-tex">{tex} \\frac { m } { M }{/tex}</span><br />
n&nbsp;=&nbsp;<span class="math-tex">{tex} \\frac { 2.0 \\ \\times \\ 10 ^ { - 2 } \\ \\times \\ 10 ^ { 3 } } { 28 }{/tex}</span>&nbsp;= 0.714<br />
Molar specific heat at constant pressure for nitrogen, <span class="math-tex">{tex}C _ { P } = \\frac { 7 } { 2 } R{/tex}</span><br />
=&nbsp;<span class="math-tex">{tex} \\frac { 7 } { 2 } \\times 8.3{/tex}</span><br />
= 29.05 J mol<sup>-1</sup>K<sup>-1</sup><br />
by heat formula :<br />
<span class="math-tex">{tex}\\Delta Q = n C _ { p } \\Delta T{/tex}</span><br />
= 0.714&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;29.05&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;45<br />
= 933.38 J<br />
So 933.38 J is the amount of heat required to increase the temperature by 45<sup>0</sup>C.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>At 27&deg; C two moles of an ideal monatomic gas <span class="math-tex">{tex}\\left( \\gamma = \\frac { 5 } { 3 } \\right){/tex}</span>occupies a volume V. The gas expands adiabatically to a volume 2V. Calculate</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>the final temperature of the gas,</li>
	<li>the work done by the gas during the expansion process, and</li>
	<li>change in internal energy of the gas. Take R = 8.31 J mol<sup>-1</sup>K<sup>-1</sup>.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given:&nbsp;T<sub>1</sub>&nbsp;= 27 &deg;C = 300 K, <span class="math-tex">{tex}\\mu{/tex}</span> = 2, <span class="math-tex">{tex}\\gamma =\\frac 53{/tex}</span>, V<sub>1</sub>&nbsp;= V, V<sub>2</sub>&nbsp;= 2V</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>For an adiabatic process,&nbsp;<span class="math-tex">{tex}T _ { 1 } V _ { 1 } ^ { \\gamma - 1 } = T _ { 2 } V _ { 2 } ^ { \\gamma - 1 }{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Final Temperature,&nbsp;<span class="math-tex">{tex}T _ { 2 } = T _ { 1 } \\left( \\frac { V _ { 1 } } { V _ { 2 } } \\right) ^ { \\gamma - 1 }{/tex}</span><span class="math-tex">{tex}= 300 \\times \\left( \\frac { 1 } { 2 } \\right) ^ { \\frac { 5 } { 3 } - 1 } = \\frac { 300 } { ( 2 ) ^ { \\frac { 2 } { 3 } } }{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;T<sub>2&nbsp;</sub>= 189 K</li>
	<li><span class="math-tex">{tex}\\Delta W = \\frac { \\mu R } { ( \\gamma - 1 ) } \\left[ T _ { 1 } - T _ { 2 } \\right] = \\frac { 2 \\times 8.31 } { \\left( \\frac { 5 } { 3 } - 1 \\right) } [ 300 - 189 ]{/tex}</span><br />
	<span class="math-tex">{tex}= \\frac { 2 \\times 8.31 \\times 111 } { \\left( \\frac { 2 } { 3 } \\right) } = 2767 \\mathrm\\; { J }{/tex}</span></li>
	<li>As in an adiabatic process,&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>Q = 0, hence&nbsp;<span class="math-tex">{tex}\\Delta U = - \\Delta W{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Change in internal energy of the gas,&nbsp;<span class="math-tex">{tex}\\Delta U = - \\Delta W = - 2767 \\mathrm { J }{/tex}</span><br />
	negative sign signifies that internal energy of the gas has decreased.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Two cylinders A and B of equal capacity are connected to each other via a stopcock. A contains a gas at standard temperature and pressure. B is completely evacuated. The entire system is thermally insulated. The stopcock is suddenly opened.&nbsp;Answer the following:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>What is the final pressure of the gas in A and B?</li>
	<li>What is the change in internal energy of the gas?</li>
	<li>What is the change in the temperature of the gas?</li>
	<li>Do the intermediate states of the system (before settling to the final equilibrium state) lie on its P-V-T surface?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Since the final temperature and initial temperature remain the same.<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;P<sub>2</sub>V<sub>2</sub> = P<sub>1</sub>V<sub>1</sub><br />
	But P<sub>1</sub> = 1 atm, V<sub>1</sub> = V, V<sub>2</sub> = 2V and P<sub>2</sub> = ?<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;P<sub>2</sub> =&nbsp;<span class="math-tex">{tex}\\frac{P_{1} V_{1}}{V_{2}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1 \\times V}{2 V}{/tex}</span>&nbsp;= 0.5 atm</li>
	<li>Since the temperature of the system remains unchanged, the change in internal energy is zero.</li>
	<li>The system being thermally insulated, there is no change in temperature (because of free expansion)</li>
	<li>The expansion is a free expansion. Therefore, the intermediate states are non-equilibrium states and the gas equation is not satisfied in these states. As a result, the gas can not return to an equilibrium state which lies on the P-V-T surface.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>In changing the state of a gas adiabatically from an equilibrium state A to another equilibrium state B, an amount of work equal to 22.3 J is done on the system. If the gas is taken from state A to B via a process in which the net heat absorbed by the system is 9.35 cal, how much is the net work done by the system in the latter case? (Take 1 cal = 4.19 J)</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The work done (W) in changing the state of system from A to B = 22.3 J.<br />
In adiabatic process&nbsp;there is no exchange of&nbsp;heat.<br />
<span class="math-tex">{tex}\\therefore \\Delta{/tex}</span>Q = 0<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>W = -22.3 J (negative sign is due to work is done on the system)<br />
From the first law of thermodynamics<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>Q = <span class="math-tex">{tex}\\Delta{/tex}</span>U + <span class="math-tex">{tex}\\Delta{/tex}</span>W<br />
Where,<br />
<span class="math-tex">{tex}\\Delta U{/tex}</span> = Change in the internal energy of the gas<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>W = work done<br />
<span class="math-tex">{tex}\\therefore \\Delta{/tex}</span>U =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>Q -&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W = 0- (- 22.3) = 22.3 Joule<br />
The net heat absorbed by the system&nbsp;<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>Q = 9.35 calory = 9.35 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;4.19 = 39.1765 Joule<br />
Heat absorbed, <span class="math-tex">{tex}\\Delta{/tex}</span>Q =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U +&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>W&nbsp;( by first law of thermodynamics)<br />
<span class="math-tex">{tex}\\therefore \\Delta{/tex}</span>W = <span class="math-tex">{tex}\\Delta{/tex}</span>Q - <span class="math-tex">{tex}\\Delta{/tex}</span>U<br />
= 39.1765 - 22.3<br />
= 16.8765 Joule<br />
Therefore, 16.88 Joule of work is done by the system in changing the state.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State first law of thermodynamics. Why is C<sub>p</sub> &gt; C<sub>v</sub>? Derive the relation C<sub>p</sub> - C<sub>v</sub> = R for an ideal gas.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The first law of thermodynamics states that energy can be converted from one form to another, but cannot be created or destroyed. The most important and critical aspect of life revolves around the idea of energy.<br />
The heat capacity at constant pressure C<sub>P</sub> is greater than the heat capacity at constant volume C<sub>v</sub> , because when heat is added at constant pressure, the substance expands and work.<br />
<strong>The relation C<sub>p</sub> - C<sub>v</sub> = R for an ideal gas.</strong><br />
According to the first law of thermodynamics, q = nC<span class="math-tex">{tex}\\Delta \\text T{/tex}</span> ...(1)<br />
Where q is the heat, n is the number of moles, C molar heat capacity and <span class="math-tex">{tex}\\Delta \\text T{/tex}</span> is the change in temperature.<br />
At constant pressure, in the equation (1), then<br />
q<sub>p</sub> = nC<sub>p</sub><span class="math-tex">{tex}\\Delta \\text T{/tex}</span><br />
The above equation is equal to the change in enthalpy, then<br />
q<sub>p</sub> = nC<sub>p</sub><span class="math-tex">{tex}\\Delta \\text T{/tex}</span> = <span class="math-tex">{tex}\\Delta \\text H{/tex}</span> ...(2)<br />
Similarly, at constant, volume, in equation (1), then<br />
q<sub>v</sub> = nC<sub>v</sub><span class="math-tex">{tex}\\Delta \\text T{/tex}</span><br />
The above equation is equal to the change in internal energy, then<br />
q<sub>p</sub> = nC<sub>p</sub><span class="math-tex">{tex}\\Delta \\text T{/tex}</span> = <span class="math-tex">{tex}\\Delta \\text U{/tex}</span> ...(3)<br />
The formula for one mole of an ideal gas is,<br />
<span class="math-tex">{tex}\\Delta \\text H{/tex}</span> = <span class="math-tex">{tex}\\Delta \\text U{/tex}</span> + <span class="math-tex">{tex}\\Delta{/tex}</span>(pv) (pv = nRT) (For one mole n = 1)<br />
Then the above equation is written as,<br />
<span class="math-tex">{tex}\\Delta \\text H{/tex}</span> = <span class="math-tex">{tex}\\Delta \\text U{/tex}</span> + <span class="math-tex">{tex}\\Delta (\\text {RT}){/tex}</span><br />
By rearranging the above equation, then<br />
<span class="math-tex">{tex}\\Delta \\text H{/tex}</span> = <span class="math-tex">{tex}\\Delta \\text U{/tex}</span> + <span class="math-tex">{tex}\\text R \\Delta \\text T{/tex}</span> ...(4)<br />
By substituting the equation (2) and equation (3) in the equation (4), then<br />
nC<sub>p</sub><span class="math-tex">{tex}\\Delta \\text T{/tex}</span> = nC<sub>v</sub><span class="math-tex">{tex}\\Delta \\text T{/tex}</span> + <span class="math-tex">{tex}\\text R \\Delta \\text T{/tex}</span><br />
Here, n = 1, then the above equation is written as,<br />
C<sub>p</sub><span class="math-tex">{tex}\\Delta \\text T{/tex}</span> = C<sub>v</sub><span class="math-tex">{tex}\\Delta \\text T{/tex}</span> + <span class="math-tex">{tex}\\text R \\Delta \\text T{/tex}</span><br />
By taking <span class="math-tex">{tex}\\Delta \\text T{/tex}</span> as a common term, then C<sub>p</sub> &times; <span class="math-tex">{tex}\\Delta \\text T{/tex}</span> = (C<sub>v</sub> + R)<span class="math-tex">{tex}\\Delta \\text T{/tex}</span><br />
By cancelling the terms <span class="math-tex">{tex}\\Delta \\text T{/tex}</span> on both sides, then<br />
C<sub>p</sub> = C<sub>v</sub> + R<br />
By rearranging the above equation, then<br />
C<sub>p</sub> &minus; C<sub>v</sub> = R</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that C<sub>P</sub> - C<sub>V </sub>= R where C<sub>P</sub> = specific heat at constant pressure; C<sub>V</sub> = specific heat at constant volume and R = Universal Gas constant&nbsp;for an ideal gas.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let us first heat the gas at constant volume till the temperature increases by&nbsp;<span class="math-tex">{tex}\\Delta T{/tex}</span> &nbsp;if&nbsp;<span class="math-tex">{tex}\\triangle Q{/tex}</span>&nbsp;is the amount of heat required to raise the temperature of 1 mole of gas to increase the&nbsp;temperature by <span class="math-tex">{tex}\\triangle T{/tex}</span></p>

<p>So, <span class="math-tex">{tex}\\Delta Q = C _ { V } \\Delta T{/tex}</span> ...(i)</p>

<p>Here <span class="math-tex">{tex}C_V{/tex}</span>&nbsp;is the specific heat at constant volume. Since volume remains the same, hence no work is heating the gas then according to law of conservation of energy, the entire heat supplied goes into raising the internal energy and hence the temperature of the gas.<br />
Now, <span class="math-tex">{tex}C_ V \\Delta T = \\Delta U{/tex}</span>&nbsp;.....(ii)<br />
<span class="math-tex">{tex}\\therefore \\Delta U{/tex}</span> = increase in the internal energy of the gas</p>

<p>Let us heat the gas at constant pressure till the temperature of the gas increases by ∆T. In this case&nbsp;external work is done to expand the gas hence by using first law of thermodynamics.<br />
<span class="math-tex">{tex}\\Delta Q ^ { 1 } = \\Delta U + \\Delta W{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm { C } _ { \\mathrm { p } } \\Delta \\mathrm { T } = \\mathrm { C } _ { \\mathrm { V } } \\Delta \\mathrm { T } + \\Delta \\mathrm { W }{/tex}</span> ( by equation (ii))</p>

<p>Here C<sub>P</sub> is the specific heat at constant pressure.</p>

<p>But <span class="math-tex">{tex}\\Delta W = P \\Delta V{/tex}</span>, so<br />
<span class="math-tex">{tex}C _ { P } \\Delta T = C _ { V } \\Delta T + P \\Delta V{/tex}</span> ...(iii)<br />
Now, form ideal gas equation : &nbsp; &nbsp; PV = RT ....(iv)</p>

<p>or <span class="math-tex">{tex}P ( V + \\Delta V ) = R ( T + \\Delta T ){/tex}</span> ...(v)<br />
Subtracting equation (iv) from equation (v)<br />
<span class="math-tex">{tex}P \\Delta V = R \\Delta T{/tex}</span><br />
Put <span class="math-tex">{tex}P \\Delta V = R \\Delta T{/tex}</span> in equation (iii)<br />
<span class="math-tex">{tex}C _ { P } \\Delta T = C _ { V } \\Delta T + P \\Delta V{/tex}</span><br />
<span class="math-tex">{tex}C _ { P } \\Delta T = C _ { V } \\Delta T + R \\Delta T{/tex}</span>&nbsp; .....(vi)</p>

<p>Divide eq (vi) by&nbsp;<span class="math-tex">{tex}\\triangle T{/tex}</span><br />
<span class="math-tex">{tex}C _ { P } = C _ { V } + R{/tex}</span><br />
or <span class="math-tex">{tex}C _ { P } - C _ { V } = R{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State the first law of thermodynamics. Apply this to derive an expression for the change in internal energy during boiling process.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The first law of thermodynamics states that energy can be converted from one form to another, but cannot be created or destroyed.<br />
Let the latent heat of vaporisation of a liquid of mass m at its boiling temperature be L.<br />
Let V<sub><span class="math-tex">{tex}\\ell{/tex}</span></sub> be the volume of liquid and V<sub>v</sub> be the volume of vapours and let evaporation take place at constant pressure P.<br />
According to the first law of thermodynamics,<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>Q = <span class="math-tex">{tex}\\Delta{/tex}</span>U + P<span class="math-tex">{tex}\\Delta{/tex}</span>V<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> mL = <span class="math-tex">{tex}\\Delta{/tex}</span>U + P(V<sub>v</sub> - V<sub><span class="math-tex">{tex}\\ell{/tex}</span></sub>)<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex}\\Delta{/tex}</span>U = mL - Pt(V<sub>v</sub> - V<sub><span class="math-tex">{tex}\\ell{/tex}</span></sub>)<br />
This is the required expression for change in internal energy.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State and prove the Zeroth Law of Thermodynamics.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Zeroth Law of Thermodynamics:- If two systems A and B are separately and independently in thermal equilibrium with a third system C, then systems A and B are in thermal equilibrium with each other too.<br />
<img alt="" data-imgur-src="M1y0Oky.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/M1y0Oky.png" style="width: 160px; height: 151px;" /><br />
Proof: Systems A and B are separated by an adiabatic (insulating) wall, which does not allow the transfer of heat between them. On the other hand, A and B are separately in contact with system C through a diathermic wall, which allows free flow of heat.<br />
As system A can freely exchange heat with system C, A and C will soon attain thermal equilibrium and accordingly<br />
T<sub>A</sub>&nbsp;= T<sub>C</sub>&nbsp;...(i)<br />
Similarly, system B can freely exchange heat with system C and soon B and C will attain thermal equilibrium and accordingly<br />
T<sub>B</sub>&nbsp;= T<sub>C</sub>&nbsp;...(ii)<br />
From (i)&nbsp;and (ii), it is evident that T<sub>A</sub> = T<sub>B</sub>&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>Derive an expression for the work done during the isothermal expansion of n moles of an ideal gas.</li>
	<li>A steam engine delivers 5.4 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>8</sup>J of work per minute and services 3.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup> J of heat per minute from its boiler. What is the efficiency of the engine? How much heat is wasted per minute?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>The work done <span class="math-tex">{tex}W{/tex}</span> during the isothermal expansion of an ideal gas can be derived using the first law of thermodynamics and the ideal gas law.<br />
	For an isothermal process, the temperature <span class="math-tex">{tex}T{/tex}</span> is constant. The pressure <span class="math-tex">{tex}P{/tex}</span> of the gas is related to the volume <span class="math-tex">{tex}V{/tex}</span> by the ideal gas law:<br />
	<span class="math-tex">{tex} P=\\frac{n R T}{V}{/tex}</span><br />
	The work done by the gas during an expansion from volume <span class="math-tex">{tex}V_i{/tex}</span> to <span class="math-tex">{tex}V_f{/tex}</span> is given by:<br />
	<span class="math-tex">{tex} W=\\int_{V_i}^{V_f} P d V{/tex}</span><br />
	Substituting <span class="math-tex">{tex}P=\\frac{n R T}{V}{/tex}</span>, we get:<br />
	<span class="math-tex">{tex} W=\\int_{V_i}^{V_f} \\frac{n R T}{V} d V{/tex}</span><br />
	Since <span class="math-tex">{tex}T{/tex}</span> is constant, the integral simplifies to:<br />
	<span class="math-tex">{tex} W=n R T \\ln \\left(\\frac{V_f}{V_i}\\right){/tex}</span><br />
	This is the work done during the isothermal expansion of <span class="math-tex">{tex}n{/tex}</span> moles of an ideal gas.</li>
	<li>Work done by the steam engine per minute, W = 5.4 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>8</sup>J<br />
	Heat supplied from the boiler, H = 3.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup>J<br />
	Efficiency of the engine = <span class="math-tex">{tex}\\frac {\\text { Output energy }} { \\text {Input energy} }{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore \\eta = \\frac { W } { H } = \\frac { 5.4 \\times 10 ^ { 8 } } { 3.6 \\times 10 ^ { 9 } }{/tex}</span>= 0.15<br />
	Hence, the percentage efficiency of the engine is 15 %.<br />
	Amount of heat wasted = 3.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup>J - 5.4 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>8</sup>J<br />
	= 3.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>8</sup>J<br />
	= 3.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup>J<br />
	Therefore, the amount of heat wasted per minute is 3.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup>J</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is an isothermal process? State two essential conditions for such a process to take place. Show analytically that work done by one mole of an ideal gas during isothermal expansion from volume V<sub>1</sub> to volume V<sub>2</sub> is given by W = RT log<sub>e</sub> <span class="math-tex">{tex}\\frac {V_2}{V_1}{/tex}</span><br />
What is the change in internal energy of a gas, which is compressed isothermally?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The process in which, temperature of gas remains constant is said to be an isothermal process.<br />
In this Process. Heat exchanged is used entirely as work.<br />
In an isothermal process, dQ = dW and dU = 0, dT = 0 and PV = constant<br />
To take a gas through an isothermal process, it must be placed in a container fitted with a piston and the container should have conducting walls. The process is carried out by varying the pressure of the gas very slowly by adjusting the mass kept on the piston. The slow speed of the process allows the gas to always remain in thermal equilibrium with its surroundings. As the surroundings are at a constant temperature, the gas temperature also remains constant. Work done in Isothermal Process.<br />
W = <span class="math-tex">{tex}\\int{/tex}</span>p<span class="math-tex">{tex}\\cdot{/tex}</span>dV = <span class="math-tex">{tex}\\int \\frac{n R T}{V}{/tex}</span><span class="math-tex">{tex}\\cdot{/tex}</span>dV By using&nbsp; PV = nRT<br />
= <span class="math-tex">{tex}\\int_\\limits{V_1}^{V_2} \\mathrm{nRT} \\frac{d V}{V}{/tex}</span> = nRT <span class="math-tex">{tex}|ln V|_{V_1}^{V_2}{/tex}</span><br />
W = nRT ln <span class="math-tex">{tex}\\frac{V_2}{V_1}{/tex}</span><br />
For n = 1<br />
W = RT log <span class="math-tex">{tex}\\frac{V_2}{V_1}{/tex}</span><br />
Change in internal energy, <span class="math-tex">{tex}\\Delta{/tex}</span>U = nC<sub>V</sub><span class="math-tex">{tex}\\Delta{/tex}</span>T for any process. So, for isothermal compression <span class="math-tex">{tex}\\Delta{/tex}</span>U = 0 as&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>T = 0</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>State second law of thermodynamics. How is a heat engine different from a refrigerator?</li>
	<li>Show that for a Carnot engine, efficiency <span class="math-tex">{tex}\\eta=1-\\frac{T_{2}}{T_{1}}{/tex}</span>(T<sub>2</sub> &lt; T<sub>1</sub>) where T<sub>1</sub> is the temperature of the source and<br />
	T<sub>2</sub> is the temperature of the sink.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>The Second Law of Thermodynamics states that the state of entropy of the entire universe, as an isolated system, will always increase over time. Refrigerators create cold air with a compressor, whereas heat engines create hot air with a fan. Unlike a combustion engine, a refrigerator (or heat pump) operates in the other direction.</li>
	<li>Efficiency, <span class="math-tex">{tex}\\eta{/tex}</span> = <span class="math-tex">{tex}\\frac{\\text { useful output }}{\\text { Input }}{/tex}</span> = <span class="math-tex">{tex}\\frac{W}{Q_1}{/tex}</span><br />
	= <span class="math-tex">{tex}\\frac{\\left(Q_1-Q_2\\right)}{Q_1}{/tex}</span><br />
	<span class="math-tex">{tex}\\frac{R\\left(T_1-T_2\\right) \\log _e \\frac{V_2}{V_1}}{R T_1 \\log e \\frac{V_2}{V_1}}{/tex}</span><br />
	<span class="math-tex">{tex}\\eta{/tex}</span> = <span class="math-tex">{tex}\\frac{T_1-T_2}{T_1}{/tex}</span><br />
	or <span class="math-tex">{tex}\\eta{/tex}</span> = 1-<span class="math-tex">{tex}\\frac{T_2}{T_1}{/tex}</span><br />
	From the equation, we conclude that efficiency depends only upon the temperature of the source and sink, and is always less than unity. The efficiency is independent of the nature of the working substance.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>A sample of 2 kg of monoatomic helium (assumed ideal) is taken through the process ABC and another sample of 2 kg of the same gas is taken through the process ADC (Figure). Given molecular mass of Helium = 4. R = 8.3 J mol<sup>-1</sup> K<sup>-1</sup>.<br/>
<img alt="" data-imgur-src="gOTlZCR.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082664-9umahx.jpg" style="width: 150px; height: 107px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>What is the temperature of Helium in each of the states A, B, C and D?</li>
<li>How much is the heat involved in each of the processes ABC and ADC?</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>Number of moles of He n =&nbsp;<span class="math-tex">{tex}\\frac{\\text { Mass of He }}{\\text { Molecular mass }}=\\frac{2000}{4}{/tex}</span>&nbsp;= 500<br />
	As P<sub>A</sub>V<sub>A</sub> = n RT<sub>A</sub><br />
	<span class="math-tex">{tex}\\therefore \\quad T_{A}=\\frac{P_{A} V_{A}}{n R}=\\frac{5 \\ \\times \\ 10^{4} \\ \\times \\ 10}{500 \\ \\times \\ 83}{/tex}</span>&nbsp;= 120.5 K<br />
	For the isochoric process (V = constant) AB,<br />
	<span class="math-tex">{tex}\\frac{T_{B}}{T_{A}}=\\frac{P_{B}}{P_{A}} {/tex}</span>&nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;T<sub>B</sub> =&nbsp;<span class="math-tex">{tex}\\frac{P_{B}}{P_{A}} \\times T_{A}=\\frac{10}{5} \\times 120.5{/tex}</span>&nbsp;= 241 K<br />
	For the isobaric process (P = constant) BC,<br />
	<span class="math-tex">{tex}\\frac{T_{C}}{T_{B}}=\\frac{V_{C}}{V_{B}}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;T<sub>C</sub> = <span class="math-tex">{tex}\\frac{V_{C}}{V_{B}} \\times T_{B}=\\frac{20}{10} \\times 241{/tex}</span>= 482 K<br />
	For the isochoric process DC,<br />
	<span class="math-tex">{tex}\\frac{T_{D}}{T_{C}}=\\frac{P_{D}}{P_{C}} \\quad \\therefore \\quad T_{D}=\\frac{P_{D}}{P_{C}} \\times T_{C}=\\frac{5}{10} \\times 482{/tex}</span>&nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;TD =&nbsp;<span class="math-tex">{tex}\\frac{P_{D}}{P_{C}} \\times T_{C}=\\frac{5}{10} \\times 482{/tex}</span>&nbsp;= 241 K</li>
	<li>The heat involved in the process ABC,<br />
	Q<sub>ABC</sub> =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U<sub>AC</sub> + W<sub>ABC</sub> = nC<sub>V&nbsp;</sub>(T<sub>C</sub> - T<sub>A</sub>) + W<sub>BC</sub><br />
	= nC<sub>V&nbsp;</sub>(T<sub>C</sub> - T<sub>A</sub>) +&nbsp;P<sub>B&nbsp;</sub>(V<sub>C</sub> - V<sub>B</sub>)<br />
	= 500&nbsp;<span class="math-tex">{tex}\\times \\frac{3}{2} \\times{/tex}</span>&nbsp;8.3&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(482 - 120.5) + 10&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>4</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(20 - 10) [<span class="math-tex">{tex}\\because{/tex}</span>&nbsp;C<sub>V</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac 32{/tex}</span>R]<br />
	= 2.25&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;+ 10<sup>6</sup>&nbsp;= 3.25&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;J = 3.25 MJ<br />
	The heat involved in the process ADC,<br />
	Q<sub>ABC</sub> =&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>U<sub>AC</sub> + W<sub>ADC</sub> = <span class="math-tex">{tex}\\Delta{/tex}</span>U<sub>AC</sub>&nbsp;+ W<sub>AD</sub><br />
	= 2.25&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup>&nbsp;+&nbsp;P<sub>A&nbsp;</sub>(V<sub>D</sub> - V<sub>A</sub>)<br />
	= 2.25&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup> + 5&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>4</sup>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(20 - 10)<br />
	= 2.75&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>6</sup> J = 2.75 MJ</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is meant by a thermodynamic reversible process? Write two characteristics of a reversible process.<br />
State in brief the meaning of Carnot cycle. Write an expression for the efficiency of a Carnot engine. What is the advantage of Carnot engine in terms of efficiency?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>In thermodynamics, a reversible process is a process whose direction can be reversed by inducing infinitesimal changes to some property of the system via its surroundings. Throughout the entire reversible process, the system is in thermodynamic equilibrium with its surroundings.<br />
The system attains mechanical equilibrium at the end of every step of the process. A reversible process results in obtaining maximum work.<br />
A Carnot cycle is defined as an ideal reversible closed thermodynamic cycle. Four successive operations are involved: isothermal expansion, adiabatic expansion, isothermal compression, and adiabatic compression. The efficiency is e = <span class="math-tex">{tex}\\frac{W}{Q_{high}}{/tex}</span>.<br />
Most efficient expansion, as no heat loss is taking place, full energy is utilised only for expansion and thereby doing work. Isothermal heat rejection- Most efficient heat rejection to a heat sink at same temperature.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type: lower-roman;">
	<li>Two bodies at different temperatures T<sub>1</sub> and T<sub>2</sub> if brought in thermal contact do not necessarily settle to mean temperature&nbsp;<span class="math-tex">{tex}\\frac{\\left(T_{1} \\ + \\ T_{2}\\right)} 2{/tex}</span></li>
	<li>The coolant in a chemical or a nuclear plant (i.e., the liquid used to prevent the different parts of a plant from getting too hot) should have high specific heat.</li>
	<li>Air pressure in a car tyre increases during driving.</li>
	<li>The climate of a harbour town is more temperate than that of a town in a desert at the same latitude.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>The two bodies may have different masses and different materials i.e., they may have different thermal capacities. In case the two bodies have equal thermal capacities, they would settle at the mean temperature&nbsp;<span class="math-tex">{tex}\\frac{\\left(T_{1} \\ + \\ T_{2}\\right)} 2{/tex}</span>.</li>
	<li>The purpose of a coolant is to absorb maximum heat with least rise in its own temperature. This is possible only if specific heat is high because Q = mc <span class="math-tex">{tex}\\Delta{/tex}</span>T. For a given value of m&nbsp;and Q,&nbsp;the rise in temperature <span class="math-tex">{tex}\\Delta{/tex}</span>T&nbsp;will be small if c&nbsp;is large. This will prevent different parts of the nuclear reactor from getting too hot.</li>
	<li>Due to the friction between the tyres and the&nbsp;road, the tyres get heated. The temperature of air inside the tyres increases. Consequently, the air pressure in the tyres increases slightly.</li>
	<li>The relative humidity of a harbour town is more than that of a desert town. Due to high specific heat of water, the variations in the temperature of humid air are less. Hence the climate of a harbour town is without the extremes of hot or cold.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>A monoatomic ideal gas of two moles is taken through a cyclic process starting from A as shown in Figure. The volume ratios are <span class="math-tex">{tex}\\frac{V_{B}}{V_{A}}{/tex}</span> = 2 and <span class="math-tex">{tex}\\frac{V_{D}}{V_{A}}{/tex}</span> = 4. If the temperature T at A is 27<span class="math-tex">{tex}{ }^{\\circ} \\mathrm{C}{/tex}</span>, calculate,<br/>
<img alt="" data-imgur-src="pzW0FvI.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082659-2b8p7n.jpg" style="width: 150px; height: 143px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>the temperature of the gas at point B,</li>
<li>heat absorbed or released by the gas in each process,</li>
<li>the total work done by the gas during the complete cycle.<br/>
	Express your answer in terms of the gas constant R.</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>The process A&nbsp;<span class="math-tex">{tex}\\rightarrow{/tex}</span>&nbsp;B is isobaric.<br />
	<span class="math-tex">{tex}\\therefore \\frac VT{/tex}</span>&nbsp;= constant<br />
	Hence&nbsp;<span class="math-tex">{tex}\\frac{V_{A}}{T_{A}}=\\frac{V_{B}}{T_{B}}{/tex}</span><br />
	or T<sub>B</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{V_{B}}{V_{A}} \\cdot T_{A}{/tex}</span>&nbsp;= 2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;300 = 600 K = 327<span class="math-tex">{tex}{ }^{\\circ} \\mathrm{C}{/tex}</span></li>
	<li>The heat absorbed in the process A&nbsp;<span class="math-tex">{tex}\\rightarrow{/tex}</span> B is given by<br />
	Q<sub>1</sub> = nC<sub>p</sub> dT = 2<span class="math-tex">{tex}(\\frac {5R}2){/tex}</span>(600 - 300) = 1500 R<br />
	The process B&nbsp;<span class="math-tex">{tex}\\rightarrow{/tex}</span>&nbsp;C is isothermal. The heat absorbed is given by<br />
	Q<sub>2</sub> = W<sub>2</sub> = nRT<sub>B</sub> log&nbsp;<span class="math-tex">{tex}(\\frac {V_D}{V_B}){/tex}</span><br />
	= 2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;R&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;600 log<sub>e</sub>&nbsp;2 = 1200 R&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;0.693 = 8316 R<br />
	The process C&nbsp;<span class="math-tex">{tex}\\rightarrow{/tex}</span>&nbsp;D is isochoric. The heat released is given by<br />
	Q<sub>2</sub> = nC<sub>v&nbsp;</sub>dT<span style="font-size: 10.8333px;">&nbsp;</span>=&nbsp;<span class="math-tex">{tex}2 \\times \\frac{3}{2} R \\ \\times{/tex}</span>&nbsp;(300 - 600) = -900 E<br />
	The process D&nbsp;<span class="math-tex">{tex}\\rightarrow{/tex}</span>&nbsp;A is isothermal. The heat released is given by<br />
	Q<sub>4</sub> = nRT<sub>A&nbsp;</sub>log<sub>e</sub><span style="font-size: 10.8333px;">&nbsp;<span class="math-tex">{tex}\\frac{V_{A}}{V_{D}}{/tex}</span>&nbsp;</span>= 2 R&nbsp;&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;300&nbsp;<sub>&nbsp;</sub>log<sub>e</sub>&nbsp;<span class="math-tex">{tex}\\frac 14{/tex}</span><br />
	= -1200 R log<sub>e&nbsp;</sub>2 = -831.6 R</li>
	<li>The total work done by the gas during the complete cycle,<br />
	W = Q<sub>1</sub>&nbsp;+&nbsp;Q<sub>2</sub> +&nbsp;Q<sub>3</sub> + Q<sub>4</sub><br />
	= 1500 R + 8316 R - 900 R - 8316 R<br />
	= 600 R</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>If a person puts an ice cube into a glass of warm lemon juice and later forgets to drink it, then after a while, the person will notice that the ice has melted but the temperature of the lemonade has cooled. This is because the total amount of heat in the system has remained the same, but has just reached an equilibrium, where both the ice cube and the lemon juice are at the same temperatures. The lemon juice will eventually become warmer again when the heat from the environment is transferred to the glass itself.<br />
<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1607601180-4qfj5j.jpg" style="height:200px; width:146px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>In a thermal process, the pressure of a fixed mass of a gas is changed in such a manner that the gas molecules give out the heat of 30J and work of 10J is done on the gas. If the initial internal energy of the gas was 40 J, find&nbsp;the final internal energy ?<strong> (2)</strong></li>
	<li>What is the concept of the zeroth law of thermodynamics? <strong>(1)</strong></li>
	<li>The internal energy of the system increases by 60 J when 140 J of heat is added to the gaseous&nbsp;system. Calculate the amount of work done.<strong> (1)</strong></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>dQ = -30J, dW = -10&nbsp;J,&nbsp;U<sub>1</sub> = 40J<br />
	By 1st law of thermodynamics,<br />
	dQ = dU + dW<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;dU = dQ - dW<br />
	= -30 + 10&nbsp;= -20J<br />
	Final internal energy,&nbsp;U<sub>2</sub>&nbsp;= U<sub>1</sub> + dU<br />
	= 40&nbsp;- 20&nbsp;= 20&nbsp;J</p>
	</li>
	<li>
	<p><strong>The Zeroth Law of Thermodynamics:</strong> It states that if two bodies are each in thermal equilibrium with some third body, then they are also in equilibrium with each other. Thermal equilibrium means that two bodies have same temperature.<br />
	So Zeroth Law of Thermodynamics leads to the concept of temperature.</p>
	</li>
	<li>
	<p>dW = dQ - dU = 140 - 60 = 80 J</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>If a person puts an ice cube into a glass of warm lemon juice and later forgets to drink it, then after a while, the person will notice that the ice has melted but the temperature of the lemonade has cooled. This is because the total amount of heat in the system has remained the same, but has just reached an equilibrium, where both the ice cube and the lemon juice are at the same temperatures. The lemon juice will eventually become warmer again when the heat from the environment is transferred to the glass itself.<br />
<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1607601180-4qfj5j.jpg" style="height:200px; width:146px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>In a thermal process, the pressure of a fixed mass of a gas is changed in such a manner that the gas molecules give out the heat of 30J and work of 10J is done on the gas. If the initial internal energy of the gas was 40 J, find&nbsp;the final internal energy ?</p>
	</li>
	<li>
	<p>What is the concept of the zeroth law of thermodynamics?</p>
	</li>
	<li>
	<p>A thermos bottle containing coffee is vigorously shaken. If coffee is considered as a system, then the temperature of coffee will ________.</p>
	</li>
	<li>
	<p>The internal energy of the system increases by 60 J when 140 J of heat is added to the gaseous&nbsp;system. Calculate the amount of work done.</p>
	</li>
	<li>
	<p>What does the first law of thermodynamics tell us?</p>
	</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>dQ = -30J, dW = -10&nbsp;J,&nbsp;U<sub>1</sub> = 40J<br />
	By 1st law of thermodynamics,<br />
	dQ = dU + dW<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;dU = dQ - dW<br />
	= -30 + 10&nbsp;= -20J<br />
	Final internal energy,&nbsp;U<sub>2</sub>&nbsp;= U<sub>1</sub> + dU<br />
	= 40&nbsp;- 20&nbsp;= 20&nbsp;J</p>
	</li>
	<li>
	<p><strong>The Zeroth Law of Thermodynamics:</strong> It states that if two bodies are each in thermal equilibrium with some third body, then they are also in equilibrium with each other. Thermal equilibrium means that two bodies have same temperature.<br />
	So Zeroth Law of Thermodynamics leads to the concept of temperature.</p>
	</li>
	<li>
	<p>increase</p>
	</li>
	<li>
	<p>dW = dQ - dU = 140 - 60 = 80 J</p>
	</li>
	<li>
	<p>The first law of thermodynamics is the law of conservation of energy, that is&nbsp;energy cannot be created or destroyed but is converted from one form to another.</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>In a small but crowded room, we start to feel very warm and will start sweating. The heat from our body is transferred to sweat.&nbsp;As the sweat absorbs more and more heat, it evaporates from your body, becoming more disordered and transferring heat to the air, which heats up the air temperature of the room.&nbsp;Many sweating people in a crowded room, that acts as a &#39;closed system&#39; will quickly start heating things up.<br />
<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1607601185-99s7we.jpg" style="height:155px; width:150px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>State first law of thermodynamics. <strong>(2)</strong></li>
	<li>What is the 3rd law of thermodynamics?&nbsp; <strong>(1)</strong></li>
	<li>What is the internal energy defined as?&nbsp; <strong>(1)</strong></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>The first law of thermodynamics defines&nbsp;the internal energy (E) as equal to the difference of the heat transfer (Q) into a system and the work (W) done by the system.<br />
	Q = <span class="math-tex">{tex}\\triangle{/tex}</span>E + W</li>
	<li>The third law of thermodynamics states that&nbsp;the entropy of a system approaches a constant value as the temperature approaches absolute zero. The entropy of a system at absolute zero is typically zero, and in all cases is determined only by the number of different ground states it has.</li>
	<li>Internal energy, in thermodynamics,&nbsp;the property or state function that defines the energy of a substance in the absence of effects due to external electric, magnetic&nbsp;and other fields.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>In a small but crowded room, we start to feel very warm and will start sweating. The heat from our body is transferred to sweat.&nbsp;As the sweat absorbs more and more heat, it evaporates from your body, becoming more disordered and transferring heat to the air, which heats up the air temperature of the room.&nbsp;Many sweating people in a crowded room, that acts as a &#39;closed system&#39; will quickly start heating things up.<br />
<img alt="" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1607601185-99s7we.jpg" style="height:155px; width:150px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>State first law of thermodynamics.</p>
	</li>
	<li>
	<p>What is the 3rd law of thermodynamics?</p>
	</li>
	<li>
	<p>What is the internal energy defined as?</p>
	</li>
	<li>
	<p>When a system is in equilibrium, any change in entropy would be ________.</p>
	</li>
	<li>
	<p>What is meant by&nbsp;second law of thermodynamics?</p>
	</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>The first law of thermodynamics defines&nbsp;the internal energy (E) as equal to the difference of the heat transfer (Q) into a system and the work (W) done by the system.<br />
	Q = <span class="math-tex">{tex}\\triangle{/tex}</span>E + W</p>
	</li>
	<li>
	<p>The third law of thermodynamics states that&nbsp;the entropy of a system approaches a constant value as the temperature approaches absolute zero. The entropy of a system at absolute zero is typically zero, and in all cases is determined only by the number of different ground states it has.</p>
	</li>
	<li>
	<p>Internal energy, in thermodynamics,&nbsp;the property or state function that defines the energy of a substance in the absence of effects due to external electric, magnetic&nbsp;and other fields.</p>
	</li>
	<li>
	<p>zero</p>
	</li>
	<li>
	<p>The second law of thermodynamics states that the total entropy of an isolated system always increases over time, or remains constant in ideal cases where the system is in a steady state or undergoing a reversible process. The increase in entropy accounts for the irreversibility of natural processes.</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Derive an expression for the work done during isothermal expansion.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Consider that 1 mole (n = 1) of a perfect gas is taken in a cylinder provided with a piston, having perfectly conducting walls and bottom.<br />
Let the cylinder be placed on a source of heat at temperature&nbsp;T. If the piston is now moved slowly outwards, the gas expands, does some work and tends to cooldown but if it absorbs required&nbsp;amount of heat from source to keep it at same temperature, then expansion is thus isothermal.&nbsp;<br />
Consider gas has initially with pressure, volume and temperature as P, V, T.<br />
Let the gas expand to a volume V<sub>2,</sub>&nbsp;when pressure reduces to P<sub>2</sub> and at the same temperature T<br />
<img data-imgur-src="Nt6xZYV.jpg" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/Nt6xZYV.jpg" style="width: 150px; height: 184px;" /><br />
If A = Area of cross-section of piston<br />
Force = Pressure <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;Area<br />
F = P <span class="math-tex">{tex}\\times{/tex}</span> A<br />
If we assume that piston moves a displacement dx,<br />
then work done : ​​​​​​&nbsp;dW = F dx<br />
dW&nbsp; = P <span class="math-tex">{tex}\\times{/tex}</span> A <span class="math-tex">{tex}\\times{/tex}</span> dx<br />
(<span class="math-tex">{tex}\\because dV = Adx{/tex}</span>)<br />
dW = P <span class="math-tex">{tex}\\times{/tex}</span> dv<br />
Total work done in increasing the volume from V<sub>1 </sub>to V<sub>2 </sub><br />
<span class="math-tex">{tex}\\int_{0}^{W}dW = \\int _ { V _ { 1 } } ^ { V _ { 2 } } P d V{/tex}</span><br />
Since, PV = nRT (from ideal gas equation)<br />
<span class="math-tex">{tex}P = \\frac { R T } { V }{/tex}</span>&nbsp; &nbsp; &nbsp; (<span class="math-tex">{tex}\\because n = 1{/tex}</span>)<br />
<span class="math-tex">{tex}W = \\int\\limits_{{V_1}}^{{V_2}} {\\frac{{RT}}{V}} dV{/tex}</span><br />
<span class="math-tex">{tex}W = RT\\int\\limits_{{V_1}}^{{V_2}} {\\frac{{dV}}{V}} {/tex}</span><br />
(<span class="math-tex">{tex}\\because{/tex}</span>&nbsp;<span class="math-tex">{tex}\\int{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{{dx}}{{x}}{/tex}</span>&nbsp;= Log<sub>e</sub><span class="math-tex">{tex}x{/tex}</span>)<br />
W = R T Log<sub>e</sub><span class="math-tex">{tex}\\left. V \\right| _ { V _ { 1 } } ^ { V _ { 2 } }{/tex}</span>&nbsp;<br />
W = R T [Log<sub>e</sub>V<sub>2</sub> - Log<sub>e</sub>V<sub>1</sub>]&nbsp;<br />
<span class="math-tex">{tex}\\left( \\because Log \\; \\mathrm { m } - Log \\; \\mathrm { n } = Log \\frac { m } { n } \\right){/tex}</span><br />
W = R T Log<sub>e</sub> <span class="math-tex">{tex}\\frac { V _ { 2 } } { V _ { 1 } }{/tex}</span>&nbsp;<br />
(<span class="math-tex">{tex}\\because{/tex}</span>Log<sub>e</sub>a = 2.303Log<sub>10</sub>a)<br />
W = 2.303RTLog<sub>10</sub> <span class="math-tex">{tex}\\left( \\frac { V _ { 2 } } { V _ { 1 } } \\right){/tex}</span><br />
As P<sub>1</sub> V<sub>1</sub> = P<sub>2</sub> V<sub>2</sub><br />
<span class="math-tex">{tex}\\frac { P _ { 1 } } { P _ { 2 } } = \\frac { V _ { 2 } } { V _ { 1 } }{/tex}</span>​​​​​​​<br />
So W = 2.303 R T Log<sub>10</sub> <span class="math-tex">{tex}\\left( \\frac { P _ { 1 } } { P _ { 2 } } \\right){/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Derive the equation of state for adiabatic change.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Consider 1 mol&nbsp;of an ideal gas enclosed in a cylinder fitted with a perfectly frictionless piston.&nbsp;</p>

<p>Let P = initial pressure, V = initial volume and T = Initial temperature of the gas.<br />
<br />
Suppose a small amount of heat dQ is given to the system. The heat is spent in two ways:-</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>The heat required in increasing temperature of the gas in very small range dT at constant volume = C<sub>v</sub>dT</li>
	<li>The heat required in the expansion of the gas by very small volume dV = PdV</li>
</ol>

<p>So, dQ = C<sub>V</sub> dT + PdV<br />
In an adiabatic process, no heat exchange takes place,<br />
So, dQ = 0<br />
C<sub>v</sub>dT + PdV = 0 ...(i)<br />
According to the standard gas equation,<br />
PV = RT<br />
Differentiate&nbsp;both sides,<br />
PdV + VdP = RdT + TdR<br />
(dR = 0, as R is a gas constant)<br />
<span class="math-tex">{tex}\\mathrm { d } \\mathrm { T } = \\frac { PdV + VdP} { R }{/tex}</span><br />
Using this equation in (i)<br />
<span class="math-tex">{tex}{ \\mathrm { C_v } } \\left( \\frac { PdV + VdP} { R } \\right) + \\mathrm { P } \\mathrm { dV } = \\mathrm { 0}{/tex}</span><br />
C<sub>v</sub>PdV + C<sub>v</sub>VdP + RPdV = 0<br />
(C<sub>v</sub> + R) PdV + C<sub>v</sub>VdP = 0 ...(ii)<br />
As, C<sub>p</sub> - C<sub>v</sub> = R<br />
or C<sub>p</sub> = R + C<sub>v</sub><br />
So equation (ii) becomes<br />
C<sub>p</sub>PdV + C<sub>v</sub>VdP = 0<br />
Divide above equation by C<sub>v</sub>PV<br />
<span class="math-tex">{tex}\\frac { C _ { P } P d V } { C _ { V } P V } + \\frac { C _ { V } V d P } { C _ { V } P V } = 0 \\left( \\because \\frac { C _ { P } } { C _ { V } } = \\gamma \\right){/tex}</span><br />
<span class="math-tex">{tex}\\gamma \\frac { d V } { V } + \\frac { d P } { P } = 0{/tex}</span><br />
Now, integrate both side,<br />
<span class="math-tex">{tex}\\gamma \\int \\frac { d V } { V } + \\int \\frac { d P } { p } = \\int 0{/tex}</span><br />
<span class="math-tex">{tex}\\gamma{/tex}</span>Log<sub>e</sub> V + Log<sub>e</sub> P = Constant<br />
Loge<span class="math-tex">{tex}V^{\\gamma}{/tex}</span> + Log<sub>e</sub>P = Constant</p>

<p>(<span class="math-tex">{tex}\\because{/tex}</span>&nbsp;aLog<sub>e</sub>b = Log<sub>e</sub>b<sup>a</sup>)</p>

<p>Log<sub>e</sub> <span class="math-tex">{tex}PV ^ {\\gamma}{/tex}</span> = Constant</p>

<p>(<span class="math-tex">{tex}\\because{/tex}</span>&nbsp;Log<sub>e</sub>a + Log<sub>e</sub>b = Log<sub>e</sub>ab)<br />
&nbsp;</p>

<p><span class="math-tex">{tex} PV^ {\\gamma}{/tex}</span>&nbsp;= e<sup>(Constant)</sup><br />
<span class="math-tex">{tex}PV^ {\\gamma} = k{/tex}</span><br />
where, k = another constant</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Consider that an ideal gas (<em>n&nbsp;</em>moles) is expanding in a process given by&nbsp;P<em>&nbsp;</em>= f (V), which passes through a point (V<sub>0</sub>, P<sub>0</sub>). Show that the gas is absorbing heat at (P<sub>0</sub>, V<sub>0</sub>)<em>&nbsp;</em>if the slope of the curve P = f (V) is larger than the slope of the adiabat passing through (P<sub>0</sub>, V<sub>0</sub>).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>An&nbsp;<b>adiabatic process</b>&nbsp;is one in which no heat is gained or lost by the system. The first law of thermodynamics with Q=0 shows that all the change in internal energy is in the form of work done.&nbsp;<br />
Slope of graph at&nbsp;<span class="math-tex">{tex}\\left( V _ { 0 } , P _ { 0 } \\right) = \\left( \\frac { d P } { d V } \\right) _ { \\left( V _ { \\mathrm { e } } P _ { 0 } \\right) }{/tex}</span>&nbsp;<br />
P = f(V)<strong>&nbsp;</strong>for adiabatic process&nbsp;<span class="math-tex">{tex}P V ^ { \\gamma }{/tex}</span>&nbsp;= constant (K)<br />
Or&nbsp;<span class="math-tex">{tex}P = \\frac { K } { V ^ { \\gamma } } \\text { or } \\frac { d P } { d V } = K ( - \\gamma ) V ^ { - \\gamma - 1 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\frac { d P } { d V } = - \\gamma P V ^ { \\gamma } V ^ { - \\gamma } V ^ { - 1 } = - \\frac { \\gamma P } { V }{/tex}</span><br />
<span class="math-tex">{tex}\\left( \\frac { d P } { d V } \\right) _ { \\left( P_o , V _ { 0 } \\right) } = \\frac { - \\gamma P _ { 0 } } { V _ { 0 } }{/tex}</span>&nbsp;Heat absorbed by in the process&nbsp;P = f(V)<br />
dQ = dU + dW<br />
dQ = nC<sub>V</sub>dT + PdV .....&nbsp;( i )<br />
PV = nRT<br />
<span class="math-tex">{tex}T = \\frac { P V } { n R } = \\frac { V } { n R } f ( V ){/tex}</span><br />
<span class="math-tex">{tex}\\frac { d T } { d V } = \\frac { 1 } { n R } \\left[ f ( V ) + V f ^ { \\prime } ( V ) \\right]{/tex}</span><br />
<span class="math-tex">{tex}\\frac { d Q } { d V } = n C v \\frac { d T } { d V } + P \\cdot \\frac { d V } { d V } = \\frac { n C v } { n R } \\left[ f ( V ) + V f ^ { \\prime } ( V ) \\right] + P{/tex}</span><br />
<span class="math-tex">{tex}\\left( \\frac { d Q } { d V } \\right) _ { V - V _ { 0 } } = \\frac { C v } { R } \\left[ f \\left( V _ { 0 } \\right) + V _ { 0 } f ^ { \\prime } \\left( V _ { 0 } \\right) \\right] + f \\left( V _ { 0 } \\right){/tex}</span>&nbsp;[ <span class="math-tex">{tex}\\because{/tex}</span> P = f (V) given]&nbsp;<br />
<span class="math-tex">{tex}= f \\left( V _ { 0 } \\right) \\left[ \\frac { C _ { V } } { R } + 1 \\right] + V _ { 0 } f ^ { \\prime } \\left( V _ { 0 } \\right) \\frac { C _ { V } } { R }{/tex}</span><br />
<span class="math-tex">{tex}C _ { P } - C _ { V } = R \\Rightarrow \\frac { C _ { P } } { C _ { V } } - 1 = \\frac { R } { C _ { V } }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\gamma - 1 = \\frac { R } { C _ { V } } \\Rightarrow C _ { V } = \\frac { R } { \\gamma - 1 } \\Rightarrow \\frac { C _ { V } } { R } = \\frac { 1 } { \\gamma - 1 }{/tex}</span><br />
<span class="math-tex">{tex}\\left( \\frac { d Q } { d V } \\right) _ { V - V _ { 0 } }{/tex}</span><span class="math-tex">{tex}= f \\left( V _ { 0 } \\right) \\left[ \\frac { 1 } { \\gamma - 1 } + 1 \\right] + V _ { 0 } f ^ { \\prime } \\left( V _ { 0 } \\right) \\frac { 1 } { \\gamma - 1 }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}= f \\left( V _ { 0 } \\right) \\left[ \\frac { 1 + \\gamma - 1 } { \\gamma - 1 } \\right] + \\frac { V _ { 0 } f ^ { \\prime } \\left( V _ { 0 } \\right) } { \\gamma - 1 }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { \\gamma } { ( \\gamma - 1 ) } f \\left( V _ { 0 } \\right) + V _ { 0 } \\frac { f ^ { \\prime } \\left( V _ { 0 } \\right) } { \\gamma - 1 }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { ( \\gamma - 1 ) } \\left[ \\gamma f \\left( V _ { 0 } \\right) + V _ { 0 } f ^ { \\prime } \\left( V _ { 0 } \\right) \\right]{/tex}</span>&nbsp;<span class="math-tex">{tex}\\left( \\because f \\left( V _ { 0 } \\right) = P _ { 0 } \\right){/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\left( \\frac { d Q } { d V } \\right) _ { V - V _ { 0 } }{/tex}</span>&nbsp;<span class="math-tex">{tex}= \\frac { 1 } { ( r - 1 ) } \\left[ \\gamma P _ { 0 } + V _ {0} f ^ { \\prime } \\left( V _ { 0 } \\right) \\right]{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\therefore \\left( \\frac { d Q } { d V } \\right) _ { V - V _ { 0 } } &gt; 1 {/tex}</span>&nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span> and <span class="math-tex">{tex}\\gamma &gt; 1{/tex}</span> so <span class="math-tex">{tex}\\frac { 1 } { \\gamma - 1 }{/tex}</span> is + ve<br />
<span class="math-tex">{tex}\\therefore \\gamma P _ { 0 } + V _ { 0 } f ^ { \\prime } \\left( V _ { 0 } \\right) &gt; 0{/tex}</span><br />
<span class="math-tex">{tex}V _ { 0 } f ^ { \\prime } \\left( V _ { 0 } \\right) &gt; - \\gamma P _ { 0 }{/tex}</span><br />
<span class="math-tex">{tex}f ^ { \\prime } \\left( V _ { 0 } \\right) &gt; \\frac { - \\gamma P _ { 0 } } { V _ { 0 } }{/tex}</span>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1352-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_KINETIC_THEORY = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The degree of freedom of a triatomic gas is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">1</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">2</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">6</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>A triatomic (non-linear) gas molecule has 3 degrees of freedom due to translatory motion and 3 degrees of freedom due to rotatory motion.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">8</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A gas behaves&nbsp;as an ideal gas at</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">low pressure and high temperature</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>A gas behaves as an ideal gas at low pressure and high temperature when the attractive forces between the molecules become negligible.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">low pressure and low temperature</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">high pressure and low temperature</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">high pressure and high temperature</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The mean kinetic energy of one mole of gas per degree of freedom (on the basis of kinetic theory of gases) is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2} k T{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{3}{2} k T{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{3}{2} R T{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2} RT{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Mean kinetic energy per mole of a gas per degree of freedom = (<span class="math-tex">{tex}\\frac 12{/tex}</span>) RT.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The collisions of the molecules of an ideal gas are</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">elastic</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>As per kinetic theory of gases the molecules are spherical in shape and collisions among molecules and the collisions of molecules with the walls of container are elastic.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">inelastic</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">completely inelastic</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">partially elastic</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The average energy associated with each translational degree of freedom is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{1}{2} k_B T{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Average energy associated with each translational degree of freedom is <span class="math-tex">{tex}\\frac{1}{2} k_B T{/tex}</span>.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{3}{2} k_B T{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">k<sub>B</sub>T</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">2k<sub>B</sub>T</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two gases A and B having same pressure P, volume V and temperature T are mixed. If mixture has volume and temperature as V and T respectively, then pressure of mixture is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">P</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">3P</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">2P</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>According to Dalton&#39;s law of partial pressures,<br />
P&#39; = P<sub>1</sub> + P<sub>2</sub> = P + P = 2P</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">4P</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The temperature of a gas is raised from 27&deg;C to 927&deg;C. The r.m.s. molecular speed</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">gets halved</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">gets doubled</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}v_{r m s} \\propto \\sqrt{T}{/tex}</span><br />
<span class="math-tex">{tex}\\frac{v_{r m s}\\left(927^{\\circ} \\mathrm{C}\\right)}{v_{r m s}\\left(27^{\\circ} \\mathrm{C}\\right)}=\\sqrt{\\frac{927+273}{27+273}}{/tex}</span><br />
<span class="math-tex">{tex}=\\sqrt{\\frac{1200}{300}}{/tex}</span>&nbsp;= 2<br />
v<sub>rms</sub>(927&deg;C) = 2v<sub>rms</sub>(27&deg;C)</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">gets times the earlier value</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">remains unchanged</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The two gases with the ratio 3 : 2 of their masses in a container are at a temperature T. The ratio of the kinetic energies of the molecule of two gases is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text">1 : 1</span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl">1 : 1</div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text">3 : 2</span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text">9 : 4</span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text">4 : 9</span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The mean free path of molecules of a gas, (radius r) is inversely proportional to</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">r<sup>3</sup></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">r<sup>2</sup></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\bar{\\lambda}=\\frac{1}{\\sqrt{2} \\pi n d^{2}}=\\frac{1}{4 \\sqrt{2} \\pi n r^{2}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\bar{\\lambda} \\propto \\frac{1}{r^{2}}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">r</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{r}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Boyle&rsquo;s law is applicable for a/an</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">adiabatic process</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">isothermal process</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><html><body><p>Boyle's law: For a given mass of an ideal gas at constant temperature, the volume of a gas is inversely proportional to its pressure.<br/>
<img alt="" data-imgur-src="hFxPLTI.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614246728-gpy47t.jpg" style="width: 250px; height: 135px;"/><br/>
So we can say that when the temperature is constant, Boyle's law is applicable.<br/>
i.e. PV = nRT = constant<br/>
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> PV = constant (at constant temperature)<br/>
i.e.. <span class="math-tex">{tex}\\frac {p \\propto 1} V{/tex}</span> - [where, P = pressure. Ve = volume]<br/>
So, this law is applicable for an isothermal process, in which temperature remains constant.</p></body></html></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">isobaric process</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">isochoric process</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The ratio of the specific heats <span class="math-tex">{tex}\\frac{C_{p}}{C_{V}}=\\gamma{/tex}</span> in terms of degrees of freedom (n) is given by</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\left(1+\\frac{n}{3}\\right){/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\left(1+\\frac{2}{n}\\right){/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}C_{V}=\\frac{n}{2} R, C_{P}=\\left(\\frac{n}{2}+1\\right) R{/tex}</span><br />
<span class="math-tex">{tex}\\gamma=\\frac{C_{P}}{C_{V}}=\\frac{\\frac{n}{2}+1}{\\frac{n}{2}}=1+\\frac{2}{n}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\left(1+\\frac{n}{2}\\right){/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\left(1+\\frac{1}{n}\\right){/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The internal energy of an ideal gas is in the form of</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text">kinetic energy of molecules</span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl">kinetic energy of molecules</div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text">potential energy of molecules</span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text">Both kinetic and potential energy of molecules</span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text">gravitational potential energy of molecules</span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>At 0K, which of the following properties of gas will be zero?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">kinetic energy</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>At 0 K, all molecular motion stops, so kinetic energy becomes zero.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">potential energy</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">vibrational energy</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">density</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Root mean square speed of the molecules of ideal gas is v. If pressure is increased two times at constant temperature, then the rms speed will become</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{v}{2}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">v</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Pressure has no effect on the rms speed of gas molecules. When pressure increases n times, density <span class="math-tex">{tex}\\rho{/tex}</span> also increases n times. The ratio&nbsp;<span class="math-tex">{tex}\\frac P \\rho{/tex}</span> remains constant.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">2v</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">4v</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>According to the kinetic theory of gases, molecules of a gas behave like</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">inelastic spheres</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">perfectly elastic rigid spheres</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>According to the kinetic theory of gases, gas molecules behave as perfectly elastic rigid spheres.</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">perfectly elastic non-rigid spheres</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">inelastic non-rigid spheres</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>What do you mean by degrees of freedom of a gas molecule? Write the number of degrees of freedom for a monatomic gas.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Degrees of freedom of a gas molecule is the minimum number of coordinates (number of independent variables) required to completely specify the position (state of motion or energy) of it. For a monatomic gas e.g.,&nbsp;He, Ne, etc., a molecule can have translational motion in any direction in the container and hence its speed v can be supposed to be consisting of three components v<sub>x</sub>, v<sub>y</sub>, and v<sub>z</sub> along three principal axes and, thus, have three degrees of translational motion. A monatomic gas molecule does not possess rotational or vibrational motion. So, a total number of degrees of freedom per molecule of a monatomic gas is three only.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Write any four fundamental postulates of the kinetic theory of an ideal gas.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The main postulates of the KMT are as follows:</p>

<ul>
	<li>The particles in a gas are in constant, random motion.</li>
	<li>The combined volume of the particles is negligible.</li>
	<li>The particles exert no forces on one another</li>
	<li>Any collisions between the particles are completely elastic</li>
</ul></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>What is meant free path of a gas molecule? On what factors does the mean free path depend?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The mean free path is the average distance travelled by a moving particle between successive collisions with the particles, which modify its direction or energy or other particle properties. factors depend on mean free path:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>radius of the molecule (size of the molecule)</li>
	<li>Pressure</li>
	<li>Temperature</li>
	<li>Density</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Show that the average kinetic energy of a gas molecule is directly proportional to the absolute temperature of the gas. Hence give the kinetic interpretation of temperature.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>We know, kinetic energy of a gas molecule,<br />
K<sub>1</sub> = <span class="math-tex">{tex}\\frac12{/tex}</span>mv<sup>2</sup><br />
Kinetic energy of n gas molecules,<br />
K = <span class="math-tex">{tex}\\frac12{/tex}</span>mv<sup>2</sup> <span class="math-tex">{tex}\\times{/tex}</span> n<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> K = <span class="math-tex">{tex}\\frac32{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> <span class="math-tex">{tex}\\frac13{/tex}</span>mnv<sup>2</sup><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> K = <span class="math-tex">{tex}\\frac32{/tex}</span> PV <span class="math-tex">{tex}\\because{/tex}</span>PV = <span class="math-tex">{tex}\\frac13{/tex}</span>mnv<sup>2</sup><br />
We know, in case of 1 mole of ideal gas, PV = RT<br />
So, Kinetic energy of gas,<br />
K = <span class="math-tex">{tex}\\frac32{/tex}</span>PV &rArr; K = <span class="math-tex">{tex}\\frac32{/tex}</span>RT<br />
<strong>From the above equation, it is clear that kinetic energy is directly proportional to absolute temperature </strong>K <span class="math-tex">{tex}\\propto{/tex}</span> T<strong>.</strong></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>Show that pressure exerted by a gas is <span class="math-tex">{tex}\\frac{2}{3}{/tex}</span>rd of the kinetic energy of gas molecules per unit volume.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>As per the kinetic theory, the pressure exerted by a gas is given by<br />
P <span class="math-tex">{tex}=\\frac{1}{3V} m n \\overline{v}^{2}{/tex}</span>&nbsp;..(i)<br />
Here, m = mass of a molecule, n =&nbsp;number of molecules&nbsp;and v = rms velocity of gas moleules, V = volume of gas<br />
Multiplying and dividing by 2 in eq(i), we get,<br />
PV&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac23n\\left(\\frac12m\\overline v^2\\right){/tex}</span>&nbsp;<br />
Mean kinetic energy of a&nbsp;gas molecule is&nbsp;<span class="math-tex">{tex}\\frac{1}{2} m \\overline{v}^{2}{/tex}</span>.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;PV&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac23{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;Average Kinetic Energy of n&nbsp;Molecules<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;P&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac23{/tex}</span>&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;Average kinetic energy of n molecules per unit volume<br />
Thus, the pressure exerted by a gas is <span class="math-tex">{tex}\\frac{2}{3}{/tex}</span>rd of its kinetic energy of n molecules&nbsp;per unit volume.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>At what temperature is the root mean square speed of an atom in an argon gas cylinder equal to the rms speed of a helium gas atom at - 20 &deg;C? (Atomic mass of Ar = 39.9 u, of He = 4.0 u).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Root mean square speed of Argon atom is<br />
<span class="math-tex">{tex} V_{rms1} = \\sqrt\\frac{3R T_1}{M_1} {/tex}</span>&nbsp; .......(i)&nbsp;<br />
Root mean square speed of Helium atom is given by&nbsp;&nbsp;<span class="math-tex">{tex} V_{rms2} = \\sqrt\\frac{3R T_2}{M_2} {/tex}</span>&nbsp; ......(ii)<br />
Divide equations (i) by (ii)&nbsp;<br />
<span class="math-tex">{tex}\\frac{ V_{rms1}}{V_{rms2}}​​ =\\frac {\\sqrt\\frac{3R T_1}{M_1} }{\\sqrt\\frac{3R T_2}{M_2} }{/tex}</span><br />
<span class="math-tex">{tex}= \\sqrt{ \\frac{T_1 M_2}{T_2M_2}} {/tex}</span><br />
But,&nbsp;<br />
<span class="math-tex">{tex}V_{rms1} = V_{rms2} {/tex}</span>&nbsp; &nbsp;[According&nbsp;to question]<br />
1 <span class="math-tex">{tex}= \\sqrt{ \\frac{T_1 M_2}{T_2M_2}} {/tex}</span><br />
<span class="math-tex">{tex}\\frac{M_1}{M_2} = \\frac{T_1}{T_2} {/tex}</span><br />
So,&nbsp;<br />
<span class="math-tex">{tex}T_1 = T_2 ×\\frac { M_1}{M_2} {/tex}</span><br />
Here,&nbsp;<br />
<span class="math-tex">{tex}T_2 {/tex}</span>= -20&deg;C = -20 + 273 = 253 K&nbsp;<br />
<span class="math-tex">{tex}M_1{/tex}</span>&nbsp;= 40g/mol&nbsp;<br />
= 4 g/mol&nbsp;<br />
<span class="math-tex">{tex} T_1 = 253 × \\frac{ 40 }{4 } {/tex}</span><br />
= 2530 K&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is meant by the term degrees of freedom? Obtain degrees of freedom for a molecule of monatomic, diatomic and polyatomic gases.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Degrees of freedom of a gas molecule is the minimum number of coordinates (number of independent variables) required to completely specify the position (state of motion or energy) of it.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li><strong>Monatomic gas:&nbsp;</strong>A&nbsp;monoatomic molecule like He, Ne, etc can have translational motion in any direction in the container and hence its speed v can be supposed to be consisting of three components v<sub>x</sub>, v<sub>y</sub>,&nbsp;and v<sub>z</sub> along three principal axes and, thus, have three degrees of translational motion. A monatomic gas molecule does not possess rotational or vibrational motion. So, a total number of degrees of freedom per molecule of a monatomic gas is three only.</li>
	<li><strong>Diatomic molecule:</strong> A diatomic molecule like H<sub>2</sub>, O<sub>2</sub>, N<sub>2</sub>, CO, etc., can have 3 degrees of freedom due to translational motion. Moreover, a diatomic molecule may have rotational motion as shown in&nbsp;and due to this, it can have 2 degrees of freedom per molecule. Thus, in general, a diatomic gas has 5 degrees of freedom per molecule. However, in some gases like chlorine, there are 2 additional degrees of freedom due to vibrational motion also. Hence, in that case, the total number of degrees of freedom becomes seven.</li>
	<li><strong>Polyatomic molecule:</strong> In general, a polyatomic gas molecule has 3 translational and 3 rotational degrees of freedom and a certain number (f) of vibrational modes. Thus, the total number of degrees of freedom per molecule is (6 + f). However, at low temperatures, vibrational motion does not take place and the number of degrees of freedom per molecule is 6 only.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Briefly explain the number of degrees of freedom per molecule of a</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>diatomic gas, and</li>
	<li>polyatomic gas.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li><strong>Diatomic gas:</strong> A diatomic gas molecule contains two atoms like H<sub>2</sub>, O<sub>2</sub>, N<sub>2</sub>, CO, etc., Diatomic molecules can have total 5 degrees of freedom, out of which 3 degrees of freedom are due to translatory&nbsp;motion and can have&nbsp;2 degrees of freedom per molecule due to rotational motion.&nbsp;</li>
	<li><strong>Polyatomic gas:</strong> In general, a polyatomic gas molecule has 3 translational and 3 rotational degrees of freedom and a certain number (f) of vibrational modes. Thus, a total number of degrees of freedom per molecule is (6 + f). However, at low temperatures, vibrational motion does not take place and a number of degrees of freedom per molecule are 6 only.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State and establish the law of equipartition of energy.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>The law of equipartition of energy</strong>&nbsp;for&nbsp;a dynamical system states that to be in thermal equilibrium, the total energy of the system is equally divided amongst various degrees of freedom of all its molecules, the energy of&nbsp;each degree of freedom per molecule will be <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>k<sub>B</sub>T, where k<sub>B</sub> is the Boltzmann&#39;s constant and T the temperature of the gas.<br />
The mean value of kinetic energy per gas molecule for an ideal gas, where we consider only translational motion i.e., each gas molecule was supposed to have only three degrees of freedom, is given as&nbsp;<br />
<span class="math-tex">{tex}\\frac{1}{2} m {v}^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{3}{2} k_{B} T{/tex}</span><br />
If this energy is divided equally amongst its three degrees of freedom, then we find that energy per degree of freedom<br />
<span class="math-tex">{tex}\\frac{1}{2} m {v}_{x}^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} m {v}_{y}^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} m {v}_{z}^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{3} \\times\\left(\\frac{1}{2} m {v}^{2}\\right){/tex}</span><br />
=&nbsp;<span class="math-tex">{tex}\\frac{1}{3} \\times \\frac{3}{2} k_{B} T{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{2} k_{B} T{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What do you mean by mean free path? Obtain an expression for it.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The mean free path is the average distance traveled by a moving particle (such as an atom, a molecule, a photon) between successive impacts (collisions), which modify its direction or energy or other particle properties.<br />
If a molecule moves with average speed v in a time t, the distance travelled is vt. In this time t, consider the molecule to move in an imaginary cylinder of volume <span class="math-tex">{tex}\\pi{/tex}</span>d<sup>2</sup>vt. It collides with any molecule whose center is within this cylinder. Therefore, the number of collisions is equal to the number of molecules in the volume of the imaginary cylinder. It is equal to <span class="math-tex">{tex}\\pi{/tex}</span>d<sup>2</sup>vtn. The total path length divided by the number of collisions in time t is the mean free path.<br />
Mean free path, <span class="math-tex">{tex}\\lambda=\\frac{\\text { Distance travelled }}{\\text { Number of collisions }}{/tex}</span><br />
<span class="math-tex">{tex}\\lambda=\\frac{v t}{n \\pi d^2 v t}=\\frac{1}{n \\pi d^2}{/tex}</span>&nbsp;...(i)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is the kinetic interpretation of temperature? Briefly explain the kinetic interpretation of temperature.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to the kinetic theory of gases, the pressure exerted by an ideal gas is given by&nbsp;<br />
P =&nbsp;<span class="math-tex">{tex}\\frac{1}{3} m n \\overline{v}^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{3} m \\frac{N}{V} \\overline{v}^{2}{/tex}</span><br />
where m = mass of each gas molecule, n = number of gas molecules per unit volume or N = number of gas molecules in volume V and <span class="math-tex">{tex}\\overline v{/tex}</span>&nbsp;is the rms speed of gas molecules.<br />
PV =&nbsp;<span class="math-tex">{tex}\\frac{1}{3} m N \\overline{v}^{2}{/tex}</span><br />
and for one mole of ideal gas PV =&nbsp;<span class="math-tex">{tex}\\frac{1}{3} m N_{A} \\overline{v}^{2}{/tex}</span>, where&nbsp;<span class="math-tex">{tex}N_{\\mathrm{A}}{/tex}</span>&nbsp;= Avogadro&#39;s number&nbsp;<br />
However, as per ideal gas equation for one mole of a gas,<br />
PV&nbsp;= RT<br />
Comparing two expressions for PV, we get<br />
<span class="math-tex">{tex}\\frac{1}{3} m N_{A} \\overline{v}^{2}{/tex}</span>&nbsp;= RT&nbsp;<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{1}{2} m \\overline{v}^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{3}{2} \\frac{R}{N_{A}} T{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{3}{2} k_{\\mathrm{B}} T{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Mean K.E. per molecule&nbsp;<span class="math-tex">{tex}\\propto{/tex}</span>&nbsp;T<br />
Hence, the mean kinetic energy of an ideal gas molecule is directly proportional to the temperature of gas on the Kelvin scale and it is the kinetic interpretation of temperature.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State the law of equipartition of energy and using this find the relation for the total internal energy of a mole of monoatomic gases.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The law of equipartition of energy states that &ldquo;For a system which is in thermal equilibrium, its total energy is divided equally among the degree of freedom.&rdquo;<br />
E = <span class="math-tex">{tex}\\frac32{/tex}</span> RT<br />
R = 8.314 J/k/mol = 1.99 cal/k /mol<br />
E = <span class="math-tex">{tex}\\frac32{/tex}</span> <span class="math-tex">{tex}\\times{/tex}</span> 1.99 <span class="math-tex">{tex}\\times{/tex}</span> 300<br />
E = 900 cal</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define average, root mean square and most probable speeds. Arrange them in the decreasing order of their values.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The average value is defined as the average of all the instantaneous values of an alternating quantity such as current or voltage over one complete cycle.<br />
RMS value (root mean square) is the square root of means of squares of instantaneous values. The RMS value can be evaluated by either graphical or analytical method.<br />
The most probable speed is the one which informs about the speed possessed by the maximum number of molecules of the gas.<br />
So, v<sub>rms</sub> &gt; v<sub>av</sub> &gt; v<sub>mp</sub>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Three vessels of equal capacity have gases at the same temperature and pressure. The first vessel contains neon (monatomic), the second contains chlorine (diatomic), and the third contains uranium hexafluoride (polyatomic). Do the vessels contain equal number of respective molecules? Is the root mean square speed of molecules the same in the three cases? If not, in which case is v<sub>rms</sub> the largest?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>All the three vessels have the same capacity, they have the same volume.&nbsp;Hence, each gas has the same pressure, volume, and temperature. Equal volumes&nbsp;of all the gases&nbsp;under similar conditions contain an equal number of molecules (according&nbsp;to Avogadro&#39;s hypothesis). Therefore, the number of molecules in each case is same. This number is equal to Avogadro&#39;s number, N = <span class="math-tex">{tex}6.023 \\times 10 ^ { 23 }{/tex}</span>.<br />
The root-mean-square speed (v<sub>rms</sub>) of gas of mass m, and temperature T, is given by the relation:<br />
<span class="math-tex">{tex}v _ { rms } = \\sqrt { \\frac { 3 k T } { m } }{/tex}</span><br />
Where, k is Boltzmann constant<br />
For the given gases, k and T are constants.<br />
Hence, v<sub>rms</sub> depends only on the mass of the atoms,<br />
<span class="math-tex">{tex}v _ { rms } \\propto \\sqrt { \\frac { 1 } { m } }{/tex}</span><br />
Therefore, the root-mean-square speed of the molecules in the three cases is not the same. Since neon has minimum atomic mass m, its v<sub>rms</sub> velocity is maximum.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Establish ideal gas equation.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>We know that volume V&nbsp;of gas is</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>directly proportional to the quantity of gas i.e., number N of molecules contained in the gas.&nbsp;Mathematically,<br />
	<span class="math-tex">{tex}V \\propto N{/tex}</span>&nbsp;(if P and T are constant)</li>
	<li>inversely proportional to pressure P.&nbsp;Mathematically,<br />
	<span class="math-tex">{tex}V \\propto \\frac{1}{P}{/tex}</span>&nbsp;(if N and T are constant)</li>
	<li>directly proportional to temperature T. Mathematically,<br />
	<span class="math-tex">{tex}V \\propto T{/tex}</span>&nbsp;(if N and P are constant)</li>
</ol>

<p>Combining all these, we have&nbsp;<span class="math-tex">{tex}V \\propto \\frac{N T}{P}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{P V}{N T}{/tex}</span>&nbsp;= constant = k<sub>B</sub> =&nbsp;Boltzmann&#39;s constant&nbsp;<br />
Generally, N is written as N = <span class="math-tex">{tex}\\mu N_A{/tex}</span>, where N<sub>A</sub> is the number of molecules in one mole of gas and&nbsp;<span class="math-tex">{tex}\\mu{/tex}</span> = quantity of gas in moles.<br />
​​​​​​​Hence, the above relation becomes<br />
<span class="math-tex">{tex}\\frac{P V}{T}=N k_{B}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\mu N_{A} k_{B}=\\mu R{/tex}</span><br />
Here R =&nbsp;<span class="math-tex">{tex}\\mu \\cdot N_{A}{/tex}</span>&nbsp;= gas constant for one mole of gas&nbsp;<br />
or&nbsp;<span class="math-tex">{tex}P V=\\mu R T{/tex}</span>&nbsp;<br />
It is the ideal gas equation or equation of state for an ideal gas.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Give a qualitative definition of pressure exerted by a gas on the basis of kinetic theory.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to kinetic theory, the molecules of a gas are in a state of continuous random motion within the gas container. Naturally, the molecules frequently collide against the walls of the container. As the collisions are perfectly elastic, the molecules rebound with the same speed with which they striked the walls of the container. Hence, gas molecules continuously impart some momentum to the walls. As under normal condition, even 1 cm<sup>3</sup> (or 1 mL) of gas contains 2.69 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>19</sup> molecules, it is self-evident that billions and billions of molecules would strike against the walls of the container every second. Thus, the rate of transfer of momentum will be large enough to give rise a steady force and this force is responsible for the pressure exerted by the gas.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>An air bubble of volume 1.0 cm<sup>3</sup> rises from the bottom of a lake 40 m deep at a temperature of 12 &deg;C. To what volume does it grow when it reaches the surface, which is at a temperature of 35 &deg;C?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>When the air bubble is at 40m depth, then<br />
V<sub>1</sub> = 1.0cm<sup>3</sup><br />
<span class="math-tex">{tex}= 1.0 \\times 10 ^ { - 6 } \\mathrm { m } ^ { 3 }{/tex}</span><br />
T<sub>1</sub> = 12<sup>o</sup>C<br />
= 12 + 273 = 285K<br />
P<sub>1</sub> = 1 atm + hpg<br />
<span class="math-tex">{tex}= 1.01 \\times 10 ^ { 5 } + 40 \\times 10 ^ { 3 } \\times 9.8{/tex}</span><br />
= 4,93,000 Pa<br />
When the air bubble reaches at the surface of lake,<br />
then<br />
V<sub>2</sub> =?<br />
T<sub>2</sub> = 35<sup>o</sup>C = 35 + 273K<br />
= 308K<br />
P<sub>2</sub>&nbsp;= 1 atm = 1.01 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>5</sup>&nbsp;Pa<br />
Now&nbsp;<span class="math-tex">{tex}\\frac { P _ { 1 } V _ { 1 } } { T _ { 1 } } = \\frac { P _ { 2 } V _ { 2 } } { T _ { 2 } }{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\mathrm { V } _ { 2 } = \\frac { \\mathrm { P } _ { 1 } \\mathrm { V } _ { 1 } \\mathrm { T } _ { 2 } } { \\mathrm { T } _ { 1 } \\mathrm { P } _ { 2 } }{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm { V } _ { 2 } = \\frac { 493000 \\times 1.01 \\times 10 ^ { - 6 } \\times 308 } { 285 \\times 1.01 \\times 10 ^ { 5 } }{/tex}</span><br />
<span class="math-tex">{tex}= 5.328 \\times 10 ^ { - 6 } \\mathrm { m } ^ { 3 }{/tex}</span>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A flask contains argon and chlorine in the ratio of 2 : 1 by mass. The temperature of the mixture is 27 &deg;C. Obtain the ratio of</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>average kinetic energy per molecule, and</li>
	<li>root mean square speed v<sub>rms</sub> of the molecules of the two gases.<br />
	Atomic mass of argon = 39.9 u; Molecular mass of chlorine = 70.9 u.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The important point to remember is that the average kinetic energy (per molecule) of any (ideal) gas (be it monatomic like argon, diatomic like chlorine or polyatomic) is always equal to (<span class="math-tex">{tex}\\frac{3}{2}{/tex}</span>) k<sub>B</sub>T. It depends only on temperature, and is independent of the nature of the gas.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Since argon and chlorine both have the same temperature in the flask, the ratio of average kinetic energy (per molecule) of the two gases is 1 : 1.</li>
	<li>Now <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>mv<sub>rms</sub><br />
	2 = average kinetic energy per<br />
	molecule = (<span class="math-tex">{tex}\\frac{3}{2}{/tex}</span>)&nbsp;k<sub>B</sub>T where m is the mass of a molecule of the gas. Therefore,<br />
	<span class="math-tex">{tex}\\frac{\\left({v}_{\\mathrm{rms}}^{2}\\right)_{\\mathrm{Ar}}}{\\left({v}_{\\mathrm{rms}}^{2}\\right)_{\\mathrm{c} 1}}=\\frac{(m)_{\\mathrm{Cl}}}{(m)_{\\mathrm{Ar}}}=\\frac{(M)_{\\mathrm{C} 1}}{(M)_{\\mathrm{Ar}}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{70.9}{39.9}{/tex}</span>&nbsp;= 1.77<br />
	where M denotes the molecular mass of the gas. (For argon, a molecule is just an atom of argon.) Taking square root of both sides,<br />
	<span class="math-tex">{tex}\\frac{\\left({v}_{\\mathrm{rms}}\\right)_{\\mathrm{Ar}}}{\\left({v}_{\\mathrm{rms}}\\right)_{\\mathrm{c}}}{/tex}</span>&nbsp;= 1.333<br />
	You should note that the composition of the mixture by mass is quite irrelevant to the above&nbsp;calculation. Any other proportion by mass of argon and chlorine would give the same answers to (i) and (ii), provided the temperature remains unaltered.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><ol start="1" style="list-style-type:lower-roman">
	<li>Define Absolute zero.</li>
	<li>Deduce the dimensional formula for R, using ideal gas equation<br />
	PV = nRT.</li>
	<li>Find the degree of freedom of a monoatomic gas.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>Absolute zero is the lowest possible temperature where heat energy is absent in a substance. Absolute zero is also known as zero kelvin temperature since it measures zero on the Kelvin scale.</li>
	<li>Dimensions of R <span class="math-tex">{tex}=\\frac{[\\mathrm{P}][\\mathrm{V}]}{[n][\\mathrm{T}]}{/tex}</span><br />
	<span class="math-tex">{tex}=\\frac{\\left[\\mathrm{ML}^{-1} \\mathrm{~T}^{-2}\\right]\\left[\\mathrm{L}^3\\right]}{\\left[\\mathrm{M}^0 \\mathrm{~L}^0 \\mathrm{~T}^0\\right]\\left[\\mathrm{K}^1\\right]}{/tex}</span><br />
	<span class="math-tex">{tex}=\\left[\\mathrm{ML}^2 \\mathrm{~T}^{-2} \\mathrm{~K}^{-1}\\right]{/tex}</span></li>
	<li><strong>the degree of freedom of monoatomic gas:</strong><br />
	Using formula,<strong> </strong>f = 3N - K<br />
	f = 3 <span class="math-tex">{tex}\\times{/tex}</span> 1 - 0<br />
	f = 3 - 0<br />
	f = 3<br />
	Hence, the degree of freedom for monoatomic gas is 3.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A cylinder of fixed capacity 44.8 litres contains helium gas at standard temperature and pressure. What is the amount of heat needed to raise the temperature of the gas in the cylinder by 15.0<sup>o</sup>C? (R = 8.31 J mo1<sup>-1</sup> K<sup>-1</sup>).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>At STP, 1 mole of a gas occupy 22.4 L of volume.<br />
Moles of helium in container,&nbsp;<span class="math-tex">{tex}\\mu = \\frac { 44.8 } { 22.4 }{/tex}</span>=2&nbsp; moles<br />
Now, helium is monoatomic, so, C<sub>v</sub>=&nbsp;<span class="math-tex">{tex}\\frac 32{/tex}</span>R (as, degrees of freedom for monoatomic gas = 3)<br />
Change in temperature,<br />
<span class="math-tex">{tex}\\Delta{/tex}</span>T = T<sub>2</sub>&nbsp;- T<sub>1</sub>&nbsp;=&nbsp;15&deg;C =15K<br />
Therefore, volume of gas remains constant<br />
<span class="math-tex">{tex}\\therefore \\Delta W = p \\Delta V = 0{/tex}</span><br />
<span class="math-tex">{tex}\\text {and}~ \\Delta Q = \\Delta U + \\Delta W{/tex}</span><br />
Amount of heat required,<br />
<span class="math-tex">{tex}\\Delta Q = \\Delta U = \\mu C _ { V } \\Delta T{/tex}</span><br />
<span class="math-tex">{tex}= 2 \\times \\frac { 3 } { 2 } R \\times 15 = 45 R{/tex}</span><br />
<span class="math-tex">{tex}= 45 \\times 8.31 = 374 J{/tex}</span>(since universal gas constant, R = 8.31 J mol<sup>-1</sup>&nbsp;K<sup>-1</sup>)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Molar volume is the volume occupied by 1 mol of any (ideal) gas at standard temperature and pressure (STP: 1 atmospheric pressure, 0 &deg;C). Show that it is 22.4 liters.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>One mole of an ideal gas equation relating pressure (P), volume (V), and absolute temperature (T) is given as:<br />
PV = nRT...(i)<br />
here,<br />
n = Number of moles is = 1<br />
T = absolute standard temperature&nbsp; is= 0<sup>0</sup>C = 273 K<br />
P = Standard pressure of atmosphere is given by&nbsp; = 1 atm = 76 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;13.6 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8 = 1.013 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>5</sup> Nm<sup>-2</sup><br />
Now from equation (i), we get<br />
<span class="math-tex">{tex}\\therefore V = \\frac { n R T } { P }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}= \\frac { 1 \\times 8.314 \\times 273 } { 1.013 \\times 10 ^ { 5 } }{/tex}</span>&nbsp;<br />
= 0.0224 m<sup>3</sup><br />
V = 22.4 liters&nbsp;(As, 1 liter&nbsp;= 10<sup>-3</sup>&nbsp;m<sup>3</sup>)<br />
Hence, the molar volume of an ideal gas at STP is 22.4 liters. This value is the same for all ideal gases at standard temperature and pressure.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that average kinetic energy of translation per molecule of a gas is directly proportional to the absolute temperature of gas.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to the kinetic theory of gases, the pressure p exerted by one mole of an ideal gas is<br />
<span class="math-tex">{tex}P = \\frac {1}{3}×\\frac{M}{V}× C^2{/tex}</span> M = Molar mass of the gas<br />
or <span class="math-tex">{tex}P V = \\frac { 1} { 3 } MC^2{/tex}</span>&nbsp;V = Volume of the gas<br />
Since PV = RT (for 1mole of an ideal gas at absolute temperature T)<br />
or <span class="math-tex">{tex}\\frac { 1 } { 3 } M C ^ { 2 } = R T{/tex}</span> (R = Universal gas contant)<br />
<span class="math-tex">{tex}\\therefore C ^ { 2 } = \\frac { 3 R T } { M }{/tex}</span> (T = Absolute temperature)<br />
So, <span class="math-tex">{tex}C\\propto \\sqrt { T }{/tex}</span>&nbsp;, [since R and M are constants for the gas]<br />
Also, <span class="math-tex">{tex}\\frac { 1 } { 3 } M C ^ { 2 } = R T{/tex}</span>....(i)<br />
Dividing equation (i) by number of molecules of the gas = N<br />
<span class="math-tex">{tex}\\frac { 1 M } { 3 N } C ^ { 2 } = \\frac { R } { N } T{/tex}</span> (K = Boltzmann&#39;s constant)<br />
<span class="math-tex">{tex}\\Rightarrow\\frac { 1 } { 3 } m C ^ { 2 } = K T \\quad {/tex}</span>[m = M/N = mass of one single molecule of the gas]<br />
or <span class="math-tex">{tex}\\frac { 1 } { 2 } m C^ { 2 } = \\frac { 3 } { 2 } K T{/tex}</span><br />
Since, <span class="math-tex">{tex}\\frac { 1 } { 2 } m C ^ { 2 }{/tex}</span> = average kinetic energy of translation per molecule of the gas<br />
So, <span class="math-tex">{tex}\\frac { 1 } { 2 } m C ^ { 2 } \\propto T{/tex}</span>&nbsp;....(ii)<br />
as <span class="math-tex">{tex}\\frac { 3 } { 2 } K ={/tex}</span> constant</p>

<p>Hence it is proved from equation (ii) that the average kinetic energy of translation per molecule of an ideal gas is directly proportional to the absolute temperature of the gas.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Establish the relation between&nbsp;<span class="math-tex">{tex}\\gamma (= \\frac { C _ { P } } { C _ { V } } ){/tex}</span> and degrees of freedom (n).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Now <span class="math-tex">{tex}\\gamma= \\frac { C _ { P } } { C _ { V } }{/tex}</span></p>

<p>Where C<sub>P</sub> = specific heat at constant pressure<br />
and C<sub>V</sub> = Specific heat at constant volume.<br />
and n = Degrees of freedom <span class="math-tex">{tex}\\to{/tex}</span>&nbsp;which is the total number of co-ordinates or independent quantities required to describe completely the position and configuration of the system.<br />
Suppose, a polyatomic gas molecule has &lsquo;n&rsquo; degrees of freedom.</p>

<p><span class="math-tex">{tex}\\therefore{/tex}</span> Total energy associated with one mole molecule of the gas with<br />
N<sub>A</sub> = Total number of molecules (Avogadro&#39;s number)<br />
R = Universal Gas Constant<br />
R = N<sub>A</sub>K<sub>B</sub><br />
K<sub>B</sub> = Boltzmann Constant<br />
<span class="math-tex">{tex}E = n \\times \\frac { 1 } { 2 } \\mathrm { K_BT } \\times \\mathrm { N _A} = \\frac { n } { 2 } R T{/tex}</span>&nbsp;....(i) (from law of equipartition of energy, we know that for each degree of freedom of a gas molecule, energy =&nbsp;<span class="math-tex">{tex}\\frac {1}{2} K_BT{/tex}</span>)</p>

<p>As,<br />
Specific heat at constant volume,</p>

<p><span class="math-tex">{tex}C _ { V } = \\frac { d E } { d T }{/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow C _ { V } = \\frac { d } { d T } \\left( \\frac { n } { 2 } R T \\right){/tex}</span>&nbsp;[putting the value of energy E from equation (i)]</p>

<p><span class="math-tex">{tex}\\therefore C _ { V } = \\frac { n } { 2 } R{/tex}</span></p>

<p>Now Specific heat at constant Pressure, C<strong><sub>P</sub></strong> = C<strong><sub>V</sub></strong> + R (using known equation C<sub>P</sub>&nbsp;- C<sub>V</sub> = R)</p>

<p><span class="math-tex">{tex}\\therefore C _ { P } = \\frac { n } { 2 } R + R{/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow C _ { P } = \\left( \\frac { n } { 2 } + 1 \\right) R{/tex}</span></p>

<p>As, <span class="math-tex">{tex}\\gamma = \\frac { C _ { P } } { C _ { V } }{/tex}</span></p>

<p><span class="math-tex">{tex}\\therefore \\gamma = \\frac { \\left( \\frac { n } { 2 } + 1 \\right) R } { \\frac { n } { 2 } R }{/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow \\gamma = \\left( \\frac { n } { 2 } + 1 \\right) \\times \\frac { 2 } { n }{/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow \\gamma = \\frac { 2} { n } \\times (\\frac { n } { 2 } + 1) {/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow \\gamma= \\left( 1 + \\frac { 2 } { n } \\right){/tex}</span>&nbsp;, This is the required relation&nbsp;<span class="math-tex">{tex}\\gamma {/tex}</span>&nbsp;and degrees of freedom, n.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>On the basis of equipartition law of energy obtain an expression for specific heat capacity of a solid.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>In a solid, atoms are closely packed. In solids translational as well as rotational motions are not possible. However, solid atoms may vibrate to and fro about their mean positions. An oscillation in one dimension gives rise to two degrees of freedom (one due to kinetic energy changes and other due to potential energy changes). Hence in three-dimensional space, each atom of a solid has 3 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;2 = 6 degrees of freedom.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;The average value of energy associated with each atom of a solid<br />
=&nbsp;<span class="math-tex">{tex}6 \\times \\frac{1}{2} k_{B} T{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}3 k_{\\mathrm{B}} T{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Mean value of internal energy of one mole of a solid (having N<sub>A</sub> atoms)<br />
U =&nbsp;<span class="math-tex">{tex}N_{A} \\times 3 k_{B} T{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}3\\left(N_{A} \\cdot k_{B}\\right) T{/tex}</span>&nbsp;= 3RT<br />
As in a solid on heating the volume remains almost unchanged i.e., <span class="math-tex">{tex}\\Delta{/tex}</span>V = 0 and hence according to the First Law of Thermodynamics, we have&nbsp;<br />
<span class="math-tex">{tex}\\Delta Q=\\Delta U+P d V=\\Delta U{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Atomic specific heat of solid C =&nbsp;<span class="math-tex">{tex}\\frac{\\Delta Q}{\\Delta T}=\\frac{\\Delta U}{\\Delta T}{/tex}</span>&nbsp;= 3R<br />
Thus, a solid has atomic specific heat of 3R = 24.9 J mol<sup>-1</sup> K<sup>-1</sup>. The result is in close agreement with experimental observations for most solids with few exceptions like carbon and boron.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>State Charles law. Obtain it from kinetic theory of gases.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Charle&#39;s law</strong> states that pressure remaining constant, the volume of a given mass of an ideal gas is directly proportional to its temperature on the kelvin scale. Mathematically, if pressure P remains constant, then for a given mass m of gas :&nbsp;<br />
<span class="math-tex">{tex}V \\propto T{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}\\frac{V_{1}}{V_{2}}=\\frac{T_{1}}{T_{2}}{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}\\frac{V}{T}{/tex}</span>&nbsp;= a constant.<br />
<strong>Charle&#39;s law from kinetic theory:</strong> According to the kinetic theory of gases, the pressure exerted by&nbsp;a gas is given by<br />
P =&nbsp;<span class="math-tex">{tex}\\frac{1}{3} m n \\overline{v}^{2}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{3} \\frac{m N}{V} \\overline{v}^{2}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;V =&nbsp;<span class="math-tex">{tex}\\frac{1}{3} \\frac{m N}{P} \\overline{v}^{2}{/tex}</span>&nbsp;...(i)<br />
As for a given quantity of gas number of molecules of a gas is constant, hence under a given&nbsp;pressure, we have&nbsp;<span class="math-tex">{tex}V \\propto m \\overline{v}^{2}{/tex}</span>&nbsp;....(ii)<br />
But according to kinetic theory, the average kinetic energy of a gas molecule is directly proportional to temperature of gas on kelvin scale i.e.,<br />
<span class="math-tex">{tex}\\frac{1}{2} m \\overline{v}^{2} \\propto T{/tex}</span>&nbsp;....(iii)<br />
Combining (ii) and (iii), we get<br />
<span class="math-tex">{tex}V \\propto T{/tex}</span>&nbsp;...(iv)<br />
Thus, pressure remaining constant, for a given mass volume of gas is directly proportional to its temperature on kelvin scale. It is the Charle&#39;s law.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State the law of equipartition energy of a dynamic system and use it to find the values of internal energy and the ratio of the specific heats of (a) monoatomic, (b) diatomic and (c) triatomic gas molecules.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>According to the law of equipartition of energy, for any dynamic system in thermal equilibrium, the total energy for the system is equally divided among the degree of freedom.<br />
Monoatomic molecule<br />
<span class="math-tex">{tex}\\mathrm{C}_{\\mathrm{V}}=\\frac{d \\mathrm{U}}{d \\mathrm{~T}}=\\frac{d}{d \\mathrm{~T}}\\left[\\frac{3}{2} \\mathrm{RT}\\right] ; \\mathrm{C}_{\\mathrm{V}}=\\left[\\frac{3}{2} \\mathrm{R}\\right]{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{C}_{\\mathrm{P}}=\\mathrm{C}_{\\mathrm{V}}+\\mathrm{R}=\\frac{3}{2} \\mathrm{R}+\\mathrm{R}=\\frac{5}{2} \\mathrm{R}{/tex}</span><br />
The ratio of specific heats,<br />
<span class="math-tex">{tex}\\gamma=\\frac{\\mathrm{C}_{\\mathrm{P}}}{\\mathrm{C}_{\\mathrm{V}}}=\\frac{\\frac{5}{2} \\mathrm{R}}{\\frac{3}{2} \\mathrm{R}}=\\frac{5}{3}{/tex}</span> = 1.67<br />
Diatomic molecule:<br />
<span class="math-tex">{tex}\\mathrm{C}_{\\mathrm{V}}=\\frac{d \\mathrm{U}}{d \\mathrm{~T}}=\\left[\\frac{5}{2} \\mathrm{RT}\\right]=\\frac{5}{2} \\mathrm{R}{/tex}</span><br />
But, <span class="math-tex">{tex}C_P=C_V+R=\\frac{5}{2} R+R=\\frac{7}{2} R{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\quad \\gamma=\\frac{\\mathrm{C}_{\\mathrm{P}}}{\\mathrm{C}_{\\mathrm{V}}}=\\frac{\\frac{7}{2} \\mathrm{R}}{\\frac{5}{2} \\mathrm{R}}=\\frac{7}{5}=1.40{/tex}</span><br />
Energy of diatomic molecule at high temperature is equal to <span class="math-tex">{tex}\\frac{7}{2} \\mathrm{RT}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{C}_{\\mathrm{V}}=\\frac{d \\mathrm{U}}{d \\mathrm{~T}}=\\frac{d}{d \\mathrm{~T}}\\left[\\frac{7}{2} \\mathrm{RT}\\right]=\\frac{7}{2} \\mathrm{R}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\mathrm{C}_{\\mathrm{P}}=\\mathrm{C}_{\\mathrm{V}}+\\mathrm{R}=\\frac{7}{2} \\mathrm{R}+\\mathrm{R}; \\mathrm{C}_{\\mathrm{P}}=\\frac{9}{2} \\mathrm{R}{/tex}</span><br />
Triatomic molecule<br />
Linear molecule:<br />
Energy of one mole <span class="math-tex">{tex}=\\frac{7}{2} k \\mathrm{~T} \\times \\mathrm{N}_{\\mathrm{A}}=\\frac{7}{2} \\mathrm{RT}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{C}_{\\mathrm{V}}=\\frac{d \\mathrm{U}}{d \\mathrm{~T}}=\\frac{d}{d \\mathrm{~T}}\\left[\\frac{7}{2} \\mathrm{RT}\\right] ; \\mathrm{C}_{\\mathrm{V}}=\\frac{7}{2} \\mathrm{R}{/tex}</span><br />
<span class="math-tex">{tex}C_P=C_V+R=\\frac{7}{2} R+R=\\frac{9 R}{2}{/tex}</span><br />
<span class="math-tex">{tex}\\gamma=\\frac{\\mathrm{C}_{\\mathrm{P}}}{\\mathrm{C}_{\\mathrm{V}}}=\\frac{\\frac{9}{2} \\mathrm{R}}{\\frac{7}{2} \\mathrm{R}}=\\frac{9}{7}{/tex}</span> = 1.28<br />
<strong>Non-linear molecule:</strong><br />
Energy of a mole <span class="math-tex">{tex}=\\frac{6}{2} k \\mathrm{~T} \\times \\mathrm{N}_{\\mathrm{A}}=\\frac{6}{2} \\mathrm{RT}=3 \\mathrm{RT}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm{C}_{\\mathrm{V}}=\\frac{d \\mathrm{U}}{d \\mathrm{~T}}=3 \\mathrm{R}{/tex}</span><br />
C<sub>P</sub> = C<sub>V</sub> + R = 3R + R = 4R<br />
<span class="math-tex">{tex}\\therefore \\gamma=\\frac{\\mathrm{C}_{\\mathrm{P}}}{\\mathrm{C}_{\\mathrm{y}}}=\\frac{4 \\mathrm{R}}{3 \\mathrm{R}}=\\frac{4}{3}{/tex}</span> = 1.33</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Consider a rectangular block of wood moving with a velocity&nbsp;<em>v</em><sub>0</sub>&nbsp;in a gas at temperature&nbsp;<em>T&nbsp;</em>and mass density &rho;. Assume the velocity is along&nbsp;<em>x</em>-axis and the area of cross-section of the block perpendicular to&nbsp;<em>v<sub>0</sub></em>&nbsp;is&nbsp;<em>A</em>. Show that the drag force on the block is&nbsp;<span class="math-tex">{tex}4 \\rho A v _ { 0 } \\sqrt { \\frac { k T } { m } }{/tex}</span>&nbsp;,where&nbsp;<em>m&nbsp;</em>is the mass of the gas molecule.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Let&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;is the number of molecule per unit volume i.e.&nbsp;<span class="math-tex">{tex}\\rho {/tex}</span>&nbsp;is molecular density per unit volume.<br />
<strong><span class="math-tex">{tex}v = {v_{rms}}{/tex}</span></strong>is the velocity of gas molecules<br />
When box moves in gas, the molecules of gas strike to the front face from opposite direction and on back face in the same direction. As v &gt;&gt;<span class="math-tex">{tex}\\mathrm { v } _ { 0 }{/tex}</span>(v<sub>0&nbsp;</sub>being the velocity of the wooden box), so relative velocity on back face =<span class="math-tex">{tex}\\left( v - v _ { 0 } \\right){/tex}</span>&nbsp;and relative velocity on front face =&nbsp;<span class="math-tex">{tex}(v + v_0){/tex}</span><br />
Now change in momentum by a molecule on front face<span class="math-tex">{tex}= 2 m \\left( v + v _ { 0 } \\right){/tex}</span>, m being the mass of the gas molecule.<br />
And change in momentum by a molecule on back side<span class="math-tex">{tex}= 2 m \\left( v - v _ { 0 } \\right){/tex}</span>&nbsp;&nbsp;<br />
Number of molecules striking on front face in&nbsp;<span class="math-tex">{tex}\\Delta t{/tex}</span>time=<span class="math-tex">{tex}\\frac {1} {2}{/tex}</span>&times; volume covered by the gas molecules x molecular density per unit volume&nbsp;<br />
&nbsp;<span class="math-tex">{tex}= \\frac { 1 } { 2 } \\left[ A × \\left(v + v _ { 0 } \\right) × \\Delta t \\right] \\rho {/tex}</span>&nbsp;<br />
Hence, total number of molecules striking to front face,<br />
<span class="math-tex">{tex}N _ { F } = \\frac { 1 } { 2 } \\left( v + v _ { 0 } \\right) A \\rho \\Delta t{/tex}</span><br />
Similarly as the speed of molecule and block remains same as before, so number of molecules striking on backend face <span class="math-tex">{tex}N _ { B } = \\frac { 1 } { 2 } \\left( v - v _ { 0 } \\right) A \\rho \\Delta t{/tex}</span>&nbsp;<br />
Total change in momentum due to striking of the N<sub>F</sub>&nbsp;number of molecules on front face,<br />
<span class="math-tex">{tex}{p_F} = 2m\\left( {v + {v_0}} \\right)×{N_F} = 2m\\left( {v + {v_0}} \\right) \\times \\frac{1}{2}\\left( {v + {v_0}} \\right)A × {\\rho }\\Delta t{/tex}</span><br />
<span class="math-tex">{tex}\\therefore p _ { F } = - m \\left( v + v _ { 0 } \\right) ^ { 2 } A \\rho \\Delta t{/tex}</span>&nbsp;(-ve sign comes due to backward direction)<br />
So rate of change of momentum on front face i.e. the force on the front face,<br />
<span class="math-tex">{tex}F _ { F } = - m \\left( v + v _ { 0 } \\right) ^ { 2 } A \\rho _ { m }{/tex}</span>&nbsp;,in the backward direction<br />
Similarly force on back end&nbsp;<span class="math-tex">{tex}F _ { B } = + m \\left( v - v _ { 0 } \\right) ^ { 2 } A \\rho _ { m }{/tex}</span>&nbsp;, in the backward direction.<br />
Hence, net dragging force, F = F<sub>F</sub>&nbsp;+ F<sub>B</sub>&nbsp;=<span class="math-tex">{tex}- m \\left( v + v _ { 0 } \\right) ^ { 2 } A × \\rho + m \\left( v - v _ { 0 } \\right) ^ { 2 } A× \\rho {/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}= - m A \\rho \\left[ \\left( v + v _ { 0 } \\right) ^ { 2 } - \\left( v - v _ { 0 } \\right) ^ { 2 } \\right]{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex} = - mA\\rho\\left[ {{v^2} + v_0^2 + 2v.{v_0} - \\left( {{v^2} + v_0^2 - 2v.{v_0}} \\right)} \\right]{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex} = - mA\\rho ×4v×{v_0}{/tex}</span>&nbsp;<br />
So magnitude of dragging force due to gas molecule<span class="math-tex">{tex} = 4mv{v_0}A\\rho {/tex}</span>&nbsp;<br />
Now, kinetic energy of the gas molecule(from kinetic theory of gases)</p>

<p>&nbsp;<span class="math-tex">{tex}= \\frac { 1 } { 2 } m v ^ { 2 } =\\frac {1}{3}× \\frac { 3} { 2 } K _ { B } T{/tex}</span>&nbsp;[K<sub>B</sub>&nbsp;and T being Boltzmann&#39;s constant and absolute temperature respectively, <span class="math-tex">{tex}\\frac {1}{3}{/tex}</span>&nbsp;comes because of the one dimensional motion of the gas molecules. And we know that the energy of a gas molecule per degree of freedom is <span class="math-tex">{tex}\\frac {1}{2} K_BT{/tex}</span>]&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<br />
<span class="math-tex">{tex}\\therefore v = \\sqrt { \\frac { K _ { B } T } { m } }{/tex}</span>&nbsp;.....(ii)<br />
<span class="math-tex">{tex}\\therefore {/tex}</span>&nbsp;Dragging force becomes[putting the value of v from equation (ii)]</p>

<p><span class="math-tex">{tex} = 4mA{\\rho }{v_0}\\sqrt {\\frac{{{K_B}T}}{m}} {/tex}</span>. (Hence proved)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><ol start="1" style="list-style-type: lower-roman;">
	<li>What do you understand by specific heat capacity of water?</li>
	<li>If one mole of ideal monoatomic gas (<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= 5/3) is mixed with one mole of diatomic gas (<span class="math-tex">{tex}\\gamma{/tex}</span> = 7/ 5). What is the value of y for the mixtures?<br />
	(here, <span class="math-tex">{tex}\\gamma{/tex}</span> represents the ratio of specific heat at constant pressure to that at constant volume)</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>We know that water molecule is made up of 3 atoms (2 hydrogen and 1 oxygen).<br />
	By using law of equipartition of energy, average energy associated with one atom of water molecule<br />
	<span class="math-tex">{tex}= 2 \\times \\left( \\frac { 1 } { 2 } k _ { B } T \\right) = k _ { B } T{/tex}</span><br />
	In three dimension, the average energy per atom of water molecule = 3k<sub>B</sub>T<br />
	Total energy of one molecule of water is<br />
	<span class="math-tex">{tex}= 3 \\times \\left( 3 k _ { B } T \\right) = 9 k _ { B } T{/tex}</span><br />
	Now, total energy of 1 mole of water is<br />
	<span class="math-tex">{tex}U = 3 \\times 3 k _ { B } T \\times N _ { A } = 9 R T{/tex}</span><br />
	Molar specific heat of water,<br />
	<span class="math-tex">{tex}C = \\frac { \\Delta Q } { \\Delta T } = \\frac { \\Delta U } { \\Delta T } = 9R{/tex}</span><br />
	Specific heat capacity of water, C = 9 R<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;C = 74.79 J mol<sup>-1</sup>K<sup>-1</sup>(putting the value of R = 8.314 J mol<sup>-1</sup>&nbsp;K<sup>-1</sup>)</li>
	<li>For monoatomic gas, C<sub>V</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac 32{/tex}</span>R<br />
	For diatomic gas,&nbsp;<span class="math-tex">{tex}C _ { V } ^ { \\prime } = \\frac { 5 } { 2 } R{/tex}</span><br />
	Let&nbsp;<span class="math-tex">{tex}\\mu \\text { and } \\mu ^ { \\prime }{/tex}</span>&nbsp;be the number of moles of mono-atomic and diatomic gases, then C<sub>V</sub>(mixture) =&nbsp;<span class="math-tex">{tex}\\frac { \\mu C _ { V } + \\mu ^ { \\prime } C _ { V } ^ { \\prime } } { \\mu + \\mu ^ { \\prime } }{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow C _ { V } = \\frac { 1 \\times \\frac { 3 } { 2 } R + 1 \\times \\frac { 5 } { 2 } R } { 1 + 1 } = 2 R{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore \\gamma ( \\text { mixture } ) = 1 + \\frac { R } { C _ { V ( \\text { mixture } ) } }{/tex}</span>, using the relation C<sub>P</sub>&nbsp;- C<sub>V</sub> = R<br />
	<span class="math-tex">{tex}= 1 + \\frac { R } { 2 R }{/tex}</span><br />
	= 1.5</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A vessel A contains hydrogen and another vessel B whose volume is twice of A contains same mass of oxygen at the same temperature. Compare</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>average kinetic energies of hydrogen and oxygen molecules</li>
	<li>root mean square speeds of the molecules and</li>
	<li>pressures of gases in A and B.</li>
</ol>

<p>The molecular weights of hydrogen and oxygen are 2 and 32 respectively.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>For all gases at the same temperature average K.E. per molecule is same and is<br />
	<span class="math-tex">{tex}\\bar{E}=\\frac{3}{2} k_{B} T{/tex}</span><br />
	As the gases in both vessels are at the same temperature, so the ratio of their average K.E. per molecule = 1 : 1.</li>
	<li>As <span class="math-tex">{tex}v_{r m s}^{2}=\\sqrt{\\frac{3 R T}{M}}{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore \\quad \\frac{v_{H}}{v_{O}}=\\sqrt{\\frac{M_{0}}{M_{H}}}=\\sqrt{\\frac{32}{2}}{/tex}</span><br />
	= 4 : 1</li>
	<li>According to kinetic theory, <span class="math-tex">{tex}P=\\frac{1}{3} \\frac{M}{V} v_{r m s}^{2}{/tex}</span><br />
	where M is the mass and V is the volume of the gas. The masses of both gases are equal. So the ratio of their pressures is<br />
	<span class="math-tex">{tex}\\frac{P_{H}}{P_{O}}=\\left[\\frac{v_{H}}{v_{O}}\\right]^{2} \\times \\frac{V_{O}}{V_{H}}=\\frac{16}{1} \\times \\frac{2}{1}{/tex}</span><br />
	= 32 : 1</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>Given figure shows plot of PV/T versus P for 1.00 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-3</sup> kg of oxygen gas at two different temperatures.<br/>
<img alt="" data-imgur-src="efM4jgv.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614338837-7fywnn.jpg" style="width: 150px; height: 99px;"/></p>
<ol start="1" style="list-style-type: lower-alpha;">
<li>What does the dotted plot signify?</li>
<li>Which is true: T<sub>1</sub> &gt; T<sub>2</sub> or T<sub>1</sub> &lt; T<sub>2</sub>?</li>
<li>What is the value of PV/T where the curves meet on the y-axis?</li>
<li>If we obtained similar plots for 1.00 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-3</sup> kg of hydrogen, would we get the same value of PV/T at the point where the curves meet on the y-axis? If not, what mass of hydrogen yields the same value of PV/T (for the low-pressure high-temperature region of the plot)? (Molecular mass of H<sub>2</sub> = 2.02 u, of O<sub>2</sub> = 32.0 u, R = 8.31 J mo1<sup>-1</sup> K<sup>-1</sup>.)</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>The dotted plot corresponds to &#39;ideal&#39; gas behaviour as it is parallel to P-axis and it tells that value of PV/T remains the same even when P&nbsp;is changed.</li>
	<li>The upper position of PV/T shows that its value is lesser for T<sub>1</sub>&nbsp;thus T<sub>1</sub> &gt;T<sub>2</sub>. This is because the curve at T<sub>1</sub>&nbsp;is&nbsp;closer to the dotted plot than the curve at T<sub>2</sub>&nbsp;since the behaviour of real gas approaches the perfect gas behaviour, as the temperature is increased.</li>
	<li>Where the two curves meet, the value of PV/T on the y-axis is equal to&nbsp;<span class="math-tex">{tex}\\mu{/tex}</span>R. Since the ideal gas equation for&nbsp;<span class="math-tex">{tex}\\mu{/tex}</span>&nbsp;moles is PV =&nbsp;<span class="math-tex">{tex}\\mu{/tex}</span>RT<br />
	Where,&nbsp;<span class="math-tex">{tex}\\mu{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1.00 \\times 10^{-3} \\mathrm{kg}}{32 \\times 10^{-3} \\mathrm{kg}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{32}{/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Value of&nbsp;<span class="math-tex">{tex}\\frac{PV}{T}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\mu R{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{32} \\times 8.31{/tex}</span>&nbsp;JK<sup>-1</sup> = 0.26 JK<sup>-1</sup>&nbsp;</li>
	<li>If we obtained similar plots for 1.00&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-3</sup> kg of hydrogen, we will not get the same value of&nbsp;<span class="math-tex">{tex}\\frac{PV}{T}{/tex}</span>&nbsp;at the point, where the curves meet on the y-axis. This is because the molecular mass of hydrogen is different from that of oxygen.<br />
	For the same value of&nbsp;<span class="math-tex">{tex}\\frac{PV}{T}{/tex}</span>, mass of hydrogen required is obtained from&nbsp;<br />
	<span class="math-tex">{tex}\\frac{PV}{T}{/tex}</span>&nbsp;= nR =&nbsp;<span class="math-tex">{tex}\\frac{m}{2.02} \\times 8.31{/tex}</span>&nbsp;= 0.26<br />
	m =&nbsp;<span class="math-tex">{tex}\\frac{2.02 \\times 0.26}{8.31}{/tex}</span>&nbsp;gram = 6.32&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-2</sup> gram</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Estimate the average thermal energy of a helium atom at</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>room temperature (27 &deg;C),</li>
	<li>the temperature on the surface of the Sun (6000 K),</li>
	<li>the temperature of 10 million Kelvin (the typical core temperature in the case of a star).</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>According to law of equipartition of energy we know that the energy of a gas molecule per degree of freedom =&nbsp;<span class="math-tex">{tex}\\frac {1}{2} kT{/tex}</span>. For helium atom in the given question, there are 3 degrees of freedom with total thermal energy =&nbsp;<span class="math-tex">{tex}3 × \\frac {1}{2} kT = \\frac {3}{2}kT{/tex}</span>&nbsp;. Now at room temperature, T= 27&deg;C = (273+27)K=300 K<br />
	We know that, the average thermal energy per molecule&nbsp;<span class="math-tex">{tex}= \\frac { 3 } { 2 } k T{/tex}</span><br />
	Where k is the Boltzmann constant <span class="math-tex">{tex}= 1.38 \\times 10 ^ { - 23 } \\mathrm { m } ^ { 2 } \\mathrm { kg } s ^ { - 2 } \\mathrm { K } ^ { - 1 }{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore \\; \\frac { 3 } { 2 } k T = \\frac { 3 } { 2 } \\times 1.38 \\times 10 ^ { - 23 } \\times 300{/tex}</span>&nbsp;(k = 1.38 &times; 10<sup>-23</sup>kg m<sup>2</sup>s<sup>-2</sup>K<sup>-1</sup>, T = 300 K)<br />
	<span class="math-tex">{tex}= 6.21 \\times 10 ^ { - 21 } J{/tex}</span><br />
	Hence, the average thermal energy of a helium atom at room temperature (27&deg;C) is <span class="math-tex">{tex}6.21 \\times 10 ^ { - 21 } J{/tex}</span>.</li>
	<li>On the surface of the sun, T= 6000 K<br />
	Average thermal energy <span class="math-tex">{tex}= \\frac { 3 } { 2 } k T{/tex}</span>&nbsp;with k = 1.38 &times; 10<sup>-23</sup>&nbsp;kg m<sup>2</sup>s<sup>-2</sup>K<sup>-1</sup><br />
	<span class="math-tex">{tex}=\\frac { 3 } { 2 } \\times 1.38 \\times 10 ^ { - 23 } \\times 6000{/tex}</span><br />
	<span class="math-tex">{tex}= 1.241 \\times 10 ^ { - 19 } J{/tex}</span><br />
	Hence, the average thermal energy of a helium atom on the surface of the sun having temperature 6000 K is <span class="math-tex">{tex}1.241 \\times 10 ^ { - 19 } J{/tex}</span>.</li>
	<li>At temperature, T= 10 million K = 100 lakhs K = 10<sup>5</sup>&nbsp;&times; 10<sup>2</sup> K =&nbsp; 10<sup>7</sup>K<br />
	Average thermal energy <span class="math-tex">{tex}= \\frac { 3 } { 2 } k T{/tex}</span>&nbsp;with k = 1.38 &times; 10<sup>-23</sup>​​​​kg m<sup>2</sup>s<sup>-2</sup>K<sup>-1</sup><br />
	<span class="math-tex">{tex}=\\frac { 3 } { 2 } \\times 1.38 \\times 10 ^ { - 23} \\times 10 ^ { 7 }{/tex}</span><br />
	<span class="math-tex">{tex}= 2.07 \\times 10 ^ { - 16 } J{/tex}</span><br />
	Hence, the average thermal energy of a helium atom at the core of a star is <span class="math-tex">{tex} 2.07 \\times 10 ^ { - 16 } J{/tex}</span>.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>An oxygen cylinder of volume 30 litres has an initial gauge pressure of 15 atm and a temperature of 27 &deg;C. After some oxygen is withdrawn from the cylinder, the gauge pressure drops to 11 atm and its temperature drops to 17 &deg;C. Estimate the mass of oxygen taken out of the cylinder (R = 8.31 J mol<sup>-1</sup> K<sup>-1</sup>, molecular mass of O<sub>2</sub> = 32 u).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Initial volume of oxygen, V<sub>1</sub> = 30 litres = <span class="math-tex">{tex}30 \\times 10 ^ { - 3 } m ^ { 3 }{/tex}</span>&nbsp;(putting1 litre = 10<sup>-3</sup>&nbsp;m<sup>3</sup>)<br />
Initial gauge pressure, P<sub>1</sub> = 15 atm = <span class="math-tex">{tex}15 \\times 1.013 \\times 10 ^ { 5 } P a{/tex}</span>&nbsp;= 15.195 &times; 10<sup>5</sup> Pa(putting 1 atm = 1.013 &times; 10<sup>5</sup>&nbsp;Pa)<br />
Initial temperature, T<sub>1</sub> = 27&deg;C = (273 + 27)K = 300 K<br />
Universal gas constant, R&nbsp;= 8.314 J mol<sup>-1</sup> K<sup>-1</sup><br />
Let the initial number of moles of oxygen gas in the cylinder be n<sub>1</sub>.<br />
The n<sub>1</sub> mole ideal gas equation is given as:<br />
P<sub>1</sub>V<sub>1</sub> = n<sub>1</sub>RT<sub>1</sub><br />
<span class="math-tex">{tex}\\therefore n _ { 1 } = \\frac { P _ { 1 } V _ { 1 } } { R T _ { 1 } }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 15.195 \\times 10 ^ { 5 } \\times 30 \\times 10 ^ { - 3 } } { ( 8.314 ) \\times 300 } = \\frac {151.95}{8.314}{/tex}</span> = 18.276<br />
But, <span class="math-tex">{tex}n _ { 1 } = \\frac { m _ { 1 } } { M }{/tex}</span>&nbsp;(as, number of moles = total given mass of the gas &divide; molar mass of the gas)<br />
Where,<br />
m<sub>1</sub> = Initial mass of oxygen<br />
M = Molecular mass of oxygen = 32 g<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> m<sub>1</sub> = number of moles &times; molar mass of oxygen = n<sub>1</sub> M = 18.276&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 32 = 584.84 g<br />
After some oxygen is withdrawn from the cylinder, the pressure and temperature reduces.</p>

<p>But as the cylinder of volume 30 litres is not changed, so the final volume of the gas will remain same.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>Final volume, V<sub>2</sub> = 30 litres = <span class="math-tex">{tex}30 \\times 10 ^ { - 3 } m ^ { 3 }{/tex}</span><br />
Final gauge pressure, P<sub>2</sub> = 11 atm = <span class="math-tex">{tex}11 \\times 1.013 \\times 10 ^ { 3 } \\mathrm { Pa }{/tex}</span>&nbsp;(given)<br />
Final temperature, T<sub>2</sub> = 17&deg;C = (273 + 17)K = 290 K(given)<br />
Let n<sub>2</sub> be the number of moles of oxygen left in the cylinder.<br />
Again the ideal gas equation for n<sub>2</sub> moles of Oxygen is given as:<br />
P<sub>2</sub>V<sub>2</sub> = n<sub>2</sub>RT<sub>2</sub><br />
<span class="math-tex">{tex}\\therefore n _ { 2 } = \\frac { P _ { 2 } V _ { 2 } } { R T _ { 2 } }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 11.143 \\times 10 ^ { 5 } \\times 30 \\times 10 ^ { - 3 } } { 8.314 \\times 290 } = \\frac {11.143 × 3}{8.314 × 0.29}{/tex}</span>= 13.86<br />
But, <span class="math-tex">{tex}n _ { 2 } = \\frac { m _ { 2 } } { M }{/tex}</span>&nbsp;(again using the formula, number of moles = total supplied mass of the gas &divide; molar mass of the gas)<br />
Where,<br />
m<sub>2</sub> is the mass of oxygen remaining in the cylinder<br />
<span class="math-tex">{tex}\\therefore{/tex}</span> m<sub>2</sub> = number of moles remaining &times; molar mass of Oxygen = n<sub>2</sub>&nbsp;&times; M = 13.86 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;32 = 453.1 g<br />
The mass of oxygen taken out of the cylinder is given by the relation:<br />
Change in mass, <span class="math-tex">{tex}\\Delta m ={/tex}</span>Initial mass of oxygen in the cylinder - Final mass of oxygen in the cylinder<br />
= m<sub>1</sub> - m<sub>2</sub><br />
= 584.84 g - 453.1 g<br />
= 131.74 g<br />
= 0.131 kg<br />
Therefore, 0.131 kg of oxygen is taken out of the cylinder.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What are the basic assumptions of kinetic theory of gases? On their basis derive an expression for the pressure exerted by an ideal gas. Use it to relate kinetic energy with pressure.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The basic assumptions of kinetic theory of gases</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>A gas consists of a large number of tiny particles called molecules.</li>
	<li>The molecules are rigid, perfectly elastic spheres of very small diameters.</li>
	<li>All the molecules of the same gas are identical in shape, size and mass.</li>
	<li>Actual volume occupied by gas molecules is very small compared to the total volume occupied by the gas.</li>
</ol>

<p>v<sup>2</sup> = <span class="math-tex">{tex}v_x^2{/tex}</span> + <span class="math-tex">{tex}\\mathrm{v}_{\\mathrm{y}}^2{/tex}</span> + <span class="math-tex">{tex}\\mathrm{v}_{\\mathrm{z}}^2{/tex}</span> ...(i)<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1709111418-t3xksg.jpg" style="height:201px; width:150px" /><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1709111436-hrntc8.jpg" style="height:206px; width:150px" /><br />
The number of collision in one second = <span class="math-tex">{tex}\\frac{vx}{2l}{/tex}</span>. Therefore the magnitude of rate of change of linear momentum is the force f<sub>x</sub> this atom/molecule exerts on face ABCD.<br />
f<sub>x</sub> = 2mv<sub>x</sub> <span class="math-tex">{tex}\\times{/tex}</span> <span class="math-tex">{tex}\\frac{\\mathrm{v}_x}{2 \\ell}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathrm{mv}_x^2}{\\ell}{/tex}</span> ...(ii)<br />
Obviously Taking into account collisions due to all atoms / molecules of gas; the total force f<sub>x</sub> on ABCD is<br />
F<sub>x</sub> = <span class="math-tex">{tex}\\sum \\mathrm{f}_x{/tex}</span> = <span class="math-tex">{tex}\\sum_\\limits{\\mathrm{j}=1}^{\\mathrm{N}}\\left(\\frac{\\mathrm{mv}_{\\mathrm{jx}}^2}{\\ell}\\right){/tex}</span> ...(iii)<br />
The pressure P<sub>x</sub>; along X&ndash;axis,<br />
P<sub>x</sub> = <span class="math-tex">{tex}\\frac{\\mathrm{F}_x}{\\ell^2}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathrm{m}}{\\ell^3} \\sum_\\limits{\\mathrm{j}=1}^{\\mathrm{N}} \\mathrm{v}_{\\mathrm{jx}}^2{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathrm{m}}{\\mathrm{V}} \\sum_\\limits{\\mathrm{j}=1}^{\\mathrm{N}} \\mathrm{v}_{\\mathrm{jx}}^2{/tex}</span> ...(iv)<br />
is V = l<sup>3</sup> = volume of cubical container. Similarly the pressure along Y and Z axis is<br />
P<sub>y</sub> = <span class="math-tex">{tex}\\frac{m}{V} \\sum_\\limits{j=1}^N v_{j y}^2{/tex}</span>; P<sub>z</sub> = <span class="math-tex">{tex}\\frac{m}{V} \\sum_\\limits{j=1}^N v_{j z}^2{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span> P<sub>x</sub> + P<sub>y</sub> + P<sub>z</sub> = <span class="math-tex">{tex}\\frac{m}{V}\\left[\\sum_\\limits{j=1}^N\\left(v_{j x}^2+v_{j y}^2+v_{j z}^2\\right)\\right]{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{m}{V}\\left[\\sum_\\limits{j=1}^N v_j^2\\right]{/tex}</span> ...(v)<br />
The pressure exerted by gas is same in every direction i.e., P<sub>x</sub> = P<sub>y</sub> = P<sub>z</sub> = P (say). Obviously<br />
P = <span class="math-tex">{tex}\\frac{m}{3 V}\\left[\\sum_\\limits{j=1}^N v_j^2\\right]{/tex}</span> = <span class="math-tex">{tex}\\frac{m N}{3 v}\\left(v_{\\text {rms }}^2\\right){/tex}</span> ...(iv)<br />
where <span class="math-tex">{tex}v_{\\mathrm{rms}}^2{/tex}</span><br />
= <span class="math-tex">{tex}\\frac{\\Sigma\\left(\\mathrm{v}_{\\mathrm{j}}^2\\right)}{\\mathrm{N}}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathrm{v}_1^2+\\mathrm{v}_2^2+\\ldots . .+\\mathrm{v}_{\\mathrm{N}}^2}{\\mathrm{~N}}{/tex}</span> ...(vii)<br />
v<sub>rms</sub> is the root mean square velocity of gas atoms/molecules. Also mN = m<sub>1</sub> = Total mass of gas in cube and <span class="math-tex">{tex}\\frac{m_1}{V}{/tex}</span> = p = density of the gas. Eqn. (vii) can be rewritten as<br />
P = <span class="math-tex">{tex}\\frac{1}{3} \\rho \\mathrm{v}_{\\mathrm{rms}}^2{/tex}</span> ...(iii)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Derive an expression for the pressure due to an ideal gas.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><img data-imgur-src="peA3aeD.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/peA3aeD.png" style="width: 150px; height: 108px;" /><br />
Consider an ideal gas contained in a cubical container shown in figure above, having each of side a and having volume V. Now, V = a<sup>3 </sup>&nbsp;[<span class="math-tex">{tex}\\because{/tex}</span>(Side)<sup>3 </sup>= volume of cube]<br />
Let n = number of molecules of the gas contained in the container<br />
m = Mass of each molecule<br />
M = mn = Total mass of the gas contained<br />
Consider one molecule is moving with velocity C<sub>1</sub>&nbsp;such that,&nbsp;<span class="math-tex">{tex}\\vec C_1 = v_{1x} \\hat i + v_{1y} \\hat j + v_{1z} \\hat k{/tex}</span>&nbsp;<br />
X-component of change in momentum of the molecule along +X axis = mv<sub>1x</sub>&nbsp;- (- v<sub>1x</sub>) = 2mv<sub>1x</sub>&nbsp;in time t = 2a/v<sub>1x</sub><br />
Now rate of change of momentum (X component) = (2mv<sub>1x</sub>)/t =&nbsp;<span class="math-tex">{tex}\\frac {m{v_{1x} }^2}{a}{/tex}</span>, this is the X component of the force, F<sub>1x</sub> by the molecule.&nbsp;<br />
Now X component of pressure exerted by the molecule P<sub>1x</sub>&nbsp;= F<sub>1x</sub>/a<sup>2</sup>&nbsp;= mv<sub>1x<sup>2</sup></sub>/a<sup>3</sup><br />
Now taking all the molecules, net X component of pressure, P<sub>x</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac {m}{a^3}×(v_{1x}^2 + v_{2x}^2+...+v_{nx}^2){/tex}</span>(for n number of molecules)<br />
Similarly P<sub>y</sub> = <span class="math-tex">{tex}\\frac { m } { a ^ { 3 } } \\left( v _ { 1y } ^ { 2 } + v _ { 2y } ^ { 2 } +....+ v_ { ny } ^ { 2 } \\right){/tex}</span>&nbsp;and&nbsp;<br />
<span class="math-tex">{tex}P _z = \\frac { m } { a ^ { 3 } } \\left( v_ { 1z } ^ { 2 } + v _ { 2z } ^ { 2 } +....+ v _ { nz } ^ { 2 } \\right){/tex}</span>&nbsp;<br />
All three component of pressures are equal for all the gas molecules.&nbsp;<br />
P = Total pressure of a single molecule = <span class="math-tex">{tex}\\frac { P _ { x } + P _ { y } + P _ { z } } { 3 }{/tex}</span><br />
<span class="math-tex">{tex} = \\frac{1}{3}\\left[ {\\frac{m}{{{a^3}}}\\left( {v_{1x}^2 + v_{2 x}^2 +...+ v_{nx}^2} \\right) + \\frac{m}{{{a^3}}}\\left( {v_{1 y}^2 + v_{2 y}^2 +...+v_{nz}^2} \\right) + \\frac{m}{{{a^3}}}\\left( {v_{1z}^2 + v_{2z}^2 + ... + v_{nz}^2} \\right)} \\right]{/tex}</span><br />
<span class="math-tex">{tex}\\therefore P = \\frac { m } { 3 V } \\left[ C _ { 1 } ^ { 2 } + C _ { 2 } ^ { 2 } +....+C _ { n } ^ { 2 } \\right]{/tex}</span>&nbsp;where C<sub>1</sub><sup>2</sup>= v<sub>1x</sub><sup>2</sup>&nbsp;+ v<sub>1y</sub><sup>2</sup>&nbsp;+ v<sub>1z</sub><sup>2</sup>, C<sub>2</sub><sup>2</sup>&nbsp;= v<sub>2x</sub><sup>2</sup>&nbsp;+ v<sub>2y</sub><sup>2</sup>&nbsp;+ v<sub>2z</sub><sup>2</sup>,....., C<sub>n</sub><sup>2</sup>&nbsp;= v<sub>nx</sub><sup>2</sup>&nbsp;+ v<sub>ny</sub><sup>2</sup>&nbsp;+ v<sub>nz</sub><sup>2</sup><br />
multiplying and dividing by n (total no of molecules of gas)<br />
<span class="math-tex">{tex}\\therefore P = \\frac { m × n } { 3 V } \\left[ \\frac { C _ { 1 } ^ { 2 } + C _ { 2 } ^ { 2 } +....+C _ { n } ^ { 2 } } { n } \\right]{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow P = \\frac { M } { 3 V } C ^ { 2 }{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{3} \\rho C^2{/tex}</span><br />
<span class="math-tex">{tex}where ~C ^ { 2 } = \\frac { C _ { 1 } ^ { 2 } + C _ { 2 } ^ { 2 } +....+C _ { n } ^ { 2 } } { n }{/tex}</span> or <span class="math-tex">{tex}C = \\sqrt { \\frac { C _ { 1 } ^ { 2 } + C _ { 2 } ^ { 2 } +....+ C _ { n } ^ { 2 } } { n } }{/tex}</span><br />
C = r. m s. velocity of gas and&nbsp;<span class="math-tex">{tex}\\rho {/tex}</span>&nbsp;being the mass density of the gas.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>State the postulates of kinetic theory of gases. Derive an expression for the pressure exerted by an ideal gas. Molar volume is the volume occupied by 1 mole of any (ideal) gas at standard temperature and pressure (STP = 1 atm pressure, 0<sup>o</sup>C). Show that it is 22.4 liters.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The postulates of kinetic theory of gases are:</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>A gas consists of a large number of tiny particles called molecules.</li>
	<li>The molecules are rigid, perfectly elastic spheres of very small diameters.</li>
	<li>All the molecules of the same gas are identical in shape, size and mass.</li>
	<li>Actual volume occupied by gas molecules is very small compared to the total volume occupied by the gas.</li>
</ol>

<p>Expression for the pressure exerted by an ideal gas.<br />
v<sup>2</sup> = <span class="math-tex">{tex}v_x^2{/tex}</span> + <span class="math-tex">{tex}\\mathrm{v}_{\\mathrm{y}}^2{/tex}</span> + <span class="math-tex">{tex}\\mathrm{v}_{\\mathrm{z}}^2{/tex}</span> ...(i)<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1709111418-t3xksg.jpg" style="height:201px; width:150px" /><img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1709111436-hrntc8.jpg" style="height:206px; width:150px" /><br />
The number of collision in one second = <span class="math-tex">{tex}\\frac{vx}{2l}{/tex}</span>. Therefore the magnitude of rate of change of linear momentum is the force f<sub>x</sub> this atom/molecule exerts on face ABCD.<br />
f<sub>x</sub> = 2mv<sub>x</sub> <span class="math-tex">{tex}\\times{/tex}</span> <span class="math-tex">{tex}\\frac{\\mathrm{v}_x}{2 \\ell}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathrm{mv}_x^2}{\\ell}{/tex}</span> ...(ii)<br />
Obviously Taking into account collisions due to all atoms / molecules of gas; the total force f<sub>x</sub> on ABCD is<br />
F<sub>x</sub> = <span class="math-tex">{tex}\\sum \\mathrm{f}_x{/tex}</span> = <span class="math-tex">{tex}\\sum_\\limits{\\mathrm{j}=1}^{\\mathrm{N}}\\left(\\frac{\\mathrm{mv}_{\\mathrm{jx}}^2}{\\ell}\\right){/tex}</span> ...(iii)<br />
The pressure P<sub>x</sub>; along X&ndash;axis,<br />
P<sub>x</sub> = <span class="math-tex">{tex}\\frac{\\mathrm{F}_x}{\\ell^2}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathrm{m}}{\\ell^3} \\sum_\\limits{\\mathrm{j}=1}^{\\mathrm{N}} \\mathrm{v}_{\\mathrm{jx}}^2{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathrm{m}}{\\mathrm{V}} \\sum_\\limits{\\mathrm{j}=1}^{\\mathrm{N}} \\mathrm{v}_{\\mathrm{jx}}^2{/tex}</span> ...(iv)<br />
is V = l<sup>3</sup> = volume of cubical container. Similarly the pressure along Y and Z axis is<br />
P<sub>y</sub> = <span class="math-tex">{tex}\\frac{m}{V} \\sum_\\limits{j=1}^N v_{j y}^2{/tex}</span>; P<sub>z</sub> = <span class="math-tex">{tex}\\frac{m}{V} \\sum_\\limits{j=1}^N v_{j z}^2{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span> P<sub>x</sub> + P<sub>y</sub> + P<sub>z</sub> = <span class="math-tex">{tex}\\frac{m}{V}\\left[\\sum_\\limits{j=1}^N\\left(v_{j x}^2+v_{j y}^2+v_{j z}^2\\right)\\right]{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{m}{V}\\left[\\sum_\\limits{j=1}^N v_j^2\\right]{/tex}</span> ...(v)<br />
The pressure exerted by gas is same in every direction i.e., P<sub>x</sub> = P<sub>y</sub> = P<sub>z</sub> = P (say). Obviously<br />
P = <span class="math-tex">{tex}\\frac{m}{3 V}\\left[\\sum_\\limits{j=1}^N v_j^2\\right]{/tex}</span> = <span class="math-tex">{tex}\\frac{m N}{3 v}\\left(v_{\\text {rms }}^2\\right){/tex}</span> ...(iv)<br />
where <span class="math-tex">{tex}v_{\\mathrm{rms}}^2{/tex}</span><br />
= <span class="math-tex">{tex}\\frac{\\Sigma\\left(\\mathrm{v}_{\\mathrm{j}}^2\\right)}{\\mathrm{N}}{/tex}</span> = <span class="math-tex">{tex}\\frac{\\mathrm{v}_1^2+\\mathrm{v}_2^2+\\ldots . .+\\mathrm{v}_{\\mathrm{N}}^2}{\\mathrm{~N}}{/tex}</span> ...(vii)<br />
v<sub>rms</sub> is the root mean square velocity of gas atoms/molecules. Also mN = m<sub>1</sub> = Total mass of gas in cube and <span class="math-tex">{tex}\\frac{m_1}{V}{/tex}</span> = p = density of the gas. Eqn. (vii) can be rewritten as<br />
P = <span class="math-tex">{tex}\\frac{1}{3} \\rho \\mathrm{v}_{\\mathrm{rms}}^2{/tex}</span> ...(viii)<br />
Here n = 1 mol, T = 273 K, R = 8.31 J/mole/K.<br />
P = 1 atm = 0.76 mm of Hg = 0.76 <span class="math-tex">{tex}\\times{/tex}</span> 9.8 <span class="math-tex">{tex}\\times{/tex}</span>13.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>3</sup> N/m<sup>2</sup><br />
Using the relation<br />
or,<br />
PV = nRT,<br />
V = <span class="math-tex">{tex}\\frac{n \\mathrm{RT}}{\\mathrm{P}}{/tex}</span><br />
= <span class="math-tex">{tex}\\frac{1 \\times 8.31 \\times 273}{0.76 \\times 9.8 \\times\\left(13.6 \\times 10^3\\right)}{/tex}</span><br />
= 22.4 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-3</sup> m<sup>3</sup><br />
= 22.4 lit.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1353-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_OSCILLATIONS = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>At extreme position, velocity of the particle executing SHM that has amplitude A is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\omega^2{/tex}</span>A</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline">0</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Velocity of the particle executing SHM is given as<br />
v =&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span><span class="math-tex">{tex}\\sqrt{A^2-x^2}{/tex}</span><br />
At extreme position, x = A<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> v = 0</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\omega{/tex}</span>A</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\omega A}{2}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which of the following relationships between the acceleration a, and the displacement x of a particle involve simple harmonic motion?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">a = 0.7 x</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">a = -200x<sup>2</sup> </p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">a = -10x</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>a = -10x represent SHM. This is because acceleration is proportional and opposite to displacement (x).</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">a = 100x<sup>3</sup> </p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The motion of satellites and planets is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">periodic</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The motion of planets and satellites are repetitive and repeats itself after a fixed interval of time. These type of motions are known as periodic motion.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">oscillatory</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">simple harmonic</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">non-periodic</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A particle executing S.H.M. has a maximum speed of 30 cm/s and a maximum acceleration of 60 cm/s<sup>2</sup>. The period of oscillation is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\pi s{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Let equation of an SHM is represented by y&nbsp;<span class="math-tex">{tex}=a \\sin \\omega{/tex}</span><br />
<span class="math-tex">{tex}v=\\frac{d y}{d t}=a \\omega \\cos \\omega t{/tex}</span><br />
Hence&nbsp;<span class="math-tex">{tex}(v)_{\\max }=a \\omega{/tex}</span>&nbsp;.... (i)<br />
Acceleration&nbsp;<span class="math-tex">{tex}(A)=\\frac{d x^{2}}{d t^{2}}=-a \\omega^{2} \\sin \\omega t{/tex}</span><br />
Hence&nbsp;<span class="math-tex">{tex}A_{\\max }=\\omega^{2} a{/tex}</span>&nbsp;.... (ii)<br />
Maximum speed,&nbsp;<span class="math-tex">{tex}v_{\\max }=\\omega A{/tex}</span>&nbsp;.... (i)<br />
Maximum acceleration,&nbsp;<span class="math-tex">{tex}a_{\\max }=\\omega^{2} A{/tex}</span>&nbsp;.... (ii)<br />
Divide eqn. (ii) by eqn. (i), we get<br />
<span class="math-tex">{tex}\\frac{a_{\\max }}{v_{\\max }}=\\frac{\\omega^{2} A}{\\omega A}=\\omega \\quad \\therefore \\frac{a_{\\max }}{v_{\\max }}=\\frac{2 \\pi}{T}{/tex}</span><br />
<span class="math-tex">{tex}T=2 \\pi\\left(\\frac{v_{\\max }}{a_{\\max }}\\right){/tex}</span><br />
Here, v<sub>max</sub> = 30 cms<sup>-1</sup>, amax = 60 cms<sup>-2</sup><br />
<span class="math-tex">{tex}\\therefore \\quad T=2 \\pi\\left(\\frac{30 \\mathrm{cms}^{-1}}{60 \\mathrm{cms}^{-2}}\\right)=\\pi \\mathrm{s}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\pi}{2} s{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}2 \\pi \\ \\mathrm{s}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\pi}{t} s{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The ratio of frequencies of two pendulums are 2 : 3, then their lengths are in ratio</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{\\frac{2}{3}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{\\frac{3}{2}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{4}{9}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{9}{4}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\frac{v_{1}}{v_{2}}=\\sqrt{\\frac{l}{l}}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{l_{1}}{l_{2}}=\\left(\\frac{v_{2}}{v_{1}}\\right)^{2}=\\left(\\frac{3}{2}\\right)^{2}=\\frac{9}{4}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The ratio of maximum acceleration to the maximum velocity of a particle performing S.H.M is equal to:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">Angular velocity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>a<sub>max&nbsp;</sub>= <span class="math-tex">{tex}\\omega^2{/tex}</span>A<br />
v<sub>max&nbsp;</sub>= <span class="math-tex">{tex}\\omega{/tex}</span>A<br />
thus<br />
<span class="math-tex">{tex}\\frac{a_{\\max }}{v_{\\max }}=\\frac{\\omega^{2} A}{\\omega A}{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Amplitude</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Square of amplitude</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Square of angular velocity</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two springs of spring constants k<sub>1</sub>&nbsp;and k<sub>2</sub> are joined in series. The effective spring constant of the combination is given by:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\sqrt{k_{1} k_{2}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac {\\left(k_{1}+k_{2}\\right)} 2{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">k<sub>1</sub> + k<sub>2</sub></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac {k_{1} k_{2}} {\\left(k_{1}+k_{2}\\right)}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}k_{s}=\\frac{k_{1} k_{2}}{k_{1}+k_{2}}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Out of the following functions representing motion of a particle which represents SHM</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>y =&nbsp;<span class="math-tex">{tex}\\sin \\omega t-\\cos \\omega t{/tex}</span></li>
	<li>y =&nbsp;<span class="math-tex">{tex}\\sin ^{3} \\omega t{/tex}</span></li>
	<li>y =&nbsp;<span class="math-tex">{tex}5 \\cos \\left(\\frac{3 \\pi}{4}-3 \\omega t\\right){/tex}</span></li>
	<li>y =&nbsp;<span class="math-tex">{tex}1+\\omega t+\\omega^{2} t^{2}{/tex}</span></li>
</ol></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">Only (i)</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Only (iv) does not represent SHM</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">Only (i) and (iii)</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>y =&nbsp;<span class="math-tex">{tex}1+\\omega t+\\omega^{2} t^{2}{/tex}</span> is algebraic function and y =&nbsp;<span class="math-tex">{tex}\\sin ^{3} \\omega t{/tex}</span> is not harmonic being the product of sin <span class="math-tex">{tex}\\omega{/tex}</span>t (thrice). But y =&nbsp;<span class="math-tex">{tex}\\sin \\omega t-\\cos \\omega t{/tex}</span> and y =&nbsp;<span class="math-tex">{tex}5 \\cos \\left(\\frac{3 \\pi}{4}-3 \\omega t\\right){/tex}</span> are simple harmonic functions. Hence y =&nbsp;<span class="math-tex">{tex}\\sin \\omega t-\\cos \\omega t{/tex}</span> and y =&nbsp;<span class="math-tex">{tex}5 \\cos \\left(\\frac{3 \\pi}{4}-3 \\omega t\\right){/tex}</span> represent SHM.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Only (i) and (ii)</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>If the metal bob of a simple pendulum is replaced by wooden bob, then its time period will</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">increase</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">decrease</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">remain the same</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Time period, T =&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{l}{g}}{/tex}</span>&nbsp;is independent of the mass of the bob.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">first increase then decrease</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The total energy of a particle, executing simple harmonic motion is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">independent of x</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>x= A cos( <span class="math-tex">{tex}\\omega t+\\phi{/tex}</span>)<br />
E = KE + PE<br />
<span class="math-tex">{tex}PE=\\frac{1}{2}kA^2cos^2(\\omega t+\\phi){/tex}</span>&nbsp; and KE=&nbsp;<span class="math-tex">{tex}\\frac{1}{2}kA^2sin^2(\\omega t+\\phi){/tex}</span><br />
<span class="math-tex">{tex}E=\\frac{1}{2}kA^2{/tex}</span>&nbsp;&nbsp;<span class="math-tex">{tex}(sin^2(\\omega t+\\phi)+cos^2(\\omega t+\\phi)){/tex}</span>&nbsp;= <span class="math-tex">{tex}\\frac{1}{2}{/tex}</span>kA<sup>2&nbsp; &nbsp;</sup>Therefore, total energy is independent of x.&nbsp;<br />
Thus the total energy of the oscillator remains constant as displacement is regained after every half cycle.<br />
no energy is dissipated then all the potential energy becomes kinetic and vice versa.<br />
The figure below shows the variation of kinetic energy and potential energy of harmonic oscillator with time where phase &phi; is set to zero for simplicity<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/0mfcCud.png" style="width: 279px; height: 150px;" /></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\propto {x}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\propto \\frac{x}{2}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\propto { x^2}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The magnitude of acceleration of particle executing SHM at the position of maximum displacement is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">zero</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">minimum</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">maximum</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Acceleration in SHM is<br />
a =&nbsp;<span class="math-tex">{tex}\\omega^{2} y{/tex}</span><br />
At y<sub>max</sub> = A, a<sub>max</sub> =&nbsp;<span class="math-tex">{tex}\\omega^{2} A{/tex}</span><br />
Acceleration is maximum at the position of maximum displacement.</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Moderate</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two simple motions are represented by<br />
y<sub>1</sub> =&nbsp;<span class="math-tex">{tex}5(\\sin 2 \\pi t+\\sqrt{3} \\cos 2 \\pi t){/tex}</span>&nbsp;<br />
y<sub>2</sub> =&nbsp;<span class="math-tex">{tex}5 \\sin (2 \\pi t+ \\frac{\\pi}{4}){/tex}</span>&nbsp;<br />
The ratio of the amplitude of two SHM&#39;s is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">1 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">1 : 2</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">2 : 1</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>y<sub>1</sub> =&nbsp;<span class="math-tex">{tex}5 \\times 2[\\sin 2 \\pi t \\cos \\frac{\\pi}{3}+\\sin \\frac{\\pi}{3} \\cos 2 \\pi t]{/tex}</span>&nbsp;<br />
= 10 sin&nbsp;<span class="math-tex">{tex}(2 \\pi t+ \\frac{\\pi}{3}){/tex}</span><br />
y<sub>2</sub> = 5 sin&nbsp;<span class="math-tex">{tex}(2 \\pi t+ \\frac{\\pi}{4}){/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{A_{1}}{A_{2}}=\\frac{10}{5}{/tex}</span> = 2 : 1</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">1 : <span class="math-tex">{tex}\\sqrt{3}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A particle executes S.H.M along a straight line with amplitude &lsquo;A&rsquo;. The potential energy is maximum when the displacement is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex} \\pm {/tex}</span> A</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Potential energy in s.h.m. is given by<br />
<span class="math-tex">{tex}U=\\;\\frac12kx^2{/tex}</span><br />
Maximum possible values of x is equal to amplitude&nbsp;<span class="math-tex">{tex}\\pm{/tex}</span>A. I.e. maximum displacement on both sides. Thus maximum P.E. is when x =&nbsp;<span class="math-tex">{tex}\\pm{/tex}</span>A.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Zero</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex} \\pm  {A\\over2}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex} \\pm {/tex}</span> A<span class="math-tex">{tex}\\sqrt 2 {/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>What is constant in simple harmonic motion?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">Time period </p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The time period of the SHM is given by&nbsp;T =&nbsp;<span class="math-tex">{tex}2\\pi\\sqrt{m\\over k}{/tex}</span>&nbsp;where &#39;m&#39; be the mass of the body (constant), &#39;k&#39;&nbsp;restoring force constant&nbsp;as T depends on &#39;m&#39; and &#39;k&#39; and they are constant for the system, so the corresponding Time period of the motion is Constant.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">Restoring force</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">Kinetic motion</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Potential energy</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Velocity of a body moving in simple harmonic motion is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\omega \\sqrt{a^{2}+y^{2}}{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\omega^{2} \\sqrt{a^{2}+y^{2}}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\omega \\sqrt{a^{2}-y^{2}}{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>In SHM,<br />
v&nbsp;=&nbsp;<span class="math-tex">{tex}\\omega \\sqrt{a^{2}-y^{2}}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\omega^{2} \\sqrt{a^{2}-y^{2}}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>The acceleration due to gravity on the surface of moon is 1.7 m/s<sup>2</sup>. What is the time period of simple pendulum on moon if its time period on the earth is 3.5s? (g on the surface of earth is 9.8 ms<sup>-2</sup>).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If l = length of simple pendulum,<br />
T = Time Period<br />
g = Acceleration due to gravity.<br />
Then, on earth ; <span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { l } { g } } \\rightarrow ( 1 ){/tex}</span></p>

<p>On Moon ; <span class="math-tex">{tex}T _ { 1 } = 2 \\pi \\sqrt { \\frac { l } { g _ { 1 } } } \\rightarrow 2 ){/tex}</span></p>

<p>g<sub>1</sub> = Acceleration due to gravity on moon = 1.7 m | S<sup>2</sup></p>

<p>g = Acceleration due to gravity on earth = 9.8m | s<sup>2</sup><br />
Dividing equation 2) by (1)</p>

<p><span class="math-tex">{tex}\\frac { T _ { 1 } } { T } = \\sqrt { \\frac { g } { g _ { 1 } } }{/tex}</span></p>

<p><span class="math-tex">{tex}\\frac { T _ { 1 } } { T } = \\sqrt { \\frac { 9.8 } { 1.7 } }{/tex}</span></p>

<p><span class="math-tex">{tex}T _ { 1 } = T \\times \\sqrt { \\frac { 9.8 } { 1.7 } }{/tex}</span></p>

<p><span class="math-tex">{tex}T _ { 1 } = 3.5 \\times \\sqrt { \\frac { 9.8 } { 1.7 } }{/tex}</span></p>

<p>T<sub>1</sub> = 8.4 s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A simple harmonic oscillation is represented by the equation,<br />
y = 0.40 sin (440t&nbsp;+ 0.61)<br />
Here y and t are in m and s respectively. What are the values of</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>amplitude</li>
	<li>angular frequency</li>
	<li>frequency of oscillations</li>
	<li>time period of oscillations and</li>
	<li>initial phase?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The given equation is y = 0.40 sin (440 t + 0.61)<br />
Comparing it with the equation of SHM&nbsp;<br />
y = a sin&nbsp;<span class="math-tex">{tex}\\left(\\omega t+\\phi_{0}\\right){/tex}</span>&nbsp;<br />
We have,</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Amplitude, a = 0.40 m</li>
	<li>Angular frequency,&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;= 440 Hz</li>
	<li>Frequency of oscillations,<br />
	<span class="math-tex">{tex}\\mathrm{v}=\\frac{\\omega}{2 \\pi}=\\frac{440}{2 \\times 22 / 7}{/tex}</span>&nbsp;= 70 Hz</li>
	<li>Time period of oscillations<br />
	T =&nbsp;<span class="math-tex">{tex}\\frac{1}{\\mathrm{v}}=\\frac{1}{70}{/tex}</span>&nbsp;= 0.0143</li>
	<li>Initial phase angle,&nbsp;<span class="math-tex">{tex}\\phi_0{/tex}</span> = 0.61 rad</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Determine the time period of oscillation of a simple pendulum.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The pendulum begins a periodic motion when the bob is shifted to a particular angle, and the periodic motion is a simple harmonic motion with angular displacement of the bob for small values of the displacement angle.<br />
F = -mg sin<span class="math-tex">{tex}\\theta{/tex}</span><br />
And<br />
a = -g sin<span class="math-tex">{tex}\\theta{/tex}</span><br />
Let us Consider is small for the small oscillation<br />
Therefore,<br />
sin<span class="math-tex">{tex}\\theta{/tex}</span> = <span class="math-tex">{tex}\\theta{/tex}</span> = <span class="math-tex">{tex}\\frac xl{/tex}</span><br />
After Putting this value in a, we get<br />
a = -g<span class="math-tex">{tex}\\theta{/tex}</span><br />
a = <span class="math-tex">{tex}\\frac{-gx}{l}{/tex}</span><br />
a = <span class="math-tex">{tex}\\frac{−\\omega^2}{x}{/tex}</span><br />
Hence, the Angular Frequency is = <span class="math-tex">{tex}\\frac{2\\pi}{T}{/tex}</span><br />
<span class="math-tex">{tex}\\mathrm\\omega=\\sqrt{\\frac{\\mathrm g}{\\mathrm l}}\\\\\\mathrm T\\;=\\frac{2\\mathrm\\pi}{\\mathrm\\omega}=2\\mathrm\\pi\\sqrt{\\frac{\\mathrm l}{\\mathrm g}}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Which of the following functions of time represent</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>periodic and</li>
	<li>non-periodic motion?</li>
</ol>

<p>Give the period for each case of periodic motion [<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;is any positive constant].</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>sin <span class="math-tex">{tex}\\omega{/tex}</span>t + cos <span class="math-tex">{tex}\\omega{/tex}</span>t</li>
	<li>sin <span class="math-tex">{tex}\\omega{/tex}</span>t + cos 2 <span class="math-tex">{tex}\\omega{/tex}</span>t + sin 4 <span class="math-tex">{tex}\\omega{/tex}</span>t</li>
	<li><span class="math-tex">{tex}e^{-\\omega t}{/tex}</span></li>
	<li>log (<span class="math-tex">{tex}\\omega{/tex}</span>t)</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>sin <span class="math-tex">{tex}\\omega{/tex}</span>t + cos <span class="math-tex">{tex}\\omega{/tex}</span>t is a periodic function, it can also be written as <span class="math-tex">{tex}\\sqrt{2}{/tex}</span>&nbsp;sin (<span class="math-tex">{tex}\\omega{/tex}</span>t + <span class="math-tex">{tex}\\frac{\\pi}{4}{/tex}</span>)<br />
	Now <span class="math-tex">{tex}\\sqrt{2}{/tex}</span>&nbsp;sin (<span class="math-tex">{tex}\\omega{/tex}</span>t + <span class="math-tex">{tex}\\frac{\\pi}{4}{/tex}</span>) = <span class="math-tex">{tex}\\sqrt{2}{/tex}</span>&nbsp;sin (<span class="math-tex">{tex}\\omega{/tex}</span>t + <span class="math-tex">{tex}\\frac{\\pi}{4}{/tex}</span>&nbsp;+ 2<span class="math-tex">{tex}\\pi{/tex}</span>)&nbsp;<br />
	=&nbsp;<span class="math-tex">{tex}\\sqrt{2}{/tex}</span>&nbsp;sin [(<span class="math-tex">{tex}\\omega{/tex}</span>t + <span class="math-tex">{tex}\\frac{2\\pi}{\\omega}{/tex}</span>) + <span class="math-tex">{tex}\\frac{\\pi}{4}{/tex}</span>]<br />
	The periodic time of the function is <span class="math-tex">{tex}\\frac{2\\pi}{\\omega}{/tex}</span>.</li>
	<li>This is an example of a periodic motion. It can be noted that each term represents a periodic function with a different angular frequency. Since period is the least interval of time after which a function repeats its value, sin &omega;t has a period T<sub>o&nbsp;</sub>= <span class="math-tex">{tex}\\frac{2\\pi}{\\omega}{/tex}</span>; cos 2 <span class="math-tex">{tex}\\omega{/tex}</span>t has a period <span class="math-tex">{tex}\\frac{\\pi}{\\omega}{/tex}</span>&nbsp;= <span class="math-tex">{tex}\\frac{T_o}{2}{/tex}</span>; and sin 4 <span class="math-tex">{tex}\\omega{/tex}</span>t has a period <span class="math-tex">{tex}\\frac{2\\pi}{4\\omega}{/tex}</span> = <span class="math-tex">{tex}\\frac{T_o}{4}{/tex}</span>. The period of the first term is a multiple of the periods of the last two terms. Therefore, the smallest interval of time after which the sum of the three terms repeats is T<sub>o</sub>, and thus, the sum is a periodic function with a period <span class="math-tex">{tex}\\frac{2\\pi}{\\omega}{/tex}</span>.</li>
	<li>The function&nbsp;<span class="math-tex">{tex}e^{-\\omega t}{/tex}</span>&nbsp;is not periodic, it decreases monotonically with increasing time and tends to zero as t <span class="math-tex">{tex}\\longrightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}\\infty{/tex}</span>&nbsp;and thus, never repeats its value.</li>
	<li>The function log(<span class="math-tex">{tex}\\omega{/tex}</span>t) increases monotonically with time t. It, therefore, never repeats its value and is a nonperiodic function. It may be noted that as t <span class="math-tex">{tex}\\longrightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}\\infty{/tex}</span>, log(<span class="math-tex">{tex}\\omega{/tex}</span>t) diverges to <span class="math-tex">{tex}\\infty{/tex}</span>. It, therefore, cannot represent any kind of physical displacement.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is S.H.M.? Show that the acceleration of a particle in S.H.M. is proportional to its displacement. Also write expression for the time-period in terms of acceleration.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Displacement, x = A cos <span class="math-tex">{tex}\\omega{/tex}</span>t<br />
Velocity,&nbsp;<span class="math-tex">{tex}v=\\frac{d x}{d t}=-\\omega A \\sin \\omega t{/tex}</span><br />
Acceleration,&nbsp;<span class="math-tex">{tex}a=\\frac{d v}{d t}=-\\omega^{2} A \\cos \\omega t=-\\omega^{2} x{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Therefore, acceleration <span class="math-tex">{tex}\\propto{/tex}</span> displacement. Magnitude of acceleration in S.H.M. is<br />
<span class="math-tex">{tex}a=\\omega^{2} x{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}\\omega^{2}=\\frac a x{/tex}</span><br />
<span class="math-tex">{tex}\\therefore T=\\frac{2 \\pi}{\\omega}=\\frac{2 \\pi}{\\sqrt{\\frac a x}}{/tex}</span><br />
<span class="math-tex">{tex}=2 \\pi \\sqrt{\\frac{x}{a}}=2 \\pi \\sqrt{\\frac{\\text { Displacement }}{\\text { Acceleration }}}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Prove that the sum of kinetic energy, potential energy and total energy of a particle doing SHM is constant.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>For SHM,<br />
acceleration , a = <span class="math-tex">{tex}\\frac{-\\omega^2}y{/tex}</span><br />
F = ma = <span class="math-tex">{tex}\\frac{-m\\omega^2}y{/tex}</span><br />
now, work , W = F.dy cos180<sup>o</sup> {because displacement and acceleration are in opposite direction so, cos180<sup>o</sup> taken}<br />
W = <span class="math-tex">{tex}\\int{/tex}</span>m<span class="math-tex">{tex}\\omega^2y{/tex}</span>.dy = <span class="math-tex">{tex}\\frac{m\\omega^2y^2}{2}{/tex}</span><br />
use standard form of SHM, y = Asin(<span class="math-tex">{tex}\\omega t \\pm \\phi{/tex}</span>)<br />
W = <span class="math-tex">{tex}\\frac{m\\omega^2A^2}{2sin²(\\omega t \\pm \\phi) }{/tex}</span><br />
We know, Potential energy is work done stored in system .<br />
so, P.E = W = <span class="math-tex">{tex}\\frac{m\\omega^2A^2}{2sin²(\\omega t \\pm \\phi) }{/tex}</span><br />
again, Kinetic energy , K.E = <span class="math-tex">{tex}\\frac12{/tex}</span>mv<sup>2</sup>, here v is velocity<br />
we know, v = <span class="math-tex">{tex}\\omega{/tex}</span> A cos(<span class="math-tex">{tex}\\omega t \\pm \\phi{/tex}</span>)<br />
so, K.E = <span class="math-tex">{tex}\\frac{m\\omega^2A^2}{2cos^2(\\omega t \\pm \\phi)}{/tex}</span><br />
Total energy = K.E + P.E<br />
= <span class="math-tex">{tex}\\frac{m\\omega^2A^2}{2 cos^2(\\omega t \\pm \\phi)}{/tex}</span> + <span class="math-tex">{tex}\\frac{m\\omega^2A^2}{2 sin^2(\\omega t \\pm \\phi)}{/tex}</span><br />
= <span class="math-tex">{tex}\\frac{m\\omega^2 A^2}{2}{/tex}</span> [cos<sup>2</sup>(<span class="math-tex">{tex}\\omega t \\pm \\phi{/tex}</span>) + sin<sup>2</sup>(<span class="math-tex">{tex}\\omega t \\pm \\phi{/tex}</span>)] = <span class="math-tex">{tex}\\frac{m\\omega^2 A^2}{2}{/tex}</span> [<span class="math-tex">{tex}\\because{/tex}</span> sin<sup>2</sup><span class="math-tex">{tex}\\alpha{/tex}</span>+ cos<sup>2</sup><span class="math-tex">{tex}\\alpha{/tex}</span>=1]<br />
= <span class="math-tex">{tex}\\frac{m\\omega^2 A^2}{2}{/tex}</span> = constant<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1709115155-y6zp6x.jpg" style="height:149px; width:250px" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><html><body><p>The figure given below depicts two circular motions. The radius of the circle, the period of revolution, the initial position and the sense of revolution are indicated in the figures. Obtain the simple harmonic motions of the x-projection of the radius vector of the rotating particle P in each case.<br/>
<img alt="" data-imgur-src="gmephp9.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1614338776-vtvpgp.jpg" style="width: 200px; height: 106px;"/></p></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>At t = 0, OP makes an angle of 45<sup>o</sup> =&nbsp;<span class="math-tex">{tex}\\frac{\\pi}{4}{/tex}</span>&nbsp;rad with the (positive direction of ) x-axis. After time t, it covers an angle&nbsp;<span class="math-tex">{tex}\\frac{2\\pi t}{T}{/tex}</span>&nbsp;in the anticlockwise sense, and makes an angle of&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{T} t+\\frac{\\pi}{4}{/tex}</span>&nbsp;with the x-axis.<br />
	The projection of OP on the x-axis at time t is given by,<br />
	x(t) = A cos&nbsp;<span class="math-tex">{tex}\\left(\\frac{2 \\pi}{T} t+\\frac{\\pi}{4}\\right){/tex}</span>&nbsp;<br />
	For T = 4s.<br />
	x(t) = A cos&nbsp;<span class="math-tex">{tex}\\left(\\frac{2 \\pi}{4} t+\\frac{\\pi}{4}\\right){/tex}</span>&nbsp;<br />
	which is an SHM of amplitude A, period 4s, and an initial phase =&nbsp;<span class="math-tex">{tex}\\frac{\\pi}{4}{/tex}</span>&nbsp;</li>
	<li>In this case at t = 0, OP makes an angle of 90<sup>o</sup> =&nbsp;<span class="math-tex">{tex}\\frac{\\pi}{2}{/tex}</span>&nbsp;with the x-axis. After a time t, it covers an angle of&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{T} t{/tex}</span>&nbsp;in the clockwise sense and makes an angle of&nbsp;<span class="math-tex">{tex}\\left(\\frac{\\pi}{2}-\\frac{2 \\pi}{T} t\\right){/tex}</span>&nbsp;with the x-axis at time t is given by<br />
	x(t) = B cos&nbsp;<span class="math-tex">{tex}\\left(\\frac{\\pi}{2}-\\frac{2 \\pi}{T} t\\right){/tex}</span>&nbsp;= B sin&nbsp;<span class="math-tex">{tex}\\left(\\frac{2 \\pi}{T} t\\right){/tex}</span>&nbsp;<br />
	For T = 30s.<br />
	x(t) = B sin&nbsp;<span class="math-tex">{tex}\\left(\\frac{\\pi}{15} t\\right){/tex}</span>&nbsp;<br />
	Writing this as x(t) = B cos&nbsp;<span class="math-tex">{tex}\\left(\\frac{\\pi}{15} t-\\frac{\\pi}{2}\\right){/tex}</span>, and&nbsp;comparing with x(t) = A cos (<span class="math-tex">{tex}\\omega{/tex}</span>t + <span class="math-tex">{tex}\\phi{/tex}</span>). We find that this represents an SHM of amplitude B, period 30 s, and an initial phase of&nbsp; -<span class="math-tex">{tex}\\frac{\\pi}{2}{/tex}</span>.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Determine the time period of a simple pendulum of length&nbsp;&#39;l&#39; when mass of bob is&#39;m&#39; Kg?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>A&nbsp;<b>simple pendulum</b>&nbsp;is one which can be considered to be a point mass suspended from a string or rod of negligible mass. It is a resonant system with a&nbsp;<b>single</b>resonant frequency.It consist of a heavy point mass body suspended by a weightless inextensible and perfectly flexible string from a&nbsp;rigid support which is free to oscillate.<br />
The distance between point of suspension and point of oscillation is effective length of pendulum.<br />
M = Mass of Bob<br />
x = Displacement = OB<br />
l = length of simple pendulum<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch14/3m/image053.png" style="height: 103px; width: 150px;" /><br />
Let the bob is displaced through a small angle &theta; the forces acting on it:-</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>weight = Mg acting vertically downwards.</li>
	<li>Tension = T acting upwards towards fixed point.</li>
</ol>

<p>Divide Mg into its components &rarr; Mg Cos &theta;(opposite to Tension) &amp; Mg Sin &theta;(Provides restoring force)<br />
T = Mg Cos &theta;<br />
F = Mg Sin &theta;<br />
- ve sign shows force is diverted towards the ocean positions. If &theta; = Small (from 0<sup>0</sup>&nbsp;to 15<sup>0</sup>)<br />
<span class="math-tex">{tex}\\sin \\theta \\cong \\theta = \\frac { A r c O B } { l } = \\frac { x } { l }{/tex}</span>&nbsp;​​​​​​​<br />
<span class="math-tex">{tex}F = - M g \\frac { x } { l }{/tex}</span>&nbsp;<br />
In S.H.M., vectoring fore, <span class="math-tex">{tex}\\mathrm { F } = - \\mathrm { mg } \\text { } \\theta {/tex}</span>&nbsp;​​​​​​​<br />
<span class="math-tex">{tex} \\mathrm { F } = - \\mathrm { mg } \\frac { x } { l } \\rightarrow 1 ){/tex}</span>&nbsp;<br />
Also, if k = spring constant<br />
F = - k x​​​​​​​<br />
<span class="math-tex">{tex}- \\operatorname { mg } \\frac { x } { l } = - k x \\left( \\text { equating } \\mathrm { F } = - \\operatorname { mg } \\frac { x } { l } \\right){/tex}</span>&nbsp;&nbsp;​​​​​​​<br />
<span class="math-tex">{tex}k = \\frac { m g } { l }{/tex}</span>&nbsp;​​​​​​​<br />
<span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { m } { k } }{/tex}</span>&nbsp;​​​​​​​<br />
<span class="math-tex">{tex}= 2 \\pi \\sqrt { \\frac { m \\times l } { m g } }{/tex}</span>&nbsp;​​​​​​​<br />
<span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { l } { g } }{/tex}</span>&nbsp;<br />
i.e.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Time period depends on length of pendulum and &lsquo;g&rsquo; of place where experiment is done(in most of the cases &#39;g&#39; is assumed to be constant)</li>
	<li>T is independent of amplitude of vibration provided and it is small and also of the mass of the bob.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A body oscillates with SHM according to the equation (in SI units),<br />
x = 5 cos [2<span class="math-tex">{tex}\\pi{/tex}</span>t + <span class="math-tex">{tex}\\frac{\\pi}{4}{/tex}</span>].<br />
At t = 1.5 s, calculate the</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>displacement,</li>
	<li>speed and</li>
	<li>acceleration of the body</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Equation of SHM is given by , x (t) = 5.0 cos<span class="math-tex">{tex}\\left[ \\ 2 \\pi t + \\pi / 4\\right.]{/tex}</span>&nbsp;m<br />
	time, t = 1.5 s<br />
	x(t) =&nbsp;<span class="math-tex">{tex}5.0 \\times \\cos [ 2 \\pi \\times 1.5 + \\pi / 4 ]{/tex}</span>&nbsp;|<br />
	<span class="math-tex">{tex}= 5.0 \\times \\cos \\left( 3 \\pi + \\frac { \\pi } { 4 } \\right) = - 5.0 \\cos \\frac { \\pi } { 4 }{/tex}</span>&nbsp;<br />
	= -5.0 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;(0.707) = -3.535 m,</li>
	<li>Now velocity of the particle executing SHM is given by,<br />
	<span class="math-tex">{tex}v = \\frac { d x } { d t } = \\frac { d } { d t } \\left[ 5.0 \\cos \\left( 2 \\pi t + \\frac { \\pi } { 4 } \\right) \\right]{/tex}</span>&nbsp;&nbsp;<br />
	=&nbsp;<span class="math-tex">{tex} - 5.0 \\times \\sin \\left( 2 \\pi t + \\frac { \\pi } { 4 } \\right) \\times 2 \\pi{/tex}</span>&nbsp;&nbsp;<br />
	=&nbsp;<span class="math-tex">{tex} - 10 \\pi \\sin \\left( 2 \\pi t + \\frac { \\pi } { 4 } \\right){/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\therefore \\quad \\left. \\frac { d x } { d t } \\right| _ { t = 1.5 s} = - 10 \\pi \\sin \\left( 3 \\pi + \\frac { \\pi } { 4 } \\right)m/s{/tex}</span><span class="math-tex">{tex}= 10 \\pi \\times 0.707{/tex}</span>&nbsp;m/s<br />
	= 22.22 m/s &nbsp;</li>
	<li>Acceleration of the particle executing SHM&nbsp;is given by<br />
	<span class="math-tex">{tex}a = \\frac { d v } { d t } = \\frac { d } { d t } \\left[ - 10 \\pi \\sin \\left[ 2 \\pi t + \\frac { \\pi } { 4 } \\right] \\right]{/tex}</span>&nbsp;<br />
	=&nbsp;<span class="math-tex">{tex} - 10 \\pi \\times 2 \\pi \\cos \\left( 2 \\pi t + \\frac { \\pi } { 4 } \\right){/tex}</span>&nbsp;<br />
	<span class="math-tex">{tex}\\left. \\frac { d v } { d t } \\right| _ { t = 1.5s } = - 20 \\pi ^ { 2 } \\cos \\left( 3 \\pi + \\frac { \\pi } { 4 } \\right) = 139.56 ~\\mathrm { m } / \\mathrm { s } ^ { 2 }{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A block whose mass is 1 kg is fastened to a spring. The spring has a spring constant of 50 Nm<sup>-1</sup>. The block is pulled to a distance x = 10 cm from its equilibrium position at x = 0 on a frictionless surface from rest at t = 0. Calculate the kinetic, potential and total energies of the block when it is 5 cm away from the mean position.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, mass(m) =1 kg, spring constant(k) =50 Nm<sup>-1</sup>, amplitude(A) =10 cm = 0.1 m, displacement(x) = 5 cm =0.05 m<br />
Kinetic energy,<br />
K =&nbsp;<span class="math-tex">{tex}\\frac { 1 } { 2 } k \\left( A ^ { 2 } - x ^ { 2 } \\right){/tex}</span><br />
<span class="math-tex">{tex}K = \\frac { 1 } { 2 } \\times 50 \\times \\left[ ( 0.1 ) ^ { 2 } - ( 0.05 ) ^ { 2 } \\right]{/tex}</span><br />
= 0.1875 J<br />
The potential energy of the block<br />
U =&nbsp;<span class="math-tex">{tex}\\frac { 1 } { 2 } k x ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 } \\times 50 \\times ( 0.05 ) ^ { 2 }{/tex}</span><br />
= 0.0625 J<br />
Total energy, E = K + U = 0.1875 + 0.0625<br />
E =0.25 J<br />
&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A spring balance has a scale that reads from 0 to 50 kg. The length of the scale is 20 cm. A body suspended from this balance, when displaced and released, oscillates with a period of 0.6 s. What is the weight of the body?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given that<br />
Maximum mass that the scale can read, M = 50 kg<br />
Maximum displacement of the spring is given by&nbsp; = Length of the scale, l = 20 cm = 0.2 m<br />
Time period is , T = 0.6 s<br />
Maximum force exerted on the spring is given by , F = Mg<br />
Where,<br />
g = acceleration due to gravity = 9.8 m/s<sup>2</sup><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;F = 50<span class="math-tex">{tex}\\times{/tex}</span>9.8 = 490N<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Spring constant is, <span class="math-tex">{tex}k = \\frac { F } { l } = \\frac { 490 } { 0.2 } = 2450 \\mathrm { Nm } ^ { - 1 }{/tex}</span><br />
Since, Mass m, is suspended from the balance.<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Time period is given by , <span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { m } { k } }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}m= \\left( \\frac { T } { 2 \\pi } \\right) ^ { 2 } \\times k{/tex}</span> <span class="math-tex">{tex}= \\left( \\frac { 0.6 } { 2 \\times 3.14 } \\right) ^ { 2 } \\times 2450 = 22.36 \\mathrm { kg }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore {/tex}</span> Weight of the body = mg = 22.36&nbsp;&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;9.8 = 219.167 N<br />
Hence, the weight of the body is about 219 N.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A particle executes SHM with a time period of 2 s and amplitude 5 cm. Find</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>displacement</li>
	<li>velocity and</li>
	<li>acceleration after 1/3 s starting from the mean position.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here, T = 2 s, A = 5 cm, t = <span class="math-tex">{tex}\\frac 13{/tex}</span>s</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>For the particle starting from mean position, (i.e.<span class="math-tex">{tex}\\phi{/tex}</span>&nbsp; = 0) displacement,<br />
	x = A sin<span class="math-tex">{tex}\\omega{/tex}</span>t =&nbsp;<span class="math-tex">{tex} A \\sin \\frac { 2 \\pi } { T } t{/tex}</span><br />
	<span class="math-tex">{tex}= 5 \\sin \\frac { 2 \\pi } { 2 } \\times \\frac { 1 } { 3 } = 5 \\sin \\frac { \\pi } { 3 }{/tex}</span>(since t = 1/3 s)<br />
	<span class="math-tex">{tex}= 5 \\times \\frac { \\sqrt { 3 } } { 2 }{/tex}</span>= 4.33 cm</li>
	<li>Velocity of the particle executing SHM,&nbsp;<span class="math-tex">{tex}v = \\frac { d x } { d t } = \\frac { d ( A \\sin \\omega t ) } { d t } = A \\omega \\cos \\omega t{/tex}</span><br />
	<span class="math-tex">{tex}= \\frac { 2 \\pi A } { T } \\cos \\frac { 2 \\pi } { T } t = \\frac { 2 \\pi \\times 5 } { 2 } \\cos \\frac { \\pi } { 3 }{/tex}</span><br />
	<span class="math-tex">{tex}= 5 \\times 3.14 \\times 0.5{/tex}</span><br />
	= 7.85 cm s<sup>-1</sup></li>
	<li>Acceleration of the particle executing SHM, a =&nbsp;<span class="math-tex">{tex}\\frac { d v } { d t } = \\frac { d ( A \\omega \\cos \\omega t ) } { d t } = - A \\omega ^ { 2 } \\sin \\omega t{/tex}</span><br />
	<span class="math-tex">{tex}= - \\frac { 4 \\pi ^ { 2 } A } { T ^ { 2 } } \\sin \\frac { 2 \\pi } { T } t{/tex}</span><br />
	<span class="math-tex">{tex}= - \\frac { 4 \\times 9.87 \\times 5 } { 4 } \\sin \\frac { \\pi } { 3 }{/tex}</span><br />
	<span class="math-tex">{tex}= - 9.87 \\times 5 \\times \\frac { \\sqrt { 3 } } { 2 }{/tex}</span>= -42.73 cm s<sup>-2</sup><br />
	<span class="math-tex">{tex}\\therefore | a | = 42.73\\; \\mathrm { cm } \\mathrm { s } ^ { - 2 }{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that for small oscillations the motion of a simple pendulum is simple harmonic. Derive an expression for its time period. Does it depend on the mass of the bob?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p><strong>Simple pendulum:</strong> An ideal simple pendulum consists of a point-mass suspended by a flexible, inelastic and weightless string from a rigid support of infinite mass. In practice, we can neither have a point-mass nor a weightless string. In practice, a simple pendulum is obtained by suspending a small metal bob by a long and fine cotton thread from a rigid support.<br/>
Expression for time period. In the equilibrium position, the bob of a simple pendulum lies vertically below the point of suspension. If the bob is slightly displaced on either side and released, it begins to oscillate about the mean position.<br/>
Suppose at any instant during oscillation, the bob lies at position A when its displacement is O A=x and the thread makes an angle <span class="math-tex">{tex}\\theta{/tex}</span> with the vertical. The forces acting on the bob are<br/>
(i) Weight mg of the bob acting vertically downwards.<br/>
(ii) Tension T along the string<br/>
<img alt="" data-imgur-src="GSVq0XK.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082744-4zx4hp.jpg" style="width: 200px; height: 244px;"/><br/>
The force mg has two rectangular components</p>
<ol start="1" style="list-style-type: lower-roman;">
<li>the component mg<span class="math-tex">{tex} \\cos \\theta{/tex}</span> acting along the thread is balanced by the tension T in the thread and</li>
<li>the tangential component m g<span class="math-tex">{tex}\\sin \\theta{/tex}</span> is the net force acting on the bob and tends to bring it back to the mean position. Thus, the restoring force is</li>
</ol>
<p>F = <span class="math-tex">{tex}-m g \\sin \\theta=-m g\\left(\\theta-\\frac{\\theta^{3}}{3 !}+\\frac{\\theta^{5}}{5 !}-\\ldots . .\\right){/tex}</span><br/>
<span class="math-tex">{tex}=-m g \\theta\\left(1-\\frac{\\theta^{2}}{6}+\\frac{\\theta^{4}}{120}-\\ldots . .\\right){/tex}</span> <br/>
where <span class="math-tex">{tex} \\theta{/tex}</span> is in radians. Clearly, oscillations are not simple harmonic because the restoring force F is not proportional to the angular displacement <span class="math-tex">{tex} \\theta{/tex}</span>.<br/>
However, if <span class="math-tex">{tex}\\theta{/tex}</span> is so small that its higher powers can be neglected, then<br/>
F = -mg<span class="math-tex">{tex} \\theta{/tex}</span><br/>
If l is the length of the simple pendulum, then<br/>
<span class="math-tex">{tex}\\theta(\\mathrm{rad})=\\frac{\\operatorname{arc}}{\\text { radius }}=\\frac{x}{l}{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> <span class="math-tex">{tex}F=-m g \\frac{x}{l}{/tex}</span><br/>
or <span class="math-tex">{tex}m a=-\\frac{m g}{l} x{/tex}</span><br/>
or <span class="math-tex">{tex}a=-\\frac{g}{l} x=-\\omega^{2} x{/tex}</span><br/>
Thus, the acceleration of the bob is proportional to its displacement x and is directed opposite to it. Hence for small oscillations, the motion of the bob is simple harmonic. Its time period is<br/>
<span class="math-tex">{tex}T=\\frac{2 \\pi}{\\omega}=\\frac{2 \\pi}{\\sqrt{g / l}}{/tex}</span> or <span class="math-tex">{tex}T=2 \\pi \\sqrt{\\frac{l}{g}}{/tex}</span><br/>
Obviously, the time period of a simple pendulum depends on its length l and acceleration due to gravity <span class="math-tex">{tex}\\theta{/tex}</span> but is independent of the mass m of the bob.</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that the total energy of a body executing SHM is independent of time?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> Let y = displacement at any time&lsquo;t&rsquo;<br />
<span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> a = amplitude<br />
<span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> &omega; = Angular frequency<br />
<span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> v = velocity,<br />
<span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> y = a Sin &omega;t<br />
<span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> So, <span class="math-tex">{tex}v = \\frac { d y } { d t } = \\frac { d } { d t } ( \\mathrm { a } \\sin \\mathrm { ωt } ){/tex}</span></p>

<p><span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> v = a &omega; cos wt<br />
<span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> Now, kinetic energy = K. E. = <span class="math-tex">{tex}\\frac { 1 } { 2 } m v ^ { 2 }{/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow K . E . = \\frac { 1 } { 2 } \\mathrm { m } \\mathrm { ω } ^ { 2 } \\mathrm { a } ^ { 2 } \\cos ^ { 2 } \\mathrm { ωt }{/tex}</span> <span class="math-tex">{tex}\\to{/tex}</span>&nbsp;1)</p>

<p><span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> Potential energy <span class="math-tex">{tex}= \\frac { 1 } { 2 } k y ^ { 2 }{/tex}</span></p>

<p><span class="math-tex">{tex}\\Rightarrow P . E = \\frac { 1 } { 2 } k a ^ { 2 } \\sin ^ { 2 } ω t \\rightarrow 2 ){/tex}</span></p>

<p>Adding equation (1) &amp; (2)<br />
<span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> Total energy = K.E. + P.E.</p>

<p><span class="math-tex">{tex}= \\frac { 1 } { 2 } m ω ^ { 2 } a ^ { 2 } \\cos ^ { 2 } ω t + \\frac { 1 } { 2 } k a ^ { 2 } \\sin ^ { 2 } ω t{/tex}</span></p>

<p><span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> Since <span class="math-tex">{tex}ω = \\sqrt { \\frac { k } { m } } \\Rightarrow ω ^ { 2 } m = k ^ { 2 }{/tex}</span></p>

<p><span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> Total energy <span class="math-tex">{tex}= \\frac { 1 } { 2 } m ω ^ { 2 } a ^ { 2 } \\cos ^ { 2 } ω t + \\frac { 1 } { 2 } k a ^ { 2 } \\sin ^ { 2 } ω t{/tex}</span></p>

<p><span class="math-tex">{tex}= \\frac { 1 } { 2 } k a ^ { 2 } \\cos ^ { 2 } ω t + \\frac { 1 } { 2 } k a ^ { 2 } \\sin _ { 2 } ω t{/tex}</span></p>

<p><span class="math-tex">{tex}= \\frac { 1 } { 2 } \\mathrm { ka } ^ { 2 } \\left( \\operatorname { cos } ^ { 2 } \\mathrm { ω } \\mathrm { t } + \\sin ^ { 2 } \\mathrm { ωt } \\right){/tex}</span></p>

<p><span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> Total energy <span class="math-tex">{tex}\\frac12ka^2{/tex}</span></p>

<p><span>​</span><span class="math-tex">{tex}\\Rightarrow{/tex}</span><span>​</span> <span>​</span><span>​</span>Thus total mechanical energy is always constant is equal to <span class="math-tex">{tex}\\frac { 1 } { 2 } k a ^ { 2 }{/tex}</span>. The total energy is independent to time.&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Obtain an expression for the velocity of a particle executing SHM, when is this velocity</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>maximum and</li>
	<li>minimum.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li><span class="math-tex">{tex}\\frac{d^2x}{dl}{/tex}</span> + w<sup>2</sup>x = 0 <span class="math-tex">{tex}\\Rightarrow{/tex}</span> x = Asin(wt + <span class="math-tex">{tex}\\phi{/tex}</span>) differentiate with respect to t <span class="math-tex">{tex}\\Rightarrow \\frac{dx}{dt}{/tex}</span> = Awcos(wt + <span class="math-tex">{tex}\\phi{/tex}</span>) <span class="math-tex">{tex}\\Rightarrow{/tex}</span> v = Aw{cos(wt + <span class="math-tex">{tex}\\phi{/tex}</span>)}&nbsp; &nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span> v<sub>max</sub> = Aw (where A is amplitude of medium)</li>
	<li>v<sub>min</sub> = 0</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that for a particle in linear SHM the average kinetic energy over a period of oscillation equal&nbsp;the average potential energy over the same period.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Suppose a particle of mass m executes SHM of time period T. The displacement of the particle at any instant t is given by the below general equation,<br />
y = A sin<span class="math-tex">{tex}\\omega{/tex}</span>t<br />
Velocity of the particle is given by, v =&nbsp;<span class="math-tex">{tex}\\frac { d y } { d t } = \\omega A \\cos \\omega t{/tex}</span><br />
Kinetic energy is given by, E<sub>K</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac { 1 } { 2 } m v ^ { 2 } = \\frac { 1 } { 2 } m \\omega ^ { 2 } A ^ { 2 } \\cos ^ { 2 } \\omega t{/tex}</span><br />
and Potential energy is given by, E<sub>p</sub>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac { 1 } { 2 } m \\omega ^ { 2 } y ^ { 2 } = \\frac { 1 } { 2 } m \\omega ^ { 2 } A ^ { 2 } \\sin ^ { 2 } \\omega t{/tex}</span><br />
Average KE of the particle executing SHM over a complete period of oscillation is given by,<br />
<span class="math-tex">{tex}E _ { k _ { \\mathrm { av } } } = \\frac { 1 } { T } \\int _ { 0 } ^ { T } E _ { k } d t = \\frac { 1 } { T } \\int _ { 0 } ^ { T } \\frac { 1 } { 2 } m \\omega ^ { 2 } A ^ { 2 } \\cos ^ { 2 } \\omega t~ d t{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 T } m \\omega ^ { 2 } A ^ { 2 } \\int _ { 0 } ^ { T } \\frac { ( 1 + \\cos 2 \\omega t ) } { 2 } d t{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 4 T } m \\omega ^ { 2 } A ^ { 2 } \\left[ t + \\frac { \\sin 2 \\omega t } { 2 \\omega } \\right] _ { 0 } ^ { T }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 4 T } m \\omega ^ { 2 } A ^ { 2 } ( T ) = \\frac { 1 } { 4 } m \\omega ^ { 2 } A ^ { 2 }{/tex}</span>..........(i)<br />
Now average PE of the particle executing SHM over a complete period of oscillation is given by,<br />
<span class="math-tex">{tex}E _ { p _ { \\mathrm { pv } } } = \\frac { 1 } { T } \\int _ { 0 } ^ { T } E _ { p } d t = \\frac { 1 } { T } \\int _ { 0 } ^ { T } \\frac { 1 } { 2 } m \\omega ^ { 2 } A ^ { 2 } \\sin ^ { 2 } \\omega t d t{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 2 T } m \\omega ^ { 2 } A ^ { 2 } \\int _ { 0 } ^ { T } \\frac { ( 1 - \\cos 2 \\omega t ) } { 2 } d t{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 4 T } m \\omega ^ { 2 } A ^ { 2 } \\left[ t - \\frac { \\sin 2 \\omega t } { 2 \\omega } \\right] _ { 0 } ^ { T }{/tex}</span><br />
<span class="math-tex">{tex}= \\frac { 1 } { 4 T } m \\omega ^ { 2 } A ^ { 2 } ( T ) = \\frac { 1 } { 4 } m \\omega ^ { 2 } A ^ { 2 }{/tex}</span>...........(ii)<br />
So it is clearly seen from Eqs.(i) and (ii),&nbsp;<span class="math-tex">{tex}E _ { k _ { \\mathrm { av } } } = E _ { p _ { \\mathrm { av } } }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Explain the total energy in simple harmonic motion and show the graphical representation of energy in SHM.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The total energy of the system of a block and a spring is equal to the sum of the potential energy stored in the spring plus the kinetic energy of the block and is proportional to the square of the amplitude.<br />
<sup><span class="math-tex">{tex}\\frac{1}{2} m\\omega^2\\left(A^2-x^2\\right)+\\frac12 m \\omega^2 x^2{/tex}</span></sup><br />
E = <span class="math-tex">{tex}\\frac12{/tex}</span>m<span class="math-tex">{tex}\\omega^2{/tex}</span>A<sup>2</sup><br />
Hence, the total energy of the particle in SHM is constant and it is independent of the instantaneous displacement. Relationship between potential energy, kinetic energy, and time in Simple Harmonic Motion at t = 0, when x = <span class="math-tex">{tex}\\pm{/tex}</span>A.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1708938455-xyr4kr.jpg" style="height:140px; width:150px" /></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A spring having with a spring constant 1200 N m<sup>&ndash;1</sup>&nbsp;is mounted on a horizontal table as shown in Fig. A mass of 3 kg is attached to the free end of the spring. The mass is then pulled sideways to a distance of 2.0 cm and released.<br />
<img id="Picture 32" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch14/4m/image044.jpg" style="width: 100px; height: 49px;" /></p>

<p>Take the position of mass when the spring is unstreched as x = 0, and the direction from left to right as the positive direction of x-axis. Give x as a function of time t for the oscillating mass if at the moment we start the stopwatch (t = 0), the mass is</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>at the mean position,</li>
	<li>at the maximum stretched position, and</li>
	<li>at the maximum compressed position.</li>
</ol>

<p>In what way do these functions for SHM differ from each other, in frequency, in amplitude or the initial phase?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The functions have the same frequency and amplitude, but different initial phases.<br />
Given:<br />
Distance travelled by the mass sideways is given by, A = 2.0 cm<br />
Force constant of the spring is given by, k = 1200 N m<sup>-1</sup><br />
Mass, m is given by = 3 kg<br />
Angular frequency of oscillation is given by:<br />
<span class="math-tex">{tex} \\omega=\\sqrt{\\frac{spring\\;cons\\tan t}{mass}}{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\Rightarrow \\omega = \\sqrt { \\frac { k } { m } }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}= \\sqrt { \\frac { 1200 } { 3 } } = \\sqrt { 400 } = 20 \\mathrm { rads } ^ { - 1 }{/tex}</span></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>When the mass is at the mean position, the initial phase is 0.<br />
	Displacement is given by,<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span> x = A sin <span class="math-tex">{tex}\\omega{/tex}</span>t&nbsp; = 2sin 20t</li>
	<li>At the maximum stretched position, the mass is toward the extreme right. Hence, the initial phase is <span class="math-tex">{tex}\\frac { \\pi } { 2 }{/tex}</span>.<br />
	&nbsp;hence, Displacement is given by,<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex}x = A \\sin \\left( \\omega t + \\frac { \\pi } { 2 } \\right){/tex}</span><br />
	<span class="math-tex">{tex}= 2 \\sin \\left( 20 t + \\frac { \\pi } { 2 } \\right){/tex}</span>&nbsp; = 2cos 20t</li>
	<li>At the maximum compressed position, the mass is toward the extreme left. Hence, the initial phase is <span class="math-tex">{tex}\\frac { 3 \\pi } { 2 }{/tex}</span>.<br />
	Displacement is given by,<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}x = A \\sin \\left( \\omega t + \\frac { 3 \\pi } { 2 } \\right){/tex}</span><br />
	<span class="math-tex">{tex}= 2 \\sin \\left( 20 t + \\frac { 3 \\pi } { 2 } \\right){/tex}</span> = &ndash;2cos 20t</li>
	<li>The functions have the same frequency&nbsp;<span class="math-tex">{tex}\\left( \\frac { 20 } { 2 \\pi } H z \\right){/tex}</span> and amplitude (2 cm), but initial phases are different <span class="math-tex">{tex}\\left( 0 , \\frac { \\pi } { 2 } , \\frac { 3 \\pi } { 2 } \\right){/tex}</span>.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Define the terms; harmonic motion, displacement, velocity, acceleration, amplitude, time period, frequency, angular frequency and phase with reference to oscillatory motion.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Harmonic motion refers to the motion an oscillating mass experiences when the restoring force is proportional to the displacement, but in opposite directions.<br />
<strong>Displacement</strong> - In an oscillatory motion, displacement simply means a change in any physical property with time.<br />
<strong>Velocity</strong> -&nbsp;The velocity of the mass on a spring, oscillating in SHM, can be found by taking the derivative of the position equation:&nbsp;v(t) = <span class="math-tex">{tex}\\frac{dx}{dt}{/tex}</span>.<br />
<strong>Acceleration</strong> - The acceleration of a particle executing simple harmonic motion is given by a(t) = <span class="math-tex">{tex}-\\omega^2x(t){/tex}</span><br />
<strong>Amplitude</strong> - maximum displacement from the equilibrium position of an object oscillating around such equilibrium position.<br />
<strong>Time period</strong> - This is the time taken to complete one oscillation. It is measured in second (s).<br />
<strong>Frequency</strong> - It is the number of oscillations made in one second. Its unit is hertz (Hz).<br />
<strong>Angular frequency</strong> - Angular frequency is angular displacement of any element of the wave per unit of time.<br />
<strong>Phase</strong> - The phase of an oscillating particle at an instant is the argument of the sine or cosine function invoved to represent the given oscillatory motion.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A particle executing SHM possesses both kinetic energy and potential energy. When a body is displaced from its equilibrium position by doing work upon it, it acquires potential energy. When the body is released, it begins to move back with velocity, thus acquiring kinetic energy.<br />
Both kinetic and potential energies of a particle in SHM vary between zero and their maximum values.</p>

<ol start="1" style="list-style-type:lower-roman">
	<li>How potential energy is stored due to elasticity of system?&nbsp;<strong>(1)</strong></li>
	<li>The expression for displacement of an object in SHM is x = A cos(<span class="math-tex">{tex}\\omega{/tex}</span>t). What is the potential energy at t =&nbsp;<span class="math-tex">{tex}\\frac T4{/tex}</span>.&nbsp;<strong>(2)</strong></li>
	<li>What would happen if&nbsp;maximum potential energy&nbsp;become double in SHM?&nbsp;<strong>(1)</strong></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>Elastic potential energy is&nbsp;energy stored as a result of applying a force to deform an elastic object. The energy is stored until the force is removed and the object springs back to its original shape, doing work in the process. The deformation could involve compressing, stretching or twisting the object.</p>
	</li>
	<li>
	<p>Potential energy of an object executing SHM is given by U(x) =&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\mathrm{kx}^2{/tex}</span><br />
	Given, x =&nbsp;<span class="math-tex">{tex}\\mathrm{A} \\cos \\omega t{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow \\mathrm{U}(\\mathrm{x})=\\frac{1}{2} \\mathrm{kA}^2 \\cos ^2 \\omega \\mathrm{t} {/tex}</span><br />
	At t =&nbsp;<span class="math-tex">{tex}\\left(\\frac{\\mathrm{T}}{4}\\right){/tex}</span><br />
	U(x) =&nbsp;<span class="math-tex">{tex}\\frac{1}{2} \\mathrm{k}^2 \\mathrm{~A}^2 \\cos ^2\\left(\\frac{2 \\pi}{\\mathrm{T}} \\times \\frac{\\mathrm{T}}{4}\\right){/tex}</span><span class="math-tex">{tex}\\left(\\therefore \\omega=\\frac{2 \\pi}{\\mathrm{T}}\\right) {/tex}</span><br />
	= <span class="math-tex">{tex}\\frac{1}{2} \\mathrm{k}^2 \\mathrm{~A}^2 \\cos ^2\\left(\\frac{\\pi}{2}\\right){/tex}</span>&nbsp;= 0<br />
	So, PE&nbsp;at t = <span class="math-tex">{tex}\\frac{T}{4}{/tex}</span> is zero.</p>
	</li>
	<li>
	<p>For a SHM, if the maximum potential energy become double, maximum kinetic and total mechanical energy will become double.</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Find the total energy of the particle executing S.H.M. and show graphically the variation of P.E. and K.E. with time in S.H.M. What is the frequency of these energies with respect to the frequency of the particle executing S.H.M?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The total energy of the system of a block and a spring is equal to the sum of the potential energy stored in the spring plus the kinetic energy of the block and is proportional to the square of the amplitude.<br />
<span class="math-tex">{tex}\\frac12{/tex}</span>m<span class="math-tex">{tex}\\omega^2{/tex}</span>(A<sup>2</sup> - x<sup>2</sup>) + <span class="math-tex">{tex}\\frac12{/tex}</span>m<span class="math-tex">{tex}\\omega^2{/tex}</span>x<sup>2</sup><br />
E = <span class="math-tex">{tex}\\frac12{/tex}</span>m<span class="math-tex">{tex}\\omega^2{/tex}</span>A<sup>2</sup><br />
Hence, the total energy of the particle in SHM is constant and it is independent of the instantaneous displacement. Relationship between potential energy, kinetic energy, and time in Simple Harmonic Motion at t = 0, when x = <span class="math-tex">{tex}\\pm{/tex}</span>A.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1708945650-6fkwxs.jpg" style="height:142px; width:150px" /><br />
The frequency of kinetic energy is twice the frequency of SHM.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Using the correspondence of S.H.M. and uniform circular motion, find displacement, velocity, amplitude, time period and frequency of a particle executing S.H.M?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>If initially at t = 0 particle was at D<br />
Then at time&nbsp;t Particle is at point P</p>

<p><img src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch14/2m/image100.jpg" style="width: 179px; height: 158px;" /></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Then draw a perpendicular From P on AB,<br />
	If the displacement OM = Y<br />
	Ratios of circle of reference = Amplitude = a<br />
	then In <span class="math-tex">{tex}\\Delta{/tex}</span>OMP, <span class="math-tex">{tex}\\angle{/tex}</span>​​​POD = <span class="math-tex">{tex}\\angle{/tex}</span>OPM =&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span> (<span class="math-tex">{tex}\\because{/tex}</span> Alternate Angles)<br />
	<span class="math-tex">{tex}sin\\theta = \\frac { O M } { O P }{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow \\sin \\theta = \\frac { y } { a }{/tex}</span>, &#39;a&#39; being radius of the above circle.<br />
	<span class="math-tex">{tex}\\Rightarrow y = a \\sin \\theta{/tex}</span><br />
	Again <span class="math-tex">{tex}\\theta = \\omega t{/tex}</span><br />
	So,&nbsp;<span class="math-tex">{tex}y = a \\sin \\omega t{/tex}</span></li>
	<li>Velocity, <span class="math-tex">{tex}v = \\frac { d y } { d t }{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow v= \\frac { d } { d t } ( \\mathrm { a } \\sin \\mathrm { \\omega t } ){/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow v = a\\omega \\cos \\omega t {/tex}</span><br />
	<span class="math-tex">{tex}\\text {again} \\cos \\theta = \\sqrt { 1 - \\sin ^ { 2 } \\theta }{/tex}</span><br />
	So,&nbsp;<span class="math-tex">{tex}v = a\\omega ×{/tex}</span>&nbsp;<span class="math-tex">{tex}\\sqrt { 1 - \\sin ^ { 2 } \\omega t }{/tex}</span><br />
	From equation of displacement : <span class="math-tex">{tex}\\sin \\omega t= \\frac { y } { a }{/tex}</span><br />
	So,&nbsp;<span class="math-tex">{tex}v = a\\omega ×{/tex}</span><span class="math-tex">{tex}\\sqrt { 1 - \\frac { y ^ { 2 } } { a ^ { 2 } } }{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow v= a w \\sqrt { \\frac { a ^ { 2 } - y ^ { 2 } } { a ^ { 2 } } }{/tex}</span><br />
	<span class="math-tex">{tex}v = \\omega \\sqrt { a ^ { 2 } - y ^ { 2 } }{/tex}</span></li>
	<li>Acceleration : <span class="math-tex">{tex} f = \\frac { d v } { d t }{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow f = a \\omega \\times \\omega ( - \\sin \\omega t ){/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow f = - \\omega^2a \\sin \\omega t \\Rightarrow f = - \\omega^2y{/tex}</span></li>
	<li><span class="math-tex">{tex}\\text {Time Period}, T = \\frac { 2 \\pi } { \\omega }{/tex}</span></li>
	<li><span class="math-tex">{tex}freuency= \\frac { 1 } { \\mathrm { T } } = \\frac { \\mathrm { \\omega } } { 2 \\pi }{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A spring having with a spring constant 1200 N m<sup>-1</sup> is mounted on a horizontal table as shown in Fig.&nbsp;A mass of 3 kg is attached to the free end of the spring. The mass is then pulled sideways to a distance of 2.0 cm and released.<br />
<img id="Picture 32" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch14/4m/image044.jpg" style="width: 100px; height: 49px;" /><br />
Determine</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the frequency of oscillations,</li>
	<li>maximum acceleration of the mass, and</li>
	<li>the maximum speed of the mass.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>In mechanics and physics, Simple Harmonic Motion is a special type of periodic motion or oscillation motion where the restoring force is directly proportional to the displacement and acts in the direction opposite to that of displacement.<br />
Spring constant, k = 1200 N m<sup>-1</sup><br />
Mass, m = 3 kg<br />
Displacement, A = 2.0 cm = 0.02 cm</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Frequency of oscillation v, is given by the relation:<br />
	<span class="math-tex">{tex}v = \\frac { 1 } { T } = \\frac { 1 } { 2 \\pi } \\sqrt { \\frac { k } { m } }{/tex}</span><br />
	Where T is the time period<br />
	<span class="math-tex">{tex}\\therefore v = \\frac { 1 } { 2 \\times 3.14 } \\sqrt { \\frac { 1200 } { 3 } } = 3.18 \\mathrm { m } / \\mathrm { s }{/tex}</span><br />
	Hence, the frequency of oscillations is 3.18 cycles per second.</li>
	<li>Maximum acceleration (a) is given by the relation:<br />
	<span class="math-tex">{tex}a = \\omega ^ { 2 } A{/tex}</span><br />
	Where,<br />
	<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;= Angular frequency = <span class="math-tex">{tex}\\sqrt { \\frac { k } { m } }{/tex}</span><br />
	A = Maximum displacement<br />
	<span class="math-tex">{tex}\\therefore a = \\frac { k } { m } A = \\frac { 1200 \\times 0.02 } { 3 } = 8 m s ^ { - 2 }{/tex}</span><br />
	Hence, the maximum acceleration of the mass is 8.0 m/s<sup>2</sup>.</li>
	<li>Maximum velocity, <span class="math-tex">{tex}v _ { \\max } = A \\omega{/tex}</span><br />
	<span class="math-tex">{tex}= A \\sqrt { \\frac { k } { m } } = 0.02 \\times \\sqrt { \\frac { 1200 } { 3 } } = 0.4 \\mathrm { m } / \\mathrm { s }{/tex}</span><br />
	Hence, the maximum velocity of the object&nbsp;is 0.4 m/s at its mean position i.e at x = 0.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Fig. (a) shows a spring of force constant k clamped rigidly at one end and a mass m attached to its free end. A force F applied at the free end stretches the spring. Fig. (b) shows the same spring with both ends free and attached to a mass m at either end. Each end of the spring in Fig. (b) is stretched by the same force F<br />
<img alt="" data-imgur-src="c4Cf3Bm.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/c4Cf3Bm.png" style="width: 200px; height: 127px;" /></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>What is the maximum extension of the spring in the two cases?</li>
	<li>If the mass in Fig. (a) and the two masses in Fig. (b) are released, then what is the period of oscillation in each case?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>For Case (a), as we know that the restoring force is given by , F = -kx <span class="math-tex">{tex}\\Rightarrow{/tex}</span> |F| = kx<br />
	<img alt="" data-imgur-src="27GbfEL.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/27GbfEL.png" style="width: 200px; height: 73px;" /><br />
	So, x =&nbsp;<span class="math-tex">{tex}\\frac{F}{k}{/tex}</span><br />
	for the Case<strong> </strong>(b)<br />
	<img alt="" data-imgur-src="IlwIlIW.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/IlwIlIW.png" style="width: 200px; height: 50px;" /><br />
	If x&#39; is the extension in the spring, then drawing free body diagram of either mass (as the system under applied force is under equilibrium).<br />
	<img alt="" data-imgur-src="0hLFmuk.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/0hLFmuk.png" style="width: 200px; height: 42px;" /><br />
	kx&#39; = F<br />
	<span class="math-tex">{tex}\\therefore x ^ { \\prime } = \\frac { F } { k }{/tex}</span><br />
	In both the cases, extension is the same<span class="math-tex">{tex}\\left( \\frac { F } { k } \\right){/tex}</span>.</li>
	<li>The period of oscillation in case(a)<br />
	As, restoring force(F) is given by&nbsp; = -kx<br />
	where, x = is the given extension<br />
	But from Newton&#39;s 2nd law of motion we know that, F = ma<br />
	<span class="math-tex">{tex}\\therefore m a = - k x \\Rightarrow a = - \\left( \\frac { k } { m } \\right) x{/tex}</span>.......(i)<br />
	<span class="math-tex">{tex}a \\propto - x{/tex}</span><br />
	On comparing eq.(i) with a = -<span class="math-tex">{tex}\\omega{/tex}</span><sup>2</sup>x, we get<br />
	<span class="math-tex">{tex}\\omega = \\sqrt { \\frac { k } { m } }{/tex}</span>(angular frequency or velocity of the motion)<br />
	Period of oscillations is given by,&nbsp;<span class="math-tex">{tex}T = \\frac { 2 \\pi } { \\omega } = 2 \\pi \\sqrt { \\frac { m } { k } }{/tex}</span><br />
	Case<strong> (</strong>b)<br />
	<img alt="" data-imgur-src="X1Hw3rF.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/X1Hw3rF.png" style="width: 200px; height: 61px;" /><br />
	The system is divided into two similar systems with spring divided in two equal halves, forming spring constant hence,<br />
	k&#39; = 2k<br />
	Hence, force is , F = - k&#39;x<br />
	Putting k&#39;&nbsp;= 2k (on cutting a spring in two halves, its k doubles)<br />
	F = -2kx<br />
	But from Newton&#39;s law of motion, force is given by F = ma<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>ma = -2kx<br />
	<span class="math-tex">{tex}\\Rightarrow a = - \\left( \\frac { 2 k } { m } \\right) x{/tex}</span>&nbsp; &nbsp;. . . . . (ii)<br />
	On comparing Eq.(ii) with a =&nbsp;-<span class="math-tex">{tex}\\omega{/tex}</span><sup>2</sup>x, we get angular frequency or velocity is,<br />
	<span class="math-tex">{tex}\\omega = \\sqrt { \\frac { 2 k } { m } }{/tex}</span><br />
	Hence the required period of oscillation of the given question,<br />
	<span class="math-tex">{tex}T = \\frac { 2 \\pi } { \\omega } = 2 \\pi \\sqrt { \\frac { m } { 2 k } }{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><html><body><p>Consider a block of mass 700 g is fastened to a spring having spring constant of 70 N/m. Find out the following parameters if block is pulled a distance of 14 cm from its mean position on a frictionless surface and released from rest at t =0.<br/>
<img alt="" data-imgur-src="Wy9klDz.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/Wy9klDz.png" style="width: 200px; height: 113px;"/></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>The angular frequency, the frequency and the period of the resulting motion.</li>
<li>The amplitude of the oscillation.</li>
<li>The maximum speed of the oscillating block.</li>
<li>The maximum acceleration of the block.</li>
<li>The phase constant and hence the displacement function x (t).</li>
</ol></body></html></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li>The angular frequency is given by<br />
	<span class="math-tex">{tex}\\omega = \\sqrt { \\frac { k } { m } } = \\sqrt { \\frac { 70 \\mathrm { N } / \\mathrm { m } } { 0.700 \\mathrm { kg } } }{/tex}</span>= 10 rad/s<br />
	Frequency,&nbsp;<span class="math-tex">{tex}f = \\frac { \\omega } { 2 \\pi } = \\frac { 10 } { 2 \\pi } \\simeq 1.59 \\mathrm { Hz }{/tex}</span><br />
	The time period, T =&nbsp;<span class="math-tex">{tex}\\frac { 1 } { f } = \\frac { 1 } { 1.59 }{/tex}</span> = 0.63 = 630 ms</li>
	<li>The maximum amplitude of the oscillation = maximum displacement<br />
	<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;x<sub>m</sub> =14 cm =0.14 m</li>
	<li>The maximum speed of the oscillation v<sub>m</sub> is given by<br />
	v<sub>m</sub> = <span class="math-tex">{tex}\\omega{/tex}</span>x<sub>m</sub> =10 <span class="math-tex">{tex}\\times{/tex}</span> 0.14 =1.4 m/s</li>
	<li>The magnitude of maximum acceleration of the block is given by<br />
	a<sub>m</sub> = <span class="math-tex">{tex}\\omega{/tex}</span><sup>2</sup>x<sub>m</sub> =100 <span class="math-tex">{tex}\\times{/tex}</span> 0.14 =14 m/s<sup>2</sup><br />
	At time t = 0, the block is located at position, x = x<sub>m</sub></li>
	<li>Then, from general equation of oscillation, x(t) = x<sub>m</sub>cos (<span class="math-tex">{tex}\\omega t + \\phi{/tex}</span>)<br />
	<span class="math-tex">{tex}\\Rightarrow x _ { m } = x _ { m } \\cos ( 0 \\times \\omega + \\phi ){/tex}</span><br />
	<span class="math-tex">{tex}\\therefore \\cos \\phi = 1 \\Rightarrow \\phi = 0{/tex}</span><br />
	The required displacement function of the given oscillation with all the above values becomes,<br />
	<span class="math-tex">{tex}x ( t ) = x _ { m } \\cos ( \\omega t + \\phi ){/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;x(t)&nbsp;<span class="math-tex">{tex}= 0.14 \\times \\cos ( 10 t + 0 ){/tex}</span><br />
	&nbsp;<span class="math-tex">{tex}\\Rightarrow{/tex}</span>x(t) = 0.14 cos 10t</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>The motion of a particle executing simple harmonic motion is described by the displacement function,&nbsp; x (t) = A cos <span class="math-tex">{tex}\\left( \\omega _ { t } + \\omega \\right){/tex}</span>.<br />
If the initial (t = 0) position of the particle is 1 cm and its initial velocity is <span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;cm/s, what are its amplitude and initial phase angle? The angular frequency of the particle is <span class="math-tex">{tex}\\pi{/tex}</span> s<sup>-1</sup>. If instead of the cosine function, we choose the sine function to describe the SHM: x = B sin <span class="math-tex">{tex}( \\omega t + a ){/tex}</span>, what are the amplitude and initial phase of the particle with the above initial conditions.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Displacement of the particles is&nbsp;given by -&nbsp;<br />
y = a sin&nbsp;<span class="math-tex">{tex}wt{/tex}</span>&nbsp;<br />
Here a is the amplitude of oscillation and&nbsp;<span class="math-tex">{tex}2\\pi/ \\omega{/tex}</span>&nbsp;is the period of oscillation and&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;is the angular frequency of the wave.<br />
Initially, at t = 0:<br />
Displacement, x = 1 cm<br />
Initial velocity, v =&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span> cm/sec.<br />
Angular frequency,&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span> = <span class="math-tex">{tex}\\pi{/tex}</span> rad/s<sup>-1</sup><br />
It is given that:<br />
<span class="math-tex">{tex}x ( x ) = A \\cos ( \\omega t + \\phi ){/tex}</span><br />
<span class="math-tex">{tex}1 = A \\cos ( \\omega \\times 0 + \\phi ) = A \\cos \\phi{/tex}</span><br />
<span class="math-tex">{tex}A \\cos \\phi = 1{/tex}</span> ...(i)<br />
Velocity, <span class="math-tex">{tex}v = \\frac { d x } { d t }{/tex}</span><br />
<span class="math-tex">{tex}\\omega = - A \\omega \\sin ( \\omega t + \\phi ){/tex}</span><br />
<span class="math-tex">{tex}1 = A \\sin ( \\omega \\times 0 + \\phi ) = A \\sin \\phi{/tex}</span><br />
<span class="math-tex">{tex}A \\sin \\phi = - 1{/tex}</span> ....(ii)<br />
Squaring and adding equations (i) and (ii), we get:<br />
<span class="math-tex">{tex}A ^ { 2 } \\left( \\sin ^ { 2 } \\phi + \\cos ^ { 2 } \\phi \\right) = 1 + 1{/tex}</span><br />
A<sup>2</sup> = 2<br />
<span class="math-tex">{tex}\\therefore A = \\sqrt { 2 } \\mathrm { cm }{/tex}</span><br />
Dividing equation (ii) by equation (i), we get:<br />
<span class="math-tex">{tex}\\tan \\phi = - 1{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\phi = \\frac { 3 \\pi } { 4 } , \\frac { 7 \\pi } { 4 } , \\dots \\ldots{/tex}</span><br />
SHM is given as:<br />
<span class="math-tex">{tex}x = B \\sin ( \\omega t + a ){/tex}</span><br />
Putting the given values in this equation, we get:<br />
<span class="math-tex">{tex}1 = B \\sin [ \\omega \\times 0 + a ]{/tex}</span><br />
B sin a = 1 &hellip;.(iii)<br />
Velocity, <span class="math-tex">{tex}v = \\omega B \\cos ( \\omega t + a ){/tex}</span><br />
Substituting the given values, we get:<br />
<span class="math-tex">{tex}\\pi = \\pi B \\sin a{/tex}</span><br />
B sin a = 1 ...(iv)<br />
Squaring and adding equations (iii) and (iv), we get:<br />
<span class="math-tex">{tex}B ^ { 2 } \\left[ \\sin ^ { 2 } a + \\cos ^ { 2 } a \\right] = 1 + 1{/tex}</span><br />
B<sup>2</sup> = 2<br />
<span class="math-tex">{tex}\\therefore B = \\sqrt { 2 } \\mathrm { cm }{/tex}</span><br />
Dividing equation (iii) by equation (iv), we get:<br />
<span class="math-tex">{tex}\\frac { B \\sin a } { B \\cos a } = \\frac { 1 } { 1 }{/tex}</span><br />
<span class="math-tex">{tex}\\tan a = 1 = \\tan \\frac { \\pi } { 4 }{/tex}</span><br />
<span class="math-tex">{tex}a = \\frac { \\pi } { 4 } , \\frac { 5 \\pi } { 4 } , \\ldots \\ldots{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Which of the following functions of time represent</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>simple harmonic motion,</li>
	<li>periodic but not simple harmonic and</li>
	<li>non-periodic motion? Find the period of each periodic motion. Here m is a positive real constant.
	<ol start="1" style="list-style-type: lower-alpha;">
		<li>sin <span class="math-tex">{tex}\\omega{/tex}</span>t + cos <span class="math-tex">{tex}\\omega{/tex}</span>t.</li>
		<li>sin <span class="math-tex">{tex}\\pi{/tex}</span>t + 2 cos 2<span class="math-tex">{tex}\\pi{/tex}</span>t + 3 sin 3<span class="math-tex">{tex}\\pi{/tex}</span>t.</li>
		<li><span class="math-tex">{tex}\\cos (2 \\omega t+\\frac \\pi 3){/tex}</span></li>
		<li><span class="math-tex">{tex}\\sin ^{2} \\omega t{/tex}</span></li>
		<li>cos <span class="math-tex">{tex}\\omega{/tex}</span>t + 2 sin<sup>2</sup> <span class="math-tex">{tex}\\omega{/tex}</span>t</li>
	</ol>
	</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li><span class="math-tex">{tex}\\sin \\omega t+\\cos \\omega t=\\sqrt{2} \\sin (\\omega t+\\frac \\pi 4){/tex}</span>, T =&nbsp;<span class="math-tex">{tex} \\frac {2\\pi} \\omega{/tex}</span></li>
	<li>Each term represents S.H.M.<br />
	Period of sin<span class="math-tex">{tex}\\pi{/tex}</span>t,&nbsp;<span class="math-tex">{tex}T=\\frac{2 \\pi}{\\pi}=2 s{/tex}</span><br />
	Period of 2 cos 2<span class="math-tex">{tex}\\pi{/tex}</span>t =&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{2 \\pi}{/tex}</span>&nbsp;= 1s =&nbsp;<span class="math-tex">{tex}\\frac T 2{/tex}</span><br />
	Period of 2 cos 3<span class="math-tex">{tex}\\pi{/tex}</span>t =&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{2 \\pi}{/tex}</span>&nbsp;= <span class="math-tex">{tex}\\frac 23{/tex}</span>s =&nbsp;<span class="math-tex">{tex}\\frac T 3{/tex}</span><br />
	The sum is not simple harmonic but periodic with<br />
	T = 2s.</li>
	<li><span class="math-tex">{tex}\\cos (2 \\omega t+\\frac \\pi 3){/tex}</span>&nbsp;represents S.H.M. with<br />
	T =&nbsp;<span class="math-tex">{tex}\\frac {2 \\pi} {2 \\omega}{/tex}</span>&nbsp;<span class="math-tex">{tex}=\\frac \\pi \\omega{/tex}</span></li>
	<li><span class="math-tex">{tex}\\sin ^{2} \\omega t={\\frac 1 2}-(\\frac 1 2) \\cos 2 \\omega t{/tex}</span><br />
	The function does not represent S.H.M. but is periodic with T =&nbsp;<span class="math-tex">{tex}\\frac {2 \\pi }{ 2 \\omega}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac { \\pi }{ \\omega}{/tex}</span>.</li>
	<li><span class="math-tex">{tex}\\cos \\omega t+2 \\sin ^{2} \\omega t{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\cos \\omega t+1-\\cos 2 \\omega t{/tex}</span><br />
	= 1 +&nbsp;cos<span class="math-tex">{tex}\\omega{/tex}</span>t &minus; cos2<span class="math-tex">{tex}\\omega{/tex}</span>t<br />
	cos <span class="math-tex">{tex}\\omega t{/tex}</span> represents S.H.M. with T = <span class="math-tex">{tex}\\frac{2 \\pi} \\omega{/tex}</span><br />
	cos 2<span class="math-tex">{tex}\\omega{/tex}</span>t represents S.H.M. with period<br />
	=&nbsp;<span class="math-tex">{tex}\\frac {2 \\pi}{ 2 \\omega}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac \\pi \\omega{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac T 2{/tex}</span><br />
	&nbsp;The combined function does not represent S.H.M. but is periodic with T =&nbsp;<span class="math-tex">{tex}\\frac {2 \\pi } \\omega{/tex}</span>.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A body of mass&nbsp;<em>m&nbsp;</em>is attached to one end of a massless string which is suspended vertically from a fixed point. The mass is held in hand so that the spring is neither stretched nor compressed. Suddenly the support of the hand is removed. The lowest position attained by the mass during oscillation is 4cm below the point, where it was held in hand.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>What is the amplitude of oscillation?</li>
	<li>Find the frequency of oscillation?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Let the mass reaches at its new position&nbsp;<span class="math-tex">{tex}x{/tex}</span>&nbsp;unit displacement from previous.<br />
	Then P.E. of spring or mass = gravitational P.E. lost by man<br />
	<img id="Picture 26" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-14/image357.png" style="width: 80px; height: 144px;" /><br />
	<span class="math-tex">{tex}P E = m g x{/tex}</span><br />
	But P.E. due to spring is<span class="math-tex">{tex}\\frac { 1 } { 2 } k x ^ { 2 }, k = \\omega ^ { 2 } A{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore \\frac { 1 } { 2 } k x ^ { 2 } = m g x{/tex}</span><br />
	<span class="math-tex">{tex}x = \\frac { 2 m g } { k }{/tex}</span><br />
	Mean position of spring by block will be when let extension is&nbsp;<span class="math-tex">{tex}x _ { 0 }{/tex}</span>&nbsp;then<br />
	<span class="math-tex">{tex}F = + k x _ { 0 }{/tex}</span><br />
	<span class="math-tex">{tex}F = m g \\therefore m g = + k x _ { 0 } \\text { or } x _ { 0 } = \\frac { m g } { k }{/tex}</span>&nbsp;....(ii)<br />
	From (i) and (ii)&nbsp;<br />
	<span class="math-tex">{tex}x = 2 \\left( \\frac { m g } { k } \\right) = 2 x _ { 0 }{/tex}</span><br />
	<span class="math-tex">{tex}x = 4 \\mathrm { cm } \\quad \\therefore 4 = 2 x _ { 0 }{/tex}</span><br />
	<span class="math-tex">{tex}x _ { 0 } = 2 \\mathrm { cm }{/tex}</span><br />
	The amplitude of oscillator is the maximum distance from mean position i.e.,&nbsp;<span class="math-tex">{tex}x-x_0 = 4-2=2{/tex}</span>cm</li>
	<li>Time Period&nbsp;<span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { m } { k } }{/tex}</span>&nbsp;which does not depend on amplitude<br />
	<span class="math-tex">{tex}\\frac { 2 m g } { k } = x{/tex}</span>&nbsp;from (i)<br />
	<span class="math-tex">{tex}\\frac { m } { k } = \\frac { x } { 2 g } = \\frac { 4 \\times 10 ^ { - 2 } } { 2 \\times 9.8 }{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}\\frac { k } { m } = \\frac { 2 \\times 9.8 } { 4 \\times 10 ^ { - 2 } }{/tex}</span><br />
	<span class="math-tex">{tex}v = \\frac { 1 } { 2 \\pi } \\sqrt { \\frac { k } { m } } = \\frac { 1 } { 2 \\times 3.144 } \\sqrt { \\frac { 2 \\times 9.8 } { 4 \\times 10 ^ { - 2 } } } = \\sqrt { \\frac { 4.9 \\times 10 ^ { 2 } } { 6.28 } }{/tex}</span><br />
	<span class="math-tex">{tex}v = \\frac { 10 \\times 2.21 } { 6.28 } = 3.52 \\mathrm { Hz }{/tex}</span><br />
	Oscillator will not rise above the positive from where it was released because total extension in spring is 4 cm when released and amplitude is 2 cm. So it oscillates below the released position.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A second&#39;s pendulum is taken in a carriage. Find the period of oscillation when the carriage moves with an acceleration of 4 ms<sup>-2</sup>&nbsp;</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>vertically upwards</li>
	<li>vertically downwards, and</li>
	<li>in a horizontal direction.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Time period of a pendulum,<br />
T =&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{l}{g}}{/tex}</span><br />
For second&#39;s pendulum, T = 2s<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;2 =&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{l}{g}}{/tex}</span>&nbsp;or 1 =&nbsp;<span class="math-tex">{tex}\\pi \\sqrt{\\frac{l}{g}}{/tex}</span><br />
or 1 =&nbsp;<span class="math-tex">{tex}\\pi^{2} \\frac{l}{g}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;l =&nbsp;<span class="math-tex">{tex}\\frac{g}{\\pi^{2}}=\\frac{9.8}{\\pi^{2}}{/tex}</span></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>When the carriage moves up with an acceleration a = 4 ms<sup>-2</sup>,&nbsp;the time period is<br />
	T<sub>1</sub> =&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{l}{g+a}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{9.8}{\\pi^{2}(9.8+4)}}{/tex}</span><br />
	=&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{\\pi} \\sqrt{\\frac{9.8}{13.8}}{/tex}</span>&nbsp;= 2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;0.843 = 1.69 s</li>
	<li>When the carriage moves down with an acceleration a = 4 ms<sup>-2</sup>,&nbsp;the time period is<br />
	T<sub>2</sub> =&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{l}{g-a}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{9.8}{\\pi^{2}(9.8-4)}}{/tex}</span><br />
	=&nbsp;<span class="math-tex">{tex}2 \\sqrt{\\frac{9.8}{5.8}}{/tex}</span>&nbsp;= 2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;1.299 = 2.59 s</li>
	<li>When the carriage moves horizontally, both g&nbsp;and a&nbsp;are at a right angle to each other, hence the net acceleration is<br />
	a&#39; =&nbsp;<span class="math-tex">{tex}\\sqrt{g^{2}+a^{2}}=\\sqrt{(9.8)^{2}+(4)^{4}}{/tex}</span><br />
	=&nbsp;<span class="math-tex">{tex}\\sqrt{96.04+16}=\\sqrt{112.04}{/tex}</span>&nbsp;= 10.58 ms<sup>-2</sup><br />
	The time period will be<br />
	T<sub>3</sub> =&nbsp;<span class="math-tex">{tex}2 \\pi \\sqrt{\\frac{l}{a^{\\prime}}}=2 \\pi \\sqrt{\\frac{9.8}{\\pi^{2} \\times 10.58}}{/tex}</span><br />
	= 2&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 0.96 = 1.92 s</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A cylindrical wooden block of cross-section 15.0 cm<sup>2</sup> and mass 230 g is floated over water with an extra weight of 50 g attached to its bottom. The cylinder floats vertically. From the state of equilibrium, it is slightly depressed and released. If the specific gravity of wood is 0.30 and g = 9.8m s<sup>-2</sup>, deduce the frequency of the block, A = 15.0 cm<sup>2</sup> = 15 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>-4</sup> m<sup>2</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Area of cross-section of the block,<br/>
A = 15.0 cm<sup>2</sup> = 15 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-4 </sup>m<sup>2</sup><br/>
Total mass of the block,<br/>
m = 230 + 50 = 280 g = 0.28 kg<br/>
Density of water,<br/>
<span class="math-tex">{tex}\\rho{/tex}</span> = 10<sup>3</sup> kg m<sup>-3</sup><br/>
Density of wood,<br/>
<span class="math-tex">{tex}\\rho{/tex}</span> = 0.30 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>3</sup> kg m<sup>-3</sup> = 300 kg m<sup>-3</sup><br/>
<img alt="" data-imgur-src="qy27Zgn.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082682-ttrffm.jpg" style="width: 150px; height: 142px;"/><br/>
Let the cylinder be depressed through a small distance y. Then<br/>
Restoring force = Weight of water displaced<br/>
or F = <span class="math-tex">{tex}A y \\sigma g{/tex}</span><br/>
Force constant,<br/>
k = <span class="math-tex">{tex}\\frac{F}{y}=A \\sigma g{/tex}</span> = <span class="math-tex">{tex}15 \\times 10^{-4} \\times 10^{3} \\times 9.8{/tex}</span> = 14.7 Nm<sup>-1</sup><br/>
Frequency, <span class="math-tex">{tex}v=\\frac{1}{2 \\pi} \\sqrt{\\frac{k}{m}}=\\frac{1}{2 \\pi} \\sqrt{\\frac{14.7}{0.28}}{/tex}</span><br/>
= <span class="math-tex">{tex}\\frac{7}{44} \\times \\sqrt{52.5}{/tex}</span> = 1.15 Hz</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Find the time period of mass M when displaced from its equilibrium positon and then released for the system shown in figure.<br/>
<img alt="" data-imgur-src="wxMymZa.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1609435010-qp78bn.jpg" style="width: 150px; height: 129px;"/></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>When mass M is pulled and released then , mass M oscillates up and&nbsp; down along with pulley<br />
Let the spring extends by&nbsp;<span class="math-tex">{tex}x _ { 0 }{/tex}</span>&nbsp;when loaded by the&nbsp; mass M. The extension and compression of spring from initial position is larger and smaller respectively due to&nbsp;gravity by same amount of forces always. So effect of gravitational force can be neglected here.&nbsp;<br />
<img id="Picture 21" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-14/image257.png" style="width: 130px; height: 211px;" /><br />
Now let the mass &lsquo;M&rsquo; is pulled by force &lsquo;F&rsquo; downward by displacement&nbsp;<span class="math-tex">{tex}x{/tex}</span>. Then extension in spring will be <span class="math-tex">{tex}2 x{/tex}</span>&nbsp;as string can not be extended.<br />
So, total extension in spring is given by&nbsp;<span class="math-tex">{tex}= \\left( x _ { 0 } + 2 x \\right){/tex}</span>&nbsp;<br />
<span class="math-tex">{tex} T ^ { \\prime } = k \\left( x _ { 0 } + 2 x \\right){/tex}</span>&nbsp;(when pulled downward by x)<br />
<img id="Picture 22" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-14/image261.png" style="width: 107px; height: 150px;" /><br />
<span class="math-tex">{tex} T = k x _ { 0 }{/tex}</span>&nbsp;(when no pulling)<br />
<span class="math-tex">{tex} F = 2 T {/tex}</span>&nbsp;<br />
<span class="math-tex">{tex} F=2kx_0{/tex}</span>&nbsp;<br />
And,<br />
&nbsp;<span class="math-tex">{tex}F ^ { \\prime } = 2 T ^ { \\prime }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\rightarrow F ^ { \\prime } = 2 k \\left( x _ { 0 } + 2 x \\right){/tex}</span>&nbsp;<br />
Restoring force is given by ;<br />
<span class="math-tex">{tex}\\rightarrow F _ { r e s t } = - \\left( F ^ { \\prime } - F \\right){/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\rightarrow f _ { rest } = - \\left[ 2 k \\left( x _ { 0 } + 2 x \\right) - 2 k x _ { 0 } \\right) ]{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\rightarrow F _ { r e s t } = - 2 k .2 x{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\rightarrow M a = - 4 k x{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}a\\propto\\;-x{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}​​\\rightarrow{/tex}</span>&nbsp;Hence, the motion is&nbsp; said to be&nbsp;&nbsp;simple harmonic motion(SHM).<br />
<img id="Picture 23" src="https://media-mycbseguide.s3.amazonaws.com/images/static/ncertexem/11/phy/ch-14/image272.png" style="width: 136px; height: 150px;" /><br />
<span class="math-tex">{tex}\\rightarrow a = - \\omega ^ { 2 } x{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\therefore \\omega ^ { 2 } = \\frac { - a } { x } = \\frac { + 4 k } { M }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex} \\omega = 2 \\sqrt { \\frac { k } { M } }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\Rightarrow \\frac { 2 \\pi } { T } = 2 \\sqrt { \\frac { k } { M } }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex} T = \\pi \\sqrt { \\frac { M } { k } }{/tex}</span>.<br />
<span class="math-tex">{tex}\\rightarrow{/tex}</span>Therefore, Time period is given by&nbsp; the relation&nbsp;<span class="math-tex">{tex}\\rightarrow{/tex}</span> <span class="math-tex">{tex}T=\\mathrm\\pi\\sqrt{\\frac{\\mathrm M}{\\mathrm k}}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A person normally weighing 50 kg stands on a mass less platform which oscillates up and down harmonically at a frequency of 2.0 s<sup>&ndash;1&nbsp;</sup>and an amplitude 5.0 cm. A weighing machine on the platform gives the persons weight against time.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Will there be any change in weight of the body, during the oscillation? Figure In extensible string.</li>
	<li>If answer to part (a) is yes, what will be the maximum and&nbsp;minimum reading in the machine and at which position?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><ol start="1" style="list-style-type: lower-alpha;">
<li>Weight in weight machine will be due to the normal reaction (N) by platform. Consider the top position of platform, two forces acting on it are due to weight of person and oscillator. They both act downward.<br/>
<img alt="" data-imgur-src="KMNkBew.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/KMNkBew.png" style="width: 158px; height: 92px;"/><br/>
	(mg = weight of the person with the oscillator is acting downwards, ma = force due to oscillation is acting upwards, N = normal reaction force acting upwards)<br/>
<span class="math-tex">{tex}{/tex}</span>Now for the downward motion of the system with an acceleration a, <br/>
	ma = mg - N .....(i)<br/>
<span class="math-tex">{tex}{/tex}</span>When platform lifts form its lowest position to upward<br/>
	ma = N - mg ......(ii)<br/>
<span class="math-tex">{tex} a = \\omega ^ { 2 } A{/tex}</span>  is value of acceleration of oscillator<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> From equation (i) we get,<br/>
<span class="math-tex">{tex} N = m g - m \\omega ^ { 2 } A{/tex}</span><br/>
<span class="math-tex">{tex}{/tex}</span>Where A is amplitude, <span class="math-tex">{tex}\\omega{/tex}</span> angular frequency and m mass of oscillator.<br/>
<span class="math-tex">{tex}\\omega=2\\pi\\nu{/tex}</span><br/>
<span class="math-tex">{tex}\\therefore\\omega = 2 \\pi \\times 2 = 4 \\pi ~r a d / \\mathrm { sec }{/tex}</span><br/>
	Again using <span class="math-tex">{tex}A = 5 ~ c m = 5 \\times 10 ^ { - 2 } m {/tex}</span> we get<br/>
<span class="math-tex">{tex}N = 50 \\times 9.8 - 50 \\times 4 \\pi \\times 4 \\pi \\times 5 \\times 10 ^ { - 2 }{/tex}</span><br/>
<span class="math-tex">{tex}= 50 \\left[ 9.8 - 16 \\pi ^ { 2 } \\times 5 \\times 10 ^ { - 2 } \\right]{/tex}</span>N<br/>
<span class="math-tex">{tex}= 50 \\left[ 9.8 - 80 \\times 3.14 \\times 3.14 \\times 10 ^ { - 2 } \\right]{/tex}</span>N<br/>
<span class="math-tex">{tex}\\Rightarrow N = 50 [ 9.8 - 7.89 ] = 50 \\times 1.91 = 95.50 \\mathrm { N }{/tex}</span><br/>
	So minimum weight is 95.50 N(for downward motion of the platform)<br/>
	From equation (ii), N – mg = ma<br/>
	For upward motion from the lowest to the highest point of oscillator,<br/>
<span class="math-tex">{tex} N = m g + m a{/tex}</span><br/>
<span class="math-tex">{tex}= m \\left[ 9.81 + \\omega ^ { 2 } A \\right] \\quad \\!\\! \\because a = \\omega ^ { 2 } A{/tex}</span><br/>
<span class="math-tex">{tex}= 50 \\left[ 9.81 + 16 \\pi ^ { 2 } \\times 5 \\times 10 ^ { - 2 } \\right]{/tex}</span><br/>
<span class="math-tex">{tex}= 50 [ 9.81 + 7.89 ] = 50 ×17.70 {/tex}</span>N = 885 N<br/>
	Hence, there is a change in weight of the body during oscillation.</li>
<li>The maximum weight is 885 N, when platform moves from lowest to upward direction.<br/>
	And the minimum weight is 95.5 N, when platform moves from the highest point to downward direction.</li>
</ol></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>The motion of a particle executing simple harmonic motion is described by the displacement function, x(t) = Acos(<span class="math-tex">{tex}\\omega{/tex}</span>t + <span class="math-tex">{tex}\\phi{/tex}</span>) If the initial (t = 0) position of the particle is 1 cm and its initial velocity is <span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;cm /s, then what are its amplitude and initial phase angle? The angular frequency of the particle is <span class="math-tex">{tex}\\pi{/tex}</span> s<sup>-1</sup>. If instead of the cosine function, we choose the sine function to describe the SHM, x = Bsin(<span class="math-tex">{tex}\\omega{/tex}</span>t + <span class="math-tex">{tex}\\phi{/tex}</span>), then what are the amplitude and initial phase of the particle with the above initial conditions?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, displacement equation x(t) = Acos(<span class="math-tex">{tex}\\omega t + \\phi{/tex}</span>) ...(i)<br />
At t&nbsp;= 0; x(0) = 1 cm, velocity of the particle&nbsp;<span class="math-tex">{tex}v{/tex}</span> = <span class="math-tex">{tex}\\omega{/tex}</span>cm/s<br />
Angular frequency <span class="math-tex">{tex}\\omega = \\pi{/tex}</span>&nbsp;s<sup>-1</sup><br />
<span class="math-tex">{tex}\\Rightarrow 1 = A \\cos ( \\omega t + \\phi ){/tex}</span><br />
For t = 0, 1 = A cos<span class="math-tex">{tex}\\phi{/tex}</span>..........(i)<br />
Now,&nbsp;<span class="math-tex">{tex}v ( t ) = \\frac { d x ( t ) } { d t } = \\frac { d } { d t } A \\cos ( \\omega t + \\phi ){/tex}</span><br />
<span class="math-tex">{tex}= - A \\omega \\sin ( \\omega t + \\phi ){/tex}</span><br />
Again at t = 0,&nbsp;<span class="math-tex">{tex}v = \\omega{/tex}</span>&nbsp;cm/s<br />
<span class="math-tex">{tex}\\Rightarrow \\omega = - A \\omega \\sin \\phi{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow - 1 = A \\sin \\phi{/tex}</span>...........(ii)<br />
Squaring and adding eqs.(i) and (ii),<br />
<span class="math-tex">{tex}A ^ { 2 } \\cos ^ { 2 } \\phi + A ^ { 2 } \\sin ^ { 2 } \\phi = ( 1 ) ^ { 2 } + ( - 1 ) ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}A ^ { 2 } = 2 \\Rightarrow A = \\pm \\sqrt { 2 } \\mathrm { cm }{/tex}</span><br />
Hence, the amplitude of the SHM =&nbsp;<span class="math-tex">{tex}\\sqrt 2{/tex}</span>&nbsp;cm<br />
Dividing Eq. (ii) by (i), we get<br />
<span class="math-tex">{tex}\\frac { A \\sin \\phi } { A \\cos \\phi } = \\frac { - 1 } { 1 } \\text { or } \\tan \\phi = - 1{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow \\phi = - \\frac { \\pi } { 4 } \\text { or } \\frac { 7 \\pi } { 4 }{/tex}</span><br />
Now, if instead of&nbsp; cosine, we choose the sine function in the displacement equation, then<br />
x(t) = B sin<span class="math-tex">{tex}( \\omega t + \\alpha ){/tex}</span><br />
At t = 0, x&nbsp; = 1 cm,&nbsp;<span class="math-tex">{tex}\\Rightarrow 1 = B \\sin ( 0 + \\alpha ){/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}B \\sin \\alpha = 1{/tex}</span>............(iii)<br />
Velocity v(t) =&nbsp;<span class="math-tex">{tex}\\frac { d x ( t ) } { d t } = \\frac { d } { d t } [ B \\sin ( \\omega t + \\alpha ) ]{/tex}</span><br />
<span class="math-tex">{tex}= + B \\omega \\cos ( \\omega t + \\alpha ){/tex}</span><br />
Again at t = 0, v(t) =&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;cm/s<br />
B cos<span class="math-tex">{tex}\\alpha{/tex}</span>&nbsp;= + 1..............(iv)<br />
Squaring and adding Eqs.(iii) and (iv),<br />
<span class="math-tex">{tex}B ^ { 2 } \\sin ^ { 2 } \\alpha + B ^ { 2 } \\cos ^ { 2 } \\alpha = ( 1 ) ^ { 2 } + ( + 1 ) ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow B ^ { 2 } \\sin ^ { 2 } \\alpha + B ^ { 2 } \\cos ^ { 2 } \\alpha = 2{/tex}</span><br />
<span class="math-tex">{tex}B ^ { 2 } \\left( \\sin ^ { 2 } \\alpha + \\cos ^ { 2 } \\alpha \\right) = 2{/tex}</span><br />
<span class="math-tex">{tex}B ^ { 2 } 1 = 2 \\Rightarrow B = \\pm \\sqrt { 2 } \\mathrm { cm }{/tex}</span><br />
Hence, amplitude of the simple harmonic motion in both types of trigonometric wave equation expression =&nbsp;<span class="math-tex">{tex}\\sqrt 2{/tex}</span>&nbsp;cm<br />
Dividing Eq. (iii) by (iv), we get<br />
<span class="math-tex">{tex}\\frac { B \\sin \\alpha } { B \\cos \\alpha } = \\frac { 1 } { 1 } \\text { or } \\tan \\alpha = 1{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\alpha = \\frac { \\pi } { 4 }{/tex}</span>, only the phase angle differs for sine and cosine wave equation.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>What is Simple pendulum? Find an expression for the time period and frequency of a simple pendulum?<br />
​​​​​​​<img id="Picture 2" src="https://media-mycbseguide.s3.amazonaws.com/images/static/impq/11/phy/ch14/5m/image001.jpg" style="width: 150px; height: 85px;" /></p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>A simple pendulum is the most common example of the body executing S.H.M, it consists of heavy point mass body suspended by a weightless inextensible and perfectly flexible string from rigid support, which is free to oscillate. When a pendulum is displaced sideways from its resting, equilibrium position, it is subject to a restoring force due to gravity&nbsp;that will accelerate it back toward the equilibrium position. When released, the restoring force acting on the pendulum&#39;s mass causes it to oscillate&nbsp;about the equilibrium position, swinging back and forth. The time for one complete cycle, a left swing and a right swing, is called the period.<br />
Let m = mass of bob<br />
l = length of a pendulum<br />
Let O is the equilibrium position, OP = X<br />
Let &theta; = small angle through which the bob is displaced.<br />
The forces acting on the bob are:-</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>The weight = Mg acting vertically downwards.</li>
	<li>The tension = T in string acting along Ps.</li>
</ol>

<p>Resolving Mg into 2 components as Mg Cos <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;and Mg Sin <span class="math-tex">{tex}\\theta{/tex}</span>,<br />
Now, T = Mg Cos&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span><br />
Restoring force F = - Mg Sin&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span><br />
- ve sign shows force is directed towards mean position.<br />
Let <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= Small, so Sin <span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;<span class="math-tex">{tex}\\approx{/tex}</span>&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= <span class="math-tex">{tex}\\frac { \\operatorname { Arc } ( \\mathrm { op } ) } { 1 } = \\frac { \\mathrm { x } } { 1 }{/tex}</span>&nbsp;<br />
Hence F = - mg&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span><br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>F = - mg <span class="math-tex">{tex}\\frac { x } { l } \\rightarrow 3 ){/tex}</span>&nbsp;<br />
Now, In S.H.M, F = k x <span class="math-tex">{tex}\\to{/tex}</span> 4)<br />
where,k = Spring constant<br />
Equating equation 3) &amp; 4) for F<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>- k x = - m g <span class="math-tex">{tex}\\frac { x } { l }{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>Spring factor = <span class="math-tex">{tex} k = \\frac { m g } { l }{/tex}</span>&nbsp;<br />
Inertia factor = Mass of bob = m<br />
Now, Time period = T<br />
<span class="math-tex">{tex}= 2 \\pi \\sqrt { \\frac { \\text {Inertia factor} } { \\text { Spring factor } } }{/tex}</span>&nbsp;​​​​​​​<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span><span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { l } { g } }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A cylindrical piece of cork of density of base area <em>A</em> and height <em>h</em> floats in a liquid of density <span class="math-tex">{tex}\\rho _ l{/tex}</span>. The cork is depressed slightly and then released. Show that the cork oscillates up and down simple harmonically with a period&nbsp;<span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { h \\rho } { \\rho _ { l } g } }{/tex}</span> Where&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span> is the density of cork. (Ignore damping due to viscosity of the liquid).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>This numerical can be solved using concept of Simple Harmonic Motion of&nbsp;floating object in which an object is dipped into the liquid and released by pushing it down,due to increased buoyant force it will move upward due to which excess force will push it downward.This repeated up and down movement of the object is governed by the laws of Simple Harmonic Motion assuming viscous forces are absent.<br />
so area of the cork = A<br />
Height of the cork = h<br />
Density of the liquid = <span class="math-tex">{tex}\\rho _ {l}{/tex}</span><br />
Density of the cork = <span class="math-tex">{tex}\\omega{/tex}</span><br />
In equilibrium:<br />
Weight of the cork = Weight of the liquid displaced by the floating cork<br />
Let the cork be depressed slightly by x. As a result, some extra water of a certain volume is displaced. Hence, an extra up-thrust acts upward and provides the restoring force to the cork.<br />
Up-thrust = Restoring force, F = Weight of the extra water displaced<br />
F = &ndash;(Volume&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> Density&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> g)<br />
Volume = Area&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> Distance through which the cork is depressed<br />
Volume = Ax<br />
<span class="math-tex">{tex}\\therefore F = - A \\times \\rho _ { l }g {/tex}</span><br />
According to the force law:<br />
F = kx<br />
<span class="math-tex">{tex}k = \\frac { F } { x }{/tex}</span><br />
Where, k is a constant<br />
<span class="math-tex">{tex}k = \\frac { F } { x } = - A \\rho _ { l } g{/tex}</span> ...(ii)<br />
The time period of the oscillations of the cork:<br />
<span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { m } { k } }{/tex}</span> ....(iii)<br />
Where,<br />
m = Mass of the cork<br />
= Volume of the cork&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> Density<br />
= Base area of the cork&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> Height of the cork&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> Density of the cork<br />
= Ah<span class="math-tex">{tex}\\rho{/tex}</span><br />
Hence, the expression for the time period will be -<br />
<span class="math-tex">{tex}T = 2 \\pi \\sqrt { \\frac { A h \\rho } { A \\rho _{l} g } } = 2 \\pi \\sqrt { \\frac { h \\rho } { \\rho _ {l} g } }{/tex}</span><br />
From the above expression it is proved that time period of the fork does not depend on the mass of the object rather depends on specific gravity of the cork and height of the cork and acceleration due to gravity.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-1354-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

const PHYIMP_WAVES = PQ_PASTEL_HEAD + `
<div class="pq-wrap"><div class="pq-card"><div class="pq-top"><span class="pq-q">Q1</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Equation of progressive wave is given by&nbsp;<span class="math-tex">{tex}y=4 \\sin \\left[\\pi\\left(\\frac{t}{5}-\\frac{x}{9}\\right)+\\frac{\\pi}{6}\\right]{/tex}</span>&nbsp;where y, x are in cm&nbsp;and t is in&nbsp;second. Then which of the following is correct?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">v = 5 cm/sec</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\lambda{/tex}</span> = 18 m</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Given equation is y = 4 sin&nbsp;<span class="math-tex">{tex}\\pi\\left[\\frac{t}{5}-\\frac{x}{9}+\\frac{\\pi}{6}\\right]{/tex}</span><br />
= 4 sin&nbsp;<span class="math-tex">{tex}\\left[\\frac{\\pi t}5-\\frac{\\pi x}9+\\frac{\\pi^2}6\\right]{/tex}</span><br />
Standard equation of wave is<br />
y = r sin&nbsp;<span class="math-tex">{tex}\\left[\\frac{2 \\pi}{T} t-\\frac{2 \\pi}{\\lambda} x+\\phi_{0}\\right]{/tex}</span><br />
comparing these equations we get,&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{\\lambda}=\\frac{-\\pi}{9}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\lambda{/tex}</span> = 18m</p></div></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">A = 0.04 cm</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">f = 50 Hz</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-1" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q2</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The wave described by y =&nbsp;0.25 sin (10<span class="math-tex">{tex}\\pi{/tex}</span>x - 2<span class="math-tex">{tex}\\pi{/tex}</span>t), where x and y are in meters and t in seconds, is a wave travelling along the:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">+ve X-direction with frequency 1 Hz and wavelength <span class="math-tex">{tex}\\lambda{/tex}</span> = 0.2 m</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>y = 0.25 sin (10<span class="math-tex">{tex}\\pi{/tex}</span>x - 2 <span class="math-tex">{tex}\\pi{/tex}</span>t)<br />
Y<sub>max</sub>. = 0.25<br />
<span class="math-tex">{tex}k=\\frac{2 \\pi}{\\lambda}{/tex}</span>&nbsp;= 10<span class="math-tex">{tex}\\pi{/tex}</span> or&nbsp;<span class="math-tex">{tex}\\lambda{/tex}</span> = 0.2 m<br />
<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;= 2<span class="math-tex">{tex}\\pi{/tex}</span>f = 2<span class="math-tex">{tex}\\pi{/tex}</span><br />
or f = 1 Hz<br />
The sign is negative inside the bracket. Therefore, this wave travels in the positive X-direction.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">-ve X-direction with amplitude 0.25 m and wavelength <span class="math-tex">{tex}\\lambda{/tex}</span> = 0.2m</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">-ve X-direction with frequency 1 Hz</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">+ve X-direction with frequency n Hz and wavelength <span class="math-tex">{tex}\\lambda{/tex}</span> = 0.2 m</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-2" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q3</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>When sound travels from air to water the quantity that remains unchanged is:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">frequency</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>When a wave travels from one medium to another only the velocity and wavelength changes in such a way that its frequency remains constant.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">speed</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">intensity</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">wavelength</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-3" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q4</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two waves are propagating with the same amplitude and nearly the same frequency in opposite direction, they result in</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">stationary wave</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Stationary waves are formed when two waves of the same frequency traveling in opposite directions are superimposed.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">beats</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">resonance</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">wave packet</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-4" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q5</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The two waves of the same frequency moving in the same direction give rise to</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">interference</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>When two waves of the same frequency moving with the same speed in the same direction superpose on each other, they produce interference of waves.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">beats</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">stationary waves</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">Motion waves</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-5" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q6</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>A wave travelling in positive X-direction with a = 0.2 m, velocity = 360 m/s and <span class="math-tex">{tex}\\lambda{/tex}</span> = 60 m, then correct expression for the wave is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}y=02 \\sin \\left[2 \\pi\\left(6 t-\\frac{x}{60}\\right)\\right]{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Here a = 0.2 m, v = 360 ms<sup>-1</sup>, <span class="math-tex">{tex}\\lambda{/tex}</span> = 60 m<br />
<span class="math-tex">{tex}v=\\frac{v}{\\lambda}=\\frac{360}{60}=6 \\mathrm{~Hz}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}T=\\frac{1}{6} \\mathbf{s}{/tex}</span><br />
Equation of a harmonic wave,<br />
y =&nbsp;<span class="math-tex">{tex}a \\sin \\left[2 \\pi\\left(\\frac{t}{T}-\\frac{x}{\\lambda}\\right)\\right]=0.2 \\sin \\left[2 \\pi\\left(6 t-\\frac{x}{60}\\right)\\right]{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}y=02 \\sin \\left[2 \\pi\\left(6 t+\\frac{x}{60}\\right)\\right]{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}y=02 \\sin \\left[\\pi\\left(6 t+\\frac{x}{60}\\right)\\right]{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}y=0.2 \\sin \\left[\\pi\\left(6 t-\\frac{x}{60}\\right)\\right]{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-6" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q7</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Speed of sound wave in air</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">is independent of temperature</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">increases with pressure</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">increases with increase in humidity</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Speed of sound (longitudinal) wave in air is <span class="math-tex">{tex}v=\\sqrt{\\frac{\\lambda P}{\\rho}}{/tex}</span>. The density of water vapours is less(rises up) than the air so on increasing humidity,the density of medium decrease in turn increases the speed of sound in air by <span class="math-tex">{tex}v \\propto \\frac{1}{\\sqrt{\\rho}}{/tex}</span> (relation).</p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">decreases with increase in humidity</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-7" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q8</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>When sound travels from air to water, which parameter does not change?</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">frequency</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Frequency remains unchanged when sound travels from air to water.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">wavelength</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">velocity</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">all of these</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-8" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q9</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Which of the following equations represents a wave?</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">y = a(<span class="math-tex">{tex}\\omega{/tex}</span>t - kx)</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">y = a sin <span class="math-tex">{tex}\\omega{/tex}</span>t</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">y = a cos kx</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span class="pq-opt-text"><p style="display:inline">y = a sin (at - bx + c)</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>The equation of wave is in the form of<br />
y = a sin (<span class="math-tex">{tex}\\omega{/tex}</span>t - kx + c)<br />
where c is the initial phase.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-9" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q10</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The ratio of the velocity of sound in hydrogen and oxygen at STP is:</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline">16 : 1</p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">8 : 1</p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline">4 : 1</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}v=\\sqrt{\\frac{\\gamma R T}{M}}{/tex}</span><br />
Y is same as both hydrogen and oxygen are diatomic.<br />
<span class="math-tex">{tex}\\therefore v \\propto \\sqrt{\\frac{1}{M}}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{v_{\\mathrm{H}}}{v_{\\mathrm{O}}}=\\sqrt{\\frac{M_{\\mathrm{O}}}{M_{\\mathrm{H}}}}=\\sqrt{\\frac{16}{1}}=\\frac{4}{1}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">2 : 1</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-10" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q11</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The equation of a simple harmonic wave is given by&nbsp;y = 3sin <span class="math-tex">{tex}\\frac{\\pi}{2}{/tex}</span>(50t - x)&nbsp;where x and y are in metres and t is in seconds. The ratio of maximum particle velocity to the wave velocity is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{3}{2} \\pi{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}\\frac{{{\\text{Maximum particle relativity}}}}{{{\\text{Wave velocity}}}}{/tex}</span><br />
<span class="math-tex">{tex} = \\frac{{\\omega A}}{{\\frac{\\omega }{k}}} = Ak = 3 \\times \\frac{\\pi }{2} = \\frac{3}{2}\\pi {/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}2 \\pi{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}3 \\pi{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{2}{3} \\pi{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-11" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q12</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Sound waves of wavelength <span class="math-tex">{tex}\\lambda{/tex}</span>&nbsp;travelling in a medium with a speed of v m/s enter into another medium where its speed is 2v m/s. The wavelength of sound waves in the second medium is</p></div><div class="pq-opt"><span class="pq-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\lambda{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{\\lambda}{2}{/tex}</span></p></span></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">C</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}2 \\lambda{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>When wave passes from one medium to another its frequency (v) does not change, but its velocity and wavelength changes.<br />
<span class="math-tex">{tex}v=v \\lambda{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}v=\\frac{v}{\\lambda}{/tex}</span><br />
<span class="math-tex">{tex}\\frac{v}{\\lambda}=\\frac{2 v}{\\lambda_{2}} \\Rightarrow \\lambda_{2}=2 \\lambda{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}4 \\lambda{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-12" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q13</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>The frequency of a sound wave is n and its velocity is v. If the frequency is increased to 4n, the velocity of the wave will be</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">v</p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Velocity of sound is independent of frequency. Therefore it is same (v) for frequency n and 4n.</p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">2v</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">4v</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac{v}{4}{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-13" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q14</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Two sound waves having a phase difference of 60<sup>o</sup> have a path difference of:</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac \\lambda6{/tex}</span></p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p>Path diff. =&nbsp;<span class="math-tex">{tex}\\frac{\\lambda}{2 \\pi} \\times{/tex}</span>&nbsp;phase difference<br />
<span class="math-tex">{tex}=\\frac{\\lambda}{2 \\pi} \\times \\frac{\\pi}{3}=\\frac{\\lambda}{6}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac \\lambda3{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">2<span class="math-tex">{tex}\\lambda{/tex}</span></p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline"><span class="math-tex">{tex}\\frac \\lambda2{/tex}</span></p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-14" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q15</span><span class="pq-tag">VSA (Very Short Answer)</span></div><div class="pq-question"><p>Equation of plane wave is&nbsp;<span class="math-tex">{tex}y=4 \\sin \\frac{\\pi}{4}\\left[2 t+\\frac{x}{8}\\right]{/tex}</span><br />
The phase difference at any given instant of two particles 16 cm apart is</p></div><div class="pq-opt pq-opt-correct"><div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span class="pq-opt-text"><p style="display:inline">90°<br/>
 </p></span></div><div class="pq-expl-label">Explanation:</div><div class="pq-expl"><p><span class="math-tex">{tex}y=4 \\sin \\left[\\frac{2 \\pi}{4} t+\\frac{\\pi}{32} x\\right]{/tex}</span><br />
<span class="math-tex">{tex}y=A \\sin \\left[\\frac{2 \\pi}{T} t+\\frac{2 \\pi}{\\lambda} x\\right]{/tex}</span><br />
<span class="math-tex">{tex}\\Delta \\phi=\\frac{2 \\pi}{\\lambda} \\Delta x=\\frac{\\pi}{32} \\times 16=\\frac{\\pi}{2}{/tex}</span></p></div></div><div class="pq-opt"><span class="pq-letter">B</span><span class="pq-opt-text"><p style="display:inline">60°</p></span></div><div class="pq-opt"><span class="pq-letter">C</span><span class="pq-opt-text"><p style="display:inline">30°</p></span></div><div class="pq-opt"><span class="pq-letter">D</span><span class="pq-opt-text"><p style="display:inline">120°</p></span></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-15" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q16</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A simple harmonic wave is expressed by equation,&nbsp;<span class="math-tex">{tex}y=7 \\times 10^{-6} \\sin \\left(800 \\pi t-\\frac{\\pi}{42.5} x\\right){/tex}</span>&nbsp;where y and x are in cm and t in seconds. Calculate the following:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>amplitude</li>
	<li>frequency</li>
	<li>wave length</li>
	<li>wave velocity, and</li>
	<li>phase difference between two particles separated by 17.0 cm.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>We compare the given equation with&nbsp;<span class="math-tex">{tex}y=A \\sin \\left(\\frac{2 \\pi}{T} t-\\frac{2 \\pi}{\\lambda} x\\right){/tex}</span></p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>A = 7 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-6</sup> cm</li>
	<li><span class="math-tex">{tex}\\frac{2 \\pi}{T}=800 \\pi{/tex}</span>&nbsp;<span class="math-tex">{tex}\\therefore \\quad \\nu=\\frac{1}{T}=400 \\mathrm{~Hz}{/tex}</span></li>
	<li><span class="math-tex">{tex}\\frac{2 \\pi}{\\lambda}=\\frac{\\pi}{42.5}{/tex}</span>&nbsp;<span class="math-tex">{tex}\\therefore{/tex}</span> <span class="math-tex">{tex}\\lambda{/tex}</span>&nbsp;= 2 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;42.5 = 85 cm</li>
	<li>v = <span class="math-tex">{tex}\\nu{/tex}</span>&nbsp;<span class="math-tex">{tex}\\lambda{/tex}</span>&nbsp;= 400 <span class="math-tex">{tex}\\times{/tex}</span> 85 = 34000 cm&nbsp;s<sup>-1&nbsp;</sup>= 340 ms<sup>-1</sup></li>
	<li><span class="math-tex">{tex}\\Delta \\phi=\\frac{2 \\pi}{\\lambda} \\Delta x=\\frac{2 \\pi}{85 \\mathrm{~cm}} \\times 17.0 \\mathrm{~cm}=\\frac{2 \\pi}{5} \\mathrm{rad}{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-16" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q17</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A string of mass 2.50kg is under a tension of 200 N. The length of the stretched string is 20.0m. If the transverse jerk is struck at one end of the string, how long does the disturbance take to reach the other end?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Mass of the string, M = 2.50 kg<br />
Tension in the string, T = 200 N<br />
Length of the string, l = 20.0 m</p>

<p>Mass per unit length, <span class="math-tex">{tex}\\mu = \\frac { M } { l } = \\frac { 2.50 } { 20 } = 0.125 \\mathrm { kg } \\mathrm { m } ^ { - 2 }{/tex}</span></p>

<p>The velocity (v) of the transverse wave in the string is given by the relation:</p>

<p><span class="math-tex">{tex}v = \\sqrt { \\frac { T } { \\mu } }{/tex}</span></p>

<p><span class="math-tex">{tex}= \\sqrt { \\frac { 200 } { 0.125 } } = \\sqrt { 1600 } = 40 \\mathrm { m } / \\mathrm { s }{/tex}</span></p>

<p><span class="math-tex">{tex}\\therefore{/tex}</span> Time taken by the disturbance to reach the other end, <span class="math-tex">{tex}t = \\frac { l } { v } = \\frac { 20 } { 40 } = 0.50 s{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-17" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q18</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A stone dropped from the top of a tower of height 300m high splashes into the water of a pond near the base of the tower. When is the splash heard at the top given that the speed of sound in air is 340 ms<sup>-1</sup>(g = 9.8 ms<sup>-2</sup>)?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Height of the tower, s = 300 m<br />
Initial velocity of the stone, u = 0<br />
Acceleration, a = g = 9.8 ms<sup>-1 </sup><br />
Speed of sound in air = 340 m s<sup>-1</sup><br />
The time (t<sub>1</sub>) taken by the stone to strike the water in the pond can be calculated using the second equation of motion, as:<br />
<span class="math-tex">{tex}s = u t _ { 1 } + \\frac { 1 } { 2 } g t _ { 1 } ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}300 = 0 + \\frac { 1 } { 2 } \\times 9.8 \\times t _ { 1 } ^ { 2 }{/tex}</span><br />
<span class="math-tex">{tex}\\therefore t _ { 1 } = \\sqrt { \\frac { 300 \\times 2 } { 9.8 } } = 7.82 s{/tex}</span><br />
Time taken by the sound to reach the top of the tower, <span class="math-tex">{tex}t _ { 2 } = \\frac { 300 } { 340 } = 0.88 s{/tex}</span><br />
Therefore, the time after which the splash is heard, t = t<sub>1</sub> + t<sub>2</sub><br />
= 7.82 + 0.88 = 8.7 s</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-18" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q19</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>A steel wire has a length of 12.0 m and a mass of 2.10 kg. What should be the tension in the wire so that the speed of a transverse wave on the wire equals the speed of sound in dry air at 20<sup>o</sup>C = 343 ms<sup>-1</sup>?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Length of the steel wire, l = 12 m<br />
Mass of the steel wire, m = 2.10 kg<br />
Velocity of the transverse wave, v = 343 m/s<br />
Mass per unit length, <span class="math-tex">{tex}\\mu = \\frac { m } { l } = \\frac { 2.10 } { 12 } = 0.175 \\mathrm { kg } \\mathrm { m } ^ { - 1 }{/tex}</span>&nbsp;<br />
For tension T, the velocity of the transverse wave can be obtained using the relation:<br />
<span class="math-tex">{tex}v = \\sqrt { \\frac { T } { \\mu } }{/tex}</span>&nbsp; here T is tension in the wire<br />
<span class="math-tex">{tex}\\therefore T = v ^ { 2 } \\mu{/tex}</span>&nbsp;<br />
<span class="math-tex">{tex}= ( 343 ) ^ { 2 } \\times 0.175 = 20588.575 \\approx 206 \\times 10 ^ { 4 } \\mathrm { N }{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-19" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q20</span><span class="pq-tag">SA-1 (Short answer type-1)</span></div><div class="pq-question"><p>If c is r.m.s. speed of molecules in a gas and v is the speed of sound waves in the gas, show that c/v is constant and independent of temperature for all diatomic gases.</p>

<ol start="1" style="list-style-type: lower-roman;">
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>From kinetic theory of gases, expression for pressure is given by :-<br />
<span class="math-tex">{tex} p=\\frac{1}{3} \\rho c^{2} {/tex}</span>, where&nbsp;c is rms speed of molecules of a gas.<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex} c=\\sqrt{\\frac{3 p}{\\rho}} {/tex}</span>&nbsp;...(i)<br />
v = speed of sound in the gas&nbsp;<span class="math-tex">{tex} =\\sqrt{\\frac{\\gamma p}{\\rho}} {/tex}</span>...(ii) [from Laplace&#39;s correction over Newton&#39;s formula]<br />
​​​​dividing&nbsp;&nbsp;equation&nbsp;(i) by equation&nbsp;(ii),we get<br />
<span class="math-tex">{tex} \\frac{c}{v}=\\sqrt{\\frac{3 p}{\\rho} \\times \\frac{\\rho}{\\gamma p}}=\\sqrt{\\frac{3}{\\gamma}} {/tex}</span><br />
For diatomic gases,&nbsp;<span class="math-tex">{tex} \\gamma {/tex}</span>&nbsp;= 1.4 = constant<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex} \\frac{c}{v}=\\sqrt{\\frac{3}{1.4}} {/tex}</span>&nbsp;= 1.46 = constant always.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-20" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q21</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A wave travelling along a string is described by&nbsp;y(x ,t) = 0.005sin(80.0x -3.0t) in which the numerical constants are in SI units (0.005 m, 80.0 rad m<sup>-1</sup>&nbsp;and 3.0 rad s<sup>-1</sup>). Calculate</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>the amplitude of particle,</li>
	<li>the wavelength and</li>
	<li>the period and frequency of the wave. Also, calculate displacement y of the particle at a distance x = 30.0 cm and time t = 20s?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, y(x ,t) = 0.005 sin(80.0x - 3.0t) m .....(i)<br />
We know the general form of the equation of an SHM as, y(x, t) = a sin(kx - <span class="math-tex">{tex}\\omega{/tex}</span>t) .....(ii)<br />
Now, comparing the given equation (i) with the general equation (ii) we get,<br />
a = 0.005 m (amplitude)<br />
k = 80.0 rad/m (a wave number)<br />
<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;= 3.0 rad/s (angular frequency)<br />
The physical quantities by using the given fundamental&nbsp;physical quantities.</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Amplitude is given by, a = 0.005 m = 5 mm</li>
	<li>Wavelength is given by,&nbsp;<span class="math-tex">{tex} \\lambda=\\frac{2 \\pi}{k}=\\frac{2 \\pi}{80} {/tex}</span>= 7.85 cm</li>
	<li>Time period is given by, T =&nbsp;<span class="math-tex">{tex} 2 \\pi / \\omega=\\frac{2 \\pi}{3} {/tex}</span>=2.09 s<br />
	and frequency is given by, <span class="math-tex">{tex}\\nu{/tex}</span>&nbsp;<span class="math-tex">{tex} =\\frac{1}{T}=\\frac{1}{2.09} {/tex}</span><br />
	= 0.478&nbsp;<span class="math-tex">{tex} \\simeq {/tex}</span>&nbsp;0.48Hz<br />
	Now, the displacement y of the particle at a distance is given by;<br />
	x = 30.0 cm = 0.3 m and time t = 20 s<br />
	y(0.3, 20) = 0.005 sin (80 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;0.3 - 3.0 <span class="math-tex">{tex}\\times{/tex}</span>&nbsp;20)<br />
	y (0.3, 20) = 0.005 sin (24 - 60)</li>
</ol>

<p>= -0.005 sin(36)<br />
= -0.00495 m&nbsp;<span class="math-tex">{tex} \\simeq {/tex}</span>&nbsp;- 5 mm</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-21" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q22</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Use the formula <span class="math-tex">{tex}v = \\sqrt { \\frac { \\gamma P } { \\rho } }{/tex}</span> to explain why the speed of sound in air</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>is independent of pressure,</li>
	<li>increases with temperature,</li>
	<li>increases with humidity.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Take the relation:<br />
	<span class="math-tex">{tex}v = \\sqrt { \\frac { \\gamma p } { \\rho } }{/tex}</span> ....(i)<br />
	Where,<br />
	Density,&nbsp; <span class="math-tex">{tex}\\rho = \\frac { M a s s } { V o l u m e } = \\frac { M } { V }{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;M = molecular weight of the gas<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;V = Volume of the gas<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>Hence, equation(i) reduces to:<br />
	<span class="math-tex">{tex}v = \\sqrt { \\frac { \\gamma P V } { M } }{/tex}</span> ...(ii)<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Now from the ideal gas equation for n = 1:<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;PV = RT<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;For constant T, PV = Constant<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Since both M and y&nbsp;are constants, v = Constant<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Hence, at a constant temperature, the speed of sound in a gaseous medium is independent of the change in the pressure of the gas.</li>
	<li>Now, Take the relation:<br />
	<span class="math-tex">{tex}v = \\sqrt { \\frac { \\gamma P } { \\rho } }{/tex}</span>&hellip;&hellip;(i)<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;For one mole of an ideal gas, the gas equation can be written as:<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;PV = RT<br />
	<span class="math-tex">{tex}\\Rightarrow \\mathrm { P } = \\frac { R T } { V }{/tex}</span> &hellip; (ii)<br />
	Substituting equation (ii) in equation (i), we get:<br />
	<span class="math-tex">{tex}\\Rightarrow v = \\sqrt { \\frac { \\gamma R T } { V \\rho } } = \\sqrt { \\frac { \\gamma R T } { M } }{/tex}</span> ....(iv)<br />
	Where,<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>M = V&rho;&nbsp;is a constant<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>y and R are also constants<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>We conclude from equation (iv) that <span class="math-tex">{tex}v \\propto \\sqrt { T }{/tex}</span>.<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>Hence, the speed of sound in a gas is directly proportional to the square root of the temperature of the gaseous medium, i.e., the speed of the sound increases with an increase in the temperature of the&nbsp;gaseous medium.</li>
	<li>Let v<sub>m</sub> and v<sub>d</sub> be the speeds of sound in moist air and dry air respectively.<br />
	Let <span class="math-tex">{tex}\\rho _ { m }{/tex}</span> and <span class="math-tex">{tex}\\rho _ { d }{/tex}</span> be the densities of moist air and dry air respectively.<br />
	<span class="math-tex">{tex}\\rightarrow{/tex}</span>Take the relation:<br />
	<span class="math-tex">{tex}\\Rightarrow v = \\sqrt { \\frac { \\gamma P } { \\rho } }{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;Hence, the speed of sound in moist air is:<br />
	<span class="math-tex">{tex}\\Rightarrow v _ { m } = \\sqrt { \\frac { \\gamma P } { \\rho _ { m } } }{/tex}</span> ....(i)<br />
	And the speed of sound in dry air is:<br />
	<span class="math-tex">{tex}\\Rightarrow v _ { d } = \\sqrt { \\frac { \\gamma P } { \\rho _ { d } } }{/tex}</span> ....(ii)<br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;On dividing equations (i) and (ii), we get:<br />
	<span class="math-tex">{tex}\\Rightarrow {v_m\\over v_d} ={ \\sqrt {{ \\gamma P\\over \\rho_m}\\times {\\rho_d\\over \\gamma P}} } = \\sqrt {{\\rho_d\\over \\rho_m}}{/tex}</span><br />
	<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;However, the presence of water vapour reduces the density of air, i.e.,<br />
	<span class="math-tex">{tex}\\rho _ { d } &lt; \\rho _ { m }{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore v _ { m } &gt; \\nu _ { d }{/tex}</span><br />
	Hence, the speed of sound in moist air is greater than it is in dry air. Thus, in a gaseous medium, the speed of sound increases with humidity.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-22" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q23</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What correction was applied by Laplace in Newton&#39;s formula for speed of sound waves? Does it lead to correct value of speed of sound in air?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Laplace applied a correction in Newton&#39;s formula, <span class="math-tex">{tex}\\left[v=\\sqrt{\\frac{B_{i s o h e r m a l}}{\\rho}}\\right]{/tex}</span>&nbsp;for speed of sound in gaseous media. Laplace argued that the compressions and rarefactions are taking place under the adiabatic condition on account of the following two reasons :</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Gases are non-conducting in nature.</li>
	<li>Compressions and rarefactions are taking place so rapidly that there is practically no chance to exchange heat with the surrounding medium.<br />
	Thus, according to Laplace, v =&nbsp;<span class="math-tex">{tex}\\sqrt{\\frac{B_{\\text { ndiahatic }}}{\\rho}}{/tex}</span>&nbsp;</li>
</ol>

<p>We know that under adiabatic conditions PV<sup><span class="math-tex">{tex}\\gamma{/tex}</span></sup>&nbsp;= constant<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}P \\cdot \\gamma V^{\\gamma-1} d V{/tex}</span>&nbsp;+&nbsp;<span class="math-tex">{tex}d P \\cdot V^{\\gamma}{/tex}</span>&nbsp;= 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}V^{\\gamma-1}[V \\cdot d P+\\gamma P d V]{/tex}</span>&nbsp;= 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span>&nbsp;<span class="math-tex">{tex}\\gamma P=-\\frac{d P}{(d V / V)}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}B_{\\text {adiabatic}}{/tex}</span>, where&nbsp;<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;is the ratio&nbsp;of two principal specific heats of a given gas. Hence, as per the Laplace modified formula, we have&nbsp;<br />
<span class="math-tex">{tex}v=\\sqrt{\\frac{\\gamma P}{\\rho}}{/tex}</span><br />
For air at STP conditions P = 1.013&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;10<sup>5</sup> Pa,&nbsp;<span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;= 1.293 kg m<sup>-3</sup> and for air&nbsp;<span class="math-tex">{tex}\\gamma{/tex}</span>&nbsp;= 1.41<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Speed of sound in&nbsp;air at STP, v =&nbsp;<span class="math-tex">{tex}\\sqrt{\\frac{1.41 \\times 1.013 \\times 10^{5}}{1.293}}{/tex}</span>&nbsp;= 332 ms<sup>-1</sup><br />
The value so obtained resembles completely with experimentally determined value of the speed of sound in air. Hence, it is the correct relation.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-23" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q24</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Define wave velocity or phase velocity. Deduce its relation with angular frequency co and propagation constant k.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Wave velocity or phase velocity: The distance covered by a wave in the direction of its propagation per unit time is called the wave velocity. It represents the velocity with which a disturbance is transferred from one particle to the next without the actual motion of the particles.<br/>
<img alt="" data-imgur-src="vDAtTH3.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082756-sbvxsf.jpg" style="width: 286px; height: 129px;"/><br/>
Figure shows two plots of the harmonic wave <span class="math-tex">{tex}y=A \\sin (\\omega t-k x){/tex}</span> at two different instants of time t and <span class="math-tex">{tex}t+\\Delta t{/tex}</span>. During the small time interval At, the entire wave pattern moves through distance Ax in the positive X-direction. As the wave moves, each point of the moving waveform, such as point P marked on the peak retains its displacement y. This is possible only when the phase of the wave remains constant.<br/>
<span class="math-tex">{tex}\\therefore \\quad \\omega t-k x{/tex}</span> = constant<br/>
Differentiating both sides w.r.t., time t, we get<br/>
<span class="math-tex">{tex}\\omega-k \\frac{d x}{d t}=0{/tex}</span> or <span class="math-tex">{tex}\\frac{d x}{d t}=\\frac{\\omega}{k}{/tex}</span><br/>
But <span class="math-tex">{tex}\\frac{d x}{d t}{/tex}</span> = wave velocity, v<br/>
<span class="math-tex">{tex}\\therefore \\quad v=\\frac{\\omega}{k}=\\frac{\\lambda}{T}=v \\lambda{/tex}</span> <span class="math-tex">{tex}\\left[\\because \\omega=\\frac{2 \\pi}{T}, k=\\frac{2 \\pi}{\\lambda}\\right]{/tex}</span></p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-24" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q25</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Given below are some functions of x and t to represent the displacement of an elastic wave.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>y = 5 cos (4x) sin (20t)</li>
	<li>y = 4 sin (5x -&nbsp;<span class="math-tex">{tex}\\frac t 2{/tex}</span>) + 3 cos (5x -&nbsp;<span class="math-tex">{tex}\\frac t 2{/tex}</span>)</li>
	<li>y = 10 cos [(252 &ndash; 250) <span class="math-tex">{tex}\\pi{/tex}</span>t] cos [(252 + 250)<span class="math-tex">{tex}\\pi{/tex}</span>t]</li>
	<li>y = 100 cos (100<span class="math-tex">{tex}\\pi{/tex}</span>t + 0.5x)</li>
</ol>

<p>State which of these represent</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>a travelling wave along -x direction</li>
	<li>a stationary wave</li>
	<li>beats</li>
	<li>a travelling wave along +x direction.<br />
	Given reasons for your answers</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The four given equations are:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>y = 5cos4x sin20t</li>
	<li>y = 4 sin (5x - <span class="math-tex">{tex}\\frac t 2{/tex}</span>) + 3 cos (5x - <span class="math-tex">{tex}\\frac t 2{/tex}</span>)</li>
	<li>y = 10cos(252 &minus; 250)<span class="math-tex">{tex}\\pi{/tex}</span>tcos(252 + 250)<span class="math-tex">{tex}\\pi{/tex}</span>t</li>
	<li>y = 100 cos (100 <span class="math-tex">{tex}\\pi{/tex}</span>t + 0.5 x)</li>
</ol>

<p>From the basic concepts, we know</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Eqn. (iv) represents a wave travelling along -x direction.</li>
	<li>Eqn. (i) represents a stationary wave as terms containing x and t are independent.</li>
	<li>Eqn. (iii) represents beats involving sum and difference of two frequencies 252 and 250.</li>
	<li>Eqn. (ii) represents a wave travelling along +x direction.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-25" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q26</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What is the nature of sound waves in air? How is the speed of sound waves in atmosphere affected by the</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>temperature</li>
	<li>and&nbsp;humidity</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Sound waves in air are longitudinal waves in which compressions and rarefactions take place alternately and move forward.</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>According to the formula&nbsp;<span class="math-tex">{tex}v=\\sqrt{\\frac{\\gamma P}{\\rho}}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\sqrt{\\frac{\\gamma R T}{M_{0}}}{/tex}</span><br />
	Thus,&nbsp;<span class="math-tex">{tex}v \\propto \\sqrt{T}{/tex}</span><br />
	With the increase in temperature T, the velocity v increases since it is directly proportional to the square root of absolute temperature.</li>
	<li>According to formula&nbsp;<span class="math-tex">{tex}v=\\sqrt{\\frac{\\gamma R T}{M_{0}}}{/tex}</span>, where M<sub>0</sub>&nbsp;is the molar mass. Molar mass&nbsp;of water vapour (H<sub>2</sub>O)&nbsp;<span class="math-tex">{tex}\\approx{/tex}</span>&nbsp;18 is much less than the molar mass of nitrogen (N<sub>2</sub>) <span class="math-tex">{tex}\\approx{/tex}</span>&nbsp;28 and oxygen <span class="math-tex">{tex}\\approx{/tex}</span>&nbsp;32. The effective molar mass M<sub>0</sub> of air decreases with the increase in water vapour. Therefore, the speed of sound in air increases with increase in humidity.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-26" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q27</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The speed of sound in dry air at S.T.P. is 332 ms<sup>-1</sup>&nbsp;Assuming air as composed of 4 parts of nitrogen and one part of oxygen, calculate the velocity of sound in oxygen under similar conditions when the densities of oxygen and nitrogen at S.T.P. are in the&nbsp;ratio of 16:14.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Density of mixture =&nbsp;<span class="math-tex">{tex}\\frac{\\text { Total mass }}{\\text { Total volume }}{/tex}</span><br />
<span class="math-tex">{tex}\\rho_{\\mathrm{mix}}=\\frac{4 V \\times \\rho_{\\mathrm{N}}+V \\times \\rho_{\\mathrm{O}}}{4 V+V}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{\\rho_{\\mathrm{O}}\\left(4 \\frac{\\rho_{\\mathrm{N}}}{\\rho_{\\mathrm{O}}}+1\\right)}{5}=\\frac{\\rho_{\\mathrm{O}}\\left(4 \\times \\frac{14}{16}+1\\right)}{5}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{9}{10} \\rho_{\\mathrm{O}}=0.9 \\mathrm{\\rho}_{\\mathrm{O}}{/tex}</span><br />
<span class="math-tex">{tex}\\frac{b}{v_{\\text {mix }}}=\\sqrt{\\frac{P_{\\text {mix }}}{\\rho_{\\mathrm{O}}}}=\\sqrt{\\frac{0.9 \\rho_{\\mathrm{O}}}{\\rho_{\\mathrm{O}}}}=\\sqrt{0.9}{/tex}</span>&nbsp;= 0.9487<br />
<span class="math-tex">{tex}\\therefore \\quad v_{0}=0.9487 \\times v_{\\operatorname{mix}}=0.9487 \\times 332{/tex}</span>&nbsp;= 314.77 ms<sup>-1</sup></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-27" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q28</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>On the basis of dimensional considerations, write the formula for the speed of transverse waves in a solid.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Speed of transverse wave in a solid. The speed of a transverse wave through a solid is determined by two factors:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>Elasticity of shape or modulus of rigidity r&nbsp;of the solid,</li>
	<li>Mass per unit volume or density <span class="math-tex">{tex}\\rho{/tex}</span> determines its inertia.</li>
</ol>

<p>Now,<br />
Dimensions of ratio&nbsp;<span class="math-tex">{tex}\\frac{\\eta}{\\rho}=\\frac{\\left[\\mathrm{ML}^{-1} \\mathrm{~T}^{-2}\\right]}{\\left[\\mathrm{ML}^{-3}\\right]}=\\left[\\mathrm{L}^{2} \\mathrm{~T}^{-2}\\right]{/tex}</span><br />
Dimensions of speed&nbsp;v = [LT<sup>-1</sup>]<br />
So we can express v in terms of <span class="math-tex">{tex}\\eta {/tex}</span> and <span class="math-tex">{tex}\\rho{/tex}</span> as<br />
<span class="math-tex">{tex}v=C \\sqrt{\\frac{\\eta}{\\rho}}{/tex}</span><br />
The dimensionless constant C is found to be unity. Thus the speed of the transverse wave in a solid is given by&nbsp;<span class="math-tex">{tex}v=\\sqrt{\\frac{\\eta}{\\rho}}{/tex}</span>.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-28" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q29</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Explain the terms wavelength, frequency and amplitude for a harmonic wave.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li><b>The wavelength</b> of a harmonic wave is the distance covered by the wave motion during the time in which a medium particle completes one vibration to and fro about its mean position. Alternately, it is the distance (parallel to the direction of wave propagation) between the consecutive repetitions of the shape of a wave. It is the minimum distance between two consecutive points in the same phase.</li>
	<li><strong>Frequency</strong> of a harmonic wave is the number of vibrations per unit time by a medium element as the wave passes through it. The frequency of a wave is defined as reciprocal of its time period and is related to angular frequency <span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;by the relation,<br />
	Frequency <span class="math-tex">{tex}\\nu{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{1}{T}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{\\omega}{2 \\pi}{/tex}</span>&nbsp;<br />
	SI unit of frequency is s<sup>-1</sup> or Hz.</li>
	<li>The <strong>amplitude</strong>&nbsp;of a harmonic wave is the magnitude of maximum displacement of a medium particle (or element) from its equilibrium position as the wave passes through it. The amplitude of a wave is a positive quantity and its SI unit is 1 metre.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-29" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q30</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>From the equation y - A sin <span class="math-tex">{tex}\\frac{2 \\pi}{\\lambda}(v t-x){/tex}</span>, establish the relation between particle velocity and wave velocity.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>The velocity with which the wave travels in space is called the wave velocity , whereas particle velocity is the velocity with which the particles are vibrating to transfer the energy in form of a wave. The relation between wave velocity and particle velocity is given as:</p>

<p>The given wave equation is y = A sin&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{\\lambda}(v t-x){/tex}</span>&nbsp;= A sin&nbsp;<span class="math-tex">{tex}\\left(\\frac{2 \\pi v}{\\lambda} t-\\frac{2 \\pi}{\\lambda} x\\right){/tex}</span><br />
or y = A sin (<span class="math-tex">{tex}\\omega{/tex}</span>t - kx),</p>

<p>because&nbsp;<span class="math-tex">{tex}2 \\pi \\frac{v}{\\lambda}=2 \\pi v{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;= angular frequency</p>

<p>and&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{\\lambda}{/tex}</span>&nbsp;= k = propogation constant.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;particle velocity&nbsp;<span class="math-tex">{tex}\\frac{d y}{d t}{/tex}</span>&nbsp;=<span class="math-tex">{tex}\\frac{dA\\sin(wt-kx)}{dt}{/tex}</span>&nbsp;=A&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;cos (<span class="math-tex">{tex}\\omega{/tex}</span>t&nbsp;- kx)</p>

<p>and&nbsp;<span class="math-tex">{tex}\\frac{d y}{d x}{/tex}</span>&nbsp;=<span class="math-tex">{tex}\\frac{dA\\sin(wt-kx)}{dx}{/tex}</span>&nbsp;=&nbsp; -AK cos (<span class="math-tex">{tex}\\omega{/tex}</span>t - kx)<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;wave velocity v =&nbsp;<span class="math-tex">{tex}\\frac{d x}{d t}{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}(\\frac{dy}{dt}.\\frac{-dx}{dy}){/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\frac{\\omega}{k}{/tex}</span><br />
Hence we conclude that particle velocity&nbsp;<span class="math-tex">{tex}\\frac{d y}{d t}{/tex}</span>&nbsp;= (-<span class="math-tex">{tex}\\frac{d y}{d x}{/tex}</span>)&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;wave velocity&nbsp;<br />
Here&nbsp;<span class="math-tex">{tex}\\frac{d y}{d x}{/tex}</span>&nbsp;is the slope of displacement position graph for given wave motion.<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;Particle velocity = - (slope of displacement - position graph)&nbsp;<span class="math-tex">{tex}\\times{/tex}</span>&nbsp;wave velocity.</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-30" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q31</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The ratio of densities of oxygen and nitrogen is 16:14. At what temperature, the speed of sound in oxygen will be equal to its speed in nitrogen at 14&deg;C?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Speed of sound<br />
<span class="math-tex">{tex}v=\\sqrt{\\frac{\\gamma R T}{M}}=\\sqrt{\\frac{Y R(t+273)}{M}}{/tex}</span><br />
Speed of sound in oxygen at t&deg;C<br />
<span class="math-tex">{tex}=\\sqrt{\\frac{\\gamma R(t+273)}{M_{\\mathrm{O}}}}{/tex}</span><br />
Speed of sound in nitrogen at 14&deg; C<br />
<span class="math-tex">{tex}=\\sqrt{\\frac{\\gamma R(14+273)}{M_{N}}}{/tex}</span><br />
But these two speeds have to be equal. Also, <span class="math-tex">{tex}\\gamma{/tex}</span> is same for both gases.<br />
Hence&nbsp;<span class="math-tex">{tex}\\sqrt{\\frac{\\gamma R(t+273)}{M_{0}}}=\\sqrt{\\frac{\\gamma R(14+273)}{M_{N}}}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{M_{0}}{M_{N}}=\\frac{t+273}{287}{/tex}</span><br />
Given&nbsp;<span class="math-tex">{tex}\\frac{M_{0}}{M_{N}}=\\frac{16}{14}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;<span class="math-tex">{tex}\\frac{16}{14}=\\frac{t+273}{287}{/tex}</span><br />
On solving, t = 55 &deg;C</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-31" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q32</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A source and an observer are approaching one another with the relative velocity 40 ms<sup>-1</sup>. If the true source frequency is 1200 Hz, deduce the observed frequency under the following conditions:</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>All velocity is in the source alone.</li>
	<li>All velocity is in the observer alone.</li>
	<li>The source moves in air at 100 ms<sup>-1 </sup>towards the observer, but the observer also moves with the velocity v<sub>0</sub> in the same direction.</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Here v = 1200 Hz, v = 340 ms<sup>-1</sup><br/>
Relative velocity = 40 ms<sup>-1</sup></p>
<ol start="1" style="list-style-type: lower-roman;">
<li>Here source moves towards the stationary observer, v<sub>s</sub> = + 40 m s<sup>-1</sup>, v<sub>o</sub> = 0<br/>
<img alt="" data-imgur-src="8zxTzPj.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082725-42w6mk.jpg" style="width: 209px; height: 45px;"/><br/>
<span class="math-tex">{tex}v^{\\prime}=\\frac{v-v_{0}}{v-v_{s}} \\times v=\\frac{340-0}{340-40} \\times 1200{/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{340 \\times 1200}{300}=1360 \\mathrm{~Hz}{/tex}</span></li>
<li>Here observer moves towards the stationary source,<br/>
	v<sub>0 </sub>= -40 ms<sup>-1</sup>, v<sub>s</sub>=0<br/>
<img alt="" data-imgur-src="bQLS9aB.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082727-qcvqpz.jpg" style="width: 220px; height: 40px;"/><br/>
<span class="math-tex">{tex}v^{\\prime}=\\frac{v-v_{0}}{v-v_{s}} \\times v=\\frac{340+40}{340-0} \\times 1200{/tex}</span><br/>
<span class="math-tex">{tex}=\\frac{380}{340} \\times 1200=1341 \\mathrm{~Hz}{/tex}</span></li>
<li>Here observer and source move in the same direction,<br/>
	v<sub>s </sub>= 100 hrm ms<sup>-1</sup>, v<sub>0 </sub>= 100 - 40 = 60 ms<sup>-1</sup><br/>
<img alt="" data-imgur-src="dKNWCwp.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082728-jsmg88.jpg" style="width: 233px; height: 41px;"/></li>
</ol></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-32" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q33</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The length of a sonometer wire is 0.75 mand density 9 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>3</sup> kg m<sup>-3</sup>. It can bear a stress of 8.1 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>8</sup> N/m<sup>2</sup> without exceeding the elastic limit. What is the fundamental frequency that can be produced in the wire?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here&nbsp;L = 0.75 m&nbsp;<span class="math-tex">{tex}\\rho=9 \\times 10^{3} \\mathrm{~kg} \\mathrm{~m}^{-3}{/tex}</span><br />
Stress&nbsp;= 8.1 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>9</sup>&nbsp;Nm<sup>-2</sup><br />
Let a be the area of cross-section of the wire, then fundamental frequency,<br />
<span class="math-tex">{tex}v=\\frac{1}{2 L} \\sqrt{\\frac{T}{m}}=\\frac{1}{2 L} \\sqrt{\\frac{\\text { Stress } \\times a}{a \\times 1 \\times \\rho}}=\\frac{1}{2 L} \\sqrt{\\frac{\\text { Stress }}{\\rho}}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{1}{2 \\times 0.75} \\sqrt{\\frac{8.1 \\times 10^{8}}{9 \\times 10^{3}}}=200 \\mathrm{~Hz}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-33" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q34</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>What are mechanical, electromagnetic and matter waves? Give an example of each type.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-roman;">
	<li><strong>Mechanical waves:</strong>&nbsp;The waves which require a material medium for their propagation are called mechanical waves. Such waves are also called elastic waves because their propagation depends on the elastic properties of the medium. These waves are governed by Newton&#39;s laws and can exist in a material mediums, such as water, air, rock etc.<br />
	Examples:&nbsp;Water waves, sound waves, seismic waves (waves produced during earthquake), etc.</li>
	<li><strong>Electromagnetic waves:</strong>&nbsp;The waves which travel in the form of oscillating electric and magnetic fields are called electromagnetic waves. Such waves do not require any material medium for their propagation and are also called non-mechanical waves. Light from the sun and distant stars reaches us through inter-stellar space, which is almost a vacuum. All electromagnetic waves travel through a vacuum at the same speed c, given by c = 29,97,92,458 ms<sup>-1</sup> (speed of light) Examples:&nbsp;Visible and ultraviolet light, radiowaves, microwaves, X-rays, etc.</li>
	<li><strong>Matter waves:</strong>&nbsp;The waves associated with microscopic particles, such as electrons, protons, neutrons, atoms, molecules, etc., when they are in motion, are called matter waves or de-Broglie waves. These waves become important in the quantum mechanical description of matter. Examples:&nbsp;Electron microscopes make use of the matter waves associated with fast moving electrons.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-34" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q35</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A wave travelling along a string is given by&nbsp;y(x, t) = 0.005 sin (80x -3t)&nbsp;where the numerical values are in SI units. Symbols have their usual meanings. Calculate:</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Frequency of the wave,</li>
	<li>Velocity of the wave.</li>
	<li>Amplitude of particle velocity</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given:&nbsp;y(x, t) = 0.005 sin(80x - 3t)<br />
Also,&nbsp;y(x, t) =&nbsp;A sin&nbsp;<span class="math-tex">{tex}\\left(\\frac{2 \\pi x}{\\lambda}-\\frac{2 \\pi t}{T}\\right){/tex}</span><br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;A = 0.005 m,<br />
<span class="math-tex">{tex}\\frac{2 \\pi}{\\lambda}{/tex}</span>=80 rad&nbsp;m<sup>-1</sup>,<br />
<span class="math-tex">{tex}\\frac{2 \\pi}{T}{/tex}</span>&nbsp;= 3 rad&nbsp;s<sup>-1</sup></p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Frequency,<span class="math-tex">{tex}\\mathrm{v}=\\frac{1}{T}=\\frac{3}{2 \\pi}=0.48 \\mathrm{~Hz}{/tex}</span></li>
	<li><span class="math-tex">{tex}\\lambda=\\frac{2 \\pi}{80} \\mathrm{~m}{/tex}</span><br />
	Wave velocity,<span class="math-tex">{tex}v=v \\lambda=\\frac{3}{2 \\pi} \\times \\frac{2 \\pi}{80}=\\frac{3}{80} \\mathrm{~ms}^{-1}=7.5 \\mathrm{cms}^{-1}{/tex}</span></li>
	<li>Amplitude of particle velocity&nbsp;<br />
	=&nbsp;<span class="math-tex">{tex}\\frac{2 \\pi}{T}{/tex}</span> A = 3 <span class="math-tex">{tex}\\times{/tex}</span> 0.005 = 0.015 ms<sup>-1</sup></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-35" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q36</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A string vibrates with a frequency of 200 Hz. Its length is doubled and its tension is altered until it begins to vibrate with a frequency of 300 Hz. What is the ratio of new tension to the original tension?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>In first case,&nbsp;<span class="math-tex">{tex}200=\\frac{1}{2 L} \\sqrt{\\frac{T_{1}}{m}}{/tex}</span>&nbsp;....(1)<br />
In second case,&nbsp;<span class="math-tex">{tex}300=\\frac{1}{2 \\times 2 L} \\sqrt{\\frac{T_{2}}{m}}{/tex}</span>&nbsp;...(2)<br />
Dividing (2) by (1), we get<br />
<span class="math-tex">{tex}\\frac{300}{200}=\\frac{1}{2} \\sqrt{\\frac{T_{2}}{T_{1}}}{/tex}</span>&nbsp;or&nbsp;<span class="math-tex">{tex}\\frac{3}{1}=\\sqrt{\\frac{T_{2}}{T_{1}}}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{T_{2}}{T_{1}}=\\frac{9}{1}=9: 1{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-36" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q37</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>A wire having a linear mass density of 5.0 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-3</sup> kg m<sup>-1</sup> is stretched between two rigid supports with a tension of 450 N. The wire resonates at a frequency of 420 Hz. The next higher frequency at which the same wire resonates is 490 Hz. Find the length of the wire.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Suppose the wire resonates at 420 Hz in its pth harmonic and at 490 Hz in its (p + 1) th harmonic.<br />
As&nbsp;<span class="math-tex">{tex}v_{p}=\\frac{p}{2 L} \\sqrt{\\frac{T}{m}}{/tex}</span><br />
<span class="math-tex">{tex}\\therefore \\quad 420=\\frac{p}{2 L} \\sqrt{\\frac{T}{m}}{/tex}</span>&nbsp;.......(i)<br />
and&nbsp;<span class="math-tex">{tex}490=\\frac{p+1}{2 L} \\sqrt{\\frac{T}{m}}{/tex}</span>..........(ii)<br />
Dividing (2) by (1), we get<br />
<span class="math-tex">{tex}\\frac{490}{420}=\\frac{p+1}{p}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}1+\\frac{70}{420}=1+\\frac{1}{p}{/tex}</span><br />
or p = 6<br />
Putting the value of p in (1), we get<br />
<span class="math-tex">{tex}420=\\frac{6}{2 L} \\sqrt{\\frac{450}{5 \\times 10^{-3}}}=\\frac{3}{L} \\sqrt{9 \\times 10^{4}}{/tex}</span>&nbsp;[<span class="math-tex">{tex}\\because{/tex}</span> m = 5.0 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-3</sup>&nbsp;kg&nbsp;m<sup>-1</sup>, T = 450 N]<br />
or&nbsp;<span class="math-tex">{tex}L=\\frac{3 \\times 3 \\times 10^{2}}{420}=\\frac{15}{7}=2.14 \\mathrm{~m}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-37" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q38</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Find the fundamental note emitted by a string of length <span class="math-tex">{tex}10 \\sqrt{10}{/tex}</span> cm under the tension of 3.14 kg. Radius of string is 0.5 mm and density = 9.8 g cm<sup>-3</sup>.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Here&nbsp;<span class="math-tex">{tex}L=10 \\sqrt{10} \\mathrm{~cm}=0.1 \\sqrt{10} \\mathrm{~m}{/tex}</span><br />
T = 3.14 kg wt = 3.14 <span class="math-tex">{tex}\\times{/tex}</span> 9.8 N, r = 0.5 mm<br />
or D = 1&nbsp;mm = 10<sup>-3</sup>m,<br />
<span class="math-tex">{tex}\\rho{/tex}</span>&nbsp;= 9.8 g&nbsp;cm<sup>-3&nbsp;</sup>= 9800 kg&nbsp;m<sup>-3</sup><br />
Fundamental note,<span class="math-tex">{tex}v=\\frac{1}{L D} \\sqrt{\\frac{T}{\\pi \\rho}}{/tex}</span><br />
<span class="math-tex">{tex}=\\frac{1}{0.1 \\sqrt{10} \\times 10^{-3}} \\sqrt{\\frac{3.14 \\times 9.8}{3.14 \\times 9800}}{/tex}</span>&nbsp;= 100 Hz</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-38" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q39</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>The equation of a wave is given by y = 6 sin 10<span class="math-tex">{tex}\\pi{/tex}</span>t&nbsp;+ 8 cos 10<span class="math-tex">{tex}\\pi{/tex}</span>t, where y is in centimetre and t in second. Determine the constants involved in the standard equation of the wave.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Given, y =6 sin 10<span class="math-tex">{tex}\\pi{/tex}</span>t + 8 cos<span class="math-tex">{tex}\\pi{/tex}</span>&nbsp;cm...(i)<br />
Now the general equation of this type of wave is<br />
y = A sin(<span class="math-tex">{tex}\\omega t + \\phi{/tex}</span>)<br />
<span class="math-tex">{tex}= A \\sin \\omega t \\cos \\phi + A \\cos \\omega t \\sin \\phi{/tex}</span><br />
<span class="math-tex">{tex}= ( A \\cos \\phi ) \\sin \\omega t + ( A \\sin \\phi ) \\cos \\omega t{/tex}</span>.......(ii)<br />
Comparing Eqs.(i) and&nbsp;(ii), we get<br />
<span class="math-tex">{tex}A \\cos \\phi = 6{/tex}</span>.......(iii)<br />
and A sin&nbsp;<span class="math-tex">{tex}\\phi{/tex}</span>&nbsp;= 8 .......(iv)<br />
Time period,<span class="math-tex">{tex} T = \\frac { 2 \\pi } { \\omega } = \\frac { 2 \\pi } { 10 \\pi } = 0.2 \\mathrm { s }{/tex}</span><br />
Squaring and adding Eqs.(iii) and (iv), we get<br />
<span class="math-tex">{tex}A ^ { 2 } \\left( \\cos ^ { 2 } \\phi + \\sin ^ { 2 } \\phi \\right) = 6 ^ { 2 } + 8 ^ { 2 }{/tex}</span><br />
= 36 + 64 = 100<br />
or A<sup>2</sup>&nbsp;= 100<br />
<span class="math-tex">{tex}\\therefore{/tex}</span>&nbsp;A = 10 cm, the amplitude of the given wave.<br />
Dividing Eq.(iv) by (iii), we get<br />
<span class="math-tex">{tex}\\tan \\phi = \\frac { 8 } { 6 }{/tex}</span>= 1.3333<br />
<span class="math-tex">{tex}\\therefore \\phi = \\tan ^ { - 1 } ( 1.3333 ) = 53 ^ { \\circ } 8 ^ { \\prime }{/tex}</span>, the value of phase angle of the given wave in the question</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-39" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q40</span><span class="pq-tag">SA-2 (Short answer type-2)</span></div><div class="pq-question"><p>Show that the wave obtained as a result of interference of two sinusoidal waves is also a sinusoidal wave.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Consider two waves having same frequency, same nature travelling in same direction superimpose on each other. Let these waves be represented by<br />
<span class="math-tex">{tex}y_{1}(x, t){/tex}</span>&nbsp;= A sin(kx -&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>t) ...(i)<br />
and&nbsp;<span class="math-tex">{tex}y_{2}(x, t){/tex}</span>&nbsp;= A sin(kx -&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>t +&nbsp;<span class="math-tex">{tex}\\phi{/tex}</span>) ...(ii)<br />
Here the second wave has been considered to be ahead in phase as compared to the first wave by a phase angle&nbsp;<span class="math-tex">{tex}\\phi{/tex}</span>&nbsp;i.e., there is a phase difference of&nbsp;<span class="math-tex">{tex}\\phi{/tex}</span>&nbsp;between the superposing waves.<br />
Applying the superposition principle, we find that the resultant wave is the algebraic sum of two constituent waves.<br />
Thus,&nbsp;<br />
y(x,t) = y<sub>1</sub>(x,t) + y<sub>2</sub>(x,t)<br />
= A sin(kx - <span class="math-tex">{tex}\\omega t{/tex}</span>) + A sin(kx -&nbsp;<span class="math-tex">{tex}\\omega t{/tex}</span>&nbsp;+&nbsp;<span class="math-tex">{tex}\\phi{/tex}</span>)<br />
= 2A&nbsp;<span class="math-tex">{tex}\\left[\\cos \\frac{\\phi}{2} \\cdot \\sin \\left(k x-\\omega t+\\frac{\\phi}{2}\\right)\\right]{/tex}</span><br />
or&nbsp;y(x,t) = 2A .&nbsp;<span class="math-tex">{tex} \\cos \\frac{\\phi}{2}{/tex}</span>.sin<span class="math-tex">{tex}(k x-\\omega t+\\frac{\\phi}{2} ){/tex}</span>......(iii)<br />
It shows that the resultant wave is also a sinusoidal wave of same frequency and wavelength travelling in +ve x-direction. But amplitude of resultant wave A<sub>r</sub> = 2 A cos<span class="math-tex">{tex}\\frac{\\phi}{2}{/tex}</span>&nbsp;and its phase is&nbsp;<span class="math-tex">{tex}\\frac{\\phi}{2}{/tex}</span>.<br />
Two special cases are of particular interest here:​​​​</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>For constructive interference, <span class="math-tex">{tex}\\phi=0{/tex}</span>, then&nbsp;<span class="math-tex">{tex}A_r={/tex}</span>&nbsp;2A cos 0<sup>o</sup>&nbsp;= 2A i.e Maximum Amplitude</li>
	<li>If&nbsp;<span class="math-tex">{tex}\\phi{/tex}</span>&nbsp;=&nbsp;<span class="math-tex">{tex}\\pi{/tex}</span>, then A<sub>r</sub> = 2A cos&nbsp;<span class="math-tex">{tex}\\left(\\frac{\\pi}{2}\\right){/tex}</span>&nbsp;= 0 and the amplitude of the resultant wave is zero. It is destructive interference.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-40" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q41</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>For the plane wave&nbsp;y = 2.5 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-0.02x</sup>&nbsp;cos (800 t - 0.82 x +<span class="math-tex">{tex}\\frac{\\pi }{2}{/tex}</span>)<br />
write down</p>

<ol start="1" style="list-style-type: lower-roman;">
	<li>the general expression for phase&nbsp;<span class="math-tex">{tex}\\phi{/tex}</span></li>
	<li>the phase at x = 0, t = 0</li>
	<li>the phase difference between the points separated by 20 cm along x-axis.</li>
	<li>the change in phase at a given place 0.6 milli second and</li>
	<li>the amplitude at x = 100 m</li>
</ol>

<p>Take units of y, t, x as 10<sup>-5</sup> cm, s and m respectively.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol>
	<li>Phase&nbsp;<span class="math-tex">{tex}\\phi=800 t-0.82 x+\\frac{\\pi}{2}{/tex}</span></li>
	<li>At x = 0, t = 0,&nbsp;<span class="math-tex">{tex}\\phi = \\frac{\\pi }{2}{/tex}</span>&nbsp;rad</li>
	<li>Here <span class="math-tex">{tex}\\Delta{/tex}</span>x = 20 cm = 0.20 m. Therefore<br />
	<span class="math-tex">{tex}\\Delta \\phi=-0.82 \\Delta x=-0.82 \\times 0.20=-0.164 \\mathrm{rad}{/tex}</span></li>
	<li>Here&nbsp;<span class="math-tex">{tex}\\Delta{/tex}</span>t = 0.6 ms = 0.6 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-3</sup>&nbsp;s&nbsp;Therefore,<br />
	<span class="math-tex">{tex}\\Delta \\phi=800 \\Delta t=800 \\times 0.6 \\times 10^{-3}=0.48 \\mathrm{rad}{/tex}</span></li>
	<li>At x = 100 m, the amplitude is<br />
	A = 2.5 <span class="math-tex">{tex}\\times 10^{-0.02 x}{/tex}</span><br />
	=2.5 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-0.02</sup> <span class="math-tex">{tex}\\times{/tex}</span> 100&nbsp;<span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup>&nbsp;cm<br />
	= 0.025 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-5</sup> cm&nbsp;[<span class="math-tex">{tex}\\because{/tex}</span> unit of A is 10<sup>-5</sup> cm as that of y]</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-41" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q42</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Explain briefly the analytical method of formation of beats?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Beats are often observed between two vibrations with similar frequencies. The beat frequency equals the difference between frequencies of the beating signals. When sound signals interfere, the beat signal can sometimes be heard as a separate note: the Tartini tone.<br />
<br />
Let us consider two wave&nbsp;trains of equal amplitude &lsquo;a&rsquo; and with different frequencies <span class="math-tex">{tex}\\nu{/tex}</span><sub>1</sub>&nbsp;and&nbsp;<span class="math-tex">{tex}\\nu{/tex}</span><sub>2</sub> in same direction. Let displacements are y<sub>1</sub> and y<sub>2</sub> in time &lsquo;t&rsquo;.<br />
<span class="math-tex">{tex}\\omega{/tex}</span><sub>1</sub> = Angular vel. of first wave =&nbsp;<span class="math-tex">{tex}2 \\pi \\nu _ { 1 }{/tex}</span><br />
<span class="math-tex">{tex}\\omega{/tex}</span><sub><span style="font-size: 10.8333px;">2</span></sub> = Angular velocity of second wave =&nbsp;<span class="math-tex">{tex}2 \\pi \\nu _ { 2 }{/tex}</span></p>

<p>y<sub>1</sub> = a sin <span class="math-tex">{tex}\\omega{/tex}</span><sub>1</sub>t<br />
<span class="math-tex">{tex}y _ { 1 } = a \\sin 2 \\pi \\nu _ { 1 } t{/tex}</span><br />
Similarly,&nbsp;<span class="math-tex">{tex}y _ { 2 } = a \\sin 2 \\pi \\nu _ { 2 } t{/tex}</span></p>

<p>Acc. to superposition principle, the resultant displacement &lsquo;y&rsquo; at the same time &lsquo;t&rsquo; is:-<br />
y = y<sub>1 </sub>+ y<sub>2</sub><br />
<span class="math-tex">{tex}y = a \\left[ \\sin 2 \\pi \\nu _ { 1 } t + \\sin 2 \\pi \\nu _ { 2 } t \\right]{/tex}</span></p>

<p>Using sin C + sin D = 2 cos <span class="math-tex">{tex}\\frac { C - D } { 2 } \\sin \\frac { C + D } { 2 }{/tex}</span>&nbsp; , we get,<br />
<span class="math-tex">{tex}y = 2 a \\cos \\frac { 2 \\pi \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) t } { 2 } \\sin \\frac { 2 \\pi \\left( \\nu _ { 1 } + \\nu _ { 2 } \\right) t } { 2 }{/tex}</span><br />
<span class="math-tex">{tex}y = 2 a \\cos \\pi \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) t \\sin \\pi \\left( \\nu _ { 1 } + \\nu _ { 2 } \\right) t{/tex}</span><br />
<span class="math-tex">{tex}y = A \\sin \\pi \\left( \\nu _ { 1 } + \\nu _ { 2 } \\right) t{/tex}</span><br />
where, A = 2a cos <span class="math-tex">{tex}\\pi \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) t{/tex}</span></p>

<p>Now, amplitude A is maximum when,<br />
<span class="math-tex">{tex}\\cos \\pi \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) t = \\max = \\pm 1 = \\cos k \\pi{/tex}</span><br />
<span class="math-tex">{tex}\\pi \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) t = k \\pi , k = 0,1,2 ....{/tex}</span><br />
<span class="math-tex">{tex}t = \\frac { k } { \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) }{/tex}</span>&nbsp;<br />
i.e resultant intensity of sound will be maximum at times, <span class="math-tex">{tex}t = 0 , \\frac { 1 } { \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } , \\frac { 3 } { \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } .....{/tex}</span><br />
Time interval between 2 successive maximum is&nbsp;<span class="math-tex">{tex}= \\frac { 1 } { \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } - 0 = \\frac { 1 } { \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } \\rightarrow ( 1 ){/tex}</span><br />
<br />
Similarly, A will be minimum,<br />
<span class="math-tex">{tex}\\cos \\pi \\left( \\nu _ { 1 } - \\nu_ { 2 } \\right) t = 0{/tex}</span><br />
<span class="math-tex">{tex}\\cos \\pi \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) t = \\cos ( 2 k + 1 ) \\frac { \\pi } { 2 } , k = 0,1,2,3 -{/tex}</span><br />
<span class="math-tex">{tex}\\pi \\left( \\nu _ { 1 } - \\nu_ { 2 } \\right) t = ( 2 k + 1 ) \\frac { \\pi } { 2 }{/tex}</span><br />
<span class="math-tex">{tex}t = \\frac { ( 2 k + 1 ) } { 2 \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) }{/tex}</span><br />
i.e. resultant intensity of sound will be minimum at times,&nbsp;<span class="math-tex">{tex}t = \\frac { 1 } { 2 \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } , \\frac { 3 } { 2 \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } , \\frac { 5 } { 2 \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) }{/tex}</span><br />
Hence time interval between 2 successive minimums is,&nbsp;<span class="math-tex">{tex}= \\frac { 3 } { 2 \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } - \\frac { 1 } { 2 \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } = \\frac { 1 } { \\left( \\nu _ { 1 } - \\nu _ { 2 } \\right) } \\rightarrow ( 2 ){/tex}</span></p>

<p>From equation (1) &amp; (2), we get,<br />
Frequency of beats = <span class="math-tex">{tex}\\left( \\nu _ { 1 } - \\nu _ { 2 } \\right){/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-42" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q43</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Determine the possible harmonics in the longitudinal vibration of a rod clamped in the middle.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>Consider a rod of length L clamped in the middle. As shown in Fig(a). it has one node in the middle and two antinodes at its free ends in the fundamental mode.<br/>
<span class="math-tex">{tex}\\therefore \\quad L=2 \\cdot \\frac{\\lambda_{1}}{4}{/tex}</span> or <span class="math-tex">{tex}\\lambda_{1}=2 L{/tex}</span><br/>
Fundamental frequency or first harmonic,<br/>
<span class="math-tex">{tex}v_{1}=\\frac{v}{\\lambda_{1}}=\\frac{v}{2 L}=v{/tex}</span> (say)<br/>
<img alt="" data-imgur-src="RXP3YsX.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082722-g2ua26.jpg" style="width: 238px; height: 94px;"/><br/>
<img alt="" data-imgur-src="ktvZnqe.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082723-buebpq.jpg" style="width: 238px; height: 84px;"/><br/>
In the second mode, there is an additional node and antinode on the two sides of the clamp, as shown in Fig. (b).<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> <span class="math-tex">{tex}L=6 \\cdot \\frac{\\lambda_{2}}{4}{/tex}</span> or <span class="math-tex">{tex}\\lambda_{2}=\\frac{2 L}{3}{/tex}</span> and <span class="math-tex">{tex}v_{2}=\\frac{v}{\\lambda_{2}}=\\frac{3 v}{2 L}=3 \\mathrm{v}{/tex}</span><br/>
This is called third harmonic or first overtone.<br/>
Similarly, for third mode,<br/>
<span class="math-tex">{tex}v_{3}=\\frac{5 v}{2 L}=5 v{/tex}</span><br/>
This is called fifth harmonic or second overtone.<br/>
Hence v<sub>1 </sub>: v<sub>2 </sub>: v<sub>3 </sub>: = 1 : 3 : 5 : ...</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-43" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q44</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A metallic rod of length 1 m is rigidly clamped at its midpoint. Longitudinal stationary waves are set up in the rod in such a way that there are two nodes on either side of the midpoint. The amplitude of an antinode is 2 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-6</sup> m. Write the equation of motion at a point 2 cm from the midpoint and those of the constituent waves in the rod. (Young&#39;s modulus = 2 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>11</sup> Nm<sup>-2</sup>, density = 8000 kg m<sup>-3</sup>).</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><html><body><p>The velocity of longitudinal waves in the rod is <span class="math-tex">{tex}v=\\sqrt{\\frac{Y}{\\rho}}=\\sqrt{\\frac{2 \\times 10^{11}}{8000}}=5000 \\mathrm{~ms}^{-1}{/tex}</span><br/>
As there are two nodes on either side of the midpoint, so <span class="math-tex">{tex}L=\\frac{5 \\lambda}{2}=1 \\mathrm{~m}{/tex}</span><br/>
or <span class="math-tex">{tex}\\lambda{/tex}</span> = 0.4 m<br/>
Frequency, <span class="math-tex">{tex}v=\\frac{v}{\\lambda}=\\frac{5000}{0.4}=12500 \\mathrm{~Hz}{/tex}</span><br/>
<img alt="" data-imgur-src="qjwq4S6.png" src="https://media-mycbseguide.s3.amazonaws.com/images/imgur/1685082748-9q2dkm.jpg" style="width: 297px; height: 107px;"/><br/>
<span class="math-tex">{tex}\\because{/tex}</span> Amplitude of an antinode = 2 <span class="math-tex">{tex}\\times{/tex}</span> Amplitude of a constituent wave<br/>
<span class="math-tex">{tex}\\therefore{/tex}</span> 2A = 2 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-6</sup> m or A = 1 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-6</sup> m<br/>
The equation for a stationary wave is <span class="math-tex">{tex}y=2 A \\cos \\frac{2 \\pi x}{\\lambda} \\sin \\frac{2 \\pi t}{T}{/tex}</span><br/>
But A = 1 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-6</sup>m, x = 2cm = 0.02m,<br/>
<span class="math-tex">{tex}\\lambda{/tex}</span> = 0.4 m <span class="math-tex">{tex}\\frac{1}{T}{/tex}</span> = 12500 Hz<br/>
<span class="math-tex">{tex}\\therefore \\quad y=2 \\times 10^{-6} \\cos \\frac{\\pi}{10} \\sin 25000 \\pi t{/tex}</span><br/>
This is the equation of motion at a point 2 cm from the mid-point.<br/>
The waves constituting the stationary waves are given by <span class="math-tex">{tex}{y_{1,2}} = A\\sin 2\\pi \\left( {\\frac{t}{T} \\mp \\frac{x}{\\lambda }} \\right){/tex}</span><br/>
or y<sub>1,2 </sub>= 1 <span class="math-tex">{tex}\\times{/tex}</span> 10<sup>-6</sup> sin 2 <span class="math-tex">{tex}\\pi{/tex}</span>(12500 t <span class="math-tex">{tex}\\mp{/tex}</span> 2.5 x)</p></body></html></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-44" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q45</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>At 16&deg;C, two open end organ pipes, when sounded together produce 34 beats in 2 seconds. How many beats per second will be produced, if the temperature rises to 51&deg; C? Neglect the increase in the length of the pipes.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Number of beats produced per second at 16&deg;C =&nbsp;<span class="math-tex">{tex}\\frac{{34}}{2}{/tex}</span> = 17<br />
Let L<sub>1</sub>, L<sub>2</sub> = lengths of the two organ pipes,<br />
v<sub>1</sub>, v<sub>2&nbsp;</sub>= lowest frequencies emitted by the pipes at 16&deg;C<br />
v&#39;<sub>1</sub>, v&#39;<sub>2&nbsp;</sub>= lowest frequencies emitted by the pipes at 51&deg;C<br />
v<sub>16</sub>, v<sub>51&nbsp;</sub>= velocities of sound at 16&deg;&nbsp;C&nbsp;and 51&deg;C respectively.<br />
<span class="math-tex">{tex}\\therefore v_{1}=\\frac{v_{16}}{2 L_{1}}{/tex}</span>&nbsp;and&nbsp;<span class="math-tex">{tex}v_{2}=\\frac{v_{16}}{2 L_{2}}{/tex}</span><br />
Beat frequency at 16&deg;C<br />
v<sub>1</sub> - v<sub>2</sub> = 17<br />
or&nbsp;<span class="math-tex">{tex}\\frac{v_{16}}{2 L_{1}}-\\frac{v_{16}}{2 L_{2}}=17{/tex}</span><br />
<span class="math-tex">{tex}v_{16}\\left[\\frac{1}{2 L_{1}}-\\frac{1}{2 L_{2}}\\right]=17{/tex}</span>...(1)<br />
Let the number of beats per second at&nbsp;51&deg;C = b<br />
Then&nbsp;<span class="math-tex">{tex}v_{1}^{\\prime}-v_{2}^{\\prime}=b{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\frac{v_{51}}{2 L_{1}}-\\frac{v_{51}}{2 L_{2}}=b{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}v_{51}\\left[\\frac{1}{2 L_{1}}-\\frac{1}{2 L_{2}}\\right]=b{/tex}</span>&nbsp;&nbsp;..(2)<br />
Dividing equation (2) by (1), we get<br />
<span class="math-tex">{tex}\\frac{v_{51}}{v_{16}}=\\frac{b}{17}{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}\\sqrt{\\frac{51+273}{16+273}}=\\frac{b}{17} \\quad\\left[\\because v_{t} \\propto \\sqrt{t+273}\\right]{/tex}</span><br />
or&nbsp;<span class="math-tex">{tex}b=17 \\times \\sqrt{\\frac{324}{289}}{/tex}</span><br />
<span class="math-tex">{tex}=17 \\times \\frac{18}{17}=18 \\mathrm{~s}^{-1}{/tex}</span></p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-45" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q46</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A stone is dropped in a liquid at rest in a tank. The fig. (a) below shows circular wave fonts. The waves produced at the centre of a circular ripple tank. Two corks A and B, floats on the water and moves up &amp; down on the surface as the wave passes. The wavelength of the wave is 8.0 cm.<br />
The Fig. (b) shows how the displacement of A varies with time.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658492627-wxdfxg.jpg" style="height:116px; width:150px" /><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658492700-686bfg.jpg" style="height:63px; width:200px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>Name the type of waves produced on water surface.&nbsp;<strong>(1)</strong></li>
	<li>What is the frequency of the wave?&nbsp;<strong>(1)</strong></li>
	<li>If the distance between the centre of the ripple tank and its edge is 40 cm, then find the time taken by the wave to travel from the centre of the tank to the edge.&nbsp;<strong>(2)</strong></li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>Transverse wave&nbsp;are produced on water surface.</li>
	<li>Frequency of the wave is 2&nbsp;Hz.</li>
	<li>If the distance between the centre of the ripple tank and its edge is 40 cm, then the time taken by the wave to travel from the centre of the tank to the edge is 2.5 s.</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-46" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q47</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A stone is dropped in a liquid at rest in a tank. The fig. (a) below shows circular wave fonts. The waves produced at the centre of a circular ripple tank. Two corks A and B, floats on the water and moves up &amp; down on the surface as the wave passes. The wavelength of the wave is 8.0 cm.<br />
The Fig. (b) shows how the displacement of A varies with time.<br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658492627-wxdfxg.jpg" style="height:116px; width:150px" /><br />
<img src="https://media-mycbseguide.s3.amazonaws.com/images/question_images/1658492700-686bfg.jpg" style="height:63px; width:200px" /></p>

<ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>Name the type of waves produced on water surface.</p>
	</li>
	<li>
	<p>What is the amplitude of the vibrations of A as wave passes?</p>
	</li>
	<li>
	<p>The horizontal distance between A and B is half the wavelength of the wave, then what is&nbsp;the displacement of B with time.</p>
	</li>
	<li>
	<p>What is the frequency of the wave?</p>
	</li>
	<li>
	<p>If the distance between the centre of the ripple tank and its edge is 40 cm, then find the time taken by the wave to travel from the centre of the tank to the edge.</p>
	</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type:lower-roman">
	<li>
	<p>Transverse wave&nbsp;are produced on water surface.</p>
	</li>
	<li>
	<p>The amplitude of the vibrations of A as wave passes is 2 mm.</p>
	</li>
	<li>
	<p>The horizontal distance between A and B is half the wavelength of the wave, then the displacement of B with time is opposite to that of A with equal magnitude.</p>
	</li>
	<li>
	<p>Frequency of the wave is 2&nbsp;Hz.</p>
	</li>
	<li>
	<p>If the distance between the centre of the ripple tank and its edge is 40 cm, then the time taken by the wave to travel from the centre of the tank to the edge is 2.5 s.</p>
	</li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-47" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q48</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>A transverse harmonic wave on a string is described by y(x, t) = 3.0 sin (36 t + 0.018 x +&nbsp;<span class="math-tex">{tex} \\frac { \\pi } { 4 }{/tex}</span>), where <em>x</em> and <em>y</em> are in cm and <em>t&nbsp;</em>in s. The positive direction of <em>x</em> is from left to right.</p>

<ol start="1" style="list-style-type: lower-alpha;">
	<li>Is this a travelling wave or a stationary wave? If it is a travelling wave, what is the speed and direction of its propagation?</li>
	<li>What is its amplitude and frequency?</li>
	<li>What is the initial phase at the origin?</li>
	<li>What is the least distance between two successive crests in the wave?</li>
</ol></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><ol start="1" style="list-style-type: lower-alpha;">
	<li>Progressive wave equation travelling from right to left is given by the displacement function:<br />
	y(x, t) = a sin (<span class="math-tex">{tex}\\omega t + k x + \\theta{/tex}</span>) &hellip;(i)<br />
	where, a = amplitude ,&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>= angular frequency,&nbsp;<span class="math-tex">{tex}\\theta{/tex}</span>&nbsp;= phase constant<br />
	The given equation is:<br />
	<span class="math-tex">{tex}y ( x , t ) = 3 \\sin \\left( 36 t + 0.018 x + \\frac { \\pi } { 4 } \\right){/tex}</span>&hellip;.(ii)<br />
	On comparing both the equations, we find that the given equation (ii) represents a travelling wave, propagating from right to left.<br />
	From equations (i) and (ii), we can write:&nbsp;<span class="math-tex">{tex}\\omega{/tex}</span>&nbsp;= 36 rad/s and k = 0.018 cm<sup>-1</sup><br />
	We know that:<br />
	Frequency of wave,&nbsp;<span class="math-tex">{tex}\\nu=\\frac\\omega{2\\pi}{/tex}</span>&nbsp;and Wavelength of wave,&nbsp;<span class="math-tex">{tex}\\lambda = \\frac { 2 \\pi } { k }{/tex}</span><br />
	Also speed, v =&nbsp;<span class="math-tex">{tex}\\nu\\lambda{/tex}</span><br />
	<span class="math-tex">{tex}\\therefore v = \\left( \\frac { \\omega } { 2 \\pi } \\right) \\times \\left( \\frac { 2 \\pi } { k } \\right) = \\frac { \\omega } { k }{/tex}</span><span class="math-tex">{tex}= \\frac { 36 } { 0.018 } = 2000 \\mathrm { cm } / \\mathrm { s } = 20 \\mathrm { m } / \\mathrm { s }{/tex}</span><br />
	Hence, the speed of the given travelling wave is 20 m/s.</li>
	<li>On comparing (i) and (ii), amplitude of the given wave, a = 3 cm<br />
	Frequency of the given wave:<br />
	<span class="math-tex">{tex}\\nu = \\frac { \\omega } { 2 \\pi } = \\frac { 36 } { 2 \\times 3.14 } = 5.73 H z{/tex}</span></li>
	<li>On comparing equations (i) and (ii), we find that the initial phase angle,&nbsp;<span class="math-tex">{tex}\\theta = \\frac { \\pi } { 4 }{/tex}</span></li>
	<li>The distance between two successive crests or troughs is equal to the wavelength of the wave.<br />
	Wavelength is:<br />
	<span class="math-tex">{tex}\\lambda = \\frac { 2 \\pi } { k }{/tex}</span>&nbsp;<span class="math-tex">{tex}= \\frac { 2 \\times 3.14 } { 0.018 } = 348.89 \\mathrm { cm } = 3.49 \\mathrm { m }{/tex}</span></li>
</ol></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-48" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q49</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Write Newton&#39;s formula for the speed of sound in gases. Why and what correction was applied by Laplace in this formula? Also deduce modified formula for speed of sound.</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p>Newton&rsquo;s formula for the velocity of sound Where P is pressure and r is the density <span class="math-tex">{tex}V=\\sqrt{\\frac{P}{\\rho}}{/tex}</span> since the motion of sound is an isothermal process. The calculation showed speed of sound at NTP is 280 ms<sup>-1 </sup>which is much less than the actual speed 332 ms<sup>-1</sup>. Laplace corrected by saying that it is adiabetic and within the adiabatic process temperature will increase &amp; decrease So,<br />
increase &amp; decrease So,<br />
<span class="math-tex">{tex}V=\\sqrt{\\frac{\\gamma P}{\\rho}}{/tex}</span><br />
So,<br />
<span class="math-tex">{tex}\\gamma{/tex}</span> is constant = <span class="math-tex">{tex}\\frac{C_P}{C_V}{/tex}</span> = 1.41<br />
&nbsp;</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-49" onclick="pqReport(this)">Report Error</button></div></div><div class="pq-card"><div class="pq-top"><span class="pq-q">Q50</span><span class="pq-tag">LA-1 (Long answer type-1)</span></div><div class="pq-question"><p>Derive Newton&#39;s formula for speed of sound in an ideal gas. What is Laplace correction?</p></div><div class="pq-solution"><div class="pq-solution-title">Solution</div><div class="pq-solution-body"><p><strong>Speed of sound in gases (Newton&#39;s formula)</strong><br />
We can estimate the speed of sound in a pas in the ideal gas approximation.<br />
For an ideal gas,<br />
PV = Nk<sub>B</sub>T ...(i)<br />
where, P <span class="math-tex">{tex}\\rightarrow{/tex}</span> Pressure of the gas<br />
V <span class="math-tex">{tex}\\rightarrow{/tex}</span> Volume of the gas<br />
T <span class="math-tex">{tex}\\rightarrow{/tex}</span> Temperature of the gas (in kelvin)<br />
N <span class="math-tex">{tex}\\rightarrow{/tex}</span> Number of molecules in volume V<br />
K<sub>B</sub> <span class="math-tex">{tex}\\rightarrow{/tex}</span> Boltzrnarn constant<br />
Newton assumed that when sound waves propagate through a gas, the change in pressure and volume of the gas are isothermal. The amount of heat produced during compression is lost to the surroundings and the amount of heat lost during rarefactions is gained from the surroundings. Therefore, the temperature of the gas remains constant.<br />
From the equation (i) above<br />
For an isothermal compression<br />
P<span class="math-tex">{tex}\\Delta{/tex}</span>V + V<span class="math-tex">{tex}\\Delta{/tex}</span>P (<span class="math-tex">{tex}\\because{/tex}</span> T is constant)<br />
<span class="math-tex">{tex}P=-\\frac{\\Delta P}{\\frac{\\Delta V }{ V}}{/tex}</span><br />
Now Bulk modulus is given by<br />
<span class="math-tex">{tex}B=-\\frac{\\Delta P}{\\frac{\\Delta V }{ V}}{/tex}</span><br />
Therefore, the speed of longitudinal waves in an ideal gas is<br />
<span class="math-tex">{tex}v=\\sqrt{\\frac{P}{P}}{/tex}</span><br />
This relation is known as Newton&#39;s formula.<br />
<strong>Laplace correction</strong><br />
Newton assumed that the pressure variations in a medium during propegation of sound are isothermal. Laplace pointed out that the pressure variations in the gases when sound propagates are so fast that the heat does get enough time to flow to surroundings or from surroundings to keep the temperature constant. Therefore, the variations are adiabatic and not isothermal.<br />
For an adiabatic process.<br />
P<span class="math-tex">{tex}V^\\gamma{/tex}</span> = Constant<br />
where <span class="math-tex">{tex}\\gamma{/tex}</span> is the ratio of molar specific heat of the gas at constant pressure (C<sub>p</sub>) to its molar specific heat at constant volume (C<sub>p</sub>)<br />
P<span class="math-tex">{tex}\\Delta{/tex}</span>(<span class="math-tex">{tex}V^\\gamma{/tex}</span>) + <span class="math-tex">{tex}V^\\gamma{/tex}</span>(<span class="math-tex">{tex}\\Delta{/tex}</span>P)= 0<br />
<span class="math-tex">{tex}V^\\gamma{/tex}</span> V<sup>t-1</sup><span class="math-tex">{tex}\\Delta{/tex}</span>V + <span class="math-tex">{tex}V^\\gamma{/tex}</span><span class="math-tex">{tex}\\Delta{/tex}</span>P = 0<br />
<span class="math-tex">{tex}\\Rightarrow{/tex}</span> <span class="math-tex">{tex} \\frac{-\\Delta P}{\\frac{\\Delta V }{ V}}=\\gamma^P{/tex}</span> ...(i)</p></div></div><div class="pq-foot"><button class="pq-report" data-qid="phyimp-4529-50" onclick="pqReport(this)">Report Error</button></div></div></div>
`;

